\n            color: #7b8d99;\n            margin-top: 14px;\n            line-height: 1.7;\n        }\n\n        .chart-box {\n            flex: 1;\n            min-height: 280px;\n            position: relative;\n        }\n\n        .program-grid {\n            display: grid;\n            grid-template-columns: repeat(3, 1fr);\n            gap: 18px;\n        }\n\n        .program-card {\n            padding: 22px;\n            min-height: 220px;\n        }\n\n        .program-card .mini-tag {\n            display: inline-flex;\n            align-items: center;\n            gap: 8px;\n            padding: 8px 12px;\n            border-radius: 999px;\n            font-size: 13px;\n            font-weight: 800;\n            color: var(--primary);\n            background: rgba(20,184,166,0.10);\n            margin-bottom: 14px;\n        }\n\n        .program-card h3 {\n            font-size: 24px;\n            line-height: 1.35;\n            color: var(--ink);\n            margin-bottom: 12px;\n            font-weight: 900;\n        }\n\n        .program-card p {\n            font-size: 16px;\n            line-height: 1.75;\n            color: var(--sub);\n        }\n\n        .target-list {\n            display: grid;\n            grid-template-columns: repeat(2, 1fr);\n            gap: 16px;\n        }\n\n        .target-item {\n            display: flex;\n            gap: 14px;\n            align-items: flex-start;\n            padding: 18px 18px 16px;\n            border-radius: 18px;\n            background: rgba(255,255,255,0.88);\n            border: 1px solid var(--line);\n        }\n\n        .target-item .num {\n            width: 46px;\n            height: 46px;\n            border-radius: 14px;\n            background: linear-gradient(135deg, var(--primary), var(--secondary));\n            color: #fff;\n            font-weight: 900;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            flex: 0 0 auto;\n        }\n\n        .target-item h4 {\n            font-size: 19px;\n            color: var(--ink);\n            font-weight: 900;\n            margin-bottom: 6px;\n        }\n\n        .target-item p {\n            font-size: 15px;\n            line-height: 1.7;\n            color: var(--sub);\n        }\n\n        .footnote {\n            position: absolute;\n            left: 56px;\n            bottom: 20px;\n            font-size: 13px;\n            color: #88a0ab;\n            letter-spacing: 0.2px;\n            z-index: 4;\n        }\n\n        .nav-hint {\n            position: absolute;\n            left: 50%;\n            bottom: 20px;\n            transform: translateX(-50%);\n            display: inline-flex;\n            align-items: center;\n            gap: 10px;\n            padding: 8px 14px;\n            border-radius: 999px;\n            background: rgba(255,255,255,0.76);\n            color: #6c818d;\n            font-size: 13px;\n            font-weight: 700;\n            box-shadow: 0 8px 18px rgba(24,49,59,0.04);\n            z-index: 5;\n        }\n\n        .nav-controls {\n            position: fixed;\n            right: 26px;\n            top: 50%;\n            transform: translateY(-50%);\n            display: flex;\n            flex-direction: column;\n            gap: 12px;\n            z-index: 20;\n        }\n\n        .nav-btn {\n            width: 48px;\n            height: 48px;\n            border: none;\n            border-radius: 16px;\n            background: rgba(255,255,255,0.88);\n            color: var(--primary);\n            font-size: 18px;\n            cursor: pointer;\n            box-shadow: 0 12px 28px rgba(24,49,59,0.08);\n            transition: transform 0.2s ease, background 0.2s ease;\n        }\n\n        .nav-btn:hover { transform: translateY(-2px); background: white; }\n\n        .dot-nav {\n            position: fixed;\n            left: 50%;\n            bottom: 24px;\n            transform: translateX(-50%);\n            display: flex;\n            gap: 10px;\n            z-index: 20;\n        }\n\n        .dot {\n            width: 12px;\n            height: 12px;\n            border-radius: 999px;\n            background: rgba(15,118,110,0.18);\n            cursor: pointer;\n            transition: all 0.25s ease;\n        }\n\n        .dot.active {\n            width: 32px;\n            background: linear-gradient(90deg, var(--primary), var(--secondary));\n        }\n    </style>\n</head>\n<body>\n    <div class=\"deck-shell\">\n        <div class=\"deck\" id=\"deck\">\n\n            <!-- Slide 1: Cover -->\n            <section class=\"slide active\" data-title=\"封面\">\n                <div class=\"bg-orb orb-a\"></div>\n                <div class=\"bg-orb orb-b\"></div>\n                <div class=\"bg-orb orb-c\"></div>\n                <div class=\"bg-pill\"></div>\n                <div class=\"bg-grid\"></div>\n                <div class=\"bg-wave\"></div>\n\n                <div class=\"topbar\">\n                    <div class=\"tag\"><i class=\"fa-solid fa-capsules\"></i> 食品药品职业学院主题模板</div>\n                    <div class=\"pagination\"><span class=\"current-page\">01</span><span>/</span><span class=\"total-pages\">07</span></div>\n                </div>\n\n                <div class=\"page-content\" style=\"top: 110px;\">\n                    <div class=\"cover-layout\">\n                        <div>\n                            <div class=\"cover-title\">{{ school_name }}<br><em>{{ report_title }}</em></div>\n                            <div class=\"cover-desc\">\n                                适用于学院宣传、专业建设汇报、产教融合展示、项目申报答辩、教学成果总结等场景。\n                                当前模板沿用原始 <strong>template.html</strong> 的单文件与占位符结构，内容风格切换为食品、药品、检验、制剂、质量与健康服务方向。\n                            </div>\n                            <div class=\"meta-row\">\n                                <div class=\"meta-chip\">\n                                    <div class=\"label\">汇报主题</div>\n                                    <div class=\"value\">{{ report_theme }}</div>\n                                </div>\n                                <div class=\"meta-chip\">\n                                    <div class=\"label\">汇报人 / 部门</div>\n                                    <div class=\"value\">{{ presenter_name }} / {{ presenter_department }}</div>\n                                </div>\n                                <div class=\"meta-chip\">\n                                    <div class=\"label\">日期</div>\n                                    <div class=\"value\">{{ report_date }}</div>\n                                </div>\n                            </div>\n                        </div>\n\n                        <div class=\"hero-card\">\n                            <div class=\"hero-inner\">\n                                <div class=\"hero-icons\">\n                                    <div class=\"icon-badge teal\"><i class=\"fa-solid fa-flask-vial\"></i></div>\n                                    <div class=\"icon-badge blue\"><i class=\"fa-solid fa-shield-heart\"></i></div>\n                                    <div class=\"icon-badge gold\"><i class=\"fa-solid fa-wheat-awn\"></i></div>\n                                </div>\n                                <div style=\"font-size: 30px; font-weight: 900; color: var(--ink); line-height: 1.35; margin-bottom: 10px;\">专业建设 × 产教融合 × 人才培养</div>\n                                <div style=\"font-size: 17px; line-height: 1.8; color: var(--sub);\">\n                                    可直接替换为学院 LOGO、主视觉图、实训基地图片、专业群关键词或办学特色摘要。\n                                </div>\n                                <div class=\"hero-stat-grid\">\n                                    <div class=\"hero-stat\">\n                                        <div class=\"num\">{{ stat_1_value }}</div>\n                                        <div class=\"txt\">{{ stat_1_label }}</div>\n                                    </div>\n                                    <div class=\"hero-stat\">\n                                        <div class=\"num\">{{ stat_2_value }}</div>\n                                        <div class=\"txt\">{{ stat_2_label }}</div>\n                                    </div>\n                                    <div class=\"hero-stat\">\n                                        <div class=\"num\">{{ stat_3_value }}</div>\n                                        <div class=\"txt\">{{ stat_3_label }}</div>\n                                    </div>\n                                    <div class=\"hero-stat\">\n                                        <div class=\"num\">{{ stat_4_value }}</div>\n                                        <div class=\"txt\">{{ stat_4_label }}</div>\n                                    </div>\n                                </div>\n                            </div>\n                        </div>\n                    </div>\n                </div>\n                <div class=\"footnote\">建议替换字段：school_name / report_title / report_theme / presenter_name / report_date</div>\n            </section>\n\n            <!-- Slide 2: Catalog -->\n            <section class=\"slide\" data-title=\"目录\">\n                <div class=\"bg-orb orb-a\"></div>\n                <div class=\"bg-orb orb-b\"></div>\n                <div class=\"bg-pill\"></div>\n                <div class=\"bg-grid\"></div>\n\n                <div class=\"topbar\">\n                    <div class=\"tag\"><i class=\"fa-solid fa-book-open\"></i> 目录 / Contents</div>\n                    <div class=\"pagination\"><span class=\"current-page\">02</span><span>/</span><span class=\"total-pages\">07</span></div>\n                </div>\n\n                <div class=\"page-head\">\n                    <div class=\"title-wrap\">\n                        <div class=\"page-title\">{{ page_title_catalog }}</div>\n                        <div class=\"page-subtitle\">