                 <div class=\"timeline-item\">\n                                    <div class=\"timeline-index\">A</div>\n                                    <div>\n                                        <h4>{{ highlight_title_1 }}</h4>\n                                        <p>{{ highlight_desc_1 }}</p>\n                                    </div>\n                                </div>\n                                <div class=\"timeline-item\">\n                                    <div class=\"timeline-index\">B</div>\n                                    <div>\n                                        <h4>{{ highlight_title_2 }}</h4>\n                                        <p>{{ highlight_desc_2 }}</p>\n                                    </div>\n                                </div>\n                                <div class=\"timeline-item\">\n                                    <div class=\"timeline-index\">C</div>\n                                    <div>\n                                        <h4>{{ highlight_title_3 }}</h4>\n                                        <p>{{ highlight_desc_3 }}</p>\n                                    </div>\n                                </div>\n                            </div>\n                        </div>\n                    </div>\n                </div>\n            </section>\n\n            <!-- Slide 4: Major groups -->\n            <section class=\"slide\" data-title=\"专业建设\">\n                <div class=\"bg-orb orb-a\"></div>\n                <div class=\"bg-orb orb-c\"></div>\n                <div class=\"bg-grid\"></div>\n\n                <div class=\"topbar\">\n                    <div class=\"tag\"><i class=\"fa-solid fa-mortar-pestle\"></i> 专业群建设</div>\n                    <div class=\"pagination\"><span class=\"current-page\">04</span><span>/</span><span class=\"total-pages\">07</span></div>\n                </div>\n\n                <div class=\"page-head\">\n                    <div class=\"title-wrap\">\n                        <div class=\"page-title\">{{ page_title_programs }}</div>\n                        <div class=\"page-subtitle\">可替换为食品类、药品类、检验检测类、健康服务类等专业群介绍。</div>\n                    </div>\n                </div>\n\n                <div class=\"page-content\">\n                    <div class=\"program-grid\">\n                        <div class=\"card program-card\">\n                            <div class=\"mini-tag\"><i class=\"fa-solid fa-bowl-food\"></i> 专业群 01</div>\n                            <h3>{{ program_1_title }}</h3>\n                            <p>{{ program_1_desc }}</p>\n                        </div>\n                        <div class=\"card program-card\">\n                            <div class=\"mini-tag\"><i class=\"fa-solid fa-pills\"></i> 专业群 02</div>\n                            <h3>{{ program_2_title }}</h3>\n                            <p>{{ program_2_desc }}</p>\n                        </div>\n                        <div class=\"card program-card\">\n                            <div class=\"mini-tag\"><i class=\"fa-solid fa-vials\"></i> 专业群 03</div>\n                            <h3>{{ program_3_title }}</h3>\n                            <p>{{ program_3_desc }}</p>\n                        </div>\n                    </div>\n\n                    <div class=\"grid-3\" style=\"margin-top: 18px;\">\n                        <div class=\"card section-card\">\n                            <div class=\"section-title\"><i class=\"fa-solid fa-layer-group\"></i> 课程体系</div>\n                            <ul class=\"bullet-list\">\n                                <li>{{ curriculum_point_1 }}</li>\n                                <li>{{ curriculum_point_2 }}</li>\n                                <li>{{ curriculum_point_3 }}</li>\n                            </ul>\n                        </div>\n                        <div class=\"card section-card\">\n                            <div class=\"section-title\"><i class=\"fa-solid fa-user-graduate\"></i> 人才培养</div>\n                            <ul class=\"bullet-list\">\n                                <li>{{ training_point_1 }}</li>\n                                <li>{{ training_point_2 }}</li>\n                                <li>{{ training_point_3 }}</li>\n                            </ul>\n                        </div>\n                        <div class=\"card section-card\">\n                            <div class=\"section-title\"><i class=\"fa-solid fa-handshake-angle\"></i> 校企协同</div>\n                            <ul class=\"bullet-list\">\n                                <li>{{ industry_point_1 }}</li>\n                                <li>{{ industry_point_2 }}</li>\n                                <li>{{ industry_point_3 }}</li>\n                            </ul>\n                        </div>\n                    </div>\n                </div>\n            </section>\n\n            <!-- Slide 5: training base + chart -->\n            <section class=\"slide\" data-title=\"实训与成果\">\n                <div class=\"bg-orb orb-a\"></div>\n                <div class=\"bg-orb orb-b\"></div>\n                <div class=\"bg-wave\"></div>\n\n                <div class=\"topbar\">\n                    <div class=\"tag\"><i class=\"fa-solid fa-microscope\"></i> 实训基地与成果展示</div>\n                    <div class=\"pagination\"><span class=\"current-page\">05</span><span>/</span><span class=\"total-pages\">07</span></div>\n                </div>\n\n                <div class=\"page-head\">\n                    <div class=\"title-wrap\">\n                        <div class=\"page-title\">{{ page_title_training }}</div>\n                        <div class=\"page-subtitle\">本页保留图表位，可替换为学生规模、就业率、项目数、竞赛成果、合作企业数量等数据。</div>\n                    </div>\n                </div>\n\n                <div class=\"page-content\">\n                    <div class=\"grid-2\">\n                        <div class=\"card section-card\">\n                            <div class=\"section-title\"><i class=\"fa-solid fa-warehouse\"></i> 实训条件与基地建设</div>\n                            <div class=\"timeline\">\n                                <div class=\"timeline-item\">\n                                    <div class=\"timeline-index\">01</div>\n                                    <div>\n                                        <h4>{{ training_title_1 }}</h4>\n                                        <p>{{ training_desc_1 }}</p>\n                                    </div>\n                                </div>\n                                <div class=\"timeline-item\">\n                                    <div class=\"timeline-index\">02</div>\n                                    <div>\n                                        <h4>{{ training_title_2 }}</h4>\n                                        <p>{{ training_desc_2 }}</p>\n                                    </div>\n                                </div>\n                                <div class=\"timeline-item\">\n                                    <div class=\"timeline-index\">03</div>\n                                    <div>\n                                        <h4>{{ training_title_3 }}</h4>\n                                        <p>{{ training_desc_3 }}</p>\n                                    </div>\n                                </div>\n                            </div>\n                        </div>\n\n                        <div class=\"card chart-panel\">\n                            <div class=\"section-title\"><i class=\"fa-solid fa-chart-column\"></i> {{ chart_title }}</div>\n                            <div class=\"chart-box\">\n                                <canvas id=\"trainingChart\"></canvas>\n                            </div>\n                            <div class=\"chart-caption\">{{ chart_caption }}</div>\n                        </div>\n                    </div>\n                </div>\n            </section>\n\n            <!-- Slide 6: achievements and employment -->\n            <section class=\"slide\" data-title=\"质量成效\">\n                <div class=\"bg-orb orb-a\"></div>\n                <div class=\"bg-grid\"></div>\n                <div class=\"bg-pill\"></div>\n\n                <div class=\"topbar\">\n                    <div class=\"tag\"><i class=\"fa-solid fa-trophy\"></i> 教学质量与就业成效</div>\n                    <div class=\"pagination\"><span class=\"current-page\">06</span><span>/</span><span class=\"total-pages\">07</span></div>\n                </div>\n\n                <div class=\"page-head\">\n                    <div class=\"title-wrap\">\n                        <div class=\"page-title\">{{ page_title_quality }}</div>\n                        <div class=\"page-subtitle\">可替换为技能竞赛、证书获取、升学就业、科研服务、社会培训等成果数据。</div>\n                    </div>\n                </div>\n\n                <div class=\"page-content\">\n                    <div class=\"grid-4\">\n                        <div class=\"card metric-card\">\n                            <div class=\"metric-top\"><div class=\"metric-icon teal\"><i class=\"fa-solid fa-medal\"></i></div></div>\n                            <div class=\"metric-value\">{{ quality_1_value }}</div>\n                            <div class=\"metric-label\">{{ quality_1_label }}</div>\n                            <div class=\"metric-desc\">{{ quality_1_desc }}</div>\n                        </div>\n                        <div class=\"card metric-card\">\n                            <div class=\"metric-top\"><div class=\"metric-icon blue\"><i class=\"fa-solid fa-certificate\"></i></div></div>\n                            <div class=\"metric-value\">{{ quality_2_value }}</div>\n                            <div class=\"metric-label\">{{ quality_2_label }}</div>\n                            <div class=\"metric-desc\">{{ quality_2_desc }}</div>\n                        </div>\n                        <div class=\"card metric-card\">\n                            <div class=\"metric-top\"><div class=\"metric-icon gold\"><i class=\"fa-solid fa-briefcase\"></i></div></div>\n                            <div class=\"metric-value\">{{ quality_3_value }}</div>\n                            <div class=\"metric-label\">{{ quality_3_label }}</div>\n                            <div class=\"metric-desc\">{{ quality_3_desc }}</div>\n                        </div>\n                        <div class=\"card metric-card\">\n                            <div class=\"metric-top\"><div class=\"metric-icon red\"><i class=\"fa-solid fa-users\"></i></div></div>\n                            <div class=\"metric-value\">{{ quality_4_value }}</div>\n                            <div class=\"metric-label\">{{ quality_4_label }}</div>\n                            <div class=\"metric-desc\">{{ quality_4_desc }}</div>\n                        </div>\n                    </div>\n\n                    <div class=\"grid-2\" style=\"margin-top: 18px; height: calc(100% - 182px);\">\n                        <div class=\"card section-card\">\n                            <div class=\"section-title\"><i class=\"fa-solid fa-check-double\"></i> 成果摘要</div>\n                            <ul class=\"bullet-list\">\n                                <li>{{ result_point_1 }}</li>\n                                <li>{{ result_point_2 }}</li>\n                                <li>{{ result_point_3 }}</li>\n                                <li>{{ result_point_4 }}</li>\n                            </ul>\n                        </div>\n                        <div class=\"card section-card\">\n                            <div class=\"section-title\"><i class=\"fa-solid fa-people-group\"></i> 用人单位评价 / 社会服务</div>\n                            <ul class=\"bullet-list\">\n                                <li>{{ service_point_1 }}</li>\n                                <li>{{ service_point_2 }}</li>\n                                <li>{{ service_point_3 }}</li>\n                                <li>{{ service_point_4 }}</li>\n                            </ul>\n                        </div>\n                    </div>\n                </div>\n            </section>\n\n            <!-- Slide 7: planning -->\n            <section class=\"slide\" data-title=\"发展规划\">\n                <div class=\"bg-orb orb-a\"></div>\n                <div class=\"bg-orb orb-b\"></div>\n                <div class=\"bg-wave\"></div>\n\n                <div class=\"topbar\">\n                    <div class=\"tag\"><i class=\"fa-solid fa-route\"></i> 发展规划</div>\n                    <div class=\"pagination\"><span class=\"current-page\">07</span><span>/</span><span class=\"total-pages\">07</span></div>\n                </div>\n\n                <div class=\"page-head\">\n                    <div class=\"title-wrap\">\n                        <div class=\"page-title\">{{ page_title_plan }}</div>\n                        <div class=\"page-subtitle\">适用于年度重点任务、申报计划、国际合作、专业升级与基地建设路线图展示。</div>\n                    </div>\n                </div>\n\n                <div class=\"page-content\">\n                    <div class=\"target-list\">\n                        <div class=\"target-item\">\n                            <div class=\"num\">01</div>\n                            <div>\n                                <h4>{{ plan_title_1 }}</h4>\n                                <p>{{ plan_desc_1 }}</p>\n                            </div>\n                        </div>\n                        <div class=\"target-item\">\n                            <div class=\"num\">02</div>\n                            <div>\n                                <h4>{{ plan_title_2 }}</h4>\n                                <p>{{ plan_desc_2 }}</p>\n                            </div>\n                        </div>\n                        <div class=\"target-item\">\n                            <div class=\"num\">03</div>\n                            <div>\n                                <h4>{{ plan_title_3 }}</h4>\n                                <p>{{ plan_desc_3 }}</p>\n                            </div>\n                        </div>\n                        <div class=\"target-item\">\n                            <div class=\"num\">04</div>\n                            <div>\n                                <h4>{{ plan_title_4 }}</h4>\n                                <p>{{ plan_desc_4 }}</p>\n                            </div>\n                        </div>\n                        <div class=\"target-item\">\n                            <div class=\"num\">05</div>\n                            <div>\n                                <h4>{{ plan_title_5 }}</h4>\n                                <p>{{ plan_desc_5 }}</p>\n                            </div>\n                        </div>\n                        <div class=\"target-item\">\n                            <div class=\"num\">06</div>\n                            <div>\n                                <h4>{{ plan_title_6 }}</h4>\n                                <p>{{ plan_desc_6 }}</p>\n                            </div>\n                        </div>\n                    </div>\n                </div>\n                <div class=\"nav-hint\"><i class=\"fa-solid fa-keyboard\"></i> 支持键盘 ← →、空格、点击圆点或按钮切换页面</div>\n            </section>\n        </div>\n    </div>\n\n    <div class=\"nav-controls\">\n        <button class=\"nav-btn\" id=\"prevBtn\" aria-label=\"上一页\"><i class=\"fa-solid fa-chevron-up\"></i></button>\n        <button class=\"nav-btn\" id=\"nextBtn\" aria-label=\"下一页\"><i class=\"fa-solid fa-chevron-down\"></i></button>\n    </div>\n    <div class=\"dot-nav\" id=\"dotNav\"></div>\n\n    <script>\n        const deck = document.getElementById(\'deck\');\n        const slides = Array.from(document.querySelectorAll(\'.slide\'));\n        const dotNav = document.getElementById(\'dotNav\');\n        let currentIndex = 0;\n\n        function scaleDeck() {\n            const width = 1280;\n            const height = 720;\n            const scale = Math.min(window.innerWidth / width, window.innerHeight / height);\n            deck.style.transform = `scale(${scale})`;\n        }\n\n        function buildDots() {\n            dotNav.innerHTML = \'\';\n            slides.forEach((slide, index) => {\n                const dot = document.createElement(\'button\');\n                dot.className = \'dot\';\n                dot.type = \'button\';\n                dot.title = slide.dataset.title || `第 ${index + 1} 页`;\n                dot.addEventListener(\'click\', () => goToSlide(index));\n                dotNav.appendChild(dot);\n            });\n        }\n\n        function updateDots() {\n            const dots = Array.from(document.querySelectorAll(\'.dot\'));\n            dots.forEach((dot, index) => {\n                dot.classList.toggle(\'active\', index === currentIndex);\n            });\n        }\n\n        function goToSlide(index) {\n            if (index < 0) index = 0;\n            if (index > slides.length - 1) index = slides.length - 1;\n            currentIndex = index;\n            slides.forEach((slide, i) => slide.classList.toggle(\'active\', i === currentIndex));\n            updateDots();\n        }\n\n        function nextSlide() {\n            goToSlide(Math.min(currentIndex + 1, slides.length - 1));\n        }\n\n        function prevSlide() {\n            goToSlide(Math.max(currentIndex - 1, 0));\n        }\n\n        document.getElementById(\'nextBtn\').addEventListener(\'click\', nextSlide);\n        document.getElementById(\'prevBtn\').addEventListener(\'click\', prevSlide);\n\n        window.addEventListener(\'keydown\', (e) => {\n            if ([\'ArrowRight\', \'ArrowDown\', \'PageDown\', \' \'].includes(e.key)) {\n                e.preventDefault();\n                nextSlide();\n            }\n            if ([\'ArrowLeft\', \'ArrowUp\', \'PageUp\'].includes(e.key)) {\n                e.preventDefault();\n                prevSlide();\n            }\n        });\n\n        let wheelLocked = false;\n        window.addEventListener(\'wheel\', (e) => {\n            if (wheelLocked) return;\n            wheelLocked = true;\n            setTimeout(() => wheelLocked = false, 320);\n            if (Math.abs(e.deltaY) < 10) return;\n            if (e.deltaY > 0) nextSlide();\n            else prevSlide();\n        }, { passive: true });\n\n        buildDots();\n        goToSlide(0);\n        scaleDeck();\n        window.addEventListener(\'resize\', scaleDeck);\n\n        // 图表示例：实际使用时可将 labels / data 替换为真实数据\n        const chartCanvas = document.getElementById(\'trainingChart\');\n        if (chartCanvas && window.Chart) {\n            new Chart(chartCanvas, {\n                type: \'bar\',\n                data: {\n                    labels: [\'实训室\', \'合作企业\', \'技能竞赛\', \'证书通过率\', \'就业质量\'],\n                    datasets: [{\n                        label: \'示例数据\',\n                        data: [12, 18, 9, 88, 92],\n                        backgroundColor: [\n                            \'rgba(15, 118, 110, 0.72)\',\n                            \'rgba(20, 184, 166, 0.68)\',\n                            \'rgba(14, 165, 233, 0.68)\',\n                            \'rgba(245, 158, 11, 0.70)\',\n                            \'rgba(239, 68, 68, 0.62)\'\n                        ],\n                        borderColor: [\n                            \'rgb(15, 118, 110)\',\n                            \'rgb(20, 184, 166)\',\n                            \'rgb(14, 165, 233)\',\n                            \'rgb(245, 158, 11)\',\n                            \'rgb(239, 68, 68)\'\n                        ],\n                        borderWidth: 2,\n                        borderRadius: 10\n                    }]\n                },\n                options: {\n                    responsive: true,\n                    maintainAspectRatio: false,\n                    plugins: {\n                        legend: { display: false },\n                        tooltip: {\n                            backgroundColor: \'rgba(24,49,59,0.92)\',\n                            titleColor: \'#fff\',\n                            bodyColor: \'#fff\',\n                            padding: 12,\n                            displayColors: false\n                        }\n                    },\n                    scales: {\n                        x: {\n                            grid: { display: false },\n                            ticks: { color: \'#58707d\', font: { family: \'Nunito\', size: 12, weight: \'700\' } }\n                        },\n                        y: {\n                            beginAtZero: true,\n                            grid: { color: \'rgba(24,49,59,0.08)\' },\n                            ticks: { color: \'#58707d\', font: { family: \'Nunito\', size: 12, weight: \'700\' } }\n                        }\n                    }\n                }\n            });\n        }\n    </script>\n</body>\n</html>\n','data:image/svg+xml;base64,','{\"dimensions\": \"1280x720\", \"aspect_ratio\": \"16:9\", \"framework\": \"HTML + CSS\", \"colors\": [\"var(--ink)\", \"linear-gradient(rgba(15,118,110,0.08) 1px, transparent 1px),\\n                linear-gradient(90deg, rgba(15,118,110,0.08) 1px, transparent 1px)\", \"radial-gradient(circle at top left, #f8fafc 0%, #edf5f2 45%, #e7eef5 100%)\", \"rgba(14,165,233,0.18)\", \"rgba(245,158,11,0.20)\", \"linear-gradient(180deg, rgba(20,184,166,0) 0%, rgba(20,184,166,0.08) 40%, rgba(14,165,233,0.10) 100%)\", \"var(--slide-bg)\", \"rgba(20,184,166,0.08)\", \"18px 18px\", \"rgba(20,184,166,0.22)\"], \"fonts\": [\"\'Nunito\', \'Microsoft YaHei\', sans-serif\"]}','[]',0,1,0,'user',1773650000,1773650000),(29,'食品药品2','','<!DOCTYPE html>\n<html lang=\"zh-CN\">\n<head>\n    <meta charset=\"UTF-8\">\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n    <title>食品药品职业学院PPT模板描述文件</title>\n\n    <!-- 引入字体与图标库 -->\n    <link rel=\"preconnect\" href=\"https://fonts.googleapis.com\">\n    <link rel=\"preconnect\" href=\"https://fonts.gstatic.com\" crossorigin>\n    <link href=\"https://fonts.googleapis.com/css2?family=Noto+Sans+SC:wght@400;500;700;900&display=swap\" rel=\"stylesheet\">\n    <link rel=\"stylesheet\" href=\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css\">\n\n    <!-- 引入图表库（用于模块预留示例） -->\n    <script src=\"https://cdn.jsdelivr.net/npm/chart.js\"></script>\n\n    <style>\n        /*\n         * 本文件不是“可直接播放的多页PPT页面”，而是“PPT模板描述页”。\n         * 写法参照 template.html：\n         * 1. 单文件、自包含；\n         * 2. 1280×720 固定画布；\n         * 3. 使用占位符描述模板结构与模块能力；\n         * 4. 保留图标、图表、分页与响应式缩放脚本，便于后续自动化生成系统复用。\n         */\n\n        /* 1. 基础与重置样式 */\n        * {\n            margin: 0;\n            padding: 0;\n            box-sizing: border-box;\n        }\n\n        html, body {\n            width: 100%;\n            height: 100%;\n            overflow: hidden;\n            background: #eef1ed;\n            font-family: \'Noto Sans SC\', sans-serif;\n            color: #26412f;\n        }\n\n        /* 2. 响应式缩放容器 */\n        .slide-container {\n            width: 100vw;\n            height: 100vh;\n            display: flex;\n            justify-content: center;\n            align-items: center;\n        }\n\n        /* 3. 幻灯片核心画布（严格 1280×720） */\n        .slide {\n            width: 1280px;\n            height: 720px;\n            background: #fbfcf8;\n            position: relative;\n            overflow: hidden;\n            transform-origin: center center;\n            box-shadow: 0 10px 30px rgba(0, 0, 0, 0.12);\n        }\n\n        /* 4. 主题装饰元素：参照原PPT中的绿色圆形与左上角叶片造型 */\n        .top-strip,\n        .bottom-strip {\n            position: absolute;\n            left: 0;\n            width: 100%;\n            height: 8px;\n            background: linear-gradient(to right, rgba(130, 130, 130, 0.12), rgba(130, 130, 130, 0.45), rgba(130, 130, 130, 0.12));\n            z-index: 1;\n        }\n        .top-strip { top: 132px; }\n        .bottom-strip { bottom: 132px; }\n\n        .deco-circle {\n            position: absolute;\n            border-radius: 50%;\n            z-index: 1;\n        }\n        .circle-a { width: 280px; height: 280px; right: 120px; top: -80px; background: #3d7a45; }\n        .circle-b { width: 210px; height: 210px; right: 220px; top: 18px; background: #8cb043; opacity: 0.95; }\n        .circle-c { width: 86px; height: 86px; right: 52px; top: 42px; background: #cfdc72; }\n        .circle-d { width: 54px; height: 54px; left: 36px; top: 18px; background: #7eb377; }\n        .circle-e { width: 150px; height: 150px; left: 70px; bottom: -58px; background: #93bf84; }\n        .circle-f { width: 270px; height: 270px; left: 230px; bottom: -120px; background: #3f7345; opacity: 0.92; }\n        .circle-g { width: 190px; height: 190px; left: 360px; bottom: -90px; background: #9eb841; opacity: 0.85; }\n        .circle-h { width: 76px; height: 76px; right: 86px; bottom: 46px; background: #d8de7f; }\n\n        .leaf-mark {\n            position: absolute;\n            top: 32px;\n            left: 44px;\n            width: 70px;\n            height: 48px;\n            z-index: 3;\n        }\n        .leaf-mark::before,\n        .leaf-mark::after,\n        .leaf-mark span {\n            content: \'\';\n            position: absolute;\n            border-radius: 0 0 40px 0;\n        }\n        .leaf-mark::before {\n            left: 0;\n            top: 0;\n            width: 32px;\n            height: 32px;\n            background: #d8df79;\n        }\n        .leaf-mark::after {\n            left: 18px;\n            top: 0;\n            width: 34px;\n            height: 34px;\n            background: #89a95d;\n        }\n        .leaf-mark span {\n            left: 32px;\n            top: 0;\n            width: 38px;\n            height: 38px;\n            background: #426f4b;\n        }\n\n        /* 5. 页眉信息区 */\n        .header-band {\n            position: absolute;\n            left: 78px;\n            top: 34px;\n            right: 100px;\n            display: flex;\n            align-items: center;\n            justify-content: space-between;\n            z-index: 4;\n        }\n\n        .logo-group {\n            display: flex;\n            align-items: center;\n            gap: 14px;\n        }\n\n        .logo-badge {\n            width: 48px;\n            height: 48px;\n            border-radius: 50%;\n            border: 2px solid #5f8e4f;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            color: #5f8e4f;\n            background: rgba(255,255,255,0.95);\n            font-size: 22px;\n        }\n\n        .logo-text {\n            line-height: 1.2;\n        }\n        .logo-text .cn {\n            font-size: 15px;\n            font-weight: 700;\n            color: #527845;\n        }\n        .logo-text .en {\n            font-size: 10px;\n            color: #7d8a79;\n            letter-spacing: 0.4px;\n        }\n\n        .template-meta {\n            text-align: right;\n        }\n        .template-meta .meta-title {\n            font-size: 16px;\n            font-weight: 700;\n            color: #587d48;\n        }\n        .template-meta .meta-subtitle {\n            margin-top: 4px;\n            font-size: 11px;\n            color: #98a095;\n            letter-spacing: 0.8px;\n        }\n\n        /* 6. 主体内容区 */\n        .content-area {\n            position: absolute;\n            top: 156px;\n            left: 68px;\n            right: 68px;\n            bottom: 64px;\n            z-index: 4;\n            display: grid;\n            grid-template-columns: 1.15fr 1fr;\n            gap: 28px;\n        }\n\n        .left-panel,\n        .right-panel {\n            background: rgba(255,255,255,0.78);\n            border: 1px solid rgba(96, 129, 79, 0.14);\n            border-radius: 20px;\n            padding: 24px 26px;\n            backdrop-filter: blur(2px);\n        }\n\n        .page-title {\n            display: inline-flex;\n            align-items: center;\n            gap: 14px;\n            margin-bottom: 16px;\n        }\n        .page-title .num {\n            width: 72px;\n            height: 72px;\n            border-radius: 50%;\n            background: #55824a;\n            color: white;\n            font-size: 36px;\n            font-weight: 900;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            box-shadow: inset 0 -8px 0 rgba(255,255,255,0.12);\n        }\n        .page-title .text h1 {\n            font-size: 30px;\n            line-height: 1.2;\n            color: #4f7b45;\n            font-weight: 900;\n        }\n        .page-title .text p {\n            font-size: 14px;\n            color: #90a28a;\n            margin-top: 6px;\n        }\n\n        .summary-box {\n            background: #f6f8f1;\n            border-left: 6px solid #7fa64d;\n            border-radius: 14px;\n            padding: 14px 16px;\n            margin-bottom: 16px;\n        }\n        .summary-box p {\n            font-size: 15px;\n            line-height: 1.75;\n            color: #516250;\n        }\n\n        .section-title {\n            display: flex;\n            align-items: center;\n            gap: 10px;\n            margin: 14px 0 12px;\n            font-size: 18px;\n            font-weight: 800;\n            color: #4e7543;\n        }\n        .section-title .dot {\n            width: 10px;\n            height: 10px;\n            border-radius: 50%;\n            background: #8dae48;\n        }\n\n        .rule-list {\n            list-style: none;\n        }\n        .rule-list li {\n            font-size: 14px;\n            line-height: 1.7;\n            color: #4f5d50;\n            margin-bottom: 8px;\n            padding-left: 22px;\n            position: relative;\n        }\n        .rule-list li::before {\n            content: \'\';\n            position: absolute;\n            left: 0;\n            top: 9px;\n            width: 10px;\n            height: 10px;\n            border-radius: 50%;\n            background: #6e9a57;\n        }\n\n        .palette-grid {\n            display: grid;\n            grid-template-columns: repeat(5, 1fr);\n            gap: 10px;\n            margin-top: 12px;\n        }\n        .swatch {\n            border-radius: 12px;\n            padding: 10px 8px;\n            color: rgba(255,255,255,0.95);\n            font-size: 11px;\n            line-height: 1.35;\n            min-height: 66px;\n            display: flex;\n            flex-direction: column;\n            justify-content: end;\n            box-shadow: inset 0 -10px 18px rgba(0,0,0,0.08);\n        }\n        .swatch.light {\n            color: #56614d;\n            border: 1px solid rgba(83, 111, 64, 0.12);\n            box-shadow: none;\n        }\n\n        .module-grid {\n            display: grid;\n            grid-template-columns: repeat(2, minmax(0, 1fr));\n            gap: 12px;\n            margin-bottom: 16px;\n        }\n        .module-card {\n            border-radius: 16px;\n            background: #f8faf4;\n            border: 1px solid rgba(89, 121, 71, 0.14);\n            padding: 14px 14px 12px;\n            min-height: 106px;\n            position: relative;\n        }\n        .module-card .tag {\n            display: inline-block;\n            padding: 3px 8px;\n            border-radius: 999px;\n            background: #dfe9ca;\n            color: #507247;\n            font-size: 11px;\n            font-weight: 700;\n            margin-bottom: 8px;\n        }\n        .module-card h3 {\n            font-size: 16px;\n            line-height: 1.3;\n            color: #4b7442;\n            margin-bottom: 6px;\n        }\n        .module-card p {\n            font-size: 12px;\n            line-height: 1.6;\n            color: #667163;\n        }\n        .module-card .mini-circle {\n            position: absolute;\n            right: 10px;\n            top: 10px;\n            width: 18px;\n            height: 18px;\n            border-radius: 50%;\n            background: #87af62;\n            opacity: 0.8;\n        }\n\n        .chart-panel {\n            display: grid;\n            grid-template-columns: 210px 1fr;\n            gap: 14px;\n            align-items: center;\n            background: #f6f8f2;\n            border-radius: 18px;\n            padding: 16px;\n            border: 1px solid rgba(96, 129, 79, 0.14);\n        }\n        .chart-meta h4 {\n            font-size: 16px;\n            color: #4e7543;\n            margin-bottom: 8px;\n        }\n        .chart-meta ul {\n            list-style: none;\n        }\n        .chart-meta li {\n            font-size: 13px;\n            line-height: 1.7;\n            color: #60705f;\n            margin-bottom: 4px;\n        }\n\n        .placeholder-box {\n            margin-top: 14px;\n            border-radius: 16px;\n            padding: 14px 16px;\n            background: linear-gradient(135deg, rgba(133,168,92,0.13), rgba(70,108,63,0.08));\n            border: 1px dashed rgba(90, 122, 70, 0.35);\n        }\n        .placeholder-box code {\n            display: inline-block;\n            background: rgba(255,255,255,0.82);\n            padding: 4px 8px;\n            border-radius: 8px;\n            font-size: 12px;\n            color: #436248;\n            margin: 4px 6px 0 0;\n        }\n\n        .pagination {\n            position: absolute;\n            right: 36px;\n            bottom: 22px;\n            z-index: 5;\n            font-size: 18px;\n            font-weight: 700;\n            color: #94a08e;\n            background: rgba(255,255,255,0.9);\n            padding: 6px 14px;\n            border-radius: 20px;\n        }\n\n        .footer-note {\n            position: absolute;\n            left: 74px;\n            bottom: 22px;\n            z-index: 5;\n            font-size: 12px;\n            color: #9aa596;\n            letter-spacing: 0.2px;\n        }\n    </style>\n</head>\n<body>\n    <div class=\"slide-container\">\n        <div class=\"slide\">\n            <!-- 主题装饰层 -->\n            <div class=\"top-strip\"></div>\n            <div class=\"bottom-strip\"></div>\n            <div class=\"deco-circle circle-a\"></div>\n            <div class=\"deco-circle circle-b\"></div>\n            <div class=\"deco-circle circle-c\"></div>\n            <div class=\"deco-circle circle-d\"></div>\n            <div class=\"deco-circle circle-e\"></div>\n            <div class=\"deco-circle circle-f\"></div>\n            <div class=\"deco-circle circle-g\"></div>\n            <div class=\"deco-circle circle-h\"></div>\n            <div class=\"leaf-mark\"><span></span></div>\n\n            <!-- 页眉占位信息 -->\n            <div class=\"header-band\">\n                <div class=\"logo-group\">\n                    <div class=\"logo-badge\"><i class=\"fa-solid fa-mortar-pestle\"></i></div>\n                    <div class=\"logo-text\">\n                        <div class=\"cn\">{{ school_name }}</div>\n                        <div class=\"en\">{{ school_name_en }}</div>\n                    </div>\n                </div>\n                <div class=\"template-meta\">\n                    <div class=\"meta-title\">{{ template_name }}</div>\n                    <div class=\"meta-subtitle\">GREEN · MINIMAL · CIRCLE-DRIVEN · SECTIONAL REPORT</div>\n                </div>\n            </div>\n\n            <!-- 主体内容 -->\n            <div class=\"content-area\">\n                <div class=\"left-panel\">\n                    <div class=\"page-title\">\n                        <div class=\"num\">{{ section_no }}</div>\n                        <div class=\"text\">\n                            <h1>{{ descriptor_title }}</h1>\n                            <p>{{ descriptor_subtitle }}</p>\n                        </div>\n                    </div>\n\n                    <div class=\"summary-box\">\n                        <p>\n                            {{ template_summary }}\n                        </p>\n                    </div>\n\n                    <div class=\"section-title\"><span class=\"dot\"></span>模板风格规则</div>\n                    <ul class=\"rule-list\">\n                        <li>整体采用白底浅灰留白，主色以深绿、草绿、浅绿、黄绿为核心，视觉关键词为“清洁、规范、生态、专业”。</li>\n                        <li>章节页使用“大号圆形数字 + 中文章节标题”的组合形式；目录页与封面页均以圆形群组作为主视觉中心。</li>\n                        <li>内容页统一保留左上角叶片标识，适合工作总结、专业建设、实训成果、课程规划、项目申报等场景。</li>\n                        <li>图文模块偏向圆形、环形、时间轴、百分比、步骤节点与图片拼贴，不适合高密度长段落排版。</li>\n                    </ul>\n\n                    <div class=\"section-title\"><span class=\"dot\"></span>推荐色板</div>\n                    <div class=\"palette-grid\">\n                        <div class=\"swatch\" style=\"background:#3f7345;\">主绿<br>{{ color_primary }}</div>\n                        <div class=\"swatch\" style=\"background:#6d9d53;\">辅绿<br>{{ color_secondary }}</div>\n                        <div class=\"swatch\" style=\"background:#8db47f;\">浅绿<br>{{ color_accent }}</div>\n                        <div class=\"swatch light\" style=\"background:#d8df79;\">黄绿<br>{{ color_highlight }}</div>\n                        <div class=\"swatch light\" style=\"background:#f6f8f1;\">留白底<br>{{ color_bg }}</div>\n                    </div>\n\n                    <div class=\"placeholder-box\">\n                        <code>{{ cover_title }}</code>\n                        <code>{{ report_period }}</code>\n                        <code>{{ section_title }}</code>\n                        <code>{{ module_title }}</code>\n                        <code>{{ metric_value }}</code>\n                        <code>{{ item_desc }}</code>\n                        <code>{{ current_page_number }}</code>\n                        <code>{{ total_page_count }}</code>\n                    </div>\n                </div>\n\n                <div class=\"right-panel\">\n                    <div class=\"section-title\"><span class=\"dot\"></span>模块类型描述</div>\n                    <div class=\"module-grid\">\n                        <div class=\"module-card\">\n                            <span class=\"tag\">封面 / 章节封页</span>\n                            <span class=\"mini-circle\"></span>\n                            <h3>{{ module_cover_name }}</h3>\n                            <p>大面积圆形叠加 + 标题居中/偏左，适合“月度总结、学院汇报、项目方案、年度计划”。</p>\n                        </div>\n                        <div class=\"module-card\">\n                            <span class=\"tag\">目录页</span>\n                            <span class=\"mini-circle\"></span>\n                            <h3>{{ module_catalog_name }}</h3>\n                            <p>目录编号以 01–04 或 01–05 分布在圆点周围，适合四段式、五段式汇报结构。</p>\n                        </div>\n                        <div class=\"module-card\">\n                            <span class=\"tag\">内容结构页</span>\n                            <span class=\"mini-circle\"></span>\n                            <h3>{{ module_content_name }}</h3>\n                            <p>支持四卡片、五节点、环形流程、辐射式说明等结构化信息表达。</p>\n                        </div>\n                        <div class=\"module-card\">\n                            <span class=\"tag\">成果 / 数据页</span>\n                            <span class=\"mini-circle\"></span>\n                            <h3>{{ module_data_name }}</h3>\n                            <p>适配百分比指标、环形统计、里程碑完成度、课程与项目成果可视化。</p>\n                        </div>\n                        <div class=\"module-card\">\n                            <span class=\"tag\">图文展示页</span>\n                            <span class=\"mini-circle\"></span>\n                            <h3>{{ module_gallery_name }}</h3>\n                            <p>适合实训基地、实验室、教学活动、校企合作现场、药品食品工艺场景拼图展示。</p>\n                        </div>\n                        <div class=\"module-card\">\n                            <span class=\"tag\">计划 / 展望页</span>\n                            <span class=\"mini-circle\"></span>\n                            <h3>{{ module_plan_name }}</h3>\n                            <p>支持时间轴、分阶段目标、年度指标、重点项目与课程规划等模块。</p>\n                        </div>\n                    </div>\n\n                    <div class=\"chart-panel\">\n                        <div style=\"height:180px;\">\n                            <canvas id=\"moduleChart\"></canvas>\n                        </div>\n                        <div class=\"chart-meta\">\n                            <h4>{{ chart_title }}</h4>\n                            <ul>\n                                <li><i class=\"fa-solid fa-circle-check\"></i> 推荐用于“完成情况 / 模块占比 / 专业群构成 / 项目进度”</li>\n                                <li><i class=\"fa-solid fa-circle-check\"></i> 数值展示宜控制在 3–5 组，保持和原模板一样的轻量可读性</li>\n                                <li><i class=\"fa-solid fa-circle-check\"></i> 图表颜色应限定在同一绿色系，避免跳色破坏模板统一感</li>\n                            </ul>\n                        </div>\n                    </div>\n                </div>\n            </div>\n\n            <div class=\"footer-note\">本文件用于描述“食品药品职业学院PPT模板”的版式语言与模块规范，供后续自动化生成新PPT时调用。</div>\n\n            <div class=\"pagination\">\n                <span>{{ current_page_number }}</span> / <span>{{ total_page_count }}</span>\n            </div>\n        </div>\n    </div>\n\n    <script>\n        // 保持 16:9 幻灯片在任意屏幕中按比例缩放\n        function scaleSlide() {\n            const slide = document.querySelector(\'.slide\');\n            const container = document.querySelector(\'.slide-container\');\n\n            const slideWidth = 1280;\n            const slideHeight = 720;\n            const containerWidth = container.offsetWidth;\n            const containerHeight = container.offsetHeight;\n            const scale = Math.min(containerWidth / slideWidth, containerHeight / slideHeight);\n\n            slide.style.transform = `scale(${scale})`;\n        }\n\n        window.onload = scaleSlide;\n        window.onresize = scaleSlide;\n\n        // 图表仅作为“模块能力示例”，实际内容应由生成系统替换\n        const ctx = document.getElementById(\'moduleChart\');\n        if (ctx) {\n            new Chart(ctx, {\n                type: \'doughnut\',\n                data: {\n                    labels: [\'封面/目录\', \'结构内容页\', \'数据页\', \'图文页\'],\n                    datasets: [{\n                        data: [20, 35, 25, 20],\n                        backgroundColor: [\n                            \'rgba(63, 115, 69, 0.95)\',\n                            \'rgba(109, 157, 83, 0.92)\',\n                            \'rgba(141, 180, 127, 0.92)\',\n                            \'rgba(216, 223, 121, 0.92)\'\n                        ],\n                        borderColor: \'#fbfcf8\',\n                        borderWidth: 4,\n                        hoverOffset: 2\n                    }]\n                },\n                options: {\n                    responsive: true,\n                    maintainAspectRatio: false,\n                    plugins: {\n                        legend: {\n                            position: \'bottom\',\n                            labels: {\n                                color: \'#5d6a58\',\n                                boxWidth: 14,\n                                padding: 16,\n                                font: {\n                                    family: \'Noto Sans SC\',\n                                    size: 11\n                                }\n                            }\n                        }\n                    },\n                    cutout: \'60%\'\n                }\n            });\n        }\n    </script>\n</body>\n</html>\n','data:image/svg+xml;base64,','{\"dimensions\": \"1280x720\", \"aspect_ratio\": \"16:9\", \"framework\": \"HTML + CSS\", \"colors\": [\"#3d7a45\", \"#3f7345\", \"#cfdc72\", \"linear-gradient(to right, rgba(130, 130, 130, 0.12), rgba(130, 130, 130, 0.45), rgba(130, 130, 130, 0.12))\", \"#fbfcf8\", \"#7eb377\", \"#26412f\", \"#93bf84\", \"#eef1ed\", \"#8cb043\"], \"fonts\": [\"\'Noto Sans SC\', sans-serif\"]}','[]',0,1,1,'user',1773650000,1773650000),(30,'食品药品_v4','','<!DOCTYPE html>\n<html lang=\"zh-CN\">\n<head>\n<meta charset=\"UTF-8\" />\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\n<title>食品药品职业学院PPT模板描述文件（字段规范版）</title>\n<style>\n    * { margin: 0; padding: 0; box-sizing: border-box; }\n    html, body {\n        width: 100%;\n        height: 100%;\n        overflow: hidden;\n        background: #edf1eb;\n        font-family: \"Microsoft YaHei\", \"PingFang SC\", \"Noto Sans SC\", sans-serif;\n        color: #335239;\n    }\n    .slide-container {\n        width: 100vw;\n        height: 100vh;\n        display: flex;\n        align-items: center;\n        justify-content: center;\n    }\n    .slide {\n        width: 1280px;\n        height: 720px;\n        position: relative;\n        overflow: hidden;\n        transform-origin: center center;\n        border-radius: 16px;\n        background: linear-gradient(180deg, #f8faf6 0%, #f2f5ef 100%);\n        box-shadow: 0 18px 42px rgba(0,0,0,.14);\n    }\n\n    .header {\n        position: absolute;\n        left: 30px;\n        right: 30px;\n        top: 24px;\n        display: grid;\n        grid-template-columns: 1fr auto;\n        gap: 20px;\n        align-items: start;\n        z-index: 30;\n    }\n    .header h1 {\n        font-size: 28px;\n        line-height: 1.2;\n        color: #48724a;\n        font-weight: 900;\n        letter-spacing: .4px;\n    }\n    .header p {\n        margin-top: 7px;\n        font-size: 12px;\n        color: #7e8e7f;\n        line-height: 1.55;\n        max-width: 650px;\n    }\n\n    .main-tabs {\n        display: flex;\n        gap: 10px;\n        align-items: center;\n        flex-wrap: wrap;\n        justify-content: flex-end;\n    }\n    .main-tab {\n        border: 1px solid rgba(90,121,80,.18);\n        background: rgba(255,255,255,.92);\n        color: #5f7860;\n        border-radius: 999px;\n        padding: 9px 16px;\n        font-size: 14px;\n        font-weight: 800;\n        cursor: pointer;\n        transition: all .18s ease;\n    }\n    .main-tab.active {\n        background: #4e7b47;\n        color: #fff;\n        box-shadow: 0 8px 18px rgba(78,123,71,.28);\n    }\n\n    .workspace {\n        position: absolute;\n        left: 28px;\n        right: 28px;\n        top: 98px;\n        bottom: 26px;\n        display: grid;\n        grid-template-columns: 400px 1fr;\n        gap: 18px;\n    }\n\n    .panel {\n        background: rgba(255,255,255,.9);\n        border: 1px solid rgba(87,124,79,.12);\n        border-radius: 24px;\n        overflow: hidden;\n    }\n\n    .rules-panel {\n        padding: 18px 12px 16px 18px;\n        display: flex;\n        flex-direction: column;\n        gap: 12px;\n        overflow: auto;\n        scrollbar-width: thin;\n        scrollbar-color: #c6d6bf transparent;\n    }\n    .rules-panel::-webkit-scrollbar { width: 8px; }\n    .rules-panel::-webkit-scrollbar-thumb { background: #c6d6bf; border-radius: 999px; }\n\n    .group-card {\n        background: linear-gradient(180deg, #f6faf4 0%, #f2f7ef 100%);\n        border: 1px solid #e3ece0;\n        border-radius: 18px;\n        padding: 14px 14px 12px;\n    }\n    .group-top {\n        display: flex;\n        align-items: center;\n        justify-content: space-between;\n        gap: 12px;\n        margin-bottom: 8px;\n    }\n    .group-badge {\n        display: inline-flex;\n        align-items: center;\n        gap: 10px;\n        color: #4d7048;\n        font-size: 14px;\n        font-weight: 900;\n    }\n    .group-badge i {\n        width: 10px;\n        height: 10px;\n        border-radius: 50%;\n        background: #7da965;\n        display: inline-block;\n    }\n    .subtype-counter {\n        font-size: 11px;\n        color: #7f8f7f;\n        background: #fff;\n        border: 1px solid #e3eade;\n        border-radius: 999px;\n        padding: 4px 9px;\n    }\n    .group-summary {\n        font-size: 12.5px;\n        color: #607163;\n        line-height: 1.72;\n    }\n\n    .subtype-wrap {\n        background: #f8fbf6;\n        border: 1px solid #e7eee3;\n        border-radius: 18px;\n        padding: 12px;\n    }\n    .subtype-wrap h3,\n    .rule-block h3 {\n        font-size: 13px;\n        color: #557850;\n        margin-bottom: 9px;\n        font-weight: 900;\n    }\n    .subtype-list {\n        display: flex;\n        flex-wrap: wrap;\n        gap: 8px;\n    }\n    .subtype-pill {\n        border: 1px solid #dfe7da;\n        background: #fff;\n        color: #647867;\n        border-radius: 999px;\n        padding: 7px 11px;\n        font-size: 11.5px;\n        font-weight: 700;\n        cursor: pointer;\n        transition: all .18s ease;\n    }\n    .subtype-pill.active {\n        background: #dbead3;\n        color: #406442;\n        border-color: #bdd4b2;\n        box-shadow: 0 6px 14px rgba(113,150,99,.16);\n    }\n\n    .rule-block {\n        background: #f7faf4;\n        border: 1px solid #e7eee3;\n        border-radius: 18px;\n        padding: 13px 14px;\n    }\n    .rule-block p,\n    .rule-block li {\n        font-size: 12.5px;\n        color: #607163;\n        line-height: 1.72;\n    }\n    .rule-block ul { list-style: none; }\n    .rule-block li {\n        position: relative;\n        padding-left: 12px;\n        margin-bottom: 4px;\n    }\n    .rule-block li::before {\n        content: \"\";\n        position: absolute;\n        left: 0;\n        top: 8px;\n        width: 5px;\n        height: 5px;\n        border-radius: 50%;\n        background: #7da864;\n    }\n\n    .token-list {\n        display: flex;\n        flex-wrap: wrap;\n        gap: 8px;\n    }\n    .token {\n        padding: 6px 10px;\n        background: #fff;\n        border-radius: 999p