; transform-origin: left center; }\n\n    .annotate-ring { position: absolute; left: 292px; top: 82px; width: 240px; height: 240px; border-radius: 50%; border: 18px solid #5d8f34; box-shadow: inset 0 0 0 20px #f8faf6; }\n    .annotate-ring::after { content: \"\"; position: absolute; right: 12px; top: 38px; width: 50px; height: 50px; border-radius: 50%; background: #4e874d; }\n    .annotate-title { position: absolute; left: 332px; top: 152px; font-size: 34px; color: #5e8b35; font-weight: 900; line-height: 1.08; text-align: center; }\n    .anno-line { position: absolute; height: 2px; background: #b6b3b3; }\n    .anno-cap { position: absolute; width: 8px; height: 8px; border-radius: 50%; background: #b6b3b3; }\n\n    .option-wheel { position: absolute; left: 298px; top: 68px; width: 250px; height: 250px; border-radius: 50%; background: conic-gradient(#8cb586 0 27%, #74b43f 27% 54%, #7e9f54 54% 78%, #568734 78% 100%); }\n    .option-wheel::after { content: \"\"; position: absolute; left: 84px; top: 84px; width: 82px; height: 82px; border-radius: 50%; background: #f8faf6; }\n    .option-badge { position: absolute; width: 68px; height: 68px; border-radius: 50%; background: #fff; border: 7px solid #f6f7f5; box-shadow: 0 0 0 5px #ffffff inset; }\n\n    .photo-label { position: absolute; left: 0; top: 180px; width: 392px; height: 112px; background: #8bb782; color: #fff; padding: 24px 24px 16px 128px; }\n    .photo-label::before { content: \"◔\"; position: absolute; left: 36px; top: 28px; font-size: 58px; font-weight: 900; }\n    .photo-grid { position: absolute; left: 0; right: 0; bottom: 28px; top: 180px; display: grid; grid-template-columns: repeat(6, 1fr); grid-template-rows: repeat(2, 1fr); gap: 0; }\n    .photo-grid div { background: linear-gradient(135deg, #e6e8e5, #cfd3d7 45%, #9ca3af); border-right: 1px solid rgba(255,255,255,.35); border-top: 1px solid rgba(255,255,255,.35); filter: grayscale(100%); }\n    .photo-grid .green { background: #8bb782; }\n\n    .project-left {\n        position: absolute; left: 0; top: 0; bottom: 0; width: 214px; background: #4d874d; color: #fff; padding: 24px 26px;\n    }\n    .project-board {\n        position: absolute; left: 214px; top: 48px; right: 28px; bottom: 40px; background: rgba(255,255,255,.88); box-shadow: 0 10px 18px rgba(0,0,0,.12);\n    }\n    .project-circles { position: absolute; left: 248px; right: 46px; top: 116px; display: grid; grid-template-columns: repeat(3, 1fr); gap: 24px; }\n    .project-circles div { height: 170px; border-radius: 50%; background: #9dbb9d; }\n\n    .future-topline { position: absolute; left: 70px; right: 70px; top: 102px; height: 1px; background: #b9d0b4; }\n    .future-head { position: absolute; top: 42px; left: 0; right: 0; text-align: center; color: #343434; font-size: 24px; font-weight: 900; }\n    .future-desc { position: absolute; top: 132px; left: 0; right: 0; text-align: center; color: #666; font-size: 12px; }\n    .future-dots { position: absolute; top: 174px; left: 0; right: 0; text-align: center; color: #87b483; font-size: 18px; letter-spacing: 6px; }\n    .future-cards { position: absolute; left: 70px; right: 70px; top: 208px; display: grid; grid-template-columns: repeat(4, 1fr); gap: 18px; }\n    .future-card { background: #fff; }\n    .future-card .hero { height: 112px; background: #4f864c; display: flex; align-items: center; justify-content: center; color: #fff; font-size: 34px; }\n    .future-card:nth-child(2) .hero, .future-card:nth-child(4) .hero { background: #8fbb88; }\n    .future-card .body { background: #eceeed; padding: 16px 16px 22px; }\n    .future-card strong { display: block; color: #567f57; font-size: 15px; margin-bottom: 10px; }\n    .future-card span { display: block; color: #727272; font-size: 11px; line-height: 1.6; }\n\n    .data-left-perc { position: absolute; left: 52px; top: 122px; width: 120px; display: flex; flex-direction: column; gap: 30px; }\n    .data-left-perc div { font-size: 34px; line-height: .98; color: #4f8948; font-weight: 900; }\n    .data-left-perc div.light { color: #8ab17f; }\n\n    .triple-circles .c { position: absolute; border-radius: 50%; border: 8px solid #4f8a49; }\n    .triple-circles .c1 { width: 160px; height: 160px; right: 114px; top: 116px; }\n    .triple-circles .c2 { width: 160px; height: 160px; right: 224px; top: 238px; }\n    .triple-circles .c3 { width: 160px; height: 160px; right: 18px; top: 236px; border-color: #88b885; }\n\n    .semi-rings { position: absolute; left: 48px; top: 120px; width: 338px; height: 250px; }\n    .semi-rings .r { position: absolute; border-radius: 50%; border-style: solid; border-color: transparent transparent transparent transparent; border-left-color: #b9d1aa; border-top-color: #b9d1aa; }\n    .semi-rings .r1 { width: 260px; height: 260px; left: 0; top: -10px; border-width: 20px; }\n    .semi-rings .r2 { width: 212px; height: 212px; left: 24px; top: 14px; border-width: 18px; border-left-color: #a8ca92; border-top-color: #a8ca92; }\n    .semi-rings .r3 { width: 168px; height: 168px; left: 46px; top: 36px; border-width: 18px; border-left-color: #8db57e; border-top-color: #8db57e; }\n    .semi-rings .r4 { width: 122px; height: 122px; left: 70px; top: 60px; border-width: 18px; border-left-color: #5b8f36; border-top-color: #5b8f36; }\n    .semi-dots { position: absolute; left: 164px; top: 222px; display: flex; gap: 22px; }\n    .semi-dots span { width: 14px; height: 14px; border-radius: 50%; background: #5c8d36; position: relative; }\n    .semi-dots span::after { content: \"\"; position: absolute; left: 13px; top: 6px; width: 48px; height: 1px; background: #cdd5c8; }\n    .semi-dots span:last-child::after { display: none; }\n\n    .clock-wrap { position: absolute; left: 48px; top: 102px; width: 300px; height: 300px; border-radius: 50%; background: #fff; border: 18px solid #59913a; box-shadow: 0 0 0 14px #9ac18d; }\n    .clock-hands::before, .clock-hands::after { content: \"\"; position: absolute; left: 150px; top: 150px; transform-origin: left center; background: #7d7d7d; }\n    .clock-hands::before { width: 66px; height: 6px; transform: rotate(0deg); }\n    .clock-hands::after { width: 52px; height: 6px; transform: rotate(-78deg); }\n    .clock-center { position: absolute; left: 141px; top: 141px; width: 18px; height: 18px; border-radius: 50%; background: #5d9037; }\n    .clock-bars { position: absolute; left: 308px; top: 128px; right: 56px; display: flex; flex-direction: column; gap: 14px; }\n    .clock-bars div { height: 46px; border-radius: 0 12px 12px 0; background: #b6d298; position: relative; }\n    .clock-bars div:nth-child(2) { background: #9cc18f; }\n    .clock-bars div:nth-child(3) { background: #76b244; }\n    .clock-bars div:nth-child(4) { background: #568936; }\n    .clock-bars div::after { content: \"\"; position: absolute; right: -15px; top: 0; width: 0; height: 0; border-left: 15px solid currentColor; border-top: 23px solid transparent; border-bottom: 23px solid transparent; color: inherit; }\n\n    .wave-path {\n        position: absolute; left: -40px; right: -40px; top: 210px; height: 120px;\n        background:\n            radial-gradient(circle at 10% 50%, transparent 74px, #66956e 75px, #66956e 79px, transparent 80px),\n            radial-gradient(circle at 30% 50%, transparent 74px, #6ea042 75px, #6ea042 79px, transparent 80px),\n            radial-gradient(circle at 50% 50%, transparent 74px, #78b34c 75px, #78b34c 79px, transparent 80px),\n            radial-gradient(circle at 70% 50%, transparent 74px, #88b385 75px, #88b385 79px, transparent 80px),\n            radial-gradient(circle at 90% 50%, transparent 74px, #afcfad 75px, #afcfad 79px, transparent 80px);\n        opacity: .95;\n    }\n    .wave-node { position: absolute; width: 88px; height: 88px; border-radius: 50%; background: #fff; border: 16px solid #5c9138; display: flex; align-items: center; justify-content: center; font-weight: 900; font-size: 18px; color: #212121; }\n    .wave-node.n2 { border-color: #6e9b7e; }\n    .wave-node.n3 { border-color: #74b53f; }\n    .wave-node.n4 { border-color: #89b283; }\n    .wave-node.n5 { border-color: #afcfad; }\n\n    .axis-core { position: absolute; left: 74px; top: 204px; width: 112px; height: 112px; border-radius: 50%; background: #4e894b; }\n    .axis-curve { position: absolute; left: 108px; top: 96px; width: 160px; height: 270px; border-left: 8px dashed #d4d7d3; border-radius: 100px 0 0 100px; }\n    .axis-small { position: absolute; width: 64px; height: 64px; border-radius: 50%; background: #4f8a49; }\n    .axis-small.a { left: 204px; top: 114px; }\n    .axis-small.b { left: 226px; top: 202px; background: #5c934f; }\n    .axis-small.c { left: 226px; top: 290px; background: #6fb340; }\n    .axis-small.d { left: 204px; top: 378px; background: #97c68e; }\n    .axis-links { position: absolute; left: 190px; top: 116px; width: 120px; height: 272px; }\n    .axis-links span { position: absolute; left: 0; width: 86px; height: 2px; background: #d5d8d4; transform-origin: left center; }\n    .axis-links span:nth-child(1) { top: 16px; transform: rotate(-36deg); }\n    .axis-links span:nth-child(2) { top: 110px; transform: rotate(-10deg); }\n    .axis-links span:nth-child(3) { top: 176px; transform: rotate(12deg); }\n    .axis-links span:nth-child(4) { top: 264px; transform: rotate(30deg); }\n\n    .progress-band { position: absolute; left: 58px; right: 58px; top: 212px; height: 42px; display: grid; grid-template-columns: repeat(4, 1fr); }\n    .progress-band div { color: #fff; display: flex; align-items: center; justify-content: center; font-size: 18px; font-weight: 900; }\n    .progress-band div:nth-child(1) { background: #4d874d; }\n    .progress-band div:nth-child(2) { background: #719877; }\n    .progress-band div:nth-child(3) { background: #8db57f; }\n    .progress-band div:nth-child(4) { background: #c9d97c; color: #ffffff; }\n    .progress-quads { position: absolute; left: 60px; right: 60px; top: 96px; display: grid; grid-template-columns: repeat(2, 1fr); gap: 20px 40px; }\n    .progress-quads .q { padding-left: 18px; border-left: 4px solid #5a8a5c; }\n    .progress-quads .q.light { border-color: #c9d97c; }\n    .progress-quads strong { display: block; font-size: 16px; color: #5a7e5e; margin-bottom: 4px; }\n    .progress-quads span { display: block; font-size: 11px; color: #787878; line-height: 1.55; }\n\n    .dual-head { position: absolute; top: 54px; left: 0; right: 0; text-align: center; color: #477c4c; font-size: 20px; font-weight: 900; line-height: 1.5; }\n    .dual-bridge { position: absolute; left: 164px; right: 164px; top: 126px; height: 34px; border-top: 2px solid #7d7d7d; border-left: 2px solid #7d7d7d; border-right: 2px solid #7d7d7d; border-radius: 18px 18px 0 0; }\n    .dual-donut { position: absolute; width: 256px; height: 256px; border-radius: 50%; background: conic-gradient(#4e874c 0 80%, #c8d676 80% 100%); }\n    .dual-donut.right { background: conic-gradient(#749978 0 80%, #8ab486 80% 100%); }\n    .dual-donut::after { content: \"\"; position: absolute; inset: 72px; border-radius: 50%; background: #f8faf6; box-shadow: 0 10px 18px rgba(0,0,0,.12); }\n    .dual-donut .num { position: absolute; inset: 0; display: flex; align-items: center; justify-content: center; flex-direction: column; z-index: 2; color: #5b8e53; font-weight: 900; font-size: 64px; }\n    .dual-donut .num small { font-size: 20px; color: #4e4e4e; }\n\n</style>\n</head>\n<body>\n<div class=\"slide-container\">\n    <div class=\"slide\">\n        <div class=\"header\">\n            <div>\n                <h1>食品药品职业学院 PPT 模板描述文件（字段规范版）</h1>\n                <p>参照 template.html 的“单文件、自包含、固定 1280×720、响应式缩放、占位符与规则说明”写法，在 v3 的子版式拆分基础上，继续把字段命名、选型规则、禁用场景和母版约束标准化，方便后续直接拿来生成新的 PPT。</p>\n            </div>\n            <div class=\"main-tabs\" id=\"mainTabs\"></div>\n        </div>\n\n        <div class=\"workspace\">\n            <div class=\"panel rules-panel\">\n                <div class=\"group-card\">\n                    <div class=\"group-top\">\n                        <div class=\"group-badge\"><i></i><span id=\"groupName\">封面系统</span></div>\n                        <div class=\"subtype-counter\" id=\"subtypeCounter\">1 / 1</div>\n                    </div>\n                    <div class=\"group-summary\" id=\"groupSummary\"></div>\n                </div>\n\n                <div class=\"subtype-wrap\">\n                    <h3>子版式</h3>\n                    <div class=\"subtype-list\" id=\"subtypeList\"></div>\n                </div>\n\n                <div class=\"rule-block\">\n                    <h3>当前版式与布局描述</h3>\n                    <div class=\"meta-grid\">\n                        <div class=\"mini-stat\">\n                            <label>版式编码</label>\n                            <strong><span class=\"code-badge\" id=\"layoutCode\">COV-01</span></strong>\n                        </div>\n                        <div class=\"mini-stat\">\n                            <label>当前版式</label>\n                            <strong id=\"subtypeName\">横幅封面</strong>\n                        </div>\n                    </div>\n                    <p style=\"margin-top:10px\" id=\"layoutText\"></p>\n                </div>\n\n                <div class=\"rule-block\">\n                    <h3>必须保留的模板语言</h3>\n                    <ul id=\"mustKeepList\"></ul>\n                </div>\n\n                <div class=\"rule-block\">\n                    <h3>适用场景与禁用场景</h3>\n                    <div class=\"dual-list\">\n                        <div class=\"decision-box\">\n                            <h4>优先使用</h4>\n                            <ul id=\"chooseWhenList\"></ul>\n                        </div>\n                        <div class=\"decision-box avoid\">\n                            <h4>避免误用</h4>\n                            <ul id=\"avoidWhenList\"></ul>\n                        </div>\n                    </div>\n                </div>\n\n                <div class=\"rule-block\">\n                    <h3>字段规范</h3>\n                    <table class=\"field-table\">\n                        <thead>\n                            <tr><th>字段</th><th>含义</th><th>类型</th><th>长度建议</th></tr>\n                        </thead>\n                        <tbody id=\"fieldSpecBody\"></tbody>\n                    </table>\n                </div>\n\n                <div class=\"rule-block\">\n                    <h3>推荐占位符</h3>\n                    <div class=\"token-list\" id=\"tokenList\"></div>\n                </div>\n\n                <div class=\"rule-block\">\n                    <h3>母版共享规则</h3>\n                    <div class=\"pill-row\" id=\"masterRulePills\"></div>\n                    <div class=\"swatch-row\" style=\"margin-top:10px\">\n                        <div class=\"swatch\"><b style=\"background:#4e874c\"></b><span>主绿<br>#4E874C</span></div>\n                        <div class=\"swatch\"><b style=\"background:#78a06f\"></b><span>辅绿<br>#78A06F</span></div>\n                        <div class=\"swatch\"><b style=\"background:#c9d97c\"></b><span>浅黄绿<br>#C9D97C</span></div>\n                        <div class=\"swatch\"><b style=\"background:#f7faf4\"></b><span>浅底色<br>#F7FAF4</span></div>\n                    </div>\n                </div>\n\n                <div class=\"rule-block\">\n                    <h3>补充说明与反规则</h3>\n                    <p id=\"noteText\"></p>\n                    <ul id=\"antiRuleList\" style=\"margin-top:8px\"></ul>\n                </div>\n            </div>\n\n            <div class=\"panel preview-panel\">\n                <div class=\"preview-caption\">PREVIEW OF LAYOUT DESCRIPTION</div>\n                <div class=\"preview-stage\">\n                    <div class=\"mini-slide\" id=\"previewMount\"></div>\n                </div>\n                <div class=\"legend\">\n                    <span>统一色系：深绿 / 草绿 / 浅黄绿</span>\n                    <span>统一背景：白底 + 高留白</span>\n                    <span>统一语法：模块化信息图 + 已标准化字段命名，不走普通长段落文本页</span>\n                </div>\n            </div>\n        </div>\n    </div>\n</div>\n\n<script>\nfunction scaleSlide() {\n    const slide = document.querySelector(\'.slide\');\n    const container = document.querySelector(\'.slide-container\');\n    const scale = Math.min(container.offsetWidth / 1280, container.offsetHeight / 720);\n    slide.style.transform = `scale(${scale})`;\n}\n\nconst previewTemplates = {\n    coverHero: `\n        <div class=\"scene active\">\n            <div class=\"cover-line top\"></div>\n            <div class=\"cover-line bottom\"></div>\n            <div class=\"bg-circle\" style=\"width:210px;height:210px;right:110px;top:-34px;background:#3f7545\"></div>\n            <div class=\"bg-circle\" style=\"width:170px;height:170px;right:194px;top:32px;background:#99b03f\"></div>\n            <div class=\"bg-circle\" style=\"width:60px;height:60px;right:50px;top:58px;background:#d7de7b\"></div>\n            <div class=\"bg-circle\" style=\"width:32px;height:32px;left:26px;top:16px;background:#7eb377\"></div>\n            <div class=\"bg-circle\" style=\"width:116px;height:116px;left:38px;bottom:-38px;background:#93bf84\"></div>\n            <div class=\"bg-circle\" style=\"width:202px;height:202px;left:174px;bottom:-84px;background:#416f46\"></div>\n            <div class=\"bg-circle\" style=\"width:142px;height:142px;left:280px;bottom:-58px;background:#9eb841\"></div>\n            <div class=\"bg-circle\" style=\"width:58px;height:58px;right:78px;bottom:28px;background:#d9e080\"></div>\n            <div class=\"cover-banner\">\n                <div class=\"cover-logo\"><div class=\"seal\">◎</div><div class=\"text\"><strong>{{ school_name }}</strong><span>{{ school_name_en }}</span></div></div>\n                <div class=\"cover-title\">{{ cover_title }}</div>\n                <div class=\"cover-meta\">{{ cover_subtitle }} ｜ {{ presenter_name }} ｜ {{ department_name }}</div>\n            </div>\n            <d