 style=\"width:40px;height:40px;left:414px;top:46px;background:#6b9a69\"></div>\n            <div class=\"dir-main\">目录</div>\n            <div class=\"dir-small\" style=\"left:404px;top:84px\"><span class=\"n\">01</span><span>{{ catalog_item_1 }}</span></div>\n            <div class=\"dir-small\" style=\"left:316px;top:162px\"><span class=\"n\">02</span><span>{{ catalog_item_2 }}</span></div>\n            <div class=\"dir-small\" style=\"left:220px;top:232px\"><span class=\"n\">03</span><span>{{ catalog_item_3 }}</span></div>\n            <div class=\"dir-small\" style=\"left:112px;top:138px\"><span class=\"n\">04</span><span>{{ catalog_item_4 }}</span></div>\n            <div class=\"helper-chip\">目录变体 A：中心主圆 + 四个散点编号</div>\n        </div>`,\n    dirList: `\n        <div class=\"scene active\">\n            <div class=\"bg-dot\" style=\"width:12px;height:12px;left:34px;top:68px;background:#8dbe7c\"></div>\n            <div class=\"bg-dot\" style=\"width:16px;height:16px;left:58px;top:92px;background:#7ba36d\"></div>\n            <div class=\"bg-dot\" style=\"width:26px;height:26px;left:110px;top:64px;background:#5f8e51\"></div>\n            <div class=\"bg-dot\" style=\"width:52px;height:52px;left:154px;top:48px;background:#4b7c47\"></div>\n            <div class=\"bg-dot\" style=\"width:22px;height:22px;left:112px;top:122px;background:#cad76e\"></div>\n            <div class=\"strong\" style=\"position:absolute;left:122px;top:72px;font-size:26px;\">目录</div>\n            <div class=\"dir-list\">\n                <div class=\"item\"><div class=\"idx\">01</div><div class=\"lab\"><strong>{{ catalog_item_1 }}</strong><span></span></div></div>\n                <div class=\"item\"><div class=\"idx\">02</div><div class=\"lab\"><strong>{{ catalog_item_2 }}</strong><span></span></div></div>\n                <div class=\"item\"><div class=\"idx\">03</div><div class=\"lab\"><strong>{{ catalog_item_3 }}</strong><span></span></div></div>\n                <div class=\"item\"><d