          showSlide(currentSlide);\n            }\n        }\n\n        function previousSlide() {\n            if (currentSlide > 0) {\n                currentSlide--;\n                showSlide(currentSlide);\n            }\n        }\n\n        // Keyboard navigation\n        document.addEventListener(\'keydown\', function(e) {\n            if (e.key === \'ArrowRight\') nextSlide();\n            if (e.key === \'ArrowLeft\') previousSlide();\n        });\n\n        // Initialize when page loads\n        document.addEventListener(\'DOMContentLoaded\', function() {\n            showSlide(0);\n        });\n    </script>\n</body>\n</html>\n            ','[{\"page_number\": 1, \"title\": \"\\u4f20\\u627f\\u5343\\u5e74\\u667a\\u6167\\uff0c\\u5b88\\u62a4\\u672a\\u6765\\u5065\\u5eb7\", \"html_content\": \"<!DOCTYPE html>\\n<html lang=\\\"zh-CN\\\">\\n<head>\\n    <meta charset=\\\"UTF-8\\\">\\n    <meta name=\\\"viewport\\\" content=\\\"width=device-width, initial-scale=1.0\\\">\\n    <title>\\u4f20\\u627f\\u5343\\u5e74\\u667a\\u6167\\uff0c\\u5b88\\u62a4\\u672a\\u6765\\u5065\\u5eb7 - \\u4e2d\\u533b\\u517b\\u751f\\u5546\\u4e1a\\u8ba1\\u5212</title>\\n    <!-- Font Awesome \\u56fe\\u6807\\u5e93 -->\\n    <link rel=\\\"stylesheet\\\" href=\\\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css\\\">\\n    <!-- \\u56fe\\u8868\\u5e93\\u9884\\u7559 (Chart.js\\u793a\\u4f8b) -->\\n    <!-- <script src=\\\"https://cdn.jsdelivr.net/npm/chart.js\\\"></script> -->\\n    <style>\\n        /* \\u5168\\u5c40\\u91cd\\u7f6e\\u4e0e\\u57fa\\u7840\\u6837\\u5f0f */\\n        * { margin: 0; padding: 0; box-sizing: border-box; }\\n        body {\\n            font-family: -apple-system, BlinkMacSystemFont, \\\"Segoe UI\\\", \\\"Microsoft YaHei\\\", sans-serif;\\n            background: linear-gradient(135deg, #f5f7fa 0%, #e4edf5 100%);\\n            display: flex;\\n            justify-content: center;\\n            align-items: center;\\n            min-height: 100vh;\\n            overflow: hidden;\\n            padding: 20px;\\n        }\\n        \\n        /* \\u4e3b\\u5bb9\\u5668\\uff1a\\u56fa\\u5b9a1280x720\\uff0c16:9 */\\n        .slide-container {\\n            width: 1280px;\\n            height: 720px;\\n            background-color: #F8F4E9;\\n            background-image: \\n                radial-gradient(circle at 10% 20%, rgba(212, 232, 217, 0.2) 0%, transparent 20%),\\n                radial-gradient(circle at 90% 80%, rgba(212, 232, 217, 0.2) 0%, transparent 20%);\\n            position: relative;\\n            box-shadow: 0 20px 60px rgba(42, 92, 85, 0.15);\\n            border-radius: 8px;\\n            overflow: hidden;\\n            display: flex;\\n            flex-direction: column;\\n        }\\n        \\n        /* \\u9876\\u90e8\\u6807\\u9898\\u680f */\\n        .header {\\n            background: linear-gradient(90deg, #2A5C55 0%, #3A7C6F 100%);\\n            color: white;\\n            padding: 24px 40px;\\n            position: relative;\\n            min-height: 100px;\\n            display: flex;\\n            align-items: center;\\n        }\\n        .header::after {\\n            content: \\\"\\\";\\n            position: absolute;\\n            bottom: 0;\\n            left: 5%;\\n            width: 90%;\\n            height: 2px;\\n            background: linear-gradient(90deg, transparent, #D4E8D9, transparent);\\n        }\\n        .title {\\n            font-family: \\\"Noto Serif SC\\\", \\\"Source Han Serif\\\", serif;\\n            font-size: 36px;\\n            font-weight: 700;\\n            line-height: 1.2;\\n            flex: 1;\\n        }\\n        .subtitle {\\n            font-size: 18px;\\n            opacity: 0.9;\\n            margin-top: 8px;\\n            font-weight: 300;\\n        }\\n        .logo {\\n            font-size: 24px;\\n            margin-left: 30px;\\n            color: #D4E8D9;\\n        }\\n        \\n        /* \\u5185\\u5bb9\\u533a\\u57df - \\u9996\\u9875\\u7279\\u6b8a\\u6837\\u5f0f */\\n        .content {\\n            flex: 1;\\n            padding: 40px;\\n            overflow: hidden;\\n            position: relative;\\n            display: flex;\\n            align-items: center;\\n            justify-content: center;\\n        }\\n        \\n        /* \\u9996\\u9875\\u4e3b\\u89c6\\u89c9\\u5bb9\\u5668 */\\n        .hero-container {\\n            width: 100%;\\n            height: 100%;\\n            display: flex;\\n            flex-direction: column;\\n            align-items: center;\\n            justify-content: center;\\n            position: relative;\\n            z-index: 2;\\n        }\\n        \\n        /* \\u4e3b\\u6807\\u9898\\u5f3a\\u5316 */\\n        .hero-title {\\n            font-family: \\\"Noto Serif SC\\\", \\\"Source Han Serif\\\", serif;\\n            font-size: 64px;\\n            font-weight: 800;\\n            color: #2A5C55;\\n            text-align: center;\\n            line-height: 1.2;\\n            margin-bottom: 30px;\\n            text-shadow: 2px 2px 4px rgba(0, 0, 0, 0.05);\\n            position: relative;\\n            padding: 0 40px;\\n        }\\n        \\n        .hero-title span {\\n            display: block;\\n        }\\n        \\n        .hero-title .line1 {\\n            font-size: 64px;\\n            color: #2A5C55;\\n        }\\n        \\n        .hero-title .line2 {\\n            font-size: 56px;\\n            color: #B3543A;\\n            margin-top: 10px;\\n        }\\n        \\n        /* \\u526f\\u6807\\u9898\\u533a\\u57df */\\n        .hero-subtitle {\\n            font-size: 28px;\\n            color: #3A7C6F;\\n            text-align: center;\\n            margin-bottom: 40px;\\n            font-weight: 500;\\n            max-width: 900px;\\n            line-height: 1.4;\\n            padding: 0 40px;\\n        }\\n        \\n        /* \\u4fe1\\u606f\\u5361\\u7247 */\\n        .info-card {\\n            background: rgba(255, 255, 255, 0.92);\\n            border-radius: 16px;\\n            padding: 30px 40px;\\n            box-shadow: 0 15px 40px rgba(42, 92, 85, 0.12);\\n            border-top: 4px solid #B3543A;\\n            max-width: 800px;\\n            text-align: center;\\n            margin-bottom: 30px;\\n            backdrop-filter: blur(10px);\\n        }\\n        \\n        .info-card h3 {\\n            font-size: 24px;\\n            color: #2A5C55;\\n            margin-bottom: 15px;\\n            font-weight: 600;\\n        }\\n        \\n        .info-card p {\\n            font-size: 20px;\\n            color: #444;\\n            line-height: 1.5;\\n            margin-bottom: 0;\\n        }\\n        \\n        /* \\u5e95\\u90e8\\u4fe1\\u606f */\\n        .presenter-info {\\n            display: flex;\\n            justify-content: center;\\n            gap: 60px;\\n            margin-top: 20px;\\n            font-size: 20px;\\n            color: #555;\\n        }\\n        \\n        .presenter-item {\\n            display: flex;\\n            align-items: center;\\n            gap: 10px;\\n        }\\n        \\n        .presenter-icon {\\n            color: #B3543A;\\n            font-size: 22px;\\n        }\\n        \\n        /* \\u88c5\\u9970\\u5143\\u7d20\\u589e\\u5f3a */\\n        .decoration {\\n            position: absolute;\\n            opacity: 0.08;\\n            pointer-events: none;\\n            z-index: 1;\\n        }\\n        \\n        .decoration-1 {\\n            top: 15%;\\n            right: 5%;\\n            font-size: 200px;\\n            color: #2A5C55;\\n            transform: rotate(15deg);\\n        }\\n        \\n        .decoration-2 {\\n            bottom: 20%;\\n            left: 5%;\\n            font-size: 150px;\\n            color: #B3543A;\\n            transform: rotate(-10deg);\\n        }\\n        \\n        .decoration-3 {\\n            top: 25%;\\n            left: 8%;\\n            font-size: 120px;\\n            color: #3A7C6F;\\n            transform: rotate(-5deg);\\n        }\\n        \\n        .decoration-4 {\\n            bottom: 30%;\\n            right: 10%;\\n            font-size: 100px;\\n            color: #2A5C55;\\n            transform: rotate(20deg);\\n        }\\n        \\n        /* \\u80cc\\u666f\\u7eb9\\u7406 */\\n        .texture-overlay {\\n            position: absolute;\\n            top: 0;\\n            left: 0;\\n            width: 100%;\\n            height: 100%;\\n            background-image: url(\'data:image/svg+xml;utf8,<svg xmlns=\\\"http://www.w3.org/2000/svg\\\" width=\\\"200\\\" height=\\\"200\\\" viewBox=\\\"0 0 200 200\\\"><path d=\\\"M50,100 C50,50 150,50 150,100 C150,150 50,150 50,100 Z\\\" fill=\\\"none\\\" stroke=\\\"%232A5C55\\\" stroke-width=\\\"0.5\\\" opacity=\\\"0.03\\\"/><path d=\\\"M100,50 C150,50 150,150 100,150 C50,150 50,50 100,50 Z\\\" fill=\\\"none\\\" stroke=\\\"%23B3543A\\\" stroke-width=\\\"0.5\\\" opacity=\\\"0.03\\\"/></svg>\');\\n            background-size: 400px;\\n            opacity: 0.3;\\n            z-index: 0;\\n        }\\n        \\n        /* \\u9875\\u811a */\\n        .footer {\\n            background: rgba(42, 92, 85, 0.05);\\n            padding: 16px 40px;\\n            display: flex;\\n            justify-content: space-between;\\n            align-items: center;\\n            border-top: 1px solid rgba(42, 92, 85, 0.1);\\n            font-size: 14px;\\n            color: #555;\\n        }\\n        .pagination {\\n            font-weight: 600;\\n            color: #2A5C55;\\n        }\\n        .brand {\\n            display: flex;\\n            align-items: center;\\n            gap: 10px;\\n        }\\n        .brand-icon {\\n            color: #B3543A;\\n        }\\n        \\n        /* \\u54cd\\u5e94\\u5f0f\\uff1a\\u4fdd\\u630116:9\\u6bd4\\u4f8b\\u7f29\\u653e */\\n        @media (max-width: 1350px) {\\n            body { transform: scale(0.9); }\\n        }\\n        @media (max-width: 1150px) {\\n            body { transform: scale(0.8); }\\n        }\\n        @media (max-width: 900px) {\\n            body { transform: scale(0.7); }\\n        }\\n    </style>\\n</head>\\n<body>\\n    <div class=\\\"slide-container\\\">\\n        <!-- \\u80cc\\u666f\\u7eb9\\u7406 -->\\n        <div class=\\\"texture-overlay\\\"></div>\\n        \\n        <!-- \\u88c5\\u9970\\u5143\\u7d20\\u589e\\u5f3a -->\\n        <div class=\\\"decoration decoration-1\\\">\\n            <i class=\\\"fas fa-leaf\\\"></i>\\n        </div>\\n        <div class=\\\"decoration decoration-2\\\">\\n            <i class=\\\"fas fa-yin-yang\\\"></i>\\n        </div>\\n        <div class=\\\"decoration decoration-3\\\">\\n            <i class=\\\"fas fa-seedling\\\"></i>\\n        </div>\\n        <div class=\\\"decoration decoration-4\\\">\\n            <i class=\\\"fas fa-heartbeat\\\"></i>\\n        </div>\\n        \\n        <!-- \\u9876\\u90e8\\u6807\\u9898\\u680f -->\\n        <div class=\\\"header\\\">\\n            <div>\\n                <div class=\\\"title\\\">\\u4f20\\u627f\\u5343\\u5e74\\u667a\\u6167\\uff0c\\u5b88\\u62a4\\u672a\\u6765\\u5065\\u5eb7</div>\\n                <div class=\\\"subtitle\\\">\\u4e2d\\u533b\\u517b\\u751f\\u5728\\u513f\\u7ae5\\u79d1\\u666e\\u6559\\u80b2\\u4e2d\\u7684\\u4ef7\\u503c\\u4e0e\\u673a\\u9047</div>\\n            </div>\\n            <div class=\\\"logo\\\">\\n                <i class=\\\"fas fa-hand-holding-heart\\\"></i>\\n            </div>\\n        </div>\\n        \\n        <!-- \\u4e3b\\u5185\\u5bb9\\u533a - \\u9996\\u9875\\u7279\\u6b8a\\u8bbe\\u8ba1 -->\\n        <div class=\\\"content\\\">\\n            <div class=\\\"hero-container\\\">\\n                <!-- \\u4e3b\\u6807\\u9898 -->\\n                <div class=\\\"hero-title\\\">\\n                    <span class=\\\"line1\\\">\\u4f20\\u627f\\u5343\\u5e74\\u667a\\u6167</span>\\n                    <span class=\\\"line2\\\">\\u5b88\\u62a4\\u672a\\u6765\\u5065\\u5eb7</span>\\n                </div>\\n                \\n                <!-- \\u526f\\u6807\\u9898 -->\\n                <div class=\\\"hero-subtitle\\\">\\n                    \\u4e2d\\u533b\\u517b\\u751f\\u5728\\u513f\\u7ae5\\u79d1\\u666e\\u6559\\u80b2\\u4e2d\\u7684\\u4ef7\\u503c\\u4e0e\\u673a\\u9047\\n                </div>\\n                \\n                <!-- \\u4fe1\\u606f\\u5361\\u7247 -->\\n                <div class=\\\"info-card\\\">\\n                    <h3>\\u9762\\u5411\\u6295\\u8d44\\u4eba\\u7684\\u5546\\u4e1a\\u8ba1\\u5212\\u7b80\\u62a5</h3>\\n                    <p>\\u5c06\\u4f20\\u7edf\\u4e2d\\u533b\\u667a\\u6167\\u8f6c\\u5316\\u4e3a\\u513f\\u7ae5\\u5065\\u5eb7\\u6559\\u80b2\\u521b\\u65b0\\u89e3\\u51b3\\u65b9\\u6848</p>\\n                </div>\\n                \\n                <!-- \\u4e3b\\u8bb2\\u4eba\\u4fe1\\u606f -->\\n                <div class=\\\"presenter-info\\\">\\n                    <div class=\\\"presenter-item\\\">\\n                        <i class=\\\"fas fa-user-tie presenter-icon\\\"></i>\\n                        <span>\\u4e3b\\u8bb2\\u4eba\\uff1a[\\u60a8\\u7684\\u59d3\\u540d/\\u673a\\u6784\\u540d\\u79f0]</span>\\n                    </div>\\n                    <div class=\\\"presenter-item\\\">\\n                        <i class=\\\"fas fa-calendar-alt presenter-icon\\\"></i>\\n                        <span>\\u65e5\\u671f\\uff1a[\\u5f53\\u524d\\u65e5\\u671f]</span>\\n                    </div>\\n                </div>\\n            </div>\\n        </div>\\n        \\n        <!-- \\u9875\\u811a -->\\n        <div class=\\\"footer\\\">\\n            <div class=\\\"brand\\\">\\n                <i class=\\\"fas fa-seedling brand-icon\\\"></i>\\n                <span>\\u4f20\\u627f\\u5343\\u5e74\\u667a\\u6167 \\u00b7 \\u5b88\\u62a4\\u672a\\u6765\\u5065\\u5eb7</span>\\n            </div>\\n            <div class=\\\"pagination\\\">\\n                \\u7b2c <span class=\\\"highlight\\\">1</span> \\u9875 / \\u5171 15 \\u9875\\n            </div>\\n            <div>\\n                \\u4e3b\\u8bb2\\u4eba\\uff1a[\\u60a8\\u7684\\u59d3\\u540d/\\u673a\\u6784\\u540d\\u79f0] \\u00b7 \\u65e5\\u671f\\uff1a[\\u5f53\\u524d\\u65e5\\u671f]\\n            </div>\\n        </div>\\n    </div>\\n</body>\\n</html>\", \"is_user_edited\": false}, {\"page_number\": 2, \"title\": \"\\u76ee\\u5f55\\uff1a\\u6211\\u4eec\\u7684\\u84dd\\u56fe\", \"html_content\": \"<!DOCTYPE html>\\n<html lang=\\\"zh-CN\\\">\\n<head>\\n    <meta charset=\\\"UTF-8\\\">\\n    <meta name=\\\"viewport\\\" content=\\\"width=device-width, initial-scale=1.0\\\">\\n    <title>\\u76ee\\u5f55\\uff1a\\u6211\\u4eec\\u7684\\u84dd\\u56fe - \\u4e2d\\u533b\\u517b\\u751f\\u5546\\u4e1a\\u8ba1\\u5212</title>\\n    <!-- Font Awesome \\u56fe\\u6807\\u5e93 -->\\n    <link rel=\\\"stylesheet\\\" href=\\\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css\\\">\\n    <style>\\n        /* \\u5168\\u5c40\\u91cd\\u7f6e\\u4e0e\\u57fa\\u7840\\u6837\\u5f0f */\\n        * { margin: 0; padding: 0; box-sizing: border-box; }\\n        body {\\n            font-family: -apple-system, BlinkMacSystemFont, \\\"Segoe UI\\\", \\\"Microsoft YaHei\\\", sans-serif;\\n            background: linear-gradient(135deg, #f5f7fa 0%, #e4edf5 100%);\\n            display: flex;\\n            justify-content: center;\\n            align-items: center;\\n            min-height: 100vh;\\n            overflow: hidden;\\n            padding: 20px;\\n        }\\n        \\n        /* \\u4e3b\\u5bb9\\u5668\\uff1a\\u56fa\\u5b9a1280x720\\uff0c16:9 */\\n        .slide-container {\\n            width: 1280px;\\n            height: 720px;\\n            background-color: #F8F4E9;\\n            background-image: \\n                radial-gradient(circle at 10% 20%, rgba(212, 232, 217, 0.2) 0%, transparent 20%),\\n                radial-gradient(circle at 90% 80%, rgba(212, 232, 217, 0.2) 0%, transparent 20%);\\n            position: relative;\\n            box-shadow: 0 20px 60px rgba(42, 92, 85, 0.15);\\n            border-radius: 8px;\\n            overflow: hidden;\\n            display: flex;\\n            flex-direction: column;\\n        }\\n        \\n        /* \\u9876\\u90e8\\u6807\\u9898\\u680f */\\n        .header {\\n            background: linear-gradient(90deg, #2A5C55 0%, #3A7C6F 100%);\\n            color: white;\\n            padding: 24px 40px;\\n            position: relative;\\n            min-height: 100px;\\n            display: flex;\\n            align-items: center;\\n        }\\n        .header::after {\\n            content: \\\"\\\";\\n            position: absolute;\\n            bottom: 0;\\n            left: 5%;\\n            width: 90%;\\n            height: 2px;\\n            background: linear-gradient(90deg, transparent, #D4E8D9, transparent);\\n        }\\n        .title {\\n            font-family: \\\"Noto Serif SC\\\", \\\"Source Han Serif\\\", serif;\\n            font-size: 36px;\\n            font-weight: 700;\\n            line-height: 1.2;\\n            flex: 1;\\n        }\\n        .subtitle {\\n            font-size: 18px;\\n            opacity: 0.9;\\n            margin-top: 8px;\\n            font-weight: 300;\\n        }\\n        .logo {\\n            font-size: 24px;\\n            margin-left: 30px;\\n            color: #D4E8D9;\\n        }\\n        \\n        /* \\u5185\\u5bb9\\u533a\\u57df */\\n        .content {\\n            flex: 1;\\n            padding: 40px;\\n            overflow: hidden;\\n            position: relative;\\n        }\\n        .content-inner {\\n            height: 100%;\\n            display: flex;\\n            flex-direction: column;\\n            justify-content: center;\\n        }\\n        \\n        /* \\u9875\\u811a */\\n        .footer {\\n            background: rgba(42, 92, 85, 0.05);\\n            padding: 16px 40px;\\n            display: flex;\\n            justify-content: space-between;\\n            align-items: center;\\n            border-top: 1px solid rgba(42, 92, 85, 0.1);\\n            font-size: 14px;\\n            color: #555;\\n        }\\n        .pagination {\\n            font-weight: 600;\\n            color: #2A5C55;\\n        }\\n        .brand {\\n            display: flex;\\n            align-items: center;\\n            gap: 10px;\\n        }\\n        .brand-icon {\\n            color: #B3543A;\\n        }\\n        \\n        /* \\u88c5\\u9970\\u5143\\u7d20 */\\n        .decoration {\\n            position: absolute;\\n            opacity: 0.05;\\n            pointer-events: none;\\n        }\\n        .decoration-1 {\\n            top: 15%;\\n            right: 5%;\\n            font-size: 180px;\\n            color: #2A5C55;\\n            transform: rotate(15deg);\\n        }\\n        .decoration-2 {\\n            bottom: 20%;\\n            left: 5%;\\n            font-size: 120px;\\n            color: #B3543A;\\n            transform: rotate(-10deg);\\n        }\\n        \\n        /* \\u76ee\\u5f55\\u9875\\u4e13\\u5c5e\\u6837\\u5f0f */\\n        .agenda-container {\\n            display: flex;\\n            height: 100%;\\n            align-items: center;\\n            position: relative;\\n            z-index: 2;\\n        }\\n        \\n        .agenda-timeline {\\n            flex: 0 0 80px;\\n            height: 480px;\\n            position: relative;\\n            margin-right: 40px;\\n        }\\n        \\n        .timeline-line {\\n            position: absolute;\\n            left: 50%;\\n            top: 0;\\n            transform: translateX(-50%);\\n            width: 4px;\\n            height: 100%;\\n            background: linear-gradient(to bottom, #2A5C55, #3A7C6F, #B3543A);\\n            border-radius: 2px;\\n        }\\n        \\n        .timeline-nodes {\\n            position: absolute;\\n            left: 0;\\n            top: 0;\\n            width: 100%;\\n            height: 100%;\\n        }\\n        \\n        .timeline-node {\\n            position: absolute;\\n            left: 50%;\\n            transform: translateX(-50%);\\n            width: 24px;\\n            height: 24px;\\n            border-radius: 50%;\\n            background-color: #F8F4E9;\\n            border: 3px solid #2A5C55;\\n            z-index: 2;\\n            transition: all 0.3s ease;\\n        }\\n        \\n        .timeline-node.active {\\n            background-color: #B3543A;\\n            border-color: #B3543A;\\n            box-shadow: 0 0 0 6px rgba(179, 84, 58, 0.2);\\n        }\\n        \\n        .agenda-content {\\n            flex: 1;\\n            display: flex;\\n            flex-direction: column;\\n            justify-content: center;\\n            height: 480px;\\n        }\\n        \\n        .agenda-item {\\n            display: flex;\\n            align-items: center;\\n            margin-bottom: 28px;\\n            padding: 16px 24px;\\n            background: rgba(255, 255, 255, 0.85);\\n            border-radius: 12px;\\n            box-shadow: 0 4px 12px rgba(42, 92, 85, 0.08);\\n            border-left: 4px solid #2A5C55;\\n            transition: all 0.3s ease;\\n            position: relative;\\n            overflow: hidden;\\n        }\\n        \\n        .agenda-item:hover {\\n            transform: translateX(8px);\\n            box-shadow: 0 6px 20px rgba(42, 92, 85, 0.15);\\n            border-left-color: #B3543A;\\n        }\\n        \\n        .agenda-item::before {\\n            content: \\\"\\\";\\n            position: absolute;\\n            left: 0;\\n            top: 0;\\n            width: 100%;\\n            height: 100%;\\n            background: linear-gradient(90deg, rgba(212, 232, 217, 0.1) 0%, transparent 100%);\\n            opacity: 0;\\n            transition: opacity 0.3s ease;\\n        }\\n        \\n        .agenda-item:hover::before {\\n            opacity: 1;\\n        }\\n        \\n        .item-number {\\n            font-family: \\\"Noto Serif SC\\\", serif;\\n            font-size: 28px;\\n            font-weight: 700;\\n            color: #2A5C55;\\n            margin-right: 20px;\\n            min-width: 40px;\\n        }\\n        \\n        .item-content {\\n            flex: 1;\\n        }\\n        \\n        .item-title {\\n            font-size: 22px;\\n            font-weight: 600;\\n            color: #2A5C55;\\n            margin-bottom: 4px;\\n            line-height: 1.3;\\n        }\\n        \\n        .item-subtitle {\\n            font-size: 16px;\\n            color: #666;\\n            font-weight: 300;\\n            line-height: 1.4;\\n        }\\n        \\n        .item-icon {\\n            font-size: 24px;\\n            color: #3A7C6F;\\n            margin-left: 20px;\\n            transition: all 0.3s ease;\\n        }\\n        \\n        .agenda-item:hover .item-icon {\\n            color: #B3543A;\\n            transform: scale(1.1);\\n        }\\n        \\n        .agenda-title {\\n            position: absolute;\\n            top: 40px;\\n            left: 40px;\\n            font-family: \\\"Noto Serif SC\\\", serif;\\n            font-size: 32px;\\n            font-weight: 700;\\n            color: #2A5C55;\\n            margin-bottom: 30px;\\n            padding-bottom: 10px;\\n            border-bottom: 2px solid rgba(179, 84, 58, 0.3);\\n            width: calc(100% - 80px);\\n        }\\n        \\n        .agenda-subtitle {\\n            position: absolute;\\n            bottom: 40px;\\n            right: 40px;\\n            font-size: 16px;\\n            color: #666;\\n            font-style: italic;\\n            text-align: right;\\n            max-width: 400px;\\n            line-height: 1.5;\\n            padding: 12px 20px;\\n            background: rgba(255, 255, 255, 0.7);\\n            border-radius: 8px;\\n            border-left: 3px solid #3A7C6F;\\n        }\\n        \\n        /* \\u54cd\\u5e94\\u5f0f\\uff1a\\u4fdd\\u630116:9\\u6bd4\\u4f8b\\u7f29\\u653e */\\n        @media (max-width: 1350px) {\\n            body { transform: scale(0.9); }\\n        }\\n        @media (max-width: 1150px) {\\n            body { transform: scale(0.8); }\\n        }\\n        @media (max-width: 900px) {\\n            body { transform: scale(0.7); }\\n        }\\n    </style>\\n</head>\\n<body>\\n    <div class=\\\"slide-container\\\">\\n        <!-- \\u88c5\\u9970\\u5143\\u7d20 -->\\n        <div class=\\\"decoration decoration-1\\\">\\n            <i class=\\\"fas fa-leaf\\\"></i>\\n        </div>\\n        <div class=\\\"decoration decoration-2\\\">\\n            <i class=\\\"fas fa-yin-yang\\\"></i>\\n        </div>\\n        \\n        <!-- \\u9876\\u90e8\\u6807\\u9898\\u680f -->\\n        <div class=\\\"header\\\">\\n            <div>\\n                <div class=\\\"title\\\">\\u76ee\\u5f55\\uff1a\\u6211\\u4eec\\u7684\\u84dd\\u56fe</div>\\n                <div class=\\\"subtitle\\\">\\u4e2d\\u533b\\u517b\\u751f\\u5728\\u513f\\u7ae5\\u79d1\\u666e\\u6559\\u80b2\\u4e2d\\u7684\\u4ef7\\u503c\\u4e0e\\u673a\\u9047</div>\\n            </div>\\n            <div class=\\\"logo\\\">\\n                <i class=\\\"fas fa-hand-holding-heart\\\"></i>\\n            </div>\\n        </div>\\n        \\n        <!-- \\u4e3b\\u5185\\u5bb9\\u533a -->\\n        <div class=\\\"content\\\">\\n            <div class=\\\"content-inner\\\">\\n                <!-- \\u76ee\\u5f55\\u9875\\u4e13\\u5c5e\\u5185\\u5bb9 -->\\n                <div class=\\\"agenda-title\\\">\\u6211\\u4eec\\u7684\\u84dd\\u56fe\\uff1a\\u516d\\u5927\\u6838\\u5fc3\\u6a21\\u5757</div>\\n                \\n                <div class=\\\"agenda-container\\\">\\n                    <div class=\\\"agenda-timeline\\\">\\n                        <div class=\\\"timeline-line\\\"></div>\\n                        <div class=\\\"timeline-nodes\\\">\\n                            <div class=\\\"timeline-node\\\" style=\\\"top: 0%;\\\"></div>\\n                            <div class=\\\"timeline-node\\\" style=\\\"top: 20%;\\\"></div>\\n                            <div class=\\\"timeline-node active\\\" style=\\\"top: 40%;\\\"></div>\\n                            <div class=\\\"timeline-node\\\" style=\\\"top: 60%;\\\"></div>\\n                            <div class=\\\"timeline-node\\\" style=\\\"top: 80%;\\\"></div>\\n                            <div class=\\\"timeline-node\\\" style=\\\"top: 100%;\\\"></div>\\n                        </div>\\n                    </div>\\n                    \\n                    <div class=\\\"agenda-content\\\">\\n                        <div class=\\\"agenda-item\\\">\\n                            <div class=\\\"item-number\\\">\\u4e00</div>\\n                            <div class=\\\"item-content\\\">\\n                                <div class=\\\"item-title\\\">\\u5e02\\u573a\\u6d1e\\u5bdf\\uff1a\\u4e3a\\u4f55\\u662f\\u513f\\u7ae5\\u4e2d\\u533b\\u517b\\u751f\\u79d1\\u666e\\uff1f</div>\\n                                <div class=\\\"item-subtitle\\\">\\u513f\\u7ae5\\u5065\\u5eb7\\u5e02\\u573a\\u7684\\u65f6\\u4ee3\\u673a\\u9047\\u4e0e\\u9700\\u6c42\\u5206\\u6790</div>\\n                            </div>\\n                            <div class=\\\"item-icon\\\">\\n                                <i class=\\\"fas fa-search\\\"></i>\\n                            </div>\\n                        </div>\\n                        \\n                        <div class=\\\"agenda-item\\\">\\n                            <div class=\\\"item-number\\\">\\u4e8c</div>\\n                            <div class=\\\"item-content\\\">\\n                                <div class=\\\"item-title\\\">\\u6838\\u5fc3\\u7406\\u5ff5\\uff1a\\u4e2d\\u533b\\u517b\\u751f\\u7684\\u56db\\u5927\\u57fa\\u77f3</div>\\n                                <div class=\\\"item-subtitle\\\">\\u878d\\u5408\\u4f20\\u7edf\\u667a\\u6167\\u4e0e\\u73b0\\u4ee3\\u6559\\u80b2\\u7684\\u521b\\u65b0\\u7406\\u5ff5</div>\\n                            </div>\\n                            <div class=\\\"item-icon\\\">\\n                                <i class=\\\"fas fa-yin-yang\\\"></i>\\n                            </div>\\n                        </div>\\n                        \\n                        <div class=\\\"agenda-item\\\">\\n                            <div class=\\\"item-number\\\">\\u4e09</div>\\n                            <div class=\\\"item-content\\\">\\n                                <div class=\\\"item-title\\\">\\u4ea7\\u54c1\\u65b9\\u6848\\uff1a\\u5bd3\\u6559\\u4e8e\\u4e50\\u7684\\u79d1\\u666e\\u4f53\\u7cfb</div>\\n                                <div class=\\\"item-subtitle\\\">\\u4e92\\u52a8\\u5f0f\\u3001\\u573a\\u666f\\u5316\\u3001\\u591a\\u5a92\\u4ecb\\u7684\\u4ea7\\u54c1\\u77e9\\u9635</div>\\n                            </div>\\n                            <div class=\\\"item-icon\\\">\\n                                <i class=\\\"fas fa-puzzle-piece\\\"></i>\\n                            </div>\\n                        </div>\\n                        \\n                        <div class=\\\"agenda-item\\\">\\n                            <div class=\\\"item-number\\\">\\u56db</div>\\n                            <div class=\\\"item-content\\\">\\n                                <div class=\\\"item-title\\\">\\u5546\\u4e1a\\u6a21\\u5f0f\\u4e0e\\u5e02\\u573a\\u6f5c\\u529b</div>\\n                                <div class=\\\"item-subtitle\\\">\\u53ef\\u6301\\u7eed\\u589e\\u957f\\u7684\\u53cc\\u8f6e\\u9a71\\u52a8\\u4e0e\\u76c8\\u5229\\u8def\\u5f84</div>\\n                            </div>\\n                            <div class=\\\"item-icon\\\">\\n                                <i class=\\\"fas fa-chart-line\\\"></i>\\n                            </div>\\n                        </div>\\n                        \\n                        <div class=\\\"agenda-item\\\">\\n                            <div class=\\\"item-number\\\">\\u4e94</div>\\n                            <div class=\\\"item-content\\\">\\n                                <div class=\\\"item-title\\\">\\u56e2\\u961f\\u4f18\\u52bf\\u4e0e\\u6267\\u884c\\u89c4\\u5212</div>\\n                                <div class=\\\"item-subtitle\\\">\\u8de8\\u754c\\u878d\\u5408\\u7684\\u4e13\\u4e1a\\u56e2\\u961f\\u4e0e\\u6e05\\u6670\\u8def\\u7ebf\\u56fe</div>\\n                            </div>\\n                            <div class=\\\"item-icon\\\">\\n                                <i class=\\\"fas fa-users\\\"></i>\\n                            </div>\\n                        </div>\\n                        \\n                        <div class=\\\"agenda-item\\\">\\n                            <div class=\\\"item-number\\\">\\u516d</div>\\n                            <div class=\\\"item-content\\\">\\n                                <div class=\\\"item-title\\\">\\u6295\\u8d44\\u4ef7\\u503c\\u4e0e\\u56de\\u62a5\\u5c55\\u671b</div>\\n                                <div class=\\\"item-subtitle\\\">\\u53ef\\u89c2\\u56de\\u62a5\\u3001\\u793e\\u4f1a\\u4ef7\\u503c\\u4e0e\\u957f\\u671f\\u6f5c\\u529b</div>\\n                            </div>\\n                            <div class=\\\"item-icon\\\">\\n                                <i class=\\\"fas fa-gem\\\"></i>\\n                            </div>\\n                        </div>\\n                    </div>\\n                </div>\\n                \\n                <div class=\\\"agenda-subtitle\\\">\\n                    \\u4ece\\u5e02\\u573a\\u673a\\u9047\\u5230\\u6295\\u8d44\\u56de\\u62a5\\u7684\\u5b8c\\u6574\\u95ed\\u73af<br>\\n                    <span style=\\\"color: #B3543A; font-weight: 500;\\\">\\u9884\\u8ba1\\u6c47\\u62a5\\u65f6\\u95f4\\uff1a25\\u5206\\u949f | \\u6bcf\\u4e2a\\u6a21\\u5757\\u7ea64\\u5206\\u949f</span>\\n                </div>\\n            </div>\\n        </div>\\n        \\n        <!-- \\u9875\\u811a -->\\n        <div class=\\\"footer\\\">\\n            <div class=\\\"brand\\\">\\n                <i class=\\\"fas fa-seedling brand-icon\\\"></i>\\n                <span>\\u4f20\\u627f\\u5343\\u5e74\\u667a\\u6167 \\u00b7 \\u5b88\\u62a4\\u672a\\u6765\\u5065\\u5eb7</span>\\n            </div>\\n            <div class=\\\"pagination\\\">\\n                \\u7b2c <span class=\\\"highlight\\\">2</span> \\u9875 / \\u5171 15 \\u9875\\n            </div>\\n            <div>\\n                \\u4e3b\\u8bb2\\u4eba\\uff1a[\\u60a8\\u7684\\u59d3\\u540d/\\u673a\\u6784\\u540d\\u79f0] \\u00b7 \\u65e5\\u671f\\uff1a[\\u5f53\\u524d\\u65e5\\u671f]\\n            </div>\\n        </div>\\n    </div>\\n</body>\\n</html>\", \"is_user_edited\": false}, {\"page_number\": 3, \"title\": \"\\u4e00\\u3001\\u5e02\\u573a\\u6d1e\\u5bdf\\uff1a\\u4e9f\\u5f85\\u5f00\\u53d1\\u7684\\u84dd\\u6d77\", \"html_content\": \"<!DOCTYPE html>\\n<html lang=\\\"zh-CN\\\">\\n<head>\\n    <meta charset=\\\"UTF-8\\\">\\n    <meta name=\\\"viewport\\\" content=\\\"width=device-width, initial-scale=1.0\\\">\\n    <title>\\u4e00\\u3001\\u5e02\\u573a\\u6d1e\\u5bdf\\uff1a\\u4e9f\\u5f85\\u5f00\\u53d1\\u7684\\u84dd\\u6d77 - \\u4e2d\\u533b\\u517b\\u751f\\u5546\\u4e1a\\u8ba1\\u5212</title>\\n    <!-- Font Awesome \\u56fe\\u6807\\u5e93 -->\\n    <link rel=\\\"stylesheet\\\" href=\\\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css\\\">\\n    <!-- Chart.js \\u56fe\\u8868\\u5e93 -->\\n    <script src=\\\"https://cdn.jsdelivr.net/npm/chart.js\\\"></script>\\n    <style>\\n        /* \\u5168\\u5c40\\u91cd\\u7f6e\\u4e0e\\u57fa\\u7840\\u6837\\u5f0f */\\n        * { margin: 0; padding: 0; box-sizing: border-box; }\\n        body {\\n            font-family: -apple-system, BlinkMacSystemFont, \\\"Segoe UI\\\", \\\"Microsoft YaHei\\\", sans-serif;\\n            background: linear-gradient(135deg, #f5f7fa 0%, #e4edf5 100%);\\n            display: flex;\\n            justify-content: center;\\n            align-items: center;\\n            min-height: 100vh;\\n            overflow: hidden;\\n            padding: 20px;\\n        }\\n        /* \\u4e3b\\u5bb9\\u5668\\uff1a\\u56fa\\u5b9a1280x720\\uff0c16:9 */\\n        .slide-container {\\n            width: 1280px;\\n            height: 720px;\\n            background-color: #F8F4E9;\\n            background-image: \\n                radial-gradient(circle at 10% 20%, rgba(212, 232, 217, 0.2) 0%, transparent 20%),\\n                radial-gradient(circle at 90% 80%, rgba(212, 232, 217, 0.2) 0%, transparent 20%);\\n            position: relative;\\n            box-shadow: 0 20px 60px rgba(42, 92, 85, 0.15);\\n            border-radius: 8px;\\n            overflow: hidden;\\n            display: flex;\\n            flex-direction: column;\\n        }\\n        /* \\u9876\\u90e8\\u6807\\u9898\\u680f */\\n        .header {\\n            background: linear-gradient(90deg, #2A5C55 0%, #3A7C6F 100%);\\n            color: white;\\n            padding: 24px 40px;\\n            position: relative;\\n            min-height: 100px;\\n            display: flex;\\n            align-items: center;\\n        }\\n        .header::after {\\n            content: \\\"\\\";\\n            position: absolute;\\n            bottom: 0;\\n            left: 5%;\\n            width: 90%;\\n            height: 2px;\\n            background: linear-gradient(90deg, transparent, #D4E8D9, transparent);\\n        }\\n        .title {\\n            font-family: \\\"Noto Serif SC\\\", \\\"Source Han Serif\\\", serif;\\n            font-size: 36px;\\n            font-weight: 700;\\n            line-height: 1.2;\\n            flex: 1;\\n        }\\n        .subtitle {\\n            font-size: 18px;\\n            opacity: 0.9;\\n            margin-top: 8px;\\n            font-weight: 300;\\n        }\\n        .logo {\\n            font-size: 24px;\\n            margin-left: 30px;\\n            color: #D4E8D9;\\n        }\\n        /* \\u5185\\u5bb9\\u533a\\u57df */\\n        .content {\\n            flex: 1;\\n            padding: 40px;\\n            overflow: hidden;\\n            position: relative;\\n        }\\n        .content-inner {\\n            height: 100%;\\n            display: flex;\\n            flex-direction: column;\\n        }\\n        /* \\u9875\\u811a */\\n        .footer {\\n            background: rgba(42, 92, 85, 0.05);\\n            padding: 16px 40px;\\n            display: flex;\\n            justify-content: space-between;\\n            align-items: center;\\n            border-top: 1px solid rgba(42, 92, 85, 0.1);\\n            font-size: 14px;\\n            color: #555;\\n        }\\n        .pagination {\\n            font-weight: 600;\\n            color: #2A5C55;\\n        }\\n        .brand {\\n            display: flex;\\n            align-items: center;\\n            gap: 10px;\\n        }\\n        .brand-icon {\\n            color: #B3543A;\\n        }\\n        /* \\u88c5\\u9970\\u5143\\u7d20 */\\n        .decoration {\\n            position: absolute;\\n            opacity: 0.05;\\n            pointer-events: none;\\n        }\\n        .decoration-1 {\\n            top: 15%;\\n            right: 5%;\\n            font-size: 180px;\\n            color: #2A5C55;\\n            transform: rotate(15deg);\\n        }\\n        .decoration-2 {\\n            bottom: 20%;\\n            left: 5%;\\n            font-size: 120px;\\n            color: #B3543A;\\n            transform: rotate(-10deg);\\n        }\\n        /* \\u65b0\\u589e\\uff1a\\u521b\\u610f\\u8bbe\\u8ba1\\u6837\\u5f0f */\\n        .market-insight-container {\\n            display: flex;\\n            flex-direction: column;\\n            height: 100%;\\n            gap: 25px;\\n        }\\n        .insight-header {\\n            text-align: center;\\n            margin-bottom: 10px;\\n        }\\n        .insight-header h1 {\\n            color: #2A5C55;\\n            font-size: 42px;\\n            margin-bottom: 8px;\\n            position: relative;\\n            display: inline-block;\\n        }\\n        .insight-header h1::after {\\n            content: \\\"\\\";\\n            position: absolute;\\n            bottom: -5px;\\n            left: 10%;\\n            width: 80%;\\n            height: 3px;\\n            background: linear-gradient(90deg, transparent, #B3543A, transparent);\\n        }\\n        .insight-header p {\\n            color: #666;\\n            font-size: 18px;\\n            max-width: 800px;\\n            margin: 0 auto;\\n            line-height: 1.5;\\n        }\\n        .insight-content {\\n            display: flex;\\n            flex: 1;\\n            gap: 30px;\\n            height: calc(100% - 120px);\\n        }\\n        .insight-points {\\n            flex: 1;\\n            display: grid;\\n            grid-template-columns: 1fr 1fr;\\n            grid-template-rows: 1fr 1fr;\\n            gap: 20px;\\n        }\\n        .insight-card {\\n            background: white;\\n            border-radius: 16px;\\n            padding: 24px;\\n            box-shadow: 0 10px 30px rgba(0, 0, 0, 0.08);\\n            display: flex;\\n            flex-direction: column;\\n            transition: transform 0.3s ease, box-shadow 0.3s ease;\\n            border-top: 5px solid;\\n            position: relative;\\n            overflow: hidden;\\n        }\\n        .insight-card:hover {\\n            transform: translateY(-5px);\\n            box-shadow: 0 15px 35px rgba(0, 0, 0, 0.12);\\n        }\\n        .insight-card::before {\\n            content: \\\"\\\";\\n            position: absolute;\\n            top: 0;\\n            left: 0;\\n            right: 0;\\n            height: 5px;\\n            background: inherit;\\n        }\\n        .card-1 {\\n            border-color: #E71D36;\\n        }\\n        .card-2 {\\n            border-color: #2EC4B6;\\n        }\\n        .card-3 {\\n            border-color: #6C757D;\\n        }\\n        .card-4 {\\n            border-color: #FF9F1C;\\n        }\\n        .card-header {\\n            display: flex;\\n            align-items: center;\\n            margin-bottom: 15px;\\n        }\\n        .card-icon {\\n            width: 50px;\\n            height: 50px;\\n            border-radius: 12px;\\n            display: flex;\\n            align-items: center;\\n            justify-content: center;\\n            margin-right: 15px;\\n            font-size: 22px;\\n            color: white;\\n        }\\n        .icon-1 {\\n            background: linear-gradient(135deg, #E71D36, #FF6B6B);\\n        }\\n        .icon-2 {\\n            background: linear-gradient(135deg, #2EC4B6, #4ECDC4);\\n        }\\n        .icon-3 {\\n            background: linear-gradient(135deg, #6C757D, #ADB5BD);\\n        }\\n        .icon-4 {\\n            background: linear-gradient(135deg, #FF9F1C, #FFB347);\\n        }\\n        .card-title {\\n            font-size: 20px;\\n            font-weight: 700;\\n            color: #2A5C55;\\n            margin-bottom: 5px;\\n        }\\n        .card-subtitle {\\n            font-size: 14px;\\n            color: #666;\\n            font-weight: 500;\\n        }\\n        .card-content {\\n            flex: 1;\\n            font-size: 16px;\\n            line-height: 1.6;\\n            color: #444;\\n        }\\n        .card-highlight {\\n            color: #B3543A;\\n            font-weight: 600;\\n        }\\n        .chart-section {\\n            flex: 1;\\n            display: flex;\\n            flex-direction: column;\\n        }\\n        .chart-title {\\n            font-size: 20px;\\n            font-weight: 700;\\n            color: #2A5C55;\\n            margin-bottom: 15px;\\n            text-align: center;\\n        }\\n        .chart-container {\\n            background: white;\\n            border-radius: 16px;\\n            padding: 20px;\\n            box-shadow: 0 10px 30px rgba(0, 0, 0, 0.08);\\n            border: 1px solid rgba(42, 92, 85, 0.1);\\n            flex: 1;\\n            display: flex;\\n            flex-direction: column;\\n        }\\n        .chart-wrapper {\\n            flex: 1;\\n            position: relative;\\n        }\\n        .chart-note {\\n            font-size: 12px;\\n            color: #888;\\n            text-align: center;\\n            margin-top: 10px;\\n            font-style: italic;\\n        }\\n        /* \\u822a\\u6d77\\u4e3b\\u9898\\u88c5\\u9970 */\\n        .ocean-wave {\\n            position: absolute;\\n            bottom: 0;\\n            left: 0;\\n            right: 0;\\n            height: 20px;\\n            background: linear-gradient(90deg, transparent, rgba(42, 92, 85, 0.1), transparent);\\n            border-radius: 50%;\\n            opacity: 0.3;\\n        }\\n        .compass {\\n            position: absolute;\\n            top: 50%;\\n            right: 20px;\\n            width: 60px;\\n            height: 60px;\\n            opacity: 0.1;\\n            transform: translateY(-50%);\\n        }\\n        .compass i {\\n            font-size: 60px;\\n            color: #2A5C55;\\n        }\\n        /* \\u54cd\\u5e94\\u5f0f\\uff1a\\u4fdd\\u630116:9\\u6bd4\\u4f8b\\u7f29\\u653e */\\n        @media (max-width: 1350px) {\\n            body { transform: scale(0.9); }\\n        }\\n        @media (max-width: 1150px) {\\n            body { transform: scale(0.8); }\\n        }\\n        @media (max-width: 900px) {\\n            body { transform: scale(0.7); }\\n        }\\n    </style>\\n</head>\\n<body>\\n    <div class=\\\"slide-container\\\">\\n        <!-- \\u88c5\\u9970\\u5143\\u7d20 -->\\n        <div class=\\\"decoration decoration-1\\\">\\n            <i class=\\\"fas fa-leaf\\\"></i>\\n        </div>\\n        <div class=\\\"decoration decoration-2\\\">\\n            <i class=\\\"fas fa-yin-yang\\\"></i>\\n        </div>\\n        <!-- \\u9876\\u90e8\\u6807\\u9898\\u680f -->\\n        <div class=\\\"header\\\">\\n            <div>\\n                <div class=\\\"title\\\">\\u4e00\\u3001\\u5e02\\u573a\\u6d1e\\u5bdf\\uff1a\\u4e9f\\u5f85\\u5f00\\u53d1\\u7684\\u84dd\\u6d77</div>\\n                <div class=\\\"subtitle\\\">\\u4e2d\\u533b\\u517b\\u751f\\u5728\\u513f\\u7ae5\\u79d1\\u666e\\u6559\\u80b2\\u4e2d\\u7684\\u4ef7\\u503c\\u4e0e\\u673a\\u9047</div>\\n            </div>\\n            <div class=\\\"logo\\\">\\n                <i class=\\\"fas fa-hand-holding-heart\\\"></i>\\n            </div>\\n        </div>\\n        <!-- \\u4e3b\\u5185\\u5bb9\\u533a -->\\n        <div class=\\\"content\\\">\\n            <div class=\\\"market-insight-container\\\">\\n                <div class=\\\"insight-header\\\">\\n                    <h1>\\u5e02\\u573a\\u6d1e\\u5bdf\\uff1a\\u4e9f\\u5f85\\u5f00\\u53d1\\u7684\\u84dd\\u6d77</h1>\\n                    <p>\\u53d1\\u73b0\\u513f\\u7ae5\\u4e2d\\u533b\\u5065\\u5eb7\\u6559\\u80b2\\u7684\\u5de8\\u5927\\u5e02\\u573a\\u6f5c\\u529b\\u4e0e\\u5546\\u4e1a\\u673a\\u9047</p>\\n                </div>\\n                <div class=\\\"insight-content\\\">\\n                    <div class=\\\"insight-points\\\">\\n                        <div class=\\\"insight-card card-1\\\">\\n                            <div class=\\\"card-header\\\">\\n                                <div class=\\\"card-icon icon-1\\\">\\n                                    <i class=\\\"fas fa-exclamation-triangle\\\"></i>\\n                                </div>\\n                                <div>\\n                                    <div class=\\\"card-title\\\">\\u8feb\\u5207\\u75db\\u70b9</div>\\n                                    <div class=\\\"card-subtitle\\\">\\u5e02\\u573a\\u5b58\\u5728\\u7684\\u6838\\u5fc3\\u95ee\\u9898</div>\\n                                </div>\\n                            </div>\\n                            <div class=\\\"card-content\\\">\\n                                \\u513f\\u7ae5\\u4e9a\\u5065\\u5eb7\\u95ee\\u9898\\u65e5\\u76ca\\u7a81\\u51fa\\uff0c<span class=\\\"card-highlight\\\">85%\\u7684\\u5bb6\\u957f</span>\\u5b58\\u5728\\u663e\\u8457\\u7684\\u5065\\u5eb7\\u7126\\u8651\\uff0c\\u5bfb\\u6c42\\u4e13\\u4e1a\\u89e3\\u51b3\\u65b9\\u6848\\u7684\\u9700\\u6c42\\u8feb\\u5207\\u3002\\n                            </div>\\n                        </div>\\n                        <div class=\\\"insight-card card-2\\\">\\n                            <div class=\\\"card-header\\\">\\n                                <div class=\\\"card-icon icon-2\\\">\\n                                    <i class=\\\"fas fa-chart-line\\\"></i>\\n                                </div>\\n                                <div>\\n                                    <div class=\\\"card-title\\\">\\u53cc\\u91cd\\u8d8b\\u52bf</div>\\n                                    <div class=\\\"card-subtitle\\\">\\u5e02\\u573a\\u53d1\\u5c55\\u7684\\u6709\\u5229\\u73af\\u5883</div>\\n                                </div>\\n                            </div>\\n                            <div class=\\\"card-content\\\">\\n                                \\u4f20\\u7edf\\u6587\\u5316\\u590d\\u5174\\u6d6a\\u6f6e\\u53e0\\u52a0\\u56fd\\u5bb6\\u653f\\u7b56\\u5bf9\\u4e2d\\u533b\\u836f\\u7684\\u5927\\u529b\\u652f\\u6301\\uff0c<span class=\\\"card-highlight\\\">\\u653f\\u7b56\\u652f\\u6301\\u529b\\u5ea6\\u8bc4\\u5206\\u8fbe90/100</span>\\uff0c\\u5f62\\u6210\\u5f3a\\u5927\\u63a8\\u52a8\\u529b\\u3002\\n                            </div>\\n                        </div>\\n                        <div class=\\\"insight-card card-3\\\">\\n                            <div class=\\\"card-header\\\">\\n                                <div class=\\\"card-icon icon-3\\\">\\n                                    <i class=\\\"fas fa-search-minus\\\"></i>\\n                                </div>\\n                                <div>\\n                                    <div class=\\\"card-title\\\">\\u5e02\\u573a\\u7a7a\\u767d</div>\\n                                    <div class=\\\"card-subtitle\\\">\\u672a\\u88ab\\u6ee1\\u8db3\\u7684\\u5173\\u952e\\u9700\\u6c42</div>\\n                                </div>\\n                            </div>\\n                            <div class=\\\"card-content\\\">\\n                                \\u5e02\\u573a\\u4e25\\u91cd\\u7f3a\\u4e4f<span class=\\\"card-highlight\\\">\\\"\\u4e13\\u4e1a\\u00d7\\u6709\\u8da3\\u00d7\\u7cfb\\u7edf\\\"\\u4e09\\u4f4d\\u4e00\\u4f53</span>\\u7684\\u513f\\u7ae5\\u4e2d\\u533b\\u79d1\\u666e\\u5185\\u5bb9\\uff0c\\u4f9b\\u7ed9\\u7aef\\u5b58\\u5728\\u660e\\u663e\\u7f3a\\u53e3\\u3002\\n                            </div>\\n                        </div>\\n                        <div class=\\\"insight-card card-4\\\">\\n                            <div class=\\\"card-header\\\">\\n                                <div class=\\\"card-icon icon-4\\\">\\n                                    <i class=\\\"fas fa-gem\\\"></i>\\n                                </div>\\n                                <div>\\n                                    <div class=\\\"card-title\\\">\\u9ec4\\u91d1\\u673a\\u9047</div>\\n                                    <div class=\\\"card-subtitle\\\">\\u5546\\u4e1a\\u4ef7\\u503c\\u7684\\u96c6\\u4e2d\\u4f53\\u73b0</div>\\n                                </div>\\n                            </div>\\n                            <div class=\\\"card-content\\\">\\n                                \\u5065\\u5eb7\\u6d88\\u8d39\\u5e74\\u589e\\u957f\\u7387<span class=\\\"card-highlight\\\">\\u8d85\\u8fc7120%</span>\\uff0c\\u53e0\\u52a0\\u5bb6\\u5ead\\u6559\\u80b2\\u6295\\u8d44\\u610f\\u613f\\u5f3a\\u52b2\\uff0c\\u5e02\\u573a\\u6f5c\\u529b\\u5de8\\u5927\\u4e14\\u53d8\\u73b0\\u8def\\u5f84\\u6e05\\u6670\\u3002\\n                            </div>\\n                        </div>\\n                    </div>\\n                    <div class=\\\"chart-section\\\">\\n                        <div class=\\\"chart-title\\\">\\u6838\\u5fc3\\u5e02\\u573a\\u9a71\\u52a8\\u529b\\u5206\\u6790</div>\\n                        <div class=\\\"chart-container\\\">\\n                            <div class=\\\"chart-wrapper\\\">\\n                                <canvas id=\\\"marketChart\\\"></canvas>\\n                            </div>\\n                            <div class=\\\"chart-note\\\">\\u6570\\u636e\\u6765\\u6e90\\uff1a2023\\u5e74\\u5e02\\u573a\\u8c03\\u7814\\u62a5\\u544a\\uff0c\\u6837\\u672c\\u91cfN=1500</div>\\n                        </div>\\n                    </div>\\n                </div>\\n            </div>\\n            <!-- \\u822a\\u6d77\\u4e3b\\u9898\\u88c5\\u9970 -->\\n            <div class=\\\"ocean-wave\\\"></div>\\n            <div class=\\\"compass\\\">\\n                <i class=\\\"fas fa-compass\\\"></i>\\n            </div>\\n        </div>\\n        <!-- \\u9875\\u811a -->\\n        <div class=\\\"footer\\\">\\n            <div class=\\\"brand\\\">\\n                <i class=\\\"fas fa-seedling brand-icon\\\"></i>\\n                <span>\\u4f20\\u627f\\u5343\\u5e74\\u667a\\u6167 \\u00b7 \\u5b88\\u62a4\\u672a\\u6765\\u5065\\u5eb7</span>\\n            </div>\\n            <div class=\\\"pagination\\\">\\n                \\u7b2c <span class=\\\"highlight\\\">3</span> \\u9875 / \\u5171 15 \\u9875\\n            </div>\\n            <div>\\n                \\u4e3b\\u8bb2\\u4eba\\uff1a[\\u60a8\\u7684\\u59d3\\u540d/\\u673a\\u6784\\u540d\\u79f0] \\u00b7 \\u65e5\\u671f\\uff1a[\\u5f53\\u524d\\u65e5\\u671f]\\n            </div>\\n        </div>\\n    </div>\\n    <script>\\n        document.addEventListener(\'DOMContentLoaded\', function() {\\n            const ctx = document.getElementById(\'marketChart\').getContext(\'2d\');\\n            const gradient1 = ctx.createLinearGradient(0, 0, 400, 0);\\n            gradient1.addColorStop(0, \'#FF9F1C\');\\n            gradient1.addColorStop(1, \'#FFB347\');\\n            const gradient2 = ctx.createLinearGradient(0, 0, 400, 0);\\n            gradient2.addColorStop(0, \'#2EC4B6\');\\n            gradient2.addColorStop(1, \'#4ECDC4\');\\n            const gradient3 = ctx.createLinearGradient(0, 0, 400, 0);\\n            gradient3.addColorStop(0, \'#E71D36\');\\n            gradient3.addColorStop(1, \'#FF6B6B\');\\n            const chart = new Chart(ctx, {\\n                type: \'bar\',\\n                data: {\\n                    labels: [\'\\u5bb6\\u957f\\u5065\\u5eb7\\u7126\\u8651\\u6307\\u6570\', \'\\u513f\\u7ae5\\u4e2d\\u533b\\u5185\\u5bb9\\u641c\\u7d22\\u91cf\\u5e74\\u589e\\u957f\\u7387\', \'\\u653f\\u7b56\\u652f\\u6301\\u529b\\u5ea6\\uff08\\u8bc4\\u5206\\uff09\'],\\n                    datasets: [{\\n                        label: \'\\u5e02\\u573a\\u9a71\\u52a8\\u529b\\u6307\\u6807\',\\n                        data: [85, 120, 90],\\n                        backgroundColor: [gradient3, gradient2, gradient1],\\n                        borderColor: [\'#CC7E15\', \'#23978F\', \'#B31526\'],\\n                        borderWidth: 1,\\n                        borderRadius: 8,\\n                        borderSkipped: false,\\n                    }]\\n                },\\n                options: {\\n                    responsive: true,\\n                    maintainAspectRatio: false,\\n                    indexAxis: \'y\',\\n                    plugins: {\\n                        legend: {\\n                            display: false\\n                        },\\n                        tooltip: {\\n                            backgroundColor: \'rgba(42, 92, 85, 0.9)\',\\n                            titleFont: {\\n                                size: 14,\\n                                family: \\\"\'Microsoft YaHei\', sans-serif\\\"\\n                            },\\n                            bodyFont: {\\n                                size: 14,\\n                                family: \\\"\'Microsoft YaHei\', sans-serif\\\"\\n                            },\\n                            padding: 12,\\n                            cornerRadius: 8,\\n                            callbacks: {\\n                                label: function(context) {\\n                                    let label = context\", \"is_user_edited\": false}, {\"page_number\": 4, \"title\": \"\\u4e8c\\u3001\\u6838\\u5fc3\\u7406\\u5ff5\\uff1a\\u4e2d\\u533b\\u517b\\u751f\\u7684\\u56db\\u5927\\u57fa\\u77f3\", \"html_content\": \"<!DOCTYPE html>\\n<html lang=\\\"zh-CN\\\">\\n<head>\\n    <meta charset=\\\"UTF-8\\\">\\n    <meta name=\\\"viewport\\\" content=\\\"width=device-width, initial-scale=1.0\\\">\\n    <title>\\u4e8c\\u3001\\u6838\\u5fc3\\u7406\\u5ff5\\uff1a\\u4e2d\\u533b\\u517b\\u751f\\u7684\\u56db\\u5927\\u57fa\\u77f3 - \\u4e2d\\u533b\\u517b\\u751f\\u5546\\u4e1a\\u8ba1\\u5212</title>\\n    <!-- Font Awesome \\u56fe\\u6807\\u5e93 -->\\n    <link rel=\\\"stylesheet\\\" href=\\\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css\\\">\\n    <!-- Chart.js \\u56fe\\u8868\\u5e93 -->\\n    <script src=\\\"https://cdn.jsdelivr.net/npm/chart.js\\\"></script>\\n    <style>\\n        /* \\u5168\\u5c40\\u91cd\\u7f6e\\u4e0e\\u57fa\\u7840\\u6837\\u5f0f */\\n        * { margin: 0; padding: 0; box-sizing: border-box; }\\n        body {\\n            font-family: -apple-system, BlinkMacSystemFont, \\\"Segoe UI\\\", \\\"Microsoft YaHei\\\", sans-serif;\\n            background: linear-gradient(135deg, #f5f7fa 0%, #e4edf5 100%);\\n            display: flex;\\n            justify-content: center;\\n            align-items: center;\\n            min-height: 100vh;\\n            overflow: hidden;\\n            padding: 20px;\\n        }\\n        \\n        /* \\u4e3b\\u5bb9\\u5668\\uff1a\\u56fa\\u5b9a1280x720\\uff0c16:9 */\\n        .slide-container {\\n            width: 1280px;\\n            height: 720px;\\n            background-color: #F8F4E9;\\n            background-image: \\n                radial-gradient(circle at 10% 20%, rgba(212, 232, 217, 0.2) 0%, transparent 20%),\\n                radial-gradient(circle at 90% 80%, rgba(212, 232, 217, 0.2) 0%, transparent 20%);\\n            position: relative;\\n            box-shadow: 0 20px 60px rgba(42, 92, 85, 0.15);\\n            border-radius: 8px;\\n            overflow: hidden;\\n            display: flex;\\n            flex-direction: column;\\n        }\\n        \\n        /* \\u9876\\u90e8\\u6807\\u9898\\u680f */\\n        .header {\\n            background: linear-gradient(90deg, #2A5C55 0%, #3A7C6F 100%);\\n            color: white;\\n            padding: 24px 40px;\\n            position: relative;\\n            min-height: 100px;\\n            display: flex;\\n            align-items: center;\\n        }\\n        .header::after {\\n            content: \\\"\\\";\\n            position: absolute;\\n            bottom: 0;\\n            left: 5%;\\n            width: 90%;\\n            height: 2px;\\n            background: linear-gradient(90deg, transparent, #D4E8D9, transparent);\\n        }\\n        .title {\\n            font-family: \\\"Noto Serif SC\\\", \\\"Source Han Serif\\\", serif;\\n            font-size: 36px;\\n            font-weight: 700;\\n            line-height: 1.2;\\n            flex: 1;\\n        }\\n        .subtitle {\\n            font-size: 18px;\\n            opacity: 0.9;\\n            margin-top: 8px;\\n            font-weight: 300;\\n        }\\n        .logo {\\n            font-size: 24px;\\n            margin-left: 30px;\\n            color: #D4E8D9;\\n        }\\n        \\n        /* \\u5185\\u5bb9\\u533a\\u57df */\\n        .content {\\n            flex: 1;\\n            padding: 40px;\\n            overflow: hidden;\\n            position: relative;\\n        }\\n        .content-inner {\\n            height: 100%;\\n            display: flex;\\n            flex-direction: column;\\n            justify-content: center;\\n        }\\n        \\n        /* \\u9875\\u811a */\\n        .footer {\\n            background: rgba(42, 92, 85, 0.05);\\n            padding: 16px 40px;\\n            display: flex;\\n            justify-content: space-between;\\n            align-items: center;\\n            border-top: 1px solid rgba(42, 92, 85, 0.1);\\n            font-size: 14px;\\n            color: #555;\\n        }\\n        .pagination {\\n            font-weight: 600;\\n            color: #2A5C55;\\n        }\\n        .brand {\\n            display: flex;\\n            align-items: center;\\n            gap: 10px;\\n        }\\n        .brand-icon {\\n            color: #B3543A;\\n        }\\n        \\n        /* \\u88c5\\u9970\\u5143\\u7d20 */\\n        .decoration {\\n            position: absolute;\\n            opacity: 0.05;\\n            pointer-events: none;\\n        }\\n        .decoration-1 {\\n            top: 15%;\\n            right: 5%;\\n            font-size: 180px;\\n            color: #2A5C55;\\n            transform: rotate(15deg);\\n        }\\n        .decoration-2 {\\n            bottom: 20%;\\n            left: 5%;\\n            font-size: 120px;\\n            color: #B3543A;\\n            transform: rotate(-10deg);\\n        }\\n        \\n        /* \\u65b0\\u589e\\u6837\\u5f0f\\uff1a\\u521b\\u610f\\u5185\\u5bb9\\u5e03\\u5c40 */\\n        .core-concept-container {\\n            display: flex;\\n            height: 100%;\\n            align-items: center;\\n            gap: 40px;\\n        }\\n        \\n        .chart-section {\\n            flex: 1;\\n            height: 100%;\\n            display: flex;\\n            flex-direction: column;\\n            justify-content: center;\\n            align-items: center;\\n        }\\n        \\n        .chart-wrapper {\\n            position: relative;\\n            width: 320px;\\n            height: 320px;\\n        }\\n        \\n        .chart-center {\\n            position: absolute;\\n            top: 50%;\\n            left: 50%;\\n            transform: translate(-50%, -50%);\\n            width: 120px;\\n            height: 120px;\\n            background: white;\\n            border-radius: 50%;\\n            display: flex;\\n            flex-direction: column;\\n            justify-content: center;\\n            align-items: center;\\n            box-shadow: 0 8px 24px rgba(0, 0, 0, 0.08);\\n            border: 3px solid #2A5C55;\\n            z-index: 10;\\n        }\\n        \\n        .chart-center i {\\n            font-size: 32px;\\n            color: #B3543A;\\n            margin-bottom: 8px;\\n        }\\n        \\n        .chart-center span {\\n            font-size: 14px;\\n            color: #2A5C55;\\n            font-weight: 600;\\n        }\\n        \\n        .concepts-section {\\n            flex: 1.2;\\n            height: 100%;\\n            display: flex;\\n            flex-direction: column;\\n            justify-content: center;\\n        }\\n        \\n        .concepts-grid {\\n            display: grid;\\n            grid-template-columns: 1fr 1fr;\\n            grid-template-rows: 1fr 1fr;\\n            gap: 24px;\\n            height: 320px;\\n        }\\n        \\n        .concept-card {\\n            background: white;\\n            border-radius: 16px;\\n            padding: 24px;\\n            display: flex;\\n            flex-direction: column;\\n            box-shadow: 0 8px 24px rgba(0, 0, 0, 0.06);\\n            transition: all 0.3s ease;\\n            border-top: 4px solid;\\n            position: relative;\\n            overflow: hidden;\\n        }\\n        \\n        .concept-card:hover {\\n            transform: translateY(-5px);\\n            box-shadow: 0 12px 32px rgba(0, 0, 0, 0.1);\\n        }\\n        \\n        .concept-card::before {\\n            content: \\\"\\\";\\n            position: absolute;\\n            top: 0;\\n            left: 0;\\n            right: 0;\\n            height: 4px;\\n            background: inherit;\\n            opacity: 0.3;\\n        }\\n        \\n        .concept-icon {\\n            font-size: 28px;\\n            margin-bottom: 16px;\\n            width: 56px;\\n            height: 56px;\\n            border-radius: 50%;\\n            display: flex;\\n            align-items: center;\\n            justify-content: center;\\n            color: white;\\n        }\\n        \\n        .concept-title {\\n            font-size: 22px;\\n            font-weight: 700;\\n            margin-bottom: 12px;\\n            color: #2A5C55;\\n        }\\n        \\n        .concept-desc {\\n            font-size: 16px;\\n            line-height: 1.5;\\n            color: #555;\\n            flex-grow: 1;\\n        }\\n        \\n        .concept-number {\\n            position: absolute;\\n            top: 20px;\\n            right: 20px;\\n            font-size: 14px;\\n            font-weight: 600;\\n            color: rgba(0, 0, 0, 0.1);\\n        }\\n        \\n        /* \\u5361\\u7247\\u989c\\u8272\\u5b9a\\u4e49 */\\n        .card-yinyang {\\n            border-top-color: #FF6B6B;\\n        }\\n        .card-yinyang .concept-icon {\\n            background: linear-gradient(135deg, #FF6B6B, #FF8E8E);\\n        }\\n        \\n        .card-wuxing {\\n            border-top-color: #4ECDC4;\\n        }\\n        .card-wuxing .concept-icon {\\n            background: linear-gradient(135deg, #4ECDC4, #6EDBD4);\\n        }\\n        \\n        .card-whole {\\n            border-top-color: #45B7D1;\\n        }\\n        .card-whole .concept-icon {\\n            background: linear-gradient(135deg, #45B7D1, #65CFE6);\\n        }\\n        \\n        .card-prevention {\\n            border-top-color: #96CEB4;\\n        }\\n        .card-prevention .concept-icon {\\n            background: linear-gradient(135deg, #96CEB4, #B0DEC6);\\n        }\\n        \\n        .section-title {\\n            font-size: 20px;\\n            font-weight: 600;\\n            color: #3A7C6F;\\n            margin-bottom: 24px;\\n            text-align: center;\\n            position: relative;\\n            padding-bottom: 12px;\\n        }\\n        \\n        .section-title::after {\\n            content: \\\"\\\";\\n            position: absolute;\\n            bottom: 0;\\n            left: 50%;\\n            transform: translateX(-50%);\\n            width: 60px;\\n            height: 3px;\\n            background: linear-gradient(90deg, transparent, #B3543A, transparent);\\n        }\\n        \\n        /* \\u54cd\\u5e94\\u5f0f\\uff1a\\u4fdd\\u630116:9\\u6bd4\\u4f8b\\u7f29\\u653e */\\n        @media (max-width: 1350px) {\\n            body { transform: scale(0.9); }\\n        }\\n        @media (max-width: 1150px) {\\n            body { transform: scale(0.8); }\\n        }\\n        @media (max-width: 900px) {\\n            body { transform: scale(0.7); }\\n        }\\n    </style>\\n</head>\\n<body>\\n    <div class=\\\"slide-container\\\">\\n        <!-- \\u88c5\\u9970\\u5143\\u7d20 -->\\n        <div class=\\\"decoration decoration-1\\\">\\n            <i class=\\\"fas fa-leaf\\\"></i>\\n        </div>\\n        <div class=\\\"decoration decoration-2\\\">\\n            <i class=\\\"fas fa-yin-yang\\\"></i>\\n        </div>\\n        \\n        <!-- \\u9876\\u90e8\\u6807\\u9898\\u680f -->\\n        <div class=\\\"header\\\">\\n            <div>\\n                <div class=\\\"title\\\">\\u4e8c\\u3001\\u6838\\u5fc3\\u7406\\u5ff5\\uff1a\\u4e2d\\u533b\\u517b\\u751f\\u7684\\u56db\\u5927\\u57fa\\u77f3</div>\\n                <div class=\\\"subtitle\\\">\\u4e2d\\u533b\\u517b\\u751f\\u5728\\u513f\\u7ae5\\u79d1\\u666e\\u6559\\u80b2\\u4e2d\\u7684\\u4ef7\\u503c\\u4e0e\\u673a\\u9047</div>\\n            </div>\\n            <div class=\\\"logo\\\">\\n                <i class=\\\"fas fa-hand-holding-heart\\\"></i>\\n            </div>\\n        </div>\\n        \\n        <!-- \\u4e3b\\u5185\\u5bb9\\u533a -->\\n        <div class=\\\"content\\\">\\n            <div class=\\\"content-inner\\\">\\n                <div class=\\\"core-concept-container\\\">\\n                    <!-- \\u5de6\\u4fa7\\uff1a\\u73af\\u5f62\\u56fe\\u533a\\u57df -->\\n                    <div class=\\\"chart-section\\\">\\n                        <div class=\\\"section-title\\\">\\u4e2d\\u533b\\u517b\\u751f\\u56db\\u5927\\u57fa\\u77f3\\u6784\\u6210</div>\\n                        <div class=\\\"chart-wrapper\\\">\\n                            <canvas id=\\\"coreConceptChart\\\"></canvas>\\n                            <div class=\\\"chart-center\\\">\\n                                <i class=\\\"fas fa-heartbeat\\\"></i>\\n                                <span>\\u5065\\u5eb7\\u4e4b\\u57fa</span>\\n                            </div>\\n                        </div>\\n                    </div>\\n                    \\n                    <!-- \\u53f3\\u4fa7\\uff1a\\u56db\\u5927\\u57fa\\u77f3\\u5361\\u7247\\u533a\\u57df -->\\n                    <div class=\\\"concepts-section\\\">\\n                        <div class=\\\"section-title\\\">\\u6838\\u5fc3\\u7406\\u5ff5\\u8be6\\u89e3</div>\\n                        <div class=\\\"concepts-grid\\\">\\n                            <!-- \\u9634\\u9633\\u5e73\\u8861 -->\\n                            <div class=\\\"concept-card card-yinyang\\\">\\n                                <div class=\\\"concept-number\\\">\\u57fa\\u77f3\\u4e00</div>\\n                                <div class=\\\"concept-icon\\\">\\n                                    <i class=\\\"fas fa-balance-scale\\\"></i>\\n                                </div>\\n                                <div class=\\\"concept-title\\\">\\u9634\\u9633\\u5e73\\u8861</div>\\n                                <div class=\\\"concept-desc\\\">\\u7406\\u89e3\\u8eab\\u4f53\\u5185\\u5916\\u7684\\u548c\\u8c10\\u4e0e\\u5bf9\\u7acb\\uff0c\\u5982\\u540c\\u663c\\u591c\\u4ea4\\u66ff\\uff0c\\u7ef4\\u6301\\u52a8\\u6001\\u5e73\\u8861\\u662f\\u5065\\u5eb7\\u4e4b\\u672c\\u3002</div>\\n                            </div>\\n                            \\n                            <!-- \\u4e94\\u884c\\u5b66\\u8bf4 -->\\n                            <div class=\\\"concept-card card-wuxing\\\">\\n                                <div class=\\\"concept-number\\\">\\u57fa\\u77f3\\u4e8c</div>\\n                                <div class=\\\"concept-icon\\\">\\n                                    <i class=\\\"fas fa-recycle\\\"></i>\\n                                </div>\\n                                <div class=\\\"concept-title\\\">\\u4e94\\u884c\\u5b66\\u8bf4</div>\\n                                <div class=\\\"concept-desc\\\">\\u8ba4\\u8bc6\\u4e94\\u810f\\u3001\\u5b63\\u8282\\u4e0e\\u60c5\\u7eea\\u7684\\u5173\\u8054\\uff0c\\u7406\\u89e3\\u6728\\u706b\\u571f\\u91d1\\u6c34\\u76f8\\u751f\\u76f8\\u514b\\u7684\\u81ea\\u7136\\u89c4\\u5f8b\\u3002</div>\\n                            </div>\\n                            \\n                            <!-- \\u6574\\u4f53\\u89c2\\u5ff5 -->\\n                            <div class=\\\"concept-card card-whole\\\">\\n                                <div class=\\\"concept-number\\\">\\u57fa\\u77f3\\u4e09</div>\\n                                <div class=\\\"concept-icon\\\">\\n                                    <i class=\\\"fas fa-globe-asia\\\"></i>\\n                                </div>\\n                                <div class=\\\"concept-title\\\">\\u6574\\u4f53\\u89c2\\u5ff5</div>\\n                                <div class=\\\"concept-desc\\\">\\u4eba\\u662f\\u4e00\\u4e2a\\u4e0e\\u81ea\\u7136\\u793e\\u4f1a\\u76f8\\u8fde\\u7684\\u6574\\u4f53\\uff0c\\u5065\\u5eb7\\u53d7\\u73af\\u5883\\u3001\\u793e\\u4f1a\\u3001\\u5fc3\\u7406\\u591a\\u56e0\\u7d20\\u5f71\\u54cd\\u3002</div>\\n                            </div>\\n                            \\n                            <!-- \\u6cbb\\u672a\\u75c5\\u601d\\u60f3 -->\\n                            <div class=\\\"concept-card card-prevention\\\">\\n                                <div class=\\\"concept-number\\\">\\u57fa\\u77f3\\u56db</div>\\n                                <div class=\\\"concept-icon\\\">\\n                                    <i class=\\\"fas fa-shield-alt\\\"></i>\\n                                </div>\\n                                <div class=\\\"concept-title\\\">\\u6cbb\\u672a\\u75c5\\u601d\\u60f3</div>\\n                                <div class=\\\"concept-desc\\\">\\u9884\\u9632\\u4e3a\\u4e3b\\uff0c\\u57f9\\u517b\\u5065\\u5eb7\\u751f\\u6d3b\\u4e60\\u60ef\\uff0c\\u5728\\u75be\\u75c5\\u53d1\\u751f\\u524d\\u8fdb\\u884c\\u5e72\\u9884\\u548c\\u8c03\\u7406\\u3002</div>\\n                            </div>\\n                        </div>\\n                    </div>\\n                </div>\\n            </div>\\n        </div>\\n        \\n        <!-- \\u9875\\u811a -->\\n        <div class=\\\"footer\\\">\\n            <div class=\\\"brand\\\">\\n                <i class=\\\"fas fa-seedling brand-icon\\\"></i>\\n                <span>\\u4f20\\u627f\\u5343\\u5e74\\u667a\\u6167 \\u00b7 \\u5b88\\u62a4\\u672a\\u6765\\u5065\\u5eb7</span>\\n            </div>\\n            <div class=\\\"pagination\\\">\\n                \\u7b2c <span class=\\\"highlight\\\">4</span> \\u9875 / \\u5171 15 \\u9875\\n            </div>\\n            <div>\\n                \\u4e3b\\u8bb2\\u4eba\\uff1a[\\u60a8\\u7684\\u59d3\\u540d/\\u673a\\u6784\\u540d\\u79f0] \\u00b7 \\u65e5\\u671f\\uff1a[\\u5f53\\u524d\\u65e5\\u671f]\\n            </div>\\n        </div>\\n    </div>\\n\\n    <script>\\n        // \\u521d\\u59cb\\u5316\\u73af\\u5f62\\u56fe\\n        document.addEventListener(\'DOMContentLoaded\', function() {\\n            const ctx = document.getElementById(\'coreConceptChart\').getContext(\'2d\');\\n            \\n            // \\u73af\\u5f62\\u56fe\\u6570\\u636e\\n            const chartData = {\\n                labels: [\'\\u9634\\u9633\\u5e73\\u8861\', \'\\u4e94\\u884c\\u5b66\\u8bf4\', \'\\u6574\\u4f53\\u89c2\\u5ff5\', \'\\u6cbb\\u672a\\u75c5\\u601d\\u60f3\'],\\n                datasets: [{\\n                    label: \'\\u56db\\u5927\\u57fa\\u77f3\',\\n                    data: [25, 25, 25, 25],\\n                    backgroundColor: [\\n                        \'#FF6B6B\', // \\u9634\\u9633\\u5e73\\u8861\\n                        \'#4ECDC4\', // \\u4e94\\u884c\\u5b66\\u8bf4\\n                        \'#45B7D1\', // \\u6574\\u4f53\\u89c2\\u5ff5\\n                        \'#96CEB4\'  // \\u6cbb\\u672a\\u75c5\\u601d\\u60f3\\n                    ],\\n                    borderColor: \'#FFFFFF\',\\n                    borderWidth: 4,\\n                    hoverBorderWidth: 6,\\n                    hoverOffset: 10\\n                }]\\n            };\\n            \\n            // \\u56fe\\u8868\\u914d\\u7f6e\\n            const chartConfig = {\\n                type: \'doughnut\',\\n                data: chartData,\\n                options: {\\n                    responsive: true,\\n                    maintainAspectRatio: false,\\n                    cutout: \'60%\',\\n                    plugins: {\\n                        legend: {\\n                            display: false\\n                        },\\n                        tooltip: {\\n                            callbacks: {\\n                                label: function(context) {\\n                                    return `${context.label}: \\u56db\\u5927\\u57fa\\u77f3\\u4e4b\\u4e00`;\\n                                }\\n                            },\\n                            backgroundColor: \'rgba(42, 92, 85, 0.9)\',\\n                            titleFont: { size: 14 },\\n                            bodyFont: { size: 13 },\\n                            padding: 12\\n                        }\\n                    },\\n                    animation: {\\n                        animateScale: true,\\n                        animateRotate: true,\\n                        duration: 1500,\\n                        easing: \'easeOutQuart\'\\n                    }\\n                }\\n            };\\n            \\n            // \\u521b\\u5efa\\u56fe\\u8868\\n            const coreConceptChart = new Chart(ctx, chartConfig);\\n            \\n            // \\u6dfb\\u52a0\\u5361\\u7247\\u60ac\\u505c\\u6548\\u679c\\u4e0e\\u56fe\\u8868\\u4ea4\\u4e92\\n            const conceptCards = document.querySelectorAll(\'.concept-card\');\\n            const chart = coreConceptChart;\\n            \\n            conceptCards.forEach((card, index) => {\\n                card.addEventListener(\'mouseenter\', function() {\\n                    // \\u9ad8\\u4eae\\u5bf9\\u5e94\\u7684\\u56fe\\u8868\\u90e8\\u5206\\n                    chart.setActiveElements([{ datasetIndex: 0, index: index }]);\\n                    chart.update();\\n                    \\n                    // \\u6dfb\\u52a0\\u5361\\u7247\\u60ac\\u505c\\u7c7b\\n                    this.style.transform = \'translateY(-8px)\';\\n                    this.style.boxShadow = \'0 16px 40px rgba(0, 0, 0, 0.12)\';\\n                });\\n                \\n                card.addEventListener(\'mouseleave\', function() {\\n                    // \\u91cd\\u7f6e\\u56fe\\u8868\\u9ad8\\u4eae\\n                    chart.setActiveElements([]);\\n                    chart.update();\\n                    \\n                    // \\u79fb\\u9664\\u5361\\u7247\\u60ac\\u505c\\u7c7b\\n                    this.style.transform = \'translateY(0)\';\\n                    this.style.boxShadow = \'0 8px 24px rgba(0, 0, 0, 0.06)\';\\n                });\\n            });\\n        });\\n    </script>\\n</body>\\n</html>\", \"is_user_edited\": false}, {\"page_number\": 5, \"title\": \"\\u57fa\\u77f3\\u4e00\\uff1a\\u9634\\u9633\\u5e73\\u8861\\u4e0e\\u513f\\u7ae5\\u5065\\u5eb7\", \"html_content\": \"<!DOCTYPE html>\\n<html lang=\\\"zh-CN\\\">\\n<head>\\n    <meta charset=\\\"UTF-8\\\">\\n    <meta name=\\\"viewport\\\" content=\\\"width=device-width, initial-scale=1.0\\\">\\n    <title>\\u57fa\\u77f3\\u4e00\\uff1a\\u9634\\u9633\\u5e73\\u8861\\u4e0e\\u513f\\u7ae5\\u5065\\u5eb7 - \\u4e2d\\u533b\\u517b\\u751f\\u5546\\u4e1a\\u8ba1\\u5212</title>\\n    <!-- Font Awesome \\u56fe\\u6807\\u5e93 -->\\n    <link rel=\\\"stylesheet\\\" href=\\\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css\\\">\\n    <!-- \\u56fe\\u8868\\u5e93\\u9884\\u7559 (Chart.js\\u793a\\u4f8b) -->\\n    <!-- <script src=\\\"https://cdn.jsdelivr.net/npm/chart.js\\\"></script> -->\\n    <style>\\n        /* \\u5168\\u5c40\\u91cd\\u7f6e\\u4e0e\\u57fa\\u7840\\u6837\\u5f0f */\\n        * { margin: 0; padding: 0; box-sizing: border-box; }\\n        body {\\n            font-family: -apple-system, BlinkMacSystemFont, \\\"Segoe UI\\\", \\\"Microsoft YaHei\\\", sans-serif;\\n            background: linear-gradient(135deg, #f5f7fa 0%, #e4edf5 100%);\\n            display: flex;\\n            justify-content: center;\\n            align-items: center;\\n            min-height: 100vh;\\n            overflow: hidden;\\n            padding: 20px;\\n        }\\n        /* \\u4e3b\\u5bb9\\u5668\\uff1a\\u56fa\\u5b9a1280x720\\uff0c16:9 */\\n        .slide-container {\\n            width: 1280px;\\n            height: 720px;\\n            background-color: #F8F4E9;\\n            background-image: \\n                radial-gradient(circle at 10% 20%, rgba(212, 232, 217, 0.2) 0%, transparent 20%),\\n                radial-gradient(circle at 90% 80%, rgba(212, 232, 217, 0.2) 0%, transparent 20%);\\n            position: relative;\\n            box-shadow: 0 20px 60px rgba(42, 92, 85, 0.15);\\n            border-radius: 8px;\\n            overflow: hidden;\\n            display: flex;\\n            flex-direction: column;\\n        }\\n        /* \\u9876\\u90e8\\u6807\\u9898\\u680f */\\n        .header {\\n            background: linear-gradient(90deg, #2A5C55 0%, #3A7C6F 100%);\\n            color: white;\\n            padding: 24px 40px;\\n            position: relative;\\n            min-height: 100px;\\n            display: flex;\\n            align-items: center;\\n        }\\n        .header::after {\\n            content: \\\"\\\";\\n            position: absolute;\\n            bottom: 0;\\n            left: 5%;\\n            width: 90%;\\n            height: 2px;\\n            background: linear-gradient(90deg, transparent, #D4E8D9, transparent);\\n        }\\n        .title {\\n            font-family: \\\"Noto Serif SC\\\", \\\"Source Han Serif\\\", serif;\\n            font-size: 36px;\\n            font-weight: 700;\\n            line-height: 1.2;\\n            flex: 1;\\n        }\\n        .subtitle {\\n            font-size: 18px;\\n            opacity: 0.9;\\n            margin-top: 8px;\\n            font-weight: 300;\\n        }\\n        .logo {\\n            font-size: 24px;\\n            margin-left: 30px;\\n            color: #D4E8D9;\\n        }\\n        /* \\u5185\\u5bb9\\u533a\\u57df */\\n        .content {\\n            flex: 1;\\n            padding: 40px;\\n            overflow: hidden;\\n            position: relative;\\n        }\\n        .content-inner {\\n            height: 100%;\\n            display: flex;\\n            flex-direction: column;\\n            justify-content: center;\\n        }\\n        /* \\u9875\\u811a */\\n        .footer {\\n            background: rgba(42, 92, 85, 0.05);\\n            padding: 16px 40px;\\n            display: flex;\\n            justify-content: space-between;\\n            align-items: center;\\n            border-top: 1px solid rgba(42, 92, 85, 0.1);\\n            font-size: 14px;\\n            color: #555;\\n        }\\n        .pagination {\\n            font-weight: 600;\\n            color: #2A5C55;\\n        }\\n        .brand {\\n            display: flex;\\n            align-items: center;\\n            gap: 10px;\\n        }\\n        .brand-icon {\\n            color: #B3543A;\\n        }\\n        /* \\u88c5\\u9970\\u5143\\u7d20 */\\n        .decoration {\\n            position: absolute;\\n            opacity: 0.05;\\n            pointer-events: none;\\n        }\\n        .decoration-1 {\\n            top: 15%;\\n            right: 5%;\\n            font-size: 180px;\\n            color: #2A5C55;\\n            transform: rotate(15deg);\\n        }\\n        .decoration-2 {\\n            bottom: 20%;\\n            left: 5%;\\n            font-size: 120px;\\n            color: #B3543A;\\n            transform: rotate(-10deg);\\n        }\\n        /* \\u56fe\\u8868\\u5bb9\\u5668\\u6837\\u5f0f */\\n        .chart-container {\\n            background: white;\\n            border-radius: 12px;\\n            padding: 20px;\\n            box-shadow: 0 8px 24px rgba(0, 0, 0, 0.05);\\n            border: 1px solid rgba(42, 92, 85, 0.1);\\n            height: 300px;\\n            margin-top: 20px;\\n        }\\n        /* \\u5185\\u5bb9\\u6837\\u5f0f */\\n        h1 { color: #2A5C55; font-size: 42px; margin-bottom: 20px; }\\n        h2 { color: #3A7C6F; font-size: 32px; margin-bottom: 16px; }\\n        h3 { color: #B3543A; font-size: 24px; margin-bottom: 12px; }\\n        p { color: #333; line-height: 1.6; margin-bottom: 16px; font-size: 18px; }\\n        ul, ol { padding-left: 24px; margin-bottom: 20px; }\\n        li { margin-bottom: 8px; color: #444; line-height: 1.5; font-size: 18px; }\\n        .highlight { color: #B3543A; font-weight: 600; }\\n        .card {\\n            background: white;\\n            border-radius: 12px;\\n            padding: 24px;\\n            box-shadow: 0 8px 24px rgba(0, 0, 0, 0.05);\\n            border-left: 5px solid #2A5C55;\\n            margin-bottom: 20px;\\n        }\\n        /* \\u54cd\\u5e94\\u5f0f\\uff1a\\u4fdd\\u630116:9\\u6bd4\\u4f8b\\u7f29\\u653e */\\n        @media (max-width: 1350px) {\\n            body { transform: scale(0.9); }\\n        }\\n        @media (max-width: 1150px) {\\n            body { transform: scale(0.8); }\\n        }\\n        @media (max-width: 900px) {\\n            body { transform: scale(0.7); }\\n        }\\n        /* \\u7b2c5\\u9875\\u81ea\\u5b9a\\u4e49\\u6837\\u5f0f */\\n        .balance-container {\\n            display: flex;\\n            flex-direction: column;\\n            height: 100%;\\n            justify-content: space-between;\\n        }\\n        .balance-main {\\n            display: flex;\\n            align-items: center;\\n            justify-content: center;\\n            flex-grow: 1;\\n            gap: 60px;\\n            margin: 20px 0;\\n        }\\n        .balance-visual {\\n            position: relative;\\n            width: 280px;\\n            height: 280px;\\n            display: flex;\\n            align-items: center;\\n            justify-content: center;\\n        }\\n        .yin-yang-circle {\\n            width: 220px;\\n            height: 220px;\\n            border-radius: 50%;\\n            background: linear-gradient(90deg, #3A7C6F 0%, #2A5C55 50%, #E8F4EA 50%, #D4E8D9 100%);\\n            position: relative;\\n            box-shadow: 0 10px 30px rgba(42, 92, 85, 0.15);\\n            animation: gentle-rotate 20s linear infinite;\\n        }\\n        .yin-yang-circle::before,\\n        .yin-yang-circle::after {\\n            content: \'\';\\n            position: absolute;\\n            border-radius: 50%;\\n            width: 60px;\\n            height: 60px;\\n            top: 50%;\\n            transform: translateY(-50%);\\n        }\\n        .yin-yang-circle::before {\\n            background: #E8F4EA;\\n            left: 30px;\\n            box-shadow: inset 0 0 10px rgba(42, 92, 85, 0.1);\\n        }\\n        .yin-yang-circle::after {\\n            background: #2A5C55;\\n            right: 30px;\\n            box-shadow: inset 0 0 10px rgba(212, 232, 217, 0.2);\\n        }\\n        .balance-points {\\n            display: flex;\\n            flex-direction: column;\\n            gap: 40px;\\n            max-width: 600px;\\n        }\\n        .balance-card {\\n            background: white;\\n            border-radius: 16px;\\n            padding: 28px;\\n            box-shadow: 0 8px 24px rgba(0, 0, 0, 0.08);\\n            border-top: 4px solid;\\n            transition: transform 0.3s ease, box-shadow 0.3s ease;\\n        }\\n        .balance-card:hover {\\n            transform: translateY(-5px);\\n            box-shadow: 0 12px 32px rgba(0, 0, 0, 0.12);\\n        }\\n        .balance-card.concept {\\n            border-top-color: #3A7C6F;\\n        }\\n        .balance-card.application {\\n            border-top-color: #B3543A;\\n        }\\n        .balance-card.goal {\\n            border-top-color: #2A5C55;\\n        }\\n        .card-header {\\n            display: flex;\\n            align-items: center;\\n            gap: 15px;\\n            margin-bottom: 18px;\\n        }\\n        .card-icon {\\n            width: 48px;\\n            height: 48px;\\n            border-radius: 50%;\\n            display: flex;\\n            align-items: center;\\n            justify-content: center;\\n            font-size: 22px;\\n            color: white;\\n        }\\n        .concept .card-icon {\\n            background: linear-gradient(135deg, #3A7C6F, #2A5C55);\\n        }\\n        .application .card-icon {\\n            background: linear-gradient(135deg, #B3543A, #D87C5F);\\n        }\\n        .goal .card-icon {\\n            background: linear-gradient(135deg, #2A5C55, #3A7C6F);\\n        }\\n        .card-title {\\n            font-size: 24px;\\n            font-weight: 700;\\n            color: #2A5C55;\\n            margin: 0;\\n        }\\n        .card-content {\\n            color: #444;\\n            line-height: 1.6;\\n            font-size: 18px;\\n            margin-bottom: 15px;\\n        }\\n        .examples {\\n            display: flex;\\n            flex-wrap: wrap;\\n            gap: 12px;\\n            margin-top: 15px;\\n        }\\n        .example-tag {\\n            background: rgba(212, 232, 217, 0.3);\\n            border: 1px solid rgba(58, 124, 111, 0.2);\\n            border-radius: 20px;\\n            padding: 6px 16px;\\n            font-size: 14px;\\n            color: #2A5C55;\\n            display: flex;\\n            align-items: center;\\n            gap: 8px;\\n        }\\n        .example-tag i {\\n            font-size: 12px;\\n        }\\n        .balance-quote {\\n            text-align: center;\\n            padding: 20px;\\n            margin-top: 20px;\\n            font-style: italic;\\n            color: #666;\\n            font-size: 18px;\\n            border-top: 1px dashed rgba(42, 92, 85, 0.2);\\n            border-bottom: 1px dashed rgba(42, 92, 85, 0.2);\\n        }\\n        .balance-quote .highlight {\\n            color: #B3543A;\\n            font-weight: 600;\\n        }\\n        @keyframes gentle-rotate {\\n            0% { transform: rotate(0deg); }\\n            100% { transform: rotate(360deg); }\\n        }\\n        /* \\u88c5\\u9970\\u5143\\u7d20\\u8c03\\u6574 */\\n        .decoration-3 {\\n            position: absolute;\\n            bottom: 120px;\\n            right: 80px;\\n            font-size: 80px;\\n            color: rgba(179, 84, 58, 0.08);\\n            transform: rotate(45deg);\\n            z-index: 0;\\n        }\\n        .decoration-4 {\\n            position: absolute;\\n            top: 150px;\\n            left: 80px;\\n            font-size: 60px;\\n            color: rgba(58, 124, 111, 0.08);\\n            transform: rotate(-30deg);\\n            z-index: 0;\\n        }\\n    </style>\\n</head>\\n<body>\\n    <div class=\\\"slide-container\\\">\\n        <!-- \\u88c5\\u9970\\u5143\\u7d20 -->\\n        <div class=\\\"decoration decoration-1\\\">\\n            <i class=\\\"fas fa-leaf\\\"></i>\\n        </div>\\n        <div class=\\\"decoration decoration-2\\\">\\n            <i class=\\\"fas fa-yin-yang\\\"></i>\\n        </div>\\n        <div class=\\\"decoration decoration-3\\\">\\n            <i class=\\\"fas fa-balance-scale\\\"></i>\\n        </div>\\n        <div class=\\\"decoration decoration-4\\\">\\n            <i class=\\\"fas fa-child\\\"></i>\\n        </div>\\n        <!-- \\u9876\\u90e8\\u6807\\u9898\\u680f -->\\n        <div class=\\\"header\\\">\\n            <div>\\n                <div class=\\\"title\\\">\\u57fa\\u77f3\\u4e00\\uff1a\\u9634\\u9633\\u5e73\\u8861\\u4e0e\\u513f\\u7ae5\\u5065\\u5eb7</div>\\n                <div class=\\\"subtitle\\\">\\u4e2d\\u533b\\u517b\\u751f\\u5728\\u513f\\u7ae5\\u79d1\\u666e\\u6559\\u80b2\\u4e2d\\u7684\\u4ef7\\u503c\\u4e0e\\u673a\\u9047</div>\\n            </div>\\n            <div class=\\\"logo\\\">\\n                <i class=\\\"fas fa-hand-holding-heart\\\"></i>\\n            </div>\\n        </div>\\n        <!-- \\u4e3b\\u5185\\u5bb9\\u533a -->\\n        <div class=\\\"content\\\">\\n            <div class=\\\"content-inner\\\">\\n                <div class=\\\"balance-container\\\">\\n                    <div class=\\\"balance-main\\\">\\n                        <!-- \\u9634\\u9633\\u5e73\\u8861\\u89c6\\u89c9\\u4e2d\\u5fc3 -->\\n                        <div class=\\\"balance-visual\\\">\\n                            <div class=\\\"yin-yang-circle\\\"></div>\\n                        </div>\\n                        <!-- \\u4e09\\u4e2a\\u5185\\u5bb9\\u5361\\u7247 -->\\n                        <div class=\\\"balance-points\\\">\\n                            <!-- \\u6982\\u5ff5\\u5361\\u7247 -->\\n                            <div class=\\\"balance-card concept\\\">\\n                                <div class=\\\"card-header\\\">\\n                                    <div class=\\\"card-icon\\\">\\n                                        <i class=\\\"fas fa-lightbulb\\\"></i>\\n                                    </div>\\n                                    <h3 class=\\\"card-title\\\">\\u6982\\u5ff5\\uff1a\\u751f\\u6d3b\\u4e2d\\u7684\\u9634\\u9633\\u5e73\\u8861</h3>\\n                                </div>\\n                                <p class=\\\"card-content\\\">\\n                                    \\u7528\\u513f\\u7ae5\\u719f\\u6089\\u7684\\u751f\\u6d3b\\u73b0\\u8c61\\u89e3\\u91ca\\u62bd\\u8c61\\u6982\\u5ff5\\uff0c\\u5c06\\u9634\\u9633\\u5e73\\u8861\\u8f6c\\u5316\\u4e3a\\u53ef\\u611f\\u77e5\\u7684\\u65e5\\u5e38\\u4f53\\u9a8c\\u3002\\n                                </p>\\n                                <div class=\\\"examples\\\">\\n                                    <span class=\\\"example-tag\\\"><i class=\\\"fas fa-sun\\\"></i> \\u767d\\u5929\\u4e0e\\u9ed1\\u591c</span>\\n                                    <span class=\\\"example-tag\\\"><i class=\\\"fas fa-thermometer-half\\\"></i> \\u51b7\\u4e0e\\u70ed</span>\\n                                    <span class=\\\"example-tag\\\"><i class=\\\"fas fa-running\\\"></i> \\u52a8\\u4e0e\\u9759</span>\\n                                    <span class=\\\"example-tag\\\"><i class=\\\"fas fa-seedling\\\"></i> \\u751f\\u957f\\u4e0e\\u4f11\\u606f</span>\\n                                </div>\\n                            </div>\\n                            <!-- \\u5e94\\u7528\\u5361\\u7247 -->\\n                            <div class=\\\"balance-card application\\\">\\n                                <div class=\\\"card-header\\\">\\n                                    <div class=\\\"card-icon\\\">\\n                                        <i class=\\\"fas fa-hands-helping\\\"></i>\\n                                    </div>\\n                                    <h3 class=\\\"card-title\\\">\\u5e94\\u7528\\uff1a\\u5e73\\u8861\\u7684\\u827a\\u672f\\u5b9e\\u8df5</h3>\\n                                </div>\\n                                <p class=\\\"card-content\\\">\\n                                    \\u5c06\\u7406\\u8bba\\u8f6c\\u5316\\u4e3a\\u5177\\u4f53\\u53ef\\u64cd\\u4f5c\\u7684\\u80b2\\u513f\\u6307\\u5bfc\\uff0c\\u5e2e\\u52a9\\u5bb6\\u957f\\u5728\\u65e5\\u5e38\\u751f\\u6d3b\\u4e2d\\u5b9e\\u73b0\\u5e73\\u8861\\u3002\\n                                </p>\\n                                <div class=\\\"examples\\\">\\n                                    <span class=\\\"example-tag\\\"><i class=\\\"fas fa-book\\\"></i> \\u5b66\\u4e60\\u4e0e\\u73a9\\u800d\\u7ed3\\u5408</span>\\n                                    <span class=\\\"example-tag\\\"><i class=\\\"fas fa-tshirt\\\"></i> \\u7a7f\\u8863\\u5bd2\\u6e29\\u9002\\u5b9c</span>\\n                                    <span class=\\\"example-tag\\\"><i class=\\\"fas fa-utensils\\\"></i> \\u996e\\u98df\\u51b7\\u70ed\\u5e73\\u8861</span>\\n                                    <span class=\\\"example-tag\\\"><i class=\\\"fas fa-bed\\\"></i> \\u4f5c\\u606f\\u89c4\\u5f8b\\u6709\\u5e8f</span>\\n                                </div>\\n                            </div>\\n                            <!-- \\u76ee\\u6807\\u5361\\u7247 -->\\n                            <div class=\\\"balance-card goal\\\">\\n                                <div class=\\\"card-header\\\">\\n                                    <div class=\\\"card-icon\\\">\\n                                        <i class=\\\"fas fa-bullseye\\\"></i>\\n                                    </div>\\n                                    <h3 class=\\\"card-title\\\">\\u76ee\\u6807\\uff1a\\u57f9\\u517b\\u52a8\\u6001\\u5065\\u5eb7\\u89c2</h3>\\n                                </div>\\n                                <p class=\\\"card-content\\\">\\n                                    \\u8d85\\u8d8a\\u5355\\u4e00\\u4e60\\u60ef\\u57f9\\u517b\\uff0c\\u5e2e\\u52a9\\u5b69\\u5b50\\u5efa\\u7acb\\u9002\\u5e94\\u53d8\\u5316\\u7684\\u52a8\\u6001\\u5e73\\u8861\\u601d\\u7ef4\\uff0c\\u5f62\\u6210\\u7ec8\\u8eab\\u53d7\\u76ca\\u7684\\u5065\\u5eb7\\u89c2\\u5ff5\\u3002\\n                                </p>\\n                                <div class=\\\"examples\\\">\\n                                    <span class=\\\"example-tag\\\"><i class=\\\"fas fa-brain\\\"></i> \\u8ba4\\u77e5\\u7075\\u6d3b\\u6027</span>\\n                                    <span class=\\\"example-tag\\\"><i class=\\\"fas fa-heartbeat\\\"></i> \\u8eab\\u4f53\\u611f\\u77e5\\u529b</span>\\n                                    <span class=\\\"example-tag\\\"><i class=\\\"fas fa-adjust\\\"></i> \\u81ea\\u6211\\u8c03\\u8282\\u80fd\\u529b</span>\\n                                    <span class=\\\"example-tag\\\"><i class=\\\"fas fa-infinity\\\"></i> \\u6301\\u7eed\\u9002\\u5e94\\u529b</span>\\n                                </div>\\n                            </div>\\n                        </div>\\n                    </div>\\n                    <!-- \\u5e95\\u90e8\\u5f15\\u7528 -->\\n                    <div class=\\\"balance-quote\\\">\\n                        <i class=\\\"fas fa-quote-left\\\" style=\\\"color: #B3543A; margin-right: 10px;\\\"></i>\\n                        \\u5065\\u5eb7\\u4e0d\\u662f\\u9759\\u6001\\u7684\\u5b8c\\u7f8e\\u72b6\\u6001\\uff0c\\u800c\\u662f<span class=\\\"highlight\\\">\\u52a8\\u6001\\u5e73\\u8861\\u7684\\u827a\\u672f</span>\\u2014\\u2014\\u5728\\u53d8\\u5316\\u4e2d\\u627e\\u5230\\u6bcf\\u4e2a\\u5b69\\u5b50\\u72ec\\u7279\\u7684\\u5e73\\u8861\\u70b9\\n                        <i class=\\\"fas fa-quote-right\\\" style=\\\"color: #B3543A; margin-left: 10px;\\\"></i>\\n                    </div>\\n                </div>\\n            </div>\\n        </div>\\n        <!-- \\u9875\\u811a -->\\n        <div class=\\\"footer\\\">\\n            <div class=\\\"brand\\\">\\n                <i class=\\\"fas fa-seedling brand-icon\\\"></i>\\n                <span>\\u4f20\\u627f\", \"is_user_edited\": false}, {\"page_number\": 6, \"title\": \"\\u57fa\\u77f3\\u4e8c\\uff1a\\u4e94\\u884c\\u5b66\\u8bf4\\u4e0e\\u4e94\\u810f\\u517b\\u62a4\", \"html_content\": \"<!DOCTYPE html>\\n<html lang=\\\"zh-CN\\\">\\n<head>\\n    <meta charset=\\\"UTF-8\\\">\\n    <meta name=\\\"viewport\\\" content=\\\"width=device-width, initial-scale=1.0\\\">\\n    <title>\\u57fa\\u77f3\\u4e8c\\uff1a\\u4e94\\u884c\\u5b66\\u8bf4\\u4e0e\\u4e94\\u810f\\u517b\\u62a4 - \\u4e2d\\u533b\\u517b\\u751f\\u5546\\u4e1a\\u8ba1\\u5212</title>\\n    <!-- Font Awesome \\u56fe\\u6807\\u5e93 -->\\n    <link rel=\\\"stylesheet\\\" href=\\\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css\\\">\\n    <!-- Chart.js \\u56fe\\u8868\\u5e93 -->\\n    <script src=\\\"https://cdn.jsdelivr.net/npm/chart.js\\\"></script>\\n    <style>\\n        /* \\u5168\\u5c40\\u91cd\\u7f6e\\u4e0e\\u57fa\\u7840\\u6837\\u5f0f */\\n        * { margin: 0; padding: 0; box-sizing: border-box; }\\n        body {\\n            font-family: -apple-system, BlinkMacSystemFont, \\\"Segoe UI\\\", \\\"Microsoft YaHei\\\", sans-serif;\\n            background: linear-gradient(135deg, #f5f7fa 0%, #e4edf5 100%);\\n            display: flex;\\n            justify-content: center;\\n            align-items: center;\\n            min-height: 100vh;\\n            overflow: hidden;\\n            padding: 20px;\\n        }\\n        /* \\u4e3b\\u5bb9\\u5668\\uff1a\\u56fa\\u5b9a1280x720\\uff0c16:9 */\\n        .slide-container {\\n            width: 1280px;\\n            height: 720px;\\n            background-color: #F8F4E9;\\n            background-image: \\n                radial-gradient(circle at 10% 20%, rgba(212, 232, 217, 0.2) 0%, transparent 20%),\\n                radial-gradient(circle at 90% 80%, rgba(212, 232, 217, 0.2) 0%, transparent 20%);\\n            position: relative;\\n            box-shadow: 0 20px 60px rgba(42, 92, 85, 0.15);\\n            border-radius: 8px;\\n            overflow: hidden;\\n            display: flex;\\n            flex-direction: column;\\n        }\\n        /* \\u9876\\u90e8\\u6807\\u9898\\u680f */\\n        .header {\\n            background: linear-gradient(90deg, #2A5C55 0%, #3A7C6F 100%);\\n            color: white;\\n            padding: 24px 40px;\\n            position: relative;\\n            min-height: 100px;\\n            display: flex;\\n            align-items: center;\\n        }\\n        .header::after {\\n            content: \\\"\\\";\\n            position: absolute;\\n            bottom: 0;\\n            left: 5%;\\n            width: 90%;\\n            height: 2px;\\n            background: linear-gradient(90deg, transparent, #D4E8D9, transparent);\\n        }\\n        .title {\\n            font-family: \\\"Noto Serif SC\\\", \\\"Source Han Serif\\\", serif;\\n            font-size: 36px;\\n            font-weight: 700;\\n            line-height: 1.2;\\n            flex: 1;\\n        }\\n        .subtitle {\\n            font-size: 18px;\\n            opacity: 0.9;\\n            margin-top: 8px;\\n            font-weight: 300;\\n        }\\n        .logo {\\n            font-size: 24px;\\n            margin-left: 30px;\\n            color: #D4E8D9;\\n        }\\n        /* \\u5185\\u5bb9\\u533a\\u57df */\\n        .content {\\n            flex: 1;\\n            padding: 40px;\\n            overflow: hidden;\\n            position: relative;\\n        }\\n        .content-inner {\\n            height: 100%;\\n            display: flex;\\n            flex-direction: column;\\n            justify-content: center;\\n        }\\n        /* \\u9875\\u811a */\\n        .footer {\\n            background: rgba(42, 92, 85, 0.05);\\n            padding: 16px 40px;\\n            display: flex;\\n            justify-content: space-between;\\n            align-items: center;\\n            border-top: 1px solid rgba(42, 92, 85, 0.1);\\n            font-size: 14px;\\n            color: #555;\\n        }\\n        .pagination {\\n            font-weight: 600;\\n            color: #2A5C55;\\n        }\\n        .brand {\\n            display: flex;\\n            align-items: center;\\n            gap: 10px;\\n        }\\n        .brand-icon {\\n            color: #B3543A;\\n        }\\n        /* \\u88c5\\u9970\\u5143\\u7d20 */\\n        .decoration {\\n            position: absolute;\\n            opacity: 0.05;\\n            pointer-events: none;\\n        }\\n        .decoration-1 {\\n            top: 15%;\\n            right: 5%;\\n            font-size: 180px;\\n            color: #2A5C55;\\n            transform: rotate(15deg);\\n        }\\n        .decoration-2 {\\n            bottom: 20%;\\n            left: 5%;\\n            font-size: 120px;\\n            color: #B3543A;\\n            transform: rotate(-10deg);\\n        }\\n        /* \\u81ea\\u5b9a\\u4e49\\u5185\\u5bb9\\u6837\\u5f0f */\\n        .page-content {\\n            display: flex;\\n            height: 100%;\\n            gap: 30px;\\n            position: relative;\\n            z-index: 2;\\n        }\\n        /* \\u5de6\\u4fa7\\u56fe\\u8868\\u533a\\u57df */\\n        .chart-section {\\n            flex: 1.2;\\n            display: flex;\\n            flex-direction: column;\\n            justify-content: center;\\n        }\\n        .chart-title {\\n            font-size: 22px;\\n            color: #2A5C55;\\n            font-weight: 600;\\n            margin-bottom: 15px;\\n            text-align: center;\\n            font-family: \\\"Noto Serif SC\\\", serif;\\n        }\\n        .chart-wrapper {\\n            background: white;\\n            border-radius: 16px;\\n            padding: 25px;\\n            box-shadow: 0 10px 30px rgba(42, 92, 85, 0.1);\\n            border: 2px solid rgba(42, 92, 85, 0.08);\\n            height: 320px;\\n            position: relative;\\n            overflow: hidden;\\n        }\\n        /* \\u4e94\\u884c\\u5faa\\u73af\\u56fe\\u6837\\u5f0f */\\n        .five-elements-cycle {\\n            position: relative;\\n            width: 100%;\\n            height: 100%;\\n        }\\n        .cycle-center {\\n            position: absolute;\\n            top: 50%;\\n            left: 50%;\\n            transform: translate(-50%, -50%);\\n            width: 80px;\\n            height: 80px;\\n            background: linear-gradient(135deg, #2A5C55, #3A7C6F);\\n            border-radius: 50%;\\n            display: flex;\\n            align-items: center;\\n            justify-content: center;\\n            color: white;\\n            font-weight: bold;\\n            font-size: 18px;\\n            box-shadow: 0 5px 15px rgba(42, 92, 85, 0.3);\\n            z-index: 10;\\n        }\\n        .element-node {\\n            position: absolute;\\n            width: 100px;\\n            height: 100px;\\n            border-radius: 50%;\\n            display: flex;\\n            flex-direction: column;\\n            align-items: center;\\n            justify-content: center;\\n            color: white;\\n            font-weight: bold;\\n            box-shadow: 0 8px 20px rgba(0, 0, 0, 0.15);\\n            transition: transform 0.3s ease;\\n            z-index: 5;\\n        }\\n        .element-node:hover {\\n            transform: scale(1.05);\\n            z-index: 15;\\n        }\\n        .element-symbol {\\n            font-size: 28px;\\n            margin-bottom: 5px;\\n            font-family: \\\"Noto Serif SC\\\", serif;\\n        }\\n        .element-details {\\n            font-size: 14px;\\n            text-align: center;\\n            line-height: 1.3;\\n            opacity: 0.9;\\n        }\\n        .cycle-line {\\n            position: absolute;\\n            height: 4px;\\n            background: linear-gradient(90deg, rgba(42, 92, 85, 0.7), rgba(58, 124, 111, 0.7));\\n            transform-origin: 0 0;\\n            z-index: 1;\\n        }\\n        .cycle-line::after {\\n            content: \'\';\\n            position: absolute;\\n            right: -8px;\\n            top: -4px;\\n            width: 0;\\n            height: 0;\\n            border-left: 8px solid rgba(58, 124, 111, 0.9);\\n            border-top: 4px solid transparent;\\n            border-bottom: 4px solid transparent;\\n        }\\n        /* \\u53f3\\u4fa7\\u5185\\u5bb9\\u533a\\u57df */\\n        .info-section {\\n            flex: 1;\\n            display: flex;\\n            flex-direction: column;\\n            justify-content: space-between;\\n            padding: 10px 0;\\n        }\\n        .info-block {\\n            background: white;\\n            border-radius: 12px;\\n            padding: 20px;\\n            box-shadow: 0 8px 20px rgba(0, 0, 0, 0.05);\\n            border-left: 4px solid;\\n            margin-bottom: 20px;\\n            flex-grow: 1;\\n            display: flex;\\n            flex-direction: column;\\n            justify-content: center;\\n        }\\n        .info-block-title {\\n            font-size: 20px;\\n            font-weight: 600;\\n            margin-bottom: 15px;\\n            display: flex;\\n            align-items: center;\\n            gap: 10px;\\n            color: #2A5C55;\\n        }\\n        .info-block-title i {\\n            color: #B3543A;\\n        }\\n        .memory-grid {\\n            display: grid;\\n            grid-template-columns: repeat(3, 1fr);\\n            gap: 12px;\\n            margin-top: 10px;\\n        }\\n        .memory-item {\\n            background: rgba(212, 232, 217, 0.3);\\n            border-radius: 8px;\\n            padding: 10px;\\n            text-align: center;\\n            font-size: 14px;\\n            transition: all 0.3s ease;\\n        }\\n        .memory-item:hover {\\n            background: rgba(212, 232, 217, 0.5);\\n            transform: translateY(-2px);\\n        }\\n        .memory-icon {\\n            font-size: 18px;\\n            margin-bottom: 5px;\\n            display: block;\\n        }\\n        .season-list {\\n            display: flex;\\n            flex-direction: column;\\n            gap: 12px;\\n        }\\n        .season-item {\\n            display: flex;\\n            align-items: center;\\n            gap: 12px;\\n            padding: 10px 15px;\\n            background: rgba(255, 255, 255, 0.8);\\n            border-radius: 8px;\\n            border-left: 4px solid;\\n            transition: all 0.3s ease;\\n        }\\n        .season-item:hover {\\n            transform: translateX(5px);\\n            box-shadow: 0 5px 15px rgba(0, 0, 0, 0.08);\\n        }\\n        .season-color {\\n            width: 20px;\\n            height: 20px;\\n            border-radius: 50%;\\n            flex-shrink: 0;\\n        }\\n        .season-text {\\n            flex: 1;\\n            font-size: 15px;\\n        }\\n        .season-text strong {\\n            color: #2A5C55;\\n        }\\n        /* \\u54cd\\u5e94\\u5f0f\\uff1a\\u4fdd\\u630116:9\\u6bd4\\u4f8b\\u7f29\\u653e */\\n        @media (max-width: 1350px) {\\n            body { transform: scale(0.9); }\\n        }\\n        @media (max-width: 1150px) {\\n            body { transform: scale(0.8); }\\n        }\\n        @media (max-width: 900px) {\\n            body { transform: scale(0.7); }\\n        }\\n    </style>\\n</head>\\n<body>\\n    <div class=\\\"slide-container\\\">\\n        <!-- \\u88c5\\u9970\\u5143\\u7d20 -->\\n        <div class=\\\"decoration decoration-1\\\">\\n            <i class=\\\"fas fa-leaf\\\"></i>\\n        </div>\\n        <div class=\\\"decoration decoration-2\\\">\\n            <i class=\\\"fas fa-yin-yang\\\"></i>\\n        </div>\\n        <!-- \\u9876\\u90e8\\u6807\\u9898\\u680f -->\\n        <div class=\\\"header\\\">\\n            <div>\\n                <div class=\\\"title\\\">\\u57fa\\u77f3\\u4e8c\\uff1a\\u4e94\\u884c\\u5b66\\u8bf4\\u4e0e\\u4e94\\u810f\\u517b\\u62a4</div>\\n                <div class=\\\"subtitle\\\">\\u4e2d\\u533b\\u517b\\u751f\\u5728\\u513f\\u7ae5\\u79d1\\u666e\\u6559\\u80b2\\u4e2d\\u7684\\u4ef7\\u503c\\u4e0e\\u673a\\u9047</div>\\n            </div>\\n            <div class=\\\"logo\\\">\\n                <i class=\\\"fas fa-hand-holding-heart\\\"></i>\\n            </div>\\n        </div>\\n        <!-- \\u4e3b\\u5185\\u5bb9\\u533a -->\\n        <div class=\\\"content\\\">\\n            <div class=\\\"page-content\\\">\\n                <!-- \\u5de6\\u4fa7\\uff1a\\u4e94\\u884c\\u5faa\\u73af\\u56fe -->\\n                <div class=\\\"chart-section\\\">\\n                    <div class=\\\"chart-title\\\">\\u4e94\\u884c\\u76f8\\u751f\\u5faa\\u73af\\u4e0e\\u5bf9\\u5e94\\u4f53\\u7cfb</div>\\n                    <div class=\\\"chart-wrapper\\\">\\n                        <div class=\\\"five-elements-cycle\\\" id=\\\"fiveElementsCycle\\\">\\n                            <!-- \\u5faa\\u73af\\u4e2d\\u5fc3 -->\\n                            <div class=\\\"cycle-center\\\">\\u76f8\\u751f</div>\\n                            <!-- \\u4e94\\u884c\\u8282\\u70b9 -->\\n                            <div class=\\\"element-node\\\" id=\\\"node-wood\\\" style=\\\"top: 20%; left: 50%; transform: translateX(-50%); background: linear-gradient(135deg, #4CAF50, #2E7D32);\\\">\\n                                <div class=\\\"element-symbol\\\">\\u6728</div>\\n                                <div class=\\\"element-details\\\">\\u809d / \\u6625 / \\u7eff</div>\\n                            </div>\\n                            <div class=\\\"element-node\\\" id=\\\"node-fire\\\" style=\\\"top: 50%; right: 10%; background: linear-gradient(135deg, #F44336, #C62828);\\\">\\n                                <div class=\\\"element-symbol\\\">\\u706b</div>\\n                                <div class=\\\"element-details\\\">\\u5fc3 / \\u590f / \\u7ea2</div>\\n                            </div>\\n                            <div class=\\\"element-node\\\" id=\\\"node-earth\\\" style=\\\"bottom: 20%; left: 50%; transform: translateX(-50%); background: linear-gradient(135deg, #FF9800, #EF6C00);\\\">\\n                                <div class=\\\"element-symbol\\\">\\u571f</div>\\n                                <div class=\\\"element-details\\\">\\u813e / \\u957f\\u590f / \\u9ec4</div>\\n                            </div>\\n                            <div class=\\\"element-node\\\" id=\\\"node-metal\\\" style=\\\"top: 50%; left: 10%; background: linear-gradient(135deg, #9E9E9E, #616161);\\\">\\n                                <div class=\\\"element-symbol\\\">\\u91d1</div>\\n                                <div class=\\\"element-details\\\">\\u80ba / \\u79cb / \\u767d</div>\\n                            </div>\\n                            <div class=\\\"element-node\\\" id=\\\"node-water\\\" style=\\\"top: 80%; left: 50%; transform: translateX(-50%); background: linear-gradient(135deg, #2196F3, #0D47A1);\\\">\\n                                <div class=\\\"element-symbol\\\">\\u6c34</div>\\n                                <div class=\\\"element-details\\\">\\u80be / \\u51ac / \\u9ed1</div>\\n                            </div>\\n                            <!-- \\u76f8\\u751f\\u8fde\\u7ebf -->\\n                            <div class=\\\"cycle-line\\\" id=\\\"line-wood-fire\\\" style=\\\"width: 120px; top: 70px; left: 170px; transform: rotate(45deg);\\\"></div>\\n                            <div class=\\\"cycle-line\\\" id=\\\"line-fire-earth\\\" style=\\\"width: 120px; top: 170px; left: 270px; transform: rotate(135deg);\\\"></div>\\n                            <div class=\\\"cycle-line\\\" id=\\\"line-earth-metal\\\" style=\\\"width: 120px; top: 270px; left: 170px; transform: rotate(225deg);\\\"></div>\\n                            <div class=\\\"cycle-line\\\" id=\\\"line-metal-water\\\" style=\\\"width: 120px; top: 170px; left: 70px; transform: rotate(315deg);\\\"></div>\\n                            <div class=\\\"cycle-line\\\" id=\\\"line-water-wood\\\" style=\\\"width: 60px; top: 340px; left: 110px; transform: rotate(90deg);\\\"></div>\\n                        </div>\\n                    </div>\\n                </div>\\n                <!-- \\u53f3\\u4fa7\\uff1a\\u4fe1\\u606f\\u5185\\u5bb9 -->\\n                <div class=\\\"info-section\\\">\\n                    <!-- \\u8da3\\u5473\\u8bb0\\u5fc6\\u6a21\\u5757 -->\\n                    <div class=\\\"info-block\\\" style=\\\"border-left-color: #B3543A;\\\">\\n                        <div class=\\\"info-block-title\\\">\\n                            <i class=\\\"fas fa-lightbulb\\\"></i>\\n                            <span>\\u8da3\\u547