       <h3><i class=\\\"fas fa-list-check\\\"></i>\\u8bfe\\u7a0b\\u56de\\u987e\\u4e0e\\u76ee\\u6807</h3>\\n                    <ul>\\n                        <li>\\u7b2c\\u4e00\\u6b21\\u8bfe\\u6838\\u5fc3\\u77e5\\u8bc6\\u70b9\\u56de\\u987e</li>\\n                        <li>\\u672c\\u6b21\\u8bfe\\u7a0b\\u5b66\\u4e60\\u76ee\\u6807</li>\\n                        <li>\\u8bfe\\u7a0b\\u5185\\u5bb9\\u6982\\u89c8</li>\\n                    </ul>\\n                </div>\\n                \\n                <div class=\\\"content-section\\\">\\n                    <h3><i class=\\\"fas fa-cogs\\\"></i>C\\u8bed\\u8a00\\u6570\\u636e\\u7c7b\\u578b\\u8be6\\u89e3</h3>\\n                    <p>\\u57fa\\u672c\\u6570\\u636e\\u7c7b\\u578b\\uff1aint, float, double, char</p>\\n                    <div class=\\\"code-example\\\">\\n                        int age = 20;<br>\\n                        float price = 99.99;<br>\\n                        char grade = \'A\';\\n                    </div>\\n                </div>\\n                \\n                <!-- \\u56fe\\u8868\\u5360\\u4f4d\\u533a\\u57df -->\\n                <div class=\\\"chart-container\\\">\\n                    <p style=\\\"color: #a0aec0;\\\"><i class=\\\"fas fa-chart-bar\\\"></i> \\u56fe\\u8868\\u533a\\u57df - \\u652f\\u6301Chart.js/ECharts</p>\\n                </div>\\n            </div>\\n        </div>\\n        \\n        <!-- \\u5e95\\u90e8\\u4fe1\\u606f\\u680f -->\\n        <div class=\\\"footer\\\">\\n            <div class=\\\"slide-number\\\">\\n                \\u9875\\u7801: <span class=\\\"current-page\\\">{{ current_page_number }}</span> / <span class=\\\"total-pages\\\">{{ total_page_count }}</span>\\n            </div>\\n            <div class=\\\"slide-controls\\\">\\n                <div class=\\\"control-btn\\\">\\n                    <i class=\\\"fas fa-chevron-left\\\"></i>\\n                </div>\\n                <div class=\\\"control-btn\\\">\\n                    <i class=\\\"fas fa-chevron-right\\\"></i>\\n                </div>\\n                <div class=\\\"control-btn\\\">\\n                    <i class=\\\"fas fa-expand\\\"></i>\\n                </div>\\n            </div>\\n        </div>\\n    </div>\\n\\n    <script>\\n        // \\u793a\\u4f8b\\uff1a\\u521d\\u59cb\\u5316\\u4e00\\u4e2a\\u7b80\\u5355\\u7684Chart.js\\u56fe\\u8868\\n        document.addEventListener(\'DOMContentLoaded\', function() {\\n            // \\u56fe\\u8868\\u5bb9\\u5668\\n            const chartContainer = document.querySelector(\'.chart-container\');\\n            \\n            // \\u5982\\u679c\\u6709canvas\\u5143\\u7d20\\uff0c\\u521d\\u59cb\\u5316\\u56fe\\u8868\\n            if (chartContainer && typeof Chart !== \'undefined\') {\\n                // \\u521b\\u5efacanvas\\u5143\\u7d20\\n                const canvas = document.createElement(\'canvas\');\\n                chartContainer.innerHTML = \'\';\\n                chartContainer.appendChild(canvas);\\n                \\n                // \\u793a\\u4f8b\\u6570\\u636e\\uff1a\\u6570\\u636e\\u7c7b\\u578b\\u4f7f\\u7528\\u9891\\u7387 - \\u8c03\\u6574\\u4e3a\\u6d45\\u84dd\\u8272\\u7cfb\\n                const ctx = canvas.getContext(\'2d\');\\n                new Chart(ctx, {\\n                    type: \'bar\',\\n                    data: {\\n                        labels: [\'int\', \'float\', \'double\', \'char\', \'\\u5176\\u4ed6\'],\\n                        datasets: [{\\n                            label: \'\\u4f7f\\u7528\\u9891\\u7387\',\\n                            data: [65, 30, 45, 40, 20],\\n                            backgroundColor: [\\n                                \'rgba(79, 195, 247, 0.7)\', /* \\u8c03\\u6574\\u4e3a\\u6d45\\u84dd\\u8272 */\\n                                \'rgba(100, 181, 246, 0.7)\', /* \\u8c03\\u6574\\u4e3a\\u6d45\\u84dd\\u8272 */\\n                                \'rgba(129, 212, 250, 0.7)\', /* \\u8c03\\u6574\\u4e3a\\u6d45\\u84dd\\u8272 */\\n                                \'rgba(41, 182, 246, 0.7)\', /* \\u8c03\\u6574\\u4e3a\\u6d45\\u84dd\\u8272 */\\n                                \'rgba(3, 169, 244, 0.7)\'  /* \\u8c03\\u6574\\u4e3a\\u6d45\\u84dd\\u8272 */\\n                            ],\\n                            borderColor: [\\n                                \'rgb(79, 195, 247)\', /* \\u8c03\\u6574\\u4e3a\\u6d45\\u84dd\\u8272 */\\n                                \'rgb(100, 181, 246)\', /* \\u8c03\\u6574\\u4e3a\\u6d45\\u84dd\\u8272 */\\n                                \'rgb(129, 212, 250)\', /* \\u8c03\\u6574\\u4e3a\\u6d45\\u84dd\\u8272 */\\n                                \'rgb(41, 182, 246)\', /* \\u8c03\\u6574\\u4e3a\\u6d45\\u84dd\\u8272 */\\n                                \'rgb(3, 169, 244)\'  /* \\u8c03\\u6574\\u4e3a\\u6d45\\u84dd\\u8272 */\\n                            ],\\n                            borderWidth: 1\\n                        }]\\n                    },\\n                    options: {\\n                        responsive: true,\\n                        maintainAspectRatio: false,\\n                        plugins: {\\n                            legend: {\\n                                display: false\\n                            },\\n                            title: {\\n                                display: true,\\n                                text: \'C\\u8bed\\u8a00\\u6570\\u636e\\u7c7b\\u578b\\u4f7f\\u7528\\u9891\\u7387\',\\n                                font: {\\n                                    size: 16\\n                                }\\n                            }\\n                        },\\n                        scales: {\\n                            y: {\\n                                beginAtZero: true,\\n                                title: {\\n                                    display: true,\\n                                    text: \'\\u4f7f\\u7528\\u9891\\u7387 (%)\'\\n                                }\\n                            }\\n                        }\\n                    }\\n                });\\n            }\\n            \\n            // \\u9875\\u7801\\u66f4\\u65b0\\u793a\\u4f8b\\n            const currentPageEl = document.querySelector(\'.current-page\');\\n            const totalPagesEl = document.querySelector(\'.total-pages\');\\n            \\n            if (currentPageEl && currentPageEl.textContent === \'{{ current_page_number }}\') {\\n                currentPageEl.textContent = \'1\';\\n            }\\n            \\n            if (totalPagesEl && totalPagesEl.textContent === \'{{ total_page_count }}\') {\\n                totalPagesEl.textContent = \'10\';\\n            }\\n            \\n            // \\u7b80\\u5355\\u7684\\u5bfc\\u822a\\u63a7\\u5236\\n            const prevBtn = document.querySelector(\'.control-btn:nth-child(1)\');\\n            const nextBtn = document.querySelector(\'.control-btn:nth-child(2)\');\\n            \\n            if (prevBtn && nextBtn && currentPageEl) {\\n                let currentPage = parseInt(currentPageEl.textContent);\\n                \\n                prevBtn.addEventListener(\'click\', function() {\\n                    if (currentPage > 1) {\\n                        currentPage--;\\n                        currentPageEl.textContent = currentPage;\\n                        updatePageContent(currentPage);\\n                    }\\n                });\\n                \\n                nextBtn.addEventListener(\'click\', function() {\\n                    if (currentPage < parseInt(totalPagesEl.textContent)) {\\n                        currentPage++;\\n                        currentPageEl.textContent = currentPage;\\n                        updatePageContent(currentPage);\\n                    }\\n                });\\n            }\\n            \\n            function updatePageContent(pageNum) {\\n                // \\u5728\\u5b9e\\u9645\\u4f7f\\u7528\\u4e2d\\uff0c\\u8fd9\\u91cc\\u4f1a\\u66f4\\u65b0\\u9875\\u9762\\u5185\\u5bb9\\n                console.log(`\\u5207\\u6362\\u5230\\u7b2c ${pageNum} \\u9875`);\\n            }\\n        });\\n    </script>\\n</body>\\n</html>\", \"free_template_name\": \"\\u81ea\\u7531\\u6a21\\u677f-99ee02dd\", \"free_template_prompt\": \"\\u4f5c\\u4e3a\\u4e13\\u4e1a\\u7684PPT\\u6a21\\u677f\\u8bbe\\u8ba1\\u5e08\\uff0c\\u8bf7\\u6839\\u636e\\u4ee5\\u4e0bPPT\\u5927\\u7eb2\\u751f\\u6210\\u4e00\\u4e2a\\u9879\\u76ee\\u4e13\\u5c5e\\u7684HTML\\u6bcd\\u7248\\u6a21\\u677f\\uff08\\u81ea\\u7531\\u6a21\\u677f\\uff09\\u3002\\n\\u8bf7\\u6309\\u7167\\u4ee5\\u4e0b\\u6b65\\u9aa4\\u601d\\u8003\\u5e76\\u751f\\u6210\\uff1a\\n1. \\u9996\\u5148\\u5206\\u6790PPT\\u5927\\u7eb2\\u7684\\u4e3b\\u9898\\u3001\\u573a\\u666f\\u548c\\u53d7\\u4f17\\n2. \\u8bbe\\u8ba1\\u6a21\\u677f\\u7684\\u6574\\u4f53\\u98ce\\u683c\\u548c\\u5e03\\u5c40\\uff08\\u4f60\\u81ea\\u884c\\u51b3\\u5b9a\\u6700\\u5408\\u9002\\u7684\\u98ce\\u683c\\u3001\\u914d\\u8272\\u3001\\u5b57\\u4f53\\u4e0e\\u88c5\\u9970\\u5143\\u7d20\\uff09\\n3. \\u786e\\u5b9a\\u8272\\u5f69\\u65b9\\u6848\\u548c\\u5b57\\u4f53\\u9009\\u62e9\\n4. \\u7f16\\u5199HTML\\u7ed3\\u6784\\n5. \\u6dfb\\u52a0CSS\\u6837\\u5f0f\\n6. \\u4f18\\u5316\\u548c\\u5b8c\\u5584\\n===== \\u9879\\u76ee\\u4fe1\\u606f =====\\n\\u4e3b\\u9898\\uff1aC\\u8bed\\u8a00\\u7b2c\\u4e8c\\u6b21\\u8bfe\\n\\u573a\\u666f\\uff1atechnology\\n\\u53d7\\u4f17\\uff1a\\u5b66\\u751f\\u7fa4\\u4f53\\n\\u98ce\\u683c\\u504f\\u597d\\uff1ageneral\\n===== PPT\\u5927\\u7eb2\\uff08\\u6700\\u591a\\u5c55\\u793a\\u524d5\\u9875\\uff09=====\\n1. C\\u8bed\\u8a00\\u7b2c\\u4e8c\\u6b21\\u8bfe\\uff08title\\uff09\\uff1a\\u57fa\\u4e8e\\u6587\\u6863\\u5185\\u5bb9\\u751f\\u6210\\uff1b\\u6f14\\u793a\\u8005\\uff1b\\u65e5\\u671f\\n2. \\u8bfe\\u7a0b\\u56de\\u987e\\u4e0e\\u76ee\\u6807\\uff08content\\uff09\\uff1a\\u7b2c\\u4e00\\u6b21\\u8bfe\\u6838\\u5fc3\\u77e5\\u8bc6\\u70b9\\u56de\\u987e\\uff1b\\u672c\\u6b21\\u8bfe\\u7a0b\\u5b66\\u4e60\\u76ee\\u6807\\uff1b\\u8bfe\\u7a0b\\u5185\\u5bb9\\u6982\\u89c8\\n3. C\\u8bed\\u8a00\\u6570\\u63