n>\n    </div>\n\n    <script>\n        let currentSlide = 0;\n        const totalSlides = 12;\n\n        // No need for initialization - iframes already have src set to file paths\n\n        function showSlide(index) {\n            document.querySelectorAll(\'.slide\').forEach(slide => slide.style.display = \'none\');\n            const targetSlide = document.getElementById(\'slide-\' + (index + 1));\n            if (targetSlide) {\n                targetSlide.style.display = \'block\';\n            }\n            document.getElementById(\'slideCounter\').textContent = (index + 1) + \' / \' + totalSlides;\n        }\n\n        function nextSlide() {\n            if (currentSlide < totalSlides - 1) {\n                currentSlide++;\n                showSlide(currentSlide);\n            }\n        }\n\n        function previousSlide() {\n            if (currentSlide > 0) {\n                currentSlide--;\n                showSlide(currentSlide);\n            }\n        }\n\n        // Keyboard navigation\n        document.addEventListener(\'keydown\', function(e) {\n            if (e.key === \'ArrowRight\') nextSlide();\n            if (e.key === \'ArrowLeft\') previousSlide();\n        });\n\n        // Initialize when page loads\n        document.addEventListener(\'DOMContentLoaded\', function() {\n            showSlide(0);\n        });\n    </script>\n</body>\n</html>\n            ','[{\"page_number\": 1, \"title\": \"\\u5174\\u8870\\u5468\\u671f\\u4e0e\\u6587\\u660e\\u4f20\\u627f\\uff1a\\u4e2d\\u56fd\\u738b\\u671d\\u66f4\\u66ff\\u7684\\u5386\\u53f2\\u903b\\u8f91\\u4e0e\\u6a21\\u5f0f\\u5206\\u6790\", \"html_content\": \"<!DOCTYPE html>\\n<html lang=\\\"zh-CN\\\">\\n<head>\\n    <meta charset=\\\"UTF-8\\\">\\n    <meta name=\\\"viewport\\\" content=\\\"width=device-width, initial-scale=1.0\\\">\\n    <title>\\u5174\\u8870\\u5468\\u671f\\u4e0e\\u6587\\u660e\\u4f20\\u627f\\uff1a\\u4e2d\\u56fd\\u738b\\u671d\\u66f4\\u66ff\\u7684\\u5386\\u53f2\\u903b\\u8f91\\u4e0e\\u6a21\\u5f0f\\u5206\\u6790 - \\u4e2d\\u56fd\\u738b\\u671d\\u66f4\\u66ff\\u5386\\u53f2</title>\\n    <!-- Font Awesome \\u56fe\\u6807 -->\\n    <link rel=\\\"stylesheet\\\" href=\\\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css\\\">\\n    <!-- \\u8c37\\u6b4c\\u5b57\\u4f53\\uff1a\\u601d\\u6e90\\u5b8b\\u4f53 & \\u601d\\u6e90\\u9ed1\\u4f53 -->\\n    <link href=\\\"https://fonts.googleapis.com/css2?family=Noto+Serif+SC:wght@400;600;700&family=Source+Han+Sans+SC:wght@300;400;500&display=swap\\\" rel=\\\"stylesheet\\\">\\n    <style>\\n        /* CSS \\u53d8\\u91cf\\u5b9a\\u4e49 - \\u4e25\\u683c\\u4fdd\\u6301\\u539f\\u6a21\\u677f */\\n        :root {\\n            --color-primary: #8B0000;\\n            --color-secondary: #D4AF37;\\n            --color-dark: #2C2C2C;\\n            --color-light: #F5F5F5;\\n            --color-border: #C0A080;\\n            --font-title: \'Noto Serif SC\', serif;\\n            --font-body: \'Source Han Sans SC\', sans-serif;\\n        }\\n\\n        * {\\n            margin: 0;\\n            padding: 0;\\n            box-sizing: border-box;\\n        }\\n\\n        html, body {\\n            width: 100%;\\n            height: 100%;\\n            overflow: hidden;\\n            display: flex;\\n            align-items: center;\\n            justify-content: center;\\n            background: linear-gradient(135deg, #1a1a1a 0%, #2c2c2c 100%);\\n        }\\n\\n        .slide-container {\\n            width: 1280px;\\n            height: 720px;\\n            background-color: var(--color-light);\\n            display: flex;\\n            flex-direction: column;\\n            position: relative;\\n            box-shadow: 0 20px 50px rgba(0, 0, 0, 0.3);\\n            font-family: var(--font-body);\\n            color: var(--color-dark);\\n            overflow: hidden;\\n        }\\n\\n        /* \\u9876\\u90e8\\u6807\\u9898\\u680f - \\u4e25\\u683c\\u4fdd\\u6301\\u539f\\u6837 */\\n        .header {\\n            height: 100px;\\n            background: linear-gradient(to right, var(--color-primary), #6A0000);\\n            color: white;\\n            padding: 20px 40px;\\n            display: flex;\\n            justify-content: space-between;\\n            align-items: center;\\n            border-bottom: 3px solid var(--color-secondary);\\n            position: relative;\\n        }\\n\\n        .header::before {\\n            content: \\\"\\\";\\n            position: absolute;\\n            bottom: -5px;\\n            left: 5%;\\n            width: 90%;\\n            height: 8px;\\n            background: url(\'data:image/svg+xml;utf8,<svg xmlns=\\\"http://www.w3.org/2000/svg\\\" viewBox=\\\"0 0 100 10\\\" width=\\\"100\\\" height=\\\"10\\\"><path d=\\\"M0,5 Q25,0 50,5 T100,5\\\" stroke=\\\"%23D4AF37\\\" fill=\\\"none\\\" stroke-width=\\\"2\\\"/></svg>\') repeat-x;\\n        }\\n\\n        .title-main {\\n            font-family: var(--font-title);\\n            font-size: 2.2rem;\\n            font-weight: 700;\\n            letter-spacing: 1px;\\n        }\\n\\n        .title-sub {\\n            font-size: 1rem;\\n            opacity: 0.9;\\n            margin-top: 5px;\\n        }\\n\\n        .header-info {\\n            text-align: right;\\n            font-size: 0.95rem;\\n        }\\n\\n        /* \\u4e3b\\u8981\\u5185\\u5bb9\\u533a\\u57df - \\u521b\\u610f\\u8bbe\\u8ba1\\u533a\\u57df */\\n        .main-content {\\n            flex: 1;\\n            padding: 0;\\n            position: relative;\\n            overflow: hidden;\\n            background: linear-gradient(to bottom, #F9F5F0 0%, #F5F1E8 100%);\\n        }\\n\\n        /* \\u80cc\\u666f\\u88c5\\u9970\\u5143\\u7d20 */\\n        .background-elements {\\n            position: absolute;\\n            width: 100%;\\n            height: 100%;\\n            z-index: 1;\\n            opacity: 0.08;\\n        }\\n\\n        .timeline-spiral {\\n            position: absolute;\\n            width: 800px;\\n            height: 800px;\\n            top: 50%;\\n            left: 50%;\\n            transform: translate(-50%, -50%);\\n            background: radial-gradient(circle, transparent 60%, var(--color-primary) 100%);\\n            border-radius: 50%;\\n        }\\n\\n        .timeline-spiral::before {\\n            content: \\\"\\\";\\n            position: absolute;\\n            width: 100%;\\n            height: 100%;\\n            background: conic-gradient(\\n                from 0deg,\\n                transparent 0deg 60deg,\\n                var(--color-secondary) 60deg 120deg,\\n                transparent 120deg 180deg,\\n                var(--color-primary) 180deg 240deg,\\n                transparent 240deg 300deg,\\n                var(--color-border) 300deg 360deg\\n            );\\n            border-radius: 50%;\\n            animation: rotate 60s linear infinite;\\n        }\\n\\n        @keyframes rotate {\\n            from { transform: rotate(0deg); }\\n            to { transform: rotate(360deg); }\\n        }\\n\\n        /* \\u4e3b\\u8981\\u5185\\u5bb9\\u5bb9\\u5668 */\\n        .content-wrapper {\\n            position: relative;\\n            z-index: 2;\\n            width: 100%;\\n            height: 100%;\\n            display: flex;\\n            flex-direction: column;\\n            align-items: center;\\n            justify-content: center;\\n            padding: 40px 80px;\\n        }\\n\\n        /* \\u6807\\u9898\\u533a\\u57df */\\n        .title-section {\\n            text-align: center;\\n            margin-bottom: 50px;\\n            max-width: 900px;\\n        }\\n\\n        .main-title {\\n            font-family: var(--font-title);\\n            font-size: 3.5rem;\\n            font-weight: 700;\\n            color: var(--color-primary);\\n            line-height: 1.2;\\n            margin-bottom: 20px;\\n            text-shadow: 2px 2px 4px rgba(0, 0, 0, 0.1);\\n            position: relative;\\n            padding-bottom: 25px;\\n        }\\n\\n        .main-title::after {\\n            content: \\\"\\\";\\n            position: absolute;\\n            bottom: 0;\\n            left: 50%;\\n            transform: translateX(-50%);\\n            width: 200px;\\n            height: 3px;\\n            background: linear-gradient(to right, transparent, var(--color-secondary), transparent);\\n        }\\n\\n        .subtitle {\\n            font-family: var(--font-title);\\n            font-size: 1.8rem;\\n            color: var(--color-dark);\\n            font-weight: 600;\\n            line-height: 1.4;\\n            opacity: 0.9;\\n        }\\n\\n        /* \\u4fe1\\u606f\\u5361\\u7247\\u533a\\u57df */\\n        .info-section {\\n            display: flex;\\n            flex-direction: column;\\n            align-items: center;\\n            gap: 25px;\\n            margin-top: 30px;\\n        }\\n\\n        .info-card {\\n            background: rgba(255, 255, 255, 0.9);\\n            padding: 20px 40px;\\n            border-radius: 12px;\\n            box-shadow: 0 8px 30px rgba(139, 0, 0, 0.1);\\n            border-left: 4px solid var(--color-secondary);\\n            text-align: center;\\n            min-width: 500px;\\n            backdrop-filter: blur(10px);\\n            transition: transform 0.3s ease, box-shadow 0.3s ease;\\n        }\\n\\n        .info-card:hover {\\n            transform: translateY(-5px);\\n            box-shadow: 0 12px 40px rgba(139, 0, 0, 0.15);\\n        }\\n\\n        .info-line {\\n            display: flex;\\n            align-items: center;\\n            justify-content: center;\\n            gap: 15px;\\n            font-size: 1.3rem;\\n            color: var(--color-dark);\\n            margin: 8px 0;\\n        }\\n\\n        .info-icon {\\n            color: var(--color-secondary);\\n            font-size: 1.2rem;\\n            width: 24px;\\n            text-align: center;\\n        }\\n\\n        .info-text {\\n            font-family: var(--font-body);\\n            font-weight: 500;\\n        }\\n\\n        .highlight {\\n            color: var(--color-primary);\\n            font-weight: 600;\\n        }\\n\\n        /* \\u88c5\\u9970\\u5143\\u7d20 */\\n        .decoration-elements {\\n            position: absolute;\\n            width: 100%;\\n            height: 100%;\\n            pointer-events: none;\\n            z-index: 1;\\n        }\\n\\n        .dynasty-symbol {\\n            position: absolute;\\n            font-family: var(--font-title);\\n            font-size: 1.2rem;\\n            color: rgba(139, 0, 0, 0.15);\\n            font-weight: 700;\\n        }\\n\\n        /* \\u5e95\\u90e8\\u9875\\u7801\\u680f - \\u4e25\\u683c\\u4fdd\\u6301\\u539f\\u6837 */\\n        .footer {\\n            height: 60px;\\n            background: var(--color-dark);\\n            color: #ddd;\\n            display: flex;\\n            justify-content: space-between;\\n            align-items: center;\\n            padding: 0 40px;\\n            border-top: 2px solid var(--color-secondary);\\n            font-size: 0.9rem;\\n            position: relative;\\n            z-index: 3;\\n        }\\n\\n        .footer::before {\\n            content: \\\"\\\";\\n            position: absolute;\\n            top: -5px;\\n            left: 5%;\\n            width: 90%;\\n            height: 8px;\\n            background: url(\'data:image/svg+xml;utf8,<svg xmlns=\\\"http://www.w3.org/2000/svg\\\" viewBox=\\\"0 0 100 10\\\" width=\\\"100\\\" height=\\\"10\\\"><path d=\\\"M0,5 Q25,10 50,5 T100,5\\\" stroke=\\\"%23D4AF37\\\" fill=\\\"none\\\" stroke-width=\\\"2\\\"/></svg>\') repeat-x;\\n        }\\n\\n        .footer-left {\\n            display: flex;\\n            align-items: center;\\n            gap: 10px;\\n        }\\n\\n        .page-numbers {\\n            font-family: var(--font-title);\\n            font-size: 1.1rem;\\n        }\\n\\n        .footer-right {\\n            display: flex;\\n            align-items: center;\\n            gap: 15px;\\n        }\\n\\n        .icon {\\n            color: var(--color-secondary);\\n            font-size: 1.2rem;\\n        }\\n\\n        /* \\u54cd\\u5e94\\u5f0f\\u9002\\u914d */\\n        @media (max-width: 1280px) {\\n            .slide-container {\\n                transform: scale(0.9);\\n                transform-origin: top center;\\n            }\\n        }\\n        @media (max-width: 1024px) {\\n            .slide-container {\\n                transform: scale(0.75);\\n            }\\n        }\\n        @media (max-width: 768px) {\\n            .slide-container {\\n                transform: scale(0.6);\\n            }\\n        }\\n    </style>\\n</head>\\n<body>\\n    <div class=\\\"slide-container\\\">\\n        <!-- \\u9876\\u90e8\\u6807\\u9898\\u680f - \\u4e25\\u683c\\u4fdd\\u6301\\u539f\\u6837 -->\\n        <header class=\\\"header\\\">\\n            <div class=\\\"title-block\\\">\\n                <div class=\\\"title-main\\\">\\u4e2d\\u56fd\\u738b\\u671d\\u66f4\\u66ff\\u5386\\u53f2\\u7814\\u7a76</div>\\n                <div class=\\\"title-sub\\\">\\u5b66\\u672f\\u7814\\u8ba8\\u4f1a \\u00b7 \\u5386\\u53f2\\u793e\\u4f1a\\u5b66\\u4e13\\u9898</div>\\n            </div>\\n            <div class=\\\"header-info\\\">\\n                <div><i class=\\\"fas fa-user icon\\\"></i> \\u4e3b\\u8bb2\\u4eba\\uff1a\\u5f20\\u6559\\u6388</div>\\n                <div><i class=\\\"fas fa-university icon\\\"></i> \\u4e1c\\u65b9\\u5927\\u5b66\\u5386\\u53f2\\u5b66\\u9662</div>\\n                <div><i class=\\\"far fa-calendar icon\\\"></i> 2023\\u5e7410\\u6708</div>\\n            </div>\\n        </header>\\n\\n        <!-- \\u4e3b\\u8981\\u5185\\u5bb9\\u533a\\u57df - \\u521b\\u610f\\u8bbe\\u8ba1 -->\\n        <main class=\\\"main-content\\\">\\n            <!-- \\u80cc\\u666f\\u88c5\\u9970 -->\\n            <div class=\\\"background-elements\\\">\\n                <div class=\\\"timeline-spiral\\\"></div>\\n            </div>\\n\\n            <!-- \\u88c5\\u9970\\u6027\\u671d\\u4ee3\\u7b26\\u53f7 -->\\n            <div class=\\\"decoration-elements\\\">\\n                <div class=\\\"dynasty-symbol\\\" style=\\\"top: 15%; left: 10%;\\\">\\u590f</div>\\n                <div class=\\\"dynasty-symbol\\\" style=\\\"top: 25%; right: 15%;\\\">\\u5546</div>\\n                <div class=\\\"dynasty-symbol\\\" style=\\\"top: 40%; left: 20%;\\\">\\u5468</div>\\n                <div class=\\\"dynasty-symbol\\\" style=\\\"top: 55%; right: 25%;\\\">\\u79e6</div>\\n                <div class=\\\"dynasty-symbol\\\" style=\\\"top: 70%; left: 15%;\\\">\\u6c49</div>\\n                <div class=\\\"dynasty-symbol\\\" style=\\\"top: 85%; right: 20%;\\\">\\u5510</div>\\n                <div class=\\\"dynasty-symbol\\\" style=\\\"top: 60%; left: 85%;\\\">\\u5b8b</div>\\n                <div class=\\\"dynasty-symbol\\\" style=\\\"top: 30%; right: 5%;\\\">\\u660e</div>\\n                <div class=\\\"dynasty-symbol\\\" style=\\\"top: 10%; left: 85%;\\\">\\u6e05</div>\\n            </div>\\n\\n            <!-- \\u4e3b\\u8981\\u5185\\u5bb9 -->\\n            <div class=\\\"content-wrapper\\\">\\n                <div class=\\\"title-section\\\">\\n                    <h1 class=\\\"main-title\\\">\\u5174\\u8870\\u5468\\u671f\\u4e0e\\u6587\\u660e\\u4f20\\u627f</h1>\\n                    <div class=\\\"subtitle\\\">\\u4e2d\\u56fd\\u738b\\u671d\\u66f4\\u66ff\\u7684\\u5386\\u53f2\\u903b\\u8f91\\u4e0e\\u6a21\\u5f0f\\u5206\\u6790</div>\\n                </div>\\n\\n                <div class=\\\"info-section\\\">\\n                    <div class=\\\"info-card\\\">\\n                        <div class=\\\"info-line\\\">\\n                            <i class=\\\"fas fa-user-tie info-icon\\\"></i>\\n                            <span class=\\\"info-text\\\">\\u4e3b\\u8bb2\\u4eba\\uff1a<span class=\\\"highlight\\\">\\u5f20\\u660e\\u8fdc \\u6559\\u6388</span></span>\\n                        </div>\\n                        <div class=\\\"info-line\\\">\\n                            <i class=\\\"fas fa-graduation-cap info-icon\\\"></i>\\n                            <span class=\\\"info-text\\\">\\u4e1c\\u65b9\\u5927\\u5b66\\u5386\\u53f2\\u5b66\\u9662 \\u00b7 \\u4e2d\\u56fd\\u53e4\\u4ee3\\u53f2\\u7814\\u7a76\\u4e2d\\u5fc3</span>\\n                        </div>\\n                    </div>\\n\\n                    <div class=\\\"info-card\\\">\\n                        <div class=\\\"info-line\\\">\\n                            <i class=\\\"fas fa-users info-icon\\\"></i>\\n                            <span class=\\\"info-text\\\">\\u5386\\u53f2\\u793e\\u4f1a\\u5b66\\u4e13\\u9898 \\u00b7 \\u5b66\\u672f\\u7814\\u8ba8\\u4f1a</span>\\n                        </div>\\n                        <div class=\\\"info-line\\\">\\n                            <i class=\\\"fas fa-calendar-alt info-icon\\\"></i>\\n                            <span class=\\\"info-text\\\">2023\\u5e7410\\u6708 \\u00b7 \\u5317\\u4eac</span>\\n                        </div>\\n                    </div>\\n                </div>\\n            </div>\\n        </main>\\n\\n        <!-- \\u5e95\\u90e8\\u9875\\u7801\\u680f - \\u4e25\\u683c\\u4fdd\\u6301\\u539f\\u6837 -->\\n        <footer class=\\\"footer\\\">\\n            <div class=\\\"footer-left\\\">\\n                <i class=\\\"fas fa-landmark icon\\\"></i> \\u738b\\u671d\\u66f4\\u66ff\\u7684\\u5386\\u53f2\\u903b\\u8f91\\u4e0e\\u6a21\\u5f0f\\u5206\\u6790\\n            </div>\\n            <div class=\\\"footer-right\\\">\\n                <div class=\\\"page-numbers\\\">\\n                    <span class=\\\"current-page\\\">1</span> / <span class=\\\"total-pages\\\">12</span>\\n                </div>\\n                <div class=\\\"footer-icons\\\">\\n                    <i class=\\\"fas fa-scroll icon\\\"></i>\\n                    <i class=\\\"fas fa-history icon\\\"></i>\\n                </div>\\n            </div>\\n        </footer>\\n    </div>\\n\\n    <script>\\n        // \\u6dfb\\u52a0\\u5fae\\u5999\\u7684\\u5165\\u573a\\u52a8\\u753b\\n        document.addEventListener(\'DOMContentLoaded\', function() {\\n            const title = document.querySelector(\'.main-title\');\\n            const subtitle = document.querySelector(\'.subtitle\');\\n            const infoCards = document.querySelectorAll(\'.info-card\');\\n            \\n            // \\u521d\\u59cb\\u72b6\\u6001\\n            title.style.opacity = \'0\';\\n            title.style.transform = \'translateY(30px)\';\\n            subtitle.style.opacity = \'0\';\\n            subtitle.style.transform = \'translateY(20px)\';\\n            infoCards.forEach(card => {\\n                card.style.opacity = \'0\';\\n                card.style.transform = \'translateY(20px)\';\\n            });\\n            \\n            // \\u52a8\\u753b\\u5e8f\\u5217\\n            setTimeout(() => {\\n                title.style.transition = \'opacity 1s ease, transform 1s ease\';\\n                title.style.opacity = \'1\';\\n                title.style.transform = \'translateY(0)\';\\n            }, 300);\\n            \\n            setTimeout(() => {\\n                subtitle.style.transition = \'opacity 0.8s ease, transform 0.8s ease\';\\n                subtitle.style.opacity = \'1\';\\n                subtitle.style.transform = \'translateY(0)\';\\n            }, 800);\\n            \\n            setTimeout(() => {\\n                infoCards.forEach((card, index) => {\\n                    setTimeout(() => {\\n                        card.style.transition = \'opacity 0.6s ease, transform 0.6s ease\';\\n                        card.style.opacity = \'1\';\\n                        card.style.transform = \'translateY(0)\';\\n                    }, index * 200);\\n                });\\n            }, 1200);\\n        });\\n    </script>\\n</body>\\n</html>\", \"is_user_edited\": false}, {\"page_number\": 2, \"title\": \"\\u76ee\\u5f55\", \"html_content\": \"<!DOCTYPE html>\\n<html lang=\\\"zh-CN\\\">\\n<head>\\n    <meta charset=\\\"UTF-8\\\">\\n    <meta name=\\\"viewport\\\" content=\\\"width=device-width, initial-scale=1.0\\\">\\n    <title>\\u76ee\\u5f55 - \\u4e2d\\u56fd\\u738b\\u671d\\u66f4\\u66ff\\u5386\\u53f2</title>\\n    <!-- Font Awesome \\u56fe\\u6807 -->\\n    <link rel=\\\"stylesheet\\\" href=\\\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css\\\">\\n    <!-- \\u8c37\\u6b4c\\u5b57\\u4f53\\uff1a\\u601d\\u6e90\\u5b8b\\u4f53 & \\u601d\\u6e90\\u9ed1\\u4f53 -->\\n    <link href=\\\"https://fonts.googleapis.com/css2?family=Noto+Serif+SC:wght@400;600;700&family=Source+Han+Sans+SC:wght@300;400;500&display=swap\\\" rel=\\\"stylesheet\\\">\\n    <style>\\n        /* CSS \\u53d8\\u91cf\\u5b9a\\u4e49 */\\n        :root {\\n            --color-primary: #8B0000;\\n            --color-secondary: #D4AF37;\\n            --color-dark: #2C2C2C;\\n            --color-light: #F5F5F5;\\n            --color-border: #C0A080;\\n            --font-title: \'Noto Serif SC\', serif;\\n            --font-body: \'Source Han Sans SC\', sans-serif;\\n            --color-accent-blue: #1a365d;\\n            --color-paper: #f5f1e6;\\n        }\\n\\n        * {\\n            margin: 0;\\n            padding: 0;\\n            box-sizing: border-box;\\n        }\\n\\n        html, body {\\n            width: 100%;\\n            height: 100%;\\n            overflow: hidden;\\n            display: flex;\\n            align-items: center;\\n            justify-content: center;\\n            background-color: #f0f0f0;\\n        }\\n\\n        .slide-container {\\n            width: 1280px;\\n            height: 720px;\\n            background-color: var(--color-light);\\n            display: flex;\\n            flex-direction: column;\\n            position: relative;\\n            box-shadow: 0 10px 30px rgba(0, 0, 0, 0.15);\\n            font-family: var(--font-body);\\n            color: var(--color-dark);\\n        }\\n\\n        /* \\u9876\\u90e8\\u6807\\u9898\\u680f */\\n        .header {\\n            height: 100px;\\n            background: linear-gradient(to right, var(--color-primary), #6A0000);\\n            color: white;\\n            padding: 20px 40px;\\n            display: flex;\\n            justify-content: space-between;\\n            align-items: center;\\n            border-bottom: 3px solid var(--color-secondary);\\n            position: relative;\\n        }\\n\\n        .header::before {\\n            content: \\\"\\\";\\n            position: absolute;\\n            bottom: -5px;\\n            left: 5%;\\n            width: 90%;\\n            height: 8px;\\n            background: url(\'data:image/svg+xml;utf8,<svg xmlns=\\\"http://www.w3.org/2000/svg\\\" viewBox=\\\"0 0 100 10\\\" width=\\\"100\\\" height=\\\"10\\\"><path d=\\\"M0,5 Q25,0 50,5 T100,5\\\" stroke=\\\"%23D4AF37\\\" fill=\\\"none\\\" stroke-width=\\\"2\\\"/></svg>\') repeat-x;\\n        }\\n\\n        .title-main {\\n            font-family: var(--font-title);\\n            font-size: 2.2rem;\\n            font-weight: 700;\\n            letter-spacing: 1px;\\n        }\\n\\n        .title-sub {\\n            font-size: 1rem;\\n            opacity: 0.9;\\n            margin-top: 5px;\\n        }\\n\\n        .header-info {\\n            text-align: right;\\n            font-size: 0.95rem;\\n        }\\n\\n        /* \\u4e3b\\u8981\\u5185\\u5bb9\\u533a\\u57df - \\u5b8c\\u5168\\u91cd\\u6784 */\\n        .main-content {\\n            flex: 1;\\n            padding: 20px 50px 30px;\\n            overflow: hidden;\\n            position: relative;\\n            display: flex;\\n            flex-direction: column;\\n            background: linear-gradient(to bottom, #ffffff, var(--color-paper));\\n        }\\n\\n        .page-title {\\n            font-family: var(--font-title);\\n            font-size: 2.8rem;\\n            color: var(--color-primary);\\n            text-align: center;\\n            margin: 15px 0 25px;\\n            padding-bottom: 15px;\\n            border-bottom: 3px solid var(--color-secondary);\\n            position: relative;\\n        }\\n\\n        .page-title::after {\\n            content: \\\"\\u63a2\\u5bfb\\u4e2d\\u56fd\\u738b\\u671d\\u66f4\\u66ff\\u7684\\u5185\\u5728\\u903b\\u8f91\\\";\\n            display: block;\\n            font-family: var(--font-body);\\n            font-size: 1.1rem;\\n            color: var(--color-accent-blue);\\n            font-weight: 400;\\n            margin-top: 8px;\\n            letter-spacing: 2px;\\n        }\\n\\n        /* \\u76ee\\u5f55\\u5bb9\\u5668 */\\n        .agenda-container {\\n            flex: 1;\\n            display: flex;\\n            flex-direction: column;\\n            justify-content: center;\\n            padding: 10px 0 30px;\\n        }\\n\\n        /* \\u65f6\\u95f4\\u8f74\\u5e03\\u5c40 */\\n        .timeline-agenda {\\n            display: flex;\\n            flex-direction: column;\\n            gap: 22px;\\n            max-width: 900px;\\n            margin: 0 auto;\\n            position: relative;\\n        }\\n\\n        /* \\u65f6\\u95f4\\u8f74\\u7ebf */\\n        .timeline-agenda::before {\\n            content: \\\"\\\";\\n            position: absolute;\\n            left: 40px;\\n            top: 0;\\n            bottom: 0;\\n            width: 4px;\\n            background: linear-gradient(to bottom, var(--color-primary), var(--color-secondary));\\n            border-radius: 2px;\\n            z-index: 1;\\n        }\\n\\n        /* \\u76ee\\u5f55\\u9879 */\\n        .agenda-item {\\n            display: flex;\\n            align-items: center;\\n            position: relative;\\n            z-index: 2;\\n            transition: transform 0.3s ease;\\n        }\\n\\n        .agenda-item:hover {\\n            transform: translateX(10px);\\n        }\\n\\n        /* \\u5e8f\\u53f7\\u5706\\u5708 */\\n        .item-number {\\n            width: 70px;\\n            flex-shrink: 0;\\n            display: flex;\\n            justify-content: center;\\n            align-items: center;\\n            position: relative;\\n        }\\n\\n        .number-circle {\\n            width: 50px;\\n            height: 50px;\\n            border-radius: 50%;\\n            background: var(--color-primary);\\n            color: white;\\n            display: flex;\\n            align-items: center;\\n            justify-content: center;\\n            font-family: var(--font-title);\\n            font-size: 1.5rem;\\n            font-weight: 700;\\n            box-shadow: 0 4px 12px rgba(139, 0, 0, 0.3);\\n            position: relative;\\n            z-index: 3;\\n            border: 3px solid white;\\n        }\\n\\n        /* \\u8fde\\u63a5\\u70b9 */\\n        .item-number::after {\\n            content: \\\"\\\";\\n            position: absolute;\\n            left: 50%;\\n            transform: translateX(-50%);\\n            width: 20px;\\n            height: 20px;\\n            background-color: var(--color-secondary);\\n            border-radius: 50%;\\n            border: 4px solid white;\\n            box-shadow: 0 0 0 3px var(--color-secondary);\\n            z-index: 2;\\n        }\\n\\n        /* \\u5185\\u5bb9\\u5361\\u7247 */\\n        .item-content {\\n            flex: 1;\\n            background: white;\\n            border-left: 5px solid var(--color-accent-blue);\\n            border-radius: 0 12px 12px 0;\\n            padding: 20px 25px;\\n            box-shadow: 0 5px 15px rgba(0, 0, 0, 0.08);\\n            display: flex;\\n            align-items: center;\\n            gap: 20px;\\n            transition: all 0.3s ease;\\n            min-height: 90px;\\n        }\\n\\n        .agenda-item:hover .item-content {\\n            box-shadow: 0 8px 20px rgba(0, 0, 0, 0.12);\\n            border-left-width: 8px;\\n        }\\n\\n        /* \\u56fe\\u6807 */\\n        .item-icon {\\n            width: 50px;\\n            height: 50px;\\n            flex-shrink: 0;\\n            display: flex;\\n            align-items: center;\\n            justify-content: center;\\n            background: linear-gradient(135deg, var(--color-paper), #e8e0d0);\\n            border-radius: 50%;\\n            color: var(--color-primary);\\n            font-size: 1.4rem;\\n            border: 2px solid rgba(212, 175, 55, 0.3);\\n        }\\n\\n        /* \\u6587\\u672c */\\n        .item-text {\\n            flex: 1;\\n        }\\n\\n        .item-title {\\n            font-family: var(--font-title);\\n            font-size: 1.5rem;\\n            font-weight: 600;\\n            color: var(--color-dark);\\n            margin-bottom: 5px;\\n            display: flex;\\n            align-items: baseline;\\n            flex-wrap: wrap;\\n        }\\n\\n        .item-subtitle {\\n            font-size: 1.1rem;\\n            color: var(--color-accent-blue);\\n            font-weight: 500;\\n            margin-left: 10px;\\n            opacity: 0.9;\\n        }\\n\\n        .item-desc {\\n            font-size: 1rem;\\n            color: #666;\\n            line-height: 1.5;\\n            font-weight: 300;\\n        }\\n\\n        /* \\u9875\\u7801\\u6807\\u7b7e */\\n        .page-tag {\\n            background: var(--color-secondary);\\n            color: var(--color-dark);\\n            padding: 4px 12px;\\n            border-radius: 20px;\\n            font-size: 0.85rem;\\n            font-weight: 600;\\n            margin-left: 15px;\\n            white-space: nowrap;\\n        }\\n\\n        /* \\u5e95\\u90e8\\u9875\\u7801\\u680f */\\n        .footer {\\n            height: 60px;\\n            background: var(--color-dark);\\n            color: #ddd;\\n            display: flex;\\n            justify-content: space-between;\\n            align-items: center;\\n            padding: 0 40px;\\n            border-top: 2px solid var(--color-secondary);\\n            font-size: 0.9rem;\\n        }\\n\\n        .footer::before {\\n            content: \\\"\\\";\\n            position: absolute;\\n            top: -5px;\\n            left: 5%;\\n            width: 90%;\\n            height: 8px;\\n            background: url(\'data:image/svg+xml;utf8,<svg xmlns=\\\"http://www.w3.org/2000/svg\\\" viewBox=\\\"0 0 100 10\\\" width=\\\"100\\\" height=\\\"10\\\"><path d=\\\"M0,5 Q25,10 50,5 T100,5\\\" stroke=\\\"%23D4AF37\\\" fill=\\\"none\\\" stroke-width=\\\"2\\\"/></svg>\') repeat-x;\\n        }\\n\\n        .page-numbers {\\n            font-family: var(--font-title);\\n            font-size: 1.1rem;\\n        }\\n\\n        .footer-right {\\n            display: flex;\\n            align-items: center;\\n            gap: 15px;\\n        }\\n\\n        .icon {\\n            color: var(--color-secondary);\\n            font-size: 1.2rem;\\n        }\\n\\n        /* \\u54cd\\u5e94\\u5f0f\\u9002\\u914d */\\n        @media (max-width: 1280px) {\\n            .slide-container {\\n                transform: scale(0.9);\\n                transform-origin: top center;\\n            }\\n        }\\n        @media (max-width: 1024px) {\\n            .slide-container {\\n                transform: scale(0.75);\\n            }\\n        }\\n        @media (max-width: 768px) {\\n            .slide-container {\\n                transform: scale(0.6);\\n            }\\n        }\\n    </style>\\n</head>\\n<body>\\n    <div class=\\\"slide-container\\\">\\n        <!-- \\u9876\\u90e8\\u6807\\u9898\\u680f -->\\n        <header class=\\\"header\\\">\\n            <div class=\\\"title-block\\\">\\n                <div class=\\\"title-main\\\">\\u4e2d\\u56fd\\u738b\\u671d\\u66f4\\u66ff\\u5386\\u53f2\\u7814\\u7a76</div>\\n                <div class=\\\"title-sub\\\">\\u5b66\\u672f\\u7814\\u8ba8\\u4f1a \\u00b7 \\u5386\\u53f2\\u793e\\u4f1a\\u5b66\\u4e13\\u9898</div>\\n            </div>\\n            <div class=\\\"header-info\\\">\\n                <div><i class=\\\"fas fa-user icon\\\"></i> \\u4e3b\\u8bb2\\u4eba\\uff1a\\u5f20