pacity: 0.95; }\\n        .circle-c { width: 86px; height: 86px; right: 52px; top: 42px; background: #cfdc72; }\\n        .circle-d { width: 54px; height: 54px; left: 36px; top: 18px; background: #7eb377; }\\n        .circle-e { width: 150px; height: 150px; left: 70px; bottom: -58px; background: #93bf84; }\\n        .circle-f { width: 270px; height: 270px; left: 230px; bottom: -120px; background: #3f7345; opacity: 0.92; }\\n        .circle-g { width: 190px; height: 190px; left: 360px; bottom: -90px; background: #9eb841; opacity: 0.85; }\\n        .circle-h { width: 76px; height: 76px; right: 86px; bottom: 46px; background: #d8de7f; }\\n        .leaf-mark {\\n            position: absolute;\\n            top: 32px;\\n            left: 44px;\\n            width: 70px;\\n            height: 48px;\\n            z-index: 3;\\n        }\\n        .leaf-mark::before,\\n        .leaf-mark::after,\\n        .leaf-mark span {\\n            content: \'\';\\n            position: absolute;\\n            border-radius: 0 0 40px 0;\\n        }\\n        .leaf-mark::before {\\n            left: 0;\\n            top: 0;\\n            width: 32px;\\n            height: 32px;\\n            background: #d8df79;\\n        }\\n        .leaf-mark::after {\\n            left: 18px;\\n            top: 0;\\n            width: 34px;\\n            height: 34px;\\n            background: #89a95d;\\n        }\\n        .leaf-mark span {\\n            left: 32px;\\n            top: 0;\\n            width: 38px;\\n            height: 38px;\\n            background: #426f4b;\\n        }\\n        /* \\u9875\\u7709\\u4fe1\\u606f\\u533a - \\u5b8c\\u5168\\u4fdd\\u6301\\u539f\\u6837 */\\n        .header-band {\\n            position: absolute;\\n            left: 78px;\\n            top: 34px;\\n            right: 100px;\\n            display: flex;\\n            align-items: center;\\n            justify-content: space-between;\\n            z-index: 4;\\n        }\\n        .logo-group {\\n            display: flex;\\n            align-items: center;\\n            gap: 14px;\\n        }\\n        .logo-badge {\\n            width: 48px;\\n            height: 48px;\\n            border-radius: 50%;\\n            border: 2px solid #5f8e4f;\\n            display: flex;\\n            align-items: center;\\n            justify-content: center;\\n            color: #5f8e4f;\\n            background: rgba(255,255,255,0.95);\\n            font-size: 22px;\\n        }\\n        .logo-text {\\n            line-height: 1.2;\\n        }\\n        .logo-text .cn {\\n            font-size: 15px;\\n            font-weight: 700;\\n            color: #527845;\\n        }\\n        .logo-text .en {\\n            font-size: 10px;\\n            color: #7d8a79;\\n            letter-spacing: 0.4px;\\n        }\\n        .template-meta {\\n            text-align: right;\\n        }\\n        .template-meta .meta-title {\\n            font-size: 16px;\\n            font-weight: 700;\\n            color: #587d48;\\n        }\\n        .template-meta .meta-subtitle {\\n            margin-top: 4px;\\n            font-size: 11px;\\n            color: #98a095;\\n            letter-spacing: 0.8px;\\n        }\\n        /* \\u9996\\u9875\\u4e3b\\u8981\\u5185\\u5bb9\\u533a\\u57df - \\u521b\\u610f\\u8bbe\\u8ba1 */\\n        .title-content {\\n            position: absolute;\\n            top: 156px;\\n            left: 68px;\\n            right: 68px;\\n            bottom: 64px;\\n            z-index: 4;\\n            display: flex;\\n            flex-direction: column;\\n            justify-content: center;\\n            align-items: center;\\n            padding: 40px;\\n        }\\n        /* \\u4e3b\\u6807\\u9898\\u533a\\u57df */\\n        .main-title-container {\\n            text-align: center;\\n            margin-bottom: 60px;\\n            position: relative;\\n            width: 100%;\\n        }\\n        .main-title {\\n            font-size: 72px;\\n            font-weight: 900;\\n            color: #3f7345;\\n            line-height: 1.1;\\n            margin-bottom: 20px;\\n            text-shadow: 0 4px 12px rgba(63, 115, 69, 0.15);\\n            position: relative;\\n            display: inline-block;\\n        }\\n        .main-title::after {\\n            content: \'\';\\n            position: absolute;\\n            bottom: -15px;\\n            left: 50%;\\n            transform: translateX(-50%);\\n            width: 180px;\\n            height: 4px;\\n            background: linear-gradient(to right, #3f7345, #8db47f, #3f7345);\\n            border-radius: 2px;\\n        }\\n        .title-sub {\\n            font-size: 28px;\\n            font-weight: 500;\\n            color: #6d9d53;\\n            margin-top: 30px;\\n            letter-spacing: 1px;\\n        }\\n        /* \\u4ee3\\u7801\\u88c5\\u9970\\u5143\\u7d20 */\\n        .code-decoration {\\n            position: absolute;\\n            top: 50%;\\n            left: 0;\\n            right: 0;\\n            transform: translateY(-50%);\\n            height: 200px;\\n            opacity: 0.08;\\n            pointer-events: none;\\n            z-index: 2;\\n        }\\n        .code-line {\\n            font-family: \'Courier New\', monospace;\\n            font-size: 14px;\\n            color: #3f7345;\\n            white-space: nowrap;\\n            margin-bottom: 8px;\\n            position: relative;\\n            padding-left: 20px;\\n        }\\n        .code-line::before {\\n            content: \'>\';\\n            position: absolute;\\n            left: 0;\\n            color: #8db47f;\\n        }\\n        /* \\u4fe1\\u606f\\u5361\\u7247\\u533a\\u57df */\\n        .info-cards {\\n            display: flex;\\n            justify-content: center;\\n            gap: 40px;\\n            width: 100%;\\n            max-width: 900px;\\n            margin-top: 30px;\\n        }\\n        .info-card {\\n            background: rgba(255, 255, 255, 0.85);\\n            border-radius: 20px;\\n            padding: 24px 30px;\\n            min-width: 250px;\\n            border: 1px solid rgba(96, 129, 79, 0.15);\\n            box-shadow: 0 8px 24px rgba(63, 115, 69, 0.08);\\n            backdrop-filter: blur(4px);\\n            transition: transform 0.3s ease, box-shadow 0.3s ease;\\n            position: relative;\\n            overflow: hidden;\\n        }\\n        .info-card:hover {\\n            transform: translateY(-5px);\\n            box-shadow: 0 12px 32px rgba(63, 115, 69, 0.15);\\n        }\\n        .info-card::before {\\n            content: \'\';\\n            position: absolute;\\n            top: 0;\\n            left: 0;\\n            right: 0;\\n            height: 4px;\\n            background: linear-gradient(to right, #3f7345, #8db47f);\\n        }\\n        .card-header {\\n            display: flex;\\n            align-items: center;\\n            gap: 12px;\\n            margin-bottom: 16px;\\n        }\\n        .card-icon {\\n            width: 40px;\\n            height: 40px;\\n            border-radius: 50%;\\n            background: #f6f8f1;\\n            display: flex;\\n            align-items: center;\\n            justify-content: center;\\n            color: #5f8e4f;\\n            font-size: 18px;\\n            border: 2px solid rgba(95, 142, 79, 0.2);\\n        }\\n        .card-title {\\n            font-size: 16px;\\n            font-weight: 700;\\n            color: #4e7543;\\n        }\\n        .card-content {\\n            font-size: 18px;\\n            font-weight: 500;\\n            color: #516250;\\n            line-height: 1.4;\\n        }\\n        .card-content .highlight {\\n            color: #3f7345;\\n            font-weight: 700;\\n        }\\n        /* \\u8bfe\\u7a0b\\u8fdb\\u5ea6\\u6307\\u793a\\u5668 */\\n        .progress-indicator {\\n            position: absolute;\\n            bottom: 40px;\\n            left: 50%;\\n            transform: translateX(-50%);\\n            display: flex;\\n            flex-direction: column;\\n            align-items: center;\\n            gap: 12px;\\n        }\\n        .progress-dots {\\n            display: flex;\\n            gap: 8px;\\n        }\\n        .progress-dot {\\n            width: 12px;\\n            height: 12px;\\n            border-radius: 50%;\\n            background: #dfe9ca;\\n            transition: all 0.3s ease;\\n        }\\n        .progress-dot.active {\\n            background: #5f8e4f;\\n            transform: scale(1.2);\\n        }\\n        .progress-text {\\n            font-size: 14px;\\n            color: #90a28a;\\n            font-weight: 500;\\n        }\\n        /* \\u9875\\u811a\\u90e8\\u5206 - \\u5b8c\\u5168\\u4fdd\\u6301\\u539f\\u6837 */\\n        .footer-note {\\n            position: absolute;\\n            left: 74px;\\n            bottom: 22px;\\n            z-index: 5;\\n            font-size: 12px;\\n            color: #9aa596;\\n            letter-spacing: 0.2px;\\n        }\\n        .pagination {\\n            position: absolute;\\n            right: 36px;\\n            bottom: 22px;\\n            z-index: 5;\\n            font-size: 18px;\\n            font-weight: 700;\\n            color: #94a08e;\\n            background: rgba(255,255,255,0.9);\\n            padding: 6px 14px;\\n            border-radius: 20px;\\n        }\\n        /* \\u54cd\\u5e94\\u5f0f\\u7f29\\u653e */\\n        @media (max-width: 1400px) {\\n            .main-title {\\n                font-size: 64px;\\n            }\\n            .title-sub {\\n                font-size: 24px;\\n            }\\n            .info-cards {\\n                gap: 30px;\\n            }\\n        }\\n        @media (max-width: 1200px) {\\n            .main-title {\\n                font-size: 56px;\\n            }\\n            .info-card {\\n                min-width: 220px;\\n                padding: 20px 24px;\\n            }\\n        }\\n    </style>\\n</head>\\n<body>\\n    <div class=\\\"s