: \"\\u8bfe\\u7a0b\\u56de\\u987e\\u4e0e\\u672c\\u6b21\\u8bfe\\u76ee\\u6807\", \"html_content\": \"<!DOCTYPE html>\\n<html lang=\\\"zh-CN\\\">\\n<head>\\n    <meta charset=\\\"UTF-8\\\">\\n    <meta name=\\\"viewport\\\" content=\\\"width=device-width, initial-scale=1.0\\\">\\n    <title>\\u7b2c2\\u9875\\uff1a\\u8bfe\\u7a0b\\u56de\\u987e\\u4e0e\\u672c\\u6b21\\u8bfe\\u76ee\\u6807</title>\\n    <!-- \\u5f15\\u5165\\u5b57\\u4f53\\u4e0e\\u56fe\\u6807\\u5e93 -->\\n    <link rel=\\\"preconnect\\\" href=\\\"https://fonts.googleapis.com\\\">\\n    <link rel=\\\"preconnect\\\" href=\\\"https://fonts.gstatic.com\\\" crossorigin>\\n    <link href=\\\"https://fonts.googleapis.com/css2?family=Noto+Sans+SC:wght@400;500;700;900&display=swap\\\" rel=\\\"stylesheet\\\">\\n    <link rel=\\\"stylesheet\\\" href=\\\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css\\\">\\n    <!-- \\u5f15\\u5165Prism.js\\u7528\\u4e8e\\u4ee3\\u7801\\u9ad8\\u4eae\\uff08C\\u8bed\\u8a00\\u8bfe\\u7a0b\\u9700\\u8981\\uff09 -->\\n    <link href=\\\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/themes/prism-tomorrow.min.css\\\" rel=\\\"stylesheet\\\" />\\n    <script src=\\\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/prism.min.js\\\"></script>\\n    <script src=\\\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/components/prism-c.min.js\\\"></script>\\n    <style>\\n        /* \\u57fa\\u7840\\u4e0e\\u91cd\\u7f6e\\u6837\\u5f0f */\\n        * {\\n            margin: 0;\\n            padding: 0;\\n            box-sizing: border-box;\\n        }\\n        html, body {\\n            width: 100%;\\n            height: 100%;\\n            overflow: hidden;\\n            background: #eef1ed;\\n            font-family: \'Noto Sans SC\', sans-serif;\\n            color: #26412f;\\n        }\\n        /* \\u54cd\\u5e94\\u5f0f\\u7f29\\u653e\\u5bb9\\u5668 */\\n        .slide-container {\\n            width: 100vw;\\n            height: 100vh;\\n            display: flex;\\n            justify-content: center;\\n            align-items: center;\\n        }\\n        /* \\u5e7b\\u706f\\u7247\\u6838\\u5fc3\\u753b\\u5e03\\uff08\\u4e25\\u683c 1280\\u00d7720\\uff09 */\\n        .slide {\\n            width: 1280px;\\n            height: 720px;\\n            background: #fbfcf8;\\n            position: relative;\\n            overflow: hidden;\\n            transform-origin: center center;\\n            box-shadow: 0 10px 30px rgba(0, 0, 0, 0.12);\\n        }\\n        /* \\u4e3b\\u9898\\u88c5\\u9970\\u5143\\u7d20\\uff1a\\u4e25\\u683c\\u4fdd\\u6301\\u539f\\u6837 */\\n        .top-strip,\\n        .bottom-strip {\\n            position: absolute;\\n            left: 0;\\n            width: 100%;\\n            height: 8px;\\n            background: linear-gradient(to right, rgba(130, 130, 130, 0.12), rgba(130, 130, 130, 0.45), rgba(130, 130, 130, 0.12));\\n            z-index: 1;\\n        }\\n        .top-strip { top: 132px; }\\n        .bottom-strip { bottom: 132px; }\\n        .deco-circle {\\n            position: absolute;\\n            border-radius: 50%;\\n            z-index: 1;\\n        }\\n        .circle-a { width: 280px; height: 280px; right: 120px; top: -80px; background: #3d7a45; }\\n        .circle-b { width: 210px; height: 210px; right: 220px; top: 18px; background: #8cb043; opacity: 0.95; }\\n        .circle-c { width: 86px; height: 86px; right: 52px; top: 42px; background: #cfdc72; }\\n        .circle-d { width: 54px; height: 54px; left: 36px; top: 18px; background: #7eb377; }\\n        .circle-e { width: 150px; height: 150px; left: 70px; bottom: -58px; background: #93bf84; }\\n        .circle-f { width: 270px; height: 270px; left: 230px; bottom: -120px; background: #3f7345; opacity: 0.92; }\\n        .circle-g { width: 190px; height: 190px; left: 360px; bottom: -90px; background: #9eb841; opacity: 0.85; }\\n        .circle-h { width: 76px; height: 76px; right: 86px; bottom: 46px; background: #d8de7f; }\\n        .leaf-mark {\\n            position: absolute;\\n            top: 32px;\\n            left: 44px;\\n            width: 70px;\\n            height: 48px;\\n            z-index: 3;\\n        }\\n        .leaf-mark::before,\\n        .leaf-mark::after,\\n        .leaf-mark span {\\n            content: \'\';\\n            position: absolute;\\n            border-radius: 0 0 40px 0;\\n        }\\n        .leaf-mark::before {\\n            left: 0;\\n            top: 0;\\n            width: 32px;\\n            height: 32px;\\n            background: #d8df79;\\n        }\\n        .leaf-mark::after {\\n            left: 18px;\\n            top: 0;\\n            width: 34px;\\n            height: 34px;\\n            background: #89a95d;\\n        }\\n        .leaf-mark span {\\n            left: 32px;\\n            top: 0;\\n            width: 38px;\\n            height: 38px;\\n            background: #426f4b;\\n        }\\n        /* \\u9875\\u7709\\u4fe1\\u606f\\u533a\\uff1a\\u4e25\\u683c\\u4fdd\\u6301\\u539f\\u6837 */\\n        .header-band {\\n            position: absolute;\\n            left: 78px;\\n            top: 34px;\\n            right: 100px;\\n            display: flex;\\n            align-items: center;\\n            justify-content: space-between;\\n            z-index: 4;\\n        }\\n        .logo-group {\\n            display: flex;\\n            align-items: center;\\n            gap: 14px;\\n        }\\n        .logo-badge {\\n            width: 48px;\\n            height: 48px;\\n            border-radius: 50%;\\n            border: 2px solid #5f8e4f;\\n            display: flex;\\n            align-items: center;\\n            justify-content: center;\\n            color: #5f8e4f;\\n            background: rgba(255,255,255,0.95);\\n            font-size: 22px;\\n        }\\n        .logo-text {\\n            line-height: 1.2;\\n        }\\n        .logo-text .cn {\\n            font-size: 15px;\\n            font-weight: 700;\\n            color: #527845;\\n        }\\n        .logo-text .en {\\n            font-size: 10px;\\n            color: #7d8a79;\\n            letter-spacing: 0.4px;\\n        }\\n        .template-meta {\\n            text-align: right;\\n        }\\n        .template-meta .meta-title {\\n            font-size: 16px;\\n            font-weight: 700;\\n            color: #587d48;\\n        }\\n        .template-meta .meta-subtitle {\\n            margin-top: 4px;\\n            font-size: 11px;\\n            color: #98a095;\\n            letter-spacing: 0.8px;\\n        }\\n        /* \\u4e3b\\u4f53\\u5185\\u5bb9\\u533a\\uff1a\\u521b\\u610f\\u8bbe\\u8ba1\\u533a\\u57df */\\n        .content-area {\\n            position: absolute;\\n            top: 156px;\\n            left: 68px;\\n            right: 68px;\\n            bottom: 64px;\\n            z-index: 4;\\n            display: flex;\\n            flex-direction: column;\\n        }\\n        /* \\u9875\\u9762\\u6807\\u9898\\u533a\\u57df */\\n        .page-title-section {\\n            margin-bottom: 36px;\\n            text-align: center;\\n        }\\n        .page-title-section h1 {\\n            font-size: 42px;\\n            font-weight: 900;\\n            color: #3f7345;\\n            margin-bottom: 8px;\\n            letter-spacing: 1px;\\n        }\\n        .page-title-section .subtitle {\\n            font-size: 18px;\\n            color: #7d9a6e;\\n            font-weight: 500;\\n        }\\n        /* \\u4e09\\u6a21\\u5757\\u65f6\\u95f4\\u8f74\\u5e03\\u5c40 */\\n        .timeline-container {\\n            display: flex;\\n            justify-content: space-between;\\n            align-items: flex-start;\\n            flex-grow: 1;\\n            margin-bottom: 20px;\\n        }\\n        .timeline-module {\\n            flex: 1;\\n            display: flex;\\n            flex-direction: column;\\n            align-items: center;\\n            position: relative;\\n            padding: 0 20px;\\n        }\\n        /* \\u8fde\\u63a5\\u7ebf */\\n        .timeline-module:not(:last-child)::after {\\n            content: \'\';\\n            position: absolute;\\n            top: 80px;\\n            right: -50%;\\n            width: 100%;\\n            height: 4px;\\n            background: linear-gradient(to right, #8cb043, #7eb377);\\n            z-index: 2;\\n        }\\n        /* \\u6a21\\u5757\\u56fe\\u6807 */\\n        .module-icon {\\n            width: 120px;\\n            height: 120px;\\n            border-radius: 50%;\\n            background: white;\\n            display: flex;\\n            align-items: center;\\n            justify-content: center;\\n            margin-bottom: 24px;\\n            box-shadow: 0 12px 24px rgba(63, 115, 69, 0.15);\\n            position: relative;\\n            z-index: 3;\\n            border: 4px solid;\\n            transition: transform 0.3s ease;\\n        }\\n        .module-icon:hover {\\n            transform: scale(1.05);\\n        }\\n        .module-icon i {\\n            font-size: 48px;\\n        }\\n        /* \\u6a21\\u57571\\uff1a\\u56de\\u987e */\\n        .module-1 .module-icon {\\n            border-color: #3d7a45;\\n            background: linear-gradient(135deg, #f6f8f1, #e8f0e3);\\n        }\\n        .module-1 .module-icon i {\\n            color: #3d7a45;\\n        }\\n        /* \\u6a21\\u57572\\uff1a\\u76ee\\u6807 */\\n        .module-2 .module-icon {\\n            border-color: #8cb043;\\n            background: linear-gradient(135deg, #f9fbf2, #f0f5e4);\\n        }\\n        .module-2 .module-icon i {\\n            color: #8cb043;\\n        }\\n        /* \\u6a21\\u57573\\uff1a\\u6982\\u89c8 */\\n        .module-3 .module-icon {\\n            border-color: #cfdc72;\\n            background: linear-gradient(135deg, #fcfdf7, #f7f9ec);\\n        }\\n        .module-3 .module-icon i {\\n            color: #9eb841;\\n        }\\n        /* \\u6a21\\u5757\\u5185\\u5bb9 */\\n        .module-content {\\n            background: rgba(255, 255, 255, 0.85);\\n            border-radius: 20px;\\n            padding: 24px;\\n            width: 100%;\\n            min-height: 220px;\\n            box-shadow: 0 8px 20px rgba(0, 0, 0, 0.06);\\n            border: 1px solid rgba(96, 129, 79, 0.12);\\n            display: flex;\\n            flex-direction: column;\\n        }\\n        .module-header {\\n            display: flex;\\n            align-items: center;\\n            margin-bottom: 16px;\\n            padding-bottom: 12px;\\n            border-bottom: 2px solid;\\n        }\\n        .module-1 .module-header {\\n            border-bottom-color: #3d7a45;\\n        }\\n        .module-2 .module-header {\\n            border-bottom-color: #8cb043;\\n        }\\n        .module-3 .module-header {\\n            border-bottom-color: #cfdc72;\\n        }\\n        .module-header h3 {\\n            font-size: 22px;\\n            font-weight: 700;\\n            color: #4f7b45;\\n            margin-left: 12px;\\n        }\\n        .module-header .icon-small {\\n            font-size: 20px;\\n        }\\n        /* \\u5185\\u5bb9\\u5217\\u8868 */\\n        .content-list {\\n            list-style: none;\\n            flex-grow: 1;\\n        }\\n        .content-list li {\\n            font-size: 16px;\\n            line-height: 1.6;\\n            color: #516250;\\n            margin-bottom: 12px;\\n            padding-left: 28px;\\n            position: relative;\\n        }\\n        .content-list li::before {\\n            content: \'\';\\n            position: absolute;\\n            left: 0;\\n            top: 10px;\\n            width: 12px;\\n            height: 12px;\\n            border-radius: 50%;\\n        }\\n        .module-1 .content-list li::before {\\n            background: #3d7a45;\\n        }\\n        .module-2 .content-list li::before {\\n            background: #8cb043;\\n        }\\n        .module-3 .content-list li::before {\\n            background: #cfdc72;\\n        }\\n        /* C\\u8bed\\u8a00\\u4ee3\\u7801\\u793a\\u4f8b */\\n        .code-preview {\\n            background: #2d2d2d;\\n            border-radius: 12px;\\n            padding: 16px;\\n            margin-top: 12px;\\n            font-family: \'Consolas\', \'Monaco\', monospace;\\n            font-size: 14px;\\n            color: #f8f8f2;\\n            overflow: hidden;\\n        }\\n        .code-preview .keyword {\\n            color: #ff79c6;\\n        }\\n        .code-preview .type {\\n            color: #8be9fd;\\n        }\\n        .code-preview .function {\\n            color: #50fa7b;\\n        }\\n        /* \\u9875\\u811a\\u533a\\u57df\\uff1a\\u4e25\\u683c\\u4fdd\\u6301\\u539f\\u6837 */\\n        .footer-note {\\n            position: absolute;\\n            left: 74px;\\n            bottom: 22px;\\n            z-index: 5;\\n            font-size: 12px;\\n            color: #9aa596;\\n            letter-spacing: 0.2px;\\n        }\\n        .pagination {\\n            position: absolute;\\n            right: 36px;\\n            bottom: 22px;\\n            z-index: 5;\\n            font-size: 18px;\\n            font-weight: 700;\\n            color: #94a08e;\\n            background: rgba(255,255,255,0.9);\\n            padding: 6px 14px;\\n            border-radius: 20px;\\n        }\\n    </style>\\n</head>\\n<body>\\n    <div class=\\\"slide-container\\\">\\n        <div class=\\\"slide\\\">\\n            <!-- \\u4e3b\\u9898\\u88c5\\u9970\\u5c42\\uff08\\u4e25\\u683c\\u4fdd\\u6301\\u539f\\u6837\\uff09 -->\\n            <div class=\\\"top-strip\\\"></div>\\n            <div class=\\\"bottom-strip\\\"></div>\\n            <div class=\\\"deco-circle circle-a\\\"></div>\\n            <div class=\\\"deco-circle circle-b\\\"></div>\\n            <div class=\\\"deco-circle circle-c\\\"></div>\\n            <div class=\\\"deco-circle circle-d\\\"></div>\\n            <div class=\\\"deco-circle circle-e\\\"></div>\\n            <div class=\\\"deco-circle circle-f\\\"></div>\\n            <div class=\\\"deco-circle circle-g\\\"></div>\\n            <div class=\\\"deco-circle circle-h\\\"></div>\\n            <div class=\\\"leaf-mark\\\"><span></span></div>\\n            <!-- \\u9875\\u7709\\u5360\\u4f4d\\u4fe1\\u606f\\uff08\\u4e25\\u683c\\u4fdd\\u6301\\u539f\\u6837\\uff09 -->\\n            <div class=\\\"header-band\\\">\\n                <div class=\\\"logo-group\\\">\\n                    <div class=\\\"logo-badge\\\"><i class=\\\"fa-solid fa-code\\\"></i></div>\\n                    <div class=\\\"logo-text\\\">\\n                        <div class=\\\"cn\\\">\\u98df\\u54c1\\u836f\\u54c1\\u804c\\u4e1a\\u5b66\\u9662</div>\\n                        <div class=\\\"en\\\">Food and Drug Vocational College</div>\\n                    </div>\\n                </div>\\n                <div class=\\\"template-meta\\\">\\n                    <div class=\\\"meta-title\\\">C\\u8bed\\u8a00\\u7a0b\\u5e8f\\u8bbe\\u8ba1 \\u00b7 \\u7b2c\\u4e09\\u6b21\\u8bfe</div>\\n                    <div class=\\\"meta-subtitle\\\">STRUCTURED \\u00b7 LOGICAL \\u00b7 PRACTICAL \\u00b7 MODERN</div>\\n                </div>\\n            </div>\\n            <!-- \\u4e3b\\u4f53\\u5185\\u5bb9\\u533a\\uff08\\u521b\\u610f\\u8bbe\\u8ba1\\u533a\\u57df\\uff09 -->\\n            <div class=\\\"content-area\\\">\\n                <div class=\\\"page-title-section\\\">\\n                    <h1>\\u8bfe\\u7a0b\\u56de\\u987e\\u4e0e\\u672c\\u6b21\\u8bfe\\u76ee\\u6807</h1>\\n                    <div class=\\\"subtitle\\\">\\u6784\\u5efa\\u5b8c\\u6574\\u7684\\u5b66\\u4e60\\u8def\\u5f84 \\u00b7 \\u4ece\\u57fa\\u7840\\u5230\\u5e94\\u7528</div>\\n                </div>\\n                <div class=\\\"timeline-container\\\">\\n                    <!-- \\u6a21\\u57571\\uff1a\\u56de\\u987e -->\\n                    <div class=\\\"timeline-module module-1\\\">\\n                        <div class=\\\"module-icon\\\">\\n                            <i class=\\\"fa-solid fa-history\\\"></i>\\n                        </div>\\n                        <div class=\\\"module-content\\\">\\n                            <div class=\\\"module-header\\\">\\n                                <i class=\\\"fa-solid fa-book-open icon-small\\\"></i>\\n                                <h3>\\u524d\\u4e24\\u6b21\\u8bfe\\u6838\\u5fc3\\u77e5\\u8bc6\\u70b9\\u56de\\u987e</h3>\\n                            </div>\\n                            <ul class=\\\"content-list\\\">\\n                                <li>C\\u8bed\\u8a00\\u57fa\\u7840\\u8bed\\u6cd5\\u4e0e\\u7a0b\\u5e8f\\u7ed3\\u6784</li>\\n                                <li>\\u53d8\\u91cf\\u3001\\u6570\\u636e\\u7c7b\\u578b\\u4e0e\\u8fd0\\u7b97\\u7b26</li>\\n                                <li>\\u987a\\u5e8f\\u3001\\u9009\\u62e9\\u3001\\u5faa\\u73af\\u7ed3\\u6784</li>\\n                                <li>\\u7b80\\u5355\\u7684\\u8f93\\u5165\\u8f93\\u51fa\\u51fd\\u6570</li>\\n                            </ul>\\n                            <div class=\\\"code-preview\\\">\\n                                <span class=\\\"keyword\\\">#include</span> &lt;stdio.h&gt;<br>\\n                                <span class=\\\"keyword\\\">int</span> <span class=\\\"function\\\">main</span>() {<br>\\n                                &nbsp;&nbsp;<span class=\\\"keyword\\\">int</span> a = 10, b = 20;<br>\\n                                &nbsp;&nbsp;<span class=\\\"keyword\\\">if</span> (a &lt; b) {<br>\\n                                &nbsp;&nbsp;&nbsp;&nbsp;printf(<span class=\\\"type\\\">\\\"a\\u5c0f\\u4e8eb\\\\n\\\"</span>);<br>\\n                                &nbsp;&nbsp;}<br>\\n                                &nbsp;&nbsp;<span class=\\\"keyword\\\">return</span> 0;<br>\\n                                }\\n                            </div>\\n                        </div>\\n                    </div>\\n                    <!-- \\u6a21\\u57572\\uff1a\\u76ee\\u6807 -->\\n                    <div class=\\\"timeline-module module-2\\\">\\n                        <div class=\\\"module-icon\\\">\\n                            <i class=\\\"fa-solid fa-bullseye\\\"></i>\\n                        </div>\\n                        <div class=\\\"module-content\\\">\\n                            <div class=\\\"module-header\\\">\\n                                <i class=\\\"fa-solid fa-flag-checkered icon-small\\\"></i>\\n                                <h3>\\u672c\\u6b21\\u8bfe\\u7a0b\\u5b66\\u4e60\\u76ee\\u6807</h3>\\n                            </div>\\n                            <ul class=\\\"content-list\\\">\\n                                <li><strong>\\u77e5\\u8bc6\\u76ee\\u6807\\uff1a</strong>\\u638c\\u63e1\\u6570\\u7ec4\\u7684\\u5b9a\\u4e49\\u4e0e\\u4f7f\\u7528\\u65b9\\u6cd5</li>\\n                                <li><strong>\\u6280\\u80fd\\u76ee\\u6807\\uff1a</strong>\\u80fd\\u591f\\u7f16\\u5199\\u7b80\\u5355\\u7684\\u6570\\u7ec4\\u5904\\u7406\\u7a0b\\u5e8f</li>\\n                                <li><strong>\\u5e94\\u7528\\u76ee\\u6807\\uff1a</strong>\\u89e3\\u51b3\\u5b9e\\u9645\\u95ee\\u9898\\u4e2d\\u7684\\u6279\\u91cf\\u6570\\u636e\\u5904\\u7406</li>\\n                                <li><strong>\\u601d\\u7ef4\\u76ee\\u6807\\uff1a</strong>\\u57f9\\u517b\\u7ed3\\u6784\\u5316\\u7f16\\u7a0b\\u601d\\u7ef4</li>\\n                            </ul>\\n                            <div style=\\\"margin-top: 12px; padding: 12px; background\", \"is_user_edited\": false}, {\"page_number\": 3, \"title\": \"\\u5faa\\u73af\\u7ed3\\u6784\\uff1afor\\u8bed\\u53e5\", \"html_content\": \"<!DOCTYPE html>\\n<html lang=\\\"zh-CN\\\">\\n<head>\\n    <meta charset=\\\"UTF-8\\\">\\n    <meta name=\\\"viewport\\\" content=\\\"width=device-width, initial-scale=1.0\\\">\\n    <title>\\u5faa\\u73af\\u7ed3\\u6784\\uff1afor\\u8bed\\u53e5 - C\\u8bed\\u8a00\\u7b2c\\u4e09\\u6b21\\u8bfe</title>\\n    <!-- \\u5f15\\u5165\\u5b57\\u4f53\\u4e0e\\u56fe\\u6807\\u5e93 -->\\n    <link rel=\\\"preconnect\\\" href=\\\"https://fonts.googleapis.com\\\">\\n    <link rel=\\\"preconnect\\\" href=\\\"https://fonts.gstatic.com\\\" crossorigin>\\n    <link href=\\\"https://fonts.googleapis.com/css2?family=Noto+Sans+SC:wght@400;500;700;900&display=swap\\\" rel=\\\"stylesheet\\\">\\n    <link rel=\\\"stylesheet\\\" href=\\\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css\\\">\\n    <!-- \\u5f15\\u5165\\u4ee3\\u7801\\u9ad8\\u4eae\\u5e93 -->\\n    <link href=\\\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/themes/prism-tomorrow.min.css\\\" rel=\\\"stylesheet\\\" />\\n    <script src=\\\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/prism.min.js\\\"></script>\\n    <script src=\\\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/components/prism-c.min.js\\\"></script>\\n    <style>\\n        /* \\u57fa\\u7840\\u4e0e\\u91cd\\u7f6e\\u6837\\u5f0f */\\n        * { margin: 0; padding: 0; box-sizing: border-box; }\\n        html, body {\\n            width: 100%; height: 100%; overflow: hidden;\\n            background: #eef1ed; font-family: \'Noto Sans SC\', sans-serif;\\n            color: #26412f;\\n        }\\n        /* \\u54cd\\u5e94\\u5f0f\\u7f29\\u653e\\u5bb9\\u5668 */\\n        .slide-container {\\n            width: 100vw; height: 100vh;\\n            display: flex; justify-content: center; align-items: center;\\n        }\\n        /* \\u5e7b\\u706f\\u7247\\u6838\\u5fc3\\u753b\\u5e03\\uff08\\u4e25\\u683c 1280\\u00d7720\\uff09 */\\n        .slide {\\n            width: 1280px; height: 720px;\\n            background: #fbfcf8; position: relative; overflow: hidden;\\n            transform-origin: center center; box-shadow: 0 10px 30px rgba(0, 0, 0, 0.12);\\n        }\\n        /* \\u4e3b\\u9898\\u88c5\\u9970\\u5143\\u7d20\\uff1a\\u5b8c\\u5168\\u4fdd\\u6301\\u539f\\u6837 */\\n        .top-strip, .bottom-strip {\\n            position: absolute; left: 0; width: 100%; height: 8px;\\n            background: linear-gradient(to right, rgba(130, 130, 130, 0.12), rgba(130, 130, 130, 0.45), rgba(130, 130, 130, 0.12)); z-index: 1;\\n        }\\n        .top-strip { top: 132px; } .bottom-strip { bottom: 132px; }\\n        .deco-circle {\\n            position: absolute; border-radius: 50%; z-index: 1;\\n        }\\n        .circle-a { width: 280px; height: 280px; right: 120px; top: -80px; background: #3d7a45; }\\n        .circle-b { width: 210px; height: 210px; right: 220px; top: 18px; background: #8cb043; opacity: 0.95; }\\n        .circle-c { width: 86px; height: 86px; right: 52px; top: 42px; background: #cfdc72; }\\n        .circle-d { width: 54px; height: 54px; left: 36px; top: 18px; background: #7eb377; }\\n        .circle-e { width: 150px; height: 150px; left: 70px; bottom: -58px; background: #93bf84; }\\n        .circle-f { width: 270px; height: 270px; left: 230px; bottom: -120px; background: #3f7345; opacity: 0.92; }\\n        .circle-g { width: 190px; height: 190px; left: 360px; bottom: -90px; background: #9eb841; opacity: 0.85; }\\n        .circle-h { width: 76px; height: 76px; right: 86px; bottom: 46px; background: #d8de7f; }\\n        .leaf-mark {\\n            position: absolute; top: 32px; left: 44px; width: 70px; height: 48px; z-index: 3;\\n        }\\n        .leaf-mark::before, .leaf-mark::after, .leaf-mark span {\\n            content: \'\'; position: absolute; border-radius: 0 0 40px 0;\\n        }\\n        .leaf-mark::before { left: 0; top: 0; width: 32px; height: 32px; background: #d8df79; }\\n        .leaf-mark::after { left: 18px; top: 0; width: 34px; height: 34px; background: #89a95d; }\\n        .leaf-mark span { left: 32px; top: 0; width: 38px; height: 38px; background: #426f4b; }\\n        /* \\u9875\\u7709\\u4fe1\\u606f\\u533a\\uff1a\\u5b8c\\u5168\\u4fdd\\u6301\\u539f\\u6837 */\\n        .header-band {\\n            position: absolute; left: 78px; top: 34px; right: 100px;\\n            display: flex; align-items: center; justify-content: space-between; z-index: 4;\\n        }\\n        .logo-group { display: flex; align-items: center; gap: 14px; }\\n        .logo-badge {\\n            width: 48px; height: 48px; border-radius: 50%; border: 2px solid #5f8e4f;\\n            display: flex; align-items: center; justify-content: center;\\n            color: #5f8e4f; background: rgba(255,255,255,0.95); font-size: 22px;\\n        }\\n        .logo-text { line-height: 1.2; }\\n        .logo-text .cn { font-size: 15px; font-weight: 700; color: #527845; }\\n        .logo-text .en { font-size: 10px; color: #7d8a79; letter-spacing: 0.4px; }\\n        .template-meta { text-align: right; }\\n        .template-meta .meta-title { font-size: 16px; font-weight: 700; color: #587d48; }\\n        .template-meta .meta-subtitle {\\n            margin-top: 4px; font-size: 11px; color: #98a095; letter-spacing: 0.8px;\\n        }\\n        /* \\u9875\\u811a\\u533a\\u57df\\uff1a\\u5b8c\\u5168\\u4fdd\\u6301\\u539f\\u6837 */\\n        .footer-note {\\n            position: absolute; left: 74px; bottom: 22px; z-index: 5;\\n            font-size: 12px; color: #9aa596; letter-spacing: 0.2px;\\n        }\\n        .pagination {\\n            position: absolute; right: 36px; bottom: 22px; z-index: 5;\\n            font-size: 18px; font-weight: 700; color: #94a08e;\\n            background: rgba(255,255,255,0.9); padding: 6px 14px; border-radius: 20px;\\n        }\\n        /* \\u4e3b\\u8981\\u5185\\u5bb9\\u533a\\u57df - \\u521b\\u610f\\u8bbe\\u8ba1\\u5f00\\u59cb */\\n        .main-content {\\n            position: absolute;\\n            top: 156px; left: 68px; right: 68px; bottom: 64px;\\n            z-index: 4;\\n            display: flex;\\n            flex-direction: column;\\n            gap: 20px;\\n        }\\n        /* \\u9875\\u9762\\u6807\\u9898\\u533a */\\n        .page-header {\\n            display: flex;\\n            align-items: center;\\n            gap: 20px;\\n            margin-bottom: 10px;\\n        }\\n        .page-num-circle {\\n            width: 72px; height: 72px;\\n            border-radius: 50%;\\n            background: #55824a;\\n            color: white;\\n            font-size: 36px;\\n            font-weight: 900;\\n            display: flex;\\n            align-items: center;\\n            justify-content: center;\\n            box-shadow: inset 0 -8px 0 rgba(255,255,255,0.12);\\n            flex-shrink: 0;\\n        }\\n        .page-title-text h1 {\\n            font-size: 32px;\\n            line-height: 1.2;\\n            color: #4f7b45;\\n            font-weight: 900;\\n            margin-bottom: 6px;\\n        }\\n        .page-title-text p {\\n            font-size: 15px;\\n            color: #90a28a;\\n        }\\n        /* \\u5185\\u5bb9\\u4e3b\\u4f53 - \\u91c7\\u7528\\u53cc\\u5217\\u5e03\\u5c40 */\\n        .content-body {\\n            display: flex;\\n            flex: 1;\\n            gap: 28px;\\n            min-height: 0; /* \\u786e\\u4fddflex\\u5b50\\u9879\\u53ef\\u4ee5\\u6536\\u7f29 */\\n        }\\n        .content-left, .content-right {\\n            background: rgba(255,255,255,0.78);\\n            border: 1px solid rgba(96, 129, 79, 0.14);\\n            border-radius: 20px;\\n            padding: 24px 26px;\\n            backdrop-filter: blur(2px);\\n            display: flex;\\n            flex-direction: column;\\n        }\\n        .content-left {\\n            flex: 1.2;\\n        }\\n        .content-right {\\n            flex: 1;\\n        }\\n        /* \\u5de6\\u4fa7\\u5185\\u5bb9\\uff1a\\u4e09\\u8981\\u7d20\\u4e0e\\u8bed\\u6cd5 */\\n        .section-title {\\n            display: flex;\\n            align-items: center;\\n            gap: 10px;\\n            margin: 0 0 16px 0;\\n            font-size: 20px;\\n            font-weight: 800;\\n            color: #4e7543;\\n        }\\n        .section-title .dot {\\n            width: 10px;\\n            height: 10px;\\n            border-radius: 50%;\\n            background: #8dae48;\\n        }\\n        /* \\u4e09\\u8981\\u7d20\\u5361\\u7247 */\\n        .three-elements {\\n            display: flex;\\n            flex-direction: column;\\n            gap: 16px;\\n            margin-bottom: 24px;\\n            flex-grow: 1;\\n        }\\n        .element-card {\\n            background: #f6f8f1;\\n            border-radius: 16px;\\n            padding: 18px;\\n            border-left: 6px solid;\\n            display: flex;\\n            align-items: flex-start;\\n            gap: 14px;\\n            transition: transform 0.2s ease;\\n        }\\n        .element-card:hover {\\n            transform: translateY(-2px);\\n        }\\n        .element-icon {\\n            width: 48px;\\n            height: 48px;\\n            border-radius: 50%;\\n            display: flex;\\n            align-items: center;\\n            justify-content: center;\\n            font-size: 20px;\\n            color: white;\\n            flex-shrink: 0;\\n        }\\n        .element-content h3 {\\n            font-size: 18px;\\n            color: #4b7442;\\n            margin-bottom: 6px;\\n            font-weight: 700;\\n        }\\n        .element-content p {\\n            font-size: 14px;\\n            line-height: 1.6;\\n            color: #516250;\\n        }\\n        /* \\u8bed\\u6cd5\\u516c\\u5f0f */\\n        .syntax-box {\\n            background: #2a3b2e;\\n            border-radius: 16px;\\n            padding: 20px;\\n            margin-top: auto;\\n        }\\n        .syntax-box h4 {\\n            color: #d8df79;\\n            font-size: 16px;\\n            margin-bottom: 12px;\\n            font-weight: 600;\\n        }\\n        .syntax-formula {\\n            font-family: \'Courier New\', monospace;\\n            font-size: 18px;\\n            color: #f8f8f2;\\n            line-height: 1.6;\\n            background: #1e2721;\\n            padding: 16px;\\n            border-radius: 12px;\\n            border: 1px solid #3f7345;\\n        }\\n        .syntax-note {\\n            font-size: 13px;\\n            color: #90a28a;\\n            margin-top: 10px;\\n            line-height: 1.5;\\n        }\\n        /* \\u53f3\\u4fa7\\u5185\\u5bb9\\uff1a\\u6267\\u884c\\u6d41\\u7a0b\\u4e0e\\u793a\\u4f8b */\\n        .flow-section {\\n            margin-bottom: 24px;\\n            flex-grow: 1;\\n        }\\n        .flow-diagram {\\n            background: #f8faf4;\\n            border-radius: 16px;\\n            padding: 20px;\\n            margin-top: 12px;\\n            position: relative;\\n            min-height: 180px;\\n        }\\n        .flow-step {\\n            position: absolute;\\n            width: 100px;\\n            text-align: center;\\n        }\\n        .flow-step .step-circle {\\n            width: 60px;\\n            height: 60px;\\n            border-radius: 50%;\\n            background: #7eb377;\\n            color: white;\\n            display: flex;\\n            align-items: center;\\n            justify-content: center;\\n            font-size: 24px;\\n            font-weight: bold;\\n            margin: 0 auto 8px;\\n            border: 3px solid white;\\n            box-shadow: 0 4px 8px rgba(0,0,0,0.1);\\n        }\\n        .flow-step .step-label {\\n            font-size: 13px;\\n            color: #4f5d50;\\n            font-weight: 600;\\n        }\\n        .flow-arrow {\\n            position: absolute;\\n            color: #8dae48;\\n            font-size: 24px;\\n        }\\n        /* \\u793a\\u4f8b\\u4ee3\\u7801\\u533a */\\n        .example-section {\\n            flex-grow: 1;\\n            display: flex;\\n            flex-direction: column;\\n        }\\n        .code-container {\\n            flex-grow: 1;\\n            background: #2a3b2e;\\n            border-radius: 16px;\\n            overflow: hidden;\\n            margin-top: 12px;\\n            border: 1px solid #3f7345;\\n        }\\n        .code-header {\\n            background: #1e2721;\\n            padding: 12px 20px;\\n            color: #d8df79;\\n            font-size: 14px;\\n            font-weight: 600;\\n            display: flex;\\n            justify-content: space-between;\\n            align-items: center;\\n        }\\n        .code-output {\\n            background: #1e2721;\\n            padding: 12px 20px;\\n            color: #f8f8f2;\\n            font-family: \'Courier New\', monospace;\\n            font-size: 16px;\\n            border-top: 1px solid #3f7345;\\n            min-height: 60px;\\n            display: flex;\\n            align-items: center;\\n            flex-wrap: wrap;\\n            gap: 8px;\\n        }\\n        .output-number {\\n            background: #3f7345;\\n            color: white;\\n            width: 36px;\\n            height: 36px;\\n            border-radius: 50%;\\n            display: inline-flex;\\n            align-items: center;\\n            justify-content: center;\\n            font-weight: bold;\\n            animation: popIn 0.3s ease backwards;\\n        }\\n        @keyframes popIn {\\n            from { transform: scale(0); opacity: 0; }\\n            to { transform: scale(1); opacity: 1; }\\n        }\\n        /* \\u54cd\\u5e94\\u5f0f\\u7f29\\u653e\\u811a\\u672c */\\n        <script>\\n        function scaleSlide() {\\n            const slide = document.querySelector(\'.slide\');\\n            const container = document.querySelector(\'.slide-container\');\\n            const slideWidth = 1280;\\n            const slideHeight = 720;\\n            const containerWidth = container.offsetWidth;\\n            const containerHeight = container.offsetHeight;\\n            const scale = Math.min(containerWidth / slideWidth, containerHeight / slideHeight);\\n            slide.style.transform = `scale(${scale})`;\\n        }\\n        window.onload = scaleSlide;\\n        window.onresize = scaleSlide;\\n        </script>\\n    </style>\\n</head>\\n<body>\\n    <div class=\\\"slide-container\\\">\\n        <div class=\\\"slide\\\">\\n            <!-- \\u4e3b\\u9898\\u88c5\\u9970\\u5c42\\uff08\\u5b8c\\u5168\\u4fdd\\u6301\\u539f\\u6837\\uff09 -->\\n            <div class=\\\"top-strip\\\"></div>\\n            <div class=\\\"bottom-strip\\\"></div>\\n            <div class=\\\"deco-circle circle-a\\\"></div>\\n            <div class=\\\"deco-circle circle-b\\\"></div>\\n            <div class=\\\"deco-circle circle-c\\\"></div>\\n            <div class=\\\"deco-circle circle-d\\\"></div>\\n            <div class=\\\"deco-circle circle-e\\\"></div>\\n            <div class=\\\"deco-circle circle-f\\\"></div>\\n            <div class=\\\"deco-circle circle-g\\\"></div>\\n            <div class=\\\"deco-circle circle-h\\\"></div>\\n            <div class=\\\"leaf-mark\\\"><span></span></div>\\n            <!-- \\u9875\\u7709\\u5360\\u4f4d\\u4fe1\\u606f\\uff08\\u5b8c\\u5168\\u4fdd\\u6301\\u539f\\u6837\\uff09 -->\\n            <div class=\\\"header-band\\\">\\n                <div class=\\\"logo-group\\\">\\n                    <div class=\\\"logo-badge\\\"><i class=\\\"fa-solid fa-mortar-pestle\\\"></i></div>\\n                    <div class=\\\"logo-text\\\">\\n                        <div class=\\\"cn\\\">\\u98df\\u54c1\\u836f\\u54c1\\u804c\\u4e1a\\u5b66\\u9662</div>\\n                        <div class=\\\"en\\\">Food and Drug Vocational College</div>\\n                    </div>\\n                </div>\\n                <div class=\\\"template-meta\\\">\\n                    <div class=\\\"meta-title\\\">C\\u8bed\\u8a00\\u7a0b\\u5e8f\\u8bbe\\u8ba1 - \\u7b2c\\u4e09\\u6b21\\u8bfe</div>\\n                    <div class=\\\"meta-subtitle\\\">GREEN \\u00b7 MINIMAL \\u00b7 CIRCLE-DRIVEN \\u00b7 SECTIONAL REPORT</div>\\n                </div>\\n            </div>\\n            <!-- \\u4e3b\\u8981\\u5185\\u5bb9\\u533a\\u57df\\uff08\\u521b\\u610f\\u8bbe\\u8ba1\\u533a\\uff09 -->\\n            <div class=\\\"main-content\\\">\\n                <!-- \\u9875\\u9762\\u6807\\u9898 -->\\n                <div class=\\\"page-header\\\">\\n                    <div class=\\\"page-num-circle\\\">03</div>\\n                    <div class=\\\"page-title-text\\\">\\n                        <h1>\\u5faa\\u73af\\u7ed3\\u6784\\uff1afor\\u8bed\\u53e5</h1>\\n                        <p>\\u638c\\u63e1for\\u5faa\\u73af\\u7684\\u6838\\u5fc3\\u673a\\u5236\\u4e0e\\u6267\\u884c\\u6d41\\u7a0b</p>\\n                    </div>\\n                </div>\\n                <!-- \\u5185\\u5bb9\\u4e3b\\u4f53 -->\\n                <div class=\\\"content-body\\\">\\n                    <!-- \\u5de6\\u4fa7\\uff1a\\u4e09\\u8981\\u7d20\\u4e0e\\u8bed\\u6cd5 -->\\n                    <div class=\\\"content-left\\\">\\n                        <div class=\\\"section-title\\\">\\n                            <span class=\\\"dot\\\"></span>\\u5faa\\u73af\\u4e09\\u8981\\u7d20\\n                        </div>\\n                        <div class=\\\"three-elements\\\">\\n                            <div class=\\\"element-card\\\" style=\\\"border-left-color: #3f7345;\\\">\\n                                <div class=\\\"element-icon\\\" style=\\\"background: #3f7345;\\\">\\n                                    <i class=\\\"fas fa-play-circle\\\"></i>\\n                                </div>\\n                                <div class=\\\"element\", \"is_user_edited\": false}, {\"page_number\": 4, \"title\": \"\\u5faa\\u73af\\u7ed3\\u6784\\uff1awhile\\u4e0edo-while\\u8bed\\u53e5\", \"html_content\": \"<!DOCTYPE html>\\n<html lang=\\\"zh-CN\\\">\\n<head>\\n    <meta charset=\\\"UTF-8\\\">\\n    <meta name=\\\"viewport\\\" content=\\\"width=device-width, initial-scale=1.0\\\">\\n    <title>\\u5faa\\u73af\\u7ed3\\u6784\\uff1awhile\\u4e0edo-while\\u8bed\\u53e5</title>\\n    <!-- \\u5f15\\u5165\\u5b57\\u4f53\\u4e0e\\u56fe\\u6807\\u5e93 -->\\n    <link rel=\\\"preconnect\\\" href=\\\"https://fonts.googleapis.com\\\">\\n    <link rel=\\\"preconnect\\\" href=\\\"https://fonts.gstatic.com\\\" crossorigin>\\n    <link href=\\\"https://fonts.googleapis.com/css2?family=Noto+Sans+SC:wght@400;500;700;900&display=swap\\\" rel=\\\"stylesheet\\\">\\n    <link rel=\\\"stylesheet\\\" href=\\\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css\\\">\\n    <!-- \\u5f15\\u5165\\u4ee3\\u7801\\u9ad8\\u4eae\\u5e93 -->\\n    <link href=\\\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/themes/prism-tomorrow.min.css\\\" rel=\\\"stylesheet\\\" />\\n    <script src=\\\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/prism.min.js\\\"></script>\\n    <script src=\\\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/components/prism-c.min.js\\\"></script>\\n    <style>\\n        * {\\n            margin: 0;\\n            padding: 0;\\n            box-sizing: border-box;\\n        }\\n        html, body {\\n            width: 100%;\\n            height: 100%;\\n            overflow: hidden;\\n            background: #eef1ed;\\n            font-family: \'Noto Sans SC\', sans-serif;\\n            color: #26412f;\\n            display: flex;\\n            align-items: center;\\n            justify-content: center;\\n        }\\n        .slide-container {\\n            width: 100vw;\\n            height: 100vh;\\n            display: flex;\\n            justify-content: center;\\n            align-items: center;\\n        }\\n        .slide {\\n            width: 1280px;\\n            height: 720px;\\n            background: #fbfcf8;\\n            position: relative;\\n            overflow: hidden;\\n            transform-origin: center center;\\n            box-shadow: 0 10px 30px rgba(0, 0, 0, 0.12);\\n        }\\n        /* \\u4e25\\u683c\\u4fdd\\u6301\\u539f\\u6837\\u7684\\u9875\\u7709\\u548c\\u9875\\u811a\\u6837\\u5f0f */\\n        .top-strip,\\n        .bottom-strip {\\n            position: absolute;\\n            left: 0;\\n            width: 100%;\\n            height: 8px;\\n            background: linear-gradient(to right, rgba(130, 130, 130, 0.12), rgba(130, 130, 130, 0.45), rgba(130, 130, 130, 0.12));\\n            z-index: 1;\\n        }\\n        .top-strip { top: 132px; }\\n        .bottom-strip { bottom: 132px; }\\n        .deco-circle {\\n            position: absolute;\\n            border-radius: 50%;\\n            z-index: 1;\\n        }\\n        .circle-a { width: 280px; height: 280px; right: 120px; top: -80px; background: #3d7a45; }\\n        .circle-b { width: 210px; height: 210px; right: 220px; top: 18px; background: #8cb043; opacity: 0.95; }\\n        .circle-c { width: 86px; height: 86px; right: 52px; top: 42px; background: #cfdc72; }\\n        .circle-d { width: 54px; height: 54px; left: 36px; top: 18px; background: #7eb377; }\\n        .circle-e { width: 150px; height: 150px; left: 70px; bottom: -58px; background: #93bf84; }\\n        .circle-f { width: 270px; height: 270px; left: 230px; bottom: -120px; background: #3f7345; opacity: 0.92; }\\n        .circle-g { width: 190px; height: 190px; left: 360px; bottom: -90px; background: #9eb841; opacity: 0.85; }\\n        .circle-h { width: 76px; height: 76px; right: 86px; bottom: 46px; background: #d8de7f; }\\n        .leaf-mark {\\n            position: absolute;\\n            top: 32px;\\n            left: 44px;\\n            width: 70px;\\n            height: 48px;\\n            z-index: 3;\\n        }\\n        .leaf-mark::before,\\n        .leaf-mark::after,\\n        .leaf-mark span {\\n            content: \'\';\\n            position: absolute;\\n            border-radius: 0 0 40px 0;\\n        }\\n        .leaf-mark::before {\\n            left: 0;\\n            top: 0;\\n            width: 32px;\\n            height: 32px;\\n            background: #d8df79;\\n        }\\n        .leaf-mark::after {\\n            left: 18px;\\n            top: 0;\\n            width: 34px;\\n            height: 34px;\\n            background: #89a95d;\\n        }\\n        .leaf-mark span {\\n            left: 32px;\\n            top: 0;\\n            width: 38px;\\n            height: 38px;\\n            background: #426f4b;\\n        }\\n        .header-band {\\n            position: absolute;\\n            left: 78px;\\n            top: 34px;\\n            right: 100px;\\n            display: flex;\\n            align-items: center;\\n            justify-content: space-between;\\n            z-index: 4;\\n        }\\n        .logo-group {\\n            display: flex;\\n            align-items: center;\\n            gap: 14px;\\n        }\\n        .logo-badge {\\n            width: 48px;\\n            height: 48px;\\n            border-radius: 50%;\\n            border: 2px solid #5f8e4f;\\n            display: flex;\\n            align-items: center;\\n            justify-content: center;\\n            color: #5f8e4f;\\n            background: rgba(255,255,255,0.95);\\n            font-size: 22px;\\n        }\\n        .logo-text {\\n            line-height: 1.2;\\n        }\\n        .logo-text .cn {\\n            font-size: 15px;\\n            font-weight: 700;\\n            color: #527845;\\n        }\\n        .logo-text .en {\\n            font-size: 10px;\\n            color: #7d8a79;\\n            letter-spacing: 0.4px;\\n        }\\n        .template-meta {\\n            text-align: right;\\n        }\\n        .template-meta .meta-title {\\n            font-size: 16px;\\n            font-weight: 700;\\n            color: #587d48;\\n        }\\n        .template-meta .meta-subtitle {\\n            margin-top: 4px;\\n            font-size: 11px;\\n            color: #98a095;\\n            letter-spacing: 0.8px;\\n        }\\n        .footer-note {\\n            position: absolute;\\n            left: 74px;\\n            bottom: 22px;\\n            z-index: 5;\\n            font-size: 12px;\\n            color: #9aa596;\\n            letter-spacing: 0.2px;\\n        }\\n        .pagination {\\n            position: absolute;\\n            right: 36px;\\n            bottom: 22px;\\n            z-index: 5;\\n            font-size: 18px;\\n            font-weight: 700;\\n            color: #94a08e;\\n            background: rgba(255,255,255,0.9);\\n            padding: 6px 14px;\\n            border-radius: 20px;\\n        }\\n        /* \\u4e3b\\u8981\\u5185\\u5bb9\\u533a\\u57df - \\u521b\\u610f\\u8bbe\\u8ba1\\u90e8\\u5206 */\\n        .main-content {\\n            position: absolute;\\n            top: 156px;\\n            left: 68px;\\n            right: 68px;\\n            bottom: 64px;\\n            z-index: 4;\\n            display: flex;\\n            flex-direction: column;\\n            gap: 20px;\\n        }\\n        .page-title {\\n            display: flex;\\n            align-items: center;\\n            gap: 14px;\\n            margin-bottom: 10px;\\n        }\\n        .page-title .num {\\n            width: 72px;\\n            height: 72px;\\n            border-radius: 50%;\\n            background: #55824a;\\n            color: white;\\n            font-size: 36px;\\n            font-weight: 900;\\n            display: flex;\\n            align-items: center;\\n            justify-content: center;\\n            box-shadow: inset 0 -8px 0 rgba(255,255,255,0.12);\\n            flex-shrink: 0;\\n        }\\n        .page-title .text h1 {\\n            font-size: 30px;\\n            line-height: 1.2;\\n            color: #4f7b45;\\n            font-weight: 900;\\n        }\\n        .page-title .text p {\\n            font-size: 14px;\\n            color: #90a28a;\\n            margin-top: 6px;\\n        }\\n        /* \\u5bf9\\u6bd4\\u5e03\\u5c40\\u5bb9\\u5668 */\\n        .comparison-container {\\n            display: flex;\\n            gap: 24px;\\n            flex: 1;\\n            min-height: 0;\\n        }\\n        .loop-card {\\n            flex: 1;\\n            background: rgba(255,255,255,0.85);\\n            border-radius: 20px;\\n            padding: 24px;\\n            border: 1px solid rgba(96, 129, 79, 0.14);\\n            backdrop-filter: blur(2px);\\n            display: flex;\\n            flex-direction: column;\\n            position: relative;\\n            overflow: hidden;\\n        }\\n        .loop-card::before {\\n            content: \'\';\\n            position: absolute;\\n            top: 0;\\n            left: 0;\\n            right: 0;\\n            height: 6px;\\n            border-radius: 20px 20px 0 0;\\n        }\\n        .while-card::before {\\n            background: linear-gradient(to right, #3d7a45, #8cb043);\\n        }\\n        .do-while-card::before {\\n            background: linear-gradient(to right, #8cb043, #cfdc72);\\n        }\\n        .card-header {\\n            display: flex;\\n            align-items: center;\\n            gap: 12px;\\n            margin-bottom: 20px;\\n        }\\n        .loop-icon {\\n            width: 48px;\\n            height: 48px;\\n            border-radius: 50%;\\n            display: flex;\\n            align-items: center;\\n            justify-content: center;\\n            font-size: 22px;\\n            color: white;\\n            flex-shrink: 0;\\n        }\\n        .while-icon {\\n            background: #3d7a45;\\n        }\\n        .do-while-icon {\\n            background: #8cb043;\\n        }\\n        .card-header h2 {\\n            font-size: 22px;\\n            color: #4f7b45;\\n            font-weight: 800;\\n        }\\n        .card-header p {\\n            font-size: 13px;\\n            color: #90a28a;\\n            margin-top: 4px;\\n        }\\n        .syntax-box {\\n            background: #f6f8f1;\\n            border-radius: 12px;\\n            padding: 16px;\\n            margin-bottom: 20px;\\n            border-left: 4px solid #7fa64d;\\n        }\\n        .syntax-box h3 {\\n            font-size: 14px;\\n            color: #4e7543;\\n            margin-bottom: 10px;\\n            font-weight: 700;\\n        }\\n        .code-block {\\n            background: #2d2d2d;\\n            border-radius: 8px;\\n            padding: 12px;\\n            font-family: \'Consolas\', \'Monaco\', monospace;\\n            font-size: 13px;\\n            line-height: 1.5;\\n            color: #f8f8f2;\\n            overflow-x: auto;\\n        }\\n        .features-list {\\n            flex: 1;\\n            display: flex;\\n            flex-direction: column;\\n            gap: 12px;\\n        }\\n        .feature-item {\\n            display: flex;\\n            align-items: flex-start;\\n            gap: 10px;\\n            padding: 10px;\\n            background: rgba(248, 250, 244, 0.8);\\n            border-radius: 10px;\\n            border-left: 3px solid #7fa64d;\\n        }\\n        .feature-icon {\\n            width: 24px;\\n            height: 24px;\\n            border-radius: 50%;\\n            background: #dfe9ca;\\n            display: flex;\\n            align-items: center;\\n            justify-content: center;\\n            color: #507247;\\n            font-size: 12px;\\n            flex-shrink: 0;\\n        }\\n        .feature-text {\\n            flex: 1;\\n        }\\n        .feature-text h4 {\\n            font-size: 14px;\\n            color: #4b7442;\\n            margin-bottom: 4px;\\n            font-weight: 600;\\n        }\\n        .feature-text p {\\n            font-size: 12px;\\n            color: #667163;\\n            line-height: 1.5;\\n        }\\n        /* \\u5e95\\u90e8\\u5bf9\\u6bd4\\u4e0e\\u8b66\\u793a\\u533a\\u57df */\\n        .bottom-section {\\n            display: flex;\\n            gap: 24px;\\n            margin-top: 10px;\\n        }\\n        .difference-box {\\n            flex: 2;\\n            background: rgba(255,255,255,0.85);\\n            border-radius: 20px;\\n            padding: 20px;\\n            border: 1px solid rgba(96, 129, 79, 0.14);\\n            backdrop-filter: blur(2px);\\n        }\\n        .warning-box {\\n            flex: 1;\\n            background: rgba(255, 245, 245, 0.9);\\n            border-radius: 20px;\\n            padding: 20px;\\n            border: 1px solid rgba(220, 53, 69, 0.2);\\n            backdrop-filter: blur(2px);\\n        }\\n        .section-title {\\n            display: flex;\\n            align-items: center;\\n            gap: 10px;\\n            margin-bottom: 16px;\\n            font-size: 18px;\\n            font-weight: 800;\\n            color: #4e7543;\\n        }\\n        .section-title .dot {\\n            width: 10px;\\n            height: 10px;\\n            border-radius: 50%;\\n            background: #8dae48;\\n        }\\n        .warning-title {\\n            color: #dc3545;\\n        }\\n        .warning-title .dot {\\n            background: #dc3545;\\n        }\\n        .difference-grid {\\n            display: grid;\\n            grid-template-columns: repeat(2, 1fr);\\n            gap: 16px;\\n        }\\n        .diff-item {\\n            background: #f8faf4;\\n            border-radius: 12px;\\n            padding: 14px;\\n            border: 1px solid rgba(89, 121, 71, 0.1);\\n        }\\n        .diff-item h4 {\\n            font-size: 14px;\\n            color: #4e7543;\\n            margin-bottom: 8px;\\n            font-weight: 700;\\n        }\\n        .diff-content {\\n            display: flex;\\n            align-items: center;\\n            gap: 12px;\\n        }\\n        .while-badge, .do-while-badge {\\n            padding: 4px 10px;\\n            border-radius: 20px;\\n            font-size: 12px;\\n            font-weight: 600;\\n            flex-shrink: 0;\\n        }\\n        .while-badge {\\n            background: #e8f0e5;\\n            color: #3d7a45;\\n        }\\n        .do-while-badge {\\n            background: #f0f5e5;\\n            color: #8cb043;\\n        }\\n        .diff-text {\\n            font-size: 13px;\\n            color: #60705f;\\n            line-height: 1.5;\\n        }\\n        .warning-list {\\n            list-style: none;\\n        }\\n        .warning-list li {\\n            font-size: 13px;\\n            line-height: 1.7;\\n            color: #666;\\n            margin-bottom: 10px;\\n            padding-left: 24px;\\n            position: relative;\\n        }\\n        .warning-list li::before {\\n            content: \'\\u26a0\\ufe0f\';\\n            position: absolute;\\n            left: 0;\\n            top: 2px;\\n            font-size: 14px;\\n        }\\n        .warning-list strong {\\n            color: #dc3545;\\n            font-weight: 700;\\n        }\\n        /* \\u6d41\\u7a0b\\u53ef\\u89c6\\u5316\\u88c5\\u9970 */\\n        .flow-visual {\\n            position: absolute;\\n            bottom: 20px;\\n            right: 20px;\\n            display: flex;\\n            align-items: center;\\n            gap: 8px;\\n            font-size: 12px;\\n            color: #90a28a;\\n        }\\n        .flow-arrow {\\n            display: flex;\\n            align-items: center;\\n            gap: 4px;\\n        }\\n        .flow-arrow i {\\n            color: #7fa64d;\\n        }\\n    </style>\\n</head>\\n<body>\\n    <div class=\\\"slide-container\\\">\\n        <div class=\\\"slide\\\">\\n            <!-- \\u4e3b\\u9898\\u88c5\\u9970\\u5c42 -->\\n            <div class=\\\"top-strip\\\"></div>\\n            <div class=\\\"bottom-strip\\\"></div>\\n            <div class=\\\"deco-circle circle-a\\\"></div>\\n            <div class=\\\"deco-circle circle-b\\\"></div>\\n            <div class=\\\"deco-circle circle-c\\\"></div>\\n            <div class=\\\"deco-circle circle-d\\\"></div>\\n            <div class=\\\"deco-circle circle-e\\\"></div>\\n            <div class=\\\"deco-circle circle-f\\\"></div>\\n            <div class=\\\"deco-circle circle-g\\\"></div>\\n            <div class=\\\"deco-circle circle-h\\\"></div>\\n            <div class=\\\"leaf-mark\\\"><span></span></div>\\n            <!-- \\u9875\\u7709\\u5360\\u4f4d\\u4fe1\\u606f -->\\n            <div class=\\\"header-band\\\">\\n                <div class=\\\"logo-group\\\">\\n                    <d