n        }\\n        .logo-badge {\\n            width: 48px;\\n            height: 48px;\\n            border-radius: 50%;\\n            border: 2px solid #5f8e4f;\\n            display: flex;\\n            align-items: center;\\n            justify-content: center;\\n            color: #5f8e4f;\\n            background: rgba(255,255,255,0.95);\\n            font-size: 22px;\\n        }\\n        .logo-text {\\n            line-height: 1.2;\\n        }\\n        .logo-text .cn {\\n            font-size: 15px;\\n            font-weight: 700;\\n            color: #527845;\\n        }\\n        .logo-text .en {\\n            font-size: 10px;\\n            color: #7d8a79;\\n            letter-spacing: 0.4px;\\n        }\\n        .template-meta {\\n            text-align: right;\\n        }\\n        .template-meta .meta-title {\\n            font-size: 16px;\\n            font-weight: 700;\\n            color: #587d48;\\n        }\\n        .template-meta .meta-subtitle {\\n            margin-top: 4px;\\n            font-size: 11px;\\n            color: #98a095;\\n            letter-spacing: 0.8px;\\n        }\\n        /* \\u9875\\u811a\\uff08\\u5b8c\\u5168\\u4fdd\\u6301\\u539f\\u6837\\uff09 */\\n        .pagination {\\n            position: absolute;\\n            right: 36px;\\n            bottom: 22px;\\n            z-index: 5;\\n            font-size: 18px;\\n            font-weight: 700;\\n            color: #94a08e;\\n            background: rgba(255,255,255,0.9);\\n            padding: 6px 14px;\\n            border-radius: 20px;\\n        }\\n        .footer-note {\\n            position: absolute;\\n            left: 74px;\\n            bottom: 22px;\\n            z-index: 5;\\n            font-size: 12px;\\n            color: #9aa596;\\n            letter-spacing: 0.2px;\\n        }\\n        /* \\u4e3b\\u8981\\u5185\\u5bb9\\u533a\\u57df - \\u521b\\u610f\\u8bbe\\u8ba1 */\\n        .main-content {\\n            position: absolute;\\n            top: 156px;\\