}\\n        .card-icon {\\n            width: 48px;\\n            height: 48px;\\n            border-radius: 50%;\\n            display: flex;\\n            align-items: center;\\n            justify-content: center;\\n            font-size: 22px;\\n            color: white;\\n        }\\n        .break-icon {\\n            background: linear-gradient(135deg, #e74c3c, #c0392b);\\n        }\\n        .continue-icon {\\n            background: linear-gradient(135deg, #3498db, #2980b9);\\n        }\\n        .card-title h3 {\\n            font-size: 22px;\\n            font-weight: 800;\\n            color: #2c3e50;\\n        }\\n        .card-title p {\\n            font-size: 13px;\\n            color: #7f8c8d;\\n            margin-top: 4px;\\n        }\\n        .card-description {\\n            font-size: 15px;\\n            line-height: 1.6;\\n            color: #516250;\\n            margin-bottom: 20px;\\n            flex-grow: 1;\\n        }\\n        .flow-diagram {\\n            background: #f8f9fa;\\n            border-radius: 12px;\\n            padding: 16px;\\n            margin-bottom: 20px;\\n            border: 1px dashed #bdc3c7;\\n        }\\n        .flow-step {\\n            display: flex;\\n            align-items: center;\\n            margin-bottom: 8px;\\n            font-size: 14px;\\n        }\\n        .step-num {\\n            width: 24px;\\n            height: 24px;\\n            border-radius: 50%;\\n            background: #95a5a6;\\n            color: white;\\n            display: flex;\\n            align-items: center;\\n            justify-content: center;\\n            margin-right: 12px;\\n            font-size: 12px;\\n            flex-shrink: 0;\\n        }\\n        .break-step .step-num {\\n            background: #e74c3c;\\n        }\\n        .continue-step .step-num {\\n            background: #3498db;\\n        }\\n        /* \\u4ee3\\u7801\\u793a\\u4f8b\\u533a */\\n        .code-example {\\n            background: #2d3436;\\n            border-radius: 12px;\\n            padding: 16px;\\n            margin-top: auto;\\n            overflow: hidden;\\n        }\\n        .code-header {\\n            display: flex;\\n            justify-content: space-between;\\n            align-items: center;\\n            margin-bottom: 12px;\\n            color: #ecf0f1;\\n            font-size: 13px;\\n        }\\n        .code-lang {\\n            background: #3d7a45;\\n            padding: 4px 12px;\\n            border-radius: 20px;\\n            font-weight: 600;\\n        }\\n        pre[class*=\\\"language-\\\"] {\\n            margin: 0;\\n            background: transparent !important;\\n            font-size: 13px;\\n        }\\n        /* \\u5e95\\u90e8\\u8981\\u70b9\\u533a */\\n        .bottom-points {\\n            display: grid;\\n            grid-template-columns: repeat(2, 1fr);\\n            gap: 16px;\\n        }\\n        .point-card {\\n            background: rgba(255,255,255,0.78);\\n            border: 1px solid rgba(96, 129, 79, 0.14);\\n            border-radius: 16px;\\n            padding: 18px;\\n            backdrop-filter: blur(2px);\\n        }\\n        .point-header {\\n            display: flex;\\n            align-items: center;\\n            gap: 10px;\\n            margin-bottom: 12px;\\n        }\\n        .point-icon {\\n            width: 36px;\\n            height: 36px;\\n            border-radius: 50%;\\n            background: #7fa64d;\\n            color: white;\\n            display: flex;\\n            align-items: center;\\n            justify-content: center;\\n            font-size: 16px;\\n        }\\n        .point-title {\\n            font-size: 16px;\\n            font-weight: 700;\\n            color: #4e7543;\\n        }\\n        .point-content {\\n            font-size: 14px;\\n            line-height: 1.6;\\n            color: #516250;\\n        }\\n        .point-content ul {\\n            list-style: none;\\n            padding-left: 0;\