ight: 76px; right: 86px; bottom: 46px; background: #d8de7f; }\\n        .leaf-mark {\\n            position: absolute;\\n            top: 32px;\\n            left: 44px;\\n            width: 70px;\\n            height: 48px;\\n            z-index: 3;\\n        }\\n        .leaf-mark::before,\\n        .leaf-mark::after,\\n        .leaf-mark span {\\n            content: \'\';\\n            position: absolute;\\n            border-radius: 0 0 40px 0;\\n        }\\n        .leaf-mark::before {\\n            left: 0;\\n            top: 0;\\n            width: 32px;\\n            height: 32px;\\n            background: #d8df79;\\n        }\\n        .leaf-mark::after {\\n            left: 18px;\\n            top: 0;\\n            width: 34px;\\n            height: 34px;\\n            background: #89a95d;\\n        }\\n        .leaf-mark span {\\n            left: 32px;\\n            top: 0;\\n            width: 38px;\\n            height: 38px;\\n            background: #426f4b;\\n        }\\n        /* \\u9875\\u7709\\u4fe1\\u606f\\u533a - \\u5b8c\\u5168\\u4fdd\\u6301\\u539f\\u6837 */\\n        .header-band {\\n            position: absolute;\\n            left: 78px;\\n            top: 34px;\\n            right: 100px;\\n            display: flex;\\n            align-items: center;\\n            justify-content: space-between;\\n            z-index: 4;\\n        }\\n        .logo-group {\\n            display: flex;\\n            align-items: center;\\n            gap: 14px;\\n        }\\n        .logo-badge {\\n            width: 48px;\\n            height: 48px;\\n            border-radius: 50%;\\n            border: 2px solid #5f8e4f;\\n            display: flex;\\n            align-items: center;\\n            justify-content: center;\\n            color: #5f8e4f;\\n            background: rgba(255,255,255,0.95);\\n            font-size: 22px;\\n        }\\n        .logo-text {\\n            line-height: 1.2;\\n        }\\n        .logo-text .cn {\\n            font-size: 15px;\\n            font-weight: 700;\\n            color: #527845;\\n        }\\n        .logo-text .en {\\n            font-size: 10px;\\n            color: #7d8a79;\\n            letter-spacing: 0.4px;\\n        }\\n        .template-meta {\\n            text-align: right;\\n        }\\n        .template-meta .meta-title {\\n            font-size: 16px;\\n            font-weight: 700;\\n            color: #587d48;\\n        }\\n        .template-meta .meta-subtitle {\\n            margin-top: 4px;\\n            font-size: 11px;\\n            color: #98a095;\\n            letter-spacing: 0.8px;\\n        }\\n        /* \\u9875\\u811a\\u533a\\u57df - \\u5b8c\\u5168\\u4fdd\\u6301\\u539f\\u6837 */\\n        .pagination {\\n            position: absolute;\\n            right: 36px;\\n            bottom: 22px;\\n            z-index: 5;\\n            font-size: 18px;\\n            font-weight: 700;\\n            color: #94a08e;\\n            background: rgba(255,255,255,0.9);\\n            padding: 6px 14px;\\n            border-radius: 20px;\\n        }\\n        .footer-note {\\n            position: absolute;\\n            left: 74px;\\n            bottom: 22px;\\n            z-index: 5;\\n            font-size: 12px;\\n            color: #9aa596;\\n            letter-spacing: 0.2px;\\n        }\\n        /* \\u4e3b\\u8981\\u5185\\u5bb9\\u533a\\u57df - \\u521b\\u610f\\u8bbe\\u8ba1\\u5f00\\u59cb */\\n        .main-content {\\n            position: absolute;\\n            top: 156px;\\n            left: 68px;\\n            right: 68px;\\n            bottom: 64px;\\n            z-index: 4;\\n            display: flex;\\n            flex-direction: column;\\n            gap: 20px;\\n        }\\n        /* \\u9875\\u9762\\u6807\\u9898\\u533a\\u57df */\\n        .page-header {\\n            display: flex;\\n            align-items: center;\\n            gap: 20px;\\n            margin-bottom: 10px;\\n        }\\n        .page-number {\\n            width: 72px;\\n            height: 72px;\\n            border-radius: 50%;\\n            background: #55824a;\\n            color: white;\\n            font-size: 36px;\\n            font-weight: 900;\\n            display: flex;\\n            align-items: center;\\n            justify-content: center;\\n            box-shadow: inset 0 -8px 0 rgba(255,255,255,0.12);\\n            flex-shrink: 0;\\n        }\\n        .page-title-content h1 {\\n            font-size: 32px;\\n            color: #4f7b45;\\n            font-weight: 900;\\n            margin-bottom: 6px;\\n        }\\n        .page-title-content .subtitle {\\n            font-size: 16px;\\n            color: #90a28a;\\n            font-weight: 500;\\n        }\\n        /* \\u7ec3\\u4e60\\u5361\\u7247\\u7f51\\u683c\\u5e03\\u5c40 */\\n        .exercises-grid {\\n            display: grid;\\n            grid-template-columns: repeat(2, 1fr);\\n            grid-template-rows: repeat(2, 1fr);\\n            gap: 24px;\\n            height: 100%;\\n            flex-grow: 1;\\n        }\\n        .exercise-card {\\n            background: rgba(255, 255, 255, 0.85);\\n            border-radius: 20px;\\n            padding: 24px;\\n            border: 2px solid rgba(96, 129, 79, 0.15);\\n            position: relative;\\n            display: flex;\\n            flex-direction: column;\\n            transition: all 0.3s ease;\\n            box-shadow: 0 6px 20px rgba(0, 0, 0, 0.05);\\n            overflow: hidden;\\n        }\\n        .exercise-card:hover {\\n            transform: translateY(-5px);\\n            box-shadow: 0 12px 30px rgba(0, 0, 0, 0.1);\\n            border-color: #7fa64d;\\n        }\\n        .exercise-card:nth-child(4) {\\n            grid-column: span 2;\\n            background: linear-gradient(135deg, rgba(255, 255, 255, 0.9), rgba(246, 248, 241, 0.95));\\n            border-color: #8dae48;\\n        }\\n        .exercise-header {\\n            display: flex;\\n            align-items: center;\\n      