247\\u7279\\u6b8a\\u6837\\u5f0f */\\n        .demo-card {\\n            display: flex;\\n            gap: 24px;\\n            height: 100%;\\n        }\\n        .demo-left {\\n            flex: 1;\\n            display: flex;\\n            flex-direction: column;\\n        }\\n        .demo-right {\\n            flex: 1;\\n            background: #1e2a38;\\n            border-radius: 12px;\\n            padding: 16px;\\n            overflow: hidden;\\n        }\\n        .demo-title {\\n            font-size: 18px;\\n            font-weight: 700;\\n            color: #4e7543;\\n            margin-bottom: 12px;\\n        }\\n        .demo-steps {\\n            list-style: none;\\n            flex-grow: 1;\\n        }\\n        .demo-steps li {\\n            font-size: 14px;\\n            color: #60705f;\\n            margin-bottom: 10px;\\n            padding-left: 20px;\\n            position: relative;\\n            line-height: 1.5;\\n        }\\n        .demo-steps li::before {\\n            content: \'\\u25b6\';\\n            position: absolute;\\n            left: 0;\\n            color: #8dae48;\\n            font-size: 12px;\\n        }\\n        .code-header {\\n            display: flex;\\n            justify-content: space-between;\\n            align-items: center;\\n            margin-bottom: 12px;\\n            padding-bottom: 8px;\\n            border-bottom: 1px solid rgba(255, 255, 255, 0.1);\\n        }\\n        .code-title {\\n            font-size: 14px;\\n            color: #c1ffc1;\\n            font-weight: 600;\\n        }\\n        .code-language {\\n            font-size: 12px;\\n            color: #90a28a;\\n            background: rgba(255, 255, 255, 0.1);\\n            padding: 2px 8px;\\n            border-radius: 4px;\\n        }\\n        .code-preview {\\n            font-family: \'Courier New\', monospace;\\n            font-size: 13px;\\n            color: #c1ffc1;\\n            line-height: 1.5;\\n            white-space: pre-wrap;\\n            overflow-y: auto;\\n            max-height: 140px;\\n        }\\n        .code-preview .keyword {\\n            color: #ff79c6;\\n        }\\n        .code-preview .function {\\n            color: #50fa7b;\\n        }\\n        .code-preview .number {\\n            color: #bd93f9;\\n        }\\n        .code-preview .comment {\\n            color: #6272a4;\\n        }\\n        /* \\u6280\\u80fd\\u6807\\u7b7e */\\n        .skill-tags {\\n            display: flex;\\n            flex-wrap: wrap;\\n            gap: 6px;\\n            margin-top: 12px;\\n        }\\n        .skill-tag {\\n            font-size: 11px;\\n            padding: 3px 8px;\\n            background: rgba(141, 180, 127, 0.15);\\n            color: #507247;\\n            border-radius: 12px;\\n            border: 1px solid rgba(141, 180, 127, 0.3);\\n        }\\n        /* \\u8fdb\\u5ea6\\u6307\\u793a\\u5668 */\\n        .progress-indicator {\\n            position: absolute;\\n            bottom: 20px;\\n            left: 50%;\\n            transform: translateX(-50%);\\n            display: flex;\\n            gap: 8px;\\n            z-index: 4;\\n        }\\n        .progress-dot {\\n            width: 8px;\\n            height: 8px;\\n            border-radius: 50%;\\n            background: rgba(141, 180, 127, 0.3);\\n            transition: all 0.3s ease;\\n        }\\n        .progress-dot.active {\\n            background: #8dae48;\\n            transform: scale(1.2);\\n        }\\n    </style>\\n</head>\\n<body>\\n    <div class=\\\"slide-container\\\">\\n        <div class=\\\"slide\\\">\\n            <!-- \\u4e3b\\u9898\\u88c5\\u9970\\u5c42 - \\u5b8c\\u5168\\u4fdd\\u6301\\u539f\\u6837 -->\\n            <div class=\\\"top-strip\\\"></div>\\n            <div class=\\\"bottom-strip\\\"></div>\\n            <div class=\\\"deco-circle circle-a\\\"></div>\\n            <div class=\\\"deco-circle circle-b\\\"></div>\\n            <div class=\\\"deco-circle circle-c\\\"></div>