umn {\\n            display: flex;\\n            flex-direction: column;\\n            gap: 20px;\\n        }\\n        .visualization-panel {\\n            background: rgba(255,255,255,0.85);\\n            border: 1px solid rgba(96, 129, 79, 0.15);\\n            border-radius: 18px;\\n            padding: 22px;\\n            box-shadow: 0 6px 16px rgba(0,0,0,0.05);\\n            flex-grow: 1;\\n            display: flex;\\n            flex-direction: column;\\n        }\\n        .array-model {\\n            display: flex;\\n            flex-direction: column;\\n            align-items: center;\\n            justify-content: center;\\n            flex-grow: 1;\\n            gap: 25px;\\n        }\\n        .array-title {\\n            font-size: 20px;\\n            color: #4e7543;\\n            font-weight: 700;\\n            text-align: center;\\n            margin-bottom: 10px;\\n        }\\n        .array-container {\\n            display: flex;\\n            align-items: center;\\n            gap: 4px;\\n            position: relative;\\n        }\\n        .array-element {\\n            width: 80px;\\n            height: 100px;\\n            background: linear-gradient(145deg, #f0f5e9, #ffffff);\\n            border: 2px solid #8cb043;\\n            border-radius: 12px;\\n            display: flex;\\n            flex-direction: column;\\n            align-items: center;\\n            justify-content: center;\\n            box-shadow: 0 4px 8px rgba(0,0,0,0.08);\\n            transition: all 0.3s;\\n            position: relative;\\n            overflow: hidden;\\n        }\\n        .array-element.active {\\n            transform: translateY(-8px);\\n            border-color: #ff6b35;\\n            box-shadow: 0 8px 16px rgba(255,107,53,0.2);\\n        }\\n        .element-index {\\n            position: absolute;\\n            top: 8px;\\n            font-size: 14px;\\n            color: #ff6b35;\\n            font-weight: 700;\\n        }\\n        .element-