            </div>\\n                        </div>\\n                        <div class=\\\"case-content\\\">\\n                            <ul class=\\\"case-points\\\">\\n                                <li>\\u8ba1\\u7b97\\u5e73\\u5747\\u5206\\u3001\\u6700\\u9ad8/\\u6700\\u4f4e\\u5206</li>\\n                                <li>\\u7edf\\u8ba1\\u5206\\u6570\\u5206\\u5e03\\u4e0e\\u7b49\\u7ea7</li>\\n                                <li>\\u6570\\u7ec4\\u904d\\u5386 + \\u6761\\u4ef6\\u5224\\u65ad\\u7ec4\\u5408</li>\\n                                <li>\\u591a\\u7ef4\\u5ea6\\u6570\\u636e\\u5206\\u6790</li>\\n                            </ul>\\n                            <div class=\\\"code-example\\\">\\n                                <pre><code class\", \"is_user_edited\": false}, {\"page_number\": 10, \"title\": \"\\u672c\\u7ae0\\u91cd\\u70b9\\u603b\\u7ed3\", \"html_content\": \"<!DOCTYPE html>\\n<html lang=\\\"zh-CN\\\">\\n<head>\\n    <meta charset=\\\"UTF-8\\\">\\n    <meta name=\\\"viewport\\\" content=\\\"width=device-width, initial-scale=1.0\\\">\\n    <title>\\u7b2c10\\u9875 - \\u672c\\u7ae0\\u91cd\\u70b9\\u603b\\u7ed3</title>\\n    <!-- \\u5f15\\u5165\\u5b57\\u4f53\\u4e0e\\u56fe\\u6807\\u5e93 -->\\n    <link rel=\\\"preconnect\\\" href=\\\"https://fonts.googleapis.com\\\">\\n    <link rel=\\\"preconnect\\\" href=\\\"https://fonts.gstatic.com\\\" crossorigin>\\n    <link href=\\\"https://fonts.googleapis.com/css2?family=Noto+Sans+SC:wght@400;500;700;900&display=swap\\\" rel=\\\"stylesheet\\\">\\n    <link rel=\\\"stylesheet\\\" href=\\\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css\\\">\\n    <!-- \\u5f15\\u5165\\u56fe\\u8868\\u5e93 -->\\n    <script src=\\\"https://cdn.jsdelivr.net/npm/chart.js\\\"></script>\\n    <style>\\n        /* \\u57fa\\u7840\\u4e0e\\u91cd\\u7f6e\\u6837\\u5f0f */\\n        * {\\n            margin: 0;\\n            padding: 0;\\n            box-sizing: border-box;\\n        }\\n        html, body {\\n            width: 100%;\\n            height: 100%;\\n            overflow: hidden;\\n            background: #eef1ed;\\n            font-family: \'Noto Sans SC\', sans-serif;\\n            color: #26412f;\\n            display: flex;\\n            align-items: center;\\n            justify-content: center;\\n        }\\n        /* \\u5e7b\\u706f\\u7247\\u6838\\u5fc3\\u753b\\u5e03\\uff08\\u4e25\\u683c 1280\\u00d7720\\uff09 */\\n        .slide-container {\\n            width: 1280px;\\n            height: 720px;\\n            position: relative;\\n            background: #fbfcf8;\\n            box-shadow: 0 10px 30px rgba(0, 0, 0, 0.12);\\n            overflow: hidden;\\n        }\\n        /* === \\u4e25\\u683c\\u4fdd\\u6301\\u539f\\u6837\\u7684\\u9875\\u7709\\u548c\\u9875\\u811a\\u6837\\u5f0f === */\\n        /* \\u4e3b\\u9898\\u88c5\\u9970\\u5143\\u7d20 */\\n        .top-strip,\\n        .bottom-strip {\\n            position: absolute;\\n            left: 0;\\n            width: 100%;\\n            height: 8px;\\n            background: linear-gradient(to right, rgba(130, 130, 130, 0.12), rgba(130, 130, 130, 0.45), rgba(130, 130, 130, 0.12));\\n            z-index: 1;\\n        }\\n        .top-strip { top: 132px; }\\n        .bottom-strip { bottom: 132px; }\\n        .deco-circle {\\n            position: absolute;\\n            border-radius: 50%;\\n            z-index: 1;\\n        }\\n        .circle-a { width: 280px; height: 280px; right: 120px; top: -80px; background: #3d7a45; }\\n        .circle-b { width: 210px; height: 210px; right: 220px; top: 18px; background: #8cb043; opacity: 0.95; }\\n        .circle-c { width: 86px; height: 86px; right: 52px; top: 42px; background: #cfdc72; }\\n        .circle-d { width: 54px; height: 54px; left: 36px; top: 18px; background: #7eb377; }\\n        .circle-e { width: 150px; height: 150px; left: 70px; bottom: -58px; background: #93bf84; }\\n        .circle-f { width: 270px; height: 270px; left: 230px; bottom: -120px; background: #3f7345; opacity: 0.92; }\\n        .circle-g { width: 190px; height: 190px; left: 360px; bottom: -90px; background: #9eb841; opacity: 0.85; }\\n        .circle-h { width: 76px; height: 76px; right: 86px; bottom: 46px; background: #d8de7f; }\\n        .leaf-mark {\\n            position: absolute;\\n            top: 32px;\\n            left: 44px;\\n            width: 70px;\\n            height: 48px;\\n            z-index: 3;\\n        }\\n        .leaf-mark::before,\\n        .leaf-mark::after,\\n        .leaf-mark span {\\n            content: \'\';\\n            position: absolute;\\n            border-radius: 0 0 40px 0;\\n        }\\n        .leaf-mark::before {\\n            left: 0;\\n            top: 0;\\n            width: 32px;\\n            height: 32px;\\n            background: #d8df79;\\n        }\\n        .leaf-mark::after {\\n            left: 18px;\\n            top: 0;\\n            width: 34px;\\n            height: 34px;\\n            background: #89a95d;\\n        }\\n        .leaf-mark span {\\n            left: 32px;\\n            top: 0;\\n            width: 38px;\\n            height: 38px;\\n            background: #426f4b;\\n        }\\n        /* \\u9875\\u7709\\u4fe1\\u606f\\u533a */\\n        .header-band {\\n            position: absolute;\\n            left: 78px;\\n            top: 34px;\\n            right: 100px;\\n            display: flex;\\n            align-items: center;\\n            justify-content: space-between;\\n            z-index: 4;\\n        }\\n        .logo-group {\\n            display: flex;\\n            align-items: center;\\n            gap: 14px;\\n        }\\n        .logo-badge {\\n            width: 48px;\\n            height: 48px;\\n            border-radius: 50%;\\n            border: 2px solid #5f8e4f;\\n            display: flex;\\n            align-items: center;\\n            justify-content: center;\\n            color: #5f8e4f;\\n            background: rgba(255,255,255,0.95);\\n         