     margin-bottom: 30px;\\n        }\\n        .page-title-num {\\n            width: 80px;\\n            height: 80px;\\n            border-radius: 50%;\\n            background: linear-gradient(135deg, #3d7a45, #8cb043);\\n            color: white;\\n            font-size: 42px;\\n            font-weight: 900;\\n            display: flex;\\n            align-items: center;\\n            justify-content: center;\\n            box-shadow: 0 8px 20px rgba(61, 122, 69, 0.3);\\n            flex-shrink: 0;\\n        }\\n        .page-title-text {\\n            flex-grow: 1;\\n        }\\n        .page-title-text h1 {\\n            font-size: 36px;\\n            color: #3f7345;\\n            font-weight: 900;\\n            margin-bottom: 6px;\\n            letter-spacing: 1px;\\n        }\\n        .page-title-text p {\\n            font-size: 16px;\\n            color: #90a28a;\\n            font-weight: 500;\\n        }\\n        /* \\u77e5\\u8bc6\\u5730\\u56fe\\u5bb9\\u5668 */\\n        .knowledge-map {\\n            flex-grow: 1;\\n            display: grid;\\n            grid-template-columns: 1fr 1fr;\\n            grid-template-rows: 1fr 1fr;\\n            gap: 24px;\\n            position: relative;\\n        }\\n        /* \\u77e5\\u8bc6\\u8282\\u70b9\\u5361\\u7247 */\\n        .knowledge-node {\\n            background: rgba(255, 255, 255, 0.85);\\n            border-radius: 20px;\\n            padding: 24px;\\n            display: flex;\\n            flex-direction: column;\\n            border: 1px solid rgba(96, 129, 79, 0.15);\\n            box-shadow: 0 6px 16px rgba(0, 0, 0, 0.06);\\n            transition: all 0.3s ease;\\n            position: relative;\\n            overflow: hidden;\\n        }\\n        .knowledge-node:hover {\\n            transform: translateY(-5px);\\n            box-shadow: 0 12px 24px rgba(0, 0, 0, 0.1);\\n        }\\n        .knowledge-node::before {\\n            content: \'\';\\n            position: absolute;\\n            top: 0;\\n            left: 0;\\n            width: 100%;\\n            height: 6px;\\n            border-radius: 20px 20px 0 0;\\n        }\\n        .node-1::before { background: linear-gradient(to right, #9F7AEA, #805AD5); }\\n        .node-2::before { background: linear-gradient(to right, #2D74C8, #1A4F8C); }\\n        .node-3::before { background: linear-gradient(to right, #38B2AC, #2C7A7B); }\\n        .node-4::before { background: linear-gradient(to right, #ED8936, #DD6B20); }\\n        .node-header {\\n            display: flex;\\n            align-items: center;\\n            gap: 12px;\\n            margin-bottom: 16px;\\n        }\\n        .node-icon {\\n            width: 48px;\\n            height: 48px;\\n            border-radius: 50%;\\n            display: flex;\\n            align-items: center;\\n            justify-content: center;\\n            font-size: 20px;\\n            color: white;\\n            flex-shrink: 0;\\n        }\\n        .node-1 .node-icon { background: #9F7AEA; }\\n        .node-2 .node-icon { background: #2D74C8; }\\n        .node-3 .node-icon { background: #38B2AC; }\\n        .node-4 .node-icon { background: #ED8936; }\\n        .node-title h3 {\\n            font-size: 20px;\\n            font-weight: 800;\\n            color: #2D3748;\\n            margin-bottom: 4px;\\n        }\\n        .node-title p {\\n            font-size: 13px;\\n            color: #718096;\\n            font-weight: 500;\\n        }\\n        .node-content {\\n            flex-grow: 1;\\n            display: flex;\\n            flex-direction: column;\\n        }\\n        .node-desc {\\n            font-size: 15px;\\n            line-height: 1.6;\\n            color: #4A5568;\\n            margin-bottom: 16px;\\n            flex-grow: 1;\\n        }\\n        .node-features {\\n            list-style: none;\\n            margin-top: auto;\\n        }\\n        .node-features li {\\n            font-size: 13px;\\n            color: #5F6C7B;\\n            margin-bottom: 6px;\\n            padding-left: 18px;\\n            position: relative;\\n        }\\n        .node-features li::before {\\n            content: \'\\u2713\';\\n            position: absolute;\\n            left: 0;\\n            color: #68D391;\\n            font-weight: bold;\\n        }\\n        /* \\u4e2d\\u5fc3\\u8fde\\u63a5\\u70b9 */\\n        .center-connection {\\n            position: absolute;\\n            top: 50%;\\n            left: 50%;\\n            transform: translate(-50%, -50%);\\n            width: 80px;\\n            height: 80px;\\n            border-radius: 50%;\\n            background: linear-gradient(135deg, #ED8936, #F6AD55);\\n            display: flex;\\n            align-items: center;\\n            justify-content: center;\\n            color: white;\\n            font-size: 14px;\\n            font-weight: 800;\\n            text-align: center;\\n            box-shadow: 0 8px 24px rgba(237, 137, 54, 0.4);\\n            z-index: 2;\\n            padding: 10px;\\n            border: 4px solid rgba(255, 255, 255, 0.9);\\n        }\\n        /* \\u8fde\\u63a5\\u7ebf */\\n        .connection-line {\\n            position: absolute;\\n            z-index: 1;\\n            stroke-width: 2;\\n            stroke-dasharray: 5, 5;\\n            opacity: 0.6;\\n        }\\n        .line-1 { stroke: #9F7AEA; }\\n        .line-2 { stroke: #2D74C8; }\\n        .line-3 { stroke: #38B2AC; }\\n        .line-4 { stroke: #ED8936; }\\n        /* \\u5e95\\u90e8\\u8fdb\\u5ea6\\u63d0\\u793a */\\n        .progress-hint {\\n            margin-top: 20px;\\n            text-align: center;\\n            font-size: 14px;\\n            color: #90a28a;\\n            font-weight: 500;\\n        }\\n        .progress-hint i {\\n            margin-right: 8px;\\n            color: #8cb043;\\n        }\\n    </style>\\n</head>\\n<body>\\n    <div class=\\\"slide-container\\\">\\n        <!-- \\u4e3b\\u9898\\u88c5\\u9970\\u5c42 -->\\n        <div class=\\\"top-strip\\\"></div>\\n        <div class=\\\"bottom-strip\\\"></div>\\n        <div class=\\\"deco-circle circle-a\\\"></div>\\n        <div class=\\\"deco-circle circle-b\\\"></div>\\n        <div class=\\\"deco-circle circle-c\\\"></div>\\n        <div class=\\\"deco-circle circle-d\\\"></div>\\n        <div class=\\\"deco-circle circle-e\\\"></div>\\n        <div class=\\\"deco-circle circle-f\\\"></div>\\n        <div class=\\\"deco-circle circle-g\\\"></div>\\n        <div class=\\\"deco-circle circle-h\\\"></div>\\n        <div class=\\\"leaf-mark\\\"><span></span></div>\\n        <!-- \\u9875\\u7709\\u4fe1\\u606f -->\\n        <div class=\\\"header-band\\\">\\n            <div class=\\\"logo-group\\\">\\n                <div class=\\\"logo-badge\\\"><i class=\\\"fa-solid fa-code\\\"></i></div>\\n                <div class=\\\"logo-text\\\">\\n                    <div class=\\\"cn\\\">C\\u8bed\\u8a00\\u7a0b\\u5e8f\\u8bbe\\u8ba1</div>\\n                    <div class=\\\"en\\\">Programming in C Language</div>\\n                </div>\\n            </div>\\n            <div class=\\\"template-meta\\\">\\n                <div class=\\\"meta-title\\\">\\u7b2c\\u4e09\\u6b21\\u8bfe\\uff1a\\u5faa\\u73af\\u4e0e\\u6570\\u7ec4</div>\\n                <div class=\\\"meta-subtitle\\\">CHAPTER SUMMARY \\u00b7 KNOWLEDGE INTEGRATION \\u00b7 KEY POINTS</div>\\n            </div>\\n        </div>\\n        <!-- \\u4e3b\\u8981\\u5185\\u5bb9\\u533a\\u57df -->\\n        <div class=\\\"main-content\\\">\\n            <!-- \\u9875\\u9762\\u6807\\u9898 -->\\n            <div class=\\\"page-title-container\\\">\\n                <div class=\\\"page-title-num\\\">10</div>\\n                <div class=\\\"page-title-text\\\">\\n                    <h1>\\u672c\\u7ae0\\u91cd\\u70b9\\u603b\\u7ed3</h1>\\n                    <p>\\u6838\\u5fc3\\u6982\\u5ff5\\u7ed3\\u6784\\u5316\\u56de\\u987e\\u4e0e\\u77e5\\u8bc6\\u5730\\u56fe\\u6784\\u5efa</p>\\n                </div>\\n            </div>\\n            <!-- \\u77e5\\u8bc6\\u5730\\u56fe -->\\n            <div class=\\\"knowledge-map\\\">\\n                <!-- \\u8fde\\u63a5\\u7ebf\\uff08SVG\\uff09 -->\\n                <svg width=\\\"100%\\\" height=\\\"100%\\\" style=\\\"position: absolute; top: 0; left: 0; z-index: 1;\\\">\\n                    <line class=\\\"connection-line line-1\\\" x1=\\\"25%\\\" y1=\\\"25%\\\" x2=\\\"50%\\\" y2=\\\"50%\\\"/>\\n                    <line class=\\\"connection-line line-2\\\" x1=\\\"75%\\\" y1=\\\"25%\\\" x2=\\\"50%\\\" y2=\\\"50%\\\"/>\\n                    <line class=\\\"connection-line line-3\\\" x1=\\\"25%\\\" y1=\\\"75%\\\" x2=\\\"50%\\\" y2=\\\"50%\\\"/>\\n                    <line class=\\\"connection-line line-4\\\" x1=\\\"75%\\\" y1=\\\"75%\\\" x2=\\\"50%\\\" y2=\\\"50%\\\"/>\\n                </svg>\\n                <!-- \\u4e2d\\u5fc3\\u8fde\\u63a5\\u70b9 -->\\n                <div class=\\\"center-connection\\\">\\n                    \\u7efc\\u5408\\u5e94\\u7528<br>\\u6838\\u5fc3\\u67a2\\u7ebd\\n                </div>\\n                <!-- \\u77e5\\u8bc6\\u8282\\u70b91 -->\\n                <div class=\\\"knowledge-node node-1\\\">\\n                    <div class=\\\"node-header\\\">\\n                        <div class=\\\"node-icon\\\">\\n                            <i class=\\\"fa-solid fa-arrows-rotate\\\"></i>\\n                        </div>\\n                        <div class=\\\"node-title\\\">\\n                            <h3>\\u5faa\\u73af\\u7ed3\\u6784\\u4e09\\u5251\\u5ba2</h3>\\n                            <p>for / while / do-while \\u7684\\u9009\\u62e9\\u7b56\\u7565</p>\\n                        </div>\\n                    </div>\\n                    <div class=\\\"node-content\\\">\\n                        <p class=\\\"node-desc\\\">\\u4e09\\u79cd\\u5faa\\u73af\\u7ed3\\u6784\\u5404\\u6709\\u9002\\u7528\\u573a\\u666f\\uff0c\\u7406\\u89e3\\u5176\\u5dee\\u5f02\\u662f\\u7f16\\u5199\\u9ad8\\u6548\\u5faa\\u73af\\u4ee3\\u7801\\u7684\\u57fa\\u7840\\u3002</p>\\n                        <ul class=\\\"node-features\\\">\\n                            <li><strong>for</strong>\\uff1a\\u5df2\\u77e5\\u5faa\\u73af\\u6b21\\u6570\\uff0c\\u7ed3\\u6784\\u7d27\\u51d1</li>\\n                            <li><strong>while</strong>\\uff1a\\u6761\\u4ef6\\u4f18\\u5148\\uff0c\\u53ef\\u80fd\\u96f6\\u6b21\\u6267\\u884c</li>\\n                            <li><strong>do-while</strong>\\uff1a\\u81f3\\u5c11\\u6267\\u884c\\u4e00\\u6b21\\uff0c\\u540e\\u9a8c\\u6761\\u4ef6</li>\\n                        </ul>\\n                    </div>\\n                </div>\\n                <!-- \\u77e5\\u8bc6\\u8282\\u70b92 -->\\n                <div class=\\\"knowledge-node node-2\\\">\\n                    <div class=\\\"node-header\\\">\\n                        <div class=\\\"node-icon\\\">\\n                            <i class=\\\"fa-solid fa-traffic-light\\\"></i>\\n                        </div>\\n                        <div class=\\\"node-title\\\">\", \"is_user_edited\": false}, {\"page_number\": 11, \"title\": \"\\u8bfe\\u540e\\u4f5c\\u4e1a\\u4e0e\\u7ec3\\u4e60\", \"html_content\": \"<!DOCTYPE html>\\n<html lang=\\\"zh-CN\\\">\\n<head>\\n    <meta charset=\\\"UTF-8\\\">\\n    <meta name=\\\"viewport\\\" content=\\\"width=device-width, initial-scale=1.0\\\">\\n    <title>\\u8bfe\\u540e\\u4f5c\\u4e1a\\u4e0e\\u7ec3\\u4e60 - C\\u8bed\\u8a00\\u7b2c\\u4e09\\u6b21\\u8bfe</title>\\n    <!-- \\u5f15\\u5165\\u5b57\\u4f53\\u4e0e\\u56fe\\u6807\\u5e93 -->\\n    <link rel=\\\"preconnect\\\" href=\\\"https://fonts.googleapis.com\\\">\\n    <link rel=\\\"preconnect\\\" href=\\\"https://fonts.gstatic.com\\\" crossorigin>\\n    <link href=\\\"https://fonts.googleapis.com/css2?family=Noto+Sans+SC:wght@400;500;700;900&display=swap\\\" rel=\\\"stylesheet\\\">\\n    <link rel=\\\"stylesheet\\\" href=\\\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css\\\">\\n    <!-- \\u5f15\\u5165\\u56fe\\u8868\\u5e93 -->\\n    <script src=\\\"https://cdn.jsdelivr.net/npm/chart.js\\\"></script>\\n    <style>\\n        /* \\u57fa\\u7840\\u4e0e\\u91cd\\u7f6e\\u6837\\u5f0f */\\n        * { margin: 0; padding: 0; box-sizing: border-box; }\\n        html, body {\\n            width: 100%; height: 100%; overflow: hidden;\\n            background: #eef1ed; font-family: \'Noto Sans SC\', sans-serif;\\n            color: #26412f;\\n        }\\n        /* \\u54cd\\u5e94\\u5f0f\\u7f29\\u653e\\u5bb9\\u5668 */\\n        .slide-container {\\n            width: 100vw; height: 100vh;\\n            display: flex; justify-content: center; align-items: center;\\n        }\\n        /* \\u5e7b\\u706f\\u7247\\u6838\\u5fc3\\u753b\\u5e03\\uff08\\u4e25\\u683c 1280\\u00d7720\\uff09 */\\n        .slide {\\n            width: 1280px; height: 720px; background: #fbfcf8;\\n            position: relative; overflow: hidden; transform-origin: center center;\\n            box-shadow: 0 10px 30px rgba(0, 0, 0, 0.12);\\n        }\\n        /* \\u4e3b\\u9898\\u88c5\\u9970\\u5143\\u7d20\\uff1a\\u5b8c\\u5168\\u4fdd\\u6301\\u539f\\u6837 */\\n        .top-strip, .bottom-strip {\\n            position: absolute; left: 0; width: 100%; height: 8px;\\n            background: linear-gradient(to right, rgba(130, 130, 130, 0.12), rgba(130, 130, 130, 0.45), rgba(130, 130, 130, 0.12));\\n            z-index: 1;\\n        }\\n        .top-strip { top: 132px; }\\n        .bottom-strip { bottom: 132px; }\\n        .deco-circle {\\n            position: absolute; border-radius: 50%; z-index: 1;\\n        }\\n        .circle-a { width: 280px; height: 280px; right: 120px; top: -80px; background: #3d7a45; }\\n        .circle-b { width: 210px; height: 210px; right: 220px; top: 18px; background: #8cb043; opacity: 0.95; }\\n        .circle-c { width: 86px; height: 86px; right: 52px; top: 42px; background: #cfdc72; }\\n        .circle-d { width: 54px; height: 54px; left: 36px; top: 18px; background: #7eb377; }\\n        .circle-e { width: 150px; height: 150px; left: 70px; bottom: -58px; background: #93bf84; }\\n        .circle-f { width: 270px; height: 270px; left: 230px; bottom: -120px; background: #3f7345; opacity: 0.92; }\\n        .circle-g { width: 190px; height: 190px; left: 360px; bottom: -90px; background: #9eb841; opacity: 0.85; }\\n        .circle-h { width: 76px; height: 76px; right: 86px; bottom: 46px; background: #d8de7f; }\\n        .leaf-mark {\\n            position: absolute; top: 32px; left: 44px; width: 70px; height: 48px; z-index: 3;\\n        }\\n        .leaf-mark::before, .leaf-mark::after, .leaf-mark span {\\n            content: \'\'; position: absolute; border-radius: 0 0 40px 0;\\n        }\\n        .leaf-mark::before { left: 0; top: 0; width: 32px; height: 32px; background: #d8df79; }\\n        .leaf-mark::after { left: 18px; top: 0; width: 34px; height: 34px; background: #89a95d; }\\n        .leaf-mark span { left: 32px; top: 0; width: 38px; height: 38px; background: #426f4b; }\\n        /* \\u9875\\u7709\\u4fe1\\u606f\\u533a\\uff1a\\u5b8c\\u5168\\u4fdd\\u6301\\u539f\\u6837 */\\n        .header-band {\\n            position: absolute; left: 78px; top: 34px; right: 100px;\\n            display: flex; align-items: center; justify-content: space-between; z-index: 4;\\n        }\\n        .logo-group { display: flex; align-items: center; gap: 14px; }\\n        .logo-badge {\\n            width: 48px; height: 48px; border-radius: 50%; border: 2px solid #5f8e4f;\\n            display: flex; align-items: center; justify-content: center;\\n            color: #5f8e4f; background: rgba(255,255,255,0.95); font-size: 22px;\\n        }\\n        .logo-text { line-height: 1.2; }\\n        .logo-text .cn { font-size: 15px; font-weight: 700; color: #527845; }\\n        .logo-text .en { font-size: 10px; color: #7d8a79; letter-spacing: 0.4px; }\\n        .template-meta { text-align: right; }\\n        .template-meta .meta-title { font-size: 16px; font-weight: 700; color: #587d48; }\\n        .template-meta .meta-subtitle {\\n            margin-top: 4px; font-size: 11px; color: #98a095; letter-spacing: 0.8px;\\n        }\\n        /* \\u9875\\u811a\\u90e8\\u5206\\uff1a\\u5b8c\\u5168\\u4fdd\\u6301\\u539f\\u6837 */\\n        .pagination {\\n            position: absolute; right: 36px; bottom: 22px; z-index: 5;\\n            font-size: 18px; font-weight: 700; color: #94a08e;\\n            background: rgba(255,255,255,0.9); padding: 6px 14px; border-radius: 20px;\\n        }\\n        .footer-note {\\n            position: absolute; left: 74px; bottom: 22px; z-index: 5;\\n            font-size: 12px; color: #9aa596; letter-spacing: 0.2px;\\n        }\\n        /* \\u4e3b\\u8981\\u5185\\u5bb9\\u533a\\u57df - \\u521b\\u610f\\u8bbe\\u8ba1\\u5f00\\u59cb */\\n        .main-content {\\n            position: absolute;\\n            top: 156px; /* \\u4e0e\\u6a21\\u677fcontent-area\\u4e00\\u81f4 */\\n            left: 68px;\\n            right: 68px;\\n            bottom: 64px; /* \\u4e3a\\u9875\\u811a\\u7559\\u51fa\\u7a7a\\u95f4 */\\n            z-index: 4;\\n            display: flex;\\n            flex-direction: column;\\n        }\\n        /* \\u9875\\u9762\\u6807\\u9898\\u533a\\u57df */\\n        .page-header {\\n            margin-bottom: 30px;\\n            display: flex;\\n            align-items: center;\\n            gap: 20px;\\n        }\\n        .page-number {\\n            width: 80px;\\n            height: 80px;\\n            border-radius: 50%;\\n            background: linear-gradient(135deg, #3f7345, #6d9d53);\\n            color: white;\\n            font-size: 42px;\\n            font-weight: 900;\\n            display: flex;\\n            align-items: center;\\n            justify-content: center;\\n            box-shadow: 0 8px 20px rgba(63, 115, 69, 0.25);\\n            flex-shrink: 0;\\n        }\\n        .page-title-text h1 {\\n            font-size: 36px;\\n            font-weight: 900;\\n            color: #3f7345;\\n            line-height: 1.2;\\n            margin-bottom: 6px;\\n        }\\n        .page-title-text .subtitle {\\n            font-size: 16px;\\n            color: #7d8a79;\\n            font-weight: 500;\\n        }\\n        /* \\u4f5c\\u4e1a\\u6a21\\u5757\\u7f51\\u683c\\u5e03\\u5c40 */\\n        .assignment-grid {\\n            display: grid;\\n            grid-template-columns: repeat(4, 1fr);\\n            gap: 24px;\\n            flex-grow: 1; /* \\u5173\\u952e\\uff1a\\u8ba9\\u7f51\\u683c\\u533a\\u57df\\u81ea\\u52a8\\u6269\\u5c55\\u586b\\u6ee1\\u7a7a\\u95f4 */\\n            margin-bottom: 20px;\\n        }\\n        .assignment-card {\\n            background: rgba(255, 255, 255, 0.85);\\n            border-radius: 20px;\\n            padding: 28px 24px;\\n            border: 1px solid rgba(96, 129, 79, 0.15);\\n            display: flex;\\n            flex-direction: column;\\n            transition: all 0.3s ease;\\n            box-shadow: 0 6px 16px rgba(0, 0, 0, 0.05);\\n            position: relative;\\n            overflow: hidden;\\n        }\\n        .assignment-card:hover {\\n            transform: translateY(-5px);\\n            box-shadow: 0 12px 24px rgba(0, 0, 0, 0.1);\\n            border-color: rgba(141, 180, 127, 0.4);\\n        }\\n        /* \\u5361\\u7247\\u9876\\u90e8\\u88c5\\u9970\\u6761 */\\n        .card-accent {\\n            position: absolute;\\n            top: 0;\\n            left: 0;\\n            right: 0;\\n            height: 6px;\\n        }\\n        .card-1 .card-accent { background: linear-gradient(to right, #3f7345, #6d9d53); }\\n        .card-2 .card-accent { background: linear-gradient(to right, #8cb043, #cfdc72); }\\n        .card-3 .card-accent { background: linear-gradient(to right, #7eb377, #93bf84); }\\n        .card-4 .card-accent { background: linear-gradient(to right, #5f8e4f, #89a95d); }\\n        /* \\u5361\\u7247\\u56fe\\u6807 */\\n        .card-icon {\\n            width: 60px;\\n            height: 60px;\\n            border-radius: 50%;\\n            display: flex;\\n            align-items: center;\\n            justify-content: center;\\n            margin-bottom: 20px;\\n            font-size: 26px;\\n            color: white;\\n            box-shadow: 0 6px 12px rgba(0, 0, 0, 0.15);\\n        }\\n        .card-1 .card-icon { background: linear-gradient(135deg, #3f7345, #4e8a55); }\\n        .card-2 .card-icon { background: linear-gradient(135deg, #8cb043, #9eb841); }\\n        .card-3 .card-icon { background: linear-gradient(135deg, #7eb377, #93bf84); }\\n        .card-4 .card-icon { background: linear-gradient(135deg, #5f8e4f, #6d9d53); }\\n        /* \\u5361\\u7247\\u5185\\u5bb9 */\\n        .card-title {\\n            font-size: 22px;\\n            font-weight: 800;\\n            color: #3f7345;\\n            margin-bottom: 12px;\\n            line-height: 1.3;\\n        }\\n        .card-desc {\\n            font-size: 14px;\\n            color: #5d6a58;\\n            line-height: 1.6;\\n            margin-bottom: 18px;\\n            flex-grow: 1; /* \\u8ba9\\u63cf\\u8ff0\\u533a\\u57df\\u6269\\u5c55\\uff0c\\u63a8\\u6324\\u5e95\\u90e8\\u5185\\u5bb9 */\\n        }\\n        /* \\u4efb\\u52a1\\u5217\\u8868 */\\n        .task-list {\\n            list-style: none;\\n            margin-bottom: 20px;\\n        }\\n        .task-list li {\\n            font-size: 13px;\\n            color: #667163;\\n            margin-bottom: 8px;\\n            padding-left: 20px;\\n            position: relative;\\n            line-height: 1.5;\\n        }\\n        .task-list li::before {\\n            content: \'\\u2022\';\\n            position: absolute;\\n            left: 0;\\n            color: #8dae48;\\n            font-size: 18px;\\n        }\\n        /* \\u5361\\u7247\\u5e95\\u90e8\\u4fe1\\u606f */\\n        .card-footer {\\n            margin-top: auto; /* \\u63a8\\u5230\\u5e95\\u90e8 */\\n            padding-top: 16px;\\n            border-top: 1px dashed rgba(96, 129, 79, 0.2);\\n            display: flex;\\n            justify-content: space-between;\\n            align-items: center;\\n        }\\n        .difficulty {\\n            display: flex;\\n            align-items: center;\\n            gap: 4px;\\n        }\\n        .difficulty i {\\n            color: #cfdc72;\\n            font-size: 12px;\\n        }\\n        .difficulty i.filled { color: #8cb043; }\\n        .time-estimate {\\n            font-size: 12px;\\n            color: #7d8a79;\\n            background: rgba(141, 180, 127, 0.1);\\n            padding: 4px 10px;\\n            border-radius: 12px;\\n        }\\n        /* \\u8054\\u7cfb\\u4fe1\\u606f\\u7279\\u522b\\u6837\\u5f0f */\\n        .contact-info {\\n            display: flex;\\n            flex-direction: column;\\n            gap: 10px;\\n        }\\n        .contact-item {\\n            display: flex;\\n            align-items: center;\\n            gap: 10px;\\n            font-size: 13px;\\n            color: #5d6a58;\\n        }\\n        .contact-item i {\\n            color: #5f8e4f;\\n            width: 20px;\\n        }\\n        /* \\u5e95\\u90e8\\u5b66\\u4e60\\u8def\\u5f84\\u88c5\\u9970 */\\n        .learning-path {\\n            display: flex;\\n            align-items: center;\\n            justify-content: center;\\n            margin-top: 10px;\\n            padding: 15px 0;\\n            position: relative;\\n        }\\n        .path-line {\\n            height: 2px;\\n            background: linear-gradient(to right, transparent, #8dae48, transparent);\\n            flex-grow: 1;\\n            max-width: 800px;\\n        }\\n        .path-label {\\n            position: absolute;\\n            top: -8px;\\n            font-size: 12px;\\n            color: #7d8a79;\\n            background: #fbfcf8;\\n            padding: 0 10px;\\n        }\\n    </style>\\n</head>\\n<body>\\n    <div class=\\\"slide-container\\\">\\n        <div class=\\\"slide\\\">\\n            <!-- \\u4e3b\\u9898\\u88c5\\u9970\\u5c42\\uff1a\\u5b8c\\u5168\\u4fdd\\u6301\\u539f\\u6837 -->\\n            <div class=\\\"top-strip\\\"></div>\\n            <div class=\\\"bottom-strip\\\"></div>\\n            <div class=\\\"deco-circle circle-a\\\"></div>\\n            <div class=\\\"deco-circle circle-b\\\"></div>\\n            <div class=\\\"deco-circle circle-c\\\"></div>\\n            <div class=\\\"deco-circle circle-d\\\"></div>\\n            <div class=\\\"deco-circle circle-e\\\"></div>\\n            <div class=\\\"deco-circle circle-f\\\"></div>\\n            <div class=\\\"deco-circle circle-g\\\"></div>\\n            <div class=\\\"deco-circle circle-h\\\"></div>\\n            <div class=\\\"leaf-mark\\\"><span></span></div>\\n            <!-- \\u9875\\u7709\\u5360\\u4f4d\\u4fe1\\u606f\\uff1a\\u5b8c\\u5168\\u4fdd\\u6301\\u539f\\u6837 -->\\n            <div class=\\\"header-band\\\">\\n                <div class=\\\"logo-group\\\">\\n                    <div class=\\\"logo-badge\\\"><i class=\\\"fa-solid fa-code\\\"></i></div>\\n                    <div class=\\\"logo-text\\\">\\n                        <div class=\\\"cn\\\">\\u98df\\u54c1\\u836f\\u54c1\\u804c\\u4e1a\\u5b66\\u9662</div>\\n                        <div class=\\\"en\\\">Food and Drug Vocational College</div>\\n                    </div>\\n                </div>\\n                <div class=\\\"template-meta\\\">\\n                    <div class=\\\"meta-title\\\">C\\u8bed\\u8a00\\u7a0b\\u5e8f\\u8bbe\\u8ba1 - \\u7b2c\\u4e09\\u6b21\\u8bfe</div>\\n                    <div class=\\\"meta-subtitle\\\">GREEN \\u00b7 MINIMAL \\u00b7 CIRCLE-DRIVEN \\u00b7 SECTIONAL REPORT</div>\\n                </div>\\n            </div>\\n            <!-- \\u4e3b\\u8981\\u5185\\u5bb9\\u533a\\u57df - \\u521b\\u610f\\u8bbe\\u8ba1 -->\\n            <div class=\\\"main-content\\\">\\n                <!-- \\u9875\\u9762\\u6807\\u9898 -->\\n                <div class=\\\"page-header\\\">\\n                    <div class=\\\"page-number\\\">11</div>\\n                    <div class=\\\"page-title-text\\\">\\n                        <h1>\\u8bfe\\u540e\\u4f5c\\u4e1a\\u4e0e\\u7ec3\\u4e60</h1>\\n                        <div class=\\\"subtitle\\\">\\u4ece\\u5b9e\\u8df5\\u5230\\u62d3\\u5c55\\u7684\\u6e10\\u8fdb\\u5f0f\\u5b66\\u4e60\\u65c5\\u7a0b</div>\\n                    </div>\\n                </div>\\n                <!-- \\u4f5c\\u4e1a\\u6a21\\u5757\\u7f51\\u683c -->\\n                <div class=\\\"assignment-grid\\\">\\n                    <!-- \\u57fa\\u7840\\u7f16\\u7a0b\\u9898 -->\\n                    <div class=\\\"assignment-card card-1\\\">\\n                        <div class=\\\"card-accent\\\"></div>\\n                        <div class=\\\"card-icon\\\">\\n                            <i class=\\\"fas fa-sync-alt\\\"></i>\\n                        </div>\\n                        <h3 class=\\\"card-title\\\">\\u57fa\\u7840\\u5de9\\u56fa<br>\\u5faa\\u73af\\u7ed3\\u6784\\u5e94\\u7528</h3>\\n                        <p class=\\\"card-desc\\\">\\u638c\\u63e1\\u5faa\\u73af\\u7ed3\\u6784\\u7684\\u6838\\u5fc3\\u903b\\u8f91\\u4e0e\\u57fa\\u7840\\u5e94\\u7528\\uff0c\\u901a\\u8fc7\\u9488\\u5bf9\\u6027\\u7ec3\\u4e60\\u5efa\\u7acb\\u7f16\\u7a0b\\u601d\\u7ef4\\u3002</p>\\n                        <ul class=\\\"task-list\\\">\\n                            <li>\\u6253\\u53701-100\\u4e4b\\u95f4\\u7684\\u6240\\u6709\\u5076\\u6570</li>\\n                            <li>\\u8ba1\\u7b971\\u5230n\\u7684\\u7d2f\\u52a0\\u548c</li>\\n                            <li>\\u8f93\\u51fa\\u6307\\u5b9a\\u884c\\u6570\\u7684\\u661f\\u53f7\\u91d1\\u5b57\\u5854</li>\\n                            <li>\\u627e\\u51fa100\\u4ee5\\u5185\\u7684\\u6240\\u6709\\u7d20\\u6570</li>\\n                        </ul>\\n                        <div class=\\\"card-footer\\\">\\n                            <div class=\\\"difficulty\\\">\\n                                <i class=\\\"fas fa-star filled\\\"></i>\\n                                <i class=\\\"fas fa-star filled\\\"></i>\\n                                <i class=\\\"fas fa-star\\\"></i>\\n                                <i class=\\\"fas fa-star\\\"></i>\\n                                <i class=\\\"fas fa-star\\\"></i>\\n                            </div>\\n                            <div class=\\\"time-estimate\\\">\\u7ea660\\u5206\\u949f</div>\\n                        </div>\\n                    </div>\\n                    <!-- \\u63d0\\u9ad8\\u9898 -->\\n                    <div class=\\\"assignment-card card-2\\\">\\n                        <div class=\\\"card-accent\\\"></div>\\n                        <div class=\\\"card-icon\\\">\\n                            <i class=\\\"fas fa-layer-group\\\"></i>\\n                        </div>\\n                        <h3 class=\\\"card-title\\\">\\u80fd\\u529b\\u63d0\\u5347<br>\\u6570\\u7ec4\\u7efc\\u5408\\u5e94\\u7528</h3>\\n                        <p class=\\\"card-desc\\\">\\u7ed3\\u5408\\u6570\\u7ec4\\u4e0e\\u5faa\\u73af\\u89e3\\u51b3\\u5b9e\\u9645\\u95ee\\u9898\\uff0c\\u6311\\u6218\\u7efc\\u5408\\u7f16\\u7a0b\\u80fd\\u529b\\u7684\\u5c0f\\u578b\\u9879\\u76ee\\u3002</p>\\n                        <ul class=\\\"task-list\\\">\\n                            <li>\\u6570\\u7ec4\\u5143\\u7d20\\u9006\\u5e8f\\u5b58\\u653e</li>\\n                            <li>\\u67e5\\u627e\\u6570\\u7ec4\", \"is_user_edited\": false}, {\"page_number\": 12, \"title\": \"Q&A \\u4e0e \\u8bfe\\u7a0b\\u7ed3\\u675f\", \"html_content\": \"<!DOCTYPE html>\\n<html lang=\\\"zh-CN\\\">\\n<head>\\n    <meta charset=\\\"UTF-8\\\">\\n    <meta name=\\\"viewport\\\" content=\\\"width=device-width, initial-scale=1.0\\\">\\n    <title>C\\u8bed\\u8a00\\u7b2c\\u4e09\\u6b21\\u8bfe - Q&A \\u4e0e \\u8bfe\\u7a0b\\u7ed3\\u675f</title>\\n    <!-- \\u5f15\\u5165\\u5b57\\u4f53\\u4e0e\\u56fe\\u6807\\u5e93 -->\\n    <link rel=\\\"preconnect\\\" href=\\\"https://fonts.googleapis.com\\\">\\n    <link rel=\\\"preconnect\\\" href=\\\"https://fonts.gstatic.com\\\" crossorigin>\\n    <link href=\\\"https://fonts.googleapis.com/css2?family=Noto+Sans+SC:wght@400;500;700;900&display=swap\\\" rel=\\\"stylesheet\\\">\\n    <link rel=\\\"stylesheet\\\" href=\\\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css\\\">\\n    <style>\\n        /* \\u57fa\\u7840\\u4e0e\\u91cd\\u7f6e\\u6837\\u5f0f */\\n        * {\\n            margin: 0;\\n            padding: 0;\\n            box-sizing: border-box;\\n        }\\n        html, body {\\n            width: 100%;\\n            height: 100%;\\n            overflow: hidden;\\n            background: #eef1ed;\\n            font-family: \'Noto Sans SC\', sans-serif;\\n            color: #26412f;\\n        }\\n        /* \\u54cd\\u5e94\\u5f0f\\u7f29\\u653e\\u5bb9\\u5668 */\\n        .slide-container {\\n            width: 100vw;\\n            height: 100vh;\\n            display: flex;\\n            justify-content: center;\\n            align-items: center;\\n        }\\n        /* \\u5e7b\\u706f\\u7247\\u6838\\u5fc3\\u753b\\u5e03\\uff08\\u4e25\\u683c 1280\\u00d7720\\uff09 */\\n        .slide {\\n            width: 1280px;\\n            height: 720px;\\n            background: #fbfcf8;\\n            position: relative;\\n            overflow: hidden;\\n            transform-origin: center center;\\n            box-shadow: 0 10px 30px rgba(0, 0, 0, 0.12);\\n        }\\n        /* \\u4e3b\\u9898\\u88c5\\u9970\\u5143\\u7d20\\uff1a\\u4e25\\u683c\\u4fdd\\u6301\\u539f\\u6837 */\\n        .top-strip,\\n        .bottom-strip {\\n            position: absolute;\\n            left: 0;\\n            width: 100%;\\n            height: 8px;\\n            background: linear-gradient(to right, rgba(130, 130, 130, 0.12), rgba(130, 130, 130, 0.45), rgba(130, 130, 130, 0.12));\\n            z-index: 1;\\n        }\\n        .top-strip { top: 132px; }\\n        .bottom-strip { bottom: 132px; }\\n        .deco-circle {\\n            position: absolute;\\n            border-radius: 50%;\\n            z-index: 1;\\n        }\\n        .circle-a { width: 280px; height: 280px; right: 120px; top: -80px; background: #3d7a45; }\\n        .circle-b { width: 210px; height: 210px; right: 220px; top: 18px; background: #8cb043; opacity: 0.95; }\\n        .circle-c { width: 86px; height: 86px; right: 52px; top: 42px; background: #cfdc72; }\\n        .circle-d { width: 54px; height: 54px; left: 36px; top: 18px; background: #7eb377; }\\n        .circle-e { width: 150px; height: 150px; left: 70px; bottom: -58px; background: #93bf84; }\\n        .circle-f { width: 270px; height: 270px; left: 230px; bottom: -120px; background: #3f7345; opacity: 0.92; }\\n        .circle-g { width: 190px; height: 190px; left: 360px; bottom: -90px; background: #9eb841; opacity: 0.85; }\\n        .circle-h { width: 76px; height: 76px; right: 86px; bottom: 46px; background: #d8de7f; }\\n        .leaf-mark {\\n            position: absolute;\\n            top: 32px;\\n            left: 44px;\\n            width: 70px;\\n            height: 48px;\\n            z-index: 3;\\n        }\\n        .leaf-mark::before,\\n        .leaf-mark::after,\\n        .leaf-mark span {\\n            content: \'\';\\n            position: absolute;\\n            border-radius: 0 0 40px 0;\\n        }\\n        .leaf-mark::before {\\n            left: 0;\\n            top: 0;\\n            width: 32px;\\n            height: 32px;\\n            background: #d8df79;\\n        }\\n        .leaf-mark::after {\\n            left: 18px;\\n            top: 0;\\n            width: 34px;\\n            height: 34px;\\n            background: #89a95d;\\n        }\\n        .leaf-mark span {\\n            left: 32px;\\n            top: 0;\\n            width: 38px;\\n            height: 38px;\\n            background: #426f4b;\\n        }\\n        /* \\u9875\\u7709\\u4fe1\\u606f\\u533a - \\u4e25\\u683c\\u4fdd\\u6301\\u539f\\u6837 */\\n        .header-band {\\n            position: absolute;\\n            left: 78px;\\n            top: 34px;\\n            right: 100px;\\n            display: flex;\\n            align-items: center;\\n            justify-content: space-between;\\n            z-index: 4;\\n        }\\n        .logo-group {\\n            display: flex;\\n            align-items: center;\\n            gap: 14px;\\n        }\\n        .logo-badge {\\n            width: 48px;\\n            height: 48px;\\n            border-radius: 50%;\\n            border: 2px solid #5f8e4f;\\n            display: flex;\\n            align-items: center;\\n            justify-content: center;\\n            color: #5f8e4f;\\n            background: rgba(255,255,255,0.95);\\n            font-size: 22px;\\n        }\\n        .logo-text {\\n            line-height: 1.2;\\n        }\\n        .logo-text .cn {\\n            font-size: 15px;\\n            font-weight: 700;\\n            color: #527845;\\n        }\\n        .logo-text .en {\\n            font-size: 10px;\\n            color: #7d8a79;\\n            letter-spacing: 0.4px;\\n        }\\n        .template-meta {\\n            text-align: right;\\n        }\\n        .template-meta .meta-title {\\n            font-size: 16px;\\n            font-weight: 700;\\n            color: #587d48;\\n        }\\n        .template-meta .meta-subtitle {\\n            margin-top: 4px;\\n            font-size: 11px;\\n            color: #98a095;\\n            letter-spacing: 0.8px;\\n        }\\n        /* \\u9875\\u811a\\u533a\\u57df - \\u4e25\\u683c\\u4fdd\\u6301\\u539f\\u6837 */\\n        .footer-note {\\n            position: absolute;\\n            left: 74px;\\n            bottom: 22px;\\n            z-index: 5;\\n            font-size: 12px;\\n            color: #9aa596;\\n            letter-spacing: 0.2px;\\n        }\\n        .pagination {\\n            position: absolute;\\n            right: 36px;\\n            bottom: 22px;\\n            z-index: 5;\\n            font-size: 18px;\\n            font-weight: 700;\\n            color: #94a08e;\\n            background: rgba(255,255,255,0.9);\\n            padding: 6px 14px;\\n            border-radius: 20px;\\n        }\\n        /* \\u4e3b\\u8981\\u5185\\u5bb9\\u533a\\u57df - \\u53ef\\u4fee\\u6539\\u533a\\u57df */\\n        .content-area {\\n            position: absolute;\\n            top: 156px;\\n            left: 68px;\\n            right: 68px;\\n            bottom: 64px;\\n            z-index: 4;\\n            display: flex;\\n            flex-direction: column;\\n        }\\n        /* \\u6807\\u9898\\u533a\\u57df */\\n        .page-title {\\n            display: flex;\\n            align-items: center;\\n            gap: 20px;\\n            margin-bottom: 30px;\\n        }\\n        .page-title .num {\\n            width: 72px;\\n            height: 72px;\\n            border-radius: 50%;\\n            background: #55824a;\\n            color: white;\\n            font-size: 36px;\\n            font-weight: 900;\\n            display: flex;\\n            align-items: center;\\n            justify-content: center;\\n            box-shadow: inset 0 -8px 0 rgba(255,255,255,0.12);\\n            flex-shrink: 0;\\n        }\\n        .page-title .text h1 {\\n            font-size: 42px;\\n            line-height: 1.2;\\n            color: #4f7b45;\\n            font-weight: 900;\\n            margin-bottom: 6px;\\n        }\\n        .page-title .text p {\\n            font-size: 16px;\\n            color: #90a28a;\\n        }\\n        /* \\u4e3b\\u8981\\u5185\\u5bb9\\u5bb9\\u5668 */\\n        .main-content {\\n            flex-grow: 1;\\n            display: grid;\\n            grid-template-columns: 1fr 1fr;\\n            gap: 30px;\\n            height: calc(100% - 110px);\\n        }\\n        /* \\u5de6\\u4fa7\\u95ee\\u7b54\\u4e0e\\u603b\\u7ed3\\u533a\\u57df */\\n        .left-section {\\n            display: flex;\\n            flex-direction: column;\\n            gap: 24px;\\n        }\\n        .content-card {\\n            background: rgba(255, 255, 255, 0.85);\\n            border-radius: 20px;\\n            padding: 24px;\\n            border: 1px solid rgba(96, 129, 79, 0.14);\\n            box-shadow: 0 6px 20px rgba(0, 0, 0, 0.05);\\n            backdrop-filter: blur(4px);\\n            flex-grow: 1;\\n            display: flex;\\n            flex-direction: column;\\n        }\\n        .card-header {\\n            display: flex;\\n            align-items: center;\\n            gap: 12px;\\n            margin-bottom: 18px;\\n        }\\n        .card-icon {\\n            width: 48px;\\n            height: 48px;\\n            border-radius: 50%;\\n            background: #6d9d53;\\n            color: white;\\n            display: flex;\\n            align-items: center;\\n            justify-content: center;\\n            font-size: 20px;\\n            flex-shrink: 0;\\n        }\\n        .card-title {\\n            font-size: 22px;\\n            font-weight: 800;\\n            color: #4e7543;\\n        }\\n        .card-content {\\n            font-size: 16px;\\n            line-height: 1.7;\\n            color: #516250;\\n            flex-grow: 1;\\n            display: flex;\\n            align-items: center;\\n        }\\n        .qa-highlight {\\n            background: #f6f8f1;\\n            border-left: 4px solid #8dae48;\\n            padding: 16px;\\n            border-radius: 12px;\\n            margin-top: 12px;\\n        }\\n        /* \\u53f3\\u4fa7\\u9884\\u544a\\u4e0e\\u611f\\u8c22\\u533a\\u57df */\\n        .right-section {\\n            display: flex;\\n            flex-direction: column;\\n            gap: 24px;\\n        }\\n        .preview-card {\\n            background: linear-gradient(135deg, rgba(141, 180, 127, 0.1), rgba(109, 157, 83, 0.08));\\n            border-radius: 20px;\\n            padding: 24px;\\n            border: 2px solid rgba(141, 180, 127, 0.3);\\n            flex-grow: 1;\\n            display: flex;\\n            flex-direction: column