e=\"display: none;\">\n                    <iframe src=\"data:text/html;charset=utf-8;base64,\"\n                            style=\"width: 100%; height: 100%; border: none;\"></iframe>\n                </div>\n                \n\n    <div class=\"navigation\">\n        <button class=\"nav-btn\" onclick=\"previousSlide()\">⬅️ 上一页</button>\n        <span class=\"slide-counter\" id=\"slideCounter\">1 / 10</span>\n        <button class=\"nav-btn\" onclick=\"nextSlide()\">下一页 ➡️</button>\n    </div>\n\n    <script>\n        let currentSlide = 0;\n        const totalSlides = 10;\n\n        // No need for initialization - iframes already have src set to file paths\n\n        function showSlide(index) {\n            document.querySelectorAll(\'.slide\').forEach(slide => slide.style.display = \'none\');\n            const targetSlide = document.getElementById(\'slide-\' + (index + 1));\n            if (targetSlide) {\n                targetSlide.style.display = \'block\';\n            }\n            document.getElementById(\'slideCounter\').textContent = (index + 1) + \' / \' + totalSlides;\n        }\n\n        function nextSlide() {\n            if (currentSlide < totalSlides - 1) {\n                currentSlide++;\n                showSlide(currentSlide);\n            }\n        }\n\n        function previousSlide() {\n            if (currentSlide > 0) {\n                currentSlide--;\n                showSlide(currentSlide);\n            }\n        }\n\n        // Keyboard navigation\n        document.addEventListener(\'keydown\', function(e) {\n            if (e.key === \'ArrowRight\') nextSlide();\n            if (e.key === \'ArrowLeft\') previousSlide();\n        });\n\n        // Initialize when page loads\n        document.addEventListener(\'DOMContentLoaded\', function() {\n            showSlide(0);\n        });\n    </script>\n</body>\n</html>\n            ','[{\"page_number\": 1, \"title\": \"C\\u8bed\\u8a00\\u7b2c\\u56db\\u6b21\\u8bfe\", \"html_content\": \"<!DOCTYPE html>\\n<html lang=\\\"zh-CN\\\">\\n<head>\\n<meta charset=\\\"UTF-8\\\" />\\n<meta name=\\\"viewport\\\" content=\\\"width=device-width, initial-scale=1.0\\\" />\\n<title>C\\u8bed\\u8a00\\u7b2c\\u56db\\u6b21\\u8bfe</title>\\n<style>\\n    * { margin: 0; padding: 0; box-sizing: border-box; }\\n    html, body {\\n        width: 100%;\\n        height: 100%;\\n        overflow: hidden;\\n        background: #edf1eb;\\n        font-family: \\\"Microsoft YaHei\\\", \\\"PingFang SC\\\", \\\"Noto Sans SC\\\", sans-serif;\\n        color: #335239;\\n    }\\n    .slide-container {\\n        width: 100vw;\\n        height: 100vh;\\n        display: flex;\\n        align-items: center;\\n        justify-content: center;\\n    }\\n    .slide {\\n        width: 1280px;\\n        height: 720px;\\n        position: relative;\\n        overflow: hidden;\\n        transform-origin: center center;\\n        border-radius: 16px;\\n        background: linear-gradient(180deg, #f8faf6 0%, #f2f5ef 100%);\\n        box-shadow: 0 18px 42px rgba(0,0,0,.14);\\n    }\\n\\n    /* \\u9875\\u7709 - \\u4e25\\u683c\\u4fdd\\u6301\\u539f\\u6837 */\\n    .header {\\n        position: absolute;\\n        left: 30px;\\n        right: 30px;\\n        top: 24px;\\n        display: grid;\\n        grid-template-columns: 1fr auto;\\n        gap: 20px;\\n        align-items: start;\\n        z-index: 30;\\n    }\\n    .header h1 {\\n        font-size: 28px;\\n        line-height: 1.2;\\n        color: #48724a;\\n        font-weight: 900;\\n        letter-spacing: .4px;\\n    }\\n    .header p {\\n        margin-top: 7px;\\n        font-size: 12px;\\n        color: #7e8e7f;\\n        line-height: 1.55;\\n        max-width: 650px;\\n    }\\n\\n    .main-tabs {\\n        display: flex;\\n        gap: 10px;\\n        align-items: center;\\n        flex-wrap: wrap;\\n        justify-content: flex-end;\\n    }\\n    .main-tab {\\n        border: 1px solid rgba(90,121,80,.18);\\n        background: rgba(255,255,255,.92);\\n        color: #5f7860;\\n        border-radius: 999px;\\n        padding: 9px 16px;\\n        font-size: 14px;\\n        font-weight: 800;\\n        cursor: pointer;\\n        transition: all .18s ease;\\n    }\\n    .main-tab.active {\\n        background: #4e7b47;\\n        color: #fff;\\n        box-shadow: 0 8px 18px rgba(78,123,71,.28);\\n    }\\n\\n    /* \\u4e3b\\u8981\\u5185\\u5bb9\\u533a\\u57df - \\u521b\\u610f\\u8bbe\\u8ba1\\u90e8\\u5206 */\\n    .main-content {\\n        position: absolute;\\n        left: 28px;\\n        right: 28px;\\n        top: 98px;\\n        bottom: 56px; /* \\u4e3a\\u9875\\u811a\\u7559\\u51fa\\u7a7a\\u95f4 */\\n        display: flex;\\n        flex-direction: column;\\n        align-items: center;\\n        justify-content: center;\\n        z-index: 10;\\n    }\\n\\n    /* \\u521b\\u610f\\u6807\\u9898\\u8bbe\\u8ba1 */\\n    .title-container {\\n        text-align: center;\\n        margin-bottom: 60px;\\n        position: relative;\\n    }\\n\\n    .main-title {\\n        font-size: 64px;\\n        font-weight: 900;\\n        color: #4e874c;\\n        line-height: 1.1;\\n        margin-bottom: 16px;\\n        letter-spacing: 1px;\\n        position: relative;\\n        display: inline-block;\\n    }\\n\\n    .main-title::after {\\n        content: \'\';\\n        position: absolute;\\n        bottom: -12px;\\n        left: 50%;\\n        transform: translateX(-50%);\\n        width: 180px;\\n        height: 4px;\\n        background: linear-gradient(90deg, transparent, #74b43f, transparent);\\n        border-radius: 2px;\\n    }\\n\\n    .title-sub {\\n        font-size: 22px;\\n        color: #7e8e7f;\\n        font-weight: 600;\\n        letter-spacing: 0.5px;\\n        margin-top: 24px;\\n    }\\n\\n    /* \\u4ee3\\u7801\\u5143\\u7d20\\u88c5\\u9970 */\\n    .code-decoration {\\n        position: absolute;\\n        font-family: \\\"Consolas\\\", \\\"Monaco\\\", monospace;\\n        color: rgba(116, 180, 63, 0.15);\\n        font-size: 14px;\\n        z-index: 1;\\n        pointer-events: none;\\n    }\\n\\n    .code-1 {\\n        top: 20%;\\n        left: 10%;\\n        transform: rotate(-15deg);\\n    }\\n\\n    .code-2 {\\n        bottom: 25%;\\n        right: 12%;\\n        transform: rotate(10deg);\\n    }\\n\\n    .code-3 {\\n        top: 40%;\\n        right: 8%;\\n        transform: rotate(5deg);\\n    }\\n\\n    /* \\u4fe1\\u606f\\u5361\\u7247 */\\n    .info-cards {\\n        display: flex;\\n        gap: 40px;\\n        margin-top: 40px;\\n    }\\n\\n    .info-card {\\n        background: rgba(255, 255, 255, 0.92);\\n        border: 1px solid rgba(87, 124, 79, 0.12);\\n        border-radius: 20px;\\n        padding: 24px 32px;\\n        min-width: 200px;\\n        text-align: center;\\n        box-shadow: 0 8px 24px rgba(0, 0, 0, 0.06);\\n        transition: all 0.25s ease;\\n    }\\n\\n    .info-card:hover {\\n        transform: translateY(-4px);\\n        box-shadow: 0 12px 32px rgba(78, 123, 71, 0.15);\\n    }\\n\\n    .card-icon {\\n        font-size: 32px;\\n        margin-bottom: 12px;\\n        color: #5d8b67;\\n    }\\n\\n    .card-label {\\n        font-size: 13px;\\n        color: #7e8e7f;\\n        margin-bottom: 8px;\\n        font-weight: 600;\\n    }\\n\\n    .card-value {\\n        font-size: 18px;\\n        color: #48724a;\\n        font-weight: 800;\\n    }\\n\\n    /* \\u8fdb\\u5ea6\\u6307\\u793a\\u5668 */\\n    .progress-indicator {\\n        position: absolute;\\n        bottom: 40px;\\n        left: 50%;\\n        transform: translateX(-50%);\\n        display: flex;\\n        align-items: center;\\n        gap: 12px;\\n    }\\n\\n    .progress-dots {\\n        display: flex;\\n        gap: 8px;\\n    }\\n\\n    .progress-dot {\\n        width: 10px;\\n        height: 10px;\\n        border-radius: 50%;\\n        background: #e3ece0;\\n        transition: all 0.3s ease;\\n    }\\n\\n    .progress-dot.active {\\n        background: #74b43f;\\n        transform: scale(1.2);\\n    }\\n\\n    .progress-text {\\n        font-size: 12px;\\n        color: #7e8e7f;\\n        font-weight: 600;\\n    }\\n\\n    /* \\u80cc\\u666f\\u88c5\\u9970\\u5143\\u7d20 */\\n    .bg-element {\\n        position: absolute;\\n        border-radius: 50%;\\n        z-index: 1;\\n        pointer-events: none;\\n    }\\n\\n    .bg-1 {\\n        width: 120px;\\n        height: 120px;\\n        background: rgba(116, 180, 63, 0.08);\\n        top: 100px;\\n        left: 100px;\\n    }\\n\\n    .bg-2 {\\n        width: 80px;\\n        height: 80px;\\n        background: rgba(93, 139, 103, 0.06);\\n        bottom: 120px;\\n        right: 120px;\\n    }\\n\\n    .bg-3 {\\n        width: 60px;\\n        height: 60px;\\n        background: rgba(201, 217, 124, 0.05);\\n        top: 180px;\\n        right: 200px;\\n    }\\n\\n    /* \\u9875\\u811a - \\u4e25\\u683c\\u4fdd\\u6301\\u539f\\u6837 */\\n    .footer {\\n        position: absolute;\\n        left: 30px;\\n        right: 30px;\\n        bottom: 24px;\\n        display: flex;\\n        justify-content: space-between;\\n        align-items: center;\\n        z-index: 30;\\n    }\\n\\n    .footer-left {\\n        font-size: 11px;\\n        color: #7e8e7f;\\n    }\\n\\n    .page-number {\\n        font-size: 12px;\\n        color: #5a7a55;\\n        font-weight: 700;\\n        background: rgba(255, 255, 255, 0.9);\\n        padding: 6px 14px;\\n        border-radius: 999px;\\n        border: 1px solid rgba(90, 121, 80, 0.15);\\n    }\\n\\n    /* \\u54cd\\u5e94\\u5f0f\\u8c03\\u6574 */\\n    @media (max-width: 1366px) {\\n        .main-title {\\n            font-size: 56px;\\n        }\\n        \\n        .info-cards {\\n            gap: 30px;\\n        }\\n        \\n        .info-card {\\n            padding: 20px 28px;\\n            min-width: 180px;\\n        }\\n    }\\n\\n    @media (max-width: 1200px) {\\n        .main-title {\\n            font-size: 48px;\\n        }\\n        \\n        .title-sub {\\n            font-size: 20px;\\n        }\\n        \\n        .info-cards {\\n            flex-direction: column;\\n            gap: 20px;\\n            align-items: center;\\n        }\\n        \\n        .info-card {\\n            width: 300px;\\n        }\\n    }\\n</style>\\n</head>\\n<body>\\n<div class=\\\"slide-container\\\">\\n    <div class=\\\"slide\\\">\\n        <!-- \\u9875\\u7709 -->\\n        <div class=\\\"header\\\">\\n            <div>\\n                <h1>\\u98df\\u54c1\\u836f\\u54c1\\u804c\\u4e1a\\u5b66\\u9662 PPT \\u6a21\\u677f\\u63cf\\u8ff0\\u6587\\u4ef6\\uff08\\u5b57\\u6bb5\\u89c4\\u8303\\u7248\\uff09</h1>\\n                <p>\\u53c2\\u7167 template.html \\u7684\\\"\\u5355\\u6587\\u4ef6\\u3001\\u81ea\\u5305\\u542b\\u3001\\u56fa\\u5b9a 1280\\u00d7720\\u3001\\u54cd\\u5e94\\u5f0f\\u7f29\\u653e\\u3001\\u5360\\u4f4d\\u7b26\\u4e0e\\u89c4\\u5219\\u8bf4\\u660e\\\"\\u5199\\u6cd5\\uff0c\\u5728 v3 \\u7684\\u5b50\\u7248\\u5f0f\\u62c6\\u5206\\u57fa\\u7840\\u4e0a\\uff0c\\u7ee7\\u7eed\\u628a\\u5b57\\u6bb5\\u547d\\u540d\\u3001\\u9009\\u578b\\u89c4\\u5219\\u3001\\u7981\\u7528\\u573a\\u666f\\u548c\\u6bcd\\u7248\\u7ea6\\u675f\\u6807\\u51c6\\u5316\\uff0c\\u65b9\\u4fbf\\u540e\\u7eed\\u76f4\\u63a5\\u62ff\\u6765\\u751f\\u6210\\u65b0\\u7684 PPT\\u3002</p>\\n            </div>\\n            <div class=\\\"main-tabs\\\">\\n                <button class=\\\"main-tab active\\\">\\u5c01\\u9762\\u7cfb\\u7edf</button>\\n                <button class=\\\"main-tab\\\">\\u76ee\\u5f55\\u7cfb\\u7edf</button>\\n                <button class=\\\"main-tab\\\">\\u5185\\u5bb9\\u7cfb\\u7edf</button>\\n                <button class=\\\"main-tab\\\">\\u6570\\u636e\\u7cfb\\u7edf</button>\\n            </div>\\n        </div>\\n\\n        <!-- \\u80cc\\u666f\\u88c5\\u9970\\u5143\\u7d20 -->\\n        <div class=\\\"bg-element bg-1\\\"></div>\\n        <div class=\\\"bg-element bg-2\\\"></div>\\n        <div class=\\\"bg-element bg-3\\\"></div>\\n\\n        <!-- \\u4ee3\\u7801\\u88c5\\u9970\\u5143\\u7d20 -->\\n        <div class=\\\"code-decoration code-1\\\">int main() { return 0; }</div>\\n        <div class=\\\"code-decoration code-2\\\">printf(\\\"Hello, World!\\\");</div>\\n        <div class=\\\"code-decoration code-3\\\">for(int i=0; i&lt;10; i++) { }</div>\\n\\n        <!-- \\u4e3b\\u8981\\u5185\\u5bb9\\u533a\\u57df -->\\n        <div class=\\\"main-content\\\">\\n            <div class=\\\"title-container\\\">\\n                <h1 class=\\\"main-title\\\">C\\u8bed\\u8a00\\u7b2c\\u56db\\u6b21\\u8bfe</h1>\\n                <div class=\\\"title-sub\\\">\\u6df1\\u5165\\u7406\\u89e3\\u6307\\u9488\\u4e0e\\u5185\\u5b58\\u7ba1\\u7406</div>\\n            </div>\\n\\n            <div class=\\\"info-cards\\\">\\n                <div class=\\\"info-card\\\">\\n                    <div class=\\\"card-icon\\\">\\ud83d\\udcda</div>\\n                    <div class=\\\"card-label\\\">\\u8bfe\\u7a0b\\u5185\\u5bb9</div>\\n                    <div class=\\\"card-value\\\">\\u57fa\\u4e8e\\u6587\\u6863\\u5185\\u5bb9\\u751f\\u6210</div>\\n                </div>\\n                \\n                <div class=\\\"info-card\\\">\\n                    <div class=\\\"card-icon\\\">\\ud83d\\udc68\\u200d\\ud83c\\udfeb</div>\\n                    <div class=\\\"card-label\\\">\\u6f14\\u793a\\u8005</div>\\n                    <div class=\\\"card-value\\\">\\u5f20\\u660e \\u8bb2\\u5e08</div>\\n                </div>\\n                \\n                <div class=\\\"info-card\\\">\\n                    <div class=\\\"card-icon\\\">\\ud83d\\udcc5</div>\\n                    <div class=\\\"card-label\\\">\\u65e5\\u671f</div>\\n                    <div class=\\\"card-value\\\">2024\\u5e743\\u670815\\u65e5</div>\\n                </div>\\n            </div>\\n\\n            <div class=\\\"progress-indicator\\\">\\n                <div class=\\\"progress-text\\\">\\u8bfe\\u7a0b\\u8fdb\\u5ea6</div>\\n                <div class=\\\"progress-dots\\\">\\n                    <div class=\\\"progress-dot active\\\"></div>\\n                    <div class=\\\"progress-dot active\\\"></div>\\n                    <div class=\\\"progress-dot active\\\"></div>\\n                    <div class=\\\"progress-dot active\\\"></div>\\n                    <div class=\\\"progress-dot\\\"></div>\\n                    <div class=\\\"progress-dot\\\"></div>\\n                    <div class=\\\"progress-dot\\\"></div>\\n                    <div class=\\\"progress-dot\\\"></div>\\n                    <div class=\\\"progress-dot\\\"></div>\\n                    <div class=\\\"progress-dot\\\"></div>\\n                </div>\\n                <div class=\\\"progress-text\\\">4/10</div>\\n            </div>\\n        </div>\\n\\n        <!-- \\u9875\\u811a -->\\n        <div class=\\\"footer\\\">\\n            <div class=\\\"footer-left\\\">\\u98df\\u54c1\\u836f\\u54c1\\u804c\\u4e1a\\u5b66\\u9662 \\u00b7 \\u8ba1\\u7b97\\u673a\\u79d1\\u5b66\\u4e0e\\u6280\\u672f\\u7cfb</div>\\n            <div class=\\\"page-number\\\">1/10</div>\\n        </div>\\n    </div>\\n</div>\\n\\n<script>\\n// \\u7b80\\u5355\\u7684\\u4ea4\\u4e92\\u6548\\u679c\\ndocument.addEventListener(\'DOMContentLoaded\', function() {\\n    // \\u5361\\u7247\\u60ac\\u505c\\u6548\\u679c\\u589e\\u5f3a\\n    const cards = document.querySelectorAll(\'.info-card\');\\n    cards.forEach(card => {\\n        card.addEventListener(\'mouseenter\', function() {\\n            this.style.transform = \'translateY(-6px)\';\\n            this.style.boxShadow = \'0 16px 40px rgba(78, 123, 71, 0.2)\';\\n        });\\n        \\n        card.addEventListener(\'mouseleave\', function() {\\n            this.style.transform = \'translateY(0)\';\\n            this.style.boxShadow = \'0 8px 24px rgba(0, 0, 0, 0.06)\';\\n        });\\n    });\\n\\n    // \\u6a21\\u62df\\u6253\\u5b57\\u673a\\u6548\\u679c\\uff08\\u53ef\\u9009\\uff09\\n    const mainTitle = document.querySelector(\'.main-title\');\\n    const originalText = mainTitle.textContent;\\n    mainTitle.textContent = \'\';\\n    \\n    let i = 0;\\n    function typeWriter() {\\n        if (i < originalText.length) {\\n            mainTitle.textContent += originalText.charAt(i);\\n            i++;\\n            setTimeout(typeWriter, 50);\\n        }\\n    }\\n    \\n    // \\u5ef6\\u8fdf\\u5f00\\u59cb\\u6253\\u5b57\\u6548\\u679c\\n    setTimeout(typeWriter, 300);\\n});\\n\\n// \\u9875\\u9762\\u7f29\\u653e\\u9002\\u914d\\nfunction scaleSlide() {\\n    const slide = document.querySelector(\'.slide\');\\n    const container = document.querySelector(\'.slide-container\');\\n    const scale = Math.min(container.offsetWidth / 1280, container.offsetHeight / 720);\\n    slide.style.transform = `scale(${scale})`;\\n}\\n\\nwindow.addEventListener(\'load\', scaleSlide);\\nwindow.addEventListener(\'resize\', scaleSlide);\\n</script>\\n</body>\\n</html>\", \"is_user_edited\": false}, {\"page_number\": 2, \"title\": \"\\u8bfe\\u7a0b\\u56de\\u987e\\u4e0e\\u672c\\u6b21\\u8bfe\\u76ee\\u6807\", \"html_content\": \"<!DOCTYPE html>\\n<html lang=\\\"zh-CN\\\">\\n<head>\\n<meta charset=\\\"UTF-8\\\" />\\n<meta name=\\\"viewport\\\" content=\\\"width=device-width, initial-scale=1.0\\\" />\\n<title>\\u7b2c2\\u9875\\uff1a\\u8bfe\\u7a0b\\u56de\\u987e\\u4e0e\\u672c\\u6b21\\u8bfe\\u76ee\\u6807</title>\\n<link rel=\\\"stylesheet\\\" href=\\\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css\\\">\\n<link rel=\\\"stylesheet\\\" href=\\\"https://cdn.jsdelivr.net/npm/prismjs@1.29.0/themes/prism-tomorrow.min.css\\\">\\n<script src=\\\"https://cdn.jsdelivr.net/npm/chart.js\\\"></script>\\n<script src=\\\"https://polyfill.io/v3/polyfill.min.js?features=es6\\\"></script>\\n<script id=\\\"MathJax-script\\\" async src=\\\"https://cdn.jsdelivr.net/npm/mathjax@3/es5/tex-mml-chtml.js\\\"></script>\\n<script src=\\\"https://cdn.jsdelivr.net/npm/prismjs@1.29.0/prism.min.js\\\"></script>\\n<style>\\n    * { margin: 0; padding: 0; box-sizing: border-box; }\\n    html, body {\\n        width: 100%;\\n        height: 100%;\\n        overflow: hidden;\\n        background: #edf1eb;\\n        font-family: \\\"Microsoft YaHei\\\", \\\"PingFang SC\\\", \\\"Noto Sans SC\\\", sans-serif;\\n        color: #335239;\\n    }\\n    .slide-container {\\n        width: 100vw;\\n        height: 100vh;\\n        display: flex;\\n        align-items: center;\\n        justify-content: center;\\n    }\\n    .slide {\\n        width: 1280px;\\n        height: 720px;\\n        position: relative;\\n        overflow: hidden;\\n        transform-origin: center center;\\n        border-radius: 16px;\\n        background: linear-gradient(180deg, #f8faf6 0%, #f2f5ef 100%);\\n        box-shadow: 0 18px 42px rgba(0,0,0,.14);\\n    }\\n    /* \\u9875\\u7709 - \\u4e25\\u683c\\u4fdd\\u6301\\u539f\\u6837 */\\n    .header {\\n        position: absolute;\\n        left: 30px;\\n        right: 30px;\\n        top: 24px;\\n        display: grid;\\n        grid-template-columns: 1fr auto;\\n        gap: 20px;\\n        align-items: start;\\n        z-index: 30;\\n    }\\n    .header h1 {\\n        font-size: 28px;\\n        line-height: 1.2;\\n        color: #48724a;\\n        font-weight: 900;\\n        letter-spacing: .4px;\\n    }\\n    .header p {\\n        margin-top: 7px;\\n        font-size: 12px;\\n        color: #7e8e7f;\\n        line-height: 1.55;\\n        max-width: 650px;\\n    }\\n    .main-tabs {\\n        display: flex;\\n        gap: 10px;\\n        align-items: center;\\n        flex-wrap: wrap;\\n        justify-content: flex-end;\\n    }\\n    .main-tab {\\n        border: 1px solid rgba(90,121,80,.18);\\n        background: rgba(255,255,255,.92);\\n        color: #5f7860;\\n        border-radius: 999px;\\n        padding: 9px 16px;\\n        font-size: 14px;\\n        font-weight: 800;\\n        cursor: pointer;\\n        transition: all .18s ease;\\n    }\\n    .main-tab.active {\\n        background: #4e7b47;\\n        color: #fff;\\n        box-shadow: 0 8px 18px rgba(78,123,71,.28);\\n    }\\n    /* \\u4e3b\\u8981\\u5185\\u5bb9\\u533a\\u57df */\\n    .content-area {\\n        position: absolute;\\n        left: 28px;\\n        right: 28px;\\n        top: 98px;\\n        bottom: 26px;\\n        display: flex;\\n        flex-direction: column;\\n        padding: 20px 0;\\n    }\\n    /* \\u9875\\u811a - \\u4e25\\u683c\\u4fdd\\u6301\\u539f\\u6837 */\\n    .footer {\\n        position: absolute;\\n        left: 0;\\n        right: 0;\\n        bottom: 0;\\n        height: 26px;\\n        display: flex;\\n        align-items: center;\\n        justify-content: space-between;\\n        padding: 0 28px;\\n        font-size: 11px;\\n        color: #7e8e7f;\\n        z-index: 20;\\n    }\\n    .footer .page-number {\\n        font-weight: 700;\\n        color: #5a7a55;\\n    }\\n    /* \\u521b\\u610f\\u5185\\u5bb9\\u8bbe\\u8ba1 */\\n    .learning-path {\\n        display: flex;\\n        flex-direction: column;\\n        height: 100%;\\n        position: relative;\\n    }\\n    .path-title {\\n        text-align: center;\\n        margin-bottom: 30px;\\n        position: relative;\\n    }\\n    .path-title h2 {\\n        font-size: 32px;\\n        color: #4e7b47;\\n        font-weight: 900;\\n        margin-bottom: 8px;\\n        letter-spacing: 1px;\\n    }\\n    .path-title .subtitle {\\n        font-size: 16px;\\n        color: #7e8e7f;\\n        font-weight: 500;\\n    }\\n    .path-container {\\n        display: flex;\\n        flex: 1;\\n        align-items: center;\\n        justify-content: space-between;\\n        position: relative;\\n        padding: 0 20px;\\n    }\\n    .path-line {\\n        position: absolute;\\n        top: 50%;\\n        left: 120px;\\n        right: 120px;\\n        height: 4px;\\n        background: linear-gradient(90deg, #c9d97c, #8cb267, #4e7b47);\\n        transform: translateY(-50%);\\n        z-index: 1;\\n        border-radius: 2px;\\n    }\\n    .path-node {\\n        position: relative;\\n        z-index: 2;\\n        width: 300px;\\n        height: 320px;\\n        display: flex;\\n        flex-direction: column;\\n        align-items: center;\\n        justify-content: center;\\n    }\\n    .node-card {\\n        width: 100%;\\n        height: 100%;\\n        background: rgba(255, 255, 255, 0.95);\\n        border-radius: 24px;\\n        padding: 30px;\\n        display: flex;\\n        flex-direction: column;\\n        align-items: center;\\n        justify-content: center;\\n        box-shadow: 0 12px 30px rgba(78, 123, 71, 0.15);\\n        border: 1px solid rgba(87, 124, 79, 0.1);\\n        transition: all 0.3s ease;\\n        position: relative;\\n        overflow: hidden;\\n    }\\n    .node-card:hover {\\n        transform: translateY(-8px);\\n        box-shadow: 0 18px 40px rgba(78, 123, 71, 0.25);\\n    }\\n    .node-icon {\\n        width: 80px;\\n        height: 80px;\\n        border-radius: 50%;\\n        display: flex;\\n        align-items: center;\\n        justify-content: center;\\n        margin-bottom: 20px;\\n        font-size: 32px;\\n        color: white;\\n    }\\n    .node-card.review .node-icon {\\n        background: linear-gradient(135deg, #a8ca92, #8ab17f);\\n    }\\n    .node-card.focus .node-icon {\\n        background: linear-gradient(135deg, #74b43f, #5b8f36);\\n    }\\n    .node-card.target .node-icon {\\n        background: linear-gradient(135deg, #4e874c, #3f6e48);\\n    }\\n    .node-title {\\n        font-size: 22px;\\n        font-weight: 900;\\n        margin-bottom: 15px;\\n        text-align: center;\\n        color: #335239;\\n    }\\n    .node-content {\\n        font-size: 16px;\\n        line-height: 1.6;\\n        text-align: center;\\n        color: #607163;\\n        margin-bottom: 20px;\\n    }\\n    .node-details {\\n        font-size: 14px;\\n        color: #7e8e7f;\\n        text-align: center;\\n        line-height: 1.5;\\n        margin-top: auto;\\n    }\\n    .node-connector {\\n        position: absolute;\\n        top: 50%;\\n        width: 60px;\\n        height: 60px;\\n        transform: translateY(-50%);\\n        display: flex;\\n        align-items: center;\\n        justify-content: center;\\n        z-index: 3;\\n    }\\n    .node-connector.right {\\n        right: -30px;\\n    }\\n    .node-connector.left {\\n        left: -30px;\\n    }\\n    .connector-arrow {\\n        width: 40px;\\n        height: 40px;\\n        background: #8cb267;\\n        border-radius: 50%;\\n        display: flex;\\n        align-items: center;\\n        justify-content: center;\\n        color: white;\\n        font-size: 18px;\\n        box-shadow: 0 6px 12px rgba(140, 178, 103, 0.3);\\n    }\\n    .memory-visualization {\\n        position: absolute;\\n        bottom: 20px;\\n        left: 50%;\\n        transform: translateX(-50%);\\n        width: 80%;\\n        height: 60px;\\n        display: flex;\\n        justify-content: center;\\n        align-items: center;\\n        z-index: 1;\\n    }\\n    .memory-block {\\n        width: 40px;\\n        height: 40px;\\n        background: rgba(120, 180, 71, 0.2);\\n        border: 1px solid rgba(120, 180, 71, 0.4);\\n        margin: 0 5px;\\n        border-radius: 6px;\\n        position: relative;\\n        transition: all 0.3s ease;\\n    }\\n    .memory-block.active {\\n        background: rgba(120, 180, 71, 0.6);\\n        transform: scale(1.1);\\n        box-shadow: 0 0 10px rgba(120, 180, 71, 0.5);\\n    }\\n    .memory-pointer {\\n        position: absolute;\\n        width: 20px;\\n        height: 20px;\\n        background: #ff6b35;\\n        border-radius: 50%;\\n        top: -10px;\\n        left: 50%;\\n        transform: translateX(-50%);\\n        display: flex;\\n        align-items: center;\\n        justify-content: center;\\n        color: white;\\n        font-size: 10px;\\n        font-weight: bold;\\n        z-index: 2;\\n    }\\n    .progress-label {\\n        position: absolute;\\n        bottom: 85px;\\n        left: 50%;\\n        transform: translateX(-50%);\\n        font-size: 14px;\\n        color: #7e8e7f;\\n        font-weight: 600;\\n        white-space: nowrap;\\n    }\\n    /* \\u54cd\\u5e94\\u5f0f\\u8c03\\u6574 */\\n    @media (max-width: 1300px) {\\n        .path-node {\\n            width: 280px;\\n            height: 300px;\\n        }\\n        .node-title {\\n            font-size: 20px;\\n        }\\n        .node-content {\\n            font-size: 15px;\\n        }\\n    }\\n    /* \\u52a8\\u753b\\u6548\\u679c */\\n    @keyframes pulse {\\n        0% { transform: scale(1); }\\n        50% { transform: scale(1.05); }\\n        100% { transform: scale(1); }\\n    }\\n    .node-card.focus {\\n        animation: pulse 3s infinite ease-in-out;\\n    }\\n    /* \\u4ee3\\u7801\\u9ad8\\u4eae\\u6837\\u5f0f */\\n    .code-snippet {\\n        background: #2d2d2d;\\n        border-radius: 10px;\\n        padding: 15px;\\n        margin-top: 15px;\\n        font-family: \'Consolas\', \'Monaco\', monospace;\\n        font-size: 13px;\\n        overflow-x: auto;\\n    }\\n</style>\\n</head>\\n<body>\\n<div class=\\\"slide-container\\\">\\n    <div class=\\\"slide\\\">\\n        <!-- \\u9875\\u7709 - \\u4e25\\u683c\\u4fdd\\u6301\\u539f\\u6837 -->\\n        <div class=\\\"header\\\">\\n            <div>\\n                <h1>C\\u8bed\\u8a00\\u7b2c\\u56db\\u6b21\\u8bfe\\uff1a\\u6307\\u9488\\u9ad8\\u7ea7\\u5e94\\u7528</h1>\\n                <p>\\u98df\\u54c1\\u836f\\u54c1\\u804c\\u4e1a\\u5b66\\u9662 \\u00b7 \\u8ba1\\u7b97\\u673a\\u79d1\\u5b66\\u4e0e\\u6280\\u672f\\u7cfb \\u00b7 \\u7f16\\u7a0b\\u57fa\\u7840\\u8bfe\\u7a0b</p>\\n            </div>\\n            <div class=\\\"main-tabs\\\">\\n                <button class=\\\"main-tab\\\">\\u8bfe\\u7a0b\\u6982\\u8ff0</button>\\n                <button class=\\\"main-tab active\\\">\\u5b66\\u4e60\\u8def\\u5f84</button>\\n                <button class=\\\"main-tab\\\">\\u5b9e\\u8df5\\u6f14\\u7ec3</button>\\n                <button class=\\\"main-tab\\\">\\u77e5\\u8bc6\\u62d3\\u5c55</button>\\n            </div>\\n        </div>\\n        <!-- \\u4e3b\\u8981\\u5185\\u5bb9\\u533a\\u57df -->\\n        <div class=\\\"content-area\\\">\\n            <div class=\\\"learning-path\\\">\\n                <div class=\\\"path-title\\\">\\n                    <h2>\\u8bfe\\u7a0b\\u56de\\u987e\\u4e0e\\u672c\\u6b21\\u8bfe\\u76ee\\u6807</h2>\\n                    <div class=\\\"subtitle\\\">\\u627f\\u524d\\u542f\\u540e\\uff1a\\u4ece\\u6307\\u9488\\u57fa\\u7840\\u5230\\u9ad8\\u7ea7\\u5185\\u5b58\\u7ba1\\u7406</div>\\n                </div>\\n                <div class=\\\"path-container\\\">\\n                    <div class=\\\"path-line\\\"></div>\\n                    <!-- \\u56de\\u987e\\u8282\\u70b9 -->\\n                    <div class=\\\"path-node\\\">\\n                        <div class=\\\"node-card review\\\">\\n                            <div class=\\\"node-icon\\\">\\n                                <i class=\\\"fas fa-history\\\"></i>\\n                            </div>\\n                            <div class=\\\"node-title\\\">\\u592f\\u5b9e\\u57fa\\u7840</div>\\n                            <div class=\\\"node-content\\\">\\u6307\\u9488\\u6838\\u5fc3\\u6982\\u5ff5\\u4e0e\\u6570\\u7ec4\\u5173\\u8054\\u56de\\u987e</div>\\n                            <div class=\\\"node-details\\\">\\n                                <p><i class=\\\"fas fa-check-circle\\\" style=\\\"color:#8ab17f; margin-right:5px;\\\"></i> \\u6307\\u9488\\u53d8\\u91cf\\u5b9a\\u4e49\\u4e0e\\u521d\\u59cb\\u5316</p>\\n                                <p><i class=\\\"fas fa-check-circle\\\" style=\\\"color:#8ab17f; margin-right:5px;\\\"></i> \\u6570\\u7ec4\\u4e0e\\u6307\\u9488\\u7684\\u7b49\\u4ef7\\u5173\\u7cfb</p>\\n                                <p><i class=\\\"fas fa-check-circle\\\" style=\\\"color:#8ab17f; margin-right:5px;\\\"></i> \\u6307\\u9488\\u7b97\\u672f\\u8fd0\\u7b97\\u89c4\\u5219</p>\\n                            </div>\\n                        </div>\\n                    </div>\\n                    <div class=\\\"node-connector right\\\">\\n                        <div class=\\\"connector-arrow\\\">\\n                            <i class=\\\"fas fa-arrow-right\\\"></i>\\n                        </div>\\n                    </div>\\n                    <!-- \\u91cd\\u70b9\\u8282\\u70b9 -->\\n                    <div class=\\\"path-node\\\">\\n                        <div class=\\\"node-card focus\\\">\\n                            <div class=\\\"node-icon\\\">\\n                                <i class=\\\"fas fa-bolt\\\"></i>\\n                            </div>\\n                            <div class=\\\"node-title\\\">\\u6838\\u5fc3\\u8fdb\\u9636</div>\\n                            <div class=\\\"node-content\\\">\\u63a2\\u7d22\\u6307\\u9488\\u9ad8\\u7ea7\\u5e94\\u7528\\u4e0e\\u52a8\\u6001\\u5185\\u5b58\\u7ba1\\u7406</div>\\n                            <div class=\\\"node-details\\\">\\n                                <p><i class=\\\"fas fa-star\\\" style=\\\"color:#ffc107; margin-right:5px;\\\"></i> \\u591a\\u7ea7\\u6307\\u9488\\u4e0e\\u6307\\u9488\\u6570\\u7ec4</p>\\n                                <p><i class=\\\"fas fa-star\\\" style=\\\"color:#ffc107; margin-right:5px;\\\"></i> \\u51fd\\u6570\\u6307\\u9488\\u4e0e\\u56de\\u8c03\\u673a\\u5236</p>\\n                                <p><i class=\\\"fas fa-star\\\" style=\\\"color:#ffc107; margin-right:5px;\\\"></i> malloc/free \\u52a8\\u6001\\u5185\\u5b58\\u7ba1\\u7406</p>\\n                            </div>\\n                        </div>\\n                    </div>\\n                    <div class=\\\"node-connector right\\\">\\n                        <div class=\\\"connector-arrow\\\">\\n                            <i class=\\\"fas fa-arrow-right\\\"></i>\\n                        </div>\\n                    </div>\\n                    <!-- \\u76ee\\u6807\\u8282\\u70b9 -->\\n                    <div class=\\\"path-node\\\">\\n                        <div class=\\\"node-card target\\\">\\n                            <div class=\\\"node-icon\\\">\\n                                <i class=\\\"fas fa-bullseye\\\"></i>\\n                            </div>\\n                            <div class=\\\"node-title\\\">\\u76ee\\u6807\\u8fbe\\u6210</div>\\n                            <div class=\\\"node-content\\\">\\u80fd\\u591f\\u7075\\u6d3b\\u8fd0\\u7528\\u590d\\u6742\\u6307\\u9488\\u5e76\\u7406\\u89e3\\u5185\\u5b58\\u5206\\u914d\\u673a\\u5236</div>\\n                            <div class=\\\"node-details\\\">\\n                                <p><i class=\\\"fas fa-flag\\\" style=\\\"color:#4e874c; margin-right:5px;\\\"></i> \\u638c\\u63e1\\u6307\\u9488\\u7684\\u590d\\u6742\\u7528\\u6cd5</p>\\n                                <p><i class=\\\"fas fa-flag\\\" style=\\\"color:#4e874c; margin-right:5px;\\\"></i> \\u7406\\u89e3\\u5185\\u5b58\\u5206\\u914d\\u539f\\u7406</p>\\n                                <p><i class=\\\"fas fa-flag\\\" style=\\\"color:#4e874c; margin-right:5px;\\\"></i> \\u80fd\\u591f\\u7f16\\u5199\\u52a8\\u6001\\u6570\\u636e\\u7ed3\\u6784</p>\\n                            </div>\\n                        </div>\\n                    </div>\\n                </div>\\n                <div class=\\\"progress-label\\\">\\u5b66\\u4e60\\u8fdb\\u5ea6\\uff1a\\u7b2c2\\u9875 \\u00b7 \\u4ece\\u57fa\\u7840\\u5230\\u9ad8\\u7ea7\\u7684\\u5b8c\\u6574\\u8def\\u5f84</div>\\n                <div class=\\\"memory-visualization\\\">\\n                    <div class=\\\"memory-block\\\">\\n                        <div class=\\\"memory-pointer\\\">ptr</div>\\n                    </div>\\n                    <div class=\\\"memory-block active\\\">\\n                        <div class=\\\"memory-pointer\\\">*ptr</div>\\n                    </div>\\n                    <div class=\\\"memory-block\\\">\\n                        <div class=\\\"memory-pointer\\\">**ptr</div>\\n                    </div>\\n                    <div class=\\\"memory-block active\\\">\\n                        <div class=\\\"memory-pointer\\\">arr</div>\\n                    </div>\\n                    <div class=\\\"memory-block\\\">\\n                        <div class=\\\"memory-pointer\\\">malloc</div>\\n                    </div>\\n                    <div class=\\\"memory-block active\\\">\\n                        <div class=\\\"memory-pointer\\\">free</div>\\n                    </div>\\n                </div>\\n            </div>\\n        </div>\\n        <!-- \\u9875\\u811a - \\u4e25\\u683c\\u4fdd\\u6301\\u539f\\u6837 -->\\n        <div class=\\\"footer\\\">\\n            <div class=\\\"footer-left\\\">\\u98df\\u54c1\\u836f\\u54c1\\u804c\\u4e1a\\u5b66\\u9662 \\u00b7 C\\u8bed\\u8a00\\u7f16\\u7a0b\\u8bfe\\u7a0b</div>\\n            <div class=\\\"page-number\\\">2/10</div>\\n            <div class=\\\"footer-right\\\">\\u7b2c\\u56db\\u6b21\\u8bfe\\uff1a\\u6307\\u9488\\u9ad8\\u7ea7\\u5e94\\u7528</div>\\n        </div>\\n    </div>\\n</div>\\n<script>\\n    document.addEventListener(\'DOMContentLoaded\', function() {\\n        const memoryBlocks = document.querySelectorAll(\'.memory-block\');\\n        let currentIndex = 0;\\n        function animateMemoryBlocks() {\\n            memoryBlocks.forEach(block => block.classList.remove(\'active\'));\\n            memoryBlocks[currentIndex].classList.add(\'active\');\\n            memoryBlocks[(currentIndex + 1) % memoryBlocks.length].classList.add(\'active\');\\n            memoryBlocks[(currentIndex + 3) % memoryBlocks.length].classList.add(\'active\');\\n            currentIndex = (currentIndex + 1) % memoryBlocks.length;\\n        }\\n        animateMemoryBlocks();\\n        setInterval(\", \"is_user_edited\": false}, {\"page_number\": 3, \"title\": \"\\u6307\\u9488\\u4e0e\\u51fd\\u6570\", \"html_content\": \"<!DOCTYPE html>\\n<html lang=\\\"zh-CN\\\">\\n<head>\\n<meta charset=\\\"UTF-8\\\" />\\n<meta name=\\\"viewport\\\" content=\\\"width=device-width, initial-scale=1.0\\\" />\\n<title>\\u6307\\u9488\\u4e0e\\u51fd\\u6570 - C\\u8bed\\u8a00\\u7b2c\\u56db\\u6b21\\u8bfe</title>\\n<link rel=\\\"stylesheet\\\" href=\\\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css\\\">\\n<link rel=\\\"stylesheet\\\" href=\\\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/themes/prism-tomorrow.min.css\\\">\\n<script src=\\\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/prism.min.js\\\"></script>\\n<script src=\\\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/components/prism-c.min.js\\\"></script>\\n<script src=\\\"https://cdn.jsdelivr.net/npm/chart.js\\\"></script>\\n<style>\\n    * { margin: 0; padding: 0; box-sizing: border-box; }\\n    html, body {\\n        width: 100%;\\n        height: 100%;\\n        overflow: hidden;\\n        background: #edf1eb;\\n        font-family: \\\"Microsoft YaHei\\\", \\\"PingFang SC\\\", \\\"Noto Sans SC\\\", sans-serif;\\n        color: #335239;\\n    }\\n    .slide-container {\\n        width: 100vw;\\n        height: 100vh;\\n        display: flex;\\n        align-items: center;\\n        justify-content: center;\\n    }\\n    .slide {\\n        width: 1280px;\\n        height: 720px;\\n        position: relative;\\n        overflow: hidden;\\n        transform-origin: center center;\\n        border-radius: 16px;\\n        background: linear-gradient(180deg, #f8faf6 0%, #f2f5ef 100%);\\n        box-shadow: 0 18px 42px rgba(0,0,0,.14);\\n    }\\n    /* \\u9875\\u7709 - \\u4e25\\u683c\\u4fdd\\u6301\\u539f\\u6837 */\\n    .header {\\n        position: absolute;\\n        left: 30px;\\n        right: 30px;\\n        top: 24px;\\n        display: grid;\\n        grid-template-columns: 1fr auto;\\n        gap: 20px;\\n        align-items: start;\\n        z-index: 30;\\n    }\\n    .header h1 {\\n        font-size: 28px;\\n        line-height: 1.2;\\n        color: #48724a;\\n        font-weight: 900;\\n        letter-spacing: .4px;\\n    }\\n    .header p {\\n        margin-top: 7px;\\n        font-size: 12px;\\n        color: #7e8e7f;\\n        line-height: 1.55;\\n        max-width: 650px;\\n    }\\n    .main-tabs {\\n        display: flex;\\n        gap: 10px;\\n        align-items: center;\\n        flex-wrap: wrap;\\n        justify-content: flex-end;\\n    }\\n    .main-tab {\\n        border: 1px solid rgba(90,121,80,.18);\\n        background: rgba(255,255,255,.92);\\n        color: #5f7860;\\n        border-radius: 999px;\\n        padding: 9px 16px;\\n        font-size: 14px;\\n        font-weight: 800;\\n        cursor: pointer;\\n        transition: all .18s ease;\\n    }\\n    .main-tab.active {\\n        background: #4e7b47;\\n        color: #fff;\\n        box-shadow: 0 8px 18px rgba(78,123,71,.28);\\n    }\\n    /* \\u4e3b\\u8981\\u5185\\u5bb9\\u533a\\u57df - \\u53ef\\u521b\\u610f\\u8bbe\\u8ba1 */\\n    .content-area {\\n        position: absolute;\\n        left: 28px;\\n        right: 28px;\\n        top: 98px;\\n        bottom: 26px;\\n        display: flex;\\n        flex-direction: column;\\n        gap: 16px;\\n    }\\n    .page-title {\\n        display: flex;\\n        align-items: center;\\n        gap: 12px;\\n        margin-bottom: 8px;\\n    }\\n    .page-title h2 {\\n        font-size: 32px;\\n        color: #4e7b47;\\n        font-weight: 900;\\n        letter-spacing: 0.5px;\\n    }\\n    .page-title .subtitle {\\n        font-size: 16px;\\n        color: #7e8e7f;\\n        font-weight: 500;\\n        padding-left: 12px;\\n        border-left: 2px solid #c9d97c;\\n    }\\n    /* \\u56db\\u8c61\\u9650\\u5e03\\u5c40 */\\n    .quadrant-container {\\n        flex: 1;\\n        display: grid;\\n        grid-template-columns: 1fr 1fr;\\n        grid-template-rows: 1fr 1fr;\\n        gap: 20px;\\n        padding: 8px;\\n    }\\n    .concept-card {\\n        background: rgba(255,255,255,0.95);\\n        border-radius: 20px;\\n        padding: 24px;\\n        display: flex;\\n        flex-direction: column;\\n        border: 1px solid rgba(87,124,79,.12);\\n        box-shadow: 0 8px 24px rgba(78,123,71,.08);\\n        transition: all 0.3s ease;\\n        position: relative;\\n        overflow: hidden;\\n    }\\n    .concept-card:hover {\\n        transform: translateY(-4px);\\n        box-shadow: 0 12px 32px rgba(78,123,71,.15);\\n    }\\n    .concept-card::before {\\n        content: \'\';\\n        position: absolute;\\n        top: 0;\\n        left: 0;\\n        width: 100%;\\n        height: 6px;\\n    }\\n    .card-1::before { background: linear-gradient(90deg, #4e7b47, #78a06f); }\\n    .card-2::before { background: linear-gradient(90deg, #78a06f, #9ab48e); }\\n    .card-3::before { background: linear-gradient(90deg, #9ab48e, #c9d97c); }\\n    .card-4::before { background: linear-gradient(90deg, #c9d97c, #dbead3); }\\n    .card-header {\\n        display: flex;\\n        align-items: center;\\n        gap: 16px;\\n        margin-bottom: 18px;\\n    }\\n    .card-icon {\\n        width: 56px;\\n        height: 56px;\\n        border-radius: 16px;\\n        display: flex;\\n        align-items: center;\\n        justify-content: center;\\n        font-size: 24px;\\n        color: white;\\n        flex-shrink: 0;\\n    }\\n    .card-1 .card-icon { background: #4e7b47; }\\n    .card-2 .card-icon { background: #78a06f; }\\n    .card-3 .card-icon { background: #9ab48e; }\\n    .card-4 .card-icon { background: #c9d97c; }\\n    .card-title {\\n        font-size: 20px;\\n        font-weight: 900;\\n        color: #335239;\\n        line-height: 1.3;\\n    }\\n    .card-desc {\\n        font-size: 14px;\\n        color: #607163;\\n        line-height: 1.6;\\n        margin-bottom: 20px;\\n        flex-grow: 1;\\n    }\\n    .code-preview {\\n        background: #2d2d2d;\\n        border-radius: 12px;\\n        padding: 16px;\\n        font-family: \'Consolas\', \'Monaco\', monospace;\\n        font-size: 13px;\\n        line-height: 1.5;\\n        color: #f8f8f2;\\n        overflow: auto;\\n        max-height: 140px;\\n        margin-top: auto;\\n    }\\n    .code-preview .keyword { color: #ff79c6; }\\n    .code-preview .type { color: #8be9fd; }\\n    .code-preview .function { color: #50fa7b; }\\n    .code-preview .comment { color: #6272a4; }\\n    .code-preview .string { color: #f1fa8c; }\\n    .code-preview .number { color: #bd93f9; }\\n    /* \\u4e2d\\u592e\\u5173\\u7cfb\\u56fe */\\n    .relationship-center {\\n        position: absolute;\\n        left: 50%;\\n        top: 50%;\\n        transform: translate(-50%, -50%);\\n        width: 180px;\\n        height: 180px;\\n        z-index: 5;\\n    }\\n    .center-circle {\\n        width: 100%;\\n        height: 100%;\\n        border-radius: 50%;\\n        background: rgba(255,255,255,0.95);\\n        border: 3px solid #4e7b47;\\n        display: flex;\\n        align-items: center;\\n        justify-content: center;\\n        box-shadow: 0 10px 30px rgba(78,123,71,.2);\\n        position: relative;\\n        z-index: 2;\\n    }\\n    .center-text {\\n        font-size: 18px;\\n        font-weight: 900;\\n        color: #4e7b47;\\n        text-align: center;\\n        line-height: 1.3;\\n    }\\n    .connection-line {\\n        position: absolute;\\n        background: #c9d97c;\\n        height: 3px;\\n        border-radius: 2px;\\n        z-index: 1;\\n    }\\n    .line-1 {\\n        width: 160px;\\n        top: 50%;\\n        left: calc(50% + 90px);\\n        transform: translateY(-50%);\\n    }\\n    .line-2 {\\n        width: 160px;\\n        top: 50%;\\n        right: calc(50% + 90px);\\n        transform: translateY(-50%);\\n    }\\n    .line-3 {\\n        width: 160px;\\n        left: 50%;\\n        top: calc(50% + 90px);\\n        transform: translateX(-50%) rotate(90deg);\\n    }\\n    .line-4 {\\n        width: 160px;\\n        left: 50%;\\n        bottom: calc(50% + 90px);\\n        transform: translateX(-50%) rotate(90deg);\\n    }\\n    /* \\u9875\\u811a - \\u4e25\\u683c\\u4fdd\\u6301\\u539f\\u6837 */\\n    .footer {\\n        position: absolute;\\n        left: 0;\\n        right: 0;\\n        bottom: 0;\\n        height: 26px;\\n        display: flex;\\n        align-items: center;\\n        justify-content: space-between;\\n        padding: 0 30px;\\n        font-size: 12px;\\n        color: #7e8e7f;\\n        z-index: 30;\\n    }\\n    .page-number {\\n        font-weight: 700;\\n        color: #5f7860;\\n    }\\n    /* \\u88c5\\u9970\\u5143\\u7d20 */\\n    .decoration-circle {\\n        position: absolute;\\n        border-radius: 50%;\\n        opacity: 0.1;\\n        z-index: 0;\\n    }\\n    .circle-1 {\\n        width: 120px;\\n        height: 120px;\\n        background: #4e7b47;\\n        top: 120px;\\n        left: 80px;\\n    }\\n    .circle-2 {\\n        width: 80px;\\n        height: 80px;\\n        background: #78a06f;\\n        bottom: 100px;\\n        right: 100px;\\n    }\\n    .circle-3 {\\n        width: 60px;\\n        height: 60px;\\n        background: #c9d97c;\\n        top: 180px;\\n        right: 150px;\\n    }\\n    /* \\u54cd\\u5e94\\u5f0f\\u8c03\\u6574 */\\n    @media (max-width: 1350px) {\\n        .slide {\\n            transform: scale(0.9);\\n        }\\n    }\\n    @media (max-width: 1200px) {\\n        .slide {\\n            transform: scale(0.8);\\n        }\\n    }\\n</style>\\n</head>\\n<body>\\n<div class=\\\"slide-container\\\">\\n    <div class=\\\"slide\\\">\\n        <!-- \\u9875\\u7709 - \\u4e25\\u683c\\u4fdd\\u6301\\u539f\\u6837 -->\\n        <div class=\\\"header\\\">\\n            <div>\\n                <h1>\\u98df\\u54c1\\u836f\\u54c1\\u804c\\u4e1a\\u5b66\\u9662 PPT \\u6a21\\u677f\\u63cf\\u8ff0\\u6587\\u4ef6\\uff08\\u5b57\\u6bb5\\u89c4\\u8303\\u7248\\uff09</h1>\\n                <p>\\u53c2\\u7167 template.html \\u7684\\\"\\u5355\\u6587\\u4ef6\\u3001\\u81ea\\u5305\\u542b\\u3001\\u56fa\\u5b9a 1280\\u00d7720\\u3001\\u54cd\\u5e94\\u5f0f\\u7f29\\u653e\\u3001\\u5360\\u4f4d\\u7b26\\u4e0e\\u89c4\\u5219\\u8bf4\\u660e\\\"\\u5199\\u6cd5\\uff0c\\u5728 v3 \\u7684\\u5b50\\u7248\\u5f0f\\u62c6\\u5206\\u57fa\\u7840\\u4e0a\\uff0c\\u7ee7\\u7eed\\u628a\\u5b57\\u6bb5\\u547d\\u540d\\u3001\\u9009\\u578b\\u89c4\\u5219\\u3001\\u7981\\u7528\\u573a\\u666f\\u548c\\u6bcd\\u7248\\u7ea6\\u675f\\u6807\\u51c6\\u5316\\uff0c\\u65b9\\u4fbf\\u540e\\u7eed\\u76f4\\u63a5\\u62ff\\u6765\\u751f\\u6210\\u65b0\\u7684 PPT\\u3002</p>\\n            </div>\\n            <div class=\\\"main-tabs\\\" id=\\\"mainTabs\\\">\\n                <button class=\\\"main-tab\\\">\\u5c01\\u9762\\u7cfb\\u7edf</button>\\n                <button class=\\\"main-tab\\\">\\u76ee\\u5f55\\u7cfb\\u7edf</button>\\n                <button class=\\\"main-tab active\\\">\\u5185\\u5bb9\\u7cfb\\u7edf</button>\\n                <button class=\\\"main-tab\\\">\\u6570\\u636e\\u7cfb\\u7edf</button>\\n            </div>\\n        </div>\\n        <!-- \\u4e3b\\u8981\\u5185\\u5bb9\\u533a\\u57df - \\u521b\\u610f\\u8bbe\\u8ba1 -->\\n        <div class=\\\"content-area\\\">\\n            <div class=\\\"page-title\\\">\\n                <h2>\\u6307\\u9488\\u4e0e\\u51fd\\u6570</h2>\\n                <div class=\\\"subtitle\\\">\\u4e09\\u79cd\\u4ea4\\u4e92\\u6a21\\u5f0f\\u4e0e\\u56de\\u8c03\\u673a\\u5236</div>\\n            </div>\\n            <!-- \\u56db\\u8c61\\u9650\\u5e03\\u5c40 -->\\n            <div class=\\\"quadrant-container\\\">\\n                <!-- \\u5361\\u72471: \\u6307\\u9488\\u4f5c\\u4e3a\\u51fd\\u6570\\u53c2\\u6570 -->\\n                <div class=\\\"concept-card card-1\\\">\\n                    <div class=\\\"card-header\\\">\\n                        <div class=\\\"card-icon\\\">\\n                            <i class=\\\"fas fa-exchange-alt\\\"></i>\\n                        </div>\\n                        <div class=\\\"card-title\\\">\\u6307\\u9488\\u4f5c\\u4e3a\\u51fd\\u6570\\u53c2\\u6570<br><span style=\\\"font-size: 14px; color: #7e8e7f;\\\">\\u4f20\\u5740\\u8c03\\u7528</span></div>\\n                    </div>\\n                    <div class=\\\"card-desc\\\">\\n                        \\u901a\\u8fc7\\u4f20\\u9012\\u6307\\u9488\\u53c2\\u6570\\uff0c\\u51fd\\u6570\\u53ef\\u4ee5\\u76f4\\u63a5\\u4fee\\u6539\\u8c03\\u7528\\u8005\\u4e2d\\u7684\\u6570\\u636e\\uff0c\\u907f\\u514d\\u6570\\u636e\\u62f7\\u8d1d\\uff0c\\u63d0\\u9ad8\\u6548\\u7387\\u3002\\n                    </div>\\n                    <div class=\\\"code-preview\\\">\\n                        <span class=\\\"keyword\\\">void</span> <span class=\\\"function\\\">modifyViaPointer</span>(<span class=\\\"keyword\\\">int</span> *<span class=\\\"variable\\\">ptr</span>) {<br>\\n                        &nbsp;&nbsp;&nbsp;&nbsp;*<span class=\\\"variable\\\">ptr</span> = <span class=\\\"number\\\">100</span>; <span class=\\\"comment\\\">// \\u76f4\\u63a5\\u4fee\\u6539\\u539f\\u6570\\u636e</span><br>\\n                        }<br><br>\\n                        <span class=\\\"comment\\\">// \\u8c03\\u7528\\u793a\\u4f8b</span><br>\\n                        <span class=\\\"keyword\\\">int</span> <span class=\\\"variable\\\">value</span> = <span class=\\\"number\\\">10</span>;<br>\\n                        <span class=\\\"function\\\">modifyViaPointer</span>(&<span class=\\\"variable\\\">value</span>);<br>\\n                        <span class=\\\"comment\\\">// value \\u73b0\\u5728\\u4e3a 100</span>\\n                    </div>\\n                </div>\\n                <!-- \\u5361\\u72472: \\u6307\\u9488\\u4f5c\\u4e3a\\u51fd\\u6570\\u8fd4\\u56de\\u503c -->\\n                <div class=\\\"concept-card card-2\\\">\\n                    <div class=\\\"card-header\\\">\\n                        <div class=\\\"card-icon\\\">\\n                            <i class=\\\"fas fa-arrow-right\\\"></i>\\n                        </div>\\n                        <div class=\\\"card-title\\\">\\u6307\\u9488\\u4f5c\\u4e3a\\u51fd\\u6570\\u8fd4\\u56de\\u503c<br><span style=\\\"font-size: 14px; color: #7e8e7f;\\\">\\u52a8\\u6001\\u5185\\u5b58\\u7ba1\\u7406</span></div>\\n                    </div>\\n                    <div class=\\\"card-desc\\\">\\n                        \\u51fd\\u6570\\u53ef\\u4ee5\\u8fd4\\u56de\\u6307\\u9488\\uff0c\\u5e38\\u7528\\u4e8e\\u52a8\\u6001\\u5185\\u5b58\\u5206\\u914d\\u3001\\u5de5\\u5382\\u6a21\\u5f0f\\u7b49\\u573a\\u666f\\uff0c\\u4f46\\u8981\\u6ce8\\u610f\\u907f\\u514d\\u8fd4\\u56de\\u5c40\\u90e8\\u53d8\\u91cf\\u7684\\u5730\\u5740\\u3002\\n                    </div>\\n                    <div class=\\\"code-preview\\\">\\n                        <span class=\\\"keyword\\\">int</span>* <span class=\\\"function\\\">createArray</span>(<span class=\\\"keyword\\\">int</span> <span class=\\\"variable\\\">size</span>) {<br>\\n                        &nbsp;&nbsp;&nbsp;&nbsp;<span class=\\\"keyword\\\">return</span> (<span class=\\\"keyword\\\">int</span>*)<span class=\\\"function\\\">malloc</span>(<span class=\\\"variable\\\">size</span> * <span class=\\\"keyword\\\">sizeof</span>(<span class=\\\"keyword\\\">int</span>));<br>\\n                        }<br><br>\\n                        <span class=\\\"comment\\\">// \\u4f7f\\u7528\\u793a\\u4f8b</span><br>\\n                        <span class=\\\"keyword\\\">int</span> *<span class=\\\"variable\\\">arr</span> = <span class=\\\"function\\\">createArray</span>(<span class=\\\"number\\\">10</span>);<br>\\n                        <span class=\\\"variable\\\">arr</span>[<span class=\\\"number\\\">0</span>] = <span class=\\\"number\\\">42</span>;<br>\\n                        <span class=\\\"function\\\">free</span>(<span class=\\\"variable\\\">arr</span>); <span class=\\\"comment\\\">// \\u8bb0\\u5f97\\u91ca\\u653e\\u5185\\u5b58</span>\\n                    </div>\\n                </div>\\n                <!-- \\u5361\\u72473: \\u51fd\\u6570\\u6307\\u9488 -->\\n                <div class=\\\"concept-card card-3\\\">\\n                    <div class=\\\"card-header\\\">\\n                        <div class=\\\"card-icon\\\">\\n                            <i class=\\\"fas fa-code\\\"></i>\\n                        </div>\\n                        <div class=\\\"card-title\\\">\\u51fd\\u6570\\u6307\\u9488<br><span style=\\\"font-size: 14px; color: #7e8e7f;\\\">\\u5b9a\\u4e49\\u3001\\u58f0\\u660e\\u4e0e\\u8c03\\u7528</span></div>\\n                    </div>\\n                    <div class=\\\"card-desc\\\">\\n                        \\u6307\\u5411\\u51fd\\u6570\\u7684\\u6307\\u9488\\uff0c\\u5141\\u8bb8\\u5728\\u8fd0\\u884c\\u65f6\\u52a8\\u6001\\u9009\\u62e9\\u8981\\u8c03\\u7528\\u7684\\u51fd\\u6570\\uff0c\\u662f\\u5b9e\\u73b0\\u591a\\u6001\\u548c\\u7b56\\u7565\\u6a21\\u5f0f\\u7684\\u57fa\\u7840\\u3002\\n                    </div>\\n                    <div class=\\\"code-preview\\\">\\n                        <span class=\\\"comment\\\">// \\u51fd\\u6570\\u6307\\u9488\\u58f0\\u660e</span><br>\\n                        <span class=\\\"keyword\\\">int</span> (*<span class=\\\"variable\\\">operation</span>)(<span class=\\\"keyword\\\">int</span>, <span class=\\\"keyword\\\">int</span>);<br><br>\\n                        <span class=\\\"keyword\\\">int</span> <span class=\\\"function\\\">add</span>(<span class=\\\"keyword\\\">int</span> <span class=\\\"variable\\\">a</span>, <span class=\\\"keyword\\\">int</span> <span class=\\\"variable\\\">b</span>) {<br>\\n                        &nbsp;&nbsp;&nbsp;&nbsp;<span class=\\\"keyword\\\">return</span> <span class=\\\"variable\\\">a</span> + <span class=\\\"variable\\\">b</span>;<br>\\n                        }<br><br>\\n                        <span class=\\\"variable\\\">operation</span> = <span class=\\\"function\\\">add</span>; <span class=\\\"comment\\\">// \\u6307\\u5411add\\u51fd\\u6570</span><br>\\n                        <span class=\\\"keyword\\\">int</span> <span class=\\\"variable\\\">result</span> = <span class=\\\"variable\\\">operation</span\", \"is_user_edited\": false}, {\"page_number\": 4, \"title\": \"\\u591a\\u7ea7\\u6307\\u9488\", \"html_content\": \"<!DOCTYPE html>\\n<html lang=\\\"zh-CN\\\">\\n<head>\\n<meta charset=\\\"UTF-8\\\" />\\n<meta name=\\\"viewport\\\" content=\\\"width=device-width, initial-scale=1.0\\\" />\\n<title>\\u591a\\u7ea7\\u6307\\u9488 - C\\u8bed\\u8a00\\u7b2c\\u56db\\u6b21\\u8bfe</title>\\n<link rel=\\\"stylesheet\\\" href=\\\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css\\\">\\n<link rel=\\\"stylesheet\\\" href=\\\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/themes/prism-tomorrow.min.css\\\">\\n<script src=\\\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/prism.min.js\\\"></script>\\n<script src=\\\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/components/prism-c.min.js\\\"></script>\\n<style>\\n    * { margin: 0; padding: 0; box-sizing: border-box; }\\n    html, body {\\n        width: 100%;\\n        height: 100%;\\n        overflow: hidden;\\n        background: #edf1eb;\\n        font-family: \\\"Microsoft YaHei\\\", \\\"PingFang SC\\\", \\\"Noto Sans SC\\\", sans-serif;\\n        color: #335239;\\n    }\\n    .slide-container {\\n        width: 100vw;\\n        height: 100vh;\\n        display: flex;\\n        align-items: center;\\n        justify-content: center;\\n    }\\n    .slide {\\n        width: 1280px;\\n        height: 720px;\\n        position: relative;\\n        overflow: hidden;\\n        transform-origin: center center;\\n        border-radius: 16px;\\n        background: linear-gradient(180deg, #f8faf6 0%, #f2f5ef 100%);\\n        box-shadow: 0 18px 42px rgba(0,0,0,.14);\\n    }\\n    /* \\u9875\\u7709 - \\u4e25\\u683c\\u4fdd\\u6301\\u539f\\u6837 */\\n    .header {\\n        position: absolute;\\n        left: 30px;\\n        right: 30px;\\n        top: 24px;\\n        display: grid;\\n        grid-template-columns: 1fr auto;\\n        gap: 20px;\\n        align-items: start;\\n        z-index: 30;\\n    }\\n    .header h1 {\\n        font-size: 28px;\\n        line-height: 1.2;\\n        color: #48724a;\\n        font-weight: 900;\\n        letter-spacing: .4px;\\n    }\\n    .header p {\\n        margin-top: 7px;\\n        font-size: 12px;\\n        color: #7e8e7f;\\n        line-height: 1.55;\\n        max-width: 650px;\\n    }\\n    .main-tabs {\\n        display: flex;\\n        gap: 10px;\\n        align-items: center;\\n        flex-wrap: wrap;\\n        justify-content: flex-end;\\n    }\\n    .main-tab {\\n        border: 1px solid rgba(90,121,80,.18);\\n        background: rgba(255,255,255,.92);\\n        color: #5f7860;\\n        border-radius: 999px;\\n        padding: 9px 16px;\\n        font-size: 14px;\\n        font-weight: 800;\\n        cursor: pointer;\\n        transition: all .18s ease;\\n    }\\n    .main-tab.active {\\n        background: #4e7b47;\\n        color: #fff;\\n        box-shadow: 0 8px 18px rgba(78,123,71,.28);\\n    }\\n    /* \\u4e3b\\u8981\\u5185\\u5bb9\\u533a\\u57df - \\u521b\\u610f\\u8bbe\\u8ba1\\u90e8\\u5206 */\\n    .content-area {\\n        position: absolute;\\n        left: 28px;\\n        right: 28px;\\n        top: 98px;\\n        bottom: 26px;\\n        display: flex;\\n        flex-direction: column;\\n    }\\n    .page-title {\\n        font-size: 36px;\\n        font-weight: 900;\\n        color: #2A5CAA;\\n        margin-bottom: 8px;\\n        display: flex;\\n        align-items: center;\\n        gap: 12px;\\n    }\\n    .page-title .subtitle {\\n        font-size: 18px;\\n        color: #7e8e7f;\\n        font-weight: 500;\\n    }\\n    .page-title i {\\n        color: #FF6B35;\\n        font-size: 32px;\\n    }\\n    .main-content {\\n        display: flex;\\n        flex: 1;\\n        gap: 24px;\\n        margin-top: 12px;\\n    }\\n    .left-panel {\\n        flex: 1;\\n        display: flex;\\n        flex-direction: column;\\n        gap: 20px;\\n    }\\n    .right-panel {\\n        flex: 1;\\n        display: flex;\\n        flex-direction: column;\\n        gap: 20px;\\n    }\\n    .concept-card {\\n        background: rgba(255,255,255,.95);\\n        border-radius: 20px;\\n        padding: 22px;\\n        box-shadow: 0 8px 24px rgba(42,92,170,.08);\\n        border: 1px solid rgba(42,92,170,.12);\\n        flex: 1;\\n        display: flex;\\n        flex-direction: column;\\n    }\\n    .card-title {\\n        font-size: 20px;\\n        font-weight: 900;\\n        color: #1A3A6A;\\n        margin-bottom: 16px;\\n        display: flex;\\n        align-items: center;\\n        gap: 10px;\\n    }\\n    .card-title i {\\n        color: #4CAF50;\\n    }\\n    .concept-list {\\n        display: flex;\\n        flex-direction: column;\\n        gap: 16px;\\n        flex: 1;\\n    }\\n    .concept-item {\\n        display: flex;\\n        gap: 14px;\\n        align-items: flex-start;\\n    }\\n    .concept-icon {\\n        width: 32px;\\n        height: 32px;\\n        border-radius: 50%;\\n        background: #2A5CAA;\\n        color: white;\\n        display: flex;\\n        align-items: center;\\n        justify-content: center;\\n        font-weight: bold;\\n        font-size: 14px;\\n        flex-shrink: 0;\\n    }\\n    .concept-text {\\n        flex: 1;\\n    }\\n    .concept-text h4 {\\n        font-size: 16px;\\n        font-weight: 800;\\n        color: #2A5CAA;\\n        margin-bottom: 4px;\\n    }\\n    .concept-text p {\\n        font-size: 14px;\\n        color: #5a6c7d;\\n        line-height: 1.5;\\n    }\\n    .code-example {\\n        background: #1a1a1a;\\n        border-radius: 12px;\\n        padding: 16px;\\n        font-family: \'Consolas\', \'Monaco\', monospace;\\n        font-size: 14px;\\n        line-height: 1.5;\\n        color: #f8f8f2;\\n        overflow: auto;\\n        margin-top: 8px;\\n    }\\n    .memory-diagram {\\n        background: rgba(255,255,255,.95);\\n        border-radius: 20px;\\n        padding: 22px;\\n        box-shadow: 0 8px 24px rgba(255,107,53,.08);\\n        border: 1px solid rgba(255,107,53,.12);\\n        flex: 1;\\n        display: flex;\\n        flex-direction: column;\\n    }\\n    .diagram-title {\\n        font-size: 20px;\\n        font-weight: 900;\\n        color: #FF6B35;\\n        margin-bottom: 16px;\\n        display: flex;\\n        align-items: center;\\n        gap: 10px;\\n    }\\n    .diagram-container {\\n        flex: 1;\\n        display: flex;\\n        align-items: center;\\n        justify-content: center;\\n        position: relative;\\n    }\\n    .pointer-levels {\\n        display: flex;\\n        align-items: center;\\n        justify-content: center;\\n        gap: 40px;\\n    }\\n    .level-box {\\n        width: 120px;\\n        height: 120px;\\n        border-radius: 16px;\\n        display: flex;\\n        flex-direction: column;\\n        align-items: center;\\n        justify-content: center;\\n        position: relative;\\n        transition: all 0.3s ease;\\n    }\\n    .level-box:hover {\\n        transform: translateY(-5px);\\n        box-shadow: 0 12px 28px rgba(0,0,0,.15);\\n    }\\n    .level-1 {\\n        background: linear-gradient(135deg, #e3f2fd, #bbdefb);\\n        border: 3px solid #64b5f6;\\n    }\\n    .level-2 {\\n        background: linear-gradient(135deg, #e8f5e9, #c8e6c9);\\n        border: 3px solid #81c784;\\n    }\\n    .level-3 {\\n        background: linear-gradient(135deg, #fff3e0, #ffe0b2);\\n        border: 3px solid #ffb74d;\\n    }\\n    .level-label {\\n        font-size: 14px;\\n        font-weight: 800;\\n        color: #333;\\n        margin-bottom: 8px;\\n    }\\n    .level-value {\\n        font-size: 18px;\\n        font-weight: 900;\\n        color: #1A3A6A;\\n        font-family: \'Consolas\', monospace;\\n    }\\n    .level-address {\\n        font-size: 12px;\\n        color: #FF6B35;\\n        font-family: \'Consolas\', monospace;\\n        margin-top: 6px;\\n    }\\n    .arrow {\\n        font-size: 28px;\\n        color: #4CAF50;\\n        font-weight: bold;\\n    }\\n    .application-card {\\n        background: rgba(255,255,255,.95);\\n        border-radius: 20px;\\n        padding: 22px;\\n        box-shadow: 0 8px 24px rgba(76,175,80,.08);\\n        border: 1px solid rgba(76,175,80,.12);\\n        flex: 1;\\n        display: flex;\\n        flex-direction: column;\\n    }\\n    .app-title {\\n        font-size: 20px;\\n        font-weight: 900;\\n        color: #4CAF50;\\n        margin-bottom: 16px;\\n        display: flex;\\n        align-items: center;\\n        gap: 10px;\\n    }\\n    .app-content {\\n        display: flex;\\n        flex: 1;\\n        gap: 20px;\\n    }\\n    .app-description {\\n        flex: 1;\\n        display: flex;\\n        flex-direction: column;\\n        gap: 12px;\\n    }\\n    .app-step {\\n        display: flex;\\n        gap: 10px;\\n        align-items: flex-start;\\n    }\\n    .step-number {\\n        width: 24px;\\n        height: 24px;\\n        border-radius: 50%;\\n        background: #4CAF50;\\n        color: white;\\n        display: flex;\\n        align-items: center;\\n        justify-content: center;\\n        font-size: 12px;\\n        font-weight: bold;\\n        flex-shrink: 0;\\n    }\\n    .step-text {\\n        font-size: 14px;\\n        color: #5a6c7d;\\n        line-height: 1.5;\\n    }\\n    .code-image-container {\\n        flex: 1;\\n        border-radius: 12px;\\n        overflow: hidden;\\n        box-shadow: 0 6px 18px rgba(0,0,0,.1);\\n        border: 1px solid rgba(0,0,0,.08);\\n        display: flex;\\n        align-items: center;\\n        justify-content: center;\\n        background: #f8f9fa;\\n    }\\n    .code-image {\\n        max-width: 100%;\\n        max-height: 100%;\\n        object-fit: contain;\\n    }\\n    .image-caption {\\n        text-align: center;\\n        font-size: 12px;\\n        color: #7e8e7f;\\n        margin-top: 8px;\\n        font-style: italic;\\n    }\\n    .key-summary {\\n        background: linear-gradient(135deg, #2A5CAA, #1A3A6A);\\n        border-radius: 16px;\\n        padding: 18px 24px;\\n        margin-top: 20px;\\n        color: white;\\n        display: flex;\\n        align-items: center;\\n        gap: 16px;\\n    }\\n    .summary-icon {\\n        font-size: 28px;\\n        color: #FF6B35;\\n    }\\n    .summary-text {\\n        flex: 1;\\n        font-size: 16px;\\n        line-height: 1.5;\\n    }\\n    .summary-text strong {\\n        color: #FFD54F;\\n    }\\n    /* \\u9875\\u811a - \\u4e25\\u683c\\u4fdd\\u6301\\u539f\\u6837 */\\n    .footer {\\n        position: absolute;\\n        left: 0;\\n        right: 0;\\n        bottom: 0;\\n        height: 40px;\\n        display: flex;\\n        align-items: center;\\n        justify-content: space-between;\\n        padding: 0 30px;\\n        background: rgba(255,255,255,.9);\\n        border-top: 1px solid rgba(87,124,79,.12);\\n        z-index: 30;\\n    }\\n    .footer .page-number {\\n        font-size: 14px;\\n        color: #5f7860;\\n        font-weight: 700;\\n    }\\n    .footer .slide-info {\\n        font-size: 12px;\\n        color: #7e8e7f;\\n    }\\n    /* \\u54cd\\u5e94\\u5f0f\\u8c03\\u6574 */\\n    @media (max-width: 1350px) {\\n        .pointer-levels {\\n            gap: 30px;\\n        }\\n        .level-box {\\n            width: 100px;\\n            height: 100px;\\n        }\\n    }\\n</style>\\n</head>\\n<body>\\n<div class=\\\"slide-container\\\">\\n    <div class=\\\"slide\\\">\\n        <!-- \\u9875\\u7709\\u533a\\u57df - \\u4e25\\u683c\\u4fdd\\u6301\\u539f\\u6837 -->\\n        <div class=\\\"header\\\">\\n            <div>\\n                <h1>\\u98df\\u54c1\\u836f\\u54c1\\u804c\\u4e1a\\u5b66\\u9662 PPT \\u6a21\\u677f\\u63cf\\u8ff0\\u6587\\u4ef6\\uff08\\u5b57\\u6bb5\\u89c4\\u8303\\u7248\\uff09</h1>\\n                <p>\\u53c2\\u7167 template.html \\u7684\\\"\\u5355\\u6587\\u4ef6\\u3001\\u81ea\\u5305\\u542b\\u3001\\u56fa\\u5b9a 1280\\u00d7720\\u3001\\u54cd\\u5e94\\u5f0f\\u7f29\\u653e\\u3001\\u5360\\u4f4d\\u7b26\\u4e0e\\u89c4\\u5219\\u8bf4\\u660e\\\"\\u5199\\u6cd5\\uff0c\\u5728 v3 \\u7684\\u5b50\\u7248\\u5f0f\\u62c6\\u5206\\u57fa\\u7840\\u4e0a\\uff0c\\u7ee7\\u7eed\\u628a\\u5b57\\u6bb5\\u547d\\u540d\\u3001\\u9009\\u578b\\u89c4\\u5219\\u3001\\u7981\\u7528\\u573a\\u666f\\u548c\\u6bcd\\u7248\\u7ea6\\u675f\\u6807\\u51c6\\u5316\\uff0c\\u65b9\\u4fbf\\u540e\\u7eed\\u76f4\\u63a5\\u62ff\\u6765\\u751f\\u6210\\u65b0\\u7684 PPT\\u3002</p>\\n            </div>\\n            <div class=\\\"main-tabs\\\">\\n                <button class=\\\"main-tab\\\">\\u5c01\\u9762\\u7cfb\\u7edf</button>\\n                <button class=\\\"main-tab\\\">\\u76ee\\u5f55\\u7cfb\\u7edf</button>\\n                <button class=\\\"main-tab active\\\">\\u5185\\u5bb9\\u7cfb\\u7edf</button>\\n                <button class=\\\"main-tab\\\">\\u6570\\u636e\\u7cfb\\u7edf</button>\\n            </div>\\n        </div>\\n        <!-- \\u4e3b\\u8981\\u5185\\u5bb9\\u533a\\u57df - \\u521b\\u610f\\u8bbe\\u8ba1\\u90e8\\u5206 -->\\n        <div class=\\\"content-area\\\">\\n            <div class=\\\"page-title\\\">\\n                <i class=\\\"fas fa-project-diagram\\\"></i>\\n                \\u591a\\u7ea7\\u6307\\u9488\\n                <span class=\\\"subtitle\\\">\\u7406\\u89e3\\\"\\u5730\\u5740\\u7684\\u5730\\u5740\\\"</span>\\n            </div>\\n            <div class=\\\"main-content\\\">\\n                <!-- \\u5de6\\u4fa7\\u9762\\u677f\\uff1a\\u6982\\u5ff5\\u4e0e\\u539f\\u7406 -->\\n                <div class=\\\"left-panel\\\">\\n                    <div class=\\\"concept-card\\\">\\n                        <div class=\\\"card-title\\\">\\n                            <i class=\\\"fas fa-cube\\\"></i>\\n                            \\u6982\\u5ff5\\u4e0e\\u539f\\u7406\\n                        </div>\\n                        <div class=\\\"concept-list\\\">\\n                            <div class=\\\"concept-item\\\">\\n                                <div class=\\\"concept-icon\\\">1</div>\\n                                <div class=\\\"concept-text\\\">\\n                                    <h4>\\u4e8c\\u7ea7\\u6307\\u9488 (int **pp)</h4>\\n                                    <p>\\u6307\\u5411\\u6307\\u9488\\u7684\\u6307\\u9488\\uff0c\\u5b58\\u50a8\\u7684\\u662f\\u6307\\u9488\\u53d8\\u91cf\\u7684\\u5730\\u5740</p>\\n                                    <div class=\\\"code-example\\\">\\n                                        int a = 10;<br>\\n                                        int *p = &a;    // p\\u6307\\u5411a<br>\\n                                        int **pp = &p;  // pp\\u6307\\u5411p\\n                                    </div>\\n                                </div>\\n                            </div>\\n                            <div class=\\\"concept-item\\\">\\n                                <div class=\\\"concept-icon\\\">2</div>\\n                                <div class=\\\"concept-text\\\">\\n                                    <h4>\\u58f0\\u660e\\u4e0e\\u521d\\u59cb\\u5316</h4>\\n                                    <p>\\u591a\\u7ea7\\u6307\\u9488\\u7684\\u58f0\\u660e\\u8bed\\u6cd5\\u4e0e\\u5c42\\u7ea7\\u5bf9\\u5e94\\u5173\\u7cfb</p>\\n                                    <div class=\\\"code-example\\\">\\n                                        int **pp;<br><br>\\n                                        int ***ppp;<br><br>\\n                                        int x = 5;<br>\\n                                        int *p = &x;<br>\\n                                        int **pp = &p;\\n                                    </div>\\n                                </div>\\n                            </div>\\n                        </div>\\n                    </div>\\n                    <div class=\\\"memory-diagram\\\">\\n                        <div class=\\\"diagram-title\\\">\\n                            <i class=\\\"fas fa-sitemap\\\"></i>\\n                            \\u5185\\u5b58\\u5c42\\u7ea7\\u56fe\\u89e3\\n                        </div>\\n                        <div class=\\\"diagram-container\\\">\\n                            <div class=\\\"pointer-levels\\\">\\n                                <div class=\\\"level-box level-3\\\">\\n                                    <div class=\\\"level-label\\\">\\u4e09\\u7ea7\\u6307\\u9488</div>\\n                                    <div class=\\\"level-value\\\">ppp</div>\\n                                    <div class=\\\"level-address\\\">0x1008</div>\\n                                </div>\\n                                <div class=\\\"arrow\\\">\\u2192</div>\\n                                <div class=\\\"level-box level-2\\\">\\n                                    <div class=\\\"level-label\\\">\\u4e8c\\u7ea7\\u6307\\u9488</div>\\n                                    <div class=\\\"level-value\\\">pp</div>\\n                                    <div class=\\\"level-address\\\">0x1010</div>\\n                                </div>\\n                                <div class=\\\"arrow\\\">\\u2192</div>\\n                                <div class=\\\"level-box level-1\\\">\\n                                    <div class=\\\"level-label\\\">\\u4e00\\u7ea7\\u6307\\u9488</div>\\n                                    <div class=\\\"level-value\\\">p</div>\\n                                    <div class=\\\"level-address\\\">0x1018</div>\\n                                </div>\\n                                <div class=\\\"arrow\\\">\\u2192</div>\\n                                <div class=\\\"level-box\\\" style=\\\"background:linear-gradient(135deg, #fce4ec, #f8bbd9); border:3px solid #f48fb1;\\\">\\n                                    <div class=\\\"level-label\\\">\\u6574\\u578b\\u53d8\\u91cf</div>\\n                                    <div class=\\\"level-value\\\">a = 10</div>\\n                                    <div class=\\\"level-address\\\">0x1020</div>\\n                                </div>\\n                            </div>\\n                        </div>\\n                    </div>\\n                </div>\\n                <!-- \\u53f3\\u4fa7\\u9762\\u677f\\uff1a\\u5e94\\u7528\\u4e0e\\u5b9e\\u8df5 -->\\n                <div class=\\\"right-panel\\\">\\n                    <div class=\\\"application-card\\\">\\n                        <div\", \"is_user_edited\": false}, {\"page_number\": 5, \"title\": \"\\u52a8\\u6001\\u5185\\u5b58\\u7ba1\\u7406\\uff1amalloc\\u4e0efree\", \"html_content\": \"<!DOCTYPE html>\\n<html lang=\\\"zh-CN\\\">\\n<head>\\n<meta charset=\\\"UTF-8\\\" />\\n<meta name=\\\"viewport\\\" content=\\\"width=device-width, initial-scale=1.0\\\" />\\n<title>\\u52a8\\u6001\\u5185\\u5b58\\u7ba1\\u7406\\uff1amalloc\\u4e0efree</title>\\n<link rel=\\\"stylesheet\\\" href=\\\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css\\\">\\n<link rel=\\\"stylesheet\\\" href=\\\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/themes/prism-tomorrow.min.css\\\">\\n<script src=\\\"https://cdn.jsdelivr.net/npm/chart.js\\\"></script>\\n<script src=\\\"https://polyfill.io/v3/polyfill.min.js?features=es6\\\"></script>\\n<script id=\\\"MathJax-script\\\" async src=\\\"https://cdn.jsdelivr.net/npm/mathjax@3/es5/tex-mml-chtml.js\\\"></script>\\n<script src=\\\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/prism.min.js\\\"></script>\\n<script src=\\\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/components/prism-c.min.js\\\"></script>\\n<style>\\n    * { margin: 0; padding: 0; box-sizing: border-box; }\\n    html, body {\\n        width: 100%;\\n        height: 100%;\\n        overflow: hidden;\\n        background: #edf1eb;\\n        font-family: \\\"Microsoft YaHei\\\", \\\"PingFang SC\\\", \\\"Noto Sans SC\\\", sans-serif;\\n        color: #335239;\\n    }\\n    .slide-container {\\n        width: 100vw;\\n        height: 100vh;\\n        display: flex;\\n        align-items: center;\\n        justify-content: center;\\n    }\\n    .slide {\\n        width: 1280px;\\n        height: 720px;\\n        position: relative;\\n        overflow: hidden;\\n        transform-origin: center center;\\n        border-radius: 16px;\\n        background: linear-gradient(180deg, #f8faf6 0%, #f2f5ef 100%);\\n        box-shadow: 0 18px 42px rgba(0,0,0,.14);\\n    }\\n    /* \\u9875\\u7709 - \\u4e25\\u683c\\u4fdd\\u6301\\u539f\\u6837 */\\n    .header {\\n        position: absolute;\\n        left: 30px;\\n        right: 30px;\\n        top: 24px;\\n        display: grid;\\n        grid-template-columns: 1fr auto;\\n        gap: 20px;\\n        align-items: start;\\n        z-index: 30;\\n    }\\n    .header h1 {\\n        font-size: 28px;\\n        line-height: 1.2;\\n        color: #48724a;\\n        font-weight: 900;\\n        letter-spacing: .4px;\\n    }\\n    .header p {\\n        margin-top: 7px;\\n        font-size: 12px;\\n        color: #7e8e7f;\\n        line-height: 1.55;\\n        max-width: 650px;\\n    }\\n    .main-tabs {\\n        display: flex;\\n        gap: 10px;\\n        align-items: center;\\n        flex-wrap: wrap;\\n        justify-content: flex-end;\\n    }\\n    .main-tab {\\n        border: 1px solid rgba(90,121,80,.18);\\n        background: rgba(255,255,255,.92);\\n        color: #5f7860;\\n        border-radius: 999px;\\n        padding: 9px 16px;\\n        font-size: 14px;\\n        font-weight: 800;\\n        cursor: pointer;\\n        transition: all .18s ease;\\n    }\\n    .main-tab.active {\\n        background: #4e7b47;\\n        color: #fff;\\n        box-shadow: 0 8px 18px rgba(78,123,71,.28);\\n    }\\n    /* \\u4e3b\\u8981\\u5185\\u5bb9\\u533a\\u57df - \\u521b\\u610f\\u8bbe\\u8ba1\\u90e8\\u5206 */\\n    .content-area {\\n        position: absolute;\\n        left: 28px;\\n        right: 28px;\\n        top: 98px;\\n        bottom: 26px;\\n        display: flex;\\n        flex-direction: column;\\n        gap: 16px;\\n    }\\n    .page-title {\\n        color: #4a7b43;\\n        font-size: 32px;\\n        font-weight: 900;\\n        margin-bottom: 8px;\\n        padding-left: 8px;\\n        border-left: 6px solid #7da965;\\n    }\\n    .content-grid {\\n        flex: 1;\\n        display: grid;\\n        grid-template-columns: 1fr 1fr;\\n        gap: 20px;\\n        height: calc(100% - 60px);\\n    }\\n    .left-column {\\n        display: flex;\\n        flex-direction: column;\\n        gap: 20px;\\n    }\\n    .right-column {\\n        display: flex;\\n        flex-direction: column;\\n        gap: 20px;\\n    }\\n    .content-card {\\n        background: rgba(255, 255, 255, 0.92);\\n        border-radius: 20px;\\n        border: 1px solid rgba(87, 124, 79, 0.15);\\n        padding: 22px;\\n        box-shadow: 0 8px 24px rgba(78, 123, 71, 0.08);\\n        transition: transform 0.3s ease;\\n        height: 100%;\\n        display: flex;\\n        flex-direction: column;\\n    }\\n    .content-card:hover {\\n        transform: translateY(-4px);\\n        box-shadow: 0 12px 28px rgba(78, 123, 71, 0.12);\\n    }\\n    .card-header {\\n        display: flex;\\n        align-items: center;\\n        gap: 12px;\\n        margin-bottom: 16px;\\n        padding-bottom: 12px;\\n        border-bottom: 2px solid #e8f0e4;\\n    }\\n    .card-icon {\\n        width: 42px;\\n        height: 42px;\\n        border-radius: 12px;\\n        display: flex;\\n        align-items: center;\\n        justify-content: center;\\n        font-size: 20px;\\n        color: white;\\n    }\\n    .icon-why { background: linear-gradient(135deg, #4e874c, #6ba068); }\\n    .icon-malloc { background: linear-gradient(135deg, #3f6e48, #5a8b54); }\\n    .icon-free { background: linear-gradient(135deg, #78a06f, #9ab48e); }\\n    .icon-example { background: linear-gradient(135deg, #c9d97c, #dbead3); }\\n    .card-title {\\n        font-size: 20px;\\n        font-weight: 900;\\n        color: #48724a;\\n        flex: 1;\\n    }\\n    .card-content {\\n        flex: 1;\\n        font-size: 15px;\\n        line-height: 1.6;\\n        color: #5a7a55;\\n    }\\n    .card-content ul {\\n        list-style: none;\\n        padding-left: 0;\\n    }\\n    .card-content li {\\n        margin-bottom: 10px;\\n        padding-left: 24px;\\n        position: relative;\\n    }\\n    .card-content li:before {\\n        content: \\\"\\u2022\\\";\\n        position: absolute;\\n        left: 0;\\n        color: #7da965;\\n        font-size: 20px;\\n    }\\n    .memory-visualization {\\n        display: flex;\\n        align-items: center;\\n        justify-content: space-between;\\n        margin-top: 15px;\\n        padding: 15px;\\n        background: #f8fbf6;\\n        border-radius: 12px;\\n        border: 1px dashed #c6d6bf;\\n    }\\n    .memory-block {\\n        width: 70px;\\n        height: 70px;\\n        border-radius: 10px;\\n        display: flex;\\n        align-items: center;\\n        justify-content: center;\\n        font-weight: 900;\\n        font-size: 14px;\\n        color: white;\\n        transition: all 0.5s ease;\\n        position: relative;\\n    }\\n    .static-memory {\\n        background: #a8b8a8;\\n        box-shadow: 0 4px 8px rgba(168, 184, 168, 0.3);\\n    }\\n    .dynamic-memory {\\n        background: #4e874c;\\n        box-shadow: 0 4px 12px rgba(78, 135, 76, 0.4);\\n    }\\n    .memory-label {\\n        font-size: 12px;\\n        color: #7e8e7f;\\n        text-align: center;\\n        margin-top: 8px;\\n    }\\n    .arrow {\\n        font-size: 24px;\\n        color: #7da965;\\n        margin: 0 10px;\\n    }\\n    .code-container {\\n        background: #2d2d2d;\\n        border-radius: 12px;\\n        overflow: hidden;\\n        margin-top: 15px;\\n        flex: 1;\\n    }\\n    .code-header {\\n        background: #3c3c3c;\\n        padding: 10px 15px;\\n        display: flex;\\n        justify-content: space-between;\\n        align-items: center;\\n    }\\n    .code-title {\\n        color: #e0e0e0;\\n        font-size: 14px;\\n        font-weight: 600;\\n    }\\n    .code-copy {\\n        color: #7da965;\\n        font-size: 12px;\\n        cursor: pointer;\\n    }\\n    .code-content {\\n        padding: 15px;\\n        font-family: \'Consolas\', \'Monaco\', monospace;\\n        font-size: 14px;\\n        line-height: 1.5;\\n        color: #f8f8f2;\\n        overflow: auto;\\n        max-height: 200px;\\n    }\\n    .warning-box {\\n        background: #fff8e6;\\n        border-left: 5px solid #ffb74d;\\n        padding: 15px;\\n        border-radius: 8px;\\n        margin-top: 15px;\\n    }\\n    .warning-title {\\n        color: #ff9800;\\n        font-weight: 900;\\n        font-size: 16px;\\n        margin-bottom: 8px;\\n        display: flex;\\n        align-items: center;\\n        gap: 8px;\\n    }\\n    .warning-content {\\n        color: #8a6d3b;\\n        font-size: 14px;\\n        line-height: 1.5;\\n    }\\n    .function-demo {\\n        display: flex;\\n        align-items: center;\\n        justify-content: space-around;\\n        margin-top: 15px;\\n        padding: 15px;\\n        background: #f0f7ed;\\n        border-radius: 12px;\\n    }\\n    .func-card {\\n        display: flex;\\n        flex-direction: column;\\n        align-items: center;\\n        text-align: center;\\n        width: 45%;\\n    }\\n    .func-icon {\\n        width: 60px;\\n        height: 60px;\\n        border-radius: 50%;\\n        display: flex;\\n        align-items: center;\\n        justify-content: center;\\n        font-size: 24px;\\n        color: white;\\n        margin-bottom: 10px;\\n    }\\n    .malloc-icon { background: #4e874c; }\\n    .free-icon { background: #c9d97c; color: #5a7a55; }\\n    .func-name {\\n        font-weight: 900;\\n        font-size: 18px;\\n        color: #48724a;\\n        margin-bottom: 5px;\\n    }\\n    .func-desc {\\n        font-size: 13px;\\n        color: #7e8e7f;\\n        line-height: 1.4;\\n    }\\n    .pair-arrow {\\n        font-size: 28px;\\n        color: #7da965;\\n        margin: 0 10px;\\n    }\\n    .lifecycle-chart {\\n        flex: 1;\\n        display: flex;\\n        align-items: center;\\n        justify-content: center;\\n        margin-top: 15px;\\n    }\\n    .lifecycle-steps {\\n        display: flex;\\n        align-items: center;\\n        justify-content: space-between;\\n        width: 100%;\\n    }\\n    .step {\\n        display: flex;\\n        flex-direction: column;\\n        align-items: center;\\n        text-align: center;\\n        width: 30%;\\n    }\\n    .step-circle {\\n        width: 70px;\\n        height: 70px;\\n        border-radius: 50%;\\n        display: flex;\\n        align-items: center;\\n        justify-content: center;\\n        font-size: 24px;\\n        color: white;\\n        margin-bottom: 10px;\\n        box-shadow: 0 6px 12px rgba(0,0,0,0.1);\\n    }\\n    .step-1 { background: #4e874c; }\\n    .step-2 { background: #78a06f; }\\n    .step-3 { background: #c9d97c; color: #5a7a55; }\\n    .step-label {\\n        font-weight: 700;\\n        color: #48724a;\\n        font-size: 15px;\\n    }\\n    .step-desc {\\n        font-size: 12px;\\n        color: #7e8e7f;\\n        margin-top: 5px;\\n    }\\n    .step-arrow {\\n        font-size: 24px;\\n        color: #7da965;\\n        margin: 0 5px;\\n    }\\n    /* \\u9875\\u811a - \\u4e25\\u683c\\u4fdd\\u6301\\u539f\\u6837 */\\n    .footer {\\n        position: absolute;\\n        left: 30px;\\n        right: 30px;\\n        bottom: 24px;\\n        display: flex;\\n        justify-content: space-between;\\n        align-items: center;\\n        z-index: 30;\\n    }\\n    .footer-left {\\n        font-size: 12px;\\n        color: #7e8e7f;\\n    }\\n    .footer-right {\\n        font-size: 14px;\\n        color: #5f7860;\\n        font-weight: 700;\\n    }\\n    .page-number {\\n        background: rgba(255,255,255,.92);\\n        border: 1px solid rgba(90,121,80,.18);\\n        border-radius: 999px;\\n        padding: 6px 14px;\\n    }\\n    /* \\u88c5\\u9970\\u5143\\u7d20 */\\n    .decoration {\\n        position: absolute;\\n        z-index: 1;\\n    }\\n    .decoration-1 {\\n        width: 120px;\\n        height: 120px;\\n        background: rgba(126, 174, 101, 0.08);\\n        border-radius: 50%;\\n        top: 120px;\\n        right: 80px;\\n    }\\n    .decoration-2 {\\n        width: 80px;\\n        height: 80px;\\n        background: rgba(201, 217, 124, 0.1);\\n        border-radius: 50%;\\n        bottom: 100px;\\n        left: 100px;\\n    }\\n    .decoration-3 {\\n        width: 60px;\\n        height: 60px;\\n        background: rgba(78, 135, 76, 0.05);\\n        border-radius: 50%;\\n        top: 200px;\\n        left: 150px;\\n    }\\n    /* \\u54cd\\u5e94\\u5f0f\\u8c03\\u6574 */\\n    @media (max-width: 1350px) {\\n        .content-grid {\\n            gap: 15px;\\n        }\\n        .card-content {\\n            font-size: 14px;\\n        }\\n        .card-title {\\n            font-size: 18px;\\n        }\\n    }\\n</style>\\n</head>\\n<body>\\n<div class=\\\"slide-container\\\">\\n    <div class=\\\"slide\\\">\\n        <!-- \\u9875\\u7709 - \\u4e25\\u683c\\u4fdd\\u6301\\u539f\\u6837 -->\\n        <div class=\\\"header\\\">\\n            <div>\\n                <h1>\\u98df\\u54c1\\u836f\\u54c1\\u804c\\u4e1a\\u5b66\\u9662 PPT \\u6a21\\u677f\\u63cf\\u8ff0\\u6587\\u4ef6\\uff08\\u5b57\\u6bb5\\u89c4\\u8303\\u7248\\uff09</h1>\\n                <p>\\u53c2\\u7167 template.html \\u7684\\\"\\u5355\\u6587\\u4ef6\\u3001\\u81ea\\u5305\\u542b\\u3001\\u56fa\\u5b9a 1280\\u00d7720\\u3001\\u54cd\\u5e94\\u5f0f\\u7f29\\u653e\\u3001\\u5360\\u4f4d\\u7b26\\u4e0e\\u89c4\\u5219\\u8bf4\\u660e\\\"\\u5199\\u6cd5\\uff0c\\u5728 v3 \\u7684\\u5b50\\u7248\\u5f0f\\u62c6\\u5206\\u57fa\\u7840\\u4e0a\\uff0c\\u7ee7\\u7eed\\u628a\\u5b57\\u6bb5\\u547d\\u540d\\u3001\\u9009\\u578b\\u89c4\\u5219\\u3001\\u7981\\u7528\\u573a\\u666f\\u548c\\u6bcd\\u7248\\u7ea6\\u675f\\u6807\\u51c6\\u5316\\uff0c\\u65b9\\u4fbf\\u540e\\u7eed\\u76f4\\u63a5\\u62ff\\u6765\\u751f\\u6210\\u65b0\\u7684 PPT\\u3002</p>\\n            </div>\\n            <div class=\\\"main-tabs\\\">\\n                <button class=\\\"main-tab\\\">\\u5c01\\u9762\\u7cfb\\u7edf</button>\\n                <button class=\\\"main-tab\\\">\\u76ee\\u5f55\\u7cfb\\u7edf</button>\\n                <button class=\\\"main-tab active\\\">\\u5185\\u5bb9\\u7cfb\\u7edf</button>\\n                <button class=\\\"main-tab\\\">\\u6570\\u636e\\u7cfb\\u7edf</button>\\n            </div>\\n        </div>\\n        <!-- \\u88c5\\u9970\\u5143\\u7d20 -->\\n        <div class=\\\"decoration decoration-1\\\"></div>\\n        <div class=\\\"decoration decoration-2\\\"></div>\\n        <div class=\\\"decoration decoration-3\\\"></div>\\n        <!-- \\u4e3b\\u8981\\u5185\\u5bb9\\u533a\\u57df - \\u521b\\u610f\\u8bbe\\u8ba1\\u90e8\\u5206 -->\\n        <div class=\\\"content-area\\\">\\n            <div class=\\\"page-title\\\">\\u52a8\\u6001\\u5185\\u5b58\\u7ba1\\u7406\\uff1amalloc\\u4e0efree</div>\\n            <div class=\\\"content-grid\\\">\\n                <!-- \\u5de6\\u5217 -->\\n                <div class=\\\"left-column\\\">\\n                    <!-- \\u4e3a\\u4ec0\\u4e48\\u9700\\u8981\\u52a8\\u6001\\u5185\\u5b58\\u5206\\u914d\\uff1f -->\\n                    <div class=\\\"content-card\\\">\\n                        <div class=\\\"card-header\\\">\\n                            <div class=\\\"card-icon icon-why\\\">\\n                                <i class=\\\"fas fa-question-circle\\\"></i>\\n                            </div>\\n                            <div class=\\\"card-title\\\">\\u4e3a\\u4ec0\\u4e48\\u9700\\u8981\\u52a8\\u6001\\u5185\\u5b58\\u5206\\u914d\\uff1f</div>\\n                        </div>\\n                        <div class=\\\"card-content\\\">\\n                            <ul>\\n                                <li>\\u9759\\u6001\\u5185\\u5b58\\u5206\\u914d\\u5728\\u7f16\\u8bd1\\u65f6\\u786e\\u5b9a\\u5927\\u5c0f\\uff0c\\u65e0\\u6cd5\\u9002\\u5e94\\u8fd0\\u884c\\u65f6\\u9700\\u6c42\\u53d8\\u5316</li>\\n                                <li>\\u52a8\\u6001\\u5185\\u5b58\\u5141\\u8bb8\\u7a0b\\u5e8f\\u5728\\u8fd0\\u884c\\u65f6\\u7533\\u8bf7\\u6240\\u9700\\u5185\\u5b58\\uff0c\\u63d0\\u9ad8\\u7075\\u6d3b\\u6027</li>\\n                                <li>\\u9002\\u7528\\u4e8e\\u6570\\u636e\\u7ed3\\u6784\\u5927\\u5c0f\\u672a\\u77e5\\u6216\\u53d8\\u5316\\u7684\\u60c5\\u51b5</li>\\n                            </ul>\\n                            <div class=\\\"memory-visualization\\\">\\n                                <div>\\n                                    <div class=\\\"memory-block static-memory\\\">\\u56fa\\u5b9a</div>\\n                                    <div class=\\\"memory-label\\\">\\u9759\\u6001\\u5206\\u914d</div>\\n                                </div>\\n                                <div class=\\\"arrow\\\"><i class=\\\"fas fa-arrow-right\\\"></i></div>\\n                                <div>\\n                                    <div class=\\\"memory-block dynamic-memory\\\">\\u7075\\u6d3b</div>\\n                                    <div class=\\\"memory-label\\\">\\u52a8\\u6001\\u5206\\u914d</div>\\n                                </div>\\n                            </div>\\n                        </div>\\n                    </div>\\n                    <!-- malloc\\u51fd\\u6570\\uff1a\\u7533\\u8bf7\\u6307\\u5b9a\\u5b57\\u8282\\u6570\\u7684\\u5185\\u5b58 -->\\n                    <div class=\\\"content-card\\\">\\n                        <div class=\\\"card-header\\\">\\n                            <div class=\\\"card-icon icon-malloc\\\">\\n                                <i class=\\\"fas fa-plus-circle\\\"></i>\\n                            </div>\\n                            <div class=\\\"card-title\\\">malloc\\u51fd\\u6570\\uff1a\\u7533\\u8bf7\\u5185\\u5b58</div>\\n                        </div>\\n                        <div class=\\\"card-content\\\">\\n                            <p\", \"is_user_edited\": false}, {\"page_number\": 6, \"title\": \"\\u52a8\\u6001\\u5185\\u5b58\\u7ba1\\u7406\\uff1acalloc\\u4e0erealloc\", \"html_content\": \"<!DOCTYPE html>\\n<html lang=\\\"zh-CN\\\">\\n<head>\\n<meta charset=\\\"UTF-8\\\" />\\n<meta name=\\\"viewport\\\" content=\\\"width=device-width, initial-scale=1.0\\\" />\\n<title>\\u52a8\\u6001\\u5185\\u5b58\\u7ba1\\u7406\\uff1acalloc\\u4e0erealloc</title>\\n<link rel=\\\"stylesheet\\\" href=\\\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css\\\">\\n<link rel=\\\"stylesheet\\\" href=\\\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/themes/prism-tomorrow.min.css\\\">\\n<script src=\\\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/prism.min.js\\\"></script>\\n<script src=\\\"https://cdn.jsdelivr.net/npm/chart.js\\\"></script>\\n<style>\\n    * { margin: 0; padding: 0; box-sizing: border-box; }\\n    html, body {\\n        width: 100%;\\n        height: 100%;\\n        overflow: hidden;\\n        background: #edf1eb;\\n        font-family: \\\"Microsoft YaHei\\\", \\\"PingFang SC\\\", \\\"Noto Sans SC\\\", sans-serif;\\n        color: #335239;\\n    }\\n    .slide-container {\\n        width: 100vw;\\n        height: 100vh;\\n        display: flex;\\n        align-items: center;\\n        justify-content: center;\\n    }\\n    .slide {\\n        width: 1280px;\\n        height: 720px;\\n        position: relative;\\n        overflow: hidden;\\n        transform-origin: center center;\\n        border-radius: 16px;\\n        background: linear-gradient(180deg, #f8faf6 0%, #f2f5ef 100%);\\n        box-shadow: 0 18px 42px rgba(0,0,0,.14);\\n    }\\n    /* \\u9875\\u7709 - \\u4e25\\u683c\\u4fdd\\u6301\\u539f\\u6837 */\\n    .header {\\n        position: absolute;\\n        left: 30px;\\n        right: 30px;\\n        top: 24px;\\n        display: grid;\\n        grid-template-columns: 1fr auto;\\n        gap: 20px;\\n        align-items: start;\\n        z-index: 30;\\n    }\\n    .header h1 {\\n        font-size: 28px;\\n        line-height: 1.2;\\n        color: #48724a;\\n        font-weight: 900;\\n        letter-spacing: .4px;\\n    }\\n    .header p {\\n        margin-top: 7px;\\n        font-size: 12px;\\n        color: #7e8e7f;\\n        line-height: 1.55;\\n        max-width: 650px;\\n    }\\n    .main-tabs {\\n        display: flex;\\n        gap: 10px;\\n        align-items: center;\\n        flex-wrap: wrap;\\n        justify-content: flex-end;\\n    }\\n    .main-tab {\\n        border: 1px solid rgba(90,121,80,.18);\\n        background: rgba(255,255,255,.92);\\n        color: #5f7860;\\n        border-radius: 999px;\\n        padding: 9px 16px;\\n        font-size: 14px;\\n        font-weight: 800;\\n        cursor: pointer;\\n        transition: all .18s ease;\\n    }\\n    .main-tab.active {\\n        background: #4e7b47;\\n        color: #fff;\\n        box-shadow: 0 8px 18px rgba(78,123,71,.28);\\n    }\\n    /* \\u4e3b\\u8981\\u5185\\u5bb9\\u533a\\u57df - \\u521b\\u610f\\u8bbe\\u8ba1\\u90e8\\u5206 */\\n    .content-area {\\n        position: absolute;\\n        left: 30px;\\n        right: 30px;\\n        top: 98px;\\n        bottom: 60px;\\n        display: flex;\\n        flex-direction: column;\\n        gap: 20px;\\n    }\\n    .page-title {\\n        color: #4e7b47;\\n        font-size: 32px;\\n        font-weight: 900;\\n        text-align: center;\\n        margin-bottom: 10px;\\n        position: relative;\\n        padding-bottom: 12px;\\n    }\\n    .page-title::after {\\n        content: \'\';\\n        position: absolute;\\n        bottom: 0;\\n        left: 50%;\\n        transform: translateX(-50%);\\n        width: 120px;\\n        height: 4px;\\n        background: linear-gradient(90deg, transparent, #7da965, transparent);\\n        border-radius: 2px;\\n    }\\n    .main-content {\\n        flex: 1;\\n        display: grid;\\n        grid-template-columns: 1fr 1fr;\\n        gap: 24px;\\n        height: calc(100% - 60px);\\n    }\\n    .function-card {\\n        background: rgba(255, 255, 255, 0.92);\\n        border-radius: 20px;\\n        padding: 24px;\\n        box-shadow: 0 10px 30px rgba(78, 123, 71, 0.08);\\n        border: 1px solid rgba(87, 124, 79, 0.15);\\n        display: flex;\\n        flex-direction: column;\\n        transition: transform 0.3s ease, box-shadow 0.3s ease;\\n    }\\n    .function-card:hover {\\n        transform: translateY(-5px);\\n        box-shadow: 0 15px 40px rgba(78, 123, 71, 0.15);\\n    }\\n    .card-header {\\n        display: flex;\\n        align-items: center;\\n        margin-bottom: 20px;\\n        padding-bottom: 15px;\\n        border-bottom: 2px solid #e8f0e5;\\n    }\\n    .function-icon {\\n        width: 60px;\\n        height: 60px;\\n        border-radius: 50%;\\n        display: flex;\\n        align-items: center;\\n        justify-content: center;\\n        margin-right: 18px;\\n        font-size: 24px;\\n        color: white;\\n        flex-shrink: 0;\\n    }\\n    .calloc-icon {\\n        background: linear-gradient(135deg, #1abc9c, #16a085);\\n    }\\n    .realloc-icon {\\n        background: linear-gradient(135deg, #f39c12, #e67e22);\\n    }\\n    .function-title {\\n        font-size: 24px;\\n        font-weight: 900;\\n        color: #2c3e50;\\n        margin-bottom: 5px;\\n    }\\n    .function-subtitle {\\n        font-size: 14px;\\n        color: #7f8c8d;\\n        font-weight: 500;\\n    }\\n    .function-details {\\n        flex: 1;\\n        display: flex;\\n        flex-direction: column;\\n        gap: 16px;\\n    }\\n    .detail-item {\\n        display: flex;\\n        align-items: flex-start;\\n        margin-bottom: 8px;\\n    }\\n    .detail-label {\\n        font-weight: 700;\\n        color: #48724a;\\n        min-width: 80px;\\n        font-size: 15px;\\n    }\\n    .detail-content {\\n        flex: 1;\\n        color: #335239;\\n        line-height: 1.5;\\n        font-size: 15px;\\n    }\\n    .code-block {\\n        background: #2c3e50;\\n        border-radius: 12px;\\n        padding: 16px;\\n        margin-top: 10px;\\n        overflow-x: auto;\\n    }\\n    .code-block pre {\\n        margin: 0;\\n        font-family: \'Consolas\', \'Monaco\', monospace;\\n        font-size: 14px;\\n        color: #ecf0f1;\\n        line-height: 1.4;\\n    }\\n    .memory-visualization {\\n        height: 120px;\\n        background: #f8f9fa;\\n        border-radius: 12px;\\n        margin-top: 15px;\\n        padding: 12px;\\n        border: 1px dashed #bdc3c7;\\n        display: flex;\\n        align-items: center;\\n        justify-content: center;\\n        position: relative;\\n    }\\n    .memory-block {\\n        width: 40px;\\n        height: 40px;\\n        border-radius: 6px;\\n        margin: 0 5px;\\n        display: flex;\\n        align-items: center;\\n        justify-content: center;\\n        font-weight: 700;\\n        font-size: 12px;\\n        color: white;\\n        transition: all 0.3s ease;\\n    }\\n    .memory-block.zero {\\n        background: #1abc9c;\\n    }\\n    .memory-block.data {\\n        background: #3498db;\\n    }\\n    .memory-block.new {\\n        background: #f39c12;\\n    }\\n    .memory-block.uninit {\\n        background: #bdc3c7;\\n        color: #7f8c8d;\\n    }\\n    .comparison-section {\\n        grid-column: 1 / span 2;\\n        background: rgba(255, 255, 255, 0.95);\\n        border-radius: 20px;\\n        padding: 24px;\\n        margin-top: 10px;\\n        box-shadow: 0 10px 30px rgba(78, 123, 71, 0.08);\\n        border: 1px solid rgba(87, 124, 79, 0.15);\\n    }\\n    .section-title {\\n        font-size: 22px;\\n        font-weight: 900;\\n        color: #4e7b47;\\n        margin-bottom: 20px;\\n        display: flex;\\n        align-items: center;\\n    }\\n    .section-title i {\\n        margin-right: 10px;\\n        color: #7da965;\\n    }\\n    .comparison-table {\\n        width: 100%;\\n        border-collapse: collapse;\\n        margin-top: 10px;\\n    }\\n    .comparison-table th {\\n        background: #f1f8e9;\\n        color: #48724a;\\n        font-weight: 900;\\n        padding: 16px 12px;\\n        text-align: center;\\n        border-bottom: 2px solid #c8e6c9;\\n        font-size: 16px;\\n    }\\n    .comparison-table td {\\n        padding: 14px 12px;\\n        text-align: center;\\n        border-bottom: 1px solid #e8f5e8;\\n        color: #335239;\\n        font-size: 15px;\\n    }\\n    .comparison-table tr:last-child td {\\n        border-bottom: none;\\n    }\\n    .comparison-table tr:hover {\\n        background: #f9fdf9;\\n    }\\n    .highlight-cell {\\n        background: #e8f5e8;\\n        font-weight: 700;\\n        color: #2e7d32;\\n    }\\n    .error-handling {\\n        grid-column: 1 / span 2;\\n        background: rgba(253, 237, 236, 0.9);\\n        border-radius: 20px;\\n        padding: 22px;\\n        margin-top: 10px;\\n        border-left: 6px solid #e74c3c;\\n        box-shadow: 0 8px 25px rgba(231, 76, 60, 0.1);\\n    }\\n    .error-title {\\n        font-size: 20px;\\n        font-weight: 900;\\n        color: #c0392b;\\n        margin-bottom: 15px;\\n        display: flex;\\n        align-items: center;\\n    }\\n    .error-title i {\\n        margin-right: 10px;\\n    }\\n    .error-steps {\\n        display: grid;\\n        grid-template-columns: repeat(4, 1fr);\\n        gap: 16px;\\n        margin-top: 10px;\\n    }\\n    .error-step {\\n        background: white;\\n        border-radius: 12px;\\n        padding: 16px;\\n        text-align: center;\\n        box-shadow: 0 5px 15px rgba(0,0,0,0.05);\\n        transition: transform 0.3s ease;\\n    }\\n    .error-step:hover {\\n        transform: translateY(-5px);\\n    }\\n    .step-number {\\n        width: 36px;\\n        height: 36px;\\n        background: #e74c3c;\\n        color: white;\\n        border-radius: 50%;\\n        display: flex;\\n        align-items: center;\\n        justify-content: center;\\n        font-weight: 900;\\n        margin: 0 auto 12px;\\n        font-size: 18px;\\n    }\\n    .step-title {\\n        font-weight: 700;\\n        color: #c0392b;\\n        margin-bottom: 8px;\\n        font-size: 16px;\\n    }\\n    .step-desc {\\n        color: #7f8c8d;\\n        font-size: 14px;\\n        line-height: 1.4;\\n    }\\n    /* \\u9875\\u811a - \\u4e25\\u683c\\u4fdd\\u6301\\u539f\\u6837 */\\n    .footer {\\n        position: absolute;\\n        left: 30px;\\n        right: 30px;\\n        bottom: 20px;\\n        display: flex;\\n        justify-content: space-between;\\n        align-items: center;\\n        z-index: 30;\\n    }\\n    .footer .page-number {\\n        font-size: 14px;\\n        color: #7e8e7f;\\n        font-weight: 700;\\n    }\\n    .footer .decorative-line {\\n        flex: 1;\\n        height: 1px;\\n        background: linear-gradient(90deg, transparent, rgba(90,121,80,.2), transparent);\\n        margin: 0 20px;\\n    }\\n    .footer .slide-type {\\n        font-size: 12px;\\n        color: #7e8e7f;\\n        text-transform: uppercase;\\n        letter-spacing: 1px;\\n    }\\n    /* \\u88c5\\u9970\\u5143\\u7d20 */\\n    .decoration {\\n        position: absolute;\\n        z-index: 1;\\n    }\\n    .decoration.circle-1 {\\n        width: 120px;\\n        height: 120px;\\n        border-radius: 50%;\\n        background: rgba(141, 198, 63, 0.1);\\n        top: 120px;\\n        right: 80px;\\n    }\\n    .decoration.circle-2 {\\n        width: 80px;\\n        height: 80px;\\n        border-radius: 50%;\\n        background: rgba(77, 175, 124, 0.08);\\n        bottom: 150px;\\n        left: 60px;\\n    }\\n    .decoration.circle-3 {\\n        width: 60px;\\n        height: 60px;\\n        border-radius: 50%;\\n        background: rgba(52, 152, 219, 0.05);\\n        top: 200px;\\n        left: 100px;\\n    }\\n    /* \\u54cd\\u5e94\\u5f0f\\u8c03\\u6574 */\\n    @media (max-width: 1350px) {\\n        .slide {\\n            transform: scale(0.9);\\n        }\\n    }\\n</style>\\n</head>\\n<body>\\n<div class=\\\"slide-container\\\">\\n    <div class=\\\"slide\\\">\\n        <!-- \\u9875\\u7709 - \\u4e25\\u683c\\u4fdd\\u6301\\u539f\\u6837 -->\\n        <div class=\\\"header\\\">\\n            <div>\\n                <h1>\\u98df\\u54c1\\u836f\\u54c1\\u804c\\u4e1a\\u5b66\\u9662 PPT \\u6a21\\u677f\\u63cf\\u8ff0\\u6587\\u4ef6\\uff08\\u5b57\\u6bb5\\u89c4\\u8303\\u7248\\uff09</h1>\\n                <p>\\u53c2\\u7167 template.html \\u7684\\\"\\u5355\\u6587\\u4ef6\\u3001\\u81ea\\u5305\\u542b\\u3001\\u56fa\\u5b9a 1280\\u00d7720\\u3001\\u54cd\\u5e94\\u5f0f\\u7f29\\u653e\\u3001\\u5360\\u4f4d\\u7b26\\u4e0e\\u89c4\\u5219\\u8bf4\\u660e\\\"\\u5199\\u6cd5\\uff0c\\u5728 v3 \\u7684\\u5b50\\u7248\\u5f0f\\u62c6\\u5206\\u57fa\\u7840\\u4e0a\\uff0c\\u7ee7\\u7eed\\u628a\\u5b57\\u6bb5\\u547d\\u540d\\u3001\\u9009\\u578b\\u89c4\\u5219\\u3001\\u7981\\u7528\\u573a\\u666f\\u548c\\u6bcd\\u7248\\u7ea6\\u675f\\u6807\\u51c6\\u5316\\uff0c\\u65b9\\u4fbf\\u540e\\u7eed\\u76f4\\u63a5\\u62ff\\u6765\\u751f\\u6210\\u65b0\\u7684 PPT\\u3002</p>\\n            </div>\\n            <div class=\\\"main-tabs\\\">\\n                <button class=\\\"main-tab\\\">\\u5c01\\u9762\\u7cfb\\u7edf</button>\\n                <button class=\\\"main-tab\\\">\\u76ee\\u5f55\\u7cfb\\u7edf</button>\\n                <button class=\\\"main-tab active\\\">\\u5185\\u5bb9\\u7cfb\\u7edf</button>\\n                <button class=\\\"main-tab\\\">\\u6570\\u636e\\u7cfb\\u7edf</button>\\n            </div>\\n        </div>\\n        <!-- \\u4e3b\\u8981\\u5185\\u5bb9\\u533a\\u57df - \\u521b\\u610f\\u8bbe\\u8ba1\\u90e8\\u5206 -->\\n        <div class=\\\"content-area\\\">\\n            <h2 class=\\\"page-title\\\">\\u52a8\\u6001