age-c\\\">// calloc \\u4f7f\\u7528\\u793a\\u4f8b\\nint *scores = (int*)calloc(5, sizeof(int));\\n                        </div>\\n                        <div class=\\\"memory-visualization\\\">\\n                            <div class=\\\"memory-block zero\\\">0</div>\\n                            <div class=\\\"memory-block zero\\\">0</div>\\n                            <div class=\\\"memory-block zero\\\">0</div>\\n                            <div class=\\\"memory-block zero\\\">0</div>\\n                            <div class=\\\"memory-block zero\\\">0</div>\\n                            <div style=\\\"margin-left: 20px; color: #7f8c8d; font-size: 14px;\\\">\\n                                <i class=\\\"fas fa-arrow-right\\\"></i> calloc\\u5206\\u914d\\u7684\\u5185\\u5b58\\u5168\\u90e8\\u521d\\u59cb\\u5316\\u4e3a0\\n                            </div>\\n                        </div>\\n                    </div>\\n                </div>\\n                <!-- Realloc \\u51fd\\u6570\\u5361\\u7247 -->\\n                <div class=\\\"function-card\\\">\\n                    <div class=\\\"card-header\\\">\\n                        <div class=\\\"function-icon realloc-icon\\\">\\n                            <i class=\\\"fas fa-expand-alt\\\"></i>\\n                        </div>\\n                        <div>\\n                            <h3 class=\\\"function-title\\\">realloc \\u51fd\\u6570</h3>\\n                            <p class=\\\"function-subtitle\\\">\\u8c03\\u6574\\u5df2\\u5206\\u914d\\u5185\\u5b58\\u7684\\u5927\\u5c0f</p>\\n                        </div>\\n                    </div>\\n                    <div class=\\\"function-details\\\">\\n                        <div\", \"is_user_edited\": false}, {\"page_number\": 7, \"title\": \"\\u5e38\\u89c1\\u5185\\u5b58\\u9519\\u8bef\\u4e0e\\u8c03\\u8bd5\", \"html_content\": \"<!DOCTYPE html>\\n<html lang=\\\"zh-CN\\\">\\n<head>\\n<meta charset=\\\"UTF-8\\\" />\\n<meta name=\\\"viewport\\\" content=\\\"width=device-width, initial-scale=1.0\\\" />\\n<title>\\u5e38\\u89c1\\u5185\\u5b58\\u9519\\u8bef\\u4e0e\\u8c03\\u8bd5 - C\\u8bed\\u8a00\\u7b2c\\u56db\\u6b21\\u8bfe</title>\\n<link rel=\\\"stylesheet\\\" href=\\\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css\\\">\\n<script src=\\\"https://cdn.jsdelivr.net/npm/chart.js\\\"></script>\\n<style>\\n    * { margin: 0; padding: 0; box-sizing: border-box; }\\n    html, body {\\n        width: 100%;\\n        height: 100%;\\n        overflow: hidden;\\n        background: #edf1eb;\\n        font-family: \\\"Microsoft YaHei\\\", \\\"PingFang SC\\\", \\\"Noto Sans SC\\\", sans-serif;\\n        color: #335239;\\n    }\\n    .slide-container {\\n        width: 100vw;\\n        height: 100vh;\\n        display: flex;\\n        align-items: center;\\n        justify-content: center;\\n    }\\n    .slide {\\n        width: 1280px;\\n        height: 720px;\\n        position: relative;\\n        overflow: hidden;\\n        transform-origin: center center;\\n        border-radius: 16px;\\n        background: linear-gradient(180deg, #f8faf6 0%, #f2f5ef 100%);\\n        box-shadow: 0 18px 42px rgba(0,0,0,.14);\\n    }\\n\\n    /* \\u9875\\u7709 - \\u4e25\\u683c\\u4fdd\\u6301\\u539f\\u6837 */\\n    .header {\\n        position: absolute;\\n        left: 30px;\\n        right: 30px;\\n        top: 24px;\\n        display: grid;\\n        grid-template-columns: 1fr auto;\\n        gap: 20px;\\n        align-items: start;\\n        z-index: 30;\\n    }\\n    .header h1 {\\n        font-size: 28px;\\n        line-height: 1.2;\\n        color: #48724a;\\n        font-weight: 900;\\n        letter-spacing: .4px;\\n    }\\n    .header p {\\n        margin-top: 7px;\\n        font-size: 12px;\\n        color: #7e8e7f;\\n        line-height: 1.55;\\n        max-width: 650px;\\n    }\\n\\n    .main-tabs {\\n        display: flex;\\n        gap: 10px;\\n        align-items: center;\\n        flex-wrap: wrap;\\n        justify-content: flex-end;\\n    }\\n    .main-tab {\\n        border: 1px solid rgba(90,121,80,.18);\\n        background: rgba(255,255,255,.92);\\n        color: #5f7860;\\n        border-radius: 999px;\\n        padding: 9px 16px;\\n        font-size: 14px;\\n        font-weight: 800;\\n        cursor: pointer;\\n        transition: all .18s ease;\\n    }\\n    .main-tab.active {\\n        background: #4e7b47;\\n        color: #fff;\\n        box-shadow: 0 8px 18px rgba(78,123,71,.28);\\n    }\\n\\n    /* \\u4e3b\\u8981\\u5185\\u5bb9\\u533a\\u57df - \\u521b\\u610f\\u8bbe\\u8ba1\\u90e8\\u5206 */\\n    .content-area {\\n        position: absolute;\\n        left: 28px;\\n        right: 28px;\\n        top: 98px;\\n        bottom: 26px;\\n        display: flex;\\n        flex-direction: column;\\n        padding: 20px 0;\\n    }\\n\\n    .page-title {\\n        text-align: center;\\n        margin-bottom: 30px;\\n        position: relative;\\n    }\\n    .page-title h2 {\\n        font-size: 36px;\\n        color: #4a7b43;\\n        font-weight: 900;\\n        margin-bottom: 8px;\\n        letter-spacing: 1px;\\n    }\\n    .page-title .subtitle {\\n        font-size: 16px;\\n        color: #7e8e7f;\\n        font-weight: 500;\\n    }\\n    .title-decoration {\\n        position: absolute;\\n        bottom: -10px;\\n        left: 50%;\\n        transform: translateX(-50%);\\n        width: 120px;\\n        height: 4px;\\n        background: linear-gradient(90deg, transparent, #7da965, transparent);\\n        border-radius: 2px;\\n    }\\n\\n    /* \\u5185\\u5b58\\u9519\\u8bef\\u7f51\\u683c\\u5e03\\u5c40 */\\n    .errors-grid {\\n        flex: 1;\\n        display: grid;\\n        grid-template-columns: repeat(3, 1fr);\\n        grid-template-rows: repeat(2, 1fr);\\n        gap: 24px;\\n        padding: 0 20px;\\n        margin-bottom: 20px;\\n    }\\n\\n    .error-card {\\n        background: rgba(255, 255, 255, 0.95);\\n        border-radius: 20px;\\n        padding: 24px;\\n        display: flex;\\n        flex-direction: column;\\n        align-items: center;\\n        justify-content: center;\\n        text-align: center;\\n        box-shadow: 0 10px 25px rgba(0, 0, 0, 0.05);\\n        border: 1px solid rgba(135, 169, 127, 0.15);\\n        transition: all 0.3s ease;\\n        position: relative;\\n        overflow: hidden;\\n    }\\n    .error-card:hover {\\n        transform: translateY(-5px);\\n        box-shadow: 0 15px 30px rgba(0, 0, 0, 0.1);\\n    }\\n\\n    .error-icon {\\n        width: 80px;\\n        height: 80px;\\n        border-radius: 50%;\\n        display: flex;\\n        align-items: center;\\n        justify-content: center;\\n        margin-bottom: 18px;\\n        font-size: 32px;\\n        color: white;\\n        position: relative;\\n    }\\n\\n    .error-name {\\n        font-size: 20px;\\n        font-weight: 900;\\n        color: #335239;\\n        margin-bottom: 6px;\\n    }\\n    .error-en {\\n        font-size: 14px;\\n        color: #7e8e7f;\\n        font-weight: 600;\\n        margin-bottom: 12px;\\n        letter-spacing: 0.5px;\\n    }\\n    .error-desc {\\n        font-size: 13px;\\n        color: #607163;\\n        line-height: 1.5;\\n        max-width: 90%;\\n    }\\n\\n    /* \\u7279\\u5b9a\\u9519\\u8bef\\u5361\\u7247\\u6837\\u5f0f */\\n    .leak .error-icon {\\n        background: linear-gradient(135deg, #E67E22, #F39C12);\\n        box-shadow: 0 8px 20px rgba(230, 126, 34, 0.3);\\n    }\\n    .dangling .error-icon {\\n        background: linear-gradient(135deg, #C0392B, #E74C3C);\\n        box-shadow: 0 8px 20px rgba(192, 57, 43, 0.3);\\n    }\\n    .double .error-icon {\\n        background: linear-gradient(135deg, #8E44AD, #9B59B6);\\n        box-shadow: 0 8px 20px rgba(142, 68, 173, 0.3);\\n    }\\n    .bounds .error-icon {\\n        background: linear-gradient(135deg, #D35400, #E67E22);\\n        box-shadow: 0 8px 20px rgba(211, 84, 0, 0.3);\\n    }\\n\\n    /* \\u5de5\\u5177\\u5361\\u7247\\u7279\\u6b8a\\u6837\\u5f0f */\\n    .tool-card {\\n        grid-column: span 1;\\n        background: linear-gradient(135deg, #27AE60, #2ECC71);\\n        color: white;\\n        border: none;\\n    }\\n    .tool-card .error-icon {\\n        background: rgba(255, 255, 255, 0.2);\\n        border: 3px solid rgba(255, 255, 255, 0.3);\\n    }\\n    .tool-card .error-name,\\n    .tool-card .error-en,\\n    .tool-card .error-desc {\\n        color: white;\\n    }\\n    .tool-card .error-desc {\\n        opacity: 0.9;\\n    }\\n\\n    /* \\u5de5\\u5177\\u533a\\u57df */\\n    .tool-section {\\n        background: linear-gradient(90deg, #f7faf4, #f2f7ef);\\n        border-radius: 20px;\\n        padding: 25px 30px;\\n        margin: 0 20px;\\n        border: 1px solid #e3ece0;\\n        display: flex;\\n        align-items: center;\\n        justify-content: space-between;\\n        box-shadow: 0 8px 20px rgba(0, 0, 0, 0.05);\\n    }\\n    .tool-info {\\n        flex: 1;\\n    }\\n    .tool-title {\\n        font-size: 22px;\\n        color: #4a7b43;\\n        font-weight: 900;\\n        margin-bottom: 8px;\\n        display: flex;\\n        align-items: center;\\n        gap: 10px;\\n    }\\n    .tool-title i {\\n        color: #27AE60;\\n    }\\n    .tool-desc {\\n        font-size: 15px;\\n        color: #607163;\\n        line-height: 1.6;\\n        max-width: 80%;\\n    }\\n    .tool-visual {\\n        width: 180px;\\n        height: 120px;\\n        background: white;\\n        border-radius: 12px;\\n        display: flex;\\n        align-items: center;\\n        justify-content: center;\\n        border: 1px solid #e3ece0;\\n        position: relative;\\n        overflow: hidden;\\n    }\\n    .tool-visual::before {\\n        content: \\\"\\\";\\n        position: absolute;\\n        top: 0;\\n        left: 0;\\n        right: 0;\\n        height: 4px;\\n        background: linear-gradient(90deg, #27AE60, #2ECC71);\\n    }\\n    .code-snippet {\\n        font-family: \'Courier New\', monospace;\\n        font-size: 13px;\\n        color: #335239;\\n        text-align: left;\\n        padding: 10px;\\n    }\\n    .code-snippet .line {\\n        margin-bottom: 4px;\\n    }\\n    .code-snippet .comment {\\n        color: #7e8e7f;\\n    }\\n    .code-snippet .command {\\n        color: #27AE60;\\n        font-weight: bold;\\n    }\\n\\n    /* \\u88c5\\u9970\\u5143\\u7d20 */\\n    .decoration {\\n        position: absolute;\\n        z-index: -1;\\n    }\\n    .decoration.circle-1 {\\n        width: 120px;\\n        height: 120px;\\n        border-radius: 50%;\\n        background: rgba(125, 169, 101, 0.08);\\n        top: 120px;\\n        left: 50px;\\n    }\\n    .decoration.circle-2 {\\n        width: 80px;\\n        height: 80px;\\n        border-radius: 50%;\\n        background: rgba(78, 123, 71, 0.05);\\n        bottom: 100px;\\n        right: 60px;\\n    }\\n    .decoration.line-1 {\\n        width: 100%;\\n        height: 1px;\\n        background: linear-gradient(90deg, transparent, rgba(125, 169, 101, 0.2), transparent);\\n        top: 180px;\\n        left: 0;\\n    }\\n\\n    /* \\u9875\\u811a - \\u4e25\\u683c\\u4fdd\\u6301\\u539f\\u6837 */\\n    .footer {\\n        position: absolute;\\n        bottom: 16px;\\n        left: 0;\\n        right: 0;\\n        text-align: center;\\n        font-size: 14px;\\n        color: #7e8e7f;\\n        z-index: 30;\\n    }\\n    .page-number {\\n        display: inline-block;\\n        padding: 6px 16px;\\n        background: rgba(255, 255, 255, 0.9);\\n        border-radius: 999px;\\n        border: 1px solid rgba(90, 121, 80, 0.15);\\n        font-weight: 700;\\n    }\\n\\n    /* \\u54cd\\u5e94\\u5f0f\\u8c03\\u6574 */\\n    @media (max-width: 1350px) {\\n        .errors-grid {\\n            gap: 20px;\\n            padding: 0 15px;\\n        }\\n        .error-card {\\n            padding: 20px;\\n        }\\n    }\\n</style>\\n</head>\\n<body>\\n<div class=\\\"slide-container\\\">\\n    <div class=\\\"slide\\\">\\n        <!-- \\u9875\\u7709 - \\u4e25\\u683c\\u4fdd\\u6301\\u539f\\u6837 -->\\n        <div class=\\\"header\\\">\\n            <div>\\n                <h1>C\\u8bed\\u8a00\\u7b2c\\u56db\\u6b21\\u8bfe\\uff1a\\u5185\\u5b58\\u7ba1\\u7406</h1>\\n                <p>\\u6df1\\u5165\\u7406\\u89e3\\u5185\\u5b58\\u9519\\u8bef\\u7c7b\\u578b\\u4e0e\\u8c03\\u8bd5\\u65b9\\u6cd5\\uff0c\\u638c\\u63e1\\u5e38\\u89c1\\u95ee\\u9898\\u7684\\u8bc6\\u522b\\u4e0e\\u89e3\\u51b3\\u6280\\u5de7</p>\\n            </div>\\n            <div class=\\\"main-tabs\\\">\\n                <div class=\\\"main-tab active\\\">\\u5185\\u5bb9\\u9875</div>\\n                <div class=\\\"main-tab\\\">\\u77e5\\u8bc6\\u70b9</div>\\n                <div class=\\\"main-tab\\\">\\u6848\\u4f8b</div>\\n            </div>\\n        </div>\\n\\n        <!-- \\u4e3b\\u8981\\u5185\\u5bb9\\u533a\\u57df - \\u521b\\u610f\\u8bbe\\u8ba1\\u90e8\\u5206 -->\\n        <div class=\\\"content-area\\\">\\n            <!-- \\u9875\\u9762\\u6807\\u9898 -->\\n            <div class=\\\"page-title\\\">\\n                <h2>\\u5e38\\u89c1\\u5185\\u5b58\\u9519\\u8bef\\u4e0e\\u8c03\\u8bd5</h2>\\n                <div class=\\\"subtitle\\\">\\u8bc6\\u522b\\u3001\\u8bca\\u65ad\\u4e0e\\u89e3\\u51b3\\u5185\\u5b58\\u76f8\\u5173\\u95ee\\u9898\\u7684\\u7cfb\\u7edf\\u65b9\\u6cd5</div>\\n                <div class=\\\"title-decoration\\\"></div>\\n            </div>\\n\\n            <!-- \\u5185\\u5b58\\u9519\\u8bef\\u7f51\\u683c -->\\n            <div class=\\\"errors-grid\\\">\\n                <!-- \\u5185\\u5b58\\u6cc4\\u6f0f -->\\n                <div class=\\\"error-card leak\\\">\\n                    <div class=\\\"error-icon\\\">\\n                        <i class=\\\"fas fa-tint\\\"></i>\\n                    </div>\\n                    <div class=\\\"error-name\\\">\\u5185\\u5b58\\u6cc4\\u6f0f</div>\\n                    <div class=\\\"error-en\\\">Memory Leak</div>\\n                    <div class=\\\"error-desc\\\">\\u5df2\\u5206\\u914d\\u7684\\u5185\\u5b58\\u672a\\u80fd\\u91ca\\u653e\\uff0c\\u5bfc\\u81f4\\u8d44\\u6e90\\u9010\\u6e10\\u8017\\u5c3d</div>\\n                </div>\\n\\n                <!-- \\u91ce\\u6307\\u9488 -->\\n                <div class=\\\"error-card dangling\\\">\\n                    <div class=\\\"error-icon\\\">\\n                        <i class=\\\"fas fa-bullseye\\\"></i>\\n                    </div>\\n                    <div class=\\\"error-name\\\">\\u91ce\\u6307\\u9488</div>\\n                    <div class=\\\"error-en\\\">Dangling Pointer</div>\\n                    <div class=\\\"error-desc\\\">\\u6307\\u5411\\u5df2\\u91ca\\u653e\\u6216\\u65e0\\u6548\\u5185\\u5b58\\u533a\\u57df\\u7684\\u6307\\u9488</div>\\n                </div>\\n\\n                <!-- \\u91cd\\u590d\\u91ca\\u653e -->\\n                <div class=\\\"error-card double\\\">\\n                    <div class=\\\"error-icon\\\">\\n                        <i class=\\\"fas fa-trash-restore\\\"></i>\\n                    </div>\\n                    <div class=\\\"error-name\\\">\\u91cd\\u590d\\u91ca\\u653e</div>\\n                    <div class=\\\"error-en\\\">Double Free</div>\\n                    <div class=\\\"error-desc\\\">\\u5bf9\\u540c\\u4e00\\u5185\\u5b58\\u533a\\u57df\\u8fdb\\u884c\\u591a\\u6b21\\u91ca\\u653e\\u64cd\\u4f5c</div>\\n                </div>\\n\\n                <!-- \\u8d8a\\u754c\\u8bbf\\u95ee -->\\n                <div class=\\\"error-card bounds\\\">\\n                    <div class=\\\"error-icon\\\">\\n                        <i class=\\\"fas fa-expand-alt\\\"></i>\\n                    </div>\\n                    <div class=\\\"error-name\\\">\\u8d8a\\u754c\\u8bbf\\u95ee</div>\\n                    <div class=\\\"error-en\\\">Out of Bounds</div>\\n                    <div class=\\\"error-desc\\\">\\u8bbf\\u95ee\\u6570\\u7ec4\\u6216\\u7f13\\u51b2\\u533a\\u4e4b\\u5916\\u7684\\u5185\\u5b58\\u533a\\u57df</div>\\n                </div>\\n\\n                <!-- \\u68c0\\u6d4b\\u5de5\\u5177 -->\\n                <div class=\\\"error-card tool-card\\\">\\n                    <div class=\\\"error-icon\\\">\\n                        <i class=\\\"fas fa-search\\\"></i>\\n                    </div>\\n                    <div class=\\\"error-name\\\">\\u68c0\\u6d4b\\u5de5\\u5177</div>\\n                    <div class=\\\"error-en\\\">Detection Tools</div>\\n                    <div class=\\\"error-desc\\\">\\u4f7f\\u7528\\u4e13\\u4e1a\\u5de5\\u5177\\u5b9a\\u4f4d\\u5185\\u5b58\\u95ee\\u9898</div>\\n                </div>\\n            </div>\\n\\n            <!-- \\u5de5\\u5177\\u533a\\u57df -->\\n            <div class=\\\"tool-section\\\">\\n                <div class=\\\"tool-info\\\">\\n                    <div class=\\\"tool-title\\\">\\n                        <i class=\\\"fas fa-tools\\\"></i>\\n                        \\u4f7f\\u7528Valgrind\\u7b49\\u5de5\\u5177\\u8fdb\\u884c\\u7cfb\\u7edf\\u68c0\\u6d4b\\n                    </div>\\n                    <div class=\\\"tool-desc\\\">\\n                        Valgrind\\u662f\\u4e00\\u6b3e\\u5f3a\\u5927\\u7684\\u5185\\u5b58\\u8c03\\u8bd5\\u5de5\\u5177\\uff0c\\u53ef\\u4ee5\\u68c0\\u6d4b\\u5185\\u5b58\\u6cc4\\u6f0f\\u3001\\u975e\\u6cd5\\u5185\\u5b58\\u8bbf\\u95ee\\u3001\\u4f7f\\u7528\\u672a\\u521d\\u59cb\\u5316\\u503c\\u7b49\\u95ee\\u9898\\u3002\\n                        \\u914d\\u5408Memcheck\\u5de5\\u5177\\uff0c\\u80fd\\u591f\\u63d0\\u4f9b\\u8be6\\u7ec6\\u7684\\u95ee\\u9898\\u62a5\\u544a\\u548c\\u5b9a\\u4f4d\\u4fe1\\u606f\\u3002\\n                    </div>\\n                </div>\\n                <div class=\\\"tool-visual\\\">\\n                    <div class=\\\"code-snippet\\\">\\n                        <div class=\\\"line\\\"><span class=\\\"command\\\">$ valgrind</span> --tool=memcheck ./program</div>\\n                        <div class=\\\"line\\\"><span class=\\\"comment\\\"># \\u68c0\\u6d4b\\u5185\\u5b58\\u6cc4\\u6f0f</span></div>\\n                        <div class=\\\"line\\\"><span class=\\\"command\\\">$ valgrind</span> --leak-check=full ./program</div>\\n                        <div class=\\\"line\\\"><span class=\\\"comment\\\"># \\u8be6\\u7ec6\\u62a5\\u544a</span></div>\\n                    </div>\\n                </div>\\n            </div>\\n        </div>\\n\\n        <!-- \\u88c5\\u9970\\u5143\\u7d20 -->\\n        <div class=\\\"decoration circle-1\\\"></div>\\n        <div class=\\\"decoration circle-2\\\"></div>\\n        <div class=\\\"decoration line-1\\\"></div>\\n\\n        <!-- \\u9875\\u811a - \\u4e25\\u683c\\u4fdd\\u6301\\u539f\\u6837 -->\\n        <div class=\\\"footer\\\">\\n            <span class=\\\"page-number\\\">7 / 10</span>\\n        </div>\\n    </div>\\n</div>\\n\\n<script>\\n    // \\u6dfb\\u52a0\\u5361\\u7247\\u4ea4\\u4e92\\u6548\\u679c\\n    document.addEventListener(\'DOMContentLoaded\', function() {\\n        const cards = document.querySelectorAll(\'.error-card\');\\n        \\n        cards.forEach(card => {\\n            card.addEventListener(\'mouseenter\', function() {\\n                const icon = this.querySelector(\'.error-icon\');\\n                icon.style.transform = \'scale(1.1)\';\\n            });\\n            \\n            card.addEventListener(\'mouseleave\', function() {\\n                const icon = this.querySelector(\'.error-icon\');\\n                icon.style.transform = \'scale(1)\';\\n            });\\n        });\\n        \\n        // \\u6a21\\u62df\\u5de5\\u5177\\u533a\\u57df\\u7684\\u52a8\\u6001\\u6548\\u679c\\n        const toolVisual = document.querySelector(\'.tool-visual\');\\n        setInterval(() => {\\n            toolVisual.style.boxShadow = \'0 0 0 2px rgba(39, 174, 96, 0.3)\';\\n            setTimeout(() => {\\n                toolVisual.style.boxShadow = \'0 0 0 0 rgba(39, 174, 96, 0)\';\\n            }, 500);\\n        }, 3000);\\n    });\\n</script>\\n</body>\\n</html>\", \"is_user_edited\": false}, {\"page_number\": 8, \"title\": \"\\u7efc\\u5408\\u6848\\u4f8b\\uff1a\\u52a8\\u6001\\u6570\\u7ec4\\u7684\\u5b9e\\u73b0\", \"html_content\": \"<!DOCTYPE html>\\n<html lang=\\\"zh-CN\\\">\\n<head>\\n<meta charset=\\\"UTF-8\\\" />\\n<meta name=\\\"viewport\\\" content=\\\"width=device-width, initial-scale=1.0\\\" />\\n<title>\\u7b2c8\\u9875\\uff1a\\u7efc\\u5408\\u6848\\u4f8b\\uff1a\\u52a8\\u6001\\u6570\\u7ec4\\u7684\\u5b9e\\u73b0</title>\\n<link rel=\\\"stylesheet\\\" href=\\\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css\\\">\\n<link rel=\\\"stylesheet\\\" href=\\\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/themes/prism-tomorrow.min.css\\\">\\n<script src=\\\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/prism.min.js\\\"></script>\\n<script src=\\\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/components/prism-c.min.js\\\"></script>\\n<style>\\n    * { margin: 0; padding: 0; box-sizing: border-box; }\\n    html, body {\\n        width: 100%;\\n        height: 100%;\\n        overflow: hidden;\\n        background: #edf1eb;\\n        font-family: \\\"Microsoft YaHei\\\", \\\"PingFang SC\\\", \\\"Noto Sans SC\\\", sans-serif;\\n        color: #335239;\\n    }\\n    .slide-container {\\n        width: 100vw;\\n        height: 100vh;\\n        display: flex;\\n        align-items: center;\\n        justify-content: center;\\n    }\\n    .slide {\\n        width: 1280px;\\n        height: 720px;\\n        position: relative;\\n        overflow: hidden;\\n        transform-origin: center center;\\n        border-radius: 16px;\\n        background: linear-gradient(180deg, #f8faf6 0%, #f2f5ef 100%);\\n        box-shadow: 0 18px 42px rgba(0,0,0,.14);\\n    }\\n    /* \\u9875\\u7709 - \\u4e25\\u683c\\u4fdd\\u6301\\u539f\\u6837 */\\n    .header {\\n        position: absolute;\\n        left: 30px;\\n        right: 30px;\\n        top: 24px;\\n        display: grid;\\n        grid-template-columns: 1fr auto;\\n        gap: 20px;\\n        align-items: start;\\n        z-index: 30;\\n    }\\n    .header h1 {\\n        font-size: 28px;\\n        line-height: 1.2;\\n        color: #48724a;\\n        font-weight: 900;\\n        letter-spacing: .4px;\\n    }\\n    .header p {\\n        margin-top: 7px;\\n        font-size: 12px;\\n        color: #7e8e7f;\\n        line-height: 1.55;\\n        max-width: 650px;\\n    }\\n    .main-tabs {\\n        display: flex;\\n        gap: 10px;\\n        align-items: center;\\n        flex-wrap: wrap;\\n        justify-content: flex-end;\\n    }\\n    .main-tab {\\n        border: 1px solid rgba(90,121,80,.18);\\n        background: rgba(255,255,255,.92);\\n        color: #5f7860;\\n        border-radius: 999px;\\n        padding: 9px 16px;\\n        font-size: 14px;\\n        font-weight: 800;\\n        cursor: pointer;\\n        transition: all .18s ease;\\n    }\\n    .main-tab.active {\\n        background: #4e7b47;\\n        color: #fff;\\n        box-shadow: 0 8px 18px rgba(78,123,71,.28);\\n    }\\n    /* \\u4e3b\\u8981\\u5185\\u5bb9\\u533a\\u57df - \\u53ef\\u521b\\u610f\\u8bbe\\u8ba1 */\\n    .content-area {\\n        position: absolute;\\n        left: 30px;\\n        right: 30px;\\n        top: 98px;\\n        bottom: 60px;\\n        display: flex;\\n        flex-direction: column;\\n        gap: 16px;\\n    }\\n    /* \\u9875\\u811a - \\u4e25\\u683c\\u4fdd\\u6301\\u539f\\u6837 */\\n    .footer {\\n        position: absolute;\\n        left: 30px;\\n        right: 30px;\\n        bottom: 20px;\\n        display: flex;\\n        justify-content: space-between;\\n        align-items: center;\\n        font-size: 12px;\\n        color: #7e8e7f;\\n        z-index: 30;\\n    }\\n    .footer .page-number {\\n        font-weight: 700;\\n        color: #5a7a55;\\n    }\\n    .footer .decorative-line {\\n        flex-grow: 1;\\n        height: 1px;\\n        background: linear-gradient(90deg, transparent, rgba(90,121,80,.2), transparent);\\n        margin: 0 15px;\\n    }\\n    /* \\u521b\\u610f\\u8bbe\\u8ba1\\u90e8\\u5206 */\\n    .page-title {\\n        font-size: 32px;\\n        font-weight: 900;\\n        color: #4a7b43;\\n        margin-bottom: 8px;\\n        display: flex;\\n        align-items: center;\\n        gap: 12px;\\n    }\\n    .page-title i {\\n        color: #6fa642;\\n        font-size: 28px;\\n    }\\n    .subtitle {\\n        font-size: 16px;\\n        color: #788874;\\n        margin-bottom: 20px;\\n        font-weight: 500;\\n    }\\n    .main-content {\\n        display: flex;\\n        flex-grow: 1;\\n        gap: 24px;\\n        height: calc(100% - 80px);\\n    }\\n    .left-panel {\\n        flex: 0 0 380px;\\n        display: flex;\\n        flex-direction: column;\\n        gap: 18px;\\n    }\\n    .feature-card {\\n        background: rgba(255,255,255,.92);\\n        border-radius: 20px;\\n        padding: 20px;\\n        border: 1px solid rgba(87,124,79,.12);\\n        box-shadow: 0 8px 20px rgba(0,0,0,.05);\\n        transition: transform 0.3s ease;\\n        flex-grow: 1;\\n        display: flex;\\n        flex-direction: column;\\n    }\\n    .feature-card:hover {\\n        transform: translateY(-5px);\\n        box-shadow: 0 12px 24px rgba(0,0,0,.08);\\n    }\\n    .feature-header {\\n        display: flex;\\n        align-items: center;\\n        gap: 12px;\\n        margin-bottom: 15px;\\n        padding-bottom: 12px;\\n        border-bottom: 1px dashed #e3ece0;\\n    }\\n    .feature-icon {\\n        width: 40px;\\n        height: 40px;\\n        border-radius: 12px;\\n        display: flex;\\n        align-items: center;\\n        justify-content: center;\\n        font-size: 18px;\\n        color: white;\\n    }\\n    .icon-1 { background: linear-gradient(135deg, #6CABE7, #4A8FD8); }\\n    .icon-2 { background: linear-gradient(135deg, #00CC88, #00AA6E); }\\n    .icon-3 { background: linear-gradient(135deg, #FF9966, #FF7744); }\\n    .icon-4 { background: linear-gradient(135deg, #9D7BFF, #7B5AEA); }\\n    .feature-title {\\n        font-size: 18px;\\n        font-weight: 800;\\n        color: #4a7b43;\\n    }\\n    .feature-desc {\\n        font-size: 14px;\\n        color: #607163;\\n        line-height: 1.6;\\n        flex-grow: 1;\\n    }\\n    .right-panel {\\n        flex: 1;\\n        display: flex;\\n        flex-direction: column;\\n        gap: 18px;\\n    }\\n    .code-section {\\n        background: #1e1e1e;\\n        border-radius: 20px;\\n        overflow: hidden;\\n        flex-grow: 1;\\n        display: flex;\\n        flex-direction: column;\\n        box-shadow: 0 10px 30px rgba(0,0,0,.2);\\n    }\\n    .code-header {\\n        background: #2d2d2d;\\n        padding: 15px 20px;\\n        display: flex;\\n        justify-content: space-between;\\n        align-items: center;\\n        border-bottom: 1px solid #3d3d3d;\\n    }\\n    .code-title {\\n        color: #f0f0f0;\\n        font-size: 16px;\\n        font-weight: 700;\\n        display: flex;\\n        align-items: center;\\n        gap: 10px;\\n    }\\n    .code-actions {\\n        display: flex;\\n        gap: 10px;\\n    }\\n    .code-btn {\\n        background: #3d3d3d;\\n        border: none;\\n        color: #aaa;\\n        padding: 6px 12px;\\n        border-radius: 6px;\\n        font-size: 12px;\\n        cursor: pointer;\\n        transition: all 0.2s;\\n    }\\n    .code-btn:hover {\\n        background: #4a4a4a;\\n        color: #fff;\\n    }\\n    .code-content {\\n        flex-grow: 1;\\n        padding: 20px;\\n        overflow: auto;\\n        font-family: \'Consolas\', \'Monaco\', monospace;\\n        font-size: 14px;\\n        line-height: 1.5;\\n    }\\n    .code-content pre {\\n        margin: 0;\\n        color: #d4d4d4;\\n    }\\n    .code-line {\\n        display: flex;\\n        margin-bottom: 4px;\\n    }\\n    .line-number {\\n        color: #6a9955;\\n        min-width: 40px;\\n        text-align: right;\\n        padding-right: 15px;\\n        user-select: none;\\n    }\\n    .line-code {\\n        flex-grow: 1;\\n    }\\n    .keyword { color: #569cd6; }\\n    .type { color: #4ec9b0; }\\n    .function { color: #dcdcaa; }\\n    .string { color: #ce9178; }\\n    .comment { color: #6a9955; }\\n    .number { color: #b5cea8; }\\n    .macro { color: #c586c0; }\\n    .thought-section {\\n        background: linear-gradient(135deg, #f7faf4, #f2f7ef);\\n        border-radius: 20px;\\n        padding: 20px;\\n        border: 1px solid #e3ece0;\\n        display: flex;\\n        align-items: center;\\n        gap: 20px;\\n    }\\n    .thought-icon {\\n        width: 60px;\\n        height: 60px;\\n        border-radius: 50%;\\n        background: #4e7b47;\\n        display: flex;\\n        align-items: center;\\n        justify-content: center;\\n        color: white;\\n        font-size: 24px;\\n        flex-shrink: 0;\\n    }\\n    .thought-content {\\n        flex-grow: 1;\\n    }\\n    .thought-title {\\n        font-size: 18px;\\n        font-weight: 800;\\n        color: #4a7b43;\\n        margin-bottom: 8px;\\n    }\\n    .thought-desc {\\n        font-size: 14px;\\n        color: #607163;\\n        line-height: 1.6;\\n    }\\n    /* \\u52a8\\u6001\\u6570\\u7ec4\\u53ef\\u89c6\\u5316 */\\n    .array-visualization {\\n        position: absolute;\\n        right: 40px;\\n        top: 120px;\\n        width: 300px;\\n        height: 180px;\\n        background: rgba(255,255,255,.8);\\n        border-radius: 16px;\\n        padding: 15px;\\n        border: 1px solid rgba(87,124,79,.15);\\n        box-shadow: 0 8px 20px rgba(0,0,0,.08);\\n        z-index: 10;\\n        display: none; /* \\u9ed8\\u8ba4\\u9690\\u85cf\\uff0c\\u53ef\\u901a\\u8fc7\\u4ea4\\u4e92\\u663e\\u793a */\\n    }\\n    .visual-title {\\n        font-size: 14px;\\n        font-weight: 700;\\n        color: #4a7b43;\\n        margin-bottom: 10px;\\n        text-align: center;\\n    }\\n    .array-container {\\n        display: flex;\\n        align-items: center;\\n        justify-content: center;\\n        gap: 8px;\\n        margin-top: 10px;\\n    }\\n    .array-element {\\n        width: 40px;\\n        height: 40px;\\n        border-radius: 8px;\\n        display: flex;\\n        align-items: center;\\n        justify-content: center;\\n        font-weight: 700;\\n        color: white;\\n        background: #6fa642;\\n        transition: all 0.3s ease;\\n    }\\n    .array-element.empty {\\n        background: #e3ece0;\\n        color: #a0b09c;\\n    }\\n    .capacity-bar {\\n        height: 6px;\\n        background: #e3ece0;\\n        border-radius: 3px;\\n        margin-top: 15px;\\n        overflow: hidden;\\n    }\\n    .used-capacity {\\n        height: 100%;\\n        background: #6fa642;\\n        border-radius: 3px;\\n        width: 60%;\\n        transition: width 0.5s ease;\\n    }\\n    /* \\u88c5\\u9970\\u5143\\u7d20 */\\n    .decoration-circle {\\n        position: absolute;\\n        border-radius: 50%;\\n        opacity: 0.1;\\n        z-index: 1;\\n    }\\n    .circle-1 {\\n        width: 120px;\\n        height: 120px;\\n        background: #6fa642;\\n        right: 80px;\\n        top: 180px;\\n    }\\n    .circle-2 {\\n        width: 80px;\\n        height: 80px;\\n        background: #4e7b47;\\n        left: 100px;\\n        bottom: 120px;\\n    }\\n    .circle-3 {\\n        width: 60px;\\n        height: 60px;\\n        background: #c9d97c;\\n        right: 200px;\\n        bottom: 80px;\\n    }\\n</style>\\n</head>\\n<body>\\n<div class=\\\"slide-container\\\">\\n    <div class=\\\"slide\\\">\\n        <!-- \\u9875\\u7709 - \\u4e25\\u683c\\u4fdd\\u6301\\u539f\\u6837 -->\\n        <div class=\\\"header\\\">\\n            <div>\\n                <h1>\\u98df\\u54c1\\u836f\\u54c1\\u804c\\u4e1a\\u5b66\\u9662 PPT \\u6a21\\u677f\\u63cf\\u8ff0\\u6587\\u4ef6\\uff08\\u5b57\\u6bb5\\u89c4\\u8303\\u7248\\uff09</h1>\\n                <p>\\u53c2\\u7167 template.html \\u7684\\\"\\u5355\\u6587\\u4ef6\\u3001\\u81ea\\u5305\\u542b\\u3001\\u56fa\\u5b9a 1280\\u00d7720\\u3001\\u54cd\\u5e94\\u5f0f\\u7f29\\u653e\\u3001\\u5360\\u4f4d\\u7b26\\u4e0e\\u89c4\\u5219\\u8bf4\\u660e\\\"\\u5199\\u6cd5\\uff0c\\u5728 v3 \\u7684\\u5b50\\u7248\\u5f0f\\u62c6\\u5206\\u57fa\\u7840\\u4e0a\\uff0c\\u7ee7\\u7eed\\u628a\\u5b57\\u6bb5\\u547d\\u540d\\u3001\\u9009\\u578b\\u89c4\\u5219\\u3001\\u7981\\u7528\\u573a\\u666f\\u548c\\u6bcd\\u7248\\u7ea6\\u675f\\u6807\\u51c6\\u5316\\uff0c\\u65b9\\u4fbf\\u540e\\u7eed\\u76f4\\u63a5\\u62ff\\u6765\\u751f\\u6210\\u65b0\\u7684 PPT\\u3002</p>\\n            </div>\\n            <div class=\\\"main-tabs\\\">\\n                <div class=\\\"main-tab active\\\">\\u5185\\u5bb9\\u7cfb\\u7edf</div>\\n                <div class=\\\"main-tab\\\">\\u6570\\u636e\\u7cfb\\u7edf</div>\\n                <div class=\\\"main-tab\\\">\\u76ee\\u5f55\\u7cfb\\u7edf</div>\\n            </div>\\n        </div>\\n        <!-- \\u4e3b\\u8981\\u5185\\u5bb9\\u533a\\u57df - \\u521b\\u610f\\u8bbe\\u8ba1 -->\\n        <div class=\\\"content-area\\\">\\n            <div class=\\\"page-title\\\">\\n                <i class=\\\"fas fa-code\\\"></i>\\n                \\u7efc\\u5408\\u6848\\u4f8b\\uff1a\\u52a8\\u6001\\u6570\\u7ec4\\u7684\\u5b9e\\u73b0\\n            </div>\\n            <div class=\\\"subtitle\\\">\\u4e00\\u79cd\\u53ef\\u81ea\\u9002\\u5e94\\u5bb9\\u91cf\\u7684\\u9ad8\\u6548\\u6570\\u636e\\u5b58\\u50a8\\u65b9\\u6848 | \\u4ece\\u8bbe\\u8ba1\\u5230\\u5c01\\u88c5\\u7684\\u5b8c\\u6574\\u5b9e\\u8df5\\u8def\\u5f84</div>\\n            <div class=\\\"main-content\\\">\\n                <!-- \\u5de6\\u4fa7\\u529f\\u80fd\\u6a21\\u5757 -->\\n                <div class=\\\"left-panel\\\">\\n                    <div class=\\\"feature-card\\\">\\n                        <div class=\\\"feature-header\\\">\\n                            <div class=\\\"feature-icon icon-1\\\">\\n                                <i class=\\\"fas fa-drafting-compass\\\"></i>\\n                            </div>\\n                            <div class=\\\"feature-title\\\">\\u8bbe\\u8ba1\\u53ef\\u52a8\\u6001\\u6269\\u5bb9\\u7684\\u6574\\u578b\\u6570\\u7ec4\\u7ed3\\u6784</div>\\n                        </div>\\n                        <div class=\\\"feature-desc\\\">\\n                            \\u5b9a\\u4e49\\u52a8\\u6001\\u6570\\u7ec4\\u7684\\u6838\\u5fc3\\u6570\\u636e\\u7ed3\\u6784\\uff0c\\u5305\\u542b\\u6570\\u636e\\u6307\\u9488\\u3001\\u5f53\\u524d\\u5927\\u5c0f\\u548c\\u603b\\u5bb9\\u91cf\\u3002\\u8bbe\\u8ba1\\u6269\\u5bb9\\u7b56\\u7565\\uff08\\u901a\\u5e38\\u4e3a2\\u500d\\u589e\\u957f\\uff09\\uff0c\\u5e73\\u8861\\u7a7a\\u95f4\\u6548\\u7387\\u4e0e\\u65f6\\u95f4\\u6027\\u80fd\\u3002\\n                        </div>\\n                    </div>\\n                    <div class=\\\"feature-card\\\">\\n                        <div class=\\\"feature-header\\\">\\n                            <div class=\\\"feature-icon icon-2\\\">\\n                                <i class=\\\"fas fa-plus-circle\\\"></i>\\n                            </div>\\n                            <div class=\\\"feature-title\\\">\\u5b9e\\u73b0\\u521d\\u59cb\\u5316\\u3001\\u6dfb\\u52a0\\u3001\\u5220\\u9664\\u3001\\u6269\\u5bb9\\u7b49\\u529f\\u80fd</div>\\n                        </div>\\n                        <div class=\\\"feature-desc\\\">\\n                            \\u7f16\\u5199\\u6838\\u5fc3\\u64cd\\u4f5c\\u51fd\\u6570\\uff1a\\u521d\\u59cb\\u5316\\u5206\\u914d\\u5185\\u5b58\\u3001\\u5c3e\\u90e8\\u6dfb\\u52a0\\u5143\\u7d20\\uff08\\u81ea\\u52a8\\u6269\\u5bb9\\uff09\\u3001\\u5220\\u9664\\u6307\\u5b9a\\u4f4d\\u7f6e\\u5143\\u7d20\\uff08\\u79fb\\u52a8\\u540e\\u7eed\\u5143\\u7d20\\uff09\\u3001\\u5bb9\\u91cf\\u4e0d\\u8db3\\u65f6\\u81ea\\u52a8\\u6269\\u5bb9\\u5e76\\u8fc1\\u79fb\\u6570\\u636e\\u3002\\n                        </div>\\n                    </div>\\n                    <div class=\\\"feature-card\\\">\\n                        <div class=\\\"feature-header\\\">\\n                            <div class=\\\"feature-icon icon-3\\\">\\n                                <i class=\\\"fas fa-laptop-code\\\"></i>\\n                            </div>\\n                            <div class=\\\"feature-title\\\">\\u4ee3\\u7801\\u6f14\\u793a\\u4e0e\\u9010\\u884c\\u8bb2\\u89e3</div>\\n                        </div>\\n                        <div class=\\\"feature-desc\\\">\\n                            \\u901a\\u8fc7\\u5b9e\\u9645\\u4ee3\\u7801\\u5c55\\u793a\\u52a8\\u6001\\u6570\\u7ec4\\u7684\\u5b9e\\u73b0\\u7ec6\\u8282\\uff0c\\u9010\\u884c\\u89e3\\u6790\\u5173\\u952e\\u7b97\\u6cd5\\u3001\\u8fb9\\u754c\\u5904\\u7406\\u3001\\u5185\\u5b58\\u7ba1\\u7406\\u548c\\u6027\\u80fd\\u8003\\u91cf\\uff0c\\u5efa\\u7acb\\u4ece\\u7406\\u8bba\\u5230\\u5b9e\\u8df5\\u7684\\u76f4\\u89c2\\u6620\\u5c04\\u3002\\n                        </div>\\n                    </div>\\n                    <div class=\\\"feature-card\\\">\\n                        <div class=\\\"feature-header\\\">\\n                            <div class=\\\"feature-icon icon-4\\\">\\n                                <i class=\\\"fas fa-cube\\\"></i>\\n                            </div>\\n                            <div class=\\\"feature-title\\\">\\u601d\\u8003\\uff1a\\u5982\\u4f55\\u5c01\\u88c5\\u6210\\u901a\\u7528\\u7684\\u52a8\\u6001\\u6570\\u7ec4\\uff1f</div>\\n                        </div>\\n                        <div class=\\\"feature-desc\\\">\\n                            \\u4ece\\u5177\\u4f53\\u7c7b\\u578b\\u62bd\\u8c61\\u5230\\u901a\\u7528\\u6a21\\u677f\\uff0c\\u63a2\\u8ba8\\u7c7b\\u578b\\u5b89\\u5168\\u3001\\u5185\\u5b58\\u7ba1\\u7406\\u3001\\u8fed\\u4ee3\\u5668\\u8bbe\\u8ba1\\u7b49\\u9ad8\\u7ea7\\u8bdd\\u9898\\uff0c\\u4e3a\\u540e\\u7eed\\u5b66\\u4e60STL\\u7b49\\u6807\\u51c6\\u5e93\\u5960\\u5b9a\\u57fa\\u7840\\u3002\\n                        </div>\\n                    </div>\\n                </div>\\n                <!-- \\u53f3\\u4fa7\\u4ee3\\u7801\\u6f14\\u793a\\u533a -->\\n                <div class=\\\"right-panel\\\">\\n                    <div class=\\\"code-section\\\">\\n                        <div class=\\\"code-header\\\">\\n                            <div class=\\\"code-title\\\">\\n                                <i class=\\\"fas fa-file-code\\\"></i>\\n                                dynamic_array.c - \\u52a8\\u6001\\u6570\\u7ec4\\u6838\\u5fc3\\u5b9e\\u73b0\\n                            </div>\\n                            <div class=\\\"code-actions\\\">\\n                                <button class=\\\"code-btn\\\"><i class=\\\"fas fa-play\\\"></i> \\u8fd0\\u884c</button>\\n                                <button class=\\\"code-btn\\\"><i class=\\\"fas fa-expand\\\"></i> \\u5c55\\u5f00</button>\\n                            </div>\\n                        </div>\\n                        <div class=\\\"code-content\\\">\\n                            <pre><code class=\\\"language-c\\\">// \\u52a8\\u6001\\u6570\\u7ec4\\u7ed3\\u6784\\u5b9a\\u4e49\\ntypedef struct {\\n    int *data;      // \\u6570\\u636e\\u6307\\u9488\\n    size_t size;    // \\u5f53\\u524d\\u5143\\u7d20\\u6570\\u91cf\\n    size_t capacity;// \\u603b\\u5bb9\\u91cf\\n} DynamicArray;\\nDynamicArray* da_init(size_t init_capacity) {\\n    DynamicArray *arr = malloc(sizeof(DynamicArray));\\n    arr->data = malloc(init_capacity * sizeof(int));\\n    arr->size = 0;\\n    arr\", \"is_user_edited\": false}, {\"page_number\": 9, \"title\": \"\\u7ec3\\u4e60\\u4e0e\\u601d\\u8003\\u9898\", \"html_content\": \"<!DOCTYPE html>\\n<html lang=\\\"zh-CN\\\">\\n<head>\\n<meta charset=\\\"UTF-8\\\" />\\n<meta name=\\\"viewport\\\" content=\\\"width=device-width, initial-scale=1.0\\\" />\\n<title>\\u7ec3\\u4e60\\u4e0e\\u601d\\u8003\\u9898 - C\\u8bed\\u8a00\\u7b2c\\u56db\\u6b21\\u8bfe</title>\\n<link rel=\\\"stylesheet\\\" href=\\\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css\\\">\\n<link rel=\\\"stylesheet\\\" href=\\\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/themes/prism-tomorrow.min.css\\\">\\n<script src=\\\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/prism.min.js\\\"></script>\\n<script src=\\\"https://cdn.jsdelivr.net/npm/chart.js\\\"></script>\\n<style>\\n    * { margin: 0; padding: 0; box-sizing: border-box; }\\n    html, body {\\n        width: 100%;\\n        height: 100%;\\n        overflow: hidden;\\n        background: #edf1eb;\\n        font-family: \\\"Microsoft YaHei\\\", \\\"PingFang SC\\\", \\\"Noto Sans SC\\\", sans-serif;\\n        color: #335239;\\n    }\\n    .slide-container {\\n        width: 100vw;\\n        height: 100vh;\\n        display: flex;\\n        align-items: center;\\n        justify-content: center;\\n    }\\n    .slide {\\n        width: 1280px;\\n        height: 720px;\\n        position: relative;\\n        overflow: hidden;\\n        transform-origin: center center;\\n        border-radius: 16px;\\n        background: linear-gradient(180deg, #f8faf6 0%, #f2f5ef 100%);\\n        box-shadow: 0 18px 42px rgba(0,0,0,.14);\\n    }\\n    /* \\u9875\\u7709 - \\u4e25\\u683c\\u4fdd\\u6301\\u539f\\u6837 */\\n    .header {\\n        position: absolute;\\n        left: 30px;\\n        right: 30px;\\n        top: 24px;\\n        display: grid;\\n        grid-template-columns: 1fr auto;\\n        gap: 20px;\\n        align-items: start;\\n        z-index: 30;\\n    }\\n    .header h1 {\\n        font-size: 28px;\\n        line-height: 1.2;\\n        color: #48724a;\\n        font-weight: 900;\\n        letter-spacing: .4px;\\n    }\\n    .header p {\\n        margin-top: 7px;\\n        font-size: 12px;\\n        color: #7e8e7f;\\n        line-height: 1.55;\\n        max-width: 650px;\\n    }\\n    .main-tabs {\\n        display: flex;\\n        gap: 10px;\\n        align-items: center;\\n        flex-wrap: wrap;\\n        justify-content: flex-end;\\n    }\\n    .main-tab {\\n        border: 1px solid rgba(90,121,80,.18);\\n        background: rgba(255,255,255,.92);\\n        color: #5f7860;\\n        border-radius: 999px;\\n        padding: 9px 16px;\\n        font-size: 14px;\\n        font-weight: 800;\\n        cursor: pointer;\\n        transition: all .18s ease;\\n    }\\n    .main-tab.active {\\n        background: #4e7b47;\\n        color: #fff;\\n        box-shadow: 0 8px 18px rgba(78,123,71,.28);\\n    }\\n    /* \\u4e3b\\u8981\\u5185\\u5bb9\\u533a\\u57df - \\u53ef\\u521b\\u610f\\u8bbe\\u8ba1 */\\n    .main-content {\\n        position: absolute;\\n        left: 30px;\\n        right: 30px;\\n        top: 98px;\\n        bottom: 60px;\\n        display: flex;\\n        flex-direction: column;\\n        gap: 20px;\\n    }\\n    /* \\u9875\\u811a - \\u4e25\\u683c\\u4fdd\\u6301\\u539f\\u6837 */\\n    .footer {\\n        position: absolute;\\n        left: 30px;\\n        right: 30px;\\n        bottom: 20px;\\n        display: flex;\\n        justify-content: space-between;\\n        align-items: center;\\n        z-index: 30;\\n    }\\n    .footer .page-number {\\n        font-size: 14px;\\n        color: #7e8e7f;\\n        font-weight: 600;\\n    }\\n    .footer .decorative-line {\\n        flex-grow: 1;\\n        height: 1px;\\n        background: linear-gradient(90deg, transparent, rgba(90,121,80,.2), transparent);\\n        margin: 0 20px;\\n    }\\n    .footer .school-name {\\n        font-size: 12px;\\n        color: #7e8e7f;\\n    }\\n    /* \\u521b\\u610f\\u8bbe\\u8ba1\\u533a\\u57df */\\n    .page-title {\\n        text-align: center;\\n        margin-bottom: 10px;\\n    }\\n    .page-title h2 {\\n        font-size: 36px;\\n        color: #4e7b47;\\n        font-weight: 900;\\n        letter-spacing: 1px;\\n        margin-bottom: 8px;\\n        position: relative;\\n        display: inline-block;\\n    }\\n    .page-title h2::after {\\n        content: \'\';\\n        position: absolute;\\n        bottom: -8px;\\n        left: 50%;\\n        transform: translateX(-50%);\\n        width: 120px;\\n        height: 4px;\\n        background: linear-gradient(90deg, #4e7b47, #8cb267);\\n        border-radius: 2px;\\n    }\\n    .page-title p {\\n        font-size: 16px;\\n        color: #7e8e7f;\\n        font-weight: 500;\\n    }\\n    .content-grid {\\n        display: grid;\\n        grid-template-columns: repeat(3, 1fr);\\n        gap: 20px;\\n        height: 100%;\\n        flex-grow: 1;\\n    }\\n    .content-card {\\n        background: rgba(255,255,255,.95);\\n        border-radius: 20px;\\n        padding: 24px;\\n        display: flex;\\n        flex-direction: column;\\n        border: 1px solid rgba(87,124,79,.12);\\n        box-shadow: 0 8px 24px rgba(0,0,0,.06);\\n        transition: all 0.3s ease;\\n        position: relative;\\n        overflow: hidden;\\n    }\\n    .content-card:hover {\\n        transform: translateY(-5px);\\n        box-shadow: 0 12px 32px rgba(78,123,71,.15);\\n    }\\n    .card-header {\\n        display: flex;\\n        align-items: center;\\n        margin-bottom: 20px;\\n        padding-bottom: 15px;\\n        border-bottom: 2px solid rgba(78,123,71,.1);\\n    }\\n    .card-icon {\\n        width: 60px;\\n        height: 60px;\\n        border-radius: 50%;\\n        display: flex;\\n        align-items: center;\\n        justify-content: center;\\n        margin-right: 18px;\\n        font-size: 28px;\\n        color: white;\\n        flex-shrink: 0;\\n    }\\n    .card-title {\\n        flex-grow: 1;\\n    }\\n    .card-title h3 {\\n        font-size: 22px;\\n        color: #335239;\\n        font-weight: 800;\\n        margin-bottom: 5px;\\n    }\\n    .card-title .subtitle {\\n        font-size: 14px;\\n        color: #7e8e7f;\\n        font-weight: 500;\\n    }\\n    .card-difficulty {\\n        display: flex;\\n        margin-top: 5px;\\n    }\\n    .star {\\n        color: #FFC107;\\n        font-size: 16px;\\n        margin-right: 2px;\\n    }\\n    .card-content {\\n        flex-grow: 1;\\n        display: flex;\\n        flex-direction: column;\\n    }\\n    .task-list {\\n        list-style: none;\\n        margin-bottom: 20px;\\n        flex-grow: 1;\\n    }\\n    .task-list li {\\n        position: relative;\\n        padding-left: 22px;\\n        margin-bottom: 12px;\\n        font-size: 15px;\\n        color: #607163;\\n        line-height: 1.5;\\n    }\\n    .task-list li::before {\\n        content: \\\"\\u25b6\\\";\\n        position: absolute;\\n        left: 0;\\n        top: 2px;\\n        color: #7da965;\\n        font-size: 12px;\\n    }\\n    .code-preview {\\n        background: #2d2d2d;\\n        border-radius: 10px;\\n        padding: 15px;\\n        margin-top: 15px;\\n        font-family: \'Consolas\', \'Monaco\', monospace;\\n        font-size: 13px;\\n        color: #f8f8f2;\\n        line-height: 1.4;\\n        overflow: hidden;\\n        flex-grow: 1;\\n    }\\n    .code-preview .comment { color: #75715e; }\\n    .code-preview .keyword { color: #66d9ef; }\\n    .code-preview .function { color: #a6e22e; }\\n    .code-preview .type { color: #f92672; }\\n    .chart-container {\\n        height: 180px;\\n        margin-top: 15px;\\n        position: relative;\\n    }\\n    .thinking-points {\\n        background: #f8fbf6;\\n        border-radius: 12px;\\n        padding: 16px;\\n        margin-top: 15px;\\n        border-left: 4px solid #7da965;\\n    }\\n    .thinking-points p {\\n        font-size: 14px;\\n        color: #607163;\\n        line-height: 1.6;\\n        margin-bottom: 10px;\\n    }\\n    .thinking-points .question {\\n        font-weight: 700;\\n        color: #4e7b47;\\n        margin-top: 12px;\\n        display: block;\\n    }\\n    .next-lesson {\\n        background: linear-gradient(135deg, #f6faf4, #e8f1e5);\\n        border-radius: 16px;\\n        padding: 20px;\\n        margin-top: 20px;\\n        border: 2px dashed #bdd4b2;\\n        display: flex;\\n        align-items: center;\\n        justify-content: space-between;\\n    }\\n    .next-lesson-content {\\n        flex-grow: 1;\\n    }\\n    .next-lesson h4 {\\n        font-size: 18px;\\n        color: #4e7b47;\\n        font-weight: 800;\\n        margin-bottom: 8px;\\n    }\\n    .next-lesson p {\\n        font-size: 14px;\\n        color: #7e8e7f;\\n    }\\n    .next-lesson-icon {\\n        font-size: 40px;\\n        color: #7da965;\\n        margin-left: 20px;\\n    }\\n    /* \\u5361\\u7247\\u7279\\u5b9a\\u6837\\u5f0f */\\n    .card-1 .card-icon { background: linear-gradient(135deg, #4A90E2, #5fa3ff); }\\n    .card-2 .card-icon { background: linear-gradient(135deg, #F5A623, #ffb84d); }\\n    .card-3 .card-icon { background: linear-gradient(135deg, #9013FE, #b150ff); }\\n    /* \\u88c5\\u9970\\u5143\\u7d20 */\\n    .decoration {\\n        position: absolute;\\n        z-index: 1;\\n    }\\n    .decoration-1 {\\n        width: 80px;\\n        height: 80px;\\n        background: rgba(141, 190, 124, 0.1);\\n        border-radius: 50%;\\n        top: 120px;\\n        left: 50px;\\n    }\\n    .decoration-2 {\\n        width: 40px;\\n        height: 40px;\\n        background: rgba(125, 169, 101, 0.15);\\n        border-radius: 50%;\\n        bottom: 100px;\\n        right: 80px;\\n    }\\n    .decoration-3 {\\n        width: 120px;\\n        height: 120px;\\n        border: 2px dashed rgba(78, 123, 71, 0.2);\\n        border-radius: 50%;\\n        top: 180px;\\n        right: 60px;\\n    }\\n    /* \\u54cd\\u5e94\\u5f0f\\u8c03\\u6574 */\\n    @media (max-width: 1350px) {\\n        .content-grid {\\n            gap: 15px;\\n        }\\n        .content-card {\\n            padding: 20px;\\n        }\\n    }\\n</style>\\n</head>\\n<body>\\n<div class=\\\"slide-container\\\">\\n    <div class=\\\"slide\\\">\\n        <!-- \\u9875\\u7709 - \\u4e25\\u683c\\u4fdd\\u6301\\u539f\\u6837 -->\\n        <div class=\\\"header\\\">\\n            <div>\\n                <h1>\\u98df\\u54c1\\u836f\\u54c1\\u804c\\u4e1a\\u5b66\\u9662 PPT \\u6a21\\u677f\\u63cf\\u8ff0\\u6587\\u4ef6\\uff08\\u5b57\\u6bb5\\u89c4\\u8303\\u7248\\uff09</h1>\\n                <p>\\u53c2\\u7167 template.html \\u7684\\\"\\u5355\\u6587\\u4ef6\\u3001\\u81ea\\u5305\\u542b\\u3001\\u56fa\\u5b9a 1280\\u00d7720\\u3001\\u54cd\\u5e94\\u5f0f\\u7f29\\u653e\\u3001\\u5360\\u4f4d\\u7b26\\u4e0e\\u89c4\\u5219\\u8bf4\\u660e\\\"\\u5199\\u6cd5\\uff0c\\u5728 v3 \\u7684\\u5b50\\u7248\\u5f0f\\u62c6\\u5206\\u57fa\\u7840\\u4e0a\\uff0c\\u7ee7\\u7eed\\u628a\\u5b57\\u6bb5\\u547d\\u540d\\u3001\\u9009\\u578b\\u89c4\\u5219\\u3001\\u7981\\u7528\\u573a\\u666f\\u548c\\u6bcd\\u7248\\u7ea6\\u675f\\u6807\\u51c6\\u5316\\uff0c\\u65b9\\u4fbf\\u540e\\u7eed\\u76f4\\u63a5\\u62ff\\u6765\\u751f\\u6210\\u65b0\\u7684 PPT\\u3002</p>\\n            </div>\\n            <div class=\\\"main-tabs\\\">\\n                <button class=\\\"main-tab\\\">\\u5c01\\u9762\\u7cfb\\u7edf</button>\\n                <button class=\\\"main-tab\\\">\\u76ee\\u5f55\\u7cfb\\u7edf</button>\\n                <button class=\\\"main-tab active\\\">\\u5185\\u5bb9\\u7cfb\\u7edf</button>\\n                <button class=\\\"main-tab\\\">\\u6570\\u636e\\u7cfb\\u7edf</button>\\n            </div>\\n        </div>\\n        <!-- \\u4e3b\\u8981\\u5185\\u5bb9\\u533a\\u57df - \\u521b\\u610f\\u8bbe\\u8ba1 -->\\n        <div class=\\\"main-content\\\">\\n            <div class=\\\"page-title\\\">\\n                <h2>\\u7ec3\\u4e60\\u4e0e\\u601d\\u8003\\u9898</h2>\\n                <p>C\\u8bed\\u8a00\\u7b2c\\u56db\\u6b21\\u8bfe \\u00b7 \\u7f16\\u7a0b\\u5b9e\\u9a8c\\u5ba4\\u5b9e\\u8df5\\u533a</p>\\n            </div>\\n            <div class=\\\"content-grid\\\">\\n                <!-- \\u7ec3\\u4e601\\u5361\\u7247 -->\\n                <div class=\\\"content-card card-1\\\">\\n                    <div class=\\\"card-header\\\">\\n                        <div class=\\\"card-icon\\\">\\n                            <i class=\\\"fas fa-calculator\\\"></i>\\n                        </div>\\n                        <div class=\\\"card-title\\\">\\n                            <h3>\\u7ec3\\u4e601</h3>\\n                            <div class=\\\"subtitle\\\">\\u51fd\\u6570\\u6307\\u9488\\u5b9e\\u6218</div>\\n                            <div class=\\\"card-difficulty\\\">\\n                                <span class=\\\"star\\\">\\u2605</span>\\n                                <span class=\\\"star\\\">\\u2605</span>\\n                                <span class=\\\"star\\\" style=\\\"color:#ddd\\\">\\u2605</span>\\n                            </div>\\n                        </div>\\n                    </div>\\n                    <div class=\\\"card-content\\\">\\n                        <ul class=\\\"task-list\\\">\\n                            <li>\\u4f7f\\u7528\\u51fd\\u6570\\u6307\\u9488\\u5b9e\\u73b0\\u56db\\u5219\\u8fd0\\u7b97\\u8ba1\\u7b97\\u5668</li>\\n                            <li>\\u901a\\u8fc7\\u51fd\\u6570\\u6307\\u9488\\u6570\\u7ec4\\u8c03\\u7528\\u4e0d\\u540c\\u8fd0\\u7b97\\u51fd\\u6570</li>\\n                            <li>\\u7406\\u89e3\\u56de\\u8c03\\u673a\\u5236\\u4e0e\\u63a5\\u53e3\\u8bbe\\u8ba1</li>\\n                            <li>\\u652f\\u6301\\u52a0\\u51cf\\u4e58\\u9664\\u56db\\u79cd\\u57fa\\u672c\\u8fd0\\u7b97</li>\\n                        </ul>\\n                        <div class=\\\"code-preview\\\">\\n                            <span class=\\\"comment\\\">// \\u51fd\\u6570\\u6307\\u9488\\u6570\\u7ec4\\u793a\\u4f8b</span><br>\\n                            <span class=\\\"type\\\">int</span> (<span class=\\\"keyword\\\">*</span>ops[<span class=\\\"number\\\">4</span>])(<span class=\\\"type\\\">int</span>, <span class=\\\"type\\\">int</span>) = {<br>\\n                            &nbsp;&nbsp;&nbsp;&nbsp;add, <span class=\\\"comment\\\">// \\u52a0\\u6cd5</span><br>\\n                            &nbsp;&nbsp;&nbsp;&nbsp;sub, <span class=\\\"comment\\\">// \\u51cf\\u6cd5</span><br>\\n                            &nbsp;&nbsp;&nbsp;&nbsp;mul, <span class=\\\"comment\\\">// \\u4e58\\u6cd5</span><br>\\n                            &nbsp;&nbsp;&nbsp;&nbsp;div&nbsp;&nbsp;<span class=\\\"comment\\\">// \\u9664\\u6cd5</span><br>\\n                            };\\n                        </div>\\n                    </div>\\n                </div>\\n                <!-- \\u7ec3\\u4e602\\u5361\\u7247 -->\\n                <div class=\\\"content-card card-2\\\">\\n                    <div class=\\\"card-header\\\">\\n                        <div class=\\\"card-icon\\\">\\n                            <i class=\\\"fas fa-chart-bar\\\"></i>\\n                        </div>\\n                        <div class=\\\"card-title\\\">\\n                            <h3>\\u7ec3\\u4e602</h3>\\n                            <div class=\\\"subtitle\\\">\\u52a8\\u6001\\u5185\\u5b58\\u7ba1\\u7406</div>\\n                            <div class=\\\"card-difficulty\\\">\\n                                <span class=\\\"star\\\">\\u2605</span>\\n                                <span class=\\\"star\\\">\\u2605</span>\\n                                <span class=\\\"star\\\">\\u2605</span>\\n                            </div>\\n                        </div>\\n                    </div>\\n                    <div class=\\\"card-content\\\">\\n                        <ul class=\\\"task-list\\\">\\n                            <li>\\u4f7f\\u7528\\u52a8\\u6001\\u5185\\u5b58\\u7ba1\\u7406\\u5b66\\u751f\\u6210\\u7ee9\\u6570\\u7ec4</li>\\n                            <li>\\u5b9e\\u73b0\\u6570\\u7ec4\\u7684\\u52a8\\u6001\\u6269\\u5bb9\\u4e0e\\u7f29\\u5bb9</li>\\n                            <li>\\u6b63\\u786e\\u5904\\u7406\\u5185\\u5b58\\u5206\\u914d\\u5931\\u8d25\\u60c5\\u51b5</li>\\n                            <li>\\u907f\\u514d\\u5185\\u5b58\\u6cc4\\u6f0f\\u4e0e\\u91ce\\u6307\\u9488</li>\\n                        </ul>\\n                        <div class=\\\"chart-container\\\">\\n                            <canvas id=\\\"memoryChart\\\"></canvas>\\n                        </div>\\n                        <div class=\\\"thinking-points\\\">\\n                            <p><strong>\\u5173\\u952e\\u70b9\\uff1a</strong>malloc/free\\u7684\\u6b63\\u786e\\u4f7f\\u7528\\uff0c\\u6307\\u9488\\u6709\\u6548\\u6027\\u68c0\\u67e5\\uff0c\\u5185\\u5b58\\u8fb9\\u754c\\u7ba1\\u7406\\u3002</p>\\n                        </div>\\n                    </div>\\n                </div>\\n                <!-- \\u601d\\u8003\\u9898\\u5361\\u7247 -->\\n                <div class=\\\"content-card card-3\\\">\\n                    <div class=\\\"card-header\\\">\\n                        <div class=\\\"card-icon\\\">\\n                            <i class=\\\"fas fa-brain\\\"></i>\\n                        </div>\\n                        <div class=\\\"card-title\\\">\\n                            <h3>\\u601d\\u8003</h3>\\n                            <div class=\\\"subtitle\\\">\\u5927\\u578b\\u9879\\u76ee\\u4e2d\\u7684\\u91cd\\u8981\\u6027</div>\\n                            <div class=\\\"card-difficulty\\\">\\n                                <span class=\\\"star\\\">\\u2605</span>\\n                                <span class=\\\"star\\\">\\u2605</span>\\n                                <span class=\\\"star\\\" style=\\\"color:#ddd\\\">\\u2605</span>\\n                            </div>\\n                        </div>\\n                    </div>\\n                    <div class=\\\"card-content\\\">\\n                        <div class=\\\"thinking-points\\\">\\n                            <p>\\u6307\\u9488\\u4e0e\\u5185\\u5b58\\u7ba1\\u7406\\u5728\\u5927\\u578b\\u8f6f\\u4ef6\\u9879\\u76ee\\u4e2d\\u7684\\u5173\\u952e\\u4f5c\\u7528\\uff1a</p>\\n                            <p>\\u2022 \\u6a21\\u5757\\u95f4\\u6570\\u636e\\u4f20\\u9012\\u7684\\u6548\\u7387\\u4f18\\u5316</p>\\n                            <p>\\u2022 \\u8d44\\u6e90\\u7ba1\\u7406\\u7684\\u5b89\\u5168\\u6027\\u4e0e\\u53ef\\u9760\\u6027</p>\\n                            <p>\\u2022 \\u7cfb\\u7edf\\u6027\\u80fd\\u7684\\u5173\\u952e\\u5f71\\u54cd\\u56e0\\u7d20</p>\\n                            <p>\\u2022 \\u4ee3\\u7801\\u53ef\\u7ef4\\u62a4\\u6027\\u7684\\u8bbe\\u8ba1\\u8003\\u91cf</p>\\n                            <span class=\\\"question\\\">\\u5f15\\u5bfc\\u6027\\u95ee\\u9898\\uff1a</span>\\n                            <p>\\u4f60\\u9047\\u5230\\u8fc7\\u54ea\\u4e9b\\u5185\\u5b58\\u7ba1\\u7406\\u95ee\\u9898\\uff1f\\u5982\\u4f55\\u8bbe\\u8ba1\\u53ef\\u7ef4\\u62a4\\u7684\\u6307\\u9488\\u63a5\\u53e3\\uff1f</p>\\n                        </div>\\n                        <div style=\\\"margin-top: 20px; padding: 12px; background: #f0f7ed; border-radius: 10px;\\\">\\n                            <p style=\\\"font-size: 13px; color: #5a7a55; text-align: center;\\\">\\n                                <i class=\\\"fas fa-lightbulb\\\" style=\\\"color: #FFC107; margin\", \"is_user_edited\": false}, {\"page_number\": 10, \"title\": \"\\u603b\\u7ed3\\u4e0eQ&A\", \"html_content\": \"<!DOCTYPE html>\\n<html lang=\\\"zh-CN\\\">\\n<head>\\n    <meta charset=\\\"UTF-8\\\">\\n    <meta name=\\\"viewport\\\" content=\\\"width=device-width, initial-scale=1.0\\\">\\n    <title>\\u603b\\u7ed3\\u4e0eQ&A - C\\u8bed\\u8a00\\u7b2c\\u56db\\u6b21\\u8bfe</title>\\n    <link rel=\\\"stylesheet\\\" href=\\\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css\\\">\\n    <script src=\\\"https://cdn.jsdelivr.net/npm/chart.js\\\"></script>\\n    <script src=\\\"https://polyfill.io/v3/polyfill.min.js?features=es6\\\"></script>\\n    <script id=\\\"MathJax-script\\\" async src=\\\"https://cdn.jsdelivr.net/npm/mathjax@3/es5/tex-mml-chtml.js\\\"></script>\\n    <script src=\\\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/prism.min.js\\\"></script>\\n    <link rel=\\\"stylesheet\\\" href=\\\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/themes/prism-tomorrow.min.css\\\">\\n    <style>\\n        * {\\n            margin: 0;\\n            padding: 0;\\n            box-sizing: border-box;\\n        }\\n        html, body {\\n            width: 100%;\\n            height: 100%;\\n            overflow: hidden;\\n            background: #edf1eb;\\n            font-family: \\\"Microsoft YaHei\\\", \\\"PingFang SC\\\", \\\"Noto Sans SC\\\", sans-serif;\\n            color: #335239;\\n        }\\n        .slide-container {\\n            width: 100vw;\\n            height: 100vh;\\n            display: flex;\\n            align-items: center;\\n            justify-content: center;\\n        }\\n        .slide {\\n            width: 1280px;\\n            height: 720px;\\n            position: relative;\\n            overflow: hidden;\\n            transform-origin: center center;\\n            border-radius: 16px;\\n            background: linear-gradient(180deg, #f8faf6 0%, #f2f5ef 100%);\\n            box-shadow: 0 18px 42px rgba(0,0,0,.14);\\n        }\\n        /* \\u9875\\u7709 - \\u4e25\\u683c\\u4fdd\\u6301\\u539f\\u6837 */\\n        .header {\\n            position: absolute;\\n            left: 30px;\\n            right: 30px;\\n            top: 24px;\\n            display: grid;\\n            grid-template-columns: 1fr auto;\\n            gap: 20px;\\n            align-items: start;\\n            z-index: 30;\\n        }\\n        .header h1 {\\n            font-size: 28px;\\n            line-height: 1.2;\\n            color: #48724a;\\n            font-weight: 900;\\n            letter-spacing: .4px;\\n        }\\n        .header p {\\n            margin-top: 7px;\\n            font-size: 12px;\\n            color: #7e8e7f;\\n            line-height: 1.55;\\n            max-width: 650px;\\n        }\\n        .main-tabs {\\n            display: flex;\\n            gap: 10px;\\n            align-items: center;\\n            flex-wrap: wrap;\\n            justify-content: flex-end;\\n        }\\n        .main-tab {\\n            border: 1px solid rgba(90,121,80,.18);\\n            background: rgba(255,255,255,.92);\\n            color: #5f7860;\\n            border-radius: 999px;\\n            padding: 9px 16px;\\n            font-size: 14px;\\n            font-weight: 800;\\n            cursor: pointer;\\n            transition: all .18s ease;\\n        }\\n        .main-tab.active {\\n            background: #4e7b47;\\n            color: #fff;\\n            box-shadow: 0 8px 18px rgba(78,123,71,.28);\\n        }\\n        /* \\u4e3b\\u8981\\u5185\\u5bb9\\u533a\\u57df */\\n        .main-content {\\n            position: absolute;\\n            left: 28px;\\n            right: 28px;\\n            top: 98px;\\n            bottom: 26px;\\n            display: flex;\\n            flex-direction: column;\\n            gap: 20px;\\n            padding: 20px 0;\\n        }\\n        /* \\u9875\\u9762\\u6807\\u9898 */\\n        .page-title {\\n            text-align: center;\\n            margin-bottom: 10px;\\n        }\\n        .page-title h2 {\\n            font-size: 42px;\\n            color: #4e874c;\\n            font-weight: 900;\\n            letter-spacing: 1px;\\n            text-shadow: 0 2px 4px rgba(0,0,0,0.08);\\n            position: relative;\\n            display: inline-block;\\n        }\\n        .page-title h2::after {\\n            content: \'\';\\n            position: absolute;\\n            bottom: -8px;\\n            left: 10%;\\n            width: 80%;\\n            height: 4px;\\n            background: linear-gradient(90deg, transparent, #7da965, transparent);\\n            border-radius: 2px;\\n        }\\n        /* \\u5185\\u5bb9\\u5bb9\\u5668 */\\n        .content-container {\\n            display: flex;\\n            flex: 1;\\n            gap: 20px;\\n            height: calc(100% - 80px);\\n        }\\n        /* \\u5de6\\u4fa7\\u603b\\u7ed3\\u533a\\u57df */\\n        .summary-section {\\n            flex: 1;\\n            display: flex;\\n            flex-direction: column;\\n            gap: 20px;\\n        }\\n        .summary-card {\\n            background: rgba(255,255,255,0.95);\\n    