% { transform: scale(1); }\\n        }\\n        .qa-icon i {\\n            font-size: 36px;\\n            color: white;\\n        }\\n        .qa-text {\\n            max-width: 80%;\\n        }\\n        .qa-text h3 {\\n            font-size: 20px;\\n            color: #1890ff;\\n            margin-bottom: 12px;\\n            font-weight: 900;\\n        }\\n        .qa-text p {\\n            font-size: 14px;\\n            color: #607163;\\n            line-height: 1.6;\\n            margin-bottom: 16px;\\n        }\\n        .qa-actions {\\n            display: flex;\\n            gap: 12px;\\n            margin-top: 10px;\\n        }\\n        .qa-button {\\n            padding: 10px 20px;\\n            border-radius: 50px;\\n            background: #1890ff;\\n            color: white;\\n            font-weight: bold;\\n            border: none;\\n            cursor: pointer;\\n            transition: all 0.3s ease;\\n            display: flex;\\n            align-items: center;\\n            gap: 8px;\\n        }\\n        .qa-button:hover {\\n            background: #096dd9;\\n            transform: translateY(-2px);\\n            box-shadow: 0 4px 12px rgba(25,144,255,0.3);\\n        }\\n        .qa-button.secondary {\\n            background: #f0f9eb;\\n            color: #52c41a;\\n            border: 1px solid #b7eb8f;\\n        }\\n        .qa-button.secondary:hover {\\n            background: #d9f7be;\\n        }\\n        /* \\u53c2\\u8003\\u8d44\\u6599\\u533a\\u57df */\\n        .resources-card {\\n            flex: 1;\\n            background: rgba(255,255,255,0.95);\\n            border-radius: 20px;\\n            padding: 24px;\\n            box-shadow: 0 8px 24px rgba(114,46,209,0.12);\\n            border: 1px solid rgba(114,46,209,.15);\\n            display: flex;\\n            flex-direction: column;\\n        }\\n        .resources-content {\\n            flex: 1;\\n            display: flex;\\n            flex-direction: column;\\n            