INSERT INTO `slide_data` VALUES (1,'d438f8e2-19a5-487e-9b54-16c4c04baed8',0,'slide_0','传承千年智慧，守护未来健康','content','<!DOCTYPE html>\n<html lang=\"zh-CN\">\n<head>\n    <meta charset=\"UTF-8\">\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n    <title>传承千年智慧，守护未来健康 - 中医养生商业计划</title>\n    <!-- Font Awesome 图标库 -->\n    <link rel=\"stylesheet\" href=\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css\">\n    <!-- 图表库预留 (Chart.js示例) -->\n    <!-- <script src=\"https://cdn.jsdelivr.net/npm/chart.js\"></script> -->\n    <style>\n        /* 全局重置与基础样式 */\n        * { margin: 0; padding: 0; box-sizing: border-box; }\n        body {\n            font-family: -apple-system, BlinkMacSystemFont, \"Segoe UI\", \"Microsoft YaHei\", sans-serif;\n            background: linear-gradient(135deg, #f5f7fa 0%, #e4edf5 100%);\n            display: flex;\n            justify-content: center;\n            align-items: center;\n            min-height: 100vh;\n            overflow: hidden;\n            padding: 20px;\n        }\n        \n        /* 主容器：固定1280x720，16:9 */\n        .slide-container {\n            width: 1280px;\n            height: 720px;\n            background-color: #F8F4E9;\n            background-image: \n                radial-gradient(circle at 10% 20%, rgba(212, 232, 217, 0.2) 0%, transparent 20%),\n                radial-gradient(circle at 90% 80%, rgba(212, 232, 217, 0.2) 0%, transparent 20%);\n            position: relative;\n            box-shadow: 0 20px 60px rgba(42, 92, 85, 0.15);\n            border-radius: 8px;\n            overflow: hidden;\n            display: flex;\n            flex-direction: column;\n        }\n        \n        /* 顶部标题栏 */\n        .header {\n            background: linear-gradient(90deg, #2A5C55 0%, #3A7C6F 100%);\n            color: white;\n            padding: 24px 40px;\n            position: relative;\n            min-height: 100px;\n            display: flex;\n            align-items: center;\n        }\n        .header::after {\n            content: \"\";\n            position: absolute;\n            bottom: 0;\n            left: 5%;\n            width: 90%;\n            height: 2px;\n            background: linear-gradient(90deg, transparent, #D4E8D9, transparent);\n        }\n        .title {\n            font-family: \"Noto Serif SC\", \"Source Han Serif\", serif;\n            font-size: 36px;\n            font-weight: 700;\n            line-height: 1.2;\n            flex: 1;\n        }\n        .subtitle {\n            font-size: 18px;\n            opacity: 0.9;\n            margin-top: 8px;\n            font-weight: 300;\n        }\n        .logo {\n            font-size: 24px;\n            margin-left: 30px;\n            color: #D4E8D9;\n        }\n        \n        /* 内容区域 - 首页特殊样式 */\n        .content {\n            flex: 1;\n            padding: 40px;\n            overflow: hidden;\n            position: relative;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n        }\n        \n        /* 首页主视觉容器 */\n        .hero-container {\n            width: 100%;\n            height: 100%;\n            display: flex;\n            flex-direction: column;\n            align-items: center;\n            justify-content: center;\n            position: relative;\n            z-index: 2;\n        }\n        \n        /* 主标题强化 */\n        .hero-title {\n            font-family: \"Noto Serif SC\", \"Source Han Serif\", serif;\n            font-size: 64px;\n            font-weight: 800;\n            color: #2A5C55;\n            text-align: center;\n            line-height: 1.2;\n            margin-bottom: 30px;\n            text-shadow: 2px 2px 4px rgba(0, 0, 0, 0.05);\n            position: relative;\n            padding: 0 40px;\n        }\n        \n        .hero-title span {\n            display: block;\n        }\n        \n        .hero-title .line1 {\n            font-size: 64px;\n            color: #2A5C55;\n        }\n        \n        .hero-title .line2 {\n            font-size: 56px;\n            color: #B3543A;\n            margin-top: 10px;\n        }\n        \n        /* 副标题区域 */\n        .hero-subtitle {\n            font-size: 28px;\n            color: #3A7C6F;\n            text-align: center;\n            margin-bottom: 40px;\n            font-weight: 500;\n            max-width: 900px;\n            line-height: 1.4;\n            padding: 0 40px;\n        }\n        \n        /* 信息卡片 */\n        .info-card {\n            background: rgba(255, 255, 255, 0.92);\n            border-radius: 16px;\n            padding: 30px 40px;\n            box-shadow: 0 15px 40px rgba(42, 92, 85, 0.12);\n            border-top: 4px solid #B3543A;\n            max-width: 800px;\n            text-align: center;\n            margin-bottom: 30px;\n            backdrop-filter: blur(10px);\n        }\n        \n        .info-card h3 {\n            font-size: 24px;\n            color: #2A5C55;\n            margin-bottom: 15px;\n            font-weight: 600;\n        }\n        \n        .info-card p {\n            font-size: 20px;\n            color: #444;\n            line-height: 1.5;\n            margin-bottom: 0;\n        }\n        \n        /* 底部信息 */\n        .presenter-info {\n            display: flex;\n            justify-content: center;\n            gap: 60px;\n            margin-top: 20px;\n            font-size: 20px;\n            color: #555;\n        }\n        \n        .presenter-item {\n            display: flex;\n            align-items: center;\n            gap: 10px;\n        }\n        \n        .presenter-icon {\n            color: #B3543A;\n            font-size: 22px;\n        }\n        \n        /* 装饰元素增强 */\n        .decoration {\n            position: absolute;\n            opacity: 0.08;\n            pointer-events: none;\n            z-index: 1;\n        }\n        \n        .decoration-1 {\n            top: 15%;\n            right: 5%;\n            font-size: 200px;\n            color: #2A5C55;\n            transform: rotate(15deg);\n        }\n        \n        .decoration-2 {\n            bottom: 20%;\n            left: 5%;\n            font-size: 150px;\n            color: #B3543A;\n            transform: rotate(-10deg);\n        }\n        \n        .decoration-3 {\n            top: 25%;\n            left: 8%;\n            font-size: 120px;\n            color: #3A7C6F;\n            transform: rotate(-5deg);\n        }\n        \n        .decoration-4 {\n            bottom: 30%;\n            right: 10%;\n            font-size: 100px;\n            color: #2A5C55;\n            transform: rotate(20deg);\n        }\n        \n        /* 背景纹理 */\n        .texture-overlay {\n            position: absolute;\n            top: 0;\n            left: 0;\n            width: 100%;\n            height: 100%;\n            background-image: url(\'data:image/svg+xml;utf8,<svg xmlns=\"http://www.w3.org/2000/svg\" width=\"200\" height=\"200\" viewBox=\"0 0 200 200\"><path d=\"M50,100 C50,50 150,50 150,100 C150,150 50,150 50,100 Z\" fill=\"none\" stroke=\"%232A5C55\" stroke-width=\"0.5\" opacity=\"0.03\"/><path d=\"M100,50 C150,50 150,150 100,150 C50,150 50,50 100,50 Z\" fill=\"none\" stroke=\"%23B3543A\" stroke-width=\"0.5\" opacity=\"0.03\"/></svg>\');\n            background-size: 400px;\n            opacity: 0.3;\n            z-index: 0;\n        }\n        \n        /* 页脚 */\n        .footer {\n            background: rgba(42, 92, 85, 0.05);\n            padding: 16px 40px;\n            display: flex;\n            justify-content: space-between;\n            align-items: center;\n            border-top: 1px solid rgba(42, 92, 85, 0.1);\n            font-size: 14px;\n            color: #555;\n        }\n        .pagination {\n            font-weight: 600;\n            color: #2A5C55;\n        }\n        .brand {\n            display: flex;\n            align-items: center;\n            gap: 10px;\n        }\n        .brand-icon {\n            color: #B3543A;\n        }\n        \n        /* 响应式：保持16:9比例缩放 */\n        @media (max-width: 1350px) {\n            body { transform: scale(0.9); }\n        }\n        @media (max-width: 1150px) {\n            body { transform: scale(0.8); }\n        }\n        @media (max-width: 900px) {\n            body { transform: scale(0.7); }\n        }\n    </style>\n</head>\n<body>\n    <div class=\"slide-container\">\n        <!-- 背景纹理 -->\n        <div class=\"texture-overlay\"></div>\n        \n        <!-- 装饰元素增强 -->\n        <div class=\"decoration decoration-1\">\n            <i class=\"fas fa-leaf\"></i>\n        </div>\n        <div class=\"decoration decoration-2\">\n            <i class=\"fas fa-yin-yang\"></i>\n        </div>\n        <div class=\"decoration decoration-3\">\n            <i class=\"fas fa-seedling\"></i>\n        </div>\n        <div class=\"decoration decoration-4\">\n            <i class=\"fas fa-heartbeat\"></i>\n        </div>\n        \n        <!-- 顶部标题栏 -->\n        <div class=\"header\">\n            <div>\n                <div class=\"title\">传承千年智慧，守护未来健康</div>\n                <div class=\"subtitle\">中医养生在儿童科普教育中的价值与机遇</div>\n            </div>\n            <div class=\"logo\">\n                <i class=\"fas fa-hand-holding-heart\"></i>\n            </div>\n        </div>\n        \n        <!-- 主内容区 - 首页特殊设计 -->\n        <div class=\"content\">\n            <div class=\"hero-container\">\n                <!-- 主标题 -->\n                <div class=\"hero-title\">\n                    <span class=\"line1\">传承千年智慧</span>\n                    <span class=\"line2\">守护未来健康</span>\n                </div>\n                \n                <!-- 副标题 -->\n                <div class=\"hero-subtitle\">\n                    中医养生在儿童科普教育中的价值与机遇\n                </div>\n                \n                <!-- 信息卡片 -->\n                <div class=\"info-card\">\n                    <h3>面向投资人的商业计划简报</h3>\n                    <p>将传统中医智慧转化为儿童健康教育创新解决方案</p>\n                </div>\n                \n                <!-- 主讲人信息 -->\n                <div class=\"presenter-info\">\n                    <div class=\"presenter-item\">\n                        <i class=\"fas fa-user-tie presenter-icon\"></i>\n                        <span>主讲人：[您的姓名/机构名称]</span>\n                    </div>\n                    <div class=\"presenter-item\">\n                        <i class=\"fas fa-calendar-alt presenter-icon\"></i>\n                        <span>日期：[当前日期]</span>\n                    </div>\n                </div>\n            </div>\n        </div>\n        \n        <!-- 页脚 -->\n        <div class=\"footer\">\n            <div class=\"brand\">\n                <i class=\"fas fa-seedling brand-icon\"></i>\n                <span>传承千年智慧 · 守护未来健康</span>\n            </div>\n            <div class=\"pagination\">\n                第 <span class=\"highlight\">1</span> 页 / 共 15 页\n            </div>\n            <div>\n                主讲人：[您的姓名/机构名称] · 日期：[当前日期]\n            </div>\n        </div>\n    </div>\n</body>\n</html>','{}',NULL,0,1773280000,1773280000),(2,'d438f8e2-19a5-487e-9b54-16c4c04baed8',1,'slide_1','目录：我们的蓝图','content','<!DOCTYPE html>\n<html lang=\"zh-CN\">\n<head>\n    <meta charset=\"UTF-8\">\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n    <title>目录：我们的蓝图 - 中医养生商业计划</title>\n    <!-- Font Awesome 图标库 -->\n    <link rel=\"stylesheet\" href=\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css\">\n    <style>\n        /* 全局重置与基础样式 */\n        * { margin: 0; padding: 0; box-sizing: border-box; }\n        body {\n            font-family: -apple-system, BlinkMacSystemFont, \"Segoe UI\", \"Microsoft YaHei\", sans-serif;\n            background: linear-gradient(135deg, #f5f7fa 0%, #e4edf5 100%);\n            display: flex;\n            justify-content: center;\n            align-items: center;\n            min-height: 100vh;\n            overflow: hidden;\n            padding: 20px;\n        }\n        \n        /* 主容器：固定1280x720，16:9 */\n        .slide-container {\n            width: 1280px;\n            height: 720px;\n            background-color: #F8F4E9;\n            background-image: \n                radial-gradient(circle at 10% 20%, rgba(212, 232, 217, 0.2) 0%, transparent 20%),\n                radial-gradient(circle at 90% 80%, rgba(212, 232, 217, 0.2) 0%, transparent 20%);\n            position: relative;\n            box-shadow: 0 20px 60px rgba(42, 92, 85, 0.15);\n            border-radius: 8px;\n            overflow: hidden;\n            display: flex;\n            flex-direction: column;\n        }\n        \n        /* 顶部标题栏 */\n        .header {\n            background: linear-gradient(90deg, #2A5C55 0%, #3A7C6F 100%);\n            color: white;\n            padding: 24px 40px;\n            position: relative;\n            min-height: 100px;\n            display: flex;\n            align-items: center;\n        }\n        .header::after {\n            content: \"\";\n            position: absolute;\n            bottom: 0;\n            left: 5%;\n            width: 90%;\n            height: 2px;\n            background: linear-gradient(90deg, transparent, #D4E8D9, transparent);\n        }\n        .title {\n            font-family: \"Noto Serif SC\", \"Source Han Serif\", serif;\n            font-size: 36px;\n            font-weight: 700;\n            line-height: 1.2;\n            flex: 1;\n        }\n        .subtitle {\n            font-size: 18px;\n            opacity: 0.9;\n            margin-top: 8px;\n            font-weight: 300;\n        }\n        .logo {\n            font-size: 24px;\n            margin-left: 30px;\n            color: #D4E8D9;\n        }\n        \n        /* 内容区域 */\n        .content {\n            flex: 1;\n            padding: 40px;\n            overflow: hidden;\n            position: relative;\n        }\n        .content-inner {\n            height: 100%;\n            display: flex;\n            flex-direction: column;\n            justify-content: center;\n        }\n        \n        /* 页脚 */\n        .footer {\n            background: rgba(42, 92, 85, 0.05);\n            padding: 16px 40px;\n            display: flex;\n            justify-content: space-between;\n            align-items: center;\n            border-top: 1px solid rgba(42, 92, 85, 0.1);\n            font-size: 14px;\n            color: #555;\n        }\n        .pagination {\n            font-weight: 600;\n            color: #2A5C55;\n        }\n        .brand {\n            display: flex;\n            align-items: center;\n            gap: 10px;\n        }\n        .brand-icon {\n            color: #B3543A;\n        }\n        \n        /* 装饰元素 */\n        .decoration {\n            position: absolute;\n            opacity: 0.05;\n            pointer-events: none;\n        }\n        .decoration-1 {\n            top: 15%;\n            right: 5%;\n            font-size: 180px;\n            color: #2A5C55;\n            transform: rotate(15deg);\n        }\n        .decoration-2 {\n            bottom: 20%;\n            left: 5%;\n            font-size: 120px;\n            color: #B3543A;\n            transform: rotate(-10deg);\n        }\n        \n        /* 目录页专属样式 */\n        .agenda-container {\n            display: flex;\n            height: 100%;\n            align-items: center;\n            position: relative;\n            z-index: 2;\n        }\n        \n        .agenda-timeline {\n            flex: 0 0 80px;\n            height: 480px;\n            position: relative;\n            margin-right: 40px;\n        }\n        \n        .timeline-line {\n            position: absolute;\n            left: 50%;\n            top: 0;\n            transform: translateX(-50%);\n            width: 4px;\n            height: 100%;\n            background: linear-gradient(to bottom, #2A5C55, #3A7C6F, #B3543A);\n            border-radius: 2px;\n        }\n        \n        .timeline-nodes {\n            position: absolute;\n            left: 0;\n            top: 0;\n            width: 100%;\n            height: 100%;\n        }\n        \n        .timeline-node {\n            position: absolute;\n            left: 50%;\n            transform: translateX(-50%);\n            width: 24px;\n            height: 24px;\n            border-radius: 50%;\n            background-color: #F8F4E9;\n            border: 3px solid #2A5C55;\n            z-index: 2;\n            transition: all 0.3s ease;\n        }\n        \n        .timeline-node.active {\n            background-color: #B3543A;\n            border-color: #B3543A;\n            box-shadow: 0 0 0 6px rgba(179, 84, 58, 0.2);\n        }\n        \n        .agenda-content {\n            flex: 1;\n            display: flex;\n            flex-direction: column;\n            justify-content: center;\n            height: 480px;\n        }\n        \n        .agenda-item {\n            display: flex;\n            align-items: center;\n            margin-bottom: 28px;\n            padding: 16px 24px;\n            background: rgba(255, 255, 255, 0.85);\n            border-radius: 12px;\n            box-shadow: 0 4px 12px rgba(42, 92, 85, 0.08);\n            border-left: 4px solid #2A5C55;\n            transition: all 0.3s ease;\n            position: relative;\n            overflow: hidden;\n        }\n        \n        .agenda-item:hover {\n            transform: translateX(8px);\n            box-shadow: 0 6px 20px rgba(42, 92, 85, 0.15);\n            border-left-color: #B3543A;\n        }\n        \n        .agenda-item::before {\n            content: \"\";\n            position: absolute;\n            left: 0;\n            top: 0;\n            width: 100%;\n            height: 100%;\n            background: linear-gradient(90deg, rgba(212, 232, 217, 0.1) 0%, transparent 100%);\n            opacity: 0;\n            transition: opacity 0.3s ease;\n        }\n        \n        .agenda-item:hover::before {\n            opacity: 1;\n        }\n        \n        .item-number {\n            font-family: \"Noto Serif SC\", serif;\n            font-size: 28px;\n            font-weight: 700;\n            color: #2A5C55;\n            margin-right: 20px;\n            min-width: 40px;\n        }\n        \n        .item-content {\n            flex: 1;\n        }\n        \n        .item-title {\n            font-size: 22px;\n            font-weight: 600;\n            color: #2A5C55;\n            margin-bottom: 4px;\n            line-height: 1.3;\n        }\n        \n        .item-subtitle {\n            font-size: 16px;\n            color: #666;\n            font-weight: 300;\n            line-height: 1.4;\n        }\n        \n        .item-icon {\n            font-size: 24px;\n            color: #3A7C6F;\n            margin-left: 20px;\n            transition: all 0.3s ease;\n        }\n        \n        .agenda-item:hover .item-icon {\n            color: #B3543A;\n            transform: scale(1.1);\n        }\n        \n        .agenda-title {\n            position: absolute;\n            top: 40px;\n            left: 40px;\n            font-family: \"Noto Serif SC\", serif;\n            font-size: 32px;\n            font-weight: 700;\n            color: #2A5C55;\n            margin-bottom: 30px;\n            padding-bottom: 10px;\n            border-bottom: 2px solid rgba(179, 84, 58, 0.3);\n            width: calc(100% - 80px);\n        }\n        \n        .agenda-subtitle {\n            position: absolute;\n            bottom: 40px;\n            right: 40px;\n            font-size: 16px;\n            color: #666;\n            font-style: italic;\n            text-align: right;\n            max-width: 400px;\n            line-height: 1.5;\n            padding: 12px 20px;\n            background: rgba(255, 255, 255, 0.7);\n            border-radius: 8px;\n            border-left: 3px solid #3A7C6F;\n        }\n        \n        /* 响应式：保持16:9比例缩放 */\n        @media (max-width: 1350px) {\n            body { transform: scale(0.9); }\n        }\n        @media (max-width: 1150px) {\n            body { transform: scale(0.8); }\n        }\n        @media (max-width: 900px) {\n            body { transform: scale(0.7); }\n        }\n    </style>\n</head>\n<body>\n    <div class=\"slide-container\">\n        <!-- 装饰元素 -->\n        <div class=\"decoration decoration-1\">\n            <i class=\"fas fa-leaf\"></i>\n        </div>\n        <div class=\"decoration decoration-2\">\n            <i class=\"fas fa-yin-yang\"></i>\n        </div>\n        \n        <!-- 顶部标题栏 -->\n        <div class=\"header\">\n            <div>\n                <div class=\"title\">目录：我们的蓝图</div>\n                <div class=\"subtitle\">中医养生在儿童科普教育中的价值与机遇</div>\n            </div>\n            <div class=\"logo\">\n                <i class=\"fas fa-hand-holding-heart\"></i>\n            </div>\n        </div>\n        \n        <!-- 主内容区 -->\n        <div class=\"content\">\n            <div class=\"content-inner\">\n                <!-- 目录页专属内容 -->\n                <div class=\"agenda-title\">我们的蓝图：六大核心模块</div>\n                \n                <div class=\"agenda-container\">\n                    <div class=\"agenda-timeline\">\n                        <div class=\"timeline-line\"></div>\n                        <div class=\"timeline-nodes\">\n                            <div class=\"timeline-node\" style=\"top: 0%;\"></div>\n                            <div class=\"timeline-node\" style=\"top: 20%;\"></div>\n                            <div class=\"timeline-node active\" style=\"top: 40%;\"></div>\n                            <div class=\"timeline-node\" style=\"top: 60%;\"></div>\n                            <div class=\"timeline-node\" style=\"top: 80%;\"></div>\n                            <div class=\"timeline-node\" style=\"top: 100%;\"></div>\n                        </div>\n                    </div>\n                    \n                    <div class=\"agenda-content\">\n                        <div class=\"agenda-item\">\n                            <div class=\"item-number\">一</div>\n                            <div class=\"item-content\">\n                                <div class=\"item-title\">市场洞察：为何是儿童中医养生科普？</div>\n                                <div class=\"item-subtitle\">儿童健康市场的时代机遇与需求分析</div>\n                            </div>\n                            <div class=\"item-icon\">\n                                <i class=\"fas fa-search\"></i>\n                            </div>\n                        </div>\n                        \n                        <div class=\"agenda-item\">\n                            <div class=\"item-number\">二</div>\n                            <div class=\"item-content\">\n                                <div class=\"item-title\">核心理念：中医养生的四大基石</div>\n                                <div class=\"item-subtitle\">融合传统智慧与现代教育的创新理念</div>\n                            </div>\n                            <div class=\"item-icon\">\n                                <i class=\"fas fa-yin-yang\"></i>\n                            </div>\n                        </div>\n                        \n                        <div class=\"agenda-item\">\n                            <div class=\"item-number\">三</div>\n                            <div class=\"item-content\">\n                                <div class=\"item-title\">产品方案：寓教于乐的科普体系</div>\n                                <div class=\"item-subtitle\">互动式、场景化、多媒介的产品矩阵</div>\n                            </div>\n                            <div class=\"item-icon\">\n                                <i class=\"fas fa-puzzle-piece\"></i>\n                            </div>\n                        </div>\n                        \n                        <div class=\"agenda-item\">\n                            <div class=\"item-number\">四</div>\n                            <div class=\"item-content\">\n                                <div class=\"item-title\">商业模式与市场潜力</div>\n                                <div class=\"item-subtitle\">可持续增长的双轮驱动与盈利路径</div>\n                            </div>\n                            <div class=\"item-icon\">\n                                <i class=\"fas fa-chart-line\"></i>\n                            </div>\n                        </div>\n                        \n                        <div class=\"agenda-item\">\n                            <div class=\"item-number\">五</div>\n                            <div class=\"item-content\">\n                                <div class=\"item-title\">团队优势与执行规划</div>\n                                <div class=\"item-subtitle\">跨界融合的专业团队与清晰路线图</div>\n                            </div>\n                            <div class=\"item-icon\">\n                                <i class=\"fas fa-users\"></i>\n                            </div>\n                        </div>\n                        \n                        <div class=\"agenda-item\">\n                            <div class=\"item-number\">六</div>\n                            <div class=\"item-content\">\n                                <div class=\"item-title\">投资价值与回报展望</div>\n                                <div class=\"item-subtitle\">可观回报、社会价值与长期潜力</div>\n                            </div>\n                            <div class=\"item-icon\">\n                                <i class=\"fas fa-gem\"></i>\n                            </div>\n                        </div>\n                    </div>\n                </div>\n                \n                <div class=\"agenda-subtitle\">\n                    从市场机遇到投资回报的完整闭环<br>\n                    <span style=\"color: #B3543A; font-weight: 500;\">预计汇报时间：25分钟 | 每个模块约4分钟</span>\n                </div>\n            </div>\n        </div>\n        \n        <!-- 页脚 -->\n        <div class=\"footer\">\n            <div class=\"brand\">\n                <i class=\"fas fa-seedling brand-icon\"></i>\n                <span>传承千年智慧 · 守护未来健康</span>\n            </div>\n            <div class=\"pagination\">\n                第 <span class=\"highlight\">2</span> 页 / 共 15 页\n            </div>\n            <div>\n                主讲人：[您的姓名/机构名称] · 日期：[当前日期]\n            </div>\n        </div>\n    </div>\n</body>\n</html>','{}',NULL,0,1773280000,1773280000),(3,'d438f8e2-19a5-487e-9b54-16c4c04baed8',2,'slide_2','一、市场洞察：亟待开发的蓝海','content','<!DOCTYPE html>\n<html lang=\"zh-CN\">\n<head>\n    <meta charset=\"UTF-8\">\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n    <title>一、市场洞察：亟待开发的蓝海 - 中医养生商业计划</title>\n    <!-- Font Awesome 图标库 -->\n    <link rel=\"stylesheet\" href=\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css\">\n    <!-- Chart.js 图表库 -->\n    <script src=\"https://cdn.jsdelivr.net/npm/chart.js\"></script>\n    <style>\n        /* 全局重置与基础样式 */\n        * { margin: 0; padding: 0; box-sizing: border-box; }\n        body {\n            font-family: -apple-system, BlinkMacSystemFont, \"Segoe UI\", \"Microsoft YaHei\", sans-serif;\n            background: linear-gradient(135deg, #f5f7fa 0%, #e4edf5 100%);\n            display: flex;\n            justify-content: center;\n            align-items: center;\n            min-height: 100vh;\n            overflow: hidden;\n            padding: 20px;\n        }\n        /* 主容器：固定1280x720，16:9 */\n        .slide-container {\n            width: 1280px;\n            height: 720px;\n            background-color: #F8F4E9;\n            background-image: \n                radial-gradient(circle at 10% 20%, rgba(212, 232, 217, 0.2) 0%, transparent 20%),\n                radial-gradient(circle at 90% 80%, rgba(212, 232, 217, 0.2) 0%, transparent 20%);\n            position: relative;\n            box-shadow: 0 20px 60px rgba(42, 92, 85, 0.15);\n            border-radius: 8px;\n            overflow: hidden;\n            display: flex;\n            flex-direction: column;\n        }\n        /* 顶部标题栏 */\n        .header {\n            background: linear-gradient(90deg, #2A5C55 0%, #3A7C6F 100%);\n            color: white;\n            padding: 24px 40px;\n            position: relative;\n            min-height: 100px;\n            display: flex;\n            align-items: center;\n        }\n        .header::after {\n            content: \"\";\n            position: absolute;\n            bottom: 0;\n            left: 5%;\n            width: 90%;\n            height: 2px;\n            background: linear-gradient(90deg, transparent, #D4E8D9, transparent);\n        }\n        .title {\n            font-family: \"Noto Serif SC\", \"Source Han Serif\", serif;\n            font-size: 36px;\n            font-weight: 700;\n            line-height: 1.2;\n            flex: 1;\n        }\n        .subtitle {\n            font-size: 18px;\n            opacity: 0.9;\n            margin-top: 8px;\n            font-weight: 300;\n        }\n        .logo {\n            font-size: 24px;\n            margin-left: 30px;\n            color: #D4E8D9;\n        }\n        /* 内容区域 */\n        .content {\n            flex: 1;\n            padding: 40px;\n            overflow: hidden;\n            position: relative;\n        }\n        .content-inner {\n            height: 100%;\n            display: flex;\n            flex-direction: column;\n        }\n        /* 页脚 */\n        .footer {\n            background: rgba(42, 92, 85, 0.05);\n            padding: 16px 40px;\n            display: flex;\n            justify-content: space-between;\n            align-items: center;\n            border-top: 1px solid rgba(42, 92, 85, 0.1);\n            font-size: 14px;\n            color: #555;\n        }\n        .pagination {\n            font-weight: 600;\n            color: #2A5C55;\n        }\n        .brand {\n            display: flex;\n            align-items: center;\n            gap: 10px;\n        }\n        .brand-icon {\n            color: #B3543A;\n        }\n        /* 装饰元素 */\n        .decoration {\n            position: absolute;\n            opacity: 0.05;\n            pointer-events: none;\n        }\n        .decoration-1 {\n            top: 15%;\n            right: 5%;\n            font-size: 180px;\n            color: #2A5C55;\n            transform: rotate(15deg);\n        }\n        .decoration-2 {\n            bottom: 20%;\n            left: 5%;\n            font-size: 120px;\n            color: #B3543A;\n            transform: rotate(-10deg);\n        }\n        /* 新增：创意设计样式 */\n        .market-insight-container {\n            display: flex;\n            flex-direction: column;\n            height: 100%;\n            gap: 25px;\n        }\n        .insight-header {\n            text-align: center;\n            margin-bottom: 10px;\n        }\n        .insight-header h1 {\n            color: #2A5C55;\n            font-size: 42px;\n            margin-bottom: 8px;\n            position: relative;\n            display: inline-block;\n        }\n        .insight-header h1::after {\n            content: \"\";\n            position: absolute;\n            bottom: -5px;\n            left: 10%;\n            width: 80%;\n            height: 3px;\n            background: linear-gradient(90deg, transparent, #B3543A, transparent);\n        }\n        .insight-header p {\n            color: #666;\n            font-size: 18px;\n            max-width: 800px;\n            margin: 0 auto;\n            line-height: 1.5;\n        }\n        .insight-content {\n            display: flex;\n            flex: 1;\n            gap: 30px;\n            height: calc(100% - 120px);\n        }\n        .insight-points {\n            flex: 1;\n            display: grid;\n            grid-template-columns: 1fr 1fr;\n            grid-template-rows: 1fr 1fr;\n            gap: 20px;\n        }\n        .insight-card {\n            background: white;\n            border-radius: 16px;\n            padding: 24px;\n            box-shadow: 0 10px 30px rgba(0, 0, 0, 0.08);\n            display: flex;\n            flex-direction: column;\n            transition: transform 0.3s ease, box-shadow 0.3s ease;\n            border-top: 5px solid;\n            position: relative;\n            overflow: hidden;\n        }\n        .insight-card:hover {\n            transform: translateY(-5px);\n            box-shadow: 0 15px 35px rgba(0, 0, 0, 0.12);\n        }\n        .insight-card::before {\n            content: \"\";\n            position: absolute;\n            top: 0;\n            left: 0;\n            right: 0;\n            height: 5px;\n            background: inherit;\n        }\n        .card-1 {\n            border-color: #E71D36;\n        }\n        .card-2 {\n            border-color: #2EC4B6;\n        }\n        .card-3 {\n            border-color: #6C757D;\n        }\n        .card-4 {\n            border-color: #FF9F1C;\n        }\n        .card-header {\n            display: flex;\n            align-items: center;\n            margin-bottom: 15px;\n        }\n        .card-icon {\n            width: 50px;\n            height: 50px;\n            border-radius: 12px;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            margin-right: 15px;\n            font-size: 22px;\n            color: white;\n        }\n        .icon-1 {\n            background: linear-gradient(135deg, #E71D36, #FF6B6B);\n        }\n        .icon-2 {\n            background: linear-gradient(135deg, #2EC4B6, #4ECDC4);\n        }\n        .icon-3 {\n            background: linear-gradient(135deg, #6C757D, #ADB5BD);\n        }\n        .icon-4 {\n            background: linear-gradient(135deg, #FF9F1C, #FFB347);\n        }\n        .card-title {\n            font-size: 20px;\n            font-weight: 700;\n            color: #2A5C55;\n            margin-bottom: 5px;\n        }\n        .card-subtitle {\n            font-size: 14px;\n            color: #666;\n            font-weight: 500;\n        }\n        .card-content {\n            flex: 1;\n            font-size: 16px;\n            line-height: 1.6;\n            color: #444;\n        }\n        .card-highlight {\n            color: #B3543A;\n            font-weight: 600;\n        }\n        .chart-section {\n            flex: 1;\n            display: flex;\n            flex-direction: column;\n        }\n        .chart-title {\n            font-size: 20px;\n            font-weight: 700;\n            color: #2A5C55;\n            margin-bottom: 15px;\n            text-align: center;\n        }\n        .chart-container {\n            background: white;\n            border-radius: 16px;\n            padding: 20px;\n            box-shadow: 0 10px 30px rgba(0, 0, 0, 0.08);\n            border: 1px solid rgba(42, 92, 85, 0.1);\n            flex: 1;\n            display: flex;\n            flex-direction: column;\n        }\n        .chart-wrapper {\n            flex: 1;\n            position: relative;\n        }\n        .chart-note {\n            font-size: 12px;\n            color: #888;\n            text-align: center;\n            margin-top: 10px;\n            font-style: italic;\n        }\n        /* 航海主题装饰 */\n        .ocean-wave {\n            position: absolute;\n            bottom: 0;\n            left: 0;\n            right: 0;\n            height: 20px;\n            background: linear-gradient(90deg, transparent, rgba(42, 92, 85, 0.1), transparent);\n            border-radius: 50%;\n            opacity: 0.3;\n        }\n        .compass {\n            position: absolute;\n            top: 50%;\n            right: 20px;\n            width: 60px;\n            height: 60px;\n            opacity: 0.1;\n            transform: translateY(-50%);\n        }\n        .compass i {\n            font-size: 60px;\n            color: #2A5C55;\n        }\n        /* 响应式：保持16:9比例缩放 */\n        @media (max-width: 1350px) {\n            body { transform: scale(0.9); }\n        }\n        @media (max-width: 1150px) {\n            body { transform: scale(0.8); }\n        }\n        @media (max-width: 900px) {\n            body { transform: scale(0.7); }\n        }\n    </style>\n</head>\n<body>\n    <div class=\"slide-container\">\n        <!-- 装饰元素 -->\n        <div class=\"decoration decoration-1\">\n            <i class=\"fas fa-leaf\"></i>\n        </div>\n        <div class=\"decoration decoration-2\">\n            <i class=\"fas fa-yin-yang\"></i>\n        </div>\n        <!-- 顶部标题栏 -->\n        <div class=\"header\">\n            <div>\n                <div class=\"title\">一、市场洞察：亟待开发的蓝海</div>\n                <div class=\"subtitle\">中医养生在儿童科普教育中的价值与机遇</div>\n            </div>\n            <div class=\"logo\">\n                <i class=\"fas fa-hand-holding-heart\"></i>\n            </div>\n        </div>\n        <!-- 主内容区 -->\n        <div class=\"content\">\n            <div class=\"market-insight-container\">\n                <div class=\"insight-header\">\n                    <h1>市场洞察：亟待开发的蓝海</h1>\n                    <p>发现儿童中医健康教育的巨大市场潜力与商业机遇</p>\n                </div>\n                <div class=\"insight-content\">\n                    <div class=\"insight-points\">\n                        <div class=\"insight-card card-1\">\n                            <div class=\"card-header\">\n                                <div class=\"card-icon icon-1\">\n                                    <i class=\"fas fa-exclamation-triangle\"></i>\n                                </div>\n                                <div>\n                                    <div class=\"card-title\">迫切痛点</div>\n                                    <div class=\"card-subtitle\">市场存在的核心问题</div>\n                                </div>\n                            </div>\n                            <div class=\"card-content\">\n                                儿童亚健康问题日益突出，<span class=\"card-highlight\">85%的家长</span>存在显著的健康焦虑，寻求专业解决方案的需求迫切。\n                            </div>\n                        </div>\n                        <div class=\"insight-card card-2\">\n                            <div class=\"card-header\">\n                                <div class=\"card-icon icon-2\">\n                                    <i class=\"fas fa-chart-line\"></i>\n                                </div>\n                                <div>\n                                    <div class=\"card-title\">双重趋势</div>\n                                    <div class=\"card-subtitle\">市场发展的有利环境</div>\n                                </div>\n                            </div>\n                            <div class=\"card-content\">\n                                传统文化复兴浪潮叠加国家政策对中医药的大力支持，<span class=\"card-highlight\">政策支持力度评分达90/100</span>，形成强大推动力。\n                            </div>\n                        </div>\n                        <div class=\"insight-card card-3\">\n                            <div class=\"card-header\">\n                                <div class=\"card-icon icon-3\">\n                                    <i class=\"fas fa-search-minus\"></i>\n                                </div>\n                                <div>\n                                    <div class=\"card-title\">市场空白</div>\n                                    <div class=\"card-subtitle\">未被满足的关键需求</div>\n                                </div>\n                            </div>\n                            <div class=\"card-content\">\n                                市场严重缺乏<span class=\"card-highlight\">\"专业×有趣×系统\"三位一体</span>的儿童中医科普内容，供给端存在明显缺口。\n                            </div>\n                        </div>\n                        <div class=\"insight-card card-4\">\n                            <div class=\"card-header\">\n                                <div class=\"card-icon icon-4\">\n                                    <i class=\"fas fa-gem\"></i>\n                                </div>\n                                <div>\n                                    <div class=\"card-title\">黄金机遇</div>\n                                    <div class=\"card-subtitle\">商业价值的集中体现</div>\n                                </div>\n                            </div>\n                            <div class=\"card-content\">\n                                健康消费年增长率<span class=\"card-highlight\">超过120%</span>，叠加家庭教育投资意愿强劲，市场潜力巨大且变现路径清晰。\n                            </div>\n                        </div>\n                    </div>\n                    <div class=\"chart-section\">\n                        <div class=\"chart-title\">核心市场驱动力分析</div>\n                        <div class=\"chart-container\">\n                            <div class=\"chart-wrapper\">\n                                <canvas id=\"marketChart\"></canvas>\n                            </div>\n                            <div class=\"chart-note\">数据来源：2023年市场调研报告，样本量N=1500</div>\n                        </div>\n                    </div>\n                </div>\n            </div>\n            <!-- 航海主题装饰 -->\n            <div class=\"ocean-wave\"></div>\n            <div class=\"compass\">\n                <i class=\"fas fa-compass\"></i>\n            </div>\n        </div>\n        <!-- 页脚 -->\n        <div class=\"footer\">\n            <div class=\"brand\">\n                <i class=\"fas fa-seedling brand-icon\"></i>\n                <span>传承千年智慧 · 守护未来健康</span>\n            </div>\n            <div class=\"pagination\">\n                第 <span class=\"highlight\">3</span> 页 / 共 15 页\n            </div>\n            <div>\n                主讲人：[您的姓名/机构名称] · 日期：[当前日期]\n            </div>\n        </div>\n    </div>\n    <script>\n        document.addEventListener(\'DOMContentLoaded\', function() {\n            const ctx = document.getElementById(\'marketChart\').getContext(\'2d\');\n            const gradient1 = ctx.createLinearGradient(0, 0, 400, 0);\n            gradient1.addColorStop(0, \'#FF9F1C\');\n            gradient1.addColorStop(1, \'#FFB347\');\n            const gradient2 = ctx.createLinearGradient(0, 0, 400, 0);\n            gradient2.addColorStop(0, \'#2EC4B6\');\n            gradient2.addColorStop(1, \'#4ECDC4\');\n            const gradient3 = ctx.createLinearGradient(0, 0, 400, 0);\n            gradient3.addColorStop(0, \'#E71D36\');\n            gradient3.addColorStop(1, \'#FF6B6B\');\n            const chart = new Chart(ctx, {\n                type: \'bar\',\n                data: {\n                    labels: [\'家长健康焦虑指数\', \'儿童中医内容搜索量年增长率\', \'政策支持力度（评分）\'],\n                    datasets: [{\n                        label: \'市场驱动力指标\',\n                        data: [85, 120, 90],\n                        backgroundColor: [gradient3, gradient2, gradient1],\n                        borderColor: [\'#CC7E15\', \'#23978F\', \'#B31526\'],\n                        borderWidth: 1,\n                        borderRadius: 8,\n                        borderSkipped: false,\n                    }]\n                },\n                options: {\n                    responsive: true,\n                    maintainAspectRatio: false,\n                    indexAxis: \'y\',\n                    plugins: {\n                        legend: {\n                            display: false\n                        },\n                        tooltip: {\n                            backgroundColor: \'rgba(42, 92, 85, 0.9)\',\n                            titleFont: {\n                                size: 14,\n                                family: \"\'Microsoft YaHei\', sans-serif\"\n                            },\n                            bodyFont: {\n                                size: 14,\n                                family: \"\'Microsoft YaHei\', sans-serif\"\n                            },\n                            padding: 12,\n                            cornerRadius: 8,\n                            callbacks: {\n           