nter-events: none;\n        }\n        .decoration-1 {\n            top: 15%;\n            right: 5%;\n            font-size: 180px;\n            color: #2A5C55;\n            transform: rotate(15deg);\n        }\n        .decoration-2 {\n            bottom: 20%;\n            left: 5%;\n            font-size: 120px;\n            color: #B3543A;\n            transform: rotate(-10deg);\n        }\n        \n        /* 新增样式：创意内容布局 */\n        .core-concept-container {\n            display: flex;\n            height: 100%;\n            align-items: center;\n            gap: 40px;\n        }\n        \n        .chart-section {\n            flex: 1;\n            height: 100%;\n            display: flex;\n            flex-direction: column;\n            justify-content: center;\n            align-items: center;\n        }\n        \n        .chart-wrapper {\n            position: relative;\n            width: 320px;\n            height: 320px;\n        }\n        \n        .chart-center {\n            position: absolute;\n            top: 50%;\n            left: 50%;\n            transform: translate(-50%, -50%);\n            width: 120px;\n            height: 120px;\n            background: white;\n            border-radius: 50%;\n            display: flex;\n            flex-direction: column;\n            justify-content: center;\n            align-items: center;\n            box-shadow: 0 8px 24px rgba(0, 0, 0, 0.08);\n            border: 3px solid #2A5C55;\n            z-index: 10;\n        }\n        \n        .chart-center i {\n            font-size: 32px;\n            color: #B3543A;\n            margin-bottom: 8px;\n        }\n        \n        .chart-center span {\n            font-size: 14px;\n            color: #2A5C55;\n            font-weight: 600;\n        }\n        \n        .concepts-section {\n            flex: 1.2;\n            height: 100%;\n            display: flex;\n            flex-direction: column;\n            justify-content: center;\n        }\n        \n        .concepts-grid {\n            display: grid;\n            grid-template-columns: 1fr 1fr;\n            grid-template-rows: 1fr 1fr;\n            gap: 24px;\n            height: 320px;\n        }\n        \n        .concept-card {\n            background: white;\n            border-radius: 16px;\n            padding: 24px;\n            display: flex;\n            flex-direction: column;\n            box-shadow: 0 8px 24px rgba(0, 0, 0, 0.06);\n            transition: all 0.3s ease;\n            border-top: 4px solid;\n            position: relative;\n            overflow: hidden;\n        }\n        \n        .concept-card:hover {\n            transform: translateY(-5px);\n            box-shadow: 0 12px 32px rgba(0, 0, 0, 0.1);\n        }\n        \n        .concept-card::before {\n            content: \"\";\n            position: absolute;\n            top: 0;\n            left: 0;\n            right: 0;\n            height: 4px;\n            background: inherit;\n            opacity: 0.3;\n        }\n        \n        .concept-icon {\n            font-size: 28px;\n            margin-bottom: 16px;\n            width: 56px;\n            height: 56px;\n            border-radius: 50%;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            color: white;\n        }\n        \n        .concept-title {\n            font-size: 22px;\n            font-weight: 700;\n            margin-bottom: 12px;\n            color: #2A5C55;\n        }\n        \n        .concept-desc {\n            font-size: 16px;\n            line-height: 1.5;\n            color: #555;\n            flex-grow: 1;\n        }\n        \n        .concept-number {\n            position: absolute;\n            top: 20px;\n            right: 20px;\n            font-size: 14px;\n            font-weight: 600;\n            color: rgba(0, 0, 0, 0.1);\n        }\n        \n        /* 卡片颜色定义 */\n        .card-yinyang {\n            border-top-color: #FF6B6B;\n        }\n        .card-yinyang .concept-icon {\n            background: linear-gradient(135deg, #FF6B6B, #FF8E8E);\n        }\n        \n        .card-wuxing {\n            border-top-color: #4ECDC4;\n        }\n        .card-wuxing .concept-icon {\n            background: linear-gradient(135deg, #4ECDC4, #6EDBD4);\n        }\n        \n        .card-whole {\n            border-top-color: #45B7D1;\n        }\n        .card-whole .concept-icon {\n            background: linear-gradient(135deg, #45B7D1, #65CFE6);\n        }\n        \n        .card-prevention {\n            border-top-color: #96CEB4;\n        }\n        .card-prevention .concept-icon {\n            background: linear-gradient(135deg, #96CEB4, #B0DEC6);\n        }\n        \n        .section-title {\n            font-size: 20px;\n            font-weight: 600;\n            color: #3A7C6F;\n            margin-bottom: 24px;\n            text-align: center;\n            position: relative;\n            padding-bottom: 12px;\n        }\n        \n        .section-title::after {\n            content: \"\";\n            position: absolute;\n            bottom: 0;\n            left: 50%;\n            transform: translateX(-50%);\n            width: 60px;\n            height: 3px;\n            background: linear-gradient(90deg, transparent, #B3543A, transparent);\n        }\n        \n        /* 响应式：保持16:9比例缩放 */\n        @media (max-width: 1350px) {\n            body { transform: scale(0.9); }\n        }\n        @media (max-width: 1150px) {\n            body { transform: scale(0.8); }\n        }\n        @media (max-width: 900px) {\n            body { transform: scale(0.7); }\n        }\n    </style>\n</head>\n<body>\n    <div class=\"slide-container\">\n        <!-- 装饰元素 -->\n        <div class=\"decoration decoration-1\">\n            <i class=\"fas fa-leaf\"></i>\n        </div>\n        <div class=\"decoration decoration-2\">\n            <i class=\"fas fa-yin-yang\"></i>\n        </div>\n        \n        <!-- 顶部标题栏 -->\n        <div class=\"header\">\n            <div>\n                <div class=\"title\">二、核心理念：中医养生的四大基石</div>\n                <div class=\"subtitle\">中医养生在儿童科普教育中的价值与机遇</div>\n            </div>\n            <div class=\"logo\">\n                <i class=\"fas fa-hand-holding-heart\"></i>\n            </div>\n        </div>\n        \n        <!-- 主内容区 -->\n        <div class=\"content\">\n            <div class=\"content-inner\">\n                <div class=\"core-concept-container\">\n                    <!-- 左侧：环形图区域 -->\n                    <div class=\"chart-section\">\n                        <div class=\"section-title\">中医养生四大基石构成</div>\n                        <div class=\"chart-wrapper\">\n                            <canvas id=\"coreConceptChart\"></canvas>\n                            <div class=\"chart-center\">\n                                <i class=\"fas fa-heartbeat\"></i>\n                                <span>健康之基</span>\n                            </div>\n                        </div>\n                    </div>\n                    \n                    <!-- 右侧：四大基石卡片区域 -->\n                    <div class=\"concepts-section\">\n                        <div class=\"section-title\">核心理念详解</div>\n                        <div class=\"concepts-grid\">\n                            <!-- 阴阳平衡 -->\n                            <div class=\"concept-card card-yinyang\">\n                                <div class=\"concept-number\">基石一</div>\n                                <div class=\"concept-icon\">\n                                    <i class=\"fas fa-balance-scale\"></i>\n                                </div>\n                                <div class=\"concept-title\">阴阳平衡</div>\n                                <div class=\"concept-desc\">理解身体内外的和谐与对立，如同昼夜交替，维持动态平衡是健康之本。</div>\n                            </div>\n                            \n                            <!-- 五行学说 -->\n                            <div class=\"concept-card card-wuxing\">\n                                <div class=\"concept-number\">基石二</div>\n                                <div class=\"concept-icon\">\n                                    <i class=\"fas fa-recycle\"></i>\n                                </div>\n                                <div class=\"concept-title\">五行学说</div>\n                                <div class=\"concept-desc\">认识五脏、季节与情绪的关联，理解木火土金水相生相克的自然规律。</div>\n                            </div>\n                            \n                            <!-- 整体观念 -->\n                            <div class=\"concept-card card-whole\">\n                                <div class=\"concept-number\">基石三</div>\n                                <div class=\"concept-icon\">\n                                    <i class=\"fas fa-globe-asia\"></i>\n                                </div>\n                                <div class=\"concept-title\">整体观念</div>\n                                <div class=\"concept-desc\">人是一个与自然社会相连的整体，健康受环境、社会、心理多因素影响。</div>\n                            </div>\n                            \n                            <!-- 治未病思想 -->\n                            <div class=\"concept-card card-prevention\">\n                                <div class=\"concept-number\">基石四</div>\n                                <div class=\"concept-icon\">\n                                    <i class=\"fas fa-shield-alt\"></i>\n                                </div>\n                                <div class=\"concept-title\">治未病思想</div>\n                                <div class=\"concept-desc\">预防为主，培养健康生活习惯，在疾病发生前进行干预和调理。</div>\n                            </div>\n                        </div>\n                    </div>\n                </div>\n            </div>\n        </div>\n        \n        <!-- 页脚 -->\n        <div class=\"footer\">\n            <div class=\"brand\">\n                <i class=\"fas fa-seedling brand-icon\"></i>\n                <span>传承千年智慧 · 守护未来健康</span>\n            </div>\n            <div class=\"pagination\">\n                第 <span class=\"highlight\">4</span> 页 / 共 15 页\n            </div>\n            <div>\n                主讲人：[您的姓名/机构名称] · 日期：[当前日期]\n            </div>\n        </div>\n    </div>\n\n    <script>\n        // 初始化环形图\n        document.addEventListener(\'DOMContentLoaded\', function() {\n            const ctx = document.getElementById(\'coreConceptChart\').getContext(\'2d\');\n            \n            // 环形图数据\n            const chartData = {\n                labels: [\'阴阳平衡\', \'五行学说\', \'整体观念\', \'治未病思想\'],\n                datasets: [{\n                    label: \'四大基石\',\n                    data: [25, 25, 25, 25],\n                    backgroundColor: [\n                        \'#FF6B6B\', // 阴阳平衡\n                        \'#4ECDC4\', // 五行学说\n                        \'#45B7D1\', // 整体观念\n                        \'#96CEB4\'  // 治未病思想\n                    ],\n                    borderColor: \'#FFFFFF\',\n                    borderWidth: 4,\n                    hoverBorderWidth: 6,\n                    hoverOffset: 10\n                }]\n            };\n            \n            // 图表配置\n            const chartConfig = {\n                type: \'doughnut\',\n                data: chartData,\n                options: {\n                    responsive: true,\n                    maintainAspectRatio: false,\n                    cutout: \'60%\',\n                    plugins: {\n                        legend: {\n                            display: false\n                        },\n                        tooltip: {\n                            callbacks: {\n                                label: function(context) {\n                                    return `${context.label}: 四大基石之一`;\n                                }\n                            },\n                            backgroundColor: \'rgba(42, 92, 85, 0.9)\',\n                            titleFont: { size: 14 },\n                            bodyFont: { size: 13 },\n                            padding: 12\n                        }\n                    },\n                    animation: {\n                        animateScale: true,\n                        animateRotate: true,\n                        duration: 1500,\n                        easing: \'easeOutQuart\'\n                    }\n                }\n            };\n            \n            // 创建图表\n            const coreConceptChart = new Chart(ctx, chartConfig);\n            \n            // 添加卡片悬停效果与图表交互\n            const conceptCards = document.querySelectorAll(\'.concept-card\');\n            const chart = coreConceptChart;\n            \n            conceptCards.forEach((card, index) => {\n                card.addEventListener(\'mouseenter\', function() {\n                    // 高亮对应的图表部分\n                    chart.setActiveElements([{ datasetIndex: 0, index: index }]);\n                    chart.update();\n                    \n                    // 添加卡片悬停类\n                    this.style.transform = \'translateY(-8px)\';\n                    this.style.boxShadow = \'0 16px 40px rgba(0, 0, 0, 0.12)\';\n                });\n                \n                card.addEventListener(\'mouseleave\', function() {\n                    // 重置图表高亮\n                    chart.setActiveElements([]);\n                    chart.update();\n                    \n                    // 移除卡片悬停类\n                    this.style.transform = \'translateY(0)\';\n                    this.style.boxShadow = \'0 8px 24px rgba(0, 0, 0, 0.06)\';\n                });\n            });\n        });\n    </script>\n</body>\n</html>','{}',NULL,0,1773280000,1773280000),(5,'d438f8e2-19a5-487e-9b54-16c4c04baed8',4,'slide_4','基石一：阴阳平衡与儿童健康','content','<!DOCTYPE html>\n<html lang=\"zh-CN\">\n<head>\n    <meta charset=\"UTF-8\">\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n    <title>基石一：阴阳平衡与儿童