r {\n            background: white;\n            border-radius: 12px;\n            padding: 20px;\n            box-shadow: 0 8px 24px rgba(0, 0, 0, 0.05);\n            border: 1px solid rgba(42, 92, 85, 0.1);\n            height: 300px;\n            margin-top: 20px;\n        }\n        /* 内容样式 */\n        h1 { color: #2A5C55; font-size: 42px; margin-bottom: 20px; }\n        h2 { color: #3A7C6F; font-size: 32px; margin-bottom: 16px; }\n        h3 { color: #B3543A; font-size: 24px; margin-bottom: 12px; }\n        p { color: #333; line-height: 1.6; margin-bottom: 16px; font-size: 18px; }\n        ul, ol { padding-left: 24px; margin-bottom: 20px; }\n        li { margin-bottom: 8px; color: #444; line-height: 1.5; font-size: 18px; }\n        .highlight { color: #B3543A; font-weight: 600; }\n        .card {\n            background: white;\n            border-radius: 12px;\n            padding: 24px;\n            box-shadow: 0 8px 24px rgba(0, 0, 0, 0.05);\n            border-left: 5px solid #2A5C55;\n            margin-bottom: 20px;\n        }\n        /* 响应式：保持16:9比例缩放 */\n        @media (max-width: 1350px) {\n            body { transform: scale(0.9); }\n        }\n        @media (max-width: 1150px) {\n            body { transform: scale(0.8); }\n        }\n        @media (max-width: 900px) {\n            body { transform: scale(0.7); }\n        }\n        /* 第5页自定义样式 */\n        .balance-container {\n            display: flex;\n            flex-direction: column;\n            height: 100%;\n            justify-content: space-between;\n        }\n        .balance-main {\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            flex-grow: 1;\n            gap: 60px;\n            margin: 20px 0;\n        }\n        .balance-visual {\n            position: relative;\n            width: 280px;\n            height: 280px;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n        }\n        .yin-yang-circle {\n            width: 220px;\n            height: 220px;\n            border-radius: 50%;\n            background: linear-gradient(90deg, #3A7C6F 0%, #2A5C55 50%, #E8F4EA 50%, #D4E8D9 100%);\n            position: relative;\n            box-shadow: 0 10px 30px rgba(42, 92, 85, 0.15);\n            animation: gentle-rotate 20s linear infinite;\n        }\n        .yin-yang-circle::before,\n        .yin-yang-circle::after {\n            content: \'\';\n            position: absolute;\n            border-radius: 50%;\n            width: 60px;\n            height: 60px;\n            top: 50%;\n            transform: translateY(-50%);\n        }\n        .yin-yang-circle::before {\n            background: #E8F4EA;\n            left: 30px;\n            box-shadow: inset 0 0 10px rgba(42, 92, 85, 0.1);\n        }\n        .yin-yang-circle::after {\n            background: #2A5C55;\n            right: 30px;\n            box-shadow: inset 0 0 10px rgba(212, 232, 217, 0.2);\n        }\n        .balance-points {\n            display: flex;\n            flex-direction: column;\n            gap: 40px;\n            max-width: 600px;\n        }\n        .balance-card {\n            background: white;\n            border-radius: 16px;\n            padding: 28px;\n            box-shadow: 0 8px 24px rgba(0, 0, 0, 0.08);\n            border-top: 4px solid;\n            transition: transform 0.3s ease, box-shadow 0.3s ease;\n        }\n        .balance-card:hover {\n            transform: translateY(-5px);\n            box-shadow: 0 12px 32px rgba(0, 0, 0, 0.12);\n        }\n        .balance-card.concept {\n            border-top-color: #3A7C6F;\n        }\n        .balance-card.application {\n            border-top-color: #B3543A;\n        }\n        .balance-card.goal {\n            border-top-color: #2A5C55;\n        }\n        .card-header {\n            display: flex;\n            align-items: center;\n            gap: 15px;\n            margin-bottom: 18px;\n        }\n        .card-icon {\n            width: 48px;\n            height: 48px;\n            border-radius: 50%;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            font-size: 22px;\n            color: white;\n        }\n        .concept .card-icon {\n            background: linear-gradient(135deg, #3A7C6F, #2A5C55);\n        }\n        .application .card-icon {\n            background: linear-gradient(135deg, #B3543A, #D87C5F);\n        }\n        .goal .card-icon {\n            background: linear-gradient(135deg, #2A5C55, #3A7C6F);\n        }\n        .card-title {\n            font-size: 24px;\n            font-weight: 700;\n            color: #2A5C55;\n            margin: 0;\n        }\n        .card-content {\n            color: #444;\n            line-height: 1.6;\n            font-size: 18px;\n            margin-bottom: 15px;\n        }\n        .examples {\n            display: flex;\n            flex-wrap: wrap;\n            gap: 12px;\n            margin-top: 15px;\n        }\n        .example-tag {\n            background: rgba(212, 232, 217, 0.3);\n            border: 1px solid rgba(58, 124, 111, 0.2);\n            border-radius: 20px;\n            padding: 6px 16px;\n            font-size: 14px;\n            color: #2A5C55;\n            display: flex;\n            align-items: center;\n            gap: 8px;\n        }\n        .example-tag i {\n            font-size: 12px;\n        }\n        .balance-quote {\n            text-align: center;\n            padding: 20px;\n            margin-top: 20px;\n            font-style: italic;\n            color: #666;\n            font-size: 18px;\n            border-top: 1px dashed rgba(42, 92, 85, 0.2);\n            border-bottom: 1px dashed rgba(42, 92, 85, 0.2);\n        }\n        .balance-quote .highlight {\n            color: #B3543A;\n            font-weight: 600;\n        }\n        @keyframes gentle-rotate {\n            0% { transform: rotate(0deg); }\n            100% { transform: rotate(360deg); }\n        }\n        /* 装饰元素调整 */\n        .decoration-3 {\n            position: absolute;\n            bottom: 120px;\n            right: 80px;\n            font-size: 80px;\n            color: rgba(179, 84, 58, 0.08);\n            transform: rotate(45deg);\n            z-index: 0;\n        }\n        .decoration-4 {\n            position: absolute;\n            top: 150px;\n            left: 80px;\n            font-size: 60px;\n            color: rgba(58, 124, 111, 0.08);\n            transform: rotate(-30deg);\n            z-index: 0;\n        }\n    </style>\n</head>\n<body>\n    <div class=\"slide-container\">\n        <!-- 装饰元素 -->\n        <div class=\"decoration decoration-1\">\n            <i class=\"fas fa-leaf\"></i>\n        </div>\n        <div class=\"decoration decoration-2\">\n            <i class=\"fas fa-yin-yang\"></i>\n        </div>\n        <div class=\"decoration decoration-3\">\n            <i class=\"fas fa-balance-scale\"></i>\n        </div>\n        <div class=\"decoration decoration-4\">\n            <i class=\"fas fa-child\"></i>\n        </div>\n        <!-- 顶部标题栏 -->\n        <div class=\"header\">\n            <div>\n                <div class=\"title\">基石一：阴阳平衡与儿童健康</div>\n                <div class=\"subtitle\">中医养生在儿童科普教育中的价值与机遇</div>\n            </div>\n            <div class=\"logo\">\n                <i class=\"fas fa-hand-holding-heart\"></i>\n            </div>\n        </div>\n        <!-- 主内容区 -->\n        <div class=\"content\">\n            <div class=\"content-inner\">\n                <div class=\"balance-container\">\n                    <div class=\"balance-main\">\n                        <!-- 阴阳平衡视觉中心 -->\n                        <div class=\"balance-visual\">\n                            <div class=\"yin-yang-circle\"></div>\n                        </div>\n                        <!-- 三个内容卡片 -->\n                        <div class=\"balance-points\">\n                            <!-- 概念卡片 -->\n                            <div class=\"balance-card concept\">\n                                <div class=\"card-header\">\n                                    <div class=\"card-icon\">\n                                        <i class=\"fas fa-lightbulb\"></i>\n                                    </div>\n                                    <h3 class=\"card-title\">概念：生活中的阴阳平衡</h3>\n                                </div>\n                                <p class=\"card-content\">\n                                    用儿童熟悉的生活现象解释抽象概念，将阴阳平衡转化为可感知的日常体验。\n                                </p>\n                                <div class=\"examples\">\n                                    <span class=\"example-tag\"><i class=\"fas fa-sun\"></i> 白天与黑夜</span>\n                                    <span class=\"example-tag\"><i class=\"fas fa-thermometer-half\"></i> 冷与热</span>\n                                    <span class=\"example-tag\"><i class=\"fas fa-running\"></i> 动与静</span>\n                                    <span class=\"example-tag\"><i class=\"fas fa-seedling\"></i> 生长与休息</span>\n                                </div>\n                            </div>\n                            <!-- 应用卡片 -->\n                            <div class=\"balance-card application\">\n                                <div class=\"card-header\">\n                                    <div class=\"card-icon\">\n                                        <i class=\"fas fa-hands-helping\"></i>\n                                    </div>\n                                    <h3 class=\"card-title\">应用：平衡的艺术实践</h3>\n                                </div>\n                                <p class=\"card-content\">\n                                    将理论转化为具体可操作的育儿指导，帮助家长在日常生活中实现平衡。\n                                </p>\n                                <div class=\"examples\">\n                                    <span class=\"example-tag\"><i class=\"fas fa-book\"></i> 学习与玩耍结合</span>\n                                    <span class=\"example-tag\"><i class=\"fas fa-tshirt\"></i> 穿衣寒温适宜</span>\n                                    <span class=\"example-tag\"><i class=\"fas fa-utensils\"></i> 饮食冷热平衡</span>\n                                    <span class=\"example-tag\"><i class=\"fas fa-bed\"></i> 作息规律有序</span>\n                                </div>\n                            </div>\n                            <!-- 目标卡片 -->\n                            <div class=\"balance-card goal\">\n                                <div class=\"card-header\">\n                                    <div class=\"card-icon\">\n                                        <i class=\"fas fa-bullseye\"></i>\n                                    </div>\n                                    <h3 class=\"card-title\">目标：培养动态健康观</h3>\n                                </div>\n                                <p class=\"card-content\">\n                                    超越单一习惯培养，帮助孩子建立适应变化的动态平衡思维，形成终身受益的健康观念。\n                                </p>\n                                <div class=\"examples\">\n                                    <span class=\"example-tag\"><i class=\"fas fa-brain\"></i> 认知灵活性</span>\n                                    <span class=\"example-tag\"><i class=\"fas fa-heartbeat\"></i> 身体感知力</span>\n                                    <span class=\"example-tag\"><i class=\"fas fa-adjust\"></i> 自我调节能力</span>\n                                    <span class=\"example-tag\"><i class=\"fas fa-infinity\"></i> 持续适应力</span>\n                                </div>\n                            </div>\n                        </div>\n                    </div>\n                    <!-- 底部引用 -->\n                    <div class=\"balance-quote\">\n                        <i class=\"fas fa-quote-left\" style=\"color: #B3543A; margin-right: 10px;\"></i>\n                        健康不是静态的完美状态，而是<span class=\"highlight\">动态平衡的艺术</span>——在变化中找到每个孩子独特的平衡点\n                        <i class=\"fas fa-quote-right\" style=\"color: #B3543A; margin-left: 10px;\"></i>\n                    </div>\n                </div>\n            </div>\n        </div>\n        <!-- 页脚 -->\n        <div class=\"footer\">\n            <div class=\"brand\">\n                <i class=\"fas fa-seedling brand-icon\"></i>\n                <span>传承','{}',NULL,0,1773280000,1773280000),(6,'d438f8e2-19a5-487e-9b54-16c4c04baed8',5,'slide_5','基石二：五行学说与五脏养护','content','<!DOCTYPE html>\n<html lang=\"zh-CN\">\n<head>\n    <meta charset=\"UTF-8\">\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n    <title>基石二：五行学说与五脏养护 - 中医养生商业计划</title>\n    <!-- Font Awesome 图标库 -->\n    <link rel=\"stylesheet\" href=\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css\">\n    <!-- Chart.js 图表库 -->\n    <script src=\"https://cdn.jsdelivr.net/npm/chart.js\"></script>\n    <style>\n        /* 全局重置与基础样式 */\n        * { margin: 0; padding: 0; box-sizing: border-box; }\n        body {\n            font-family: -apple-system, BlinkMacSystemFont, \"Segoe UI\", \"Microsoft YaHei\", sans-serif;\n            background: linear-gradient(135deg, #f5f7fa 0%, #e4edf5 100%);\n            display: flex;\n            justify-content: center;\n            align-items: center;\n            min-height: 100vh;\n            overflow: hidden;\n            padding: 20px;\n        }\n        /* 主容器：固定1280x720，16:9 */\n        .slide-container {\n            width: 1280px;\n            height: 720px;\n            background-color: #F8F4E9;\n            background-image: \n                radial-gradient(circle at 10% 20%, rgba(212, 232, 217, 0.2) 0%, transparent 20%),\n                radial-gradient(circle at 90% 80%, rgba(212, 232, 217, 0.2) 0%, transparent 20%);\n            position: relative;\n            box-shadow: 0 20px 60px rgba(42, 92, 85, 0.15);\n            border-radius: 8px;\n            overflow: hidden;\n            display: flex;\n            flex-direction: column;\n        }\n        /* 顶部标题栏 */\n        .header {\n            background: linear-gradient(90deg, #2A5C55 0%, #3A7C6F 100%);\n            color: white;\n            padding: 24px 40px;\n            position: relative;\n            min-height: 100px;\n            display: flex;\n            align-items: center;\n        }\n        .header::after {\n            content: \"\";\n            position: absolute;\n            bottom: 0;\n            left: 5%;\n            width: 90%;\n            height: 2px;\n            background: linear-gradient(90deg, transparent, #D4E8D9, transparent);\n        }\n        .title {\n            font-family: \"Noto Serif SC\", \"Source Han Serif\", serif;\n            font-size: 36px;\n            font-weight: 700;\n            line-height: 1.2;\n            flex: 1;\n        }\n        .subtitle {\n            font-size: 18px;\n            opacity: 0.9;\n            margin-top: 8px;\n            font-weight: 300;\n        }\n        .logo {\n            font-size: 24px;\n            margin-left: 30px;\n            color: #D4E8D9;\n        }\n        /* 内容区域 */\n        .content {\n            flex: 1;\n            padding: 40px;\n            overflow: hidden;\n            position: relative;\n        }\n        .content-inner {\n            height: 100%;\n            display: flex;\n            flex-direction: column;\n            justify-content: center;\n        }\n        /* 页脚 */\n        .footer {\n            background: rgba(42, 92, 85, 0.05);\n            padding: 16px 40px;\n            display: flex;\n            justify-content: space-between;\n            align-items: center;\n            border-top: 1px solid rgba(42, 92, 85, 0.1);\n            font-size: 14px;\n            color: #555;\n        }\n        .pagination {\n            font-weight: 600;\n            color: #2A5C55;\n        }\n        .brand {\n            display: flex;\n            align-items: center;\n            gap: 10px;\n        }\n        .brand-icon {\n            color: #B3543A;\n        }\n        /* 装饰元素 */\n        .decoration {\n            position: absolute;\n            opacity: 0.05;\n            pointer-events: none;\n        }\n        .decoration-1 {\n            top: 15%;\n            right: 5%;\n            font-size: 180px;\n            color: #2A5C55;\n            transform: rotate(15deg);\n        }\n        .decoration-2 {\n            bottom: 20%;\n            left: 5%;\n            font-size: 120px;\n            color: #B3543A;\n            transform: rotate(-10deg);\n        }\n        /* 自定义内容样式 */\n        .page-content {\n            display: flex;\n            height: 100%;\n            gap: 30px;\n            position: relative;\n            z-index: 2;\n        }\n        /* 左侧图表区域 */\n        .chart-section {\n            flex: 1.2;\n            display: flex;\n            flex-direction: column;\n            justify-content: center;\n        }\n        .chart-title {\n            font-size: 22px;\n            color: #2A5C55;\n            font-weight: 600;\n            margin-bottom: 15px;\n            text-align: center;\n            font-family: \"Noto Serif SC\", serif;\n        }\n        .chart-wrapper {\n            background: white;\n            border-radius: 16px;\n            padding: 25px;\n            box-shadow: 0 10px 30px rgba(42, 92, 85, 0.1);\n            border: 2px solid rgba(42, 92, 85, 0.08);\n            height: 320px;\n            position: relative;\n            overflow: hidden;\n        }\n        /* 五行循环图样式 */\n        .five-elements-cycle {\n            position: relative;\n            width: 100%;\n            height: 100%;\n        }\n        .cycle-center {\n            position: absolute;\n            top: 50%;\n            left: 50%;\n            transform: translate(-50%, -50%);\n            width: 80px;\n            height: 80px;\n            background: linear-gradient(135deg, #2A5C55, #3A7C6F);\n            border-radius: 50%;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            color: white;\n            font-weight: bold;\n            font-size: 18px;\n            box-shadow: 0 5px 15px rgba(42, 92, 85, 0.3);\n            z-index: 10;\n        }\n        .element-node {\n            position: absolute;\n            width: 100px;\n            height: 100px;\n            border-radius: 50%;\n            display: flex;\n            flex-direction: column;\n            align-items: center;\n            justify-content: center;\n            color: white;\n            font-weight: bold;\n            box-shadow: 0 8px 20px rgba(0, 0, 0, 0.15);\n            transition: transform 0.3s ease;\n            z-index: 5;\n        }\n        .element-node:hover {\n            transform: scale(1.05);\n            z-index: 15;\n        }\n        .element-symbol {\n            font-size: 28px;\n            margin-bottom: 5px;\n            font-family: \"Noto Serif SC\", serif;\n        }\n        .element-details {\n            font-size: 14px;\n            text-align: center;\n            line-height: 1.3;\n            opacity: 0.9;\n        }\n        .cycle-line {\n            position: absolute;\n            height: 4px;\n            background: linear-gradient(90deg, rgba(42, 92, 85, 0.7), rgba(58, 124, 111, 0.7));\n            transform-origin: 0 0;\n            z-index: 1;\n        }\n        .cycle-line::after {\n            content: \'\';\n            position: absolute;\n            right: -8px;\n            top: -4px;\n            width: 0;\n            height: 0;\n            border-left: 8px solid rgba(58, 124, 111, 0.9);\n            border-top: 4px solid transparent;\n            border-bottom: 4px solid transparent;\n        }\n        /* 右侧内容区域 */\n        .info-section {\n            flex: 1;\n            display: flex;\n            flex-direction: column;\n            justify-content: space-between;\n            padding: 10px 0;\n        }\n        .info-block {\n            background: white;\n            border-radius: 12px;\n            padding: 20px;\n            box-shadow: 0 8px 20px rgba(0, 0, 0, 0.05);\n            border-left: 4px solid;\n            margin-bottom: 20px;\n            flex-grow: 1;\n            display: flex;\n            flex-direction: column;\n            justify-content: center;\n        }\n        .info-block-title {\n            font-size: 20px;\n            font-weight: 600;\n            margin-bottom: 15px;\n            display: flex;\n            align-items: center;\n            gap: 10px;\n            color: #2A5C55;\n        }\n        .info-block-title i {\n            color: #B3543A;\n        }\n        .memory-grid {\n            display: grid;\n            grid-template-columns: repeat(3, 1fr);\n            gap: 12px;\n            margin-top: 10px;\n        }\n        .memory-item {\n            background: rgba(212, 232, 217, 0.3);\n            border-radius: 8px;\n            padding: 10px;\n            text-align: center;\n            font-size: 14px;\n            transition: all 0.3s ease;\n        }\n        .memory-item:hover {\n            background: rgba(212, 232, 217, 0.5);\n            transform: translateY(-2px);\n        }\n        .memory-icon {\n            font-size: 18px;\n            margin-bottom: 5px;\n            display: block;\n        }\n        .season-list {\n            display: flex;\n            flex-direction: column;\n            gap: 12px;\n        }\n        .season-item {\n            display: flex;\n            align-items: center;\n            gap: 12px;\n            padding: 10px 15px;\n            background: rgba(255, 255, 255, 0.8);\n            border-radius: 8px;\n            border-left: 4px solid;\n            transition: all 0.3s ease;\n        }\n        .season-item:hover {\n            transform: translateX(5px);\n            box-shadow: 0 5px 15px rgba(0, 0, 0, 0.08);\n        }\n        .season-color {\n            width: 20px;\n            height: 20px;\n            border-radius: 50%;\n            flex-shrink: 0;\n        }\n        .season-text {\n            flex: 1;\n            font-size: 15px;\n        }\n        .season-text strong {\n            color: #2A5C55;\n        }\n        /* 响应式：保持16:9比例缩放 */\n        @media (max-width: 1350px) {\n            body { transform: scale(0.9); }\n        }\n        @media (max-width: 1150px) {\n            body { transform: scale(0.8); }\n        }\n        @media (max-width: 900px) {\n            body { transform: scale(0.7); }\n        }\n    </style>\n</head>\n<body>\n    <div class=\"slide-container\">\n        <!-- 装饰元素 -->\n        <div class=\"decoration decoration-1\">\n            <i class=\"fas fa-leaf\"></i>\n        </div>\n        <div class=\"decoration decoration-2\">\n            <i class=\"fas fa-yin-yang\"></i>\n        </div>\n        <!-- 顶部标题栏 -->\n        <div class=\"header\">\n            <div>\n                <div class=\"title\">基石二：五行学说与五脏养护</div>\n                <div class=\"subtitle\">中医养生在儿童科普教育中的价值与机遇</div>\n            </div>\n            <div class=\"logo\">\n                <i class=\"fas fa-hand-holding-heart\"></i>\n            </div>\n        </div>\n        <!-- 主内容区 -->\n        <div class=\"content\">\n            <div class=\"page-content\">\n                <!-- 左侧：五行循环图 -->\n                <div class=\"chart-section\">\n                    <div class=\"chart-title\">五行相生循环与对应体系</div>\n                    <div class=\"chart-wrapper\">\n                        <div class=\"five-elements-cycle\" id=\"fiveElementsCycle\">\n                            <!-- 循环中心 -->\n                            <div class=\"cycle-center\">相生</div>\n                            <!-- 五行节点 -->\n                            <div class=\"element-node\" id=\"node-wood\" style=\"top: 20%; left: 50%; transform: translateX(-50%); background: linear-gradient(135deg, #4CAF50, #2E7D32);\">\n                                <div class=\"element-symbol\">木</div>\n                                <div class=\"element-details\">肝 / 春 / 绿</div>\n                            </div>\n                            <div class=\"element-node\" id=\"node-fire\" style=\"top: 50%; right: 10%; background: linear-gradient(135deg, #F44336, #C62828);\">\n                                <div class=\"element-symbol\">火</div>\n                                <div class=\"element-details\">心 / 夏 / 红</div>\n                            </div>\n                            <div class=\"element-node\" id=\"node-earth\" style=\"bottom: 20%; left: 50%; transform: translateX(-50%); background: linear-gradient(135deg, #FF9800, #EF6C00);\">\n                                <div class=\"element-symbol\">土</div>\n                                <div class=\"element-details\">脾 / 长夏 / 黄</div>\n                            </div>\n                            <div class=\"element-node\" id=\"node-metal\" style=\"top: 50%; left: 10%; background: linear-gradient(135deg, #9E9E9E, #616161);\">\n                                <div class=\"element-symbol\">金</div>\n                                <div class=\"element-details\">肺 / 秋 / 白</div>\n                            </div>\n                            <div class=\"element-node\" id=\"node-water\" style=\"top: 80%; left: 50%; transform: translateX(-50%); background: linear-gradient(135deg, #2196F3, #0D47A1);\">\n                                <div class=\"element-symbol\">水</div>\n                                <div class=\"element-details\">肾 / 冬 / 黑</div>\n                            </div>\n                            <!-- 相生连线 -->\n                            <div class=\"cycle-line\" id=\"line-wood-fire\" style=\"width: 120px; top: 70px; left: 170px; transform: rotate(45deg);\"></div>\n                            <div class=\"cycle-line\" id=\"line-fire-earth\" style=\"width: 120px; top: 170px; left: 270px; transform: rotate(135deg);\"></div>\n                            <div class=\"cycle-line\" id=\"line-earth-metal\" style=\"width: 120px; top: 270px; left: 170px; transform: rotate(225deg);\"></div>\n                            <div class=\"cycle-line\" id=\"line-metal-water\" style=\"width: 120px; top: 170px; left: 70px; transform: rotate(315deg);\"></div>\n                            <div class=\"cycle-line\" id=\"line-water-wood\" style=\"width: 60px; top: 340px; left: 110px; transform: rotate(90deg);\"></div>\n                        </div>\n                    </div>\n                </div>\n                <!-- 右侧：信息内容 -->\n                <div class=\"info-section\">\n                    <!-- 趣味记忆模块 -->\n                    <div class=\"info-block\" style=\"border-left-color: #B3543A;\">\n                        <div class=\"info-block-title\">\n                            <i class=\"fas fa-lightbulb\"></i>\n                            <span>趣味记忆法</span>\n                        </div>\n                        <p style=\"font-size: 15px; color: #555; margin-bottom: 15px;\">通过多重感官关联，轻松记忆五行五脏对应关系</p>\n                        <div class=\"memory-grid\">\n                            <div class=\"memory-item\">\n                                <span class=\"memory-icon\" style=\"color: #4CAF50;\"><i class=\"fas fa-palette\"></i></span>\n                                <span>色彩记忆<br>绿红黄白黑</span>\n                            </div>\n                            <div class=\"memory-item\">\n                                <span class=\"memory-icon\" style=\"color: #F44336;\"><i class=\"fas fa-utensils\"></i></span>\n                                <span>五味对应<br>酸苦甘辛咸</span>\n                            </div>\n                            <div class=\"memory-item\">\n                                <span class=\"memory-icon\" style=\"color: #2196F3;\"><i class=\"fas fa-dragon\"></i></span>\n                                <span>神兽联想<br>青龙朱雀玄武</span>\n                            </div>\n                        </div>\n                    </div>\n                    <!-- 实践建议模块 -->\n                    <div class=\"info-block\" style=\"border-left-color: #2A5C55;\">\n                        <div class=\"info-block-title\">\n                            <i class=\"fas fa-calendar-alt\"></i>\n                            <span>四季养护实践指南</span>\n                        </div>\n                        <div class=\"season-list\">\n                            <div class=\"season-item\" style=\"border-left-color: #4CAF50;\">\n                                <div class=\"season-color\" style=\"background-color: #4CAF50;\"></div>\n                                <div class=\"season-text\"><strong>春季养肝：</strong>绿色蔬菜 + 户外舒展运动</div>\n                            </div>\n                            <div class=\"season-item\" style=\"border-left-color: #F44336;\">\n                                <div class=\"season-color\" style=\"background-color: #F44336;\"></div>\n                                <div class=\"season-text\"><strong>夏季养心：</strong>红色食物 + 午间小憩静心</div>\n                            </div','{}',NULL,0,1773280000,1773280000),(7,'d438f8e2-19a5-487e-9b54-16c4c04baed8',6,'slide_6','三、产品方案：多维一体的科普体系','content','<!DOCTYPE html>\n<html lang=\"zh-CN\">\n<head>\n    <meta charset=\"UTF-8\">\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n    <title>三、产品方案：多维一体的科普体系 - 中医养生商业计划</title>\n    <!-- Font Awesome 图标库 -->\n    <link rel=\"stylesheet\" href=\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css\">\n    <style>\n        /* 全局重置与基础样式 */\n        * { margin: 0; padding: 0; box-sizing: border-box; }\n        body {\n            font-family: -apple-system, BlinkMacSystemFont, \"Segoe UI\", \"Microsoft YaHei\", sans-serif;\n            background: linear-gradient(135deg, #f5f7fa 0%, #e4edf5 100%);\n            display: flex;\n            justify-content: center;\n            align-items: center;\n            min-height: 100vh;\n            overflow: hidden;\n            padding: 20px;\n        }\n        \n        /* 主容器：固定1280x720，16:9 */\n        .slide-container {\n            width: 1280px;\n            height: 720px;\n            background-color: #F8F4E9;\n            background-image: \n                radial-gradient(circle at 10% 20%, rgba(212, 232, 217, 0.2) 0%, transparent 20%),\n                radial-gradient(circle at 90% 80%, rgba(212, 232, 217, 0.2) 0%, transparent 20%);\n            position: relative;\n            box-shadow: 0 20px 60px rgba(42, 92, 85, 0.15);\n            border-radius: 8px;\n            overflow: hidden;\n            display: flex;\n            flex-direction: column;\n        }\n        \n        /* 顶部标题栏 */\n        .header {\n            background: linear-gradient(90deg, #2A5C55 0%, #3A7C6F 100%);\n            color: white;\n            padding: 24px 40px;\n            position: relative;\n            min-height: 100px;\n            display: flex;\n            align-items: center;\n        }\n        .header::after {\n            content: \"\";\n            position: absolute;\n            bottom: 0;\n            left: 5%;\n            width: 90%;\n            height: 2px;\n            background: linear-gradient(90deg, transparent, #D4E8D9, transparent);\n        }\n        .title {\n            font-family: \"Noto Serif SC\", \"Source Han Serif\", serif;\n            font-size: 36px;\n            font-weight: 700;\n            line-height: 1.2;\n            flex: 1;\n        }\n        .subtitle {\n            font-size: 18px;\n            opacity: 0.9;\n            margin-top: 8px;\n            font-weight: 300;\n        }\n        .logo {\n            font-size: 24px;\n            margin-left: 30px;\n            color: #D4E8D9;\n        }\n        \n        /* 内容区域 */\n        .content {\n            flex: 1;\n            padding: 40px;\n            overflow: hidden;\n            position: relative;\n        }\n        .content-inner {\n            height: 100%;\n            display: flex;\n            flex-direction: column;\n            justify-content: center;\n        }\n        \n        /* 页脚 */\n        .footer {\n            background: rgba(42, 92, 85, 0.05);\n            padding: 16px 40px;\n            display: flex;\n            justify-content: space-between;\n            align-items: center;\n            border-top: 1px solid rgba(42, 92, 85, 0.1);\n            font-size: 14px;\n            color: #555;\n        }\n        .pagination {\n            font-weight: 600;\n            color: #2A5C55;\n        }\n        .brand {\n            display: flex;\n            align-items: center;\n            gap: 10px;\n        }\n        .brand-icon {\n            color: #B3543A;\n        }\n        \n        /* 装饰元素 */\n        .decoration {\n            position: absolute;\n            opacity: 0.05;\n            pointer-events: none;\n        }\n        .decoration-1 {\n            top: 15%;\n            right: 5%;\n            font-size: 180px;\n            color: #2A5C55;\n            transform: rotate(15deg);\n        }\n        .decoration-2 {\n            bottom: 20%;\n            left: 5%;\n            font-size: 120px;\n            color: #B3543A;\n            transform: rotate(-10deg);\n        }\n        \n        /* 产品方案页面专用样式 */\n        .product-system {\n            display: flex;\n            flex-direction: column;\n            height: 100%;\n            position: relative;\n        }\n        \n        .system-title {\n            text-align: center;\n            margin-bottom: 30px;\n            position: relative;\n        }\n        \n        .system-title h1 {\n            color: #2A5C55;\n            font-size: 42px;\n            margin-bottom: 10px;\n            font-weight: 700;\n        }\n        \n        .system-title p {\n            color: #666;\n            font-size: 20px;\n            max-width: 800px;\n            margin: 0 auto;\n            line-height: 1.5;\n        }\n        \n        .product-grid {\n            display: grid;\n            grid-template-columns: repeat(2, 1fr);\n            grid-template-rows: repeat(2, 1fr);\n            gap: 30px;\n            flex-grow: 1;\n            margin-bottom: 20px;\n        }\n        \n        .product-card {\n            background: white;\n            border-radius: 16px;\n            padding: 30px;\n            box-shadow: 0 10px 30px rgba(42, 92, 85, 0.08);\n            display: flex;\n            flex-direction: column;\n            transition: all 0.3s ease;\n            border-top: 5px solid;\n            position: relative;\n            overflow: hidden;\n        }\n        \n        .product-card:hover {\n            transform: translateY(-5px);\n            box-shadow: 0 15px 40px rgba(42, 92, 85, 0.15);\n        }\n        \n        .product-card-1 {\n            border-top-color: #F0D696;\n            background: linear-gradient(135deg, #FFFBF0 0%, #FFF 100%);\n        }\n        \n        .product-card-2 {\n            border-top-color: #4A8C6D;\n            background: linear-gradient(135deg, #F0F8F4 0%, #FFF 100%);\n        }\n        \n        .product-card-3 {\n            border-top-color: #B85C38;\n            background: linear-gradient(135deg, #FCF4F0 0%, #FFF 100%);\n        }\n        \n        .product-card-4 {\n            border-top-color: #9C3D3D;\n            background: linear-gradient(135deg, #FCF0F0 0%, #FFF 100%);\n        }\n        \n        .card-icon {\n            font-size: 40px;\n            margin-bottom: 20px;\n            width: 70px;\n            height: 70px;\n            border-radius: 50%;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            color: white;\n        }\n        \n        .card-icon-1 {\n            background: linear-gradient(135deg, #F0D696 0%, #E6C67A 100%);\n        }\n        \n        .card-icon-2 {\n            background: linear-gradient(135deg, #4A8C6D 0%, #3A7C5D 100%);\n        }\n        \n        .card-icon-3 {\n            background: linear-gradient(135deg, #B85C38 0%, #A84C28 100%);\n        }\n        \n        .card-icon-4 {\n            background: linear-gradient(135deg, #9C3D3D 0%, #8C2D2D 100%);\n        }\n        \n        .card-title {\n            font-size: 24px;\n            font-weight: 700;\n            margin-bottom: 15px;\n            color: #2A5C55;\n            line-height: 1.3;\n        }\n        \n        .card-description {\n            color: #555;\n            line-height: 1.6;\n            font-size: 18px;\n            flex-grow: 1;\n        }\n        \n        .card-tag {\n            display: inline-block;\n            padding: 5px 12px;\n            background: rgba(42, 92, 85, 0.1);\n            border-radius: 20px;\n            font-size: 14px;\n            color: #2A5C55;\n            margin-top: 15px;\n            font-weight: 500;\n        }\n        \n        .system-connection {\n            position: absolute;\n            top: 50%;\n            left: 50%;\n            transform: translate(-50%, -50%);\n            width: 200px;\n            height: 200px;\n            z-index: 1;\n            pointer-events: none;\n        }\n        \n        .connection-circle {\n            position: absolute;\n            top: 50%;\n            left: 50%;\n            transform: translate(-50%, -50%);\n            width: 120px;\n            height: 120px;\n            border-radius: 50%;\n            background: rgba(212, 232, 217, 0.3);\n            border: 2px dashed #2A5C55;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            color: #2A5C55;\n            font-size: 24px;\n            font-weight: bold;\n        }\n        \n        .connection-line {\n            position: absolute;\n            background: rgba(42, 92, 85, 0.15);\n            height: 2px;\n            transform-origin: center;\n        }\n        \n        .line-1 { width: 180px; transform: rotate(45deg); top: 50%; left: 50%; }\n        .line-2 { width: 180px; transform: rotate(135deg); top: 50%; left: 50%; }\n        .line-3 { width: 180px; transform: rotate(225deg); top: 50%; left: 50%; }\n        .line-4 { width: 180px; transform: rotate(315deg); top: 50%; left: 50%; }\n        \n        /* 响应式：保持16:9比例缩放 */\n        @media (max-width: 1350px) {\n            body { transform: scale(0.9); }\n        }\n        @media (max-width: 1150px) {\n            body { transform: scale(0.8); }\n        }\n        @media (max-width: 900px) {\n            body { transform: scale(0.7); }\n        }\n    </style>\n</head>\n<body>\n    <div class=\"slide-container\">\n        <!-- 装饰元素 -->\n        <div class=\"decoration decoration-1\">\n            <i class=\"fas fa-leaf\"></i>\n        </div>\n        <div class=\"decoration decoration-2\">\n            <i class=\"fas fa-yin-yang\"></i>\n        </div>\n        \n        <!-- 顶部标题栏 -->\n        <div class=\"header\">\n            <div>\n                <div class=\"title\">三、产品方案：多维一体的科普体系</div>\n                <div class=\"subtitle\">中医养生在儿童科普教育中的价值与机遇</div>\n            </div>\n            <div class=\"logo\">\n                <i class=\"fas fa-hand-holding-heart\"></i>\n            </div>\n        </div>\n        \n        <!-- 主内容区 -->\n        <div class=\"content\">\n            <div class=\"content-inner\">\n                <div class=\"product-system\">\n                    <div class=\"system-title\">\n                        <h1>多维一体的科普体系</h1>\n                        <p>构建从线上到线下、从认知到实践的完整中医启蒙生态</p>\n                    </div>\n                    \n                    <div class=\"system-connection\">\n                        <div class=\"connection-line line-1\"></div>\n                        <div class=\"connection-line line-2\"></div>\n                        <div class=\"connection-line line-3\"></div>\n                        <div class=\"connection-line line-4\"></div>\n                        <div class=\"connection-circle\">\n                            一体<br>多维\n                        </div>\n                    </div>\n                    \n                    <div class=\"product-grid\">\n                        <!-- 产品1：IP形象与动画系列 -->\n                        <div class=\"product-card product-card-1\">\n                            <div class=\"card-icon card-icon-1\">\n                                <i class=\"fas fa-user-md\"></i>\n                            </div>\n                            <h3 class=\"card-title\">IP形象与动画系列</h3>\n                            <p class=\"card-description\">\n                                打造\"中医小博士\"卡通IP矩阵，通过动画系列、角色故事宇宙，建立亲切的中医认知入口，覆盖3-12岁全年龄段。\n                            </p>\n                            <span class=\"card-tag\">品牌认知入口</span>\n                        </div>\n                        \n                        <!-- 产品2：互动绘本与游戏书 -->\n                        <div class=\"product-card product-card-2\">\n                            <div class=\"card-icon card-icon-2\">\n                                <i class=\"fas fa-book-open\"></i>\n                            </div>\n                            <h3 class=\"card-title\">互动绘本与游戏书</h3>\n                            <p class=\"card-description\">\n                                开发动手动脑的沉浸式学习材料，配套20+互动游戏，让孩子在探索中理解中医奥秘，培养自主学习兴趣。\n                            </p>\n                            <span class=\"card-tag\">沉浸式学习</span>\n                        </div>\n                        \n                        <!-- 产品3：线下体验工作坊 -->\n                        <div class=\"product-card product-card-3\">\n                            <div class=\"card-icon card-icon-3\">\n                                <i class=\"fas fa-users\"></i>\n                            </div>\n                            <h3 class=\"card-title\">线下体验工作坊</h3>\n                            <p class=\"card-description\">\n                                每月举办2场主题活动，包括节气养生体验、\"小小药师\"实践等，提供亲身体验中医智慧的机会。\n                            </p>\n                            <span class=\"card-tag\">实践体验</span>\n                        </div>\n                        \n                        <!-- 产品4：家庭健康工具包 -->\n                        <div class=\"product-card product-card-4\">\n                            <div class=\"card-icon card-icon-4\">\n                                <i class=\"fas fa-home\"></i>\n                            </div>\n                            <h3 class=\"card-title\">家庭健康工具包</h3>\n                            <p class=\"card-description\">\n                                包含食疗配方、穴位按摩图、实践工具等10种家庭健康组件，将中医智慧融入日常生活，促进家庭健康管理。\n                            </p>\n                            <span class=\"card-tag\">家庭应用</span>\n                        </div>\n                    </div>\n                </div>\n            </div>\n        </div>\n        \n        <!-- 页脚 -->\n        <div class=\"footer\">\n            <div class=\"brand\">\n                <i class=\"fas fa-seedling brand-icon\"></i>\n                <span>传承千年智慧 · 守护未来健康</span>\n            </div>\n            <div class=\"pagination\">\n                第 <span class=\"highlight\">7</span> 页 / 共 15 页\n            </div>\n            <div>\n                主讲人：[您的姓名/机构名称] · 日期：[当前日期]\n            </div>\n        </div>\n    </div>\n</body>\n</html>','{}',NULL,0,1773280000,1773280000),(8,'d438f8e2-19a5-487e-9b54-16c4c04baed8',7,'slide_7','产品核心：IP动画系列内容规划','content','<!DOCTYPE html>\n<html lang=\"zh-CN\">\n<head>\n    <meta charset=\"UTF-8\">\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n    <title>产品核心：IP动画系列内容规划 - 中医养生商业计划</title>\n    <!-- Font Awesome 图标库 -->\n    <link rel=\"stylesheet\" href=\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css\">\n    <!-- Chart.js 图表库 -->\n    <script src=\"https://cdn.jsdelivr.net/