er {\n            content: \"\";\n            position: absolute;\n            bottom: 0;\n            left: 5%;\n            width: 90%;\n            height: 2px;\n            background: linear-gradient(90deg, transparent, #D4E8D9, transparent);\n        }\n        .title {\n            font-family: \"Noto Serif SC\", \"Source Han Serif\", serif;\n            font-size: 36px;\n            font-weight: 700;\n            line-height: 1.2;\n            flex: 1;\n        }\n        .subtitle {\n            font-size: 18px;\n            opacity: 0.9;\n            margin-top: 8px;\n            font-weight: 300;\n        }\n        .logo {\n            font-size: 24px;\n            margin-left: 30px;\n            color: #D4E8D9;\n        }\n        \n        /* 内容区域 */\n        .content {\n            flex: 1;\n            padding: 40px;\n            overflow: hidden;\n            position: relative;\n        }\n        .content-inner {\n            height: 100%;\n            display: flex;\n            flex-direction: column;\n            justify-content: center;\n        }\n        \n        /* 页脚 */\n        .footer {\n            background: rgba(42, 92, 85, 0.05);\n            padding: 16px 40px;\n            display: flex;\n            justify-content: space-between;\n            align-items: center;\n            border-top: 1px solid rgba(42, 92, 85, 0.1);\n            font-size: 14px;\n            color: #555;\n        }\n        .pagination {\n            font-weight: 600;\n            color: #2A5C55;\n        }\n        .brand {\n            display: flex;\n            align-items: center;\n            gap: 10px;\n        }\n        .brand-icon {\n            color: #B3543A;\n        }\n        \n        /* 装饰元素 */\n        .decoration {\n            position: absolute;\n            opacity: 0.05;\n            pointer-events: none;\n        }\n        .decoration-1 {\n            top: 15%;\n            right: 5%;\n            font-size: 180px;\n            color: #2A5C55;\n            transform: rotate(15deg);\n        }\n        .decoration-2 {\n            bottom: 20%;\n            left: 5%;\n            font-size: 120px;\n            color: #B3543A;\n            transform: rotate(-10deg);\n        }\n        \n        /* 创意内容区域样式 */\n        .business-model-container {\n            display: flex;\n            height: 100%;\n            gap: 30px;\n        }\n        \n        .model-blocks {\n            flex: 1;\n            display: flex;\n            flex-direction: column;\n            gap: 15px;\n        }\n        \n        .model-block {\n            background: white;\n            border-radius: 12px;\n            padding: 20px;\n            box-shadow: 0 6px 20px rgba(0, 0, 0, 0.05);\n            border-left: 5px solid;\n            transition: transform 0.3s ease, box-shadow 0.3s ease;\n            flex: 1;\n            display: flex;\n            flex-direction: column;\n            justify-content: center;\n        }\n        \n        .model-block:hover {\n            transform: translateY(-5px);\n            box-shadow: 0 10px 25px rgba(0, 0, 0, 0.1);\n        }\n        \n        .model-header {\n            display: flex;\n            align-items: center;\n            gap: 12px;\n            margin-bottom: 12px;\n        }\n        \n        .model-icon {\n            width: 40px;\n            height: 40px;\n            border-radius: 50%;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            color: white;\n            font-size: 18px;\n        }\n        \n        .model-title {\n            font-size: 20px;\n            font-weight: 700;\n            color: #2A5C55;\n        }\n        \n        .model-items {\n            list-style: none;\n            padding-left: 0;\n        }\n        \n        .model-items li {\n            padding: 6px 0;\n            color: #555;\n            font-size: 16px;\n            display: flex;\n            align-items: center;\n            gap: 8px;\n        }\n        \n        .model-items li i {\n            color: #B3543A;\n            font-size: 12px;\n        }\n        \n        /* 图表容器样式 */\n        .chart-section {\n            flex: 1.2;\n            display: flex;\n            flex-direction: column;\n        }\n        \n        .chart-title {\n            font-size: 20px;\n            font-weight: 700;\n            color: #2D3047;\n            margin-bottom: 15px;\n            text-align: center;\n        }\n        \n        .chart-container {\n            background: white;\n            border-radius: 12px;\n            padding: 20px;\n            box-shadow: 0 8px 24px rgba(0, 0, 0, 0.05);\n            border: 1px solid rgba(42, 92, 85, 0.1);\n            flex: 1;\n            position: relative;\n        }\n        \n        .chart-summary {\n            background: linear-gradient(135deg, #2D3047 0%, #3A4A6E 100%);\n            color: white;\n            border-radius: 12px;\n            padding: 15px;\n            margin-top: 15px;\n            text-align: center;\n        }\n        \n        .total-revenue {\n            font-size: 24px;\n            font-weight: 700;\n            color: #FFEAA7;\n        }\n        \n        .revenue-label {\n            font-size: 14px;\n            opacity: 0.9;\n        }\n        \n        /* 响应式：保持16:9比例缩放 */\n        @media (max-width: 1350px) {\n            body { transform: scale(0.9); }\n        }\n        @media (max-width: 1150px) {\n            body { transform: scale(0.8); }\n        }\n        @media (max-width: 900px) {\n            body { transform: scale(0.7); }\n        }\n    </style>\n</head>\n<body>\n    <div class=\"slide-container\">\n        <!-- 装饰元素 -->\n        <div class=\"decoration decoration-1\">\n            <i class=\"fas fa-leaf\"></i>\n        </div>\n        <div class=\"decoration decoration-2\">\n            <i class=\"fas fa-yin-yang\"></i>\n        </div>\n        \n        <!-- 顶部标题栏 -->\n        <div class=\"header\">\n            <div>\n                <div class=\"title\">四、商业模式：多元收入，稳健增长</div>\n                <div class=\"subtitle\">中医养生在儿童科普教育中的价值与机遇</div>\n            </div>\n            <div class=\"logo\">\n                <i class=\"fas fa-hand-holding-heart\"></i>\n            </div>\n        </div>\n        \n        <!-- 主内容区 -->\n        <div class=\"content\">\n            <div class=\"content-inner\">\n                <div class=\"business-model-container\">\n                    <!-- 左侧：四大商业模式板块 -->\n                    <div class=\"model-blocks\">\n                        <!-- B2C 板块 -->\n                        <div class=\"model-block\" style=\"border-left-color: #4ECDC4;\">\n                            <div class=\"model-header\">\n                                <div class=\"model-icon\" style=\"background: #4ECDC4;\">\n                                    <i class=\"fas fa-users\"></i>\n                                </div>\n                                <div class=\"model-title\">B2C · 直接触达消费者</div>\n                            </div>\n                            <ul class=\"model-items\">\n                                <li><i class=\"fas fa-circle\"></i> IP内容订阅（会员制服务）</li>\n                                <li><i class=\"fas fa-circle\"></i> 图书与工具包零售</li>\n                            </ul>\n                        </div>\n                        \n                        <!-- B2B 板块 -->\n                        <div class=\"model-block\" style=\"border-left-color: #96CEB4;\">\n                            <div class=\"model-header\">\n                                <div class=\"model-icon\" style=\"background: #96CEB4;\">\n                                    <i class=\"fas fa-building\"></i>\n                                </div>\n                                <div class=\"model-title\">B2B · 赋能教育机构</div>\n                            </div>\n                            <ul class=\"model-items\">\n                                <li><i class=\"fas fa-circle\"></i> 幼儿园/小学课程授权</li>\n                                <li><i class=\"fas fa-circle\"></i> 研学营地内容合作</li>\n                            </ul>\n                        </div>\n                        \n                        <!-- B2G 板块 -->\n                        <div class=\"model-block\" style=\"border-left-color: #FFEAA7;\">\n                            <div class=\"model-header\">\n                                <div class=\"model-icon\" style=\"background: #FFEAA7; color: #2D3047;\">\n                                    <i class=\"fas fa-landmark\"></i>\n                                </div>\n                                <div class=\"model-title\">B2G · 公共服务合作</div>\n                            </div>\n                            <ul class=\"model-items\">\n                                <li><i class=\"fas fa-circle\"></i> 卫健委合作（健康公益）</li>\n                                <li><i class=\"fas fa-circle\"></i> 教育局合作（教育公益）</li>\n                            </ul>\n                        </div>\n                        \n                        <!-- IP授权 板块 -->\n                        <div class=\"model-block\" style=\"border-left-color: #FF9F1C;\">\n                            <div class=\"model-header\">\n                                <div class=\"model-icon\" style=\"background: #FF9F1C;\">\n                                    <i class=\"fas fa-trademark\"></i>\n                                </div>\n                                <div class=\"model-title\">IP授权 · 生态价值延伸</div>\n                            </div>\n                            <ul class=\"model-items\">\n                                <li><i class=\"fas fa-circle\"></i> 衍生品开发</li>\n                                <li><i class=\"fas fa-circle\"></i> 舞台剧改编</li>\n                                <li><i class=\"fas fa-circle\"></i> 健康食品联名</li>\n                            </ul>\n                        </div>\n                    </div>\n                    \n                    <!-- 右侧：瀑布图 -->\n                    <div class=\"chart-section\">\n                        <div class=\"chart-title\">三年预测营收构成（单位：万元）</div>\n                        <div class=\"chart-container\">\n                            <canvas id=\"revenueChart\"></canvas>\n                        </div>\n                        <div class=\"chart-summary\">\n                            <div class=\"revenue-label\">三年总营收预测</div>\n                            <div class=\"total-revenue\">460 万元</div>\n                            <div style=\"font-size: 12px; margin-top: 5px; opacity: 0.8;\">多元收入结构 · 稳健增长模型</div>\n                        </div>\n                    </div>\n                </div>\n            </div>\n        </div>\n        \n        <!-- 页脚 -->\n        <div class=\"footer\">\n            <div class=\"brand\">\n                <i class=\"fas fa-seedling brand-icon\"></i>\n                <span>传承千年智慧 · 守护未来健康</span>\n            </div>\n            <div class=\"pagination\">\n                第 <span class=\"highlight\">9</span> 页 / 共 15 页\n            </div>\n            <div>\n                主讲人：[您的姓名/机构名称] · 日期：[当前日期]\n            </div>\n        </div>\n    </div>\n\n    <script>\n        // 瀑布图数据配置\n        const chartData = {\n            labels: [\'B2C订阅\', \'B2C零售\', \'B2B授权\', \'B2G项目\', \'IP授权\', \'总营收\'],\n            datasets: [{\n                label: \'营收（万元）\',\n                data: [120, 80, 150, 50, 60, 460],\n                backgroundColor: [\'#4ECDC4\', \'#45B7D1\', \'#96CEB4\', \'#FFEAA7\', \'#FF9F1C\', \'#2D3047\'],\n                borderColor: [\'#4ECDC4\', \'#45B7D1\', \'#96CEB4\', \'#FFEAA7\', \'#FF9F1C\', \'#2D3047\'],\n                borderWidth: 1,\n                barPercentage: 0.6,\n                categoryPercentage: 0.8\n            }]\n        };\n\n        // 瀑布图配置\n        const chartConfig = {\n            type: \'bar\',\n            data: chartData,\n            options: {\n                responsive: true,\n                maintainAspectRatio: false,\n                plugins: {\n                    legend: {\n                        display: false\n                    },\n                    tooltip: {\n                        callbacks: {\n                            label: function(context) {\n                                return `${context.dataset.label}: ${context.parsed.y} 万元`;\n                            }\n                        }\n                    }\n                },\n                scales: {\n                    y: {\n                        beginAtZero: true,\n                        grid: {\n                            color: \'rgba(0, 0, 0, 0.05)\'\n                        },\n                        ticks: {\n                            callback: function(value) {\n                                return value + \' 万\';\n                            }\n                        }\n                    },\n                    x: {\n                        grid: {\n                            display: false\n                        }\n                    }\n                }\n            }\n        };\n\n        // 初始化图表\n        window.onload = function() {\n            const ctx = document.getElementById(\'revenueChart\').getContext(\'2d\');\n            new Chart(ctx, chartConfig);\n        };\n    </script>\n</body>\n</html>','{}',NULL,0,1773280000,1773280000),(10,'d438f8e2-19a5-487e-9b54-16c4c04baed8',9,'slide_9','市场潜力与竞争分析','content','<!DOCTYPE html>\n<html lang=\"zh-CN\">\n<head>\n    <meta charset=\"UTF-8\">\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n    <title>市场潜力与竞争分析 - 中医养生商业计划</title>\n    <!-- Font Awesome 图标库 -->\n    <link rel=\"stylesheet\" href=\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css\">\n    <!-- Chart.js 图表库 -->\n    <script src=\"https://cdn.jsdelivr.net/npm/chart.js\"></script>\n    <style>\n        /* 全局重置与基础样式 */\n        * { margin: 0; padding: 0; box-sizing: border-box; }\n        body {\n            font-family: -apple-system, BlinkMacSystemFont, \"Segoe UI\", \"Microsoft YaHei\", sans-serif;\n            background: linear-gradient(135deg, #f5f7fa 0%, #e4edf5 100%);\n            display: flex;\n            justify-content: center;\n            align-items: center;\n            min-height: 100vh;\n            overflow: hidden;\n            padding: 20px;\n        }\n        \n        /* 主容器：固定1280x720，16:9 */\n        .slide-container {\n            width: 1280px;\n            height: 720px;\n            background-color: #F8F4E9;\n            background-image: \n                radial-gradient(circle at 10% 20%, rgba(212, 232, 217, 0.2) 0%, transparent 20%),\n                radial-gradient(circle at 90% 80%, rgba(212, 232, 217, 0.2) 0%, transparent 20%);\n            position: relative;\n            box-shadow: 0 20px 60px rgba(42, 92, 85, 0.15);\n            border-radius: 8px;\n            overflow: hidden;\n            display: flex;\n            flex-direction: column;\n        }\n        \n        /* 顶部标题栏 */\n        .header {\n            background: linear-gradient(90deg, #2A5C55 0%, #3A7C6F 100%);\n            color: white;\n            padding: 24px 40px;\n            position: relative;\n            min-height: 100px;\n            display: flex;\n            align-items: center;\n        }\n        .header::after {\n            content: \"\";\n            position: absolute;\n            bottom: 0;\n            left: 5%;\n            width: 90%;\n            height: 2px;\n            background: linear-gradient(90deg, transparent, #D4E8D9, transparent);\n        }\n        .title {\n            font-family: \"Noto Serif SC\", \"Source Han Serif\", serif;\n            font-size: 36px;\n            font-weight: 700;\n            line-height: 1.2;\n            flex: 1;\n        }\n        .subtitle {\n            font-size: 18px;\n            opacity: 0.9;\n            margin-top: 8px;\n            font-weight: 300;\n        }\n        .logo {\n            font-size: 24px;\n            margin-left: 30px;\n            color: #D4E8D9;\n        }\n        \n        /* 内容区域 */\n        .content {\n            flex: 1;\n            padding: 40px;\n            overflow: hidden;\n            position: relative;\n        }\n        .content-inner {\n            height: 100%;\n            display: flex;\n            flex-direction: column;\n            justify-content: center;\n        }\n        \n        /* 页脚 */\n        .footer {\n            background: rgba(42, 92, 85, 0.05);\n            padding: 16px 40px;\n            display: flex;\n            justify-content: space-between;\n            align-items: center;\n            border-top: 1px solid rgba(42, 92, 85, 0.1);\n            font-size: 14px;\n            color: #555;\n        }\n        .pagination {\n            font-weight: 600;\n            color: #2A5C55;\n        }\n        .brand {\n            display: flex;\n            align-items: center;\n            gap: 10px;\n        }\n        .brand-icon {\n            color: #B3543A;\n        }\n        \n        /* 装饰元素 */\n        .decoration {\n            position: absolute;\n            opacity: 0.05;\n            pointer-events: none;\n        }\n        .decoration-1 {\n            top: 15%;\n            right: 5%;\n            font-size: 180px;\n            color: #2A5C55;\n            transform: rotate(15deg);\n        }\n        .decoration-2 {\n            bottom: 20%;\n            left: 5%;\n            font-size: 120px;\n            color: #B3543A;\n            transform: rotate(-10deg);\n        }\n        \n        /* 创意内容区域样式 */\n        .analysis-grid {\n            display: grid;\n            grid-template-columns: repeat(2, 1fr);\n            grid-template-rows: repeat(2, 1fr);\n            gap: 24px;\n            height: 100%;\n            margin-bottom: 20px;\n        }\n        \n        .analysis-card {\n            background: white;\n            border-radius: 16px;\n            padding: 28px;\n            box-shadow: 0 10px 30px rgba(42, 92, 85, 0.08);\n            border-top: 6px solid;\n            display: flex;\n            flex-direction: column;\n            transition: transform 0.3s ease, box-shadow 0.3s ease;\n            position: relative;\n            overflow: hidden;\n        }\n        \n        .analysis-card:hover {\n            transform: translateY(-5px);\n            box-shadow: 0 15px 40px rgba(42, 92, 85, 0.12);\n        }\n        \n        .card-1 { border-color: #1E3A8A; } /* 市场潜力 - 专业蓝 */\n        .card-2 { border-color: #10B981; } /* 竞争优势 - 成长绿 */\n        .card-3 { border-color: #92400E; } /* 竞品分析 - 中医赭 */\n        .card-4 { border-color: #F59E0B; } /* 增长预测 - 儿童橙 */\n        \n        .card-icon {\n            font-size: 32px;\n            margin-bottom: 16px;\n            width: 60px;\n            height: 60px;\n            border-radius: 50%;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            color: white;\n        }\n        \n        .card-1 .card-icon { background: linear-gradient(135deg, #1E3A8A, #3B82F6); }\n        .card-2 .card-icon { background: linear-gradient(135deg, #10B981, #34D399); }\n        .card-3 .card-icon { background: linear-gradient(135deg, #92400E, #B45309); }\n        .card-4 .card-icon { background: linear-gradient(135deg, #F59E0B, #FBBF24); }\n        \n        .card-title {\n            font-size: 22px;\n            font-weight: 700;\n            color: #2A5C55;\n            margin-bottom: 12px;\n            line-height: 1.3;\n        }\n        \n        .card-content {\n            flex: 1;\n            font-size: 18px;\n            line-height: 1.6;\n            color: #444;\n        }\n        \n        .highlight-data {\n            font-size: 28px;\n            font-weight: 800;\n            color: #B3543A;\n            margin: 8px 0;\n            display: block;\n        }\n        \n        .comparison-visual {\n            display: flex;\n            align-items: center;\n            justify-content: space-between;\n            margin-top: 12px;\n            padding: 12px;\n            background: #F8F4E9;\n            border-radius: 10px;\n        }\n        \n        .comparison-item {\n            text-align: center;\n            flex: 1;\n            padding: 8px;\n        }\n        \n        .comparison-item .icon {\n            font-size: 24px;\n            margin-bottom: 8px;\n            display: block;\n        }\n        \n        .traditional .icon { color: #92400E; }\n        .emerging .icon { color: #F59E0B; }\n        .our-edge .icon { color: #10B981; }\n        \n        .growth-chart-container {\n            background: white;\n            border-radius: 12px;\n            padding: 20px;\n            box-shadow: 0 8px 24px rgba(0, 0, 0, 0.05);\n            border: 1px solid rgba(42, 92, 85, 0.1);\n            height: 180px;\n            margin-top: 10px;\n        }\n        \n        .chart-legend {\n            display: flex;\n            justify-content: center;\n            gap: 20px;\n            margin-top: 10px;\n            font-size: 14px;\n        }\n        \n        .legend-item {\n            display: flex;\n            align-items: center;\n            gap: 6px;\n        }\n        \n        .legend-color {\n            width: 12px;\n            height: 12px;\n            border-radius: 2px;\n        }\n        \n        /* 响应式：保持16:9比例缩放 */\n        @media (max-width: 1350px) {\n            body { transform: scale(0.9); }\n        }\n        @media (max-width: 1150px) {\n            body { transform: scale(0.8); }\n        }\n        @media (max-width: 900px) {\n            body { transform: scale(0.7); }\n        }\n    </style>\n</head>\n<body>\n    <div class=\"slide-container\">\n        <!-- 装饰元素 -->\n        <div class=\"decoration decoration-1\">\n            <i class=\"fas fa-leaf\"></i>\n        </div>\n        <div class=\"decoration decoration-2\">\n            <i class=\"fas fa-yin-yang\"></i>\n        </div>\n        \n        <!-- 顶部标题栏 -->\n        <div class=\"header\">\n            <div>\n                <div class=\"title\">市场潜力与竞争分析</div>\n                <div class=\"subtitle\">中医养生在儿童科普教育中的价值与机遇</div>\n            </div>\n            <div class=\"logo\">\n                <i class=\"fas fa-hand-holding-heart\"></i>\n            </div>\n        </div>\n        \n        <!-- 主内容区 -->\n        <div class=\"content\">\n            <div class=\"content-inner\">\n                <!-- 创意内容区域 -->\n                <div class=\"analysis-grid\">\n                    <!-- 目标市场卡片 -->\n                    <div class=\"analysis-card card-1\">\n                        <div class=\"card-icon\">\n                            <i class=\"fas fa-map-marked-alt\"></i>\n                        </div>\n                        <h3 class=\"card-title\">目标市场</h3>\n                        <div class=\"card-content\">\n                            <span class=\"highlight-data\">1.2亿+</span>\n                            中国0-12岁儿童家庭\n                            <p style=\"font-size: 16px; color: #666; margin-top: 8px;\">\n                                规模庞大且持续增长的核心市场\n                            </p>\n                        </div>\n                    </div>\n                    \n                    <!-- 竞争优势卡片 -->\n                    <div class=\"analysis-card card-2\">\n                        <div class=\"card-icon\">\n                            <i class=\"fas fa-shield-alt\"></i>\n                        </div>\n                        <h3 class=\"card-title\">双引擎竞争优势</h3>\n                        <div class=\"card-content\">\n                            <p><strong>深厚壁垒：</strong>独家中医儿童健康内容体系</p>\n                            <p><strong>创作保障：</strong>金鹰奖级儿童内容团队</p>\n                            <div style=\"margin-top: 12px; font-size: 16px; color: #10B981;\">\n                                <i class=\"fas fa-check-circle\"></i> 专业性与趣味性完美融合\n                            </div>\n                        </div>\n                    </div>\n                    \n                    <!-- 竞品分析卡片 -->\n                    <div class=\"analysis-card card-3\">\n                        <div class=\"card-icon\">\n                            <i class=\"fas fa-balance-scale\"></i>\n                        </div>\n                        <h3 class=\"card-title\">市场空白分析</h3>\n                        <div class=\"card-content\">\n                            <div class=\"comparison-visual\">\n                                <div class=\"comparison-item traditional\">\n                                    <i class=\"fas fa-book icon\"></i>\n                                    <div style=\"font-size: 14px;\">传统教育</div>\n                                    <div style=\"font-size: 12px; color: #92400E;\">专业✔ 枯燥✘</div>\n                                </div>\n                                <div class=\"comparison-item emerging\">\n                                    <i class=\"fas fa-gamepad icon\"></i>\n                                    <div style=\"font-size: 14px;\">新兴内容</div>\n                                    <div style=\"font-size: 12px; color: #F59E0B;\">趣味✔ 无体系✘</div>\n                                </div>\n                                <div class=\"comparison-item our-edge\">\n                                    <i class=\"fas fa-star icon\"></i>\n                                    <div style=\"font-size: 14px;\">我方定位</div>\n                                    <div style=\"font-size: 12px; color: #10B981;\">专业✔ 趣味✔</div>\n                                </div>\n                            </div>\n                        </div>\n                    </div>\n                    \n                    <!-- 增长预测卡片 -->\n                    <div class=\"analysis-card card-4\">\n                        <div class=\"card-icon\">\n                            <i class=\"fas fa-chart-line\"></i>\n                        </div>\n                        <h3 class=\"card-title\">三年增长路径</h3>\n                        <div class=\"card-content\">\n                            <span class=\"highlight-data\">100万+</span>\n                            家庭用户覆盖目标\n                            <div class=\"growth-chart-container\">\n                                <canvas id=\"growthChart\"></canvas>\n                            </div>\n                            <div class=\"chart-legend\">\n                                <div class=\"legend-item\">\n                                    <div class=\"legend-color\" style=\"background-color: #F59E0B;\"></div>\n                                    <span>用户规模</span>\n                                </div>\n                            </div>\n                        </div>\n                    </div>\n                </div>\n                \n                <!-- 底部总结 -->\n                <div style=\"text-align: center; margin-top: 10px; padding: 16px; background: rgba(42, 92, 85, 0.05); border-radius: 10px;\">\n                    <p style=\"font-size: 18px; color: #2A5C55; font-weight: 600;\">\n                        <i class=\"fas fa-bullseye\" style=\"color: #B3543A; margin-right: 8px;\"></i>\n                        核心结论：市场足够大 · 我们足够强 · 增长足够快\n                    </p>\n                </div>\n            </div>\n        </div>\n        \n        <!-- 页脚 -->\n        <div class=\"footer\">\n            <div class=\"brand\">\n                <i class=\"fas fa-seedling brand-icon\"></i>\n                <span>传承千年智慧 · 守护未来健康</span>\n            </div>\n            <div class=\"pagination\">\n                第 <span class=\"highlight\">10</span> 页 / 共 15 页\n            </div>\n            <div>\n                主讲人：[您的姓名/机构名称] · 日期：[当前日期]\n            </div>\n        </div>\n    </div>\n\n    <script>\n        // 增长预测图表\n        document.addEventListener(\'DOMContentLoaded\', function() {\n            const ctx = document.getElementById(\'growthChart\').getContext(\'2d\');\n            \n            // 设置Canvas尺寸\n            const chartContainer = document.querySelector(\'.growth-chart-container\');\n            ctx.canvas.width = chartContainer.clientWidth;\n            ctx.canvas.height = chartContainer.clientHeight - 40;\n            \n            new Chart(ctx, {\n                type: \'line\',\n                data: {\n                    labels: [\'2024 Q1\', \'2024 Q4\', \'2025 Q4\', \'2026 Q4\'],\n                    datasets: [{\n                        label: \'用户规模 (万)\',\n                        data: [1, 10, 40, 100],\n                        borderColor: \'#F59E0B\',\n                        backgroundColor: \'rgba(245, 158, 11, 0.1)\',\n                        borderWidth: 3,\n                        fill: true,\n                        tension: 0.4,\n                        pointBackgroundColor: \'#F59E0B\',\n                        pointBorderColor: \'#FFFFFF\',\n                        pointBorderWidth: 2,\n                        pointRadius: 6,\n                        pointHoverRadius: 8\n                    }]\n                },\n                options: {\n                    responsive: true,\n                    maintainAspectRatio: false,\n                    plugins: {\n                        legend: {\n                            display: false\n                        },\n                        tooltip: {\n                            callbacks: {\n                                label: function(context) {\n                                    return `用户规模: ${context.parsed.y}万家庭`;\n                                }\n                            }\n                        }\n                    },\n                    scales: {\n                        y: {\n                            beginAtZero: true,\n                            grid: {\n                                color: \'rgba(0, 0, 0, 0.05)\'\n                            },\n                            ticks: {\n                                callback: function(value) {\n                                    return value + \'万\';\n                                }\n                            },\n                            title: {\n                                display: true,\n                                text: \'用户规模\'\n                            }\n                        },\n                        x: {\n                            grid: {\n                                color: \'rgba(0, 0, 0, 0.05)\'\n                            }\n                        }\n                    }\n                }\n            });\n        });\n    </script>\n</body>\n</html>','{}',NULL,0,1773280000,1773280000),(11,'d438f8e2-19a5-487e-9b54-16c4c04baed8',10,'slide_10','五、核心团队：跨界融合，优势互补','content','<!DOCTYPE html>\n<html lang=\"zh-CN\">\n<head>\n    <meta charset=\"UTF-8\">\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n    <title>五、核心团队：跨界融合，优势互补 - 中医养生商业计划</title>\n    <!-- Font Awesome 图标库 -->\n    <link rel=\"stylesheet\" href=\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css\">\n    <style>\n        /* 全局重置与基础样式 */\n        * { margin: 0; padding: 0; box-sizing: border-box; }\n        body {\n            font-family: -apple-system, BlinkMacSystemFont, \"Segoe UI\", \"Microsoft YaHei\", sans-serif;\n            background: linear-gradient(135deg, #f5f7fa 0%, #e4edf5 100%);\n            display: flex;\n            justify-content: center;\n            align-items: center;\n            min-height: 100vh;\n            overflow: hidden;\n            padding: 20px;\n        }\n        \n        /* 主容器：固定1280x720，16:9 */\n        .slide-container {\n            width: 1280px;\n            height: 720px;\n            background-color: #F8F4E9;\n            background-image: \n                radial-gradient(circle at 10% 20%, rgba(212, 232, 217, 0.2) 0%, transparent 20%),\n                radial-gradient(circle at 90% 80%, rgba(212, 232, 217, 0.2) 0%, transparent 20%);\n            position: relative;\n            box-shadow: 0 20px 60px rgba(42, 92, 85, 0.15);\n            border-radius: 8px;\n            overflow: hidden;\n            display: flex;\n            flex-direction: column;\n        }\n        \n        /* 顶部标题栏 */\n        .header {\n            background: linear-gradient(90deg, #2A5C55 0%, #3A7C6F 100%);\n            color: white;\n            padding: 24px 40px;\n            position: relative;\n            min-height: 100px;\n            display: flex;\n            align-items: center;\n        }\n        .header::after {\n            content: \"\";\n            position: absolute;\n            bottom: 0;\n            left: 5%;\n            width: 90%;\n            height: 2px;\n            background: linear-gradient(90deg, transparent, #D4E8D9, transparent);\n        }\n        .title {\n            font-family: \"Noto Serif SC\", \"Source Han Serif\", serif;\n            font-size: 36px;\n            font-weight: 700;\n            line-height: 1.2;\n            flex: 1;\n        }\n        .subtitle {\n            font-size: 18px;\n            opacity: 0.9;\n            margin-top: 8px;\n            font-weight: 300;\n        }\n        .logo {\n            font-size: 24px;\n            margin-left: 30px;\n            color: #D4E8D9;\n        }\n        \n        /* 内容区域 */\n        .content {\n            flex: 1;\n            padding: 40px;\n            overflow: hidden;\n            position: relative;\n        }\n        .content-inner {\n            height: 100%;\n            display: flex;\n            flex-direction: column;\n            justify-content: center;\n        }\n        \n        /* 页脚 */\n        .footer {\n            background: rgba(42, 92, 85, 0.05);\n            padding: 16px 40px;\n            display: flex;\n            justify-content: space-between;\n            align-items: center;\n            border-top: 1px solid rgba(42, 92, 85, 0.1);\n            font-size: 14px;\n            color: #555;\n        }\n        .pagination {\n            font-weight: 600;\n            color: #2A5C55;\n        }\n        .brand {\n            display: flex;\n            align-items: center;\n            gap: 10px;\n        }\n        .brand-icon {\n            color: #B3543A;\n        }\n        \n        /* 装饰元素 */\n        .decoration {\n            position: absolute;\n            opacity: 0.05;\n            pointer-events: none;\n        }\n        .decoration-1 {\n            top: 15%;\n            right: 5%;\n            font-size: 180px;\n            color: #2A5C55;\n            transform: rotate(15deg);\n        }\n        .decoration-2 {\n            bottom: 20%;\n            left: 5%;\n            font-size: 120px;\n            color: #B3543A;\n            transform: rotate(-10deg);\n        }\n        \n        /* 团队页面专属样式 */\n        .team-container {\n            display: flex;\n            flex-direction: column;\n            height: 100%;\n            width: 100%;\n        }\n        \n        .team-header {\n            text-align: center;\n            margin-bottom: 40px;\n        }\n        \n        .team-subtitle {\n            font-size: 22px;\n            color: #3A7C6F;\n            font-weight: 500;\n            margin-top: 8px;\n        }\n        \n        .team-grid {\n            display: flex;\n            justify-content: space-between;\n            gap: 30px;\n            margin-bottom: 40px;\n            flex: 1;\n        }\n        \n        .team-card {\n            flex: 1;\n            background: white;\n            border-radius: 16px;\n            padding: 30px;\n            box-shadow: 0 10px 30px rgba(42, 92, 85, 0.08);\n            display: flex;\n            flex-direction: column;\n            transition: transform 0.3s ease, box-shadow 0.3s ease;\n            position: relative;\n            overflow: hidden;\n        }\n        \n        .team-card:hover {\n            transform: translateY(-5px);\n            box-shadow: 0 15px 40px rgba(42, 92, 85, 0.12);\n        }\n        \n        .team-card::before {\n            content: \'\';\n            position: absolute;\n            top: 0;\n            left: 0;\n            width: 100%;\n            height: 5px;\n        }\n        \n        .team-card:nth-child(1)::before {\n            background: linear-gradient(90deg, #2A5C55, #3A7C6F);\n        }\n        \n        .team-card:nth-child(2)::before {\n            background: linear-gradient(90deg, #B3543A, #D87C56);\n        }\n        \n        .team-card:nth-child(3)::before {\n            background: linear-gradient(90deg, #2A5C55, #4A9C8F);\n        }\n        \n        .team-icon {\n            font-size: 42px;\n            margin-bottom: 20px;\n            text-align: center;\n        }\n        \n        .team-card:nth-child(1) .team-icon {\n            color: #2A5C55;\n        }\n        \n        .team-card:nth-child(2) .team-icon {\n            color: #B3543A;\n        }\n        \n        .team-card:nth-child(3) .team-icon {\n            color: #2A5C55;\n        }\n        \n        .team-title {\n            font-size: 24px;\n            font-weight: 700;\n            margin-bottom: 15px;\n            color: #2A5C55;\n            text-align: center;\n        }\n        \n        .team-list {\n            list-style: none;\n            padding: 0;\n            margin: 0;\n            flex: 1;\n        }\n        \n        .team-list li {\n            padding: 12px 0;\n            border-bottom: 1px solid rgba(42, 92, 85, 0.1);\n            font-size: 18px;\n            color: #444;\n            display: flex;\n            align-items: center;\n        }\n        \n        .team-list li:last-child {\n            border-bottom: none;\n        }\n        \n        .team-list li i {\n            margin-right: 12px;\n            font-size: 16px;\n            width: 24px;\n            text-align: center;\n        }\n        \n        .team-card:nth-child(1) .team-list li i {\n            color: #3A7C6F;\n        }\n        \n        .team-card:nth-child(2) .team-list li i {\n            color: #D87C56;\n        }\n        \n        .team-card:nth-child(3) .team-list li i {\n            color: #4A9C8F;\n        }\n        \n        .values-section {\n            background: linear-gradient(135deg, rgba(212, 232, 217, 0.3), rgba(180, 84, 58, 0.1));\n            border-radius: 16px;\n            padding: 25px 40px;\n            text-align: center;\n            border: 2px solid rgba(42, 92, 85, 0.15);\n            margin-top: auto;\n        }\n        \n        .values-title {\n            font-size: 20px;\n            font-weight: 600;\n            color: #2A5C55;\n            margin-bottom: 10px;\n        }\n        \n        .values-content {\n            font-size: 24px;\n            font-weight: 700;\n            color: #B3543A;\n            display: flex;\n            justify-content: center;\n            align-items: center;\n            gap: 20px;\n        }\n        \n        .values-content i {\n            font-size: 28px;\n        }\n        \n        .team-connection {\n            position: absolute;\n            top: 50%;\n            left: 0;\n            width: 100%;\n            height: 2px;\n            background: linear-gradient(90deg, transparent, rgba(42, 92, 85, 0.2), transparent);\n            z-index: -1;\n        }\n        \n        /* 响应式：保持16:9比例缩放 */\n        @media (max-width: 1350px) {\n            body { transform: scale(0.9); }\n        }\n        @media (max-width: 1150px) {\n            body { transform: scale(0.8); }\n        }\n        @media (max-width: 900px) {\n            body { transform: scale(0.7); }\n        }\n    </style>\n</head>\n<body>\n    <div class=\"slide-container\">\n        <!-- 装饰元素 -->\n        <div class=\"decoration decoratio