ry);\n            position: relative;\n        }\n\n        .header::before {\n            content: \"\";\n            position: absolute;\n            bottom: -5px;\n            left: 5%;\n            width: 90%;\n            height: 8px;\n            background: url(\'data:image/svg+xml;utf8,<svg xmlns=\"http://www.w3.org/2000/svg\" viewBox=\"0 0 100 10\" width=\"100\" height=\"10\"><path d=\"M0,5 Q25,0 50,5 T100,5\" stroke=\"%23D4AF37\" fill=\"none\" stroke-width=\"2\"/></svg>\') repeat-x;\n        }\n\n        .title-main {\n            font-family: var(--font-title);\n            font-size: 2.2rem;\n            font-weight: 700;\n            letter-spacing: 1px;\n        }\n\n        .title-sub {\n            font-size: 1rem;\n            opacity: 0.9;\n            margin-top: 5px;\n        }\n\n        .header-info {\n            text-align: right;\n            font-size: 0.95rem;\n        }\n\n        /* 主要内容区域 - 修改部分 */\n        .main-content {\n            flex: 1;\n            padding: 30px 50px;\n            overflow: hidden;\n            position: relative;\n            display: flex;\n            flex-direction: column;\n        }\n\n        .page-title {\n            font-family: var(--font-title);\n            font-size: 2.5rem;\n            color: var(--color-primary);\n            margin-bottom: 25px;\n            padding-bottom: 10px;\n            border-bottom: 2px solid var(--color-border);\n            text-align: center;\n        }\n\n        /* 尾页专用布局 */\n        .closing-container {\n            display: flex;\n            flex-direction: column;\n            flex-grow: 1;\n            justify-content: space-between;\n            align-items: center;\n            padding: 20px 0 40px;\n        }\n\n        .references-section {\n            width: 100%;\n            max-width: 900px;\n            margin-bottom: 30px;\n        }\n\n        .references-title {\n            font-family: var(--font-title);\n            font-size: 1.5rem;\n            color: var(--color-dark);\n            margin-bottom: 25px;\n            text-align: center;\n            position: relative;\n        }\n\n        .references-title::after {\n            content: \"\";\n            position: absolute;\n            bottom: -8px;\n            left: 50%;\n            transform: translateX(-50%);\n            width: 80px;\n            height: 2px;\n            background-color: var(--color-secondary);\n        }\n\n        .references-grid {\n            display: grid;\n            grid-template-columns: repeat(2, 1fr);\n            gap: 25px;\n        }\n\n        .reference-item {\n            display: flex;\n            align-items: flex-start;\n            padding: 15px 20px;\n            background: linear-gradient(135deg, rgba(139, 0, 0, 0.03), rgba(212, 175, 55, 0.03));\n            border-radius: 8px;\n            border-left: 4px solid var(--color-primary);\n            transition: transform 0.3s ease, box-shadow 0.3s ease;\n        }\n\n        .reference-item:hover {\n            transform: translateY(-3px);\n            box-shadow: 0 5px 15px rgba(0, 0, 0, 0.08);\n        }\n\n        .reference-icon {\n            color: var(--color-secondary);\n            font-size: 1.3rem;\n            margin-right: 15px;\n            margin-top: 2px;\n        }\n\n        .reference-text {\n            flex: 1;\n        }\n\n        .reference-author {\n            font-weight: 600;\n            color: var(--color-primary);\n            margin-bottom: 5px;\n            font-size: 1.1rem;\n        }\n\n        .reference-book {\n            color: var(--color-dark);\n            font-style: italic;\n            font-size: 1rem;\n        }\n\n        .closing-section {\n            text-align: center;\n            padding: 30px 0;\n            width: 100%;\n            position: relative;\n        }\n\n        .closing-section::before {\n            content: \"\";\n            position: absolute;\n            top: 0;\n            left: 50%;\n            transform: translateX(-50%);\n            width: 200px;\n            height: 1px;\n            background: linear-gradient(to right, transparent, var(--color-border), transparent);\n        }\n\n        .thank-you {\n            font-family: var(--font-title);\n            font-size: 2.2rem;\n            color: var(--color-primary);\n            margin-bottom: 15px;\n            line-height: 1.3;\n        }\n\n        .invitation {\n            font-size: 1.3rem;\n            color: var(--color-dark);\n            opacity: 0.9;\n        }\n\n        .qa-hint {\n            display: inline-flex;\n            align-items: center;\n            margin-top: 25px;\n            padding: 10px 25px;\n            background-color: rgba(139, 0, 0, 0.05);\n            border-radius: 50px;\n            color: var(--color-primary);\n            font-weight: 500;\n            animation: pulse 2s infinite;\n        }\n\n        .qa-hint i {\n            margin-right: 10px;\n            font-size: 1.2rem;\n        }\n\n        @keyframes pulse {\n            0% { opacity: 0.8; }\n            50% { opacity: 1; }\n            100% { opacity: 0.8; }\n        }\n\n        /* 底部页码栏 */\n        .footer {\n            height: 60px;\n            background: var(--color-dark);\n            color: #ddd;\n            display: flex;\n            justify-content: space-between;\n            align-items: center;\n            padding: 0 40px;\n            border-top: 2px solid var(--color-secondary);\n            font-size: 0.9rem;\n        }\n\n        .footer::before {\n            content: \"\";\n            position: absolute;\n            top: -5px;\n            left: 5%;\n            width: 90%;\n            height: 8px;\n            background: url(\'data:image/svg+xml;utf8,<svg xmlns=\"http://www.w3.org/2000/svg\" viewBox=\"0 0 100 10\" width=\"100\" height=\"10\"><path d=\"M0,5 Q25,10 50,5 T100,5\" stroke=\"%23D4AF37\" fill=\"none\" stroke-width=\"2\"/></svg>\') repeat-x;\n        }\n\n        .page-numbers {\n            font-family: var(--font-title);\n            font-size: 1.1rem;\n        }\n\n        .footer-right {\n            display: flex;\n            align-items: center;\n            gap: 15px;\n        }\n\n        .icon {\n            color: var(--color-secondary);\n            font-size: 1.2rem;\n        }\n\n        /* 响应式适配 */\n        @media (max-width: 1280px) {\n            .slide-container {\n                transform: scale(0.9);\n                transform-origin: top center;\n            }\n        }\n        @media (max-width: 1024px) {\n            .slide-container {\n                transform: scale(0.75);\n            }\n        }\n        @media (max-width: 768px) {\n            .slide-container {\n                transform: scale(0.6);\n            }\n        }\n    </style>\n</head>\n<body>\n    <div class=\"slide-container\">\n        <!-- 顶部标题栏 -->\n        <header class=\"header\">\n            <div class=\"title-block\">\n                <div class=\"title-main\">中国王朝更替历史研究</div>\n                <div class=\"title-sub\">学术研讨会 · 历史社会学专题</div>\n            </div>\n            <div class=\"header-info\">\n                <div><i class=\"fas fa-user icon\"></i> 主讲人：张教授</div>\n                <div><i class=\"fas fa-university icon\"></i> 东方大学历史学院</div>\n                <div><i class=\"far fa-calendar icon\"></i> 2023年10月</div>\n            </div>\n        </header>\n\n        <!-- 主要内容区域 -->\n        <main class=\"main-content\">\n            <h1 class=\"page-title\">Q&A 参考文献</h1>\n            \n            <div class=\"closing-container\">\n                <div class=\"references-section\">\n                    <h2 class=\"references-title\">核心参考文献</h2>\n                    <div class=\"references-grid\">\n                        <div class=\"reference-item\">\n                            <i class=\"fas fa-book-open reference-icon\"></i>\n                            <div class=\"reference-text\">\n                                <div class=\"reference-author\">钱穆</div>\n                                <div class=\"reference-book\">《国史大纲》</div>\n                            </div>\n                        </div>\n                        \n                        <div class=\"reference-item\">\n                            <i class=\"fas fa-book-open reference-icon\"></i>\n                            <div class=\"reference-text\">\n                                <div class=\"reference-author\">黄仁宇</div>\n                                <div class=\"reference-book\">《中国大历史》</div>\n                            </div>\n                        </div>\n                        \n                        <div class=\"reference-item\">\n                            <i class=\"fas fa-book-open reference-icon\"></i>\n                            <div class=\"reference-text\">\n                                <div class=\"reference-author\">金观涛，刘青峰</div>\n                                <div class=\"reference-book\">《兴盛与危机》</div>\n                            </div>\n                        </div>\n                        \n                        <div class=\"reference-item\">\n                            <i class=\"fas fa-book-open reference-icon\"></i>\n                            <div class=\"reference-text\">\n                                <div class=\"reference-author\">王国斌</div>\n                                <div class=\"reference-book\">《转变的中国：历史变迁与欧洲经验的局限》</div>\n                            </div>\n                        </div>\n                    </div>\n                </div>\n                \n                <div class=\"closing-section\">\n                    <div class=\"thank-you\">感谢聆听</div>\n                    <div class=\"invitation\">敬请指正！</div>\n                    \n                    <div class=\"qa-hint\">\n                        <i class=\"fas fa-comments\"></i>\n                        欢迎提问与交流\n                    </div>\n                </div>\n            </div>\n        </main>\n\n        <!-- 底部页码栏 -->\n        <footer class=\"footer\">\n            <div class=\"footer-left\">\n                <i class=\"fas fa-landmark icon\"></i> 王朝更替的历史逻辑与模式分析\n            </div>\n            <div class=\"footer-right\">\n                <div class=\"page-numbers\">\n                    <span class=\"current-page\">12</span> / <span class=\"total-pages\">12</span>\n                </div>\n                <div class=\"footer-icons\">\n                    <i class=\"fas fa-scroll icon\"></i>\n                    <i class=\"fas fa-history icon\"></i>\n                </div>\n            </div>\n        </footer>\n    </div>\n</body>\n</html>','{}',NULL,0,1773400000,1773400000),(40,'00bc98f1-1a7f-42d1-a550-45e85b9e61a1',0,'slide_0','C语言第三次课','content','<!DOCTYPE html>\n<html lang=\"zh-CN\">\n<head>\n    <meta charset=\"UTF-8\">\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n    <title>C语言第三次课</title>\n    <!-- 引入字体与图标库 -->\n    <link rel=\"preconnect\" href=\"https://fonts.googleapis.com\">\n    <link rel=\"preconnect\" href=\"https://fonts.gstatic.com\" crossorigin>\n    <link href=\"https://fonts.googleapis.com/css2?family=Noto+Sans+SC:wght@400;500;700;900&display=swap\" rel=\"stylesheet\">\n    <link rel=\"stylesheet\" href=\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css\">\n    <!-- 引入代码高亮库 -->\n    <link href=\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/themes/prism-tomorrow.min.css\" rel=\"stylesheet\" />\n    <script src=\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/prism.min.js\"></script>\n    <script src=\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/components/prism-c.min.js\"></script>\n    <style>\n        /* 基础与重置样式 */\n        * {\n            margin: 0;\n            padding: 0;\n            box-sizing: border-box;\n        }\n        html, body {\n            width: 100%;\n            height: 100%;\n            overflow: hidden;\n            background: #eef1ed;\n            font-family: \'Noto Sans SC\', sans-serif;\n            color: #26412f;\n        }\n        /* 响应式缩放容器 */\n        .slide-container {\n            width: 100vw;\n            height: 100vh;\n            display: flex;\n            justify-content: center;\n            align-items: center;\n        }\n        /* 幻灯片核心画布（严格 1280×720） */\n        .slide {\n            width: 1280px;\n            height: 720px;\n            background: #fbfcf8;\n            position: relative;\n            overflow: hidden;\n            transform-origin: center center;\n            box-shadow: 0 10px 30px rgba(0, 0, 0, 0.12);\n        }\n        /* 主题装饰元素：参照原PPT中的绿色圆形与左上角叶片造型 */\n        .top-strip,\n        .bottom-strip {\n            position: absolute;\n            left: 0;\n            width: 100%;\n            height: 8px;\n            background: linear-gradient(to right, rgba(130, 130, 130, 0.12), rgba(130, 130, 130, 0.45), rgba(130, 130, 130, 0.12));\n            z-index: 1;\n        }\n        .top-strip { top: 132px; }\n        .bottom-strip { bottom: 132px; }\n        .deco-circle {\n            position: absolute;\n            border-radius: 50%;\n            z-index: 1;\n        }\n        .circle-a { width: 280px; height: 280px; right: 120px; top: -80px; background: #3d7a45; }\n        .circle-b { width: 210px; height: 210px; right: 220px; top: 18px; background: #8cb043; opacity: 0.95; }\n        .circle-c { width: 86px; height: 86px; right: 52px; top: 42px; background: #cfdc72; }\n        .circle-d { width: 54px; height: 54px; left: 36px; top: 18px; background: #7eb377; }\n        .circle-e { width: 150px; height: 150px; left: 70px; bottom: -58px; background: #93bf84; }\n        .circle-f { width: 270px; height: 270px; left: 230px; bottom: -120px; background: #3f7345; opacity: 0.92; }\n        .circle-g { width: 190px; height: 190px; left: 360px; bottom: -90px; background: #9eb841; opacity: 0.85; }\n        .circle-h { width: 76px; height: 76px; right: 86px; bottom: 46px; background: #d8de7f; }\n        .leaf-mark {\n            position: absolute;\n            top: 32px;\n            left: 44px;\n            width: 70px;\n            height: 48px;\n            z-index: 3;\n        }\n        .leaf-mark::before,\n        .leaf-mark::after,\n        .leaf-mark span {\n            content: \'\';\n            position: absolute;\n            border-radius: 0 0 40px 0;\n        }\n        .leaf-mark::before {\n            left: 0;\n            top: 0;\n            width: 32px;\n            height: 32px;\n            background: #d8df79;\n        }\n        .leaf-mark::after {\n            left: 18px;\n            top: 0;\n            width: 34px;\n            height: 34px;\n            background: #89a95d;\n        }\n        .leaf-mark span {\n            left: 32px;\n            top: 0;\n            width: 38px;\n            height: 38px;\n            background: #426f4b;\n        }\n        /* 页眉信息区 - 完全保持原样 */\n        .header-band {\n            position: absolute;\n            left: 78px;\n            top: 34px;\n            right: 100px;\n            display: flex;\n            align-items: center;\n            justify-content: space-between;\n            z-index: 4;\n        }\n        .logo-group {\n            display: flex;\n            align-items: center;\n            gap: 14px;\n        }\n        .logo-badge {\n            width: 48px;\n            height: 48px;\n            border-radius: 50%;\n            border: 2px solid #5f8e4f;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            color: #5f8e4f;\n            background: rgba(255,255,255,0.95);\n            font-size: 22px;\n        }\n        .logo-text {\n            line-height: 1.2;\n        }\n        .logo-text .cn {\n            font-size: 15px;\n            font-weight: 700;\n            color: #527845;\n        }\n        .logo-text .en {\n            font-size: 10px;\n            color: #7d8a79;\n            letter-spacing: 0.4px;\n        }\n        .template-meta {\n            text-align: right;\n        }\n        .template-meta .meta-title {\n            font-size: 16px;\n            font-weight: 700;\n            color: #587d48;\n        }\n        .template-meta .meta-subtitle {\n            margin-top: 4px;\n            font-size: 11px;\n            color: #98a095;\n            letter-spacing: 0.8px;\n        }\n        /* 首页主要内容区域 - 创意设计 */\n        .title-content {\n            position: absolute;\n            top: 156px;\n            left: 68px;\n            right: 68px;\n            bottom: 64px;\n            z-index: 4;\n            display: flex;\n            flex-direction: column;\n            justify-content: center;\n            align-items: center;\n            padding: 40px;\n        }\n        /* 主标题区域 */\n        .main-title-container {\n            text-align: center;\n            margin-bottom: 60px;\n            position: relative;\n            width: 100%;\n        }\n        .main-title {\n            font-size: 72px;\n            font-weight: 900;\n            color: #3f7345;\n            line-height: 1.1;\n            margin-bottom: 20px;\n            text-shadow: 0 4px 12px rgba(63, 115, 69, 0.15);\n            position: relative;\n            display: inline-block;\n        }\n        .main-title::after {\n            content: \'\';\n            position: absolute;\n            bottom: -15px;\n            left: 50%;\n            transform: translateX(-50%);\n            width: 180px;\n            height: 4px;\n            background: linear-gradient(to right, #3f7345, #8db47f, #3f7345);\n            border-radius: 2px;\n        }\n        .title-sub {\n            font-size: 28px;\n            font-weight: 500;\n            color: #6d9d53;\n            margin-top: 30px;\n            letter-spacing: 1px;\n        }\n        /* 代码装饰元素 */\n        .code-decoration {\n            position: absolute;\n            top: 50%;\n            left: 0;\n            right: 0;\n            transform: translateY(-50%);\n            height: 200px;\n            opacity: 0.08;\n            pointer-events: none;\n            z-index: 2;\n        }\n        .code-line {\n            font-family: \'Courier New\', monospace;\n            font-size: 14px;\n            color: #3f7345;\n            white-space: nowrap;\n            margin-bottom: 8px;\n            position: relative;\n            padding-left: 20px;\n        }\n        .code-line::before {\n            content: \'>\';\n            position: absolute;\n            left: 0;\n            color: #8db47f;\n        }\n        /* 信息卡片区域 */\n        .info-cards {\n            display: flex;\n            justify-content: center;\n            gap: 40px;\n            width: 100%;\n            max-width: 900px;\n            margin-top: 30px;\n        }\n        .info-card {\n            background: rgba(255, 255, 255, 0.85);\n            border-radius: 20px;\n            padding: 24px 30px;\n            min-width: 250px;\n            border: 1px solid rgba(96, 129, 79, 0.15);\n            box-shadow: 0 8px 24px rgba(63, 115, 69, 0.08);\n            backdrop-filter: blur(4px);\n            transition: transform 0.3s ease, box-shadow 0.3s ease;\n            position: relative;\n            overflow: hidden;\n        }\n        .info-card:hover {\n            transform: translateY(-5px);\n            box-shadow: 0 12px 32px rgba(63, 115, 69, 0.15);\n        }\n        .info-card::before {\n            content: \'\';\n            position: absolute;\n            top: 0;\n            left: 0;\n            right: 0;\n            height: 4px;\n            background: linear-gradient(to right, #3f7345, #8db47f);\n        }\n        .card-header {\n            display: flex;\n            align-items: center;\n            gap: 12px;\n            margin-bottom: 16px;\n        }\n        .card-icon {\n            width: 40px;\n            height: 40px;\n            border-radius: 50%;\n            background: #f6f8f1;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            color: #5f8e4f;\n            font-size: 18px;\n            border: 2px solid rgba(95, 142, 79, 0.2);\n        }\n        .card-title {\n            font-size: 16px;\n            font-weight: 700;\n            color: #4e7543;\n        }\n        .card-content {\n            font-size: 18px;\n            font-weight: 500;\n            color: #516250;\n            line-height: 1.4;\n        }\n        .card-content .highlight {\n            color: #3f7345;\n            font-weight: 700;\n        }\n        /* 课程进度指示器 */\n        .progress-indicator {\n            position: absolute;\n            bottom: 40px;\n            left: 50%;\n            transform: translateX(-50%);\n            display: flex;\n            flex-direction: column;\n            align-items: center;\n            gap: 12px;\n        }\n        .progress-dots {\n            display: flex;\n            gap: 8px;\n        }\n        .progress-dot {\n            width: 12px;\n            height: 12px;\n            border-radius: 50%;\n            background: #dfe9ca;\n            transition: all 0.3s ease;\n        }\n        .progress-dot.active {\n            background: #5f8e4f;\n            transform: scale(1.2);\n        }\n        .progress-text {\n            font-size: 14px;\n            color: #90a28a;\n            font-weight: 500;\n        }\n        /* 页脚部分 - 完全保持原样 */\n        .footer-note {\n            position: absolute;\n            left: 74px;\n            bottom: 22px;\n            z-index: 5;\n            font-size: 12px;\n            color: #9aa596;\n            letter-spacing: 0.2px;\n        }\n        .pagination {\n            position: absolute;\n            right: 36px;\n            bottom: 22px;\n            z-index: 5;\n            font-size: 18px;\n            font-weight: 700;\n            color: #94a08e;\n            background: rgba(255,255,255,0.9);\n            padding: 6px 14px;\n            border-radius: 20px;\n        }\n        /* 响应式缩放 */\n        @media (max-width: 1400px) {\n            .main-title {\n                font-size: 64px;\n            }\n            .title-sub {\n                font-size: 24px;\n            }\n            .info-cards {\n                gap: 30px;\n            }\n        }\n        @media (max-width: 1200px) {\n            .main-title {\n                font-size: 56px;\n            }\n            .info-card {\n                min-width: 220px;\n                padding: 20px 24px;\n            }\n        }\n    </style>\n</head>\n<body>\n    <div class=\"slide-container\">\n        <div class=\"slide\">\n            <!-- 主题装饰层 -->\n            <div class=\"top-strip\"></div>\n            <div class=\"bottom-strip\"></div>\n            <div class=\"deco-circle circle-a\"></div>\n            <div class=\"deco-circle circle-b\"></div>\n            <div class=\"deco-circle circle-c\"></div>\n            <div class=\"deco-circle circle-d\"></div>\n            <div class=\"deco-circle circle-e\"></div>\n            <div class=\"deco-circle circle-f\"></div>\n            <div class=\"deco-circle circle-g\"></div>\n            <div class=\"deco-circle circle-h\"></div>\n            <div class=\"leaf-mark\"><span></span></div>\n            <!-- 页眉占位信息 - 完全保持原样 -->\n            <div class=\"header-band\">\n                <div class=\"logo-group\">\n                    <div class=\"logo-badge\"><i class=\"fa-solid fa-code\"></i></div>\n                    <div class=\"logo-text\">\n                        <div class=\"cn\">计算机科学与技术学院</div>\n                        <div class=\"en\">School of Computer Science</div>\n                    </div>\n                </div>\n                <div class=\"template-meta\">\n                    <div class=\"meta-title\">C语言编程课程</div>\n                    <div class=\"meta-subtitle\">STRUCTURED · CLEAN · CODE-DRIVEN · EDUCATIONAL</div>\n                </div>\n            </div>\n            <!-- 首页主要内容区域 -->\n            <div class=\"title-content\">\n                <!-- 代码装饰背景 -->\n                <div class=\"code-decoration\">\n                    <div class=\"code-line\">#include &lt;stdio.h&gt;</div>\n                    <div class=\"code-line\">int main() {</div>\n                    <div class=\"code-line\">    printf(\"Welcome to C Programming\");</div>\n                    <div class=\"code-line\">    return 0;</div>\n                    <div class=\"code-line\">}</div>\n                </div>\n                <!-- 主标题 -->\n                <div class=\"main-title-container\">\n                    <h1 class=\"main-title\">C语言第三次课</h1>\n                    <div class=\"title-sub\">基于文档内容生成</div>\n                </div>\n                <!-- 信息卡片 -->\n                <div class=\"info-cards\">\n                    <div class=\"info-card\">\n                        <div class=\"card-header\">\n                            <div class=\"card-icon\">\n                                <i class=\"fa-solid fa-user-tie\"></i>\n                            </div>\n                            <div class=\"card-title\">演示者</div>\n                        </div>\n                        <div class=\"card-content\">\n                            张明教授<br>\n                            <span class=\"highlight\">高级软件工程师</span>\n                        </div>\n                    </div>\n                    <div class=\"info-card\">\n                        <div class=\"card-header\">\n                            <div class=\"card-icon\">\n                                <i class=\"fa-solid fa-calendar-days\"></i>\n                            </div>\n                            <div class=\"card-title\">日期</div>\n                        </div>\n                        <div class=\"card-content\">\n                            2023年10月26日<br>\n                            <span class=\"highlight\">周四 14:00-16:00</span>\n                        </div>\n                    </div>\n                    <div class=\"info-card\">\n                        <div class=\"card-header\">\n                            <div class=\"card-icon\">\n                                <i class=\"fa-solid fa-graduation-cap\"></i>\n                            </div>\n                            <div class=\"card-title\">课程进度</div>\n                        </div>\n                        <div class=\"card-content\">\n                            第3课 / 共12课<br>\n                            <span class=\"highlight\">指针与内存管理</span>\n                        </div>\n                    </div>\n                </div>\n                <!-- 进度指示器 -->\n                <div class=\"progress-indicator\">\n                    <div class=\"progress-dots\">\n                        <div class=\"progress-dot active\"></div>\n                        <div class=\"progress-dot active\"></div>\n                        <div class=\"progress-dot active\"></div>\n                        <div class=\"progress-dot\"></div>\n                        <div class=\"progress-dot\"></div>\n                        <div class=\"progress-dot\"></div>\n                        <div class=\"progress-dot\"></div>\n                        <div class=\"progress-dot\"></div>\n                        <div class=\"progress-dot\"></div>\n                        <div class=\"progress-dot\"></div>\n                        <div class=\"progress-dot\"></div>\n                        <div class=\"progress-dot\"></div>','{}',NULL,0,1773650000,1773650000),(41,'00bc98f1-1a7f-42d1-a550-45e85b9e61a1',1,'slide_1','课程回顾与本次课目标','content','<!DOCTYPE html>\n<html lang=\"zh-CN\">\n<head>\n    <meta charset=\"UTF-8\">\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n    <title>第2页：课程回顾与本次课目标</title>\n    <!-- 引入字体与图标库 -->\n    <link rel=\"preconnect\" href=\"https://fonts.googleapis.com\">\n    <link rel=\"preconnect\" href=\"https://fonts.gstatic.com\" crossorigin>\n    <link href=\"https://fonts.googleapis.com/css2?family=Noto+Sans+SC:wght@400;500;700;900&display=swap\" rel=\"stylesheet\">\n    <link rel=\"stylesheet\" href=\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css\">\n    <!-- 引入Prism.js用于代码高亮（C语言课程需要） -->\n    <link href=\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/themes/prism-tomorrow.min.css\" rel=\"stylesheet\" />\n    <script src=\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/prism.min.js\"></script>\n    <script src=\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/components/prism-c.min.js\"></script>\n    <style>\n        /* 基础与重置样式 */\n        * {\n            margin: 0;\n            padding: 0;\n            box-sizing: border-box;\n        }\n        html, body {\n            width: 100%;\n            height: 100%;\n            overflow: hidden;\n            background: #eef1ed;\n            font-family: \'Noto Sans SC\', sans-serif;\n            color: #26412f;\n        }\n        /* 响应式缩放容器 */\n        .slide-container {\n            width: 100vw;\n            height: 100vh;\n            display: flex;\n            justify-content: center;\n            align-items: center;\n        }\n        /* 幻灯片核心画布（严格 1280×720） */\n        .slide {\n            width: 1280px;\n            height: 720px;\n            background: #fbfcf8;\n            position: relative;\n            overflow: hidden;\n            transform-origin: center center;\n            box-shadow: 0 10px 30px rgba(0, 0, 0, 0.12);\n        }\n        /* 主题装饰元素：严格保持原样 */\n        .top-strip,\n        .bottom-strip {\n            position: absolute;\n            left: 0;\n            width: 100%;\n            height: 8px;\n            background: linear-gradient(to right, rgba(130, 130, 130, 0.12), rgba(130, 130, 130, 0.45), rgba(130, 130, 130, 0.12));\n            z-index: 1;\n        }\n        .top-strip { top: 132px; }\n        .bottom-strip { bottom: 132px; }\n        .deco-circle {\n            position: absolute;\n            border-radius: 50%;\n            z-index: 1;\n        }\n        .circle-a { width: 280px; height: 280px; right: 120px; top: -80px; background: #3d7a45; }\n        .circle-b { width: 210px; height: 210px; right: 220px; top: 18px; background: #8cb043; opacity: 0.95; }\n        .circle-c { width: 86px; height: 86px; right: 52px; top: 42px; background: #cfdc72; }\n        .circle-d { width: 54px; height: 54px; left: 36px; top: 18px; background: #7eb377; }\n        .circle-e { width: 150px; height: 150px; left: 70px; bottom: -58px; background: #93bf84; }\n        .circle-f { width: 270px; height: 270px; left: 230px; bottom: -120px; background: #3f7345; opacity: 0.92; }\n        .circle-g { width: 190px; height: 190px; left: 360px; bottom: -90px; background: #9eb841; opacity: 0.85; }\n        .circle-h { width: 76px; height: 76px; right: 86px; bottom: 46px; background: #d8de7f; }\n        .leaf-mark {\n            position: absolute;\n            top: 32px;\n            left: 44px;\n            width: 70px;\n            height: 48px;\n            z-index: 3;\n        }\n        .leaf-mark::before,\n        .leaf-mark::after,\n        .leaf-mark span {\n            content: \'\';\n            position: absolute;\n            border-radius: 0 0 40px 0;\n        }\n        .leaf-mark::before {\n            left: 0;\n            top: 0;\n            width: 32px;\n            height: 32px;\n            background: #d8df79;\n        }\n        .leaf-mark::after {\n            left: 18px;\n            top: 0;\n            width: 34px;\n            height: 34px;\n            background: #89a95d;\n        }\n        .leaf-mark span {\n            left: 32px;\n            top: 0;\n            width: 38px;\n            height: 38px;\n            background: #426f4b;\n        }\n        /* 页眉信息区：严格保持原样 */\n        .header-band {\n            position: absolute;\n            left: 78px;\n            top: 34px;\n            right: 100px;\n            display: flex;\n            align-items: center;\n            justify-content: space-between;\n            z-index: 4;\n        }\n        .logo-group {\n            display: flex;\n            align-items: center;\n            gap: 14px;\n        }\n        .logo-badge {\n            width: 48px;\n            height: 48px;\n            border-radius: 50%;\n            border: 2px solid #5f8e4f;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            color: #5f8e4f;\n            background: rgba(255,255,255,0.95);\n            font-size: 22px;\n        }\n        .logo-text {\n            line-height: 1.2;\n        }\n        .logo-text .cn {\n            font-size: 15px;\n            font-weight: 700;\n            color: #527845;\n        }\n        .logo-text .en {\n            font-size: 10px;\n            color: #7d8a79;\n            letter-spacing: 0.4px;\n        }\n        .template-meta {\n            text-align: right;\n        }\n        .template-meta .meta-title {\n            font-size: 16px;\n            font-weight: 700;\n            color: #587d48;\n        }\n        .template-meta .meta-subtitle {\n            margin-top: 4px;\n            font-size: 11px;\n            color: #98a095;\n            letter-spacing: 0.8px;\n        }\n        /* 主体内容区：创意设计区域 */\n        .content-area {\n            position: absolute;\n            top: 156px;\n            left: 68px;\n            right: 68px;\n            bottom: 64px;\n            z-index: 4;\n            display: flex;\n            flex-direction: column;\n        }\n        /* 页面标题区域 */\n        .page-title-section {\n            margin-bottom: 36px;\n            text-align: center;\n        }\n        .page-title-section h1 {\n            font-size: 42px;\n            font-weight: 900;\n            color: #3f7345;\n            margin-bottom: 8px;\n            letter-spacing: 1px;\n        }\n        .page-title-section .subtitle {\n            font-size: 18px;\n            color: #7d9a6e;\n            font-weight: 500;\n        }\n        /* 三模块时间轴布局 */\n        .timeline-container {\n            display: flex;\n            justify-content: space-between;\n            align-items: flex-start;\n            flex-grow: 1;\n            margin-bottom: 20px;\n        }\n        .timeline-module {\n            flex: 1;\n            display: flex;\n            flex-direction: column;\n            align-items: center;\n            position: relative;\n            padding: 0 20px;\n        }\n        /* 连接线 */\n        .timeline-module:not(:last-child)::after {\n            content: \'\';\n            position: absolute;\n            top: 80px;\n            right: -50%;\n            width: 100%;\n            height: 4px;\n            background: linear-gradient(to right, #8cb043, #7eb377);\n            z-index: 2;\n        }\n        /* 模块图标 */\n        .module-icon {\n            width: 120px;\n            height: 120px;\n            border-radius: 50%;\n            background: white;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            margin-bottom: 24px;\n            box-shadow: 0 12px 24px rgba(63, 115, 69, 0.15);\n            position: relative;\n            z-index: 3;\n            border: 4px solid;\n            transition: transform 0.3s ease;\n        }\n        .module-icon:hover {\n            transform: scale(1.05);\n        }\n        .module-icon i {\n            font-size: 48px;\n        }\n        /* 模块1：回顾 */\n        .module-1 .module-icon {\n            border-color: #3d7a45;\n            background: linear-gradient(135deg, #f6f8f1, #e8f0e3);\n        }\n        .module-1 .module-icon i {\n            color: #3d7a45;\n        }\n        /* 模块2：目标 */\n        .module-2 .module-icon {\n            border-color: #8cb043;\n            background: linear-gradient(135deg, #f9fbf2, #f0f5e4);\n        }\n        .module-2 .module-icon i {\n            color: #8cb043;\n        }\n        /* 模块3：概览 */\n        .module-3 .module-icon {\n            border-color: #cfdc72;\n            background: linear-gradient(135deg, #fcfdf7, #f7f9ec);\n        }\n        .module-3 .module-icon i {\n            color: #9eb841;\n        }\n        /* 模块内容 */\n        .module-content {\n            background: rgba(255, 255, 255, 0.85);\n            border-radius: 20px;\n            padding: 24px;\n            width: 100%;\n            min-height: 220px;\n            box-shadow: 0 8px 20px rgba(0, 0, 0, 0.06);\n            border: 1px solid rgba(96, 129, 79, 0.12);\n            display: flex;\n            flex-direction: column;\n        }\n        .module-header {\n            display: flex;\n            align-items: center;\n            margin-bottom: 16px;\n            padding-bottom: 12px;\n            border-bottom: 2px solid;\n        }\n        .module-1 .module-header {\n            border-bottom-color: #3d7a45;\n        }\n        .module-2 .module-header {\n            border-bottom-color: #8cb043;\n        }\n        .module-3 .module-header {\n            border-bottom-color: #cfdc72;\n        }\n        .module-header h3 {\n            font-size: 22px;\n            font-weight: 700;\n            color: #4f7b45;\n            margin-left: 12px;\n        }\n        .module-header .icon-small {\n            font-size: 20px;\n        }\n        /* 内容列表 */\n        .content-list {\n            list-style: none;\n            flex-grow: 1;\n        }\n        .content-list li {\n            font-size: 16px;\n            line-height: 1.6;\n            color: #516250;\n            margin-bottom: 12px;\n            padding-left: 28px;\n            position: relative;\n        }\n        .content-list li::before {\n            content: \'\';\n            position: absolute;\n            left: 0;\n            top: 10px;\n            width: 12px;\n            height: 12px;\n            border-radius: 50%;\n        }\n        .module-1 .content-list li::before {\n            background: #3d7a45;\n        }\n        .module-2 .content-list li::before {\n            background: #8cb043;\n        }\n        .module-3 .content-list li::before {\n            background: #cfdc72;\n        }\n        /* C语言代码示例 */\n        .code-preview {\n            background: #2d2d2d;\n            border-radius: 12px;\n            padding: 16px;\n            margin-top: 12px;\n            font-family: \'Consolas\', \'Monaco\', monospace;\n            font-size: 14px;\n            color: #f8f8f2;\n            overflow: hidden;\n        }\n        .code-preview .keyword {\n            color: #ff79c6;\n        }\n        .code-preview .type {\n            color: #8be9fd;\n        }\n        .code-preview .function {\n            color: #50fa7b;\n        }\n        /* 页脚区域：严格保持原样 */\n        .footer-note {\n            position: absolute;\n            left: 74px;\n            bottom: 22px;\n            z-index: 5;\n            font-size: 12px;\n            color: #9aa596;\n            letter-spacing: 0.2px;\n        }\n        .pagination {\n            position: absolute;\n            right: 36px;\n            bottom: 22px;\n            z-index: 5;\n            font-size: 18px;\n            font-weight: 700;\n            color: #94a08e;\n            background: rgba(255,255,255,0.9);\n            padding: 6px 14px;\n            border-radius: 20px;\n        }\n    </style>\n</head>\n<body>\n    <div class=\"slide-container\">\n        <div class=\"slide\">\n            <!-- 主题装饰层（严格保持原样） -->\n            <div class=\"top-strip\"></div>\n            <div class=\"bottom-strip\"></div>\n            <div class=\"deco-circle circle-a\"></div>\n            <div class=\"deco-circle circle-b\"></div>\n            <div class=\"deco-circle circle-c\"></div>\n            <div class=\"deco-circle circle-d\"></div>\n            <div class=\"deco-circle circle-e\"></div>\n            <div class=\"deco-circle circle-f\"></div>\n            <div class=\"deco-circle circle-g\"></div>\n            <div class=\"deco-circle circle-h\"></div>\n            <div class=\"leaf-mark\"><span></span></div>\n            <!-- 页眉占位信息（严格保持原样） -->\n            <div class=\"header-band\">\n                <div class=\"logo-group\">\n                    <div class=\"logo-badge\"><i class=\"fa-solid fa-code\"></i></div>\n                    <div class=\"logo-text\">\n                        <div class=\"cn\">食品药品职业学院</div>\n                        <div class=\"en\">Food and Drug Vocational College</div>\n                    </div>\n                </div>\n                <div class=\"template-meta\">\n                    <div class=\"meta-title\">C语言程序设计 · 第三次课</div>\n                    <div class=\"meta-subtitle\">STRUCTURED · LOGICAL · PRACTICAL · MODERN</div>\n                </div>\n            </div>\n            <!-- 主体内容区（创意设计区域） -->\n            <div class=\"content-area\">\n                <div class=\"page-title-section\">\n                    <h1>课程回顾与本次课目标</h1>\n                    <div class=\"subtitle\">构建完整的学习路径 · 从基础到应用</div>\n                </div>\n                <div class=\"timeline-container\">\n                    <!-- 模块1：回顾 -->\n                    <div class=\"timeline-module module-1\">\n                        <div class=\"module-icon\">\n                            <i class=\"fa-solid fa-history\"></i>\n                        </div>\n                        <div class=\"module-content\">\n                            <div class=\"module-header\">\n                                <i class=\"fa-solid fa-book-open icon-small\"></i>\n                                <h3>前两次课核心知识点回顾</h3>\n                            </div>\n                            <ul class=\"content-list\">\n                                <li>C语言基础语法与程序结构</li>\n                                <li>变量、数据类型与运算符</li>\n                                <li>顺序、选择、循环结构</li>\n                                <li>简单的输入输出函数</li>\n                            </ul>\n                            <div class=\"code-preview\">\n                                <span class=\"keyword\">#include</span> &lt;stdio.h&gt;<br>\n                                <span class=\"keyword\">int</span> <span class=\"function\">main</span>() {<br>\n                                &nbsp;&nbsp;<span class=\"keyword\">int</span> a = 10, b = 20;<br>\n                                &nbsp;&nbsp;<span class=\"keyword\">if</span> (a &lt; b) {<br>\n                                &nbsp;&nbsp;&nbsp;&nbsp;printf(<span class=\"type\">\"a小于b\\n\"</span>);<br>\n                                &nbsp;&nbsp;}<br>\n                                &nbsp;&nbsp;<span class=\"keyword\">return</span> 0;<br>\n                                }\n                            </div>\n                        </div>\n                    </div>\n                    <!-- 模块2：目标 -->\n                    <div class=\"timeline-module module-2\">\n                        <div class=\"module-icon\">\n                            <i class=\"fa-solid fa-bullseye\"></i>\n                        </div>\n                        <div class=\"module-content\">\n                            <div class=\"module-header\">\n                                <i class=\"fa-solid fa-flag-checkered icon-small\"></i>\n                                <h3>本次课程学习目标</h3>\n                            </div>\n                            <ul class=\"content-list\">\n                                <li><strong>知识目标：</strong>掌握数组的定义与使用方法</li>\n                                <li><strong>技能目标：</strong>能够编写简单的数组处理程序</li>\n                                <li><strong>应用目标：</strong>解决实际问题中的批量数据处理</li>\n                                <li><strong>思维目标：</strong>培养结构化编程思维</li>\n                            </ul>\n                            <div style=\"margin-top: 12px; padding: 12px; background','{}',NULL,0,1773650000,1773650000),(42,'00bc98f1-1a7f-42d1-a550-45e85b9e61a1',2,'slide_2','循环结构：for语句','content','<!DOCTYPE html>\n<html lang=\"zh-CN\">\n<head>\n    <meta charset=\"UTF-8\">\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n    <title>循环结构：for语句 - C语言第三次课</title>\n    <!-- 引入字体与图标库 -->\n    <link rel=\"preconnect\" href=\"https://fonts.googleapis.com\">\n    <link rel=\"preconnect\" href=\"https://fonts.gstatic.com\" crossorigin>\n    <link href=\"https://fonts.googleapis.com/css2?family=Noto+Sans+SC:wght@400;500;700;900&display=swap\" rel=\"stylesheet\">\n    <link rel=\"stylesheet\" href=\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css\">\n    <!-- 引入代码高亮库 -->\n    <link href=\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/themes/prism-tomorrow.min.css\" rel=\"stylesheet\" />\n    <script src=\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/prism.min.js\"></script>\n    <script src=\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/components/prism-c.min.js\"></script>\n    <style>\n        /* 基础与重置样式 */\n        * { margin: 0; padding: 0; box-sizing: border-box; }\n        html, body {\n            width: 100%; height: 100%; overflow: hidden;\n            background: #eef1ed; font-family: \'Noto Sans SC\', sans-serif;\n            color: #26412f;\n        }\n        /* 响应式缩放容器 */\n        .slide-container {\n            width: 100vw; height: 100vh;\n            display: flex; justify-content: center; align-items: center;\n        }\n        /* 幻灯片核心画布（严格 1280×720） */\n        .slide {\n            width: 1280px; height: 720px;\n            background: #fbfcf8; position: relative; overflow: hidden;\n            transform-origin: center center; box-shadow: 0 10px 30px rgba(0, 0, 0, 0.12);\n        }\n        /* 主题装饰元素：完全保持原样 */\n        .top-strip, .bottom-strip {\n            position: absolute; left: 0; width: 100%; height: 8px;\n    