.while-card::before {\n            background: linear-gradient(to right, #3d7a45, #8cb043);\n        }\n        .do-while-card::before {\n            background: linear-gradient(to right, #8cb043, #cfdc72);\n        }\n        .card-header {\n            display: flex;\n            align-items: center;\n            gap: 12px;\n            margin-bottom: 20px;\n        }\n        .loop-icon {\n            width: 48px;\n            height: 48px;\n            border-radius: 50%;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            font-size: 22px;\n            color: white;\n            flex-shrink: 0;\n        }\n        .while-icon {\n            background: #3d7a45;\n        }\n        .do-while-icon {\n            background: #8cb043;\n        }\n        .card-header h2 {\n            font-size: 22px;\n            color: #4f7b45;\n            font-weight: 800;\n        }\n        .card-header p {\n            font-size: 13px;\n            color: #90a28a;\n            margin-top: 4px;\n        }\n        .syntax-box {\n            background: #f6f8f1;\n            border-radius: 12px;\n            padding: 16px;\n            margin-bottom: 20px;\n            border-left: 4px solid #7fa64d;\n        }\n        .syntax-box h3 {\n            font-size: 14px;\n            color: #4e7543;\n            margin-bottom: 10px;\n            font-weight: 700;\n        }\n        .code-block {\n            background: #2d2d2d;\n            border-radius: 8px;\n            padding: 12px;\n            font-family: \'Consolas\', \'Monaco\', monospace;\n            font-size: 13px;\n            line-height: 1.5;\n            color: #f8f8f2;\n            overflow-x: auto;\n        }\n        .features-list {\n            flex: 1;\n            display: flex;\n            flex-direction: column;\n            gap: 12px;\n        }\n        .feature-item {\n            display: flex;\n            align-items: flex-start;\n            gap: 10px;\n            padding: 10px;\n            background: rgba(248, 250, 244, 0.8);\n            border-radius: 10px;\n            border-left: 3px solid #7fa64d;\n        }\n        .feature-icon {\n            width: 24px;\n            height: 24px;\n            border-radius: 50%;\n            background: #dfe9ca;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            color: #507247;\n            font-size: 12px;\n            flex-shrink: 0;\n        }\n        .feature-text {\n            flex: 1;\n        }\n        .feature-text h4 {\n            font-size: 14px;\n            color: #4b7442;\n            margin-bottom: 4px;\n            font-weight: 600;\n        }\n        .feature-text p {\n            font-size: 12px;\n            color: #667163;\n            line-height: 1.5;\n        }\n        /* 底部对比与警示区域 */\n        .bottom-section {\n            display: flex;\n            gap: 24px;\n            margin-top: 10px;\n        }\n        .difference-box {\n            flex: 2;\n            background: rgba(255,255,255,0.85);\n            border-radius: 20px;\n            padding: 20px;\n            border: 1px solid rgba(96, 129, 79, 0.14);\n            backdrop-filter: blur(2px);\n        }\n        .warning-box {\n            flex: 1;\n            background: rgba(255, 245, 245, 0.9);\n            border-radius: 20px;\n            padding: 20px;\n            border: 1px solid rgba(220, 53, 69, 0.2);\n            backdrop-filter: blur(2px);\n        }\n        .section-title {\n            display: flex;\n            align-items: center;\n            gap: 10px;\n            margin-bottom: 16px;\n            font-size: 18px;\n            font-weight: 800;\n            color: #4e7543;\n        }\n        .section-title .dot {\n            width: 10px;\n            height: 10px;\n            border-radius: 50%;\n            background: #8dae48;\n        }\n        .warning-title {\n            color: #dc3545;\n        }\n        .warning-title .dot {\n            background: #dc3545;\n        }\n        .difference-grid {\n            display: grid;\n            grid-template-columns: repeat(2, 1fr);\n            gap: 16px;\n        }\n        .diff-item {\n            background: #f8faf4;\n            border-radius: 12px;\n            padding: 14px;\n            border: 1px solid rgba(89, 121, 71, 0.1);\n        }\n        .diff-item h4 {\n            font-size: 14px;\n            color: #4e7543;\n            margin-bottom: 8px;\n            font-weight: 700;\n        }\n        .diff-content {\n            display: flex;\n            align-items: center;\n            gap: 12px;\n        }\n        .while-badge, .do-while-badge {\n            padding: 4px 10px;\n            border-radius: 20px;\n            font-size: 12px;\n            font-weight: 600;\n            flex-shrink: 0;\n        }\n        .while-badge {\n            background: #e8f0e5;\n            color: #3d7a45;\n        }\n        .do-while-badge {\n            background: #f0f5e5;\n            color: #8cb043;\n        }\n        .diff-text {\n            font-size: 13px;\n            color: #60705f;\n            line-height: 1.5;\n        }\n        .warning-list {\n            list-style: none;\n        }\n        .warning-list li {\n            font-size: 13px;\n            line-height: 1.7;\n            color: #666;\n            margin-bottom: 10px;\n            padding-left: 24px;\n            position: relative;\n        }\n        .warning-list li::before {\n            content: \'⚠️\';\n            position: absolute;\n            left: 0;\n            top: 2px;\n            font-size: 14px;\n        }\n        .warning-list strong {\n            color: #dc3545;\n            font-weight: 700;\n        }\n        /* 流程可视化装饰 */\n        .flow-visual {\n            position: absolute;\n            bottom: 20px;\n            right: 20px;\n            display: flex;\n            align-items: center;\n            gap: 8px;\n            font-size: 12px;\n            color: #90a28a;\n        }\n        .flow-arrow {\n            display: flex;\n            align-items: center;\n            gap: 4px;\n        }\n        .flow-arrow i {\n            color: #7fa64d;\n        }\n    </style>\n</head>\n<body>\n    <div class=\"slide-container\">\n        <div class=\"slide\">\n            <!-- 主题装饰层 -->\n            <div class=\"top-strip\"></div>\n            <div class=\"bottom-strip\"></div>\n            <div class=\"deco-circle circle-a\"></div>\n            <div class=\"deco-circle circle-b\"></div>\n            <div class=\"deco-circle circle-c\"></div>\n            <div class=\"deco-circle circle-d\"></div>\n            <div class=\"deco-circle circle-e\"></div>\n            <div class=\"deco-circle circle-f\"></div>\n            <div class=\"deco-circle circle-g\"></div>\n            <div class=\"deco-circle circle-h\"></div>\n            <div class=\"leaf-mark\"><span></span></div>\n            <!-- 页眉占位信息 -->\n            <div class=\"header-band\">\n                <div class=\"logo-group\">\n                    <div class=\"logo-badge\"><i class=\"fa-solid fa-code\"></i></div>\n                    <div class=\"logo-text\">\n                        <div class=\"cn\">C语言程序设计</div>\n                        <div class=\"en\">C Programming Language</div>\n                    </div>\n                </div>\n                <div class=\"template-meta\">\n                    <div class=\"meta-title\">第三次课：流程控制</div>\n                    <div class=\"meta-subtitle\">LOOP STRUCTURES · CONTROL FLOW · SYNTAX COMPARISON</div>\n                </div>\n            </div>\n            <!-- 主要内容','{}',NULL,0,1773650000,1773650000),(44,'00bc98f1-1a7f-42d1-a550-45e85b9e61a1',4,'slide_4','循环控制语句：break与continue','content','<!DOCTYPE html>\n<html lang=\"zh-CN\">\n<head>\n    <meta charset=\"UTF-8\">\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n    <title>循环控制语句：break与continue</title>\n    <!-- 引入字体与图标库 -->\n    <link rel=\"preconnect\" href=\"https://fonts.googleapis.com\">\n    <link rel=\"preconnect\" href=\"https://fonts.gstatic.com\" crossorigin>\n    <link href=\"https://fonts.googleapis.com/css2?family=Noto+Sans+SC:wght@400;500;700;900&display=swap\" rel=\"stylesheet\">\n    <link rel=\"stylesheet\" href=\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css\">\n    <!-- 引入代码高亮库 -->\n    <link href=\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/themes/prism-tomorrow.min.css\" rel=\"stylesheet\" />\n    <script src=\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/prism.min.js\"></script>\n    <script src=\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/components/prism-c.min.js\"></script>\n    <style>\n        * {\n            margin: 0;\n            padding: 0;\n            box-sizing: border-box;\n        }\n        html, body {\n            width: 100%;\n            height: 100%;\n            overflow: hidden;\n            background: #eef1ed;\n            font-family: \'Noto Sans SC\', sans-serif;\n            color: #26412f;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n        }\n        .slide-container {\n            width: 100vw;\n            height: 100vh;\n            display: flex;\n            justify-content: center;\n            align-items: center;\n        }\n        .slide {\n            width: 1280px;\n            height: 720px;\n            background: #fbfcf8;\n            position: relative;\n            overflow: hidden;\n            transform-origin: center center;\n            box-shadow: 0 10px 30px rgba(0, 0, 0, 0.12);\n        }\n        /* 主题装饰元素（完全保持原样） */\n        .top-strip,\n        .bottom-strip {\n            position: absolute;\n            left: 0;\n            width: 100%;\n            height: 8px;\n            background: linear-gradient(to right, rgba(130, 130, 130, 0.12), rgba(130, 130, 130, 0.45), rgba(130, 130, 130, 0.12));\n            z-index: 1;\n        }\n        .top-strip { top: 132px; }\n        .bottom-strip { bottom: 132px; }\n        .deco-circle {\n            position: absolute;\n            border-radius: 50%;\n            z-index: 1;\n        }\n        .circle-a { width: 280px; height: 280px; right: 120px; top: -80px; background: #3d7a45; }\n        .circle-b { width: 210px; height: 210px; right: 220px; top: 18px; background: #8cb043; opacity: 0.95; }\n        .circle-c { width: 86px; height: 86px; right: 52px; top: 42px; background: #cfdc72; }\n        .circle-d { width: 54px; height: 54px; left: 36px; top: 18px; background: #7eb377; }\n        .circle-e { width: 150px; height: 150px; left: 70px; bottom: -58px; background: #93bf84; }\n        .circle-f { width: 270px; height: 270px; left: 230px; bottom: -120px; background: #3f7345; opacity: 0.92; }\n        .circle-g { width: 190px; height: 190px; left: 360px; bottom: -90px; background: #9eb841; opacity: 0.85; }\n        .circle-h { width: 76px; height: 76px; right: 86px; bottom: 46px; background: #d8de7f; }\n        .leaf-mark {\n            position: absolute;\n            top: 32px;\n            left: 44px;\n            width: 70px;\n            height: 48px;\n            z-index: 3;\n        }\n        .leaf-mark::before,\n        .leaf-mark::after,\n        .leaf-mark span {\n            content: \'\';\n            position: absolute;\n            border-radius: 0 0 40px 0;\n        }\n        .leaf-mark::before {\n            left: 0;\n            top: 0;\n            width: 32px;\n            height: 32px;\n            background: #d8df79;\n        }\n        .leaf-mark::after {\n            left: 18px;\n            top: 0;\n            width: 34px;\n            height: 34px;\n            background: #89a95d;\n        }\n        .leaf-mark span {\n            left: 32px;\n            top: 0;\n            width: 38px;\n            height: 38px;\n            background: #426f4b;\n        }\n        /* 页眉信息区（完全保持原样） */\n        .header-band {\n            position: absolute;\n            left: 78px;\n            top: 34px;\n            right: 100px;\n            display: flex;\n            align-items: center;\n            justify-content: space-between;\n            z-index: 4;\n        }\n        .logo-group {\n            display: flex;\n            align-items: center;\n            gap: 14px;\n        }\n        .logo-badge {\n            width: 48px;\n            height: 48px;\n            border-radius: 50%;\n            border: 2px solid #5f8e4f;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            color: #5f8e4f;\n            background: rgba(255,255,255,0.95);\n            font-size: 22px;\n        }\n        .logo-text {\n            line-height: 1.2;\n        }\n        .logo-text .cn {\n            font-size: 15px;\n            font-weight: 700;\n            color: #527845;\n        }\n        .logo-text .en {\n            font-size: 10px;\n            color: #7d8a79;\n            letter-spacing: 0.4px;\n        }\n        .template-meta {\n            text-align: right;\n        }\n        .template-meta .meta-title {\n            font-size: 16px;\n            font-weight: 700;\n            color: #587d48;\n        }\n        .template-meta .meta-subtitle {\n            margin-top: 4px;\n            font-size: 11px;\n            color: #98a095;\n            letter-spacing: 0.8px;\n        }\n        /* 页脚（完全保持原样） */\n        .pagination {\n            position: absolute;\n            right: 36px;\n            bottom: 22px;\n            z-index: 5;\n            font-size: 18px;\n            font-weight: 700;\n            color: #94a08e;\n            background: rgba(255,255,255,0.9);\n            padding: 6px 14px;\n            border-radius: 20px;\n        }\n        .footer-note {\n            position: absolute;\n            left: 74px;\n            bottom: 22px;\n            z-index: 5;\n            font-size: 12px;\n            color: #9aa596;\n            letter-spacing: 0.2px;\n        }\n        /* 主要内容区域 - 创意设计 */\n        .main-content {\n            position: absolute;\n            top: 156px;\n            left: 68px;\n            right: 68px;\n            bottom: 64px;\n            z-index: 4;\n            display: flex;\n            flex-direction: column;\n        }\n        .page-title-area {\n            margin-bottom: 24px;\n            display: flex;\n            align-items: center;\n            gap: 16px;\n        }\n        .page-num-circle {\n            width: 72px;\n            height: 72px;\n            border-radius: 50%;\n            background: #55824a;\n            color: white;\n            font-size: 36px;\n            font-weight: 900;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            box-shadow: inset 0 -8px 0 rgba(255,255,255,0.12);\n            flex-shrink: 0;\n        }\n        .page-title-text h1 {\n            font-size: 30px;\n            line-height: 1.2;\n            color: #4f7b45;\n            font-weight: 900;\n        }\n        .page-title-text p {\n            font-size: 14px;\n            color: #90a28a;\n            margin-top: 6px;\n        }\n        /* 对比展示区 */\n        .comparison-section {\n            display: flex;\n            gap: 20px;\n            flex-grow: 1;\n            margin-bottom: 20px;\n        }\n        .break-card, .continue-card {\n            flex: 1;\n            background: rgba(255,255,255,0.78);\n            border: 1px solid rgba(96, 129, 79, 0.14);\n            border-radius: 20px;\n            padding: 24px;\n            backdrop-filter: blur(2px);\n            display: flex;\n            flex-direction: column;\n        }\n        .break-card {\n            border-top: 6px solid #e74c3c;\n        }\n        .continue-card {\n            border-top: 6px solid #3498db;\n        }\n        .card-header {\n            display: flex;\n            align-items: center;\n            gap: 12px;\n            margin-bottom: 16px;\n        }\n        .card-icon {\n            width: 48px;\n            height: 48px;\n            border-radius: 50%;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            font-size: 22px;\n            color: white;\n        }\n        .break-icon {\n            background: linear-gradient(135deg, #e74c3c, #c0392b);\n        }\n        .continue-icon {\n            background: linear-gradient(135deg, #3498db, #2980b9);\n        }\n        .card-title h3 {\n            font-size: 22px;\n            font-weight: 800;\n            color: #2c3e50;\n        }\n        .card-title p {\n            font-size: 13px;\n            color: #7f8c8d;\n            margin-top: 4px;\n        }\n        .card-description {\n            font-size: 15px;\n            line-height: 1.6;\n            color: #516250;\n            margin-bottom: 20px;\n            flex-grow: 1;\n        }\n        .flow-diagram {\n            background: #f8f9fa;\n            border-radius: 12px;\n            padding: 16px;\n            margin-bottom: 20px;\n            border: 1px dashed #bdc3c7;\n        }\n        .flow-step {\n            display: flex;\n            align-items: center;\n            margin-bottom: 8px;\n            font-size: 14px;\n        }\n        .step-num {\n            width: 24px;\n            height: 24px;\n            border-radius: 50%;\n            background: #95a5a6;\n            color: white;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            margin-right: 12px;\n            font-size: 12px;\n            flex-shrink: 0;\n        }\n        .break-step .step-num {\n            background: #e74c3c;\n        }\n        .continue-step .step-num {\n            background: #3498db;\n        }\n        /* 代码示例区 */\n        .code-example {\n            background: #2d3436;\n            border-radius: 12px;\n            padding: 16px;\n            margin-top: auto;\n            overflow: hidden;\n        }\n        .code-header {\n            display: flex;\n            justify-content: space-between;\n            align-items: center;\n            margin-bottom: 12px;\n            color: #ecf0f1;\n            font-size: 13px;\n        }\n        .code-lang {\n            background: #3d7a45;\n            padding: 4px 12px;\n            border-radius: 20px;\n            font-weight: 600;\n        }\n        pre[class*=\"language-\"] {\n            margin: 0;\n            background: transparent !important;\n            font-size: 13px;\n        }\n        /* 底部要点区 */\n        .bottom-points {\n            display: grid;\n            grid-template-columns: repeat(2, 1fr);\n            gap: 16px;\n        }\n        .point-card {\n            background: rgba(255,255,255,0.78);\n            border: 1px solid rgba(96, 129, 79, 0.14);\n            border-radius: 16px;\n            padding: 18px;\n            backdrop-filter: blur(2px);\n        }\n        .point-header {\n            display: flex;\n            align-items: center;\n            gap: 10px;\n            margin-bottom: 12px;\n        }\n        .point-icon {\n            width: 36px;\n            height: 36px;\n            border-radius: 50%;\n            background: #7fa64d;\n            color: white;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            font-size: 16px;\n        }\n        .point-title {\n            font-size: 16px;\n            font-weight: 700;\n            color: #4e7543;\n        }\n        .point-content {\n            font-size: 14px;\n            line-height: 1.6;\n            color: #516250;\n        }\n        .point-content ul {\n            list-style: none;\n            padding-left: 0;\n        }\n        .point-content li {\n            margin-bottom: 6px;\n            padding-left: 20px;\n            position: relative;\n        }\n        .point-content li::before {\n            content: \'•\';\n            position: absolute;\n            left: 0;\n            color: #7fa64d;\n            font-weight: bold;\n        }\n    </style>\n</head>\n<body>\n    <div class=\"slide-container\">\n        <div class=\"slide\">\n            <!-- 主题装饰层（完全保持原样） -->\n            <div class=\"top-strip\"></div>\n            <div class=\"bottom-strip\"></div>\n            <div class=\"deco-circle circle-a\"></div>\n            <div class=\"deco-circle circle-b\"></div>\n            <div class=\"deco-circle circle-c\"></div>\n            <div class=\"deco-circle circle-d\"></div>\n            <div class=\"deco-circle circle-e\"></div>\n            <div class=\"deco-circle circle-f\"></div>\n            <div class=\"deco-circle circle-g\"></div>\n            <div class=\"deco-circle circle-h\"></div>\n            <div class=\"leaf-mark\"><span></span></div>\n            <!-- 页眉占位信息（完全保持原样） -->\n            <div class=\"header-band\">\n                <div class=\"logo-group\">\n                    <div class=\"logo-badge\"><i class=\"fa-solid fa-mortar-pestle\"></i></div>\n                    <div class=\"logo-text\">\n                        <div class=\"cn\">食品药品职业学院</div>\n                        <div class=\"en\">Food and Drug Vocational College</div>\n                    </div>\n                </div>\n                <div class=\"template-meta\">\n                    <div class=\"meta-title\">C语言程序设计</div>\n                    <div class=\"meta-subtitle\">THIRD LESSON · LOOP CONTROL · BREAK & CONTINUE</div>\n                </div>\n            </div>\n            <!-- 主要内容区域 -->\n            <div class=\"main-content\">\n                <!-- 页面标题 -->\n                <div class=\"page-title-area\">\n                    <div class=\"page-num-circle\">5</div>\n                    <div class=\"page-title-text\">\n                        <h1>循环控制语句：break与continue</h1>\n                        <p>掌握循环的精准控制 - 理解两种关键控制语句的区别与应用</p>\n                    </div>\n                </div>\n                <!-- 对比展示区 -->\n                <div class=\"comparison-section\">\n                    <!-- break语句卡片 -->\n                    <div class=\"break-card\">\n                        <div class=\"card-header\">\n                            <div class=\"card-icon break-icon\">\n                                <i class=\"fa-solid fa-stop-circle\"></i>\n                            </div>\n                            <div class=\"card-title\">\n                                <h3>break语句</h3>\n                                <p>完全退出循环 · 循环终结者</p>\n                            </div>\n                        </div>\n                        <div class=\"card-description\">\n                            当满足特定条件时，立即终止整个循环的执行，跳出循环体，继续执行循环后面的代码。\n                        </div>\n                        <div class=\"flow-diagram\">\n                            <div class=\"flow-step break-step\">\n                                <div class=\"step-num\">1</div>\n                                <span>循环开始执行</span>\n                            </div>\n                            <div class=\"flow-step break-step\">\n                                <div class=\"step-num\">2</div>\n                                <span>执行循环体语句</span>\n                            </div>\n                            <div class=\"flow-step break-step\">\n                                <div class=\"step-num\">3</div>\n                                <span>遇到break条件</span>\n                            </div>\n                            <div class=\"flow-step break-step\">\n                                <div class=\"step-num\">4</div>\n                                <span><strong>立即终止循环</strong></span>\n                            </div>\n                            <div class=\"flow-step break-step\">\n                                <div class=\"step-num\">5</div>\n                                <span>执行循环后代码</span>\n                            </div>\n                        </div>\n                        <div class=\"code-example\">\n                            <div class=\"code-header\">\n                                <span>代码示例</span>\n                                <span class=\"code-lang\">C语言</span>\n                            </div>\n                            <pre><code class=\"language-c\">// 找到第一个负数就停止\nint numbers[] = {3, 8, -1, 7, 2};\nfor(int i = 0; i < 5; i++) {\n    if','{}',NULL,0,1773650000,1773650000),(45,'00bc98f1-1a7f-42d1-a550-45e85b9e61a1',5,'slide_5','循环结构实战练习','content','<!DOCTYPE html>\n<html lang=\"zh-CN\">\n<head>\n    <meta charset=\"UTF-8\">\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n    <title>循环结构实战练习 - C语言第三次课</title>\n    <!-- 引入字体与图标库 -->\n    <link rel=\"preconnect\" href=\"https://fonts.googleapis.com\">\n    <link rel=\"preconnect\" href=\"https://fonts.gstatic.com\" crossorigin>\n    <link href=\"https://fonts.googleapis.com/css2?family=Noto+Sans+SC:wght@400;500;700;900&display=swap\" rel=\"stylesheet\">\n    <link rel=\"stylesheet\" href=\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css\">\n    <!-- 引入Prism.js代码高亮 -->\n    <link href=\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/themes/prism-tomorrow.min.css\" rel=\"stylesheet\" />\n    <script src=\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/prism.min.js\"></script>\n    <script src=\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/components/prism-c.min.js\"></script>\n    <style>\n        /* 基础与重置样式 */\n        * {\n            margin: 0;\n            padding: 0;\n            box-sizing: border-box;\n        }\n        html, body {\n            width: 100%;\n            height: 100%;\n            overflow: hidden;\n            background: #eef1ed;\n            font-family: \'Noto Sans SC\', sans-serif;\n            color: #26412f;\n        }\n        /* 响应式缩放容器 */\n        .slide-container {\n            width: 100vw;\n            height: 100vh;\n            display: flex;\n            justify-content: center;\n            align-items: center;\n        }\n        /* 幻灯片核心画布（严格 1280×720） */\n        .slide {\n            width: 1280px;\n            height: 720px;\n            background: #fbfcf8;\n            position: relative;\n            overflow: hidden;\n            transform-origin: center center;\n            box-shadow: 0 10px 30px rgba(0, 0, 0, 0.12);\n        }\n        /* 主题装饰元素：完全保持原样 */\n        .top-strip,\n        .bottom-strip {\n            position: absolute;\n            left: 0;\n            width: 100%;\n            height: 8px;\n            background: linear-gradient(to right, rgba(130, 130, 130, 0.12), rgba(130, 130, 130, 0.45), rgba(130, 130, 130, 0.12));\n            z-index: 1;\n        }\n        .top-strip { top: 132px; }\n        .bottom-strip { bottom: 132px; }\n        .deco-circle {\n            position: absolute;\n            border-radius: 50%;\n            z-index: 1;\n        }\n        .circle-a { width: 280px; height: 280px; right: 120px; top: -80px; background: #3d7a45; }\n        .circle-b { width: 210px; height: 210px; right: 220px; top: 18px; background: #8cb043; opacity: 0.95; }\n        .circle-c { width: 86px; height: 86px; right: 52px; top: 42px; background: #cfdc72; }\n        .circle-d { width: 54px; height: 54px; left: 36px; top: 18px; background: #7eb377; }\n        .circle-e { width: 150px; height: 150px; left: 70px; bottom: -58px; background: #93bf84; }\n        .circle-f { width: 270px; height: 270px; left: 230px; bottom: -120px; background: #3f7345; opacity: 0.92; }\n        .circle-g { width: 190px; height: 190px; left: 360px; bottom: -90px; background: #9eb841; opacity: 0.85; }\n        .circle-h { width: 76px; height: 76px; right: 86px; bottom: 46px; background: #d8de7f; }\n        .leaf-mark {\n            position: absolute;\n            top: 32px;\n            left: 44px;\n            width: 70px;\n            height: 48px;\n            z-index: 3;\n        }\n        .leaf-mark::before,\n        .leaf-mark::after,\n        .leaf-mark span {\n            content: \'\';\n            position: absolute;\n            border-radius: 0 0 40px 0;\n        }\n        .leaf-mark::before {\n            left: 0;\n            top: 0;\n            width: 32px;\n            height: 32px;\n            background: #d8df79;\n        }\n        .leaf-mark::after {\n            left: 18px;\n            top: 0;\n            width: 34px;\n            height: 34px;\n            background: #89a95d;\n        }\n        .leaf-mark span {\n            left: 32px;\n            top: 0;\n            width: 38px;\n            height: 38px;\n            background: #426f4b;\n        }\n        /* 页眉信息区 - 完全保持原样 */\n        .header-band {\n            position: absolute;\n            left: 78px;\n            top: 34px;\n            right: 100px;\n            display: flex;\n            align-items: center;\n            justify-content: space-between;\n            z-index: 4;\n        }\n        .logo-group {\n            display: flex;\n            align-items: center;\n            gap: 14px;\n        }\n        .logo-badge {\n            width: 48px;\n            height: 48px;\n            border-radius: 50%;\n            border: 2px solid #5f8e4f;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            color: #5f8e4f;\n            background: rgba(255,255,255,0.95);\n            font-size: 22px;\n        }\n        .logo-text {\n            line-height: 1.2;\n        }\n        .logo-text .cn {\n            font-size: 15px;\n            font-weight: 700;\n            color: #527845;\n        }\n        .logo-text .en {\n            font-size: 10px;\n            color: #7d8a79;\n            letter-spacing: 0.4px;\n        }\n        .template-meta {\n            text-align: right;\n        }\n        .template-meta .meta-title {\n            font-size: 16px;\n            font-weight: 700;\n            color: #587d48;\n        }\n        .template-meta .meta-subtitle {\n            margin-top: 4px;\n            font-size: 11px;\n            color: #98a095;\n            letter-spacing: 0.8px;\n        }\n        /* 页脚区域 - 完全保持原样 */\n        .pagination {\n            position: absolute;\n            right: 36px;\n            bottom: 22px;\n            z-index: 5;\n            font-size: 18px;\n            font-weight: 700;\n            color: #94a08e;\n            background: rgba(255,255,255,0.9);\n            padding: 6px 14px;\n            border-radius: 20px;\n        }\n        .footer-note {\n            position: absolute;\n            left: 74px;\n            bottom: 22px;\n            z-index: 5;\n            font-size: 12px;\n            color: #9aa596;\n            letter-spacing: 0.2px;\n        }\n        /* 主要内容区域 - 创意设计开始 */\n        .main-content {\n            position: absolute;\n            top: 156px;\n            left: 68px;\n            right: 68px;\n            bottom: 64px;\n            z-index: 4;\n            display: flex;\n            flex-direction: column;\n            gap: 20px;\n        }\n        /* 页面标题区域 */\n        .page-header {\n            display: flex;\n            align-items: center;\n            gap: 20px;\n            margin-bottom: 10px;\n        }\n        .page-number {\n            width: 72px;\n            height: 72px;\n            border-radius: 50%;\n            background: #55824a;\n            color: white;\n            font-size: 36px;\n            font-weight: 900;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            box-shadow: inset 0 -8px 0 rgba(255,255,255,0.12);\n            flex-shrink: 0;\n        }\n        .page-title-content h1 {\n            font-size: 32px;\n            color: #4f7b45;\n            font-weight: 900;\n            margin-bottom: 6px;\n        }\n        .page-title-content .subtitle {\n            font-size: 16px;\n            color: #90a28a;\n            font-weight: 500;\n        }\n        /* 练习卡片网格布局 */\n        .exercises-grid {\n            display: grid;\n            grid-template-columns: repeat(2, 1fr);\n            grid-template-rows: repeat(2, 1fr);\n            gap: 24px;\n            height: 100%;\n            flex-grow: 1;\n        }\n        .exercise-card {\n            background: rgba(255, 255, 255, 0.85);\n            border-radius: 20px;\n            padding: 24px;\n            border: 2px solid rgba(96, 129, 79, 0.15);\n            position: relative;\n            display: flex;\n            flex-direction: column;\n            transition: all 0.3s ease;\n            box-shadow: 0 6px 20px rgba(0, 0, 0, 0.05);\n            overflow: hidden;\n        }\n        .exercise-card:hover {\n            transform: translateY(-5px);\n            box-shadow: 0 12px 30px rgba(0, 0, 0, 0.1);\n            border-color: #7fa64d;\n        }\n        .exercise-card:nth-child(4) {\n            grid-column: span 2;\n            background: linear-gradient(135deg, rgba(255, 255, 255, 0.9), rgba(246, 248, 241, 0.95));\n            border-color: #8dae48;\n        }\n        .exercise-header {\n            display: flex;\n            align-items: center;\n            justify-content: space-between;\n            margin-bottom: 16px;\n        }\n        .exercise-number {\n            width: 42px;\n            height: 42px;\n            border-radius: 50%;\n            background: #6d9d53;\n            color: white;\n            font-size: 20px;\n            font-weight: 700;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            flex-shrink: 0;\n        }\n        .exercise-title {\n            font-size: 20px;\n            font-weight: 700;\n            color: #4e7543;\n            flex-grow: 1;\n            margin-left: 16px;\n        }\n        .difficulty {\n            display: flex;\n            gap: 4px;\n        }\n        .star {\n            color: #ffd43b;\n            font-size: 14px;\n        }\n        .exercise-description {\n            font-size: 14px;\n            color: #60705f;\n            line-height: 1.6;\n            margin-bottom: 16px;\n            flex-grow: 1;\n        }\n        .exercise-visual {\n            display: flex;\n            align-items: center;\n            gap: 16px;\n            margin-top: auto;\n        }\n        .visual-icon {\n            width: 60px;\n            height: 60px;\n            border-radius: 12px;\n            background: rgba(141, 180, 127, 0.2);\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            color: #4e7543;\n            font-size: 24px;\n            flex-shrink: 0;\n        }\n        .visual-content {\n            flex-grow: 1;\n        }\n        .visual-title {\n            font-size: 13px;\n            font-weight: 600;\n            color: #6d9d53;\n            margin-bottom: 4px;\n        }\n        .visual-desc {\n            font-size: 12px;\n            color: #7d8a79;\n            line-height: 1.4;\n        }\n        /* 代码演示卡片特殊样式 */\n        .demo-card {\n            display: flex;\n            gap: 24px;\n            height: 100%;\n        }\n        .demo-left {\n            flex: 1;\n            display: flex;\n            flex-direction: column;\n        }\n        .demo-right {\n            flex: 1;\n            background: #1e2a38;\n            border-radius: 12px;\n            padding: 16px;\n            overflow: hidden;\n        }\n        .demo-title {\n            font-size: 18px;\n            font-weight: 700;\n            color: #4e7543;\n            margin-bottom: 12px;\n        }\n        .demo-steps {\n            list-style: none;\n            flex-grow: 1;\n        }\n        .demo-steps li {\n            font-size: 14px;\n            color: #60705f;\n            margin-bottom: 10px;\n            padding-left: 20px;\n            position: relative;\n            line-height: 1.5;\n        }\n        .demo-steps li::before {\n            content: \'▶\';\n            position: absolute;\n            left: 0;\n            color: #8dae48;\n            font-size: 12px;\n        }\n        .code-header {\n            display: flex;\n            justify-content: space-between;\n            align-items: center;\n            margin-bottom: 12px;\n            padding-bottom: 8px;\n            border-bottom: 1px solid rgba(255, 255, 255, 0.1);\n        }\n        .code-title {\n            font-size: 14px;\n            color: #c1ffc1;\n            font-weight: 600;\n        }\n        .code-language {\n            font-size: 12px;\n            color: #90a28a;\n            background: rgba(255, 255, 255, 0.1);\n            padding: 2px 8px;\n            border-radius: 4px;\n        }\n        .code-preview {\n            font-family: \'Courier New\', monospace;\n            font-size: 13px;\n            color: #c1ffc1;\n            line-height: 1.5;\n            white-space: pre-wrap;\n            overflow-y: auto;\n            max-height: 140px;\n        }\n        .code-preview .keyword {\n            color: #ff79c6;\n        }\n        .code-preview .function {\n            color: #50fa7b;\n        }\n        .code-preview .number {\n            color: #bd93f9;\n        }\n        .code-preview .comment {\n            color: #6272a4;\n        }\n        /* 技能标签 */\n        .skill-tags {\n            display: flex;\n            flex-wrap: wrap;\n            gap: 6px;\n            margin-top: 12px;\n        }\n        .skill-tag {\n            font-size: 11px;\n            padding: 3px 8px;\n            background: rgba(141, 180, 127, 0.15);\n            color: #507247;\n            border-radius: 12px;\n            border: 1px solid rgba(141, 180, 127, 0.3);\n        }\n        /* 进度指示器 */\n        .progress-indicator {\n            position: absolute;\n            bottom: 20px;\n            left: 50%;\n            transform: translateX(-50%);\n            display: flex;\n            gap: 8px;\n            z-index: 4;\n        }\n        .progress-dot {\n            width: 8px;\n            height: 8px;\n            border-radius: 50%;\n            background: rgba(141, 180, 127, 0.3);\n            transition: all 0.3s ease;\n        }\n        .progress-dot.active {\n            background: #8dae48;\n            transform: scale(1.2);\n        }\n    </style>\n</head>\n<body>\n    <div class=\"slide-container\">\n        <div class=\"slide\">\n            <!-- 主题装饰层 - 完全保持原样 -->\n            <div class=\"top-strip\"></div>\n            <div class=\"bottom-strip\"></div>\n            <div class=\"deco-circle circle-a\"></div>\n            <div class=\"deco-circle circle-b\"></div>\n            <div class=\"deco-circle circle-c\"></div>\n            <div class=\"deco-circle circle-d\"></div>\n            <div class=\"deco-circle circle-e\"></div>\n            <div class=\"deco-circle circle-f\"></div>\n            <div class=\"deco-circle circle-g\"></div>\n            <div class=\"deco-circle circle-h\"></div>\n            <div class=\"leaf-mark\"><span></span></div>\n            <!-- 页眉占位信息 - 完全保持原样 -->\n            <div class=\"header-band\">\n                <div class=\"logo-group\">\n                    <div class=\"logo-badge\"><i class=\"fa-solid fa-code\"></i></div>\n                    <div class=\"logo-text\">\n                        <div class=\"cn\">食品药品职业学院</div>\n                        <div class=\"en\">Food and Drug Vocational College</div>\n                    </div>\n                </div>\n                <div class=\"template-meta\">\n                    <div class=\"meta-title\">C语言程序设计</div>\n                    <div class=\"meta-subtitle\">第三次课 · 循环结构专题</div>\n                </div>\n            </div>\n            <!-- 主要内容区域 - 创意设计 -->\n            <div class=\"main-content\">\n                <div class=\"page-header\">\n                    <div class=\"page-number\">06</div>\n                    <div class=\"page-title-content\">\n                        <h1>循环结构实战练习</h1>\n                        <div class=\"subtitle\">从理论到实践 · 掌握循环编程核心技能</div>\n                    </div>\n                </div>\n                <div class=\"exercises-grid\">\n                    <!-- 练习一','{}',NULL,0,1773650000,1773650000),(46,'00bc98f1-1a7f-42d1-a550-45e85b9e61a1',6,'slide_6','一维数组：定义与初始化','content','<!DOCTYPE html>\n<html lang=\"zh-CN\">\n<head>\n    <meta charset=\"UTF-8\">\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n    <title>一维数组：定义与初始化</title>\n    <link rel=\"preconnect\" href=\"https://fonts.googleapis.com\">\n    <link rel=\"preconnect\" href=\"https://fonts.gstatic.com\" crossorigin>\n    <link href=\"https://fonts.googleapis.com/css2?family=Noto+Sans+SC:wght@400;500;700;900&display=swap\" rel=\"stylesheet\">\n    <link rel=\"stylesheet\" href=\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css\">\n    <script src=\"https://cdn.jsdelivr.net/npm/chart.js\"></script>\n    <script src=\"https://polyfill.io/v3/polyfill.min.js?features=es6\"></script>\n    <script id=\"MathJax-script\" async src=\"https://cdn.jsdelivr.net/npm/mathjax@3/es5/tex-mml-chtml.js\"></script>\n    <link href=\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/themes/prism-tomorrow.min.css\" rel=\"stylesheet\" />\n    <script src=\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/prism.min.js\"></script>\n    <script src=\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/components/prism-c.min.js\"></script>\n    <style>\n        * {\n            margin: 0;\n            padding: 0;\n            box-sizing: border-box;\n        }\n        html, body 