            letter-spacing: 0.4px;\n        }\n        .template-meta {\n            text-align: right;\n        }\n        .template-meta .meta-title {\n            font-size: 16px;\n            font-weight: 700;\n            color: #587d48;\n        }\n        .template-meta .meta-subtitle {\n            margin-top: 4px;\n            font-size: 11px;\n            color: #98a095;\n            letter-spacing: 0.8px;\n        }\n        .content-area {\n            position: absolute;\n            top: 156px;\n            left: 68px;\n            right: 68px;\n            bottom: 64px;\n            z-index: 4;\n            display: flex;\n            flex-direction: column;\n            gap: 20px;\n        }\n        .page-title {\n            display: flex;\n            align-items: center;\n            gap: 20px;\n            margin-bottom: 10px;\n        }\n        .page-title .num {\n            width: 72px;\n            height: 72px;\n            border-radius: 50%;\n            background: #55824a;\n            color: white;\n            font-size: 36px;\n            font-weight: 900;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            box-shadow: inset 0 -8px 0 rgba(255,255,255,0.12);\n            flex-shrink: 0;\n        }\n        .page-title .text h1 {\n            font-size: 36px;\n            line-height: 1.2;\n            color: #4f7b45;\n            font-weight: 900;\n        }\n        .page-title .text p {\n            font-size: 16px;\n            color: #90a28a;\n            margin-top: 6px;\n        }\n        .main-content {\n            display: grid;\n            grid-template-columns: 1fr 1.2fr;\n            gap: 30px;\n            flex-grow: 1;\n            min-height: 0;\n        }\n        .left-column {\n            display: flex;\n            flex-direction: column;\n            gap: 20px;\n        }\n        .concept-card {\n            background: rgba(255,255,255,0.85);\n     