        .right-column {\n            display: flex;\n            flex-direction: column;\n            gap: 20px;\n        }\n        .visualization-panel {\n            background: rgba(255,255,255,0.85);\n            border: 1px solid rgba(96, 129, 79, 0.15);\n            border-radius: 18px;\n            padding: 22px;\n            box-shadow: 0 6px 16px rgba(0,0,0,0.05);\n            flex-grow: 1;\n            display: flex;\n            flex-direction: column;\n        }\n        .array-model {\n            display: flex;\n            flex-direction: column;\n            align-items: center;\n            justify-content: center;\n            flex-grow: 1;\n            gap: 25px;\n        }\n        .array-title {\n            font-size: 20px;\n            color: #4e7543;\n            font-weight: 700;\n            text-align: center;\n            margin-bottom: 10px;\n        }\n        .array-container {\n            display: flex;\n            align-items: center;\n            gap: 4px;\n            position: relative;\n        }\n        .array-element {\n            width: 80px;\n            height: 100px;\n            background: linear-gradient(145deg, #f0f5e9, #ffffff);\n            border: 2px solid #8cb043;\n            border-radius: 12px;\n            display: flex;\n            flex-direction: column;\n            align-items: center;\n            justify-content: center;\n            box-shadow: 0 4px 8px rgba(0,0,0,0.08);\n            transition: all 0.3s;\n            position: relative;\n            overflow: hidden;\n        }\n        .array-element.active {\n            transform: translateY(-8px);\n            border-color: #ff6b35;\n            box-shadow: 0 8px 16px rgba(255,107,53,0.2);\n        }\n        .element-index {\n            position: absolute;\n            top: 8px;\n            font-size: 14px;\n            color: #ff6b35;\n            font-weight: 700;\n        }\n        .element-value {\n            font-size: 28px;\n            font-weight: 900;\n            color: #3f7345;\n            font-family: \'Consolas\', monospace;\n        }\n        .element-address {\n            position: absolute;\n            bottom: 8px;\n            font-size: 11px;\n            color: #7d8a79;\n            font-family: \'Consolas\', monospace;\n        }\n        .access-pointer {\n            position: absolute;\n            bottom: -40px;\n            left: 50%;\n            transform: translateX(-50%);\n            display: flex;\n            flex-direction: column;\n            align-items: center;\n            gap: 5px;\n            opacity: 0;\n            transition: opacity 0.3s;\n        }\n        .access-pointer.show {\n            opacity: 1;\n        }\n        .pointer-arrow {\n            color: #e53e3e;\n            font-size: 24px;\n        }\n        .pointer-label {\n            background: #e53e3e;\n            color: white;\n            padding: 4px 12px;\n            border-radius: 20px;\n            font-size: 14px;\n            font-weight: 700;\n            white-space: nowrap;\n        }\n        .memory-note {\n            text-align: center;\n            font-size: 14px;\n            color: #667163;\n            background: #f6f8f2;\n            padding: 10px 20px;\n            border-radius: 12px;\n            border: 1px dashed #8cb043;\n            max-width: 80%;\n            margin: 0 auto;\n        }\n        .code-examples {\n            background: #2d3748;\n            border-radius: 16px;\n            padding: 20px;\n            overflow: hidden;\n        }\n        .code-header {\n            display: flex;\n            justify-content: space-between;\n            align-items: center;\n            margin-bottom: 15px;\n        }\n        .code-header h3 {\n            color: #e2e8f0;\n            font-size: 18px;\n            font-weight: 700;\n        }\n        .code-tabs {\n            display: flex;\n            gap: 10px;\n        }\n        .code-tab {\n 