round: #9eb841; opacity: 0.85; }\n        .circle-h { width: 76px; height: 76px; right: 86px; bottom: 46px; background: #d8de7f; }\n        .leaf-mark {\n            position: absolute;\n            top: 32px;\n            left: 44px;\n            width: 70px;\n            height: 48px;\n            z-index: 3;\n        }\n        .leaf-mark::before,\n        .leaf-mark::after,\n        .leaf-mark span {\n            content: \'\';\n            position: absolute;\n            border-radius: 0 0 40px 0;\n        }\n        .leaf-mark::before {\n            left: 0;\n            top: 0;\n            width: 32px;\n            height: 32px;\n            background: #d8df79;\n        }\n        .leaf-mark::after {\n            left: 18px;\n            top: 0;\n            width: 34px;\n            height: 34px;\n            background: #89a95d;\n        }\n        .leaf-mark span {\n            left: 32px;\n            top: 0;\n            width: 38px;\n            height: 38px;\n            background: #426f4b;\n        }\n        .header-band {\n            position: absolute;\n            left: 78px;\n            top: 34px;\n            right: 100px;\n            display: flex;\n            align-items: center;\n            justify-content: space-between;\n            z-index: 4;\n        }\n        .logo-group {\n            display: flex;\n            align-items: center;\n            gap: 14px;\n        }\n        .logo-badge {\n            width: 48px;\n            height: 48px;\n            border-radius: 50%;\n            border: 2px solid #5f8e4f;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            color: #5f8e4f;\n            background: rgba(255,255,255,0.95);\n            font-size: 22px;\n        }\n        .logo-text {\n            line-height: 1.2;\n        }\n        .logo-text .cn {\n            font-size: 15px;\n            font-weight: 700;\n            color: #527845;\n        }\n        .logo-text .en {\n            font-size: 10px;\n            color: #7d8a79;\n            letter-spacing: 0.4px;\n        }\n        .template-meta {\n            text-align: right;\n        }\n        .template-meta .meta-title {\n            font-size: 16px;\n            font-weight: 700;\n            color: #587d48;\n        }\n        .template-meta .meta-subtitle {\n            margin-top: 4px;\n            font-size: 11px;\n            color: #98a095;\n            letter-spacing: 0.8px;\n        }\n        .footer-note {\n            position: absolute;\n            left: 74px;\n            bottom: 22px;\n            z-index: 5;\n            font-size: 12px;\n            color: #9aa596;\n            letter-spacing: 0.2px;\n        }\n        .pagination {\n            position: absolute;\n            right: 36px;\n            bottom: 22px;\n            z-index: 5;\n            font-size: 18px;\n            font-weight: 700;\n            color: #94a08e;\n            background: rgba(255,255,255,0.9);\n            padding: 6px 14px;\n            border-radius: 20px;\n        }\n        /* 主要内容区域 - 创意设计部分 */\n        .main-content {\n            position: absolute;\n            top: 156px;\n            left: 68px;\n            right: 68px;\n            bottom: 64px;\n            z-index: 4;\n            display: flex;\n            flex-direction: column;\n        }\n        .page-header {\n            margin-bottom: 30px;\n            display: flex;\n            align-items: center;\n            gap: 20px;\n        }\n        .page-number-circle {\n            width: 72px;\n            height: 72px;\n            border-radius: 50%;\n            background: #55824a;\n            color: white;\n            font-size: 36px;\n            font-weight: 900;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            box-shadow: inset 0 -8px 0 rgba(255,255,255,0.12);\n            flex-shrink: 0;\n        }\n        .page-title-section h1 {\n            font-size: 32px;\n            color: #4f7b45;\n            font-weight: 900;\n            margin-bottom: 6px;\n        }\n        .page-title-section .subtitle {\n            font-size: 16px;\n            color: #90a28a;\n            font-weight: 500;\n        }\n        /* 操作流程可视化设计 */\n        .operation-flow {\n            flex-grow: 1;\n            display: flex;\n            flex-direction: column;\n            justify-content: center;\n        }\n        .flow-container {\n            display: flex;\n            align-items: center;\n            justify-content: space-between;\n            margin-bottom: 40px;\n            position: relative;\n        }\n        .flow-step {\n            width: 220px;\n            height: 180px;\n            background: rgba(255, 255, 255, 0.85);\n            border-radius: 20px;\n            padding: 24px;\n            display: flex;\n            flex-direction: column;\n            align-items: center;\n            justify-content: center;\n            text-align: center;\n            box-shadow: 0 8px 24px rgba(63, 115, 69, 0.12);\n            border: 2px solid rgba(96, 129, 79, 0.1);\n            transition: transform 0.3s ease, box-shadow 0.3s ease;\n            position: relative;\n            z-index: 2;\n        }\n        .flow-step:hover {\n            transform: translateY(-5px);\n            box-shadow: 0 12px 32px rgba(63, 115, 69, 0.18);\n        }\n        .step-icon {\n            width: 60px;\n            height: 60px;\n            border-radius: 50%;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            margin-bottom: 16px;\n            font-size: 24px;\n            color: white;\n        }\n        .step-1 .step-icon { background: linear-gradient(135deg, #4CAF50, #2E7D32); }\n        .step-2 .step-icon { background: linear-gradient(135deg, #2196F3, #0D47A1); }\n        .step-3 .step-icon { background: linear-gradient(135deg, #FF9800, #EF6C00); }\n        .step-4 .step-icon { background: linear-gradient(135deg, #9C27B0, #6A1B9A); }\n        .step-title {\n            font-size: 18px;\n            font-weight: 700;\n            color: #2c3e2f;\n            margin-bottom: 8px;\n        }\n        .step-desc {\n            font-size: 13px;\n            color: #5a6d5a;\n            line-height: 1.5;\n        }\n        .flow-arrow {\n            position: absolute;\n            width: 80px;\n            height: 4px;\n            background: linear-gradient(to right, #8dae48, #6e9a57);\n            z-index: 1;\n        }\n        .flow-arrow::after {\n            content: \'\';\n            position: absolute;\n            right: -8px;\n            top: -6px;\n            width: 0;\n            height: 0;\n            border-left: 10px solid #6e9a57;\n            border-top: 8px solid transparent;\n            border-bottom: 8px solid transparent;\n        }\n        .arrow-1 { left: 240px; top: 90px; }\n        .arrow-2 { left: 500px; top: 90px; }\n        .arrow-3 { left: 760px; top: 90px; }\n        /* 代码示例区域 */\n        .code-examples {\n            background: rgba(255, 255, 255, 0.78);\n            border-radius: 16px;\n            padding: 20px;\n            border: 1px solid rgba(96, 129, 79, 0.14);\n            backdrop-filter: blur(2px);\n        }\n        .code-title {\n            font-size: 16px;\n            font-weight: 700;\n            color: #4e7543;\n            margin-bottom: 12px;\n            display: flex;\n            align-items: center;\n            gap: 8px;\n        }\n        .code-title i {\n            color: #8dae48;\n        }\n        .code-grid {\n            display: grid;\n            grid-template-columns: repeat(2, 1fr);\n            gap: 16px;\n        }\n        .code-block {\n            background: #1e1e1e;\n            border-radius: 12px;\n            overflow: hidden;\n            border: 1px solid rgba(255, 255, 255, 0.1);\n        }\n        .code-header {\n            background: #2d2d2d;\n            padding: 8px 16px;\n            font-size: 12px;\n            color: #ccc;\n            display: flex;\n            justify-content: space-between;\n            align-items: center;\n        }\n        .code-lang {\n            color: #8dae48;\n            font-weight: 600;\n        }\n        pre[class*=\"language-\"] {\n            margin: 0;\n            padding: 16px;\n            font-size: 13px;\n            max-height: 160px;\n            overflow-y: auto;\n        }\n        .code-block:nth-child(1) .code-header { border-left: 4px solid #4CAF50; }\n        .code-block:nth-child(2) .code-header { border-left: 4px solid #2196F3; }\n        .code-block:nth-child(3) .code-header { border-left: 4px solid #FF9800; }\n        .code-block:nth-child(4) .code-header { border-left: 4px solid #9C27B0; }\n    </style>\n</head>\n<body>\n    <div class=\"slide-container\">\n        <div class=\"slide\">\n            <!-- 主题装饰层（严格保持原样） -->\n            <div class=\"top-strip\"></div>\n            <div class=\"bottom-strip\"></div>\n            <div class=\"deco-circle circle-a\"></div>\n            <div class=\"deco-circle circle-b\"></div>\n            <div class=\"deco-circle circle-c\"></div>\n            <div class=\"deco-circle circle-d\"></div>\n            <div class=\"deco-circle circle-e\"></div>\n            <div class=\"deco-circle circle-f\"></div>\n            <div class=\"deco-circle circle-g\"></div>\n            <div class=\"deco-circle circle-h\"></div>\n            <div class=\"leaf-mark\"><span></span></div>\n            <!-- 页眉占位信息（严格保持原样） -->\n            <div class=\"header-band\">\n                <div class=\"logo-group\">\n                    <div class=\"logo-badge\"><i class=\"fa-solid fa-mortar-pestle\"></i></div>\n                    <div class=\"logo-text\">\n                        <div class=\"cn\">食品药品职业学院</div>\n                        <div class=\"en\">Food and Drug Vocat