(to right, #38B2AC, #2C7A7B); }\n        .node-4::before { background: linear-gradient(to right, #ED8936, #DD6B20); }\n        .node-header {\n            display: flex;\n            align-items: center;\n            gap: 12px;\n            margin-bottom: 16px;\n        }\n        .node-icon {\n            width: 48px;\n            height: 48px;\n            border-radius: 50%;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            font-size: 20px;\n            color: white;\n            flex-shrink: 0;\n        }\n        .node-1 .node-icon { background: #9F7AEA; }\n        .node-2 .node-icon { background: #2D74C8; }\n        .node-3 .node-icon { background: #38B2AC; }\n        .node-4 .node-icon { background: #ED8936; }\n        .node-title h3 {\n            font-size: 20px;\n            font-weight: 800;\n            color: #2D3748;\n            margin-bottom: 4px;\n        }\n        .node-title p {\n            font-size: 13px;\n            color: #718096;\n            font-weight: 500;\n        }\n        .node-content {\n            flex-grow: 1;\n            display: flex;\n            flex-direction: column;\n        }\n        .node-desc {\n            font-size: 15px;\n            line-height: 1.6;\n            color: #4A5568;\n            margin-bottom: 16px;\n            flex-grow: 1;\n        }\n        .node-features {\n            list-style: none;\n            margin-top: auto;\n        }\n        .node-features li {\n            font-size: 13px;\n            color: #5F6C7B;\n            margin-bottom: 6px;\n            padding-left: 18px;\n            position: relative;\n        }\n        .node-features li::before {\n            content: \'✓\';\n            position: absolute;\n            left: 0;\n            color: #68D391;\n            font-weight: bold;\n        }\n        /* 中心连接点 */\n        .center-connection {\n            position: absolute;\n            top: 50%;\n            left: 50%;\n            transform: translate(-50%, -50%);\n            width: 80px;\n            height: 80px;\n            border-radius: 50%;\n            background: linear-gradient(135deg, #ED8936, #F6AD55);\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            color: white;\n            font-size: 14px;\n            font-weight: 800;\n            text-align: center;\n            box-shadow: 0 8px 24px rgba(237, 137, 54, 0.4);\n            z-index: 2;\n            padding: 10px;\n            border: 4px solid rgba(255, 255, 255, 0.9);\n        }\n        /* 连接线 */\n        .connection-line {\n            position: absolute;\n            z-index: 1;\n            stroke-width: 2;\n            stroke-dasharray: 5, 5;\n            opacity: 0.6;\n        }\n        .line-1 { stroke: #9F7AEA; }\n        .line-2 { stroke: #2D74C8; }\n        .line-3 { stroke: #38B2AC; }\n        .line-4 { stroke: #ED8936; }\n        /* 底部进度提示 */\n        .progress-hint {\n            margin-top: 20px;\n            text-align: center;\n            font-size: 14px;\n            color: #90a28a;\n            font-weight: 500;\n        }\n        .progress-hint i {\n            margin-right: 8px;\n            color: #8cb043;\n        }\n    </style>\n</head>\n<body>\n    <div class=\"slide-container\">\n        <!-- 主题装饰层 -->\n        <div class=\"top-strip\"></div>\n        <div class=\"bottom-strip\"></div>\n        <div class=\"deco-circle circle-a\"></div>\n        <div class=\"deco-circle circle-b\"></div>\n        <div class=\"deco-circle circle-c\"></div>\n        <div class=\"deco-circle circle-d\"></div>\n        <div class=\"deco-circle circle-e\"></div>\n        <div class=\"deco-circle circle-f\"></div>\n        <div class=\"deco-circle circle-g\"></div>\n        <div class=\"deco-circle circle-h\"></div>\n        <div class=\"leaf-mark\"><span></span></div>\n        <!-- 页眉信息 -->\n        <div class=\"header-band\">\n    