        }\n        .leaf-mark span {\n            left: 32px;\n            top: 0;\n            width: 38px;\n            height: 38px;\n            background: #426f4b;\n        }\n        /* 页眉信息区 - 严格保持原样 */\n        .header-band {\n            position: absolute;\n            left: 78px;\n            top: 34px;\n            right: 100px;\n            display: flex;\n            align-items: center;\n            justify-content: space-between;\n            z-index: 4;\n        }\n        .logo-group {\n            display: flex;\n            align-items: center;\n            gap: 14px;\n        }\n        .logo-badge {\n            width: 48px;\n            height: 48px;\n            border-radius: 50%;\n            border: 2px solid #5f8e4f;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            color: #5f8e4f;\n            background: rgba(255,255,255,0.95);\n            font-size: 22px;\n        }\n        .logo-text {\n            line-height: 1.2;\n        }\n        .logo-text .cn {\n            font-size: 15px;\n            font-weight: 700;\n            color: #527845;\n        }\n        .logo-text .en {\n            font-size: 10px;\n            color: #7d8a79;\n            letter-spacing: 0.4px;\n        }\n        .template-meta {\n            text-align: right;\n        }\n        .template-meta .meta-title {\n            font-size: 16px;\n            font-weight: 700;\n            color: #587d48;\n        }\n        .template-meta .meta-subtitle {\n            margin-top: 4px;\n            font-size: 11px;\n            color: #98a095;\n            letter-spacing: 0.8px;\n        }\n        /* 页脚区域 - 严格保持原样 */\n        .footer-note {\n            position: absolute;\n            left: 74px;\n            bottom: 22px;\n            z-index: 5;\n            font-size: 12px;\n            color: #9aa596;\n            letter-spacing: 0.2px;\n        }\n        .pagination {\n            position: absolute;\n            right: 36px;\n            bottom: 22px;\n            z-index: 5;\n            font-size: 18px;\n            font-weight: 700;\n            color: #94a08e;\n            background: rgba(255,255,255,0.9);\n            padding: 6px 14px;\n            border-radius: 20px;\n        }\n        /* 主要内容区域 - 可修改区域 */\n        .content-area {\n            position: absolute;\n            top: 156px;\n            left: 68px;\n            right: 68px;\n            bottom: 64px;\n            z-index: 4;\n            display: flex;\n            flex-direction: column;\n        }\n        /* 标题区域 */\n        .page-title {\n            display: flex;\n            align-items: center;\n            gap: 20px;\n            margin-bottom: 30px;\n        }\n        .page-title .num {\n            width: 72px;\n            height: 72px;\n            border-radius: 50%;\n            background: #55824a;\n            color: white;\n            font-size: 36px;\n            font-weight: 900;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            box-shadow: inset 0 -8px 0 rgba(255,255,255,0.12);\n            flex-shrink: 0;\n        }\n        .page-title .text h1 {\n            font-size: 42px;\n            line-height: 1.2;\n            color: #4f7b45;\n            font-weight: 900;\n            margin-bottom: 6px;\n        }\n        .page-title .text p {\n            font-size: 16px;\n            color: #90a28a;\n        }\n        /* 主要内容容器 */\n        .main-content {\n            flex-grow: 1;\n            display: grid;\n            grid-template-columns: 1fr 1fr;\n            gap: 30px;\n            height: calc(100% - 110px);\n        }\n        /* 左侧问答与总结区域 */\n        .left-section {\n            display: flex;\n            flex-direction: column;\n            gap: 24px;\n        }\n        .content-card {\n            background: rgba(255, 255, 255, 0.85);\n            border-radius: 20px;\n            padding: 24px;\n            border: 1px solid rgba(96, 129, 79, 0.14);\n            box-shadow: 0 6px 20px rgba(0, 0, 0, 0.05);\n            backdrop-filter: blur(4px);\n            flex-grow: 1;\n            display: flex;\n            flex-direction: column;\n        }\n        .card-header {\n            display: flex;\n            align-items: center;\n            gap: 12px;\n            margin-bottom: 18px;\n        }\n        .card-icon {\n            width: 48px;\n            height: 48px;\n            border-radius: 50%;\n            background: #6d9d53;\n            color: white;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            font-size: 20px;\n            flex-shrink: 0;\n        }\n        .card-title {\n            font-size: 22px;\n            font-weight: 800;\n            color: #4e7543;\n        }\n        .card-content {\n            font-size: 16px;\n            line-height: 1.7;\n            color: #516250;\n            flex-grow: 1;\n            display: flex;\n            align-items: center;\n        }\n        .qa-highlight {\n            background: #f6f8f1;\n            border-left: 4px solid #8dae48;\n            padding: 16px;\n            border-radius: 12px;\n            margin-top: 12px;\n        }\n        /* 右侧预告与感谢区域 */\n        .right-section {\n            display: flex;\n            flex-direction: column;\n            gap: 24px;\n        }\n        .preview-card {\n            background: linear-gradient(135deg, rgba(141, 180, 127, 0.1), rgba(109, 157, 83, 0.08));\n            border-radius: 20px;\n            padding: 24px;\n            border: 2px solid rgba(141, 180, 127, 0.3);\n            flex-grow: 1;\n            display: flex;\n            flex-direction: column;\n        }\n        .preview-title {\n            font-size: 20px;\n            font-weight: 800;\n            color: #4e7543;\n            margin-bottom: 16px;\n            display: flex;\n            align-items: center;\n            gap: 10px;\n        }\n        .preview-title i {\n            color: #8dae48;\n        }\n        .next-topic {\n            background: white;\n            border-radius: 16px;\n            padding: 20px;\n            margin-top: 12px;\n            border: 1px solid rgba(141, 180, 127, 0.2);\n        }\n        .topic-title {\n            font-size: 18px;\n            font-weight: 700;\n            color: #3f7345;\n            margin-bottom: 8px;\n        }\n        .topic-desc {\n            font-size: 14px;\n            color: #667163;\n            line-height: 1.6;\n        }\n        /* 感谢区域 */\n        .thankyou-card {\n            background: linear-gradient(135deg, #55824a, #6d9d53);\n            border-radius: 20px;\n            padding: 32px;\n            text-align: center;\n            display: flex;\n            flex-direction: column;\n            justify-content: center;\n            align-items: center;\n            min-height: 180px;\n        }\n        .thankyou-text {\n            font-size: 48px;\n            font-weight: 900;\n            color: white;\n            margin-bottom: 12px;\n            text-shadow: 0 4px 8px rgba(0, 0, 0, 0.15);\n        }\n        .thankyou-subtext {\n            font-size: 18px;\n            color: rgba(255, 255, 255, 0.9);\n            font-weight: 500;\n        }\n        /* 装饰元素 */\n        .floating-icon {\n            position: absolute;\n            z-index: 2;\n            opacity: 0.7;\n        }\n        .floating-icon.question {\n            right: 180px;\n            bottom: 180px;\n            font-size: 32px;\n            color: #8dae48;\n        }\n        .floating-icon.check {\n            left: 200px;\n            bottom: 220px;\n            font-size: 28px;\n            color: #6d9d53;\n        }\n        .floating-icon.calendar {\n            right: 250px;\n            top: 200px;\n            font-size: 24px;\n            color: #7eb377;\n        }\n    </style>\n</head>\n<body>\n    <div class=\"slide-container\">\n        <div class=\"slide\">\n            <!-- 主题装饰层 - 严格保持原样 -->\n            <div class=\"top-strip\"></div>\n            <div class=\"bottom-strip\"></div>\n            <div class=\"deco-circle circle-a\"></div>\n            <div class=\"deco-circle circle-b\"></div>\n            <div class=\"deco-circle circle-c\"></div>\n            <div class=\"deco-circle circle-d\"></div>\n            <div class=\"deco-circle circle-e\"></div>\n            <div class=\"deco-circle circle-f\"></div>\n            <div class=\"deco-circle circle-g\"></div>\n            <div class=\"deco-circle circle-h\"></div>\n            <div class=\"leaf-mark\"><span></span></div>\n            <!-- 页眉占位信息 - 严格保持原样 -->\n            <div class=\"header-band\">\n                <div class=\"logo-group\">\n                    <div class=\"logo-badge\"><i class=\"fa-solid fa-code\"></i></div>\n                    <div class=\"logo-text\">\n                        <div class=\"cn\">C语言程序设计</div>\n                        <div class=\"en\">C Programming Language</div>\n                    </div>\n                </div>\n                <div class=\"template-meta\">\n                    <div class=\"meta-title\">第三次课：指针与数组</div>\n                    <div class=\"meta-subtitle\">GREEN · MINIMAL · CIRCLE-DRIVEN · SECTIONAL REPORT</div>\n                </div>\n            </div>\n            <!-- 主要内容区域 -->\n            <div class=\"content-area\">\n                <!-- 页面标题 -->\n                <div class=\"page-title\">\n                    <div class=\"num\">12</div>\n                    <div class=\"text\">\n                        <h1>Q&A 与 课程结束</h1>\n                        <p>互动交流 · 总结回顾 · 展望未来</p>\n                    </div>\n                </div>\n                <!-- 主要内容网格 -->\n                <div class=\"main-content\">\n                    <!-- 左侧区域 -->\n                    <div class=\"left-section\">\n                        <!-- 问答环节 -->\n                        <div class=\"content-card\">\n                            <div class=\"card-header\">\n                                <div class=\"card-icon\">\n                                    <i class=\"fa-solid fa-comments\"></i>\n                                </div>\n                                <div class=\"card-title\">欢迎提问 · 互动交流</div>\n                            </div>\n                            <div class=\"card-content\">\n                                <div>\n                                    <p>现在是自由提问时间，关于指针、数组、内存管理或任何C语言相关的问题，我们都将为您详细解答。</p>\n                                    <div class=\"qa-highlight\">\n                                        <p><strong>提问方式：</strong></p>\n                                        <p>1. 课堂现场提问<br>\n                                        2. 课程群内@讲师<br>\n                                        3. 邮件至：c_course@edu.cn</p>\n                                    </div>\n                                </div>\n                            </div>\n                        </div>\n                        <!-- 课程总结 -->\n                        <div class=\"content-card\">\n                            <div class=\"card-header\">\n                                <div class=\"card-icon\">\n                                    <i class=\"fa-solid fa-star\"></i>\n                                </div>\n                                <div class=\"card-title\">核心回顾 · 与你共勉</div>\n                            </div>\n                            <div class=\"card-content\">\n                                <div>\n                                    <p>本次课程我们深入探讨了指针与数组的核心概念，掌握了内存地址操作的基本原理。记住：理解指针是掌握C语言的关键一步。</p>\n                                    <p style=\"margin-top: 12px; font-style: italic; color: #6d9d53;\">\"编程不仅是写代码，更是理解计算机如何思考。\"</p>\n                                </div>\n                            </div>\n                        </div>\n                    </div>\n                    <!-- 右侧区域 -->\n                    <div class=\"right-section\">\n                        <!-- 下节课预告 -->\n                        <div class=\"preview-card\">\n                            <div class=\"preview-title\">\n                                <i class=\"fa-solid fa-calendar-alt\"></i>\n                                下期预告 · 精彩继续\n                            </div>\n                            <div class=\"card-content\">\n                                <p>下一节课我们将进入更精彩的C语言世界：</p>\n                                <div class=\"next-topic\">\n                                    <div class=\"topic-title\">结构体与文件操作</div>\n                                    <div class=\"topic-desc\">\n                                        学习如何组织复杂数据，以及如何将数据持久化保存到文件中。这是从基础语法向实际应用迈进的重要一步。\n                                    </div>\n                                </div>\n                                <p style=\"margin-top: 16px; font-size: 14px; color: #667163;\">\n                                    <i class=\"','{}',NULL,0,1773650000,1773650000),(52,'d2191990-b108-4b42-8218-35c46b7c4b86',0,'slide_0','C语言第四次课','content','<!DOCTYPE html>\n<html lang=\"zh-CN\">\n<head>\n<meta charset=\"UTF-8\" />\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\n<title>C语言第四次课</title>\n<style>\n    * { margin: 0; padding: 0; box-sizing: border-box; }\n    html, body {\n        width: 100%;\n        height: 100%;\n        overflow: hidden;\n        background: #edf1eb;\n        font-family: \"Microsoft YaHei\", \"PingFang SC\", \"Noto Sans SC\", sans-serif;\n        color: #335239;\n    }\n    .slide-container {\n        width: 100vw;\n        height: 100vh;\n        display: flex;\n        align-items: center;\n        justify-content: center;\n    }\n    .slide {\n        width: 1280px;\n        height: 720px;\n        position: relative;\n        overflow: hidden;\n        transform-origin: center center;\n        border-radius: 16px;\n        background: linear-gradient(180deg, #f8faf6 0%, #f2f5ef 100%);\n        box-shadow: 0 18px 42px rgba(0,0,0,.14);\n    }\n\n    /* 页眉 - 严格保持原样 */\n    .header {\n        position: absolute;\n        left: 30px;\n        right: 30px;\n        top: 24px;\n        display: grid;\n        grid-template-columns: 1fr auto;\n        gap: 20px;\n        align-items: start;\n        z-index: 30;\n    }\n    .header h1 {\n        font-size: 28px;\n        line-height: 1.2;\n        color: #48724a;\n        font-weight: 900;\n        letter-spacing: .4px;\n    }\n    .header p {\n        margin-top: 7px;\n        font-size: 12px;\n        color: #7e8e7f;\n        line-height: 1.55;\n        max-width: 650px;\n    }\n\n    .main-tabs {\n        display: flex;\n        gap: 10px;\n        align-items: center;\n        flex-wrap: wrap;\n        justify-content: flex-end;\n    }\n    .main-tab {\n        border: 1px solid rgba(90,121,80,.18);\n        background: rgba(255,255,255,.92);\n        color: #5f7860;\n        border-radius: 999px;\n        padding: 9px 16px;\n        font-size: 14px;\n        font-weight: 800;\n        cursor: pointer;\n        transition: all .18s ease;\n    }\n    .main-tab.active {\n        background: #4e7b47;\n        color: #fff;\n        box-shadow: 0 8px 18px rgba(78,123,71,.28);\n    }\n\n    /* 主要内容区域 - 创意设计部分 */\n    .main-content {\n        position: absolute;\n        left: 28px;\n        right: 28px;\n        top: 98px;\n        bottom: 56px; /* 为页脚留出空间 */\n        display: flex;\n        flex-direction: column;\n        align-items: center;\n        justify-content: center;\n        z-index: 10;\n    }\n\n    /* 创意标题设计 */\n    .title-container {\n        text-align: center;\n        margin-bottom: 60px;\n        position: relative;\n    }\n\n    .main-title {\n        font-size: 64px;\n        font-weight: 900;\n        color: #4e874c;\n        line-height: 1.1;\n        margin-bottom: 16px;\n        letter-spacing: 1px;\n        position: relative;\n        display: inline-block;\n    }\n\n    .main-title::after {\n        content: \'\';\n        position: absolute;\n        bottom: -12px;\n        left: 50%;\n        transform: translateX(-50%);\n        width: 180px;\n        height: 4px;\n        background: linear-gradient(90deg, transparent, #74b43f, transparent);\n        border-radius: 2px;\n    }\n\n    .title-sub {\n        font-size: 22px;\n        color: #7e8e7f;\n        font-weight: 600;\n        letter-spacing: 0.5px;\n        margin-top: 24px;\n    }\n\n    /* 代码元素装饰 */\n    .code-decoration {\n        position: absolute;\n        font-family: \"Consolas\", \"Monaco\", monospace;\n        color: rgba(116, 180, 63, 0.15);\n        font-size: 14px;\n        z-index: 1;\n        pointer-events: none;\n    }\n\n    .code-1 {\n        top: 20%;\n        left: 10%;\n        transform: rotate(-15deg);\n    }\n\n    .code-2 {\n        bottom: 25%;\n        right: 12%;\n        transform: rotate(10deg);\n    }\n\n    .code-3 {\n        top: 40%;\n        right: 8%;\n        transform: rotate(5deg);\n    }\n\n    /* 信息卡片 */\n    .info-cards {\n        display: flex;\n        gap: 40px;\n        margin-top: 40px;\n    }\n\n    .info-card {\n        background: rgba(255, 255, 255, 0.92);\n        border: 1px solid rgba(87, 124, 79, 0.12);\n        border-radius: 20px;\n        padding: 24px 32px;\n        min-width: 200px;\n        text-align: center;\n        box-shadow: 0 8px 24px rgba(0, 0, 0, 0.06);\n        transition: all 0.25s ease;\n    }\n\n    .info-card:hover {\n        transform: translateY(-4px);\n        box-shadow: 0 12px 32px rgba(78, 123, 71, 0.15);\n    }\n\n    .card-icon {\n        font-size: 32px;\n        margin-bottom: 12px;\n        color: #5d8b67;\n    }\n\n    .card-label {\n        font-size: 13px;\n        color: #7e8e7f;\n        margin-bottom: 8px;\n        font-weight: 600;\n    }\n\n    .card-value {\n        font-size: 18px;\n        color: #48724a;\n        font-weight: 800;\n    }\n\n    /* 进度指示器 */\n    .progress-indicator {\n        position: absolute;\n        bottom: 40px;\n        left: 50%;\n        transform: translateX(-50%);\n        display: flex;\n        align-items: center;\n        gap: 12px;\n    }\n\n    .progress-dots {\n        display: flex;\n        gap: 8px;\n    }\n\n    .progress-dot {\n        width: 10px;\n        height: 10px;\n        border-radius: 50%;\n        background: #e3ece0;\n        transition: all 0.3s ease;\n    }\n\n    .progress-dot.active {\n        background: #74b43f;\n        transform: scale(1.2);\n    }\n\n    .progress-text {\n        font-size: 12px;\n        color: #7e8e7f;\n        font-weight: 600;\n    }\n\n    /* 背景装饰元素 */\n    .bg-element {\n        position: absolute;\n        border-radius: 50%;\n        z-index: 1;\n        pointer-events: none;\n    }\n\n    .bg-1 {\n        width: 120px;\n        height: 120px;\n        background: rgba(116, 180, 63, 0.08);\n        top: 100px;\n        left: 100px;\n    }\n\n    .bg-2 {\n        width: 80px;\n        height: 80px;\n        background: rgba(93, 139, 103, 0.06);\n        bottom: 120px;\n        right: 120px;\n    }\n\n    .bg-3 {\n        width: 60px;\n        height: 60px;\n        background: rgba(201, 217, 124, 0.05);\n        top: 180px;\n        right: 200px;\n    }\n\n    /* 页脚 - 严格保持原样 */\n    .footer {\n        position: absolute;\n        left: 30px;\n        right: 30px;\n        bottom: 24px;\n        display: flex;\n        justify-content: space-between;\n        align-items: center;\n        z-index: 30;\n    }\n\n    .footer-left {\n        font-size: 11px;\n        color: #7e8e7f;\n    }\n\n    .page-number {\n        font-size: 12px;\n        color: #5a7a55;\n        font-weight: 700;\n        background: rgba(255, 255, 255, 0.9);\n        padding: 6px 14px;\n        border-radius: 999px;\n        border: 1px solid rgba(90, 121, 80, 0.15);\n    }\n\n    /* 响应式调整 */\n    @media (max-width: 1366px) {\n        .main-title {\n            font-size: 56px;\n        }\n        \n        .info-cards {\n            gap: 30px;\n        }\n        \n        .info-card {\n            padding: 20px 28px;\n            min-width: 180px;\n        }\n    }\n\n    @media (max-width: 1200px) {\n        .main-title {\n            font-size: 48px;\n        }\n        \n        .title-sub {\n            font-size: 20px;\n        }\n        \n        .info-cards {\n            flex-direction: column;\n            gap: 20px;\n            align-items: center;\n        }\n        \n        .info-card {\n            width: 300px;\n        }\n    }\n</style>\n</head>\n<body>\n<div class=\"slide-container\">\n    <div class=\"slide\">\n        <!-- 页眉 -->\n        <div class=\"header\">\n            <div>\n                <h1>食品药品职业学院 PPT 模板描述文件（字段规范版）</h1>\n                <p>参照 template.html 的\"单文件、自包含、固定 1280×720、响应式缩放、占位符与规则说明\"写法，在 v3 的子版式拆分基础上，继续把字段命名、选型规则、禁用场景和母版约束标准化，方便后续直接拿来生成新的 PPT。</p>\n            </div>\n            <div class=\"main-tabs\">\n                <button class=\"main-tab active\">封面系统</button>\n                <button class=\"main-tab\">目录系统</button>\n                <button class=\"main-tab\">内容系统</button>\n                <button class=\"main-tab\">数据系统</button>\n            </div>\n        </div>\n\n        <!-- 背景装饰元素 -->\n        <div class=\"bg-element bg-1\"></div>\n        <div class=\"bg-element bg-2\"></div>\n        <div class=\"bg-element bg-3\"></div>\n\n        <!-- 代码装饰元素 -->\n        <div class=\"code-decoration code-1\">int main() { return 0; }</div>\n        <div class=\"code-decoration code-2\">printf(\"Hello, World!\");</div>\n        <div class=\"code-decoration code-3\">for(int i=0; i&lt;10; i++) { }</div>\n\n        <!-- 主要内容区域 -->\n        <div class=\"main-content\">\n            <div class=\"title-container\">\n                <h1 class=\"main-title\">C语言第四次课</h1>\n                <div class=\"title-sub\">深入理解指针与内存管理</div>\n            </div>\n\n            <div class=\"info-cards\">\n                <div class=\"info-card\">\n                    <div class=\"card-icon\">📚</div>\n                    <div class=\"card-label\">课程内容</div>\n                    <div class=\"card-value\">基于文档内容生成</div>\n                </div>\n                \n                <div class=\"info-card\">\n                    <div class=\"card-icon\">👨‍🏫</div>\n                    <div class=\"card-label\">演示者</div>\n                    <div class=\"card-value\">张明 讲师</div>\n                </div>\n                \n                <div class=\"info-card\">\n                    <div class=\"card-icon\">📅</div>\n                    <div class=\"card-label\">日期</div>\n                    <div class=\"card-value\">2024年3月15日</div>\n                </div>\n            </div>\n\n            <div class=\"progress-indicator\">\n                <div class=\"progress-text\">课程进度</div>\n                <div class=\"progress-dots\">\n                    <div class=\"progress-dot active\"></div>\n                    <div class=\"progress-dot active\"></div>\n                    <div class=\"progress-dot active\"></div>\n                    <div class=\"progress-dot active\"></div>\n                    <div class=\"progress-dot\"></div>\n                    <div class=\"progress-dot\"></div>\n                    <div class=\"progress-dot\"></div>\n                    <div class=\"progress-dot\"></div>\n                    <div class=\"progress-dot\"></div>\n                    <div class=\"progress-dot\"></div>\n                </div>\n                <div class=\"progress-text\">4/10</div>\n            </div>\n        </div>\n\n        <!-- 页脚 -->\n        <div class=\"footer\">\n            <div class=\"footer-left\">食品药品职业学院 · 计算机科学与技术系</div>\n            <div class=\"page-number\">1/10</div>\n        </div>\n    </div>\n</div>\n\n<script>\n// 简单的交互效果\ndocument.addEventListener(\'DOMContentLoaded\', function() {\n    // 卡片悬停效果增强\n    const cards = document.querySelectorAll(\'.info-card\');\n    cards.forEach(card => {\n        card.addEventListener(\'mouseenter\', function() {\n            this.style.transform = \'translateY(-6px)\';\n            this.style.boxShadow = \'0 16px 40px rgba(78, 123, 71, 0.2)\';\n        });\n        \n        card.addEventListener(\'mouseleave\', function() {\n            this.style.transform = \'translateY(0)\';\n            this.style.boxShadow = \'0 8px 24px rgba(0, 0, 0, 0.06)\';\n        });\n    });\n\n    // 模拟打字机效果（可选）\n    const mainTitle = document.querySelector(\'.main-title\');\n    const originalText = mainTitle.textContent;\n    mainTitle.textContent = \'\';\n    \n    let i = 0;\n    function typeWriter() {\n        if (i < originalText.length) {\n            mainTitle.textContent += originalText.charAt(i);\n            i++;\n            setTimeout(typeWriter, 50);\n        }\n    }\n    \n    // 延迟开始打字效果\n    setTimeout(typeWriter, 300);\n});\n\n// 页面缩放适配\nfunction scaleSlide() {\n    const slide = document.querySelector(\'.slide\');\n    const container = document.querySelector(\'.slide-container\');\n    const scale = Math.min(container.offsetWidth / 1280, container.offsetHeight / 720);\n    slide.style.transform = `scale(${scale})`;\n}\n\nwindow.addEventListener(\'load\', scaleSlide);\nwindow.addEventListener(\'resize\', scaleSlide);\n</script>\n</body>\n</html>','{}',NULL,0,1773720000,1773720000),(53,'d2191990-b108-4b42-8218-35c46b7c4b86',1,'slide_1','课程回顾与本次课目标','content','<!DOCTYPE html>\n<html lang=\"zh-CN\">\n<head>\n<meta charset=\"UTF-8\" />\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\n<title>第2页：课程回顾与本次课目标</title>\n<link rel=\"stylesheet\" href=\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css\">\n<link rel=\"stylesheet\" href=\"https://cdn.jsdelivr.net/npm/prismjs@1.29.0/themes/prism-tomorrow.min.css\">\n<script src=\"https://cdn.jsdelivr.net/npm/chart.js\"></script>\n<script src=\"https://polyfill.io/v3/polyfill.min.js?features=es6\"></script>\n<script id=\"MathJax-script\" async src=\"https://cdn.jsdelivr.net/npm/mathjax@3/es5/tex-mml-chtml.js\"></script>\n<script src=\"https://cdn.jsdelivr.net/npm/prismjs@1.29.0/prism.min.js\"></script>\n<style>\n    * { margin: 0; padding: 0; box-sizing: border-box; }\n    html, body {\n        width: 100%;\n        height: 100%;\n        overflow: hidden;\n        background: #edf1eb;\n        font-family: \"Microsoft YaHei\", \"PingFang SC\", \"Noto Sans SC\", sans-serif;\n        color: #335239;\n    }\n    .slide-container {\n        width: 100vw;\n        height: 100vh;\n        display: flex;\n        align-items: center;\n        justify-content: center;\n    }\n    .slide {\n        width: 1280px;\n        height: 720px;\n        position: relative;\n        overflow: hidden;\n        transform-origin: center center;\n        border-radius: 16px;\n        background: linear-gradient(180deg, #f8faf6 0%, #f2f5ef 100%);\n        box-shadow: 0 18px 42px rgba(0,0,0,.14);\n    }\n    /* 页眉 - 严格保持原样 */\n    .header {\n        position: absolute;\n        left: 30px;\n        right: 30px;\n        top: 24px;\n        display: grid;\n        grid-template-columns: 1fr auto;\n        gap: 20px;\n        align-items: start;\n        z-index: 30;\n    }\n    .header h1 {\n        font-size: 28px;\n        line-height: 1.2;\n        color: #48724a;\n        font-weight: 900;\n        letter-spacing: .4px;\n    }\n    .header p {\n        margin-top: 7px;\n        font-size: 12px;\n        color: #7e8e7f;\n        line-height: 1.55;\n        max-width: 650px;\n    }\n    .main-tabs {\n        display: flex;\n        gap: 10px;\n        align-items: center;\n        flex-wrap: wrap;\n        justify-content: flex-end;\n    }\n    .main-tab {\n        border: 1px solid rgba(90,121,80,.18);\n        background: rgba(255,255,255,.92);\n        color: #5f7860;\n        border-radius: 999px;\n        padding: 9px 16px;\n        font-size: 14px;\n        font-weight: 800;\n        cursor: pointer;\n        transition: all .18s ease;\n    }\n    .main-tab.active {\n        background: #4e7b47;\n        color: #fff;\n        box-shadow: 0 8px 18px rgba(78,123,71,.28);\n    }\n    /* 主要内容区域 */\n    .content-area {\n        position: absolute;\n        left: 28px;\n        right: 28px;\n        top: 98px;\n        bottom: 26px;\n        display: flex;\n        flex-direction: column;\n        padding: 20px 0;\n    }\n    /* 页脚 - 严格保持原样 */\n    .footer {\n        position: absolute;\n        left: 0;\n        right: 0;\n        bottom: 0;\n        height: 26px;\n        display: flex;\n        align-items: center;\n        justify-content: space-between;\n        padding: 0 28px;\n        font-size: 11px;\n        color: #7e8e7f;\n        z-index: 20;\n    }\n    .footer .page-number {\n        font-weight: 700;\n        color: #5a7a55;\n    }\n    /* 创意内容设计 */\n    .learning-path {\n        display: flex;\n        flex-direction: column;\n        height: 100%;\n        position: relative;\n    }\n    .path-title {\n        text-align: center;\n        margin-bottom: 30px;\n        position: relative;\n    }\n    .path-title h2 {\n        font-size: 32px;\n        color: #4e7b47;\n        font-weight: 900;\n        margin-bottom: 8px;\n        letter-spacing: 1px;\n    }\n    .path-title .subtitle {\n        font-size: 16px;\n        color: #7e8e7f;\n        font-weight: 500;\n    }\n    .path-container {\n        display: flex;\n        flex: 1;\n        align-items: center;\n        justify-content: space-between;\n        position: relative;\n        padding: 0 20px;\n    }\n    .path-line {\n        position: absolute;\n        top: 50%;\n        left: 120px;\n        right: 120px;\n        height: 4px;\n        background: linear-gradient(90deg, #c9d97c, #8cb267, #4e7b47);\n        transform: translateY(-50%);\n        z-index: 1;\n        border-radius: 2px;\n    }\n    .path-node {\n        position: relative;\n        z-index: 2;\n        width: 300px;\n        height: 320px;\n        display: flex;\n        flex-direction: column;\n        align-items: center;\n        justify-content: center;\n    }\n    .node-card {\n        width: 100%;\n        height: 100%;\n        background: rgba(255, 255, 255, 0.95);\n        border-radius: 24px;\n        padding: 30px;\n        display: flex;\n        flex-direction: column;\n        align-items: center;\n        justify-content: center;\n        box-shadow: 0 12px 30px rgba(78, 123, 71, 0.15);\n        border: 1px solid rgba(87, 124, 79, 0.1);\n        transition: all 0.3s ease;\n        position: relative;\n        overflow: hidden;\n    }\n    .node-card:hover {\n        transform: translateY(-8px);\n        box-shadow: 0 18px 40px rgba(78, 123, 71, 0.25);\n    }\n    .node-icon {\n        width: 80px;\n        height: 80px;\n        border-radius: 50%;\n        display: flex;\n        align-items: center;\n        justify-content: center;\n        margin-bottom: 20px;\n        font-size: 32px;\n        color: white;\n    }\n    .node-card.review .node-icon {\n        background: linear-gradient(135deg, #a8ca92, #8ab17f);\n    }\n    .node-card.focus .node-icon {\n        background: linear-gradient(135deg, #74b43f, #5b8f36);\n    }\n    .node-card.target .node-icon {\n        background: linear-gradient(135deg, #4e874c, #3f6e48);\n    }\n    .node-title {\n        font-size: 22px;\n        font-weight: 900;\n        margin-bottom: 15px;\n        text-align: center;\n        color: #335239;\n    }\n    .node-content {\n        font-size: 16px;\n        line-height: 1.6;\n        text-align: center;\n        color: #607163;\n        margin-bottom: 20px;\n    }\n    .node-details {\n        font-size: 14px;\n        color: #7e8e7f;\n        text-align: center;\n        line-height: 1.5;\n        margin-top: auto;\n    }\n    .node-connector {\n        position: absolute;\n        top: 50%;\n        width: 60px;\n        height: 60px;\n        transform: translateY(-50%);\n        display: flex;\n        align-items: center;\n        justify-content: center;\n        z-index: 3;\n    }\n    .node-connector.right {\n        right: -30px;\n    }\n    .node-connector.left {\n        left: -30px;\n    }\n    .connector-arrow {\n        width: 40px;\n        height: 40px;\n        background: #8cb267;\n        border-radius: 50%;\n        display: flex;\n        align-items: center;\n        justify-content: center;\n        color: white;\n        font-size: 18px;\n        box-shadow: 0 6px 12px rgba(140, 178, 103, 0.3);\n    }\n    .memory-visualization {\n        position: absolute;\n        bottom: 20px;\n        left: 50%;\n        transform: translateX(-50%);\n        width: 80%;\n        height: 60px;\n        display: flex;\n        justify-content: center;\n        align-items: center;\n        z-index: 1;\n    }\n    .memory-block {\n        width: 40px;\n        height: 40px;\n        background: rgba(120, 180, 71, 0.2);\n        border: 1px solid rgba(120, 180, 71, 0.4);\n        margin: 0 5px;\n        border-radius: 6px;\n        position: relative;\n        transition: all 0.3s ease;\n    }\n    .memory-block.active {\n        background: rgba(120, 180, 71, 0.6);\n        transform: scale(1.1);\n        box-shadow: 0 0 10px rgba(120, 180, 71, 0.5);\n    }\n    .memory-pointer {\n        position: absolute;\n        width: 20px;\n        height: 20px;\n        background: #ff6b35;\n        border-radius: 50%;\n        top: -10px;\n        left: 50%;\n        transform: translateX(-50%);\n        display: flex;\n        align-items: center;\n        justify-content: center;\n        color: white;\n        font-size: 10px;\n        font-weight: bold;\n        z-index: 2;\n    }\n    .progress-label {\n        position: absolute;\n        bottom: 85px;\n        left: 50%;\n        transform: translateX(-50%);\n        font-size: 14px;\n        color: #7e8e7f;\n        font-weight: 600;\n        white-space: nowrap;\n    }\n    /* 响应式调整 */\n    @media (max-width: 1300px) {\n        .path-node {\n            width: 280px;\n            height: 300px;\n        }\n        .node-title {\n            font-size: 20px;\n        }\n        .node-content {\n            font-size: 15px;\n        }\n    }\n    /* 动画效果 */\n    @keyframes pulse {\n        0% { transform: scale(1); }\n        50% { transform: scale(1.05); }\n        100% { transform: scale(1); }\n    }\n    .node-card.focus {\n        animation: pulse 3s infinite ease-in-out;\n    }\n    /* 代码高亮样式 */\n    .code-snippet {\n        background: #2d2d2d;\n        border-radius: 10px;\n        padding: 15px;\n        margin-top: 15px;\n        font-family: \'Consolas\', \'Monaco\', monospace;\n        font-size: 13px;\n        overflow-x: auto;\n    }\n</style>\n</head>\n<body>\n<div class=\"slide-container\">\n    <div class=\"slide\">\n        <!-- 页眉 - 严格保持原样 -->\n        <div class=\"header\">\n            <div>\n                <h1>C语言第四次课：指针高级应用</h1>\n                <p>食品药品职业学院 · 计算机科学与技术系 · 编程基础课程</p>\n            </div>\n            <div class=\"main-tabs\">\n                <button class=\"main-tab\">课程概述</button>\n                <button class=\"main-tab active\">学习路径</button>\n                <button class=\"main-tab\">实践演练</button>\n                <button class=\"main-tab\">知识拓展</button>\n            </div>\n        </div>\n        <!-- 主要内容区域 -->\n        <div class=\"content-area\">\n            <div class=\"learning-path\">\n                <div class=\"path-title\">\n                    <h2>课程回顾与本次课目标</h2>\n                    <div class=\"subtitle\">承前启后：从指针基础到高级内存管理</div>\n                </div>\n                <div class=\"path-container\">\n                    <div class=\"path-line\"></div>\n                    <!-- 回顾节点 -->\n                    <div class=\"path-node\">\n                        <div class=\"node-card review\">\n                            <div class=\"node-icon\">\n                                <i class=\"fas fa-history\"></i>\n                            </div>\n                            <div class=\"node-title\">夯实基础</div>\n                            <div class=\"node-content\">指针核心概念与数组关联回顾</div>\n                            <div class=\"node-details\">\n                                <p><i class=\"fas fa-check-circle\" style=\"color:#8ab17f; margin-right:5px;\"></i> 指针变量定义与初始化</p>\n                                <p><i class=\"fas fa-check-circle\" style=\"color:#8ab17f; margin-right:5px;\"></i> 数组与指针的等价关系</p>\n                                <p><i class=\"fas fa-check-circle\" style=\"color:#8ab17f; margin-right:5px;\"></i> 指针算术运算规则</p>\n                            </div>\n                        </div>\n                    </div>\n                    <div class=\"node-connector right\">\n                        <div class=\"connector-arrow\">\n                            <i class=\"fas fa-arrow-right\"></i>\n                        </div>\n                    </div>\n                    <!-- 重点节点 -->\n                    <div class=\"path-node\">\n                        <div class=\"node-card focus\">\n                            <div class=\"node-icon\">\n                                <i class=\"fas fa-bolt\"></i>\n                            </div>\n                            <div class=\"node-title\">核心进阶</div>\n                            <div class=\"node-content\">探索指针高级应用与动态内存管理</div>\n                            <div class=\"node-details\">\n                                <p><i class=\"fas fa-star\" style=\"color:#ffc107; margin-right:5px;\"></i> 多级指针与指针数组</p>\n                                <p><i class=\"fas fa-star\" style=\"color:#ffc107; margin-right:5px;\"></i> 函数指针与回调机制</p>\n                                <p><i class=\"fas fa-star\" style=\"color:#ffc107; margin-right:5px;\"></i> malloc/free 动态内存管理</p>\n                            </div>\n                        </div>\n                    </div>\n                    <div class=\"node-connector right\">\n                        <div class=\"connector-arrow\">\n                            <i class=\"fas fa-arrow-right\"></i>\n                        </div>\n                    </div>\n                    <!-- 目标节点 -->\n                    <div class=\"path-node\">\n                        <div class=\"node-card target\">\n                            <div class=\"node-icon\">\n                                <i class=\"fas fa-bullseye\"></i>\n                            </div>\n                            <div class=\"node-title\">目标达成</div>\n                            <div class=\"node-content\">能够灵活运用复杂指针并理解内存分配机制</div>\n                            <div class=\"node-details\">\n                                <p><i class=\"fas fa-flag\" style=\"color:#4e874c; margin-right:5px;\"></i> 掌握指针的复杂用法</p>\n                                <p><i class=\"fas fa-flag\" style=\"color:#4e874c; margin-right:5px;\"></i> 理解内存分配原理</p>\n                                <p><i class=\"fas fa-flag\" style=\"color:#4e874c; margin-right:5px;\"></i> 能够编写动态数据结构</p>\n                            </div>\n                        </div>\n                    </div>\n                </div>\n                <div class=\"progress-label\">学习进度：第2页 · 从基础到高级的完整路径</div>\n                <div class=\"memory-visualization\">\n                    <div class=\"memory-block\">\n                        <div class=\"memory-pointer\">ptr</div>\n                    </div>\n                    <div class=\"memory-block active\">\n                        <div class=\"memory-pointer\">*ptr</div>\n                    </div>\n                    <div class=\"memory-block\">\n                        <div class=\"memory-pointer\">**ptr</div>\n                    </div>\n                    <div class=\"memory-block active\">\n                        <div class=\"memory-pointer\">arr</div>\n                    </div>\n                    <div class=\"memory-block\">\n                        <div class=\"memory-pointer\">malloc</div>\n                    </div>\n                    <div class=\"memory-block active\">\n                        <div class=\"memory-pointer\">free</div>\n                    </div>\n                </div>\n            </div>\n        </div>\n        <!-- 页脚 - 严格保持原样 -->\n        <div class=\"footer\">\n            <div class=\"footer-left\">食品药品职业学院 · C语言编程课程</div>\n            <div class=\"page-number\">2/10</div>\n            <div class=\"footer-right\">第四次课：指针高级应用</div>\n        </div>\n    </div>\n</div>\n<script>\n    document.addEventListener(\'DOMContentLoaded\', function() {\n        const memoryBlocks = document.querySelectorAll(\'.memory-block\');\n        let currentIndex = 0;\n        function animateMemoryBlocks() {\n            memoryBlocks.forEach(block => block.classList.remove(\'active\'));\n            memoryBlocks[currentIndex].classList.add(\'active\');\n            memoryBlocks[(currentIndex + 1) % memoryBlocks.length].classList.add(\'active\');\n            memoryBlocks[(currentIndex + 3) % memoryBlocks.length].classList.add(\'active\');\n            currentIndex = (currentIndex + 1) % memoryBlocks.length;\n        }\n        animateMemoryBlocks();\n        setInterval(','{}',NULL,0,1773720000,1773720000),(54,'d2191990-b108-4b42-8218-35c46b7c4b86',2,'slide_2','指针与函数','content','<!DOCTYPE html>\n<html lang=\"zh-CN\">\n<head>\n<meta charset=\"UTF-8\" />\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\n<title>指针与函数 - C语言第四次课</title>\n<link rel=\"stylesheet\" href=\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css\">\n<link rel=\"stylesheet\" href=\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/themes/prism-tomorrow.min.css\">\n<script src=\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/prism.min.js\"></script>\n<script src=\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/components/prism-c.min.js\"></script>\n<script src=\"https://cdn.jsdelivr.net/npm/chart.js\"></script>\n<style>\n    * { margin: 0; padding: 0; box-sizing: border-box; }\n    html, body {\n        width: 100%;\n        height: 100%;\n        overflow: hidden;\n        background: #edf1eb;\n        font-family: \"Microsoft YaHei\", \"PingFang SC\", \"Noto Sans SC\", sans-serif;\n        color: #335239;\n    }\n    .slide-container {\n        width: 100vw;\n        height: 100vh;\n        display: flex;\n        align-items: center;\n        justify-content: center;\n    }\n    .slide {\n        width: 1280px;\n        height: 720px;\n        position: relative;\n        overflow: hidden;\n        transform-origin: center center;\n        border-radius: 16px;\n        background: linear-gradient(180deg, #f8faf6 0%, #f2f5ef 100%);\n        box-shadow: 0 18px 42px rgba(0,0,0,.14);\n    }\n    /* 页眉 - 严格保持原样 */\n    .header {\n        position: absolute;\n        left: 30px;\n        right: 30px;\n        top: 24px;\n        display: grid;\n        grid-template-columns: 1fr auto;\n        gap: 20px;\n        align-items: start;\n        z-index: 30;\n    }\n    .header h1 {\n        font-size: 28px;\n        line-height: 1.2;\n        color: #48724a;\n        font-weight: 900;\n        letter-spacing: .4px;\n    }\n    .header p {\n        margin-top: 7px;\n        font-size: 12px;\n        color: #7e8e7f;\n        line-height: 1.55;\n        max-width: 650px;\n    }\n    .main-tabs {\n        display: flex;\n        gap: 10px;\n        align-items: center;\n        flex-wrap: wrap;\n        justify-content: flex-end;\n    }\n    .main-tab {\n        border: 1px solid rgba(90,121,80,.18);\n        background: rgba(255,255,255,.92);\n        color: #5f7860;\n        border-radius: 999px;\n        padding: 9px 16px;\n        font-size: 14px;\n        font-weight: 800;\n        cursor: pointer;\n        transition: all .18s ease;\n    }\n    .main-tab.active {\n        background: #4e7b47;\n        color: #fff;\n        box-shadow: 0 8px 18px rgba(78,123,71,.28);\n    }\n    /* 主要内容区域 - 可创意设计 */\n    .content-area {\n        position: absolute;\n        left: 28px;\n        right: 28px;\n        top: 98px;\n        bottom: 26px;\n        display: flex;\n        flex-direction: column;\n        gap: 16px;\n    }\n    .page-title {\n        display: flex;\n        align-items: center;\n        gap: 12px;\n        margin-bottom: 8px;\n    }\n    .page-title h2 {\n        font-size: 32px;\n        color: #4e7b47;\n        font-weight: 900;\n        letter-spacing: 0.5px;\n    }\n    .page-title .subtitle {\n        font-size: 16px;\n        color: #7e8e7f;\n        font-weight: 500;\n        padding-left: 12px;\n        border-left: 2px solid #c9d97c;\n    }\n    /* 四象限布局 */\n    .quadrant-container {\n        flex: 1;\n        display: grid;\n        grid-template-columns: 1fr 1fr;\n        grid-template-rows: 1fr 1fr;\n        gap: 20px;\n        padding: 8px;\n    }\n    .concept-card {\n        background: rgba(255,255,255,0.95);\n        border-radius: 20px;\n        padding: 24px;\n        display: flex;\n        flex-direction: column;\n        border: 1px solid rgba(87,124,79,.12);\n        box-shadow: 0 8px 24px rgba(78,123,71,.08);\n        transition: all 0.3s ease;\n        position: relative;\n        overflow: hidden;\n    }\n    .concept-card:hover {\n        transform: translateY(-4px);\n        box-shadow: 0 12px 32px rgba(78,123,71,.15);\n    }\n    .concept-card::before {\n        content: \'\';\n        position: absolute;\n        top: 0;\n        left: 0;\n        width: 100%;\n        height: 6px;\n    }\n    .card-1::before { background: linear-gradient(90deg, #4e7b47, #78a06f); }\n    .card-2::before { background: linear-gradient(90deg, #78a06f, #9ab48e); }\n    .card-3::before { background: linear-gradient(90deg, #9ab48e, #c9d97c); }\n    .card-4::before { background: linear-gradient(90deg, #c9d97c, #dbead3); }\n    .card-header {\n        display: flex;\n        align-items: center;\n        gap: 16px;\n        margin-bottom: 18px;\n    }\n    .card-icon {\n        width: 56px;\n        height: 56px;\n        border-radius: 16px;\n        display: flex;\n        align-items: center;\n        justify-content: center;\n        font-size: 24px;\n        color: white;\n        flex-shrink: 0;\n    }\n    .card-1 .card-icon { background: #4e7b47; }\n    .card-2 .card-icon { background: #78a06f; }\n    .card-3 .card-icon { background: #9ab48e; }\n    .card-4 .card-icon { background: #c9d97c; }\n    .card-title {\n        font-size: 20px;\n        font-weight: 900;\n        color: #335239;\n        line-height: 1.3;\n    }\n    .card-desc {\n        font-size: 14px;\n        color: #607163;\n        line-height: 1.6;\n        margin-bottom: 20px;\n        flex-grow: 1;\n    }\n    .code-preview {\n        background: #2d2d2d;\n        border-radius: 12px;\n        padding: 16px;\n        font-family: \'Consolas\', \'Monaco\', monospace;\n        font-size: 13px;\n        line-height: 1.5;\n        color: #f8f8f2;\n        overflow: auto;\n        max-height: 140px;\n        margin-top: auto;\n    }\n    .code-preview .keyword { color: #ff79c6; }\n    .code-preview .type { color: #8be9fd; }\n    .code-preview .function { color: #50fa7b; }\n    .code-preview .comment { color: #6272a4; }\n    .code-preview .string { color: #f1fa8c; }\n    .code-preview .number { color: #bd93f9; }\n    /* 中央关系图 */\n    .relationship-center {\n        position: absolute;\n        left: 50%;\n        top: 50%;\n        transform: translate(-50%, -50%);\n        width: 180px;\n        height: 180px;\n        z-index: 5;\n    }\n    .center-circle {\n        width: 100%;\n        height: 100%;\n        border-radius: 50%;\n        background: rgba(255,255,255,0.95);\n        border: 3px solid #4e7b47;\n        display: flex;\n        align-items: center;\n        justify-content: center;\n        box-shadow: 0 10px 30px rgba(78,123,71,.2);\n        position: relative;\n        z-index: 2;\n    }\n    .center-text {\n        font-size: 18px;\n        font-weight: 900;\n        color: #4e7b47;\n        text-align: center;\n        line-height: 1.3;\n    }\n    .connection-line {\n        position: absolute;\n        background: #c9d97c;\n        height: 3px;\n        border-radius: 2px;\n        z-index: 1;\n    }\n    .line-1 {\n        width: 160px;\n        top: 50%;\n        left: calc(50% + 90px);\n        transform: translateY(-50%);\n    }\n    .line-2 {\n        width: 160px;\n        top: 50%;\n        right: calc(50% + 90px);\n        transform: translateY(-50%);\n    }\n    .line-3 {\n        width: 160px;\n        left: 50%;\n        top: calc(50% + 90px);\n        transform: translateX(-50%) rotate(90deg);\n    }\n    .line-4 {\n        width: 160px;\n        left: 50%;\n        bottom: calc(50% + 90px);\n        transform: translateX(-50%) rotate(90deg);\n    }\n    /* 页脚 - 严格保持原样 */\n    .footer {\n        position: absolute;\n        left: 0;\n        right: 0;\n        bottom: 0;\n        height: 26px;\n        display: flex;\n        align-items: center;\n        justify-content: space-between;\n        padding: 0 30px;\n        font-size: 12px;\n        color: #7e8e7f;\n        z-index: 30;\n    }\n    .page-number {\n        font-weight: 700;\n        color: #5f7860;\n    }\n    /* 装饰元素 */\n    .decoration-circle {\n        position: absolute;\n        border-radius: 50%;\n        opacity: 0.1;\n        z-index: 0;\n    }\n    .circle-1 {\n        width: 120px;\n        height: 120px;\n        background: #4e7b47;\n        top: 120px;\n        left: 80px;\n    }\n    .circle-2 {\n        width: 80px;\n        height: 80px;\n        background: #78a06f;\n        bottom: 100px;\n        right: 100px;\n    }\n    .circle-3 {\n        width: 60px;\n        height: 60px;\n        background: #c9d97c;\n        top: 180px;\n        right: 150px;\n    }\n    /* 响应式调整 */\n    @media (max-width: 1350px) {\n        .slide {\n            transform: scale(0.9);\n        }\n    }\n    @media (max-width: 1200px) {\n        .slide {\n            transform: scale(0.8);\n        }\n    }\n</style>\n</head>\n<body>\n<div class=\"slide-container\">\n    <div class=\"slide\">\n        <!-- 页眉 - 严格保持原样 -->\n        <div class=\"header\">\n            <div>\n                <h1>食品药品职业学院 PPT 模板描述文件（字段规范版）</h1>\n                <p>参照 template.html 的\"单文件、自包含、固定 1280×720、响应式缩放、占位符与规则说明\"写法，在 v3 的子版式拆分基础上，继续把字段命名、选型规则、禁用场景和母版约束标准化，方便后续直接拿来生成新的 PPT。</p>\n            </div>\n            <div class=\"main-tabs\" id=\"mainTabs\">\n                <button class=\"main-tab\">封面系统</button>\n                <button class=\"main-tab\">目录系统</button>\n                <button class=\"main-tab active\">内容系统</button>\n                <button class=\"main-tab\">数据系统</button>\n            </div>\n        </div>\n        <!-- 主要内容区域 - 创意设计 -->\n        <div class=\"content-area\">\n            <div class=\"page-title\">\n                <h2>指针与函数</h2>\n                <div class=\"subtitle\">三种交互模式与回调机制</div>\n            </div>\n            <!-- 四象限布局 -->\n            <div class=\"quadrant-container\">\n                <!-- 卡片1: 指针作为函数参数 -->\n                <div class=\"concept-card card-1\">\n                    <div class=\"card-header\">\n                        <div class=\"card-icon\">\n                            <i class=\"fas fa-exchange-alt\"></i>\n                        </div>\n                        <div class=\"card-title\">指针作为函数参数<br><span style=\"font-size: 14px; color: #7e8e7f;\">传址调用</span></div>\n                    </div>\n                    <div class=\"card-desc\">\n                        通过传递指针参数，函数可以直接修改调用者中的数据，避免数据拷贝，提高效率。\n                    </div>\n                    <div class=\"code-preview\">\n                        <span class=\"keyword\">void</span> <span class=\"function\">modifyViaPointer</span>(<span class=\"keyword\">int</span> *<span class=\"variable\">ptr</span>) {<br>\n                        &nbsp;&nbsp;&nbsp;&nbsp;*<span class=\"variable\">ptr</span> = <span class=\"number\">100</span>; <span class=\"comment\">// 直接修改原数据</span><br>\n                        }<br><br>\n                        <span class=\"comment\">// 调用示例</span><br>\n                        <span class=\"keyword\">int</span> <span class=\"variable\">value</span> = <span class=\"number\">10</span>;<br>\n                        <span class=\"function\">modifyViaPointer</span>(&<span class=\"variable\">value</span>);<br>\n                        <span class=\"comment\">// value 现在为 100</span>\n                    </div>\n                </div>\n                <!-- 卡片2: 指针作为函数返回值 -->\n                <div class=\"concept-card card-2\">\n                    <div class=\"card-header\">\n                        <div class=\"card-icon\">\n                            <i class=\"fas fa-arrow-right\"></i>\n                        </div>\n                        <div class=\"card-title\">指针作为函数返回值<br><span style=\"font-size: 14px; color: #7e8e7f;\">动态内存管理</span></div>\n                    </div>\n                    <div class=\"card-desc\">\n                        函数可以返回指针，常用于动态内存分配、工厂模式等场景，但要注意避免返回局部变量的地址。\n                    </div>\n                    <div class=\"code-preview\">\n                        <span class=\"keyword\">int</span>* <span class=\"function\">createArray</span>(<span class=\"keyword\">int</span> <span class=\"variable\">size</span>) {<br>\n                        &nbsp;&nbsp;&nbsp;&nbsp;<span class=\"keyword\">return</span> (<span class=\"keyword\">int</span>*)<span class=\"function\">malloc</span>(<span class=\"variable\">size</span> * <span class=\"keyword\">sizeof</span>(<span class=\"keyword\">int</span>));<br>\n                        }<br><br>\n                        <span class=\"comment\">// 使用示例</span><br>\n                        <span class=\"keyword\">int</span> *<span class=\"variable\">arr</span> = <span class=\"function\">createArray</span>(<span class=\"number\">10</span>);<br>\n                        <span class=\"variable\">arr</span>[<span class=\"number\">0</span>] = <span class=\"number\">42</span>;<br>\n                        <span class=\"function\">free</span>(<span class=\"variable\">arr</span>); <span class=\"comment\">// 记得释放内存</span>\n                    </div>\n                </div>\n                <!-- 卡片3: 函数指针 -->\n                <div class=\"concept-card card-3\">\n                    <div class=\"card-header\">\n                        <div class=\"card-icon\">\n                            <i class=\"fas fa-code\"></i>\n                        </div>\n                        <div class=\"card-title\">函数指针<br><span style=\"font-size: 14px; color: #7e8e7f;\">定义、声明与调用</span></div>\n                    </div>\n                    <div class=\"card-desc\">\n                        指向函数的指针，允许在运行时动态选择要调用的函数，是实现多态和策略模式的基础。\n                    </div>\n                    <div class=\"code-preview\">\n                        <span class=\"comment\">// 函数指针声明</span><br>\n                        <span class=\"keyword\">int</span> (*<span class=\"variable\">operation</span>)(<span class=\"keyword\">int</span>, <span class=\"keyword\">int</span>);<br><br>\n                        <span class=\"keyword\">int</span> <span class=\"function\">add</span>(<span class=\"keyword\">int</span> <span class=\"variable\">a</span>, <span class=\"keyword\">int</span> <span class=\"variable\">b</span>) {<br>\n                        &nbsp;&nbsp;&nbsp;&nbsp;<span class=\"keyword\">return</span> <span class=\"variable\">a</span> + <span class=\"variable\">b</span>;<br>\n                        }<br><br>\n                        <span class=\"variable\">operation</span> = <span class=\"function\">add</span>; <span class=\"comment\">// 指向add函数</span><br>\n                        <span class=\"keyword\">int</span> <span class=\"variable\">result</span> = <span class=\"variable\">operation</span','{}',NULL,0,1773720000,1773720000),(55,'d2191990-b108-4b42-8218-35c46b7c4b86',3,'slide_3','多级指针','content','<!DOCTYPE html>\n<html lang=\"zh-CN\">\n<head>\n<meta charset=\"UTF-8\" />\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\n<title>多级指针 - C语言第四次课</title>\n<link rel=\"stylesheet\" href=\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css\">\n<link rel=\"stylesheet\" href=\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/themes/prism-tomorrow.min.css\">\n<script src=\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/prism.min.js\"></script>\n<script src=\"https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/components/prism-c.min.js\"></script>\n<style>\n    * { margin: 0; padding: 0; box-sizing: border-box; }\n    html, body {\n        width: 100%;\n        height: 100%;\n        overflow: hidden;\n        background: #edf1eb;\n        font-family: \"Microsoft YaHei\", \"PingFang SC\", \"Noto Sans SC\", sans-serif;\n        color: #335239;\n    }\n    .slide-container {\n        width: 100vw;\n        height: 100vh;\n        display: flex;\n        align-items: center;\n        justify-content: center;\n    }\n    .slide {\n        width: 1280px;\n        height: 720px;\n        position: relative;\n        overflow: hidden;\n        transform-origin: center center;\n        border-radius: 16px;\n        background: linear-gradient(180deg, #f8faf6 0%, #f2f5ef 100%);\n        box-shadow: 0 18px 42px rgba(0,0,0,.14);\n    }\n    /* 页眉 - 严格保持原样 */\n    .header {\n        position: absolute;\n        left: 30px;\n        right: 30px;\n        top: 24px;\n        display: grid;\n        grid-template-columns: 1fr auto;\n        gap: 20px;\n        align-items: start;\n        z-index: 30;\n    }\n    .header h1 {\n        font-size: 28px;\n        line-height: 1.2;\n        color: #48724a;\n        font-weight: 900;\n        letter-spacing: .4px;\n    }\n    .header p {\n        margin-top: 7px;\n        font-size: 12px;\n        color: #7e8e7f;\n        line-height: 1.55;\n        max-width: 650px;\n    }\n    .main-tabs {\n        display: flex;\n        gap: 10px;\n        align-items: center;\n        flex-wrap: wrap;\n        justify-content: flex-end;\n    }\n    .main-tab {\n        border: 1px solid rgba(90,121,80,.18);\n        background: rgba(255,255,255,.92);\n        color: #5f7860;\n        border-radius: 999px;\n        padding: 9px 16px;\n        font-size: 14px;\n        font-weight: 800;\n        cursor: pointer;\n        transition: all .18s ease;\n    }\n    .main-tab.active {\n        background: #4e7b47;\n        color: #fff;\n        box-shadow: 0 8px 18px rgba(78,123,71,.28);\n    }\n    /* 主要内容区域 - 创意设计部分 */\n    .content-area {\n        position: absolute;\n        left: 28px;\n        right: 28px;\n        top: 98px;\n        bottom: 26px;\n        display: flex;\n        flex-direction: column;\n    }\n    .page-title {\n        font-size: 36px;\n        font-weight: 900;\n        color: #2A5CAA;\n        margin-bottom: 8px;\n        display: flex;\n        align-items: center;\n        gap: 12px;\n    }\n    .page-title .subtitle {\n        font-size: 18px;\n        color: #7e8e7f;\n        font-weight: 500;\n    }\n    .page-title i {\n        color: #FF6B35;\n        font-size: 32px;\n    }\n    .main-content {\n        display: flex;\n        flex: 1;\n        gap: 24px;\n        margin-top: 12px;\n    }\n    .left-panel {\n        flex: 1;\n        display: flex;\n        flex-direction: column;\n        gap: 20px;\n    }\n    .right-panel {\n        flex: 1;\n        display: flex;\n        flex-direction: column;\n        gap: 20px;\n    }\n    .concept-card {\n        background: rgba(255,255,255,.95);\n        border-radius: 20px;\n        padding: 22px;\n        box-shadow: 0 8px 24px rgba(42,92,170,.08);\n        border: 1px solid rgba(42,92,170,.12);\n        flex: 1;\n        display: flex;\n        flex-direction: column;\n    }\n    .card-title {\n        font-size: 20px;\n        font-weight: 900;\n        color: #1A3A6A;\n        margin-bottom: 16px;\n        display: flex;\n        align-items: center;\n        gap: 10px;\n    }\n    .card-title i {\n        color: #4CAF50;\n    }\n    .concept-list {\n        display: flex;\n        flex-direction: column;\n        gap: 16px;\n        flex: 1;\n    }\n    .concept-item {\n        display: flex;\n        gap: 14px;\n        align-items: flex-start;\n    }\n    .concept-icon {\n        width: 32px;\n        height: 32px;\n        border-radius: 50%;\n        background: #2A5CAA;\n        color: white;\n        display: flex;\n        align-items: center;\n        justify-content: center;\n        font-weight: bold;\n        font-size: 14px;\n        flex-shrink: 0;\n    }\n    .concept-text {\n        flex: 1;\n    }\n    .concept-text h4 {\n        font-size: 16px;\n        font-weight: 800;\n        color: #2A5CAA;\n        margin-bottom: 4px;\n    }\n    .concept-text p {\n        font-size: 14px;\n        color: #5a6c7d;\n        line-height: 1.5;\n    }\n    .code-example {\n        background: #1a1a1a;\n        border-radius: 12px;\n        padding: 16px;\n        font-family: \'Consolas\', \'Monaco\', monospace;\n        font-size: 14px;\n        line-height: 1.5;\n        color: #f8f8f2;\n        overflow: auto;\n        margin-top: 8px;\n    }\n    .memory-diagram {\n        background: rgba(255,255,255,.95);\n        border-radius: 20px;\n        padding: 22px;\n        box-shadow: 0 8px 24px rgba(255,107,53,.08);\n        border: 1px solid rgba(255,107,53,.12);\n        flex: 1;\n        display: flex;\n        flex-direction: column;\n    }\n    .diagram-title {\n        font-size: 20px;\n        font-weight: 900;\n        color: #FF6B35;\n        margin-bottom: 16px;\n        display: flex;\n        align-items: center;\n        gap: 10px;\n    }\n    .diagram-container {\n        flex: 1;\n        display: flex;\n        align-items: center;\n        justify-content: center;\n        position: relative;\n    }\n    .pointer-levels {\n        display: flex;\n        align-items: center;\n        justify-content: center;\n        gap: 40px;\n    }\n    .level-box {\n        width: 120px;\n        height: 120px;\n        border-radius: 16px;\n        display: flex;\n        flex-direction: column;\n        align-items: center;\n        justify-content: center;\n        position: relative;\n        transition: all 0.3s ease;\n    }\n    .level-box:hover {\n        transform: translateY(-5px);\n        box-shadow: 0 12px 28px rgba(0,0,0,.15);\n    }\n    .level-1 {\n        background: linear-gradient(135deg, #e3f2fd, #bbdefb);\n        border: 3px solid #64b5f6;\n    }\n    .level-2 {\n        background: linear-gradient(135deg, #e8f5e9, #c8e6c9);\n        border: 3px solid #81c784;\n    }\n    .level-3 {\n        background: linear-gradient(135deg, #fff3e0, #ffe0b2);\n        border: 3px solid #ffb74d;\n    }\n    .level-label {\n        font-size: 14px;\n        font-weight: 800;\n        color: #333;\n        margin-bottom: 8px;\n    }\n    .level-value {\n        font-size: 18px;\n        font-weight: 900;\n        color: #1A3A6A;\n        font-family: \'Consolas\', monospace;\n    }\n    .level-address {\n        font-size: 12px;\n        color: #FF6B35;\n        font-family: \'Consolas\', monospace;\n        margin-top: 6px;\n    }\n    .arrow {\n        font-size: 28px;\n        color: #4CAF50;\n        font-weight: bold;\n    }\n    .application-card {\n        background: rgba(255,255,255,.95);\n        border-radius: 20px;\n        padding: 22px;\n        box-shadow: 0 8px 24px rgba(76,175,80,.08);\n        border: 1px solid rgba(76,175,80,.12);\n        flex: 1;\n        display: flex;\n        flex-direction: column;\n    }\n    .app-title {\n        font-size: 20px;\n        font-weight: 900;\n        color: #4CAF50;\